// --- Marked.js Konfiguration: Links in neuem Tab oeffnen ---
const renderer = new marked.Renderer();
renderer.link = function(href, title, text) {
    // Unterstuetzung fuer marked.js v4+ (Objekt-Parameter)
    if (typeof href === 'object') {
        const token = href;
        href = token.href;
        title = token.title;
        text = token.text;
    }
    const titleAttr = title ? ` title="${title}"` : '';
    return `<a href="${href}" target="_blank" rel="noopener noreferrer"${titleAttr}>${text}</a>`;
};
marked.setOptions({ renderer: renderer });

// --- Default Avatar Generator ---
function generateDefaultAvatar(name) {
    const initial = (name && name !== '—') ? name.charAt(0).toUpperCase() : '?';
    // Farbe aus dem Namen ableiten (deterministisch)
    let hash = 0;
    for (let i = 0; i < (name || '').length; i++) {
        hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    const hue = Math.abs(hash) % 360;
    const bg = `hsl(${hue}, 45%, 45%)`;
    const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="200" height="200">
        <rect width="200" height="200" rx="12" fill="${bg}"/>
        <text x="100" y="115" font-family="Arial,sans-serif" font-size="90" font-weight="bold"
              fill="white" text-anchor="middle">${initial}</text>
    </svg>`;
    return 'data:image/svg+xml,' + encodeURIComponent(svg);
}

// --- Profilbild/Video Helper ---
function isVideoUrl(url) {
    if (!url) return false;
    // Query-Parameter und Fragment entfernen bevor Extension geprueft wird
    const path = url.split('?')[0].split('#')[0];
    return path.toLowerCase().endsWith('.mp4');
}

function setProfileMedia(url, isDefault) {
    const imgEl = document.getElementById('agent-profile-image');
    const vidEl = document.getElementById('agent-profile-video');
    if (!imgEl) return;

    const _onClick = isDefault ? null : (() => openLightbox(url));

    if (!isDefault && isVideoUrl(url)) {
        imgEl.style.display = 'none';
        if (vidEl) {
            vidEl.src = url;
            vidEl.style.display = 'block';
            vidEl.style.cursor = 'pointer';
            vidEl.title = 'Vergroessern';
            vidEl.onclick = _onClick;
        }
    } else {
        if (vidEl) {
            vidEl.style.display = 'none';
            vidEl.src = '';
        }
        imgEl.src = url;
        imgEl.style.display = 'block';
        imgEl.style.cursor = isDefault ? 'default' : 'pointer';
        imgEl.title = isDefault ? '' : 'Vergroessern';
        imgEl.onclick = _onClick;
    }
    imgEl.dataset.hasRealImage = isDefault ? 'false' : 'true';
    imgEl.dataset.profileUrl = isDefault ? '' : url;
}

// Cache fuer Frame-Metadaten (1 Fetch pro Session, World-spezifisch)
let _MESSAGING_FRAME_CACHE = null;

async function _getMessagingFrameMeta() {
    if (_MESSAGING_FRAME_CACHE !== null) return _MESSAGING_FRAME_CACHE;
    try {
        const r = await fetch('/world/messaging-frame');
        _MESSAGING_FRAME_CACHE = r.ok ? await r.json() : { has_frame: false };
    } catch {
        _MESSAGING_FRAME_CACHE = { has_frame: false };
    }
    return _MESSAGING_FRAME_CACHE;
}

// Public: Cache invalidieren (z.B. nach Frame-Regeneration im Admin)
function invalidateMessagingFrameCache() { _MESSAGING_FRAME_CACHE = null; }

function _clearCustomFrame(container) {
    if (!container) return;
    const overlay = container.querySelector('.messaging-frame-overlay');
    if (overlay) overlay.remove();
    const inner = container.querySelector('.messaging-frame-inner');
    if (inner) inner.remove();
}

async function _applyMessagingFrame(container, sceneImg, profileUrl, characterName) {
    if (!container) return;
    const meta = await _getMessagingFrameMeta();

    // Default: kein konfiguriertes Frame -> aktiviere CSS-Default (phone-chat-mode)
    if (!meta || !meta.has_frame) {
        sceneImg.src = profileUrl;
        sceneImg.style.display = '';
        container.classList.add('phone-chat-mode');
        container.classList.remove('custom-frame-mode');
        _clearCustomFrame(container);
        _setSceneOutfitLabel(characterName);
        _updateOutfitLockButton('agent', characterName);
        _updateSceneWardrobeButton('agent', characterName);
        sceneImg.style.cursor = '';
        sceneImg.title = `📞 Phone-Chat — ${characterName} (Profilbild)`;
        sceneImg.onclick = null;
        return;
    }

    // Custom-Frame: zwei-Layer-Composite (Charakter im bbox-Bereich + Frame oben)
    const [fw, fh] = meta.frame_size || [600, 800];
    const bbox = meta.bbox || { x: 0, y: 0, w: fw, h: fh };
    container.classList.remove('phone-chat-mode');
    container.classList.add('custom-frame-mode');

    // sceneImg ausblenden, eigene Struktur drueberlegen
    sceneImg.style.display = 'none';
    sceneImg.src = '';
    _clearCustomFrame(container);

    // Wrapper mit aspect-ratio des Frames + bbox als CSS-Variablen
    const wrap = document.createElement('div');
    wrap.className = 'messaging-frame-inner';
    wrap.style.setProperty('--frame-w', fw);
    wrap.style.setProperty('--frame-h', fh);
    wrap.style.setProperty('--bbox-x', (bbox.x / fw * 100) + '%');
    wrap.style.setProperty('--bbox-y', (bbox.y / fh * 100) + '%');
    wrap.style.setProperty('--bbox-w', (bbox.w / fw * 100) + '%');
    wrap.style.setProperty('--bbox-h', (bbox.h / fh * 100) + '%');
    wrap.title = `📞 Phone-Chat — ${characterName}`;
    // Innen-Bereich = Wrapper-DIV mit Frame-Screen-Hintergrund + Bild drinnen,
    // leicht verkleinert. So bleibt das Bild zuverlaessig innerhalb der bbox
    // auch wenn der Chroma-Key den Anzeigebereich grosszuegig erkannt hat.
    const screen = document.createElement('div');
    screen.className = 'messaging-frame-screen';
    const inner = document.createElement('img');
    inner.className = 'messaging-frame-content';
    inner.src = profileUrl;
    inner.alt = characterName;
    screen.appendChild(inner);
    wrap.appendChild(screen);
    // Frame-Overlay (PNG mit transparenter Anzeigeflaeche)
    const overlay = document.createElement('img');
    overlay.className = 'messaging-frame-overlay';
    overlay.src = '/world/messaging-frame.png?t=' + (meta.generated_at || '');
    overlay.alt = '';
    wrap.appendChild(overlay);
    container.appendChild(wrap);

    _setSceneOutfitLabel(characterName);
    _updateOutfitLockButton('agent', characterName);
    _updateSceneWardrobeButton('agent', characterName);
}


// --- Character Scene ---
async function updateCharacterScene(characterName) {
    const sceneImg = document.getElementById('character-scene-img');
    if (!sceneImg) return;

    if (!characterName || characterName === 'KI') {
        sceneImg.style.display = 'none';
        sceneImg.src = '';
        const _sc = document.getElementById('character-scene');
        if (_sc) _sc.classList.remove('phone-chat-mode');
        _clearCustomFrame(_sc);
        _setSceneOutfitLabel(null);
        _updateOutfitLockButton('agent', null);
        _updateSceneWardrobeButton('agent', null);
        return;
    }

    // Phone-Chat (Avatar nicht am gleichen Ort): Profilbild in Welt-spezifischem
    // Frame (Smartphone, Spiegel, Schautafel — admin-konfigurierbar via
    // /world/messaging-frame/generate). Fallback: schmaler CSS-Default-Frame.
    const _sceneContainer = document.getElementById('character-scene');
    if (currentChatMedium === 'messaging' || currentChatMedium === 'telegram') {
        try {
            const r = await fetch(`/characters/${encodeURIComponent(characterName)}/images`);
            if (r.ok) {
                const d = await r.json();
                const profileImg = d.profile_image || '';
                if (profileImg) {
                    const profileUrl = `/characters/${encodeURIComponent(characterName)}/images/${encodeURIComponent(profileImg)}?t=${Date.now()}`;
                    await _applyMessagingFrame(_sceneContainer, sceneImg, profileUrl, characterName);
                    return;
                }
            }
        } catch (e) { /* fallthrough auf Variant-Pfad wenn Profilbild fehlt */ }
    } else {
        // Face-to-face: phone-Modus immer wieder entfernen
        if (_sceneContainer) _sceneContainer.classList.remove('phone-chat-mode');
        _clearCustomFrame(_sceneContainer);
    }

    // Expression-Variant ist die EINZIGE Quelle fuer das Scene-Bild.
    // Frueher: ohne outfit_set wurde das Profilbild als Scene angezeigt — das
    // ist falsch, das Profilbild ist nur Roster-Avatar. Wenn keine Variant da
    // ist, soll generiert werden (Backend liefert dann 202 → FE pollt) und
    // bestenfalls das letzte vorhandene Variant als Platzhalter erscheinen.
    let placeholderOutfit = null;
    try {
        const outfitsRes = await fetch(`/characters/${encodeURIComponent(characterName)}/outfits`);
        const outfits = outfitsRes.ok ? (await outfitsRes.json()).outfits || [] : [];
        placeholderOutfit = outfits.find(o => o.image) || null;
    } catch (e) { /* ignore — _loadExpressionImage haendelt das ohne Outfit */ }

    _setSceneOutfitLabel(characterName);
    _loadExpressionImage(characterName, sceneImg, placeholderOutfit);
    _updateOutfitLockButton('agent', characterName);
    _updateSceneWardrobeButton('agent', characterName);
    sceneImg.style.cursor = '';
    sceneImg.title = '';
    sceneImg.onclick = null;
}

function _setSceneOutfitLabel(characterName) {
    // Zeigt jetzt die angelegten Outfit-Teile statt des Set-Namens.
    // Leerer characterName -> Label ausblenden.
    _setEquippedPiecesLabel('character-scene-outfit', characterName);
}

async function _setEquippedPiecesLabel(elementId, characterName) {
    const el = document.getElementById(elementId);
    if (!el) return;
    const name = (characterName || '').trim();
    if (!name) { el.textContent = ''; el.style.display = 'none'; return; }
    try {
        const [eqRes, invRes] = await Promise.all([
            fetch(`/inventory/characters/${encodeURIComponent(name)}/equipped`),
            fetch(`/inventory/characters/${encodeURIComponent(name)}?include_equipped=true`),
        ]);
        if (!eqRes.ok) { el.textContent = ''; el.style.display = 'none'; return; }
        const eq = await eqRes.json();
        const inv = invRes.ok ? ((await invRes.json()).inventory || []) : [];
        const pieces = eq.equipped_pieces || {};
        const labels = [];
        // Multi-Slot-Pieces (z.B. Bikini-Bra in top + underwear_top via
        // additional_slots) tauchen unter mehreren Slot-Keys mit derselben
        // item_id auf — pro Item nur EIN Label, beim ersten Slot-Treffer.
        const seenItemIds = new Set();
        // SLOT_ORDER hat feste Reihenfolge — Label ist immer gleich sortiert
        for (const slot of SLOT_ORDER) {
            const iid = pieces[slot];
            if (!iid || seenItemIds.has(iid)) continue;
            seenItemIds.add(iid);
            const it = inv.find(x => x.item_id === iid);
            labels.push(it ? (it.item_name || iid) : iid);
        }
        if (!labels.length) {
            el.textContent = '';
            el.style.display = 'none';
        } else {
            el.textContent = `🧥 ${labels.join(', ')}`;
            el.style.display = '';
        }
    } catch (e) {
        el.textContent = '';
        el.style.display = 'none';
    }
}

// --- Expression Image Loading ---
// Getrennter State fuer Chat-Partner (NPC) und Avatar — sonst brechen sich
// die Polling-Timer gegenseitig ab.
// abortController: canceled fruehere Fetches wenn ein neuer Call kommt, damit
// stale Responses nicht das falsche Bild ueberschreiben.
const _AGENT_EXPR = { timer: null, character: null, abort: null };
const _PLAYER_EXPR = { timer: null, character: null, abort: null };

// --- Outfit-Lock (blockiert Auto-Outfit-Aenderungen) ---
// Character-Name pro Scene merken, damit der Button weiss, wen er sperren soll.
const _OUTFIT_LOCK_TARGET = { agent: null, avatar: null };

async function _updateOutfitLockButton(which, characterName) {
    // which: 'agent' | 'avatar'
    const btnId = which === 'agent' ? 'character-scene-lock' : 'player-scene-lock';
    const btn = document.getElementById(btnId);
    if (!btn) return;
    _OUTFIT_LOCK_TARGET[which] = characterName || null;
    if (!characterName) {
        btn.style.display = 'none';
        return;
    }
    try {
        const res = await fetch(`/characters/${encodeURIComponent(characterName)}/outfit-lock`);
        if (!res.ok) { btn.style.display = 'none'; return; }
        const data = await res.json();
        const locked = !!data.locked;
        btn.style.display = '';
        btn.textContent = locked ? '🔒' : '🔓';
        btn.classList.toggle('locked', locked);
        btn.title = locked ? 'Outfit gesperrt (Klick zum Entsperren)' : 'Outfit sperren (keine Auto-Aenderungen)';
    } catch (e) {
        btn.style.display = 'none';
    }
}

// Garderobe/Inventar-Buttons im Scene-Overlay (oberhalb vom Lock-Button)
// ein-/ausblenden und das Ziel-Character fuer den Klick merken.
const _WARDROBE_BTN_TARGET = { agent: null, avatar: null };
function _updateSceneWardrobeButton(which, characterName) {
    _WARDROBE_BTN_TARGET[which] = characterName || null;
    const wardrobeId = which === 'agent' ? 'character-scene-wardrobe' : 'player-scene-wardrobe';
    const invId      = which === 'agent' ? 'character-scene-inventory' : 'player-scene-inventory';
    for (const id of [wardrobeId, invId]) {
        const btn = document.getElementById(id);
        if (btn) btn.style.display = characterName ? '' : 'none';
    }
}

function openWardrobeFromScene(which) {
    const name = _WARDROBE_BTN_TARGET[which];
    if (name) openWardrobeModal(name, 'studio');
}

function openInventoryFromScene(which) {
    const name = _WARDROBE_BTN_TARGET[which];
    if (name) openWardrobeModal(name, 'inventory');
}

async function toggleOutfitLock(which) {
    const characterName = _OUTFIT_LOCK_TARGET[which];
    if (!characterName) return;
    const btnId = which === 'agent' ? 'character-scene-lock' : 'player-scene-lock';
    const btn = document.getElementById(btnId);
    if (!btn) return;
    const currentlyLocked = btn.classList.contains('locked');
    try {
        const res = await fetch(`/characters/${encodeURIComponent(characterName)}/outfit-lock`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ locked: !currentlyLocked }),
        });
        if (!res.ok) return;
        const data = await res.json();
        const locked = !!data.locked;
        btn.textContent = locked ? '🔒' : '🔓';
        btn.classList.toggle('locked', locked);
        btn.title = locked ? 'Outfit gesperrt (Klick zum Entsperren)' : 'Outfit sperren (keine Auto-Aenderungen)';
    } catch (e) { /* silent */ }
}

async function _loadExpressionImage(characterName, sceneImg, outfit, state) {
    state = state || _AGENT_EXPR;
    // fallback=default: Backend liefert das Profilbild wenn noch keine Variant
    // fertig ist. Header X-Variant-Status=fallback-default zeigt an, dass es
    // ein Platzhalter ist — dann weiter pollen bis die echte Variant kommt.
    const exprUrl = `/characters/${encodeURIComponent(characterName)}/outfit-expression`;

    // Vorherige Fetches/Timer abbrechen — verhindert dass stale Responses das
    // Bild eines neueren Characters ueberschreiben (z.B. Chat-Partner-Variant
    // im Avatar-Scene wenn schnell gewechselt wurde).
    if (state.timer) { clearTimeout(state.timer); state.timer = null; }
    if (state.abort) { try { state.abort.abort(); } catch (_) {} }
    const ctrl = new AbortController();
    state.abort = ctrl;
    state.character = characterName;

    // Solange noch nichts da ist: Outfit-Bild als Platzhalter zeigen (falls vorhanden).
    if (outfit && outfit.image) {
        sceneImg.src = `/characters/${encodeURIComponent(characterName)}/outfits/${outfit.image}?t=${Date.now()}`;
    }
    sceneImg.style.display = '';

    try {
        const resp = await fetch(exprUrl + `?fallback=default&t=${Date.now()}`, { signal: ctrl.signal });
        if (state.character !== characterName || state.abort !== ctrl) return;
        if (resp.status === 200) {
            const blob = await resp.blob();
            if (state.character !== characterName || state.abort !== ctrl) return;
            sceneImg.src = URL.createObjectURL(blob);
            // Wenn IRGENDEIN Fallback geliefert wurde (default-variant, neuestes
            // Variant, oder Profilbild) ist die echte passende Variant noch nicht
            // bereit — weiter pollen bis sie kommt. Frueher: nur 'fallback-default'
            // hat Polling getriggert, dann blieb das Profilbild fuer immer kleben.
            const _vStatus = resp.headers.get('X-Variant-Status') || '';
            if (_vStatus.startsWith('fallback-')) {
                _pollExpressionImage(characterName, sceneImg, exprUrl, 0, state);
            }
            return;
        }
        if (resp.status === 202) {
            // Kein Profilbild verfuegbar — weiter pollen.
            _pollExpressionImage(characterName, sceneImg, exprUrl, 0, state);
        }
    } catch (e) {
        // AbortError bei State-Wechsel ist erwartet; sonst Placeholder behalten.
    }
}

function _pollExpressionImage(characterName, sceneImg, exprUrl, attempt, state) {
    state = state || _AGENT_EXPR;
    if (state.timer) clearTimeout(state.timer);
    if (attempt >= 60) return;

    state.timer = setTimeout(async () => {
        state.timer = null;
        if (state.character !== characterName) return;
        // Neuen AbortController fuer diesen Poll-Versuch — so wird ein
        // laufender Fetch abgebrochen wenn der State inzwischen wechselt.
        if (state.abort) { try { state.abort.abort(); } catch (_) {} }
        const ctrl = new AbortController();
        state.abort = ctrl;
        try {
            // Ohne fallback-Param — wir wollen die echte Variant erkennen, nicht
            // wieder das Profilbild reingereicht bekommen.
            const resp = await fetch(exprUrl + `?t=${Date.now()}`, { signal: ctrl.signal });
            if (state.character !== characterName || state.abort !== ctrl) return;
            if (resp.status === 200) {
                const blob = await resp.blob();
                if (state.character !== characterName || state.abort !== ctrl) return;
                sceneImg.src = URL.createObjectURL(blob);
                return;
            }
            if (resp.status === 202) {
                _pollExpressionImage(characterName, sceneImg, exprUrl, attempt + 1, state);
            }
        } catch (e) {
            if (e && e.name === 'AbortError') return;
            _pollExpressionImage(characterName, sceneImg, exprUrl, attempt + 1, state);
        }
    }, 5000);
}

// --- Avatar Activity Picker (manuelles Setzen) ---

async function openAvatarActivityPicker(avatarName) {
    if (!avatarName) return;
    let available = [];
    let current = '';
    try {
        const [aRes, cRes] = await Promise.all([
            fetch(`/activities/available/${encodeURIComponent(avatarName)}`),
            fetch(`/characters/${encodeURIComponent(avatarName)}/current-activity`),
        ]);
        if (aRes.ok) available = (await aRes.json()).activities || [];
        if (cRes.ok) current = (await cRes.json()).current_activity || '';
    } catch (e) {}

    const overlay = document.createElement('div');
    overlay.className = 'caption-mode-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    const dialog = document.createElement('div');
    dialog.className = 'prompt-edit-dialog';
    dialog.style.maxWidth = '540px';
    dialog.style.width = 'min(540px, 92vw)';

    const list = available.length
        ? available.map(a => {
            const name = a.name || '';
            const nameDe = a.name_de || '';
            const label = nameDe || name;
            const isActive = (name === current || nameDe === current);
            return `
                <button type="button" class="avatar-act-pick"
                        data-act="${escapeHtml(name)}"
                        style="display:block;width:100%;text-align:left;padding:8px 12px;margin-bottom:4px;border-radius:6px;border:1px solid ${isActive ? 'var(--accent)' : 'var(--border)'};background:${isActive ? 'var(--bg)' : 'var(--bg-alt)'};cursor:pointer;color:var(--text);">
                    ${escapeHtml(label)}${nameDe && nameDe !== name ? ` <span style="color:var(--text-muted);font-size:11px;">(${escapeHtml(name)})</span>` : ''}
                </button>`;
        }).join('')
        : `<p class="scheduler-empty">${escapeHtml(t('No activities at the current location.'))}</p>`;

    dialog.innerHTML = `
        <div class="caption-mode-title">Aktivitaet fuer ${escapeHtml(avatarName)}</div>
        <div style="max-height:50vh;overflow-y:auto;">${list}</div>
        <label style="font-size:12px;color:var(--text-muted);margin-top:10px;">Freitext</label>
        <input type="text" class="agent-status-input avatar-act-free"
               placeholder="z.B. aus dem Fenster schauen">
        <div class="prompt-edit-actions" style="margin-top:12px;">
            <button class="prompt-edit-btn prompt-edit-cancel">Abbrechen</button>
            <button class="prompt-edit-btn prompt-edit-submit save-btn">Freitext setzen</button>
        </div>
    `;
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);

    const input = dialog.querySelector('.avatar-act-free');
    const doSave = async (value) => {
        const act = (value || '').trim();
        if (!act) return;
        try {
            const resp = await fetch(`/characters/${encodeURIComponent(avatarName)}/current-activity`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ current_activity: act }),
            });
            if (resp.ok) {
                overlay.remove();
                loadPlayerAvatar();
            } else {
                showStatusToast(t('Could not set activity'), 'error');
            }
        } catch (e) {
            showStatusToast(t('Could not set activity'), 'error');
        }
    };

    dialog.querySelectorAll('.avatar-act-pick').forEach(b => {
        b.onclick = () => doSave(b.dataset.act);
    });
    dialog.querySelector('.prompt-edit-cancel').onclick = () => overlay.remove();
    dialog.querySelector('.prompt-edit-submit').onclick = () => doSave(input.value);
    input.onkeydown = (e) => { if (e.key === 'Enter') doSave(input.value); };
}

// --- Avatar Room/Location Picker ---

async function openAvatarRoomPicker(avatarName) {
    if (!avatarName) return;
    let curLocId = '';
    let curRoomId = '';
    try {
        const curRes = await fetch(`/characters/${encodeURIComponent(avatarName)}/current-location`);
        if (curRes.ok) {
            const d = await curRes.json();
            curLocId = d.current_location_id || '';
            curRoomId = d.current_room || '';
        }
    } catch (e) {}

    // Nur die AKTUELLE Location und ihre Räume holen — kein Welt-Picker.
    let curLoc = null;
    if (curLocId) {
        try {
            const locRes = await fetch(`/world/locations?character_name=${encodeURIComponent(avatarName)}`);
            if (locRes.ok) {
                const all = (await locRes.json()).locations || [];
                curLoc = all.find(l => l.id === curLocId) || null;
            }
        } catch (e) {}
    }

    const overlay = document.createElement('div');
    overlay.className = 'caption-mode-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    const dialog = document.createElement('div');
    dialog.className = 'prompt-edit-dialog';
    dialog.style.maxWidth = '520px';
    dialog.style.width = 'min(520px, 92vw)';

    let body;
    if (!curLoc) {
        body = `<p class="scheduler-empty">${escapeHtml(t('No current location available.'))}</p>`;
    } else {
        const rooms = (curLoc.rooms || []).map(r => {
            const isCurRoom = (r.id === curRoomId);
            return `
                <button type="button" class="avatar-room-pick"
                        data-loc="${escapeHtml(curLoc.id || '')}"
                        data-room="${escapeHtml(r.id || '')}"
                        style="display:block;width:100%;text-align:left;padding:8px 12px;margin-bottom:4px;border-radius:6px;border:1px solid ${isCurRoom ? 'var(--accent)' : 'var(--border)'};background:${isCurRoom ? 'var(--bg)' : 'var(--bg-alt)'};cursor:pointer;color:var(--text);">
                    ${escapeHtml(r.name || r.id || '?')}${isCurRoom ? ' 📍' : ''}
                    ${r.description ? `<div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${escapeHtml(r.description.substring(0, 80))}${r.description.length > 80 ? '...' : ''}</div>` : ''}
                </button>`;
        }).join('');
        body = rooms || `<p class="scheduler-empty">${escapeHtml(t('No rooms at this location.'))}</p>`;
    }

    const locLabel = curLoc ? (curLoc.name || curLoc.id) : '?';
    dialog.innerHTML = `
        <div class="caption-mode-title">Raum in ${escapeHtml(locLabel)}</div>
        <div style="max-height:60vh;overflow-y:auto;">${body}</div>
        <div class="prompt-edit-actions" style="margin-top:12px;">
            <button class="prompt-edit-btn prompt-edit-cancel">Abbrechen</button>
        </div>
    `;
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);

    const doMove = async (locId, roomId) => {
        try {
            const resp = await fetch(`/characters/${encodeURIComponent(avatarName)}/current-location`, {
                method: 'POST',
                credentials: 'same-origin',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ current_location: locId, current_room: roomId }),
            });
            if (resp.ok) {
                overlay.remove();
                const _data = await resp.json().catch(() => null);
                await refreshAfterAvatarMove();
                _announceRoomEntry(_data);
            } else {
                const err = await resp.json().catch(() => ({}));
                let msg = 'Ort konnte nicht gesetzt werden';
                let blocked = false;
                if (err && err.detail) {
                    if (typeof err.detail === 'object' && err.detail.message) {
                        msg = String(err.detail.message);
                        blocked = err.detail.reason && String(err.detail.reason).startsWith('block_');
                    } else {
                        msg = String(err.detail);
                    }
                }
                if (resp.status === 403 || blocked) {
                    overlay.remove();
                    if (typeof showCharNoticeBlock === 'function') showCharNoticeBlock(msg);
                } else {
                    showStatusToast(msg, 'error');
                }
            }
        } catch (e) {
            showStatusToast(t('Could not set location'), 'error');
        }
    };

    dialog.querySelectorAll('.avatar-room-pick').forEach(b => {
        b.onclick = () => doMove(b.dataset.loc, b.dataset.room);
    });
    dialog.querySelector('.prompt-edit-cancel').onclick = () => overlay.remove();
}

// --- Avatar Mood Popover (manuelles Setzen) ---

const AVATAR_MOOD_QUICKPICKS = [
    'freudig', 'entspannt', 'gelangweilt', 'traurig',
    'gestresst', 'wuetend', 'aengstlich', 'erschoepft', 'verliebt',
];

async function openAvatarMoodPicker(avatarName) {
    if (!avatarName) return;
    let currentFeeling = '';
    try {
        const r = await fetch(`/characters/${encodeURIComponent(avatarName)}/current-feeling`);
        if (r.ok) currentFeeling = (await r.json()).current_feeling || '';
    } catch (e) {}

    const overlay = document.createElement('div');
    overlay.className = 'caption-mode-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    const dialog = document.createElement('div');
    dialog.className = 'prompt-edit-dialog';
    dialog.style.maxWidth = '420px';
    dialog.style.width = 'min(420px, 92vw)';

    const picks = AVATAR_MOOD_QUICKPICKS.map(m => `
        <button type="button" class="reset-btn mood-quickpick"
                data-mood="${escapeHtml(m)}"
                style="padding:6px 12px;border-radius:6px;font-size:13px;">
            ${escapeHtml(m)}
        </button>`).join('');

    dialog.innerHTML = `
        <div class="caption-mode-title">Stimmung fuer ${escapeHtml(avatarName)}</div>
        <label style="font-size:12px;color:var(--text-muted);">Freitext</label>
        <input type="text" class="agent-status-input mood-text-input"
               value="${escapeHtml(currentFeeling)}"
               placeholder="z.B. neugierig, entspannt, genervt...">
        <label style="font-size:12px;color:var(--text-muted);margin-top:8px;">Vorschlaege</label>
        <div style="display:flex;flex-wrap:wrap;gap:6px;">${picks}</div>
        <div class="prompt-edit-actions" style="margin-top:12px;">
            <button class="prompt-edit-btn prompt-edit-cancel">Abbrechen</button>
            <button class="prompt-edit-btn prompt-edit-submit save-btn">Setzen</button>
        </div>
    `;
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);

    const input = dialog.querySelector('.mood-text-input');
    const doSave = async (value) => {
        const mood = (value || '').trim();
        try {
            const resp = await fetch(`/characters/${encodeURIComponent(avatarName)}/current-feeling`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ current_feeling: mood }),
            });
            if (resp.ok) {
                overlay.remove();
                loadPlayerAvatar();  // refresh mood line + expression
            } else {
                showStatusToast(t('Could not set mood'), 'error');
            }
        } catch (e) {
            showStatusToast(t('Could not set mood'), 'error');
        }
    };

    dialog.querySelectorAll('.mood-quickpick').forEach(b => {
        b.onclick = () => doSave(b.dataset.mood);
    });
    dialog.querySelector('.prompt-edit-cancel').onclick = () => overlay.remove();
    dialog.querySelector('.prompt-edit-submit').onclick = () => doSave(input.value);
    input.focus();
    input.onkeydown = (e) => { if (e.key === 'Enter') doSave(input.value); };
}

// --- Room-Items Panel (rechts oben am Chat) ---
// Session-only Auswahl. Bei Raumwechsel -> Auswahl leeren, Panel neu laden.
const _roomItemsState = {
    locationId: '',
    roomId: '',
    selectedIds: new Set(),
};

function _getSelectedRoomItemIds() {
    return Array.from(_roomItemsState.selectedIds);
}

async function loadRoomItemsPanel(locationId, roomId) {
    const panelContent = document.getElementById('room-items-panel-content');
    if (!panelContent) return;

    // Raumwechsel? Auswahl leeren
    if (locationId !== _roomItemsState.locationId || roomId !== _roomItemsState.roomId) {
        _roomItemsState.selectedIds.clear();
    }
    _roomItemsState.locationId = locationId || '';
    _roomItemsState.roomId = roomId || '';

    if (!locationId || !roomId) {
        panelContent.innerHTML = '<div class="room-items-empty">Kein Raum aktiv</div>';
        return;
    }

    let items = [];
    try {
        const url = `/inventory/rooms/${encodeURIComponent(locationId)}/${encodeURIComponent(roomId)}`;
        const resp = await fetch(url);
        if (resp.ok) {
            const data = await resp.json();
            items = (data.items || []).filter(it => !it.hidden);
        }
    } catch (e) { /* empty */ }

    if (!items.length) {
        panelContent.innerHTML = `<div class="room-items-empty">${escapeHtml(t('No items in the room'))}</div>`;
        return;
    }

    panelContent.innerHTML = items.map(it => {
        const id = it.item_id || '';
        const name = it.item_name || id;
        const sel = _roomItemsState.selectedIds.has(id) ? ' selected' : '';
        const imgUrl = it.item_image
            ? `/inventory/items/${encodeURIComponent(id)}/image`
            : '';
        const imgHtml = imgUrl
            ? `<img class="room-item-card-img" src="${imgUrl}" alt="${escapeHtml(name)}">`
            : `<div class="room-item-card-img" style="display:flex;align-items:center;justify-content:center;font-size:20px;">📦</div>`;
        return `<div class="room-item-card${sel}" data-item-id="${escapeHtml(id)}" title="${escapeHtml(name)}">
            ${imgHtml}
            <div class="room-item-card-name">${escapeHtml(name)}</div>
        </div>`;
    }).join('');

    panelContent.querySelectorAll('.room-item-card').forEach(card => {
        card.onclick = () => {
            const id = card.dataset.itemId;
            if (_roomItemsState.selectedIds.has(id)) {
                _roomItemsState.selectedIds.delete(id);
                card.classList.remove('selected');
            } else {
                _roomItemsState.selectedIds.add(id);
                card.classList.add('selected');
            }
        };
    });
}

// =====================================================================
// Wardrobe-Modal — vollwertige Outfit-Verwaltung mit zwei Reitern.
// Ersetzt langfristig den alten openAvatarOutfitPicker / openGarderobePicker
// als primaere UI fuer Outfit-Wechsel + Piece-Erstellung.
// =====================================================================

const _wardrobeState = {
    character: '',
    activeTab: 'studio',
    inventory: [],
    equipped: { equipped_pieces: {}, equipped_items: [] },
    outfits: [],
    // Slots die beim Speichern des Sets "aktiv geleert" werden sollen
    // (werden beim Anziehen per unequip_piece entfernt)
    setRemoveSlots: new Set(),
    autoSyncDone: false,
    // Ephemeral Set-Editor: wenn ein Set im Dropdown ausgewaehlt ist, zeigt
    // Spalte 2 dessen Pieces (nicht den realen Equipped-State). Aenderungen
    // via Slot-/Anlegen-Buttons wandern hier rein, "Speichern" schreibt zurueck.
    // Bei leerer Dropdown-Auswahl ist setEditMode=false -> Column 2 spiegelt
    // equipped, und Buttons wirken direkt auf Real-State.
    setEditMode: false,
    setEditPieces: {}, // {slot: item_id}
    setEditColors: {}, // {slot: color}  — Farb-Overrides im Set-Editor
    // Farb-Overrides im Live-Modus die noch nicht zum Server synchronisiert
    // wurden (bei sofort-Speicherung nicht nötig, aber Cache fuer Rendering).
    liveColorDraft: {}, // reserved
    // Filter in Spalte 3 (Inventar): "" = alle, sonst outfit_type-Wert
    availableFilter: '',
    availableOutfitTypeFilter: '',
};

function openWardrobeModal(characterName, startTab) {
    if (!characterName) return;
    _wardrobeState.character = characterName;
    _wardrobeState.autoSyncDone = false;
    _wardrobeState.setRemoveSlots = new Set();
    _wardrobeState.availableFilter = '';
    _wardrobeState.availableOutfitTypeFilter = '';
    // (Slot-Wechsel-Binding entfaellt — _renderWpcSlots verdrahtet die
    // Cover-Aktualisierung jetzt direkt ueber den onChange-Callback der
    // Slot-Tag-Picker.)
    document.getElementById('wardrobe-char-name').textContent = characterName;
    document.getElementById('wardrobe-modal').style.display = 'flex';
    switchWardrobeTab(startTab || 'studio');
    _loadWardrobeData().then(() => _loadWardrobePreview(characterName));
    _loadOutfitTypeSuggestions();
}

function closeWardrobeModal() {
    document.getElementById('wardrobe-modal').style.display = 'none';
}

function switchWardrobeTab(tab) {
    _wardrobeState.activeTab = tab;
    document.querySelectorAll('#wardrobe-modal .memory-tab').forEach(b => {
        b.classList.toggle('active', b.dataset.wtab === tab);
    });
    const tabs = {
        studio: document.getElementById('wardrobe-tab-studio'),
        pieces: document.getElementById('wardrobe-tab-pieces'),
        inventory: document.getElementById('wardrobe-tab-inventory'),
        rules: document.getElementById('wardrobe-tab-rules'),
    };
    for (const [key, el] of Object.entries(tabs)) {
        if (!el) continue;
        el.classList.toggle('active', tab === key);
        el.style.removeProperty('display');
    }
    // Lazy-Load: Inventar-Tab beim erstmaligen Oeffnen befuellen.
    if (tab === 'inventory') {
        const charName = _wardrobeState.character;
        if (charName) {
            _loadEditorInventory(charName);
            _populateEditorInventoryItemDropdown();
        }
    }
    if (tab === 'rules') {
        loadWardrobeRulesTab();
    }
    // Pieces-Tab: Form-Defaults rendern wenn nicht schon ein Item ausgewaehlt
    if (tab === 'pieces' && !_wardrobeState.previewItemId) {
        _wardrobeFormReset();
    }
}

async function loadWardrobeRulesTab() {
    const char = _wardrobeState.character;
    if (!char) return;
    const statusEl = document.getElementById('wardrobe-rules-compliance');
    const matrixEl = document.getElementById('wardrobe-rules-exceptions');
    try {
        const _t = Date.now();
        const [cRes, rRes, eRes] = await Promise.all([
            fetch(`/characters/${encodeURIComponent(char)}/outfit-compliance?t=${_t}`, {cache: 'no-store'}),
            fetch(`/characters/outfit-rules?t=${_t}`, {cache: 'no-store'}),
            fetch(`/characters/${encodeURIComponent(char)}/outfit-exceptions?t=${_t}`, {cache: 'no-store'}),
        ]);
        const compliance = cRes.ok ? await cRes.json() : {};
        const rules = rRes.ok ? await rRes.json() : { outfit_types: {} };
        const excData = eRes.ok ? await eRes.json() : { exceptions: {} };
        const exceptions = excData.exceptions || {};

        // Compliance-Banner
        const missing = compliance.missing || [];
        const equipped = compliance.equipped || [];
        const req = compliance.required || [];
        const typeInfo = compliance.outfit_type
            ? `<b>${escapeHtml(compliance.outfit_type)}</b>`
            : '<i>(kein outfit_type gesetzt)</i>';
        const locInfo = compliance.location
            ? ` @ ${escapeHtml(compliance.location)}${compliance.room ? ' / ' + escapeHtml(compliance.room) : ''}`
            : '';
        let banner = `<div style="color:var(--text);"><b>Aktueller Ort:</b> ${locInfo || '—'}<br><b>outfit_type:</b> ${typeInfo}</div>`;
        banner += `<div style="margin-top:6px;color:var(--text);"><b>${escapeHtml(t('Required:'))}</b> ${req.length ? req.map(s => `<span style="display:inline-block;padding:1px 6px;margin:0 2px;background:${equipped.includes(s) ? '#2a4a2a' : '#5a2a2a'};color:#fff;border-radius:3px;font-size:11px;">${escapeHtml(SLOT_LABELS_DE[s] || s)}</span>`).join('') : '—'}</div>`;
        if (missing.length) {
            banner += `<div style="margin-top:6px;color:#ff9a73;"><b>Fehlt:</b> ${missing.map(s => escapeHtml(SLOT_LABELS_DE[s] || s)).join(', ')}</div>`;
        } else if (req.length) {
            banner += `<div style="margin-top:6px;color:#8fd17f;">Vollstaendig angezogen.</div>`;
        }
        statusEl.innerHTML = banner;

        // Matrix outfit_type × slot, Haken = skip_required (Ausnahme aktiv)
        const allSlots = SLOT_ORDER;
        const types = Object.keys(rules.outfit_types || {}).sort((a, b) => a.localeCompare(b));
        let tbl = '<table style="border-collapse:collapse;font-size:12px;color:var(--text);">';
        tbl += '<thead><tr><th style="text-align:left;padding:4px 8px;border-bottom:1px solid var(--border);color:var(--text);">outfit_type</th>';
        for (const s of allSlots) {
            tbl += `<th style="padding:4px 6px;border-bottom:1px solid var(--border);color:var(--text);">${escapeHtml(SLOT_LABELS_DE[s] || s)}</th>`;
        }
        tbl += '</tr></thead><tbody>';
        for (const t of types) {
            const baseline = new Set((rules.outfit_types[t] || {}).required || []);
            const skip = new Set(((exceptions[t] || {}).skip_required) || []);
            tbl += `<tr><td style="padding:4px 8px;color:var(--text);"><b>${escapeHtml(t)}</b></td>`;
            for (const s of allSlots) {
                const inBaseline = baseline.has(s);
                const isSkipped = skip.has(s);
                if (!inBaseline) {
                    tbl += '<td style="padding:4px 6px;text-align:center;color:var(--text-muted);">·</td>';
                } else {
                    tbl += `<td style="padding:4px 6px;text-align:center;"><input type="checkbox" data-type="${escapeHtml(t)}" data-slot="${escapeHtml(s)}"${isSkipped ? ' checked' : ''} title="Haken = Ausnahme aktiv (Slot wird bei ${escapeHtml(t)} NICHT verlangt)"></td>`;
                }
            }
            tbl += '</tr>';
        }
        tbl += '</tbody></table>';
        tbl += '<p style="font-size:11px;color:var(--text-muted);margin-top:8px;">Punkt = Slot ist bei diesem outfit_type ohnehin nicht required. Checkbox = optional Ausnahme setzen.</p>';
        matrixEl.innerHTML = tbl;
    } catch (e) {
        statusEl.innerHTML = `<span style="color:var(--error-color,#e74c3c);">Fehler: ${escapeHtml(e.message)}</span>`;
    }
}

async function saveWardrobeExceptions() {
    const char = _wardrobeState.character;
    if (!char) return;
    const status = document.getElementById('wardrobe-rules-status');
    const cbs = document.querySelectorAll('#wardrobe-rules-exceptions input[type="checkbox"]');
    const byType = {};
    for (const cb of cbs) {
        if (!cb.checked) continue;
        const t = cb.dataset.type;
        const s = cb.dataset.slot;
        if (!byType[t]) byType[t] = { skip_required: [], reason: '' };
        byType[t].skip_required.push(s);
    }
    try {
        const r = await fetch(`/characters/${encodeURIComponent(char)}/outfit-exceptions`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ exceptions: byType }),
        });
        if (r.ok) {
            status.textContent = 'Gespeichert.';
            status.style.color = 'var(--text-muted)';
            await loadWardrobeRulesTab();  // Neu rendern damit Compliance-Banner aktualisiert
            setTimeout(() => { if (status.textContent === 'Gespeichert.') status.textContent = ''; }, 2500);
        } else {
            status.textContent = 'Fehler beim Speichern';
            status.style.color = 'var(--error-color,#e74c3c)';
        }
    } catch (e) {
        status.textContent = 'Verbindungsfehler: ' + e.message;
        status.style.color = 'var(--error-color,#e74c3c)';
    }
}

async function _loadWardrobeData() {
    const c = _wardrobeState.character;
    if (!c) return;
    try {
        const _t = Date.now();
        const [invRes, eqRes, outRes] = await Promise.all([
            fetch(`/inventory/characters/${encodeURIComponent(c)}?include_equipped=true&t=${_t}`, {cache: 'no-store'}),
            fetch(`/inventory/characters/${encodeURIComponent(c)}/equipped?t=${_t}`, {cache: 'no-store'}),
            fetch(`/characters/${encodeURIComponent(c)}/outfits?t=${_t}`, {cache: 'no-store'}),
        ]);
        _wardrobeState.inventory = invRes.ok ? ((await invRes.json()).inventory || []) : [];
        _wardrobeState.equipped = eqRes.ok ? (await eqRes.json()) : { equipped_pieces: {}, equipped_items: [] };
        _wardrobeState.outfits = outRes.ok ? ((await outRes.json()).outfits || []) : [];
    } catch (e) {
        showStatusToast(t('Could not load wardrobe'), 'error');
    }

    _renderWardrobeStudio();
    _renderWardrobeInventory();
    _renderWardrobeSetSelect();
    // KEIN _loadWardrobePreview hier — wird nur von expliziten Triggern
    // aufgerufen (Modal-Open, Set-Wechsel, Equip/Unequip, Refresh-Button).
}

function _wardrobePieces() {
    return _wardrobeState.inventory.filter(it => it.item_category === 'outfit_piece');
}

function _updateWardrobePreviewLabel() {
    const el = document.getElementById('wardrobe-preview-label');
    if (!el) return;
    // Zeigt den effektiven Prompt wie er in die Bild-Generierung einfliesst,
    // inkl. covers (rausfallen), partially_covers ("X underneath Y") und
    // Farb-Overrides (wird dem Fragment vorangestellt).
    const pieces = _wardrobeState.setEditMode
        ? (_wardrobeState.setEditPieces || {})
        : (_wardrobeState.equipped.equipped_pieces || {});
    const inv = _wardrobePieces();
    // Farb-Quelle: im Edit-Mode aus setEditColors (pending), sonst live-Meta
    const colorSrc = _wardrobeState.setEditMode
        ? (_wardrobeState.setEditColors || {})
        : Object.fromEntries(Object.entries(
            _wardrobeState.equipped.equipped_pieces_meta || {}
          ).map(([s, m]) => [s, (m && m.color) || '']));
    const _slotColor = (s) => ((colorSrc[s] || '') + '').trim();

    // 1) covers + partially_covers sammeln (Farbe geht in covering-frag mit rein).
    //    Multi-Slot-Pieces nur einmal verarbeiten — beim ersten Slot in SLOT_ORDER.
    const coveredSlots = new Set();
    const partiallyCovered = {}; // slot → {frag, slot}
    const seenItemsForCovers = new Set();
    for (const slot of SLOT_ORDER) {
        const iid = pieces[slot];
        if (!iid || seenItemsForCovers.has(iid)) continue;
        seenItemsForCovers.add(iid);
        const it = inv.find(p => p.item_id === iid);
        if (!it || !it.outfit_piece) continue;
        let coveringFrag = (it.item_prompt_fragment || '').trim();
        const cColor = _slotColor(slot);
        if (cColor && coveringFrag) coveringFrag = `${cColor} ${coveringFrag}`;
        for (const c of (it.outfit_piece.covers || [])) {
            if (c) coveredSlots.add(c);
        }
        for (const c of (it.outfit_piece.partially_covers || [])) {
            if (c && coveringFrag) partiallyCovered[c] = { frag: coveringFrag, slot };
        }
    }

    // Slots deren Fragment bereits im "underneath"-Teil eines anderen Slots
    // enthalten ist — nur unterdruecken wenn der Ziel-Slot belegt ist.
    const suppressedSlots = new Set();
    for (const [targetSlot, info] of Object.entries(partiallyCovered)) {
        if (pieces[targetSlot]) suppressedSlots.add(info.slot);
    }

    // 2) Fragments mit covers/partially_covers Logik + Farben aufbauen.
    //    Multi-Slot-Pieces werden nur EINMAL gerendert — im ersten Slot, der
    //    in SLOT_ORDER auftaucht (Render-Slot).
    const fragments = [];
    const renderedItems = new Set();
    for (const slot of SLOT_ORDER) {
        if (coveredSlots.has(slot)) continue;
        if (suppressedSlots.has(slot)) continue;
        const iid = pieces[slot];
        if (!iid) continue;
        if (renderedItems.has(iid)) continue;
        const it = inv.find(p => p.item_id === iid);
        if (!it) continue;
        renderedItems.add(iid);
        let frag = (it.item_prompt_fragment || '').trim();
        if (!frag) continue;
        const color = _slotColor(slot);
        if (color) frag = `${color} ${frag}`;
        if (partiallyCovered[slot]) {
            frag = `${frag} underneath ${partiallyCovered[slot].frag}`;
        }
        fragments.push(frag);
    }
    if (!fragments.length) {
        el.textContent = '— kein Prompt —';
    } else {
        el.textContent = fragments.join(', ');
    }
}

function _renderWardrobeAvailableFilter() {
    const el = document.getElementById('wardrobe-available-filter');
    if (!el) return;
    // Zwei Filter-Reihen:
    //   Reihe 1: Slot-Filter (top, head, chest, ...) — nur Slots die tatsaechlich
    //            in den Inventar-Pieces vorkommen, in SLOT_ORDER-Reihenfolge.
    //   Reihe 2: Outfit-Type-Filter (casual, formal, athletic, ...) — alle
    //            Outfit-Types die in den Inventar-Pieces vorkommen, alphabetisch.
    const presentSlots = new Set();
    const presentOutfitTypes = new Set();
    for (const it of _wardrobeState.inventory) {
        if (it.item_category !== 'outfit_piece') continue;
        for (const s of ((it.outfit_piece && it.outfit_piece.slots) || [])) {
            if (s) presentSlots.add(s);
        }
        for (const ot of ((it.outfit_piece && it.outfit_piece.outfit_types) || [])) {
            const _t = (ot || '').toString().trim();
            if (_t) presentOutfitTypes.add(_t);
        }
    }
    const slots = SLOT_ORDER.filter(s => presentSlots.has(s));
    const outfitTypes = Array.from(presentOutfitTypes).sort(
        (a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));
    const curSlot = _wardrobeState.availableFilter || '';
    const curType = _wardrobeState.availableOutfitTypeFilter || '';

    let html = '<div class="wardrobe-filter-row">';
    html += `<button class="${!curSlot ? 'active' : ''}" data-slot="">${escapeHtml(t('All'))}</button>`;
    for (const s of slots) {
        const active = curSlot === s;
        const label = SLOT_LABELS_DE[s] || s;
        html += `<button class="${active ? 'active' : ''}" data-slot="${escapeHtml(s)}">${escapeHtml(label)}</button>`;
    }
    html += '</div>';

    if (outfitTypes.length) {
        html += '<div class="wardrobe-filter-row">';
        html += `<button class="${!curType ? 'active' : ''}" data-otype="">${escapeHtml(t('All types'))}</button>`;
        for (const ot of outfitTypes) {
            const active = curType === ot;
            html += `<button class="${active ? 'active' : ''}" data-otype="${escapeHtml(ot)}">${escapeHtml(ot)}</button>`;
        }
        html += '</div>';
    }
    el.innerHTML = html;

    el.querySelectorAll('button[data-slot]').forEach(b => {
        b.onclick = () => {
            _wardrobeState.availableFilter = b.dataset.slot || '';
            _renderWardrobeStudio();
        };
    });
    el.querySelectorAll('button[data-otype]').forEach(b => {
        b.onclick = () => {
            _wardrobeState.availableOutfitTypeFilter = b.dataset.otype || '';
            _renderWardrobeStudio();
        };
    });
}

function _wardrobeItemImg(itemId) {
    return `/inventory/items/${encodeURIComponent(itemId)}/image?t=${Date.now()}`;
}

