function _colorSwatchForName(name) {
    // Leerer Name -> "keine Farbe" Eintrag (style=none)
    const target = name || '';
    return WARDROBE_COLOR_PALETTE.find(c => (c.name || '') === target) || null;
}

// Liefert das CSS background-Style (inklusive background-size wo noetig) fuer
// einen Swatch-Eintrag.
function _swatchCss(c) {
    if (!c) return 'background:transparent;';
    const style = c.style || 'solid';
    if (style === 'solid') {
        return `background:${c.hex || 'transparent'};`;
    }
    if (style === 'none') {
        // Weiss mit rotem Diagonalstrich (oben-rechts nach unten-links)
        return 'background:linear-gradient(225deg, #ffffff 0 calc(50% - 1.5px), #e02020 calc(50% - 1.5px) calc(50% + 1.5px), #ffffff calc(50% + 1.5px) 100%);';
    }
    if (style === 'transparent') {
        // Schachbrett (hell/dunkelgrau) — Standard-Transparenz-Indikator
        return (
            'background:' +
            'linear-gradient(45deg, #bbb 25%, transparent 25% 75%, #bbb 75%),' +
            'linear-gradient(45deg, transparent 25%, #bbb 25% 75%, transparent 75%);' +
            'background-size:8px 8px;' +
            'background-position:0 0, 4px 4px;' +
            'background-color:#fff;'
        );
    }
    if (style === 'semi') {
        // Schachbrett + halbtransparente Farbflaeche drueber (z.B. blau)
        return (
            'background:' +
            'linear-gradient(rgba(100,160,230,0.55), rgba(100,160,230,0.55)),' +
            'linear-gradient(45deg, #bbb 25%, transparent 25% 75%, #bbb 75%),' +
            'linear-gradient(45deg, transparent 25%, #bbb 25% 75%, transparent 75%);' +
            'background-size:auto, 8px 8px, 8px 8px;' +
            'background-position:0 0, 0 0, 4px 4px;' +
            'background-color:#fff;'
        );
    }
    return 'background:transparent;';
}

function _renderColorDot(colorName, slot) {
    // Kein Meta-Eintrag vorhanden -> 🎨 Placeholder (Farbe setzen)
    if (!colorName) {
        return `<button class="wardrobe-color-dot" data-slot="${escapeHtml(slot)}"
            title="Farbe setzen"
            style="width:22px;height:22px;border-radius:50%;background:transparent;border:1px dashed rgba(255,255,255,0.35);cursor:pointer;padding:0;font-size:11px;line-height:20px;display:inline-flex;align-items:center;justify-content:center;">🎨</button>`;
    }
    // Meta-Eintrag vorhanden -> Swatch entsprechend dem Style/Hex
    const c = _colorSwatchForName(colorName);
    const title = c ? `Farbe: ${c.label} (${c.name || 'keine'})` : `Farbe: ${colorName}`;
    const bgCss = c ? _swatchCss(c) : `background:${colorName};`;
    const sym = c && (c.style === 'none' || c.style === 'transparent' || c.style === 'semi') ? (c.symbol || '') : '';
    return `<button class="wardrobe-color-dot" data-slot="${escapeHtml(slot)}"
        title="${escapeHtml(title)}"
        style="width:22px;height:22px;border-radius:50%;${bgCss}border:1px solid rgba(255,255,255,0.25);cursor:pointer;padding:0;font-size:11px;line-height:20px;display:inline-flex;align-items:center;justify-content:center;color:#222;text-shadow:0 0 2px #fff;">${escapeHtml(sym)}</button>`;
}

function _closeColorPopover() {
    const existing = document.getElementById('wardrobe-color-popover');
    if (existing) existing.remove();
    document.removeEventListener('click', _colorPopoverOutside, true);
}

function _colorPopoverOutside(e) {
    const pop = document.getElementById('wardrobe-color-popover');
    if (!pop) return;
    if (pop.contains(e.target)) return;
    if (e.target.classList && e.target.classList.contains('wardrobe-color-dot')) return;
    _closeColorPopover();
}

function _openColorPopover(anchorBtn, slot, currentColor) {
    _closeColorPopover();
    const pop = document.createElement('div');
    pop.id = 'wardrobe-color-popover';
    pop.style.cssText = [
        'position:absolute', 'z-index:10000',
        'background:#161b22', 'border:1px solid #30363d', 'border-radius:8px',
        'padding:8px', 'box-shadow:0 8px 24px rgba(0,0,0,0.5)',
        'max-width:280px',
    ].join(';');
    // Grid
    let swatches = '';
    for (const c of WARDROBE_COLOR_PALETTE) {
        const isActive = (c.name || '') === (currentColor || '');
        const ring = isActive ? 'box-shadow:0 0 0 2px #58a6ff;' : '';
        const style = c.style || 'solid';
        const bgCss = _swatchCss(c);
        // Symbole nur fuer die 3 speziellen Eintraege, sonst leer
        const sym = (style === 'none' || style === 'transparent' || style === 'semi')
            ? (c.symbol || '')
            : '';
        swatches += `<button class="wardrobe-color-swatch" data-color="${escapeHtml(c.name)}"
            title="${escapeHtml(c.label)} (${escapeHtml(c.name || 'keine')})"
            style="width:24px;height:24px;border-radius:4px;border:1px solid rgba(255,255,255,0.15);${bgCss}cursor:pointer;padding:0;font-size:12px;color:#222;text-shadow:0 0 2px #fff;${ring}">${escapeHtml(sym)}</button>`;
    }
    pop.innerHTML = `<div style="display:grid;grid-template-columns:repeat(9,24px);gap:4px;">${swatches}</div>`;
    document.body.appendChild(pop);
    // Position: directly under the anchor button
    const rect = anchorBtn.getBoundingClientRect();
    pop.style.left = Math.max(6, Math.min(window.innerWidth - pop.offsetWidth - 6, rect.left)) + 'px';
    pop.style.top  = (window.scrollY + rect.bottom + 6) + 'px';
    // Bind swatch clicks
    pop.querySelectorAll('.wardrobe-color-swatch').forEach(btn => {
        btn.onclick = async (ev) => {
            ev.stopPropagation();
            const color = btn.dataset.color || '';
            _closeColorPopover();
            await _wardrobeSetPieceColor(slot, color);
        };
    });
    // Outside-click → schliessen
    setTimeout(() => document.addEventListener('click', _colorPopoverOutside, true), 0);
}

async function _wardrobeSetPieceColor(slot, color) {
    const c = _wardrobeState.character;
    if (!c) return;

    // Set-Editor-Modus: nur lokalen State anpassen, wirkt erst beim Anziehen.
    if (_wardrobeState.setEditMode) {
        if (!_wardrobeState.setEditColors) _wardrobeState.setEditColors = {};
        if (color) {
            _wardrobeState.setEditColors[slot] = color;
        } else {
            delete _wardrobeState.setEditColors[slot];
        }
        _renderWardrobeStudio();
        return;
    }

    // Live-Modus: sofort zum Server
    try {
        const resp = await fetch(
            `/inventory/characters/${encodeURIComponent(c)}/pieces/${encodeURIComponent(slot)}/color`,
            {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ color }),
            }
        );
        if (!resp.ok) {
            const d = await resp.json().catch(() => ({}));
            showStatusToast(t('Color') + `: ${d.detail || t('Error')}`, 'error');
            return;
        }
        const meta = _wardrobeState.equipped.equipped_pieces_meta || {};
        if (color) {
            meta[slot] = Object.assign({}, meta[slot] || {}, { color });
        } else {
            delete meta[slot];
        }
        _wardrobeState.equipped.equipped_pieces_meta = meta;
        _renderWardrobeStudio();
        _loadWardrobePreview(_wardrobeState.character);
    } catch (e) {
        showStatusToast(t('Color') + `: ${e.message || e}`, 'error');
    }
}

function _renderWardrobeStudio() {
    const c = _wardrobeState.character;
    if (!c) return;

    // 1) Preview-Label aktualisieren (kein auto-Refresh des Bildes —
    // der User klickt manuell "Aktualisieren" in Spalte 2).
    _updateWardrobePreviewLabel();
    // Set-Dropdown auf passendes Preset syncen (nur nach Equip/Unequip, d.h.
    // nach jedem Studio-Rerender). Kein Backend-Match — reine UI-Logik.
    _syncSetSelectToEquipped();

    // 2) Equipped — feste Slot-Liste. Zwei Modi:
    //   - Live: zeigt real-equipped, Buttons ruft Backend equip/unequip
    //   - Set-Edit: zeigt setEditPieces, Buttons bearbeiten den Edit-State
    //   Slot-Button State-Machine:
    //     equipped -> (click) -> empty
    //     empty    -> (click) -> remove
    //     remove   -> (click) -> empty
    const equippedEl = document.getElementById('wardrobe-equipped');
    if (equippedEl) {
        const pieces = _wardrobePieces();
        const editMode = !!_wardrobeState.setEditMode;
        const eq = editMode
            ? (_wardrobeState.setEditPieces || {})
            : (_wardrobeState.equipped.equipped_pieces || {});
        const rows = SLOT_ORDER.map(slot => {
            const itemId = eq[slot] || '';
            const it = itemId ? pieces.find(p => p.item_id === itemId) : null;
            const isRemove = _wardrobeState.setRemoveSlots.has(slot);
            // Mirror-Slot? Multi-Slot-Pieces werden im ersten ihrer slots
            // (in SLOT_ORDER-Reihenfolge) gerendert; alle weiteren Slots
            // sind Mirror-Slots und werden dezent dargestellt.
            const itemSlots = it ? ((it.outfit_piece && it.outfit_piece.slots) || []) : [];
            const renderSlot = itemSlots.length
                ? (SLOT_ORDER.find(s => itemSlots.includes(s)) || '')
                : '';
            const isMirror = it && renderSlot && renderSlot !== slot;

            let state, icon, title;
            if (isMirror) {
                state = 'mirror'; icon = '✕'; title = `Multi-Slot-Teil "${it.item_name}" — Klick loest gesamtes Teil ab`;
            } else if (it) {
                state = 'equipped'; icon = '✕'; title = 'Entfernen (Slot leeren)';
            } else if (isRemove) {
                state = 'remove'; icon = '⊘'; title = 'Entfernen (Markierung aufheben)';
            } else {
                state = 'empty'; icon = '◯'; title = 'Slot als "aktiv leeren" markieren';
            }
            const actionBtn = `<button class="reset-btn wardrobe-slot-action"
                data-slot="${escapeHtml(slot)}" data-state="${state}"
                title="${title}" style="padding:2px 8px;font-size:11px;">${icon}</button>`;

            if (it) {
                if (isMirror) {
                    // Multi-Slot-Teil im Mirror-Slot: Item-Name dezent dargestellt
                    // (italic + Graustufe). Kein zusaetzliches Badge — alle Slots
                    // sind unter dem symmetrischen Modell gleichberechtigt; das
                    // Item taucht in allen seinen Slots auf, wird aber nur einmal
                    // mit voller Farbe gerendert (im ersten Slot in SLOT_ORDER).
                    return `<div class="wardrobe-slot-row wardrobe-slot-mirror" data-slot="${escapeHtml(slot)}" style="opacity:0.78;">
                        <div class="wardrobe-slot-label">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
                        <div class="wardrobe-slot-piece">
                            ${it.item_image
                                ? `<img class="wardrobe-slot-img" src="${_wardrobeItemImg(it.item_id)}" alt="" style="filter:grayscale(0.4);">`
                                : `<div class="wardrobe-slot-img" style="display:flex;align-items:center;justify-content:center;font-size:18px;">📦</div>`}
                            <span class="wardrobe-slot-name" style="font-style:italic;">${escapeHtml(it.item_name || it.item_id)}</span>
                        </div>
                        ${actionBtn}
                    </div>`;
                }
                // Farb-Swatch nur fuer "generic" Rarity — alle hoeheren haben feste Farbe im Prompt
                const rarity = (it.item_rarity || 'common').toLowerCase();
                const metaColor = editMode
                    ? (_wardrobeState.setEditColors?.[slot] || '')
                    : (((_wardrobeState.equipped.equipped_pieces_meta || {})[slot] || {}).color || '');
                const colorDot = rarity === 'generic' ? _renderColorDot(metaColor, slot) : '';
                return `<div class="wardrobe-slot-row" data-slot="${escapeHtml(slot)}">
                    <div class="wardrobe-slot-label">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
                    <div class="wardrobe-slot-piece">
                        ${it.item_image
                            ? `<img class="wardrobe-slot-img" src="${_wardrobeItemImg(it.item_id)}" alt="">`
                            : `<div class="wardrobe-slot-img" style="display:flex;align-items:center;justify-content:center;font-size:18px;">📦</div>`}
                        <span class="wardrobe-slot-name">${escapeHtml(it.item_name || it.item_id)}</span>
                    </div>
                    ${colorDot}
                    ${actionBtn}
                </div>`;
            }
            return `<div class="wardrobe-slot-row empty${isRemove ? ' marked-remove' : ''}" data-slot="${escapeHtml(slot)}">
                <div class="wardrobe-slot-label">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
                <div class="wardrobe-slot-piece"><span class="wardrobe-slot-empty">${isRemove ? '⊘ aktiv leeren' : '— leer —'}</span></div>
                ${actionBtn}
            </div>`;
        }).join('');
        // Equipped Items (nur im Live-Modus sichtbar — Sets tragen keine
        // Ausruestungs-Items in der aktuellen Datenstruktur).
        const eqItems = editMode ? [] : (_wardrobeState.equipped.equipped_items || []);
        const eqItemRows = eqItems.length ? eqItems.map(iid => {
            const it = _wardrobeState.inventory.find(x => x.item_id === iid);
            if (!it) return '';
            return `<div class="wardrobe-slot-row" data-item="${escapeHtml(iid)}">
                <div class="wardrobe-slot-label">Ausruestung</div>
                <div class="wardrobe-slot-piece">
                    ${it.item_image
                        ? `<img class="wardrobe-slot-img" src="${_wardrobeItemImg(iid)}" alt="">`
                        : `<div class="wardrobe-slot-img" style="display:flex;align-items:center;justify-content:center;font-size:18px;">🔧</div>`}
                    <span class="wardrobe-slot-name">${escapeHtml(it.item_name || iid)}</span>
                </div>
                <button class="reset-btn wardrobe-unequip-item" data-item="${escapeHtml(iid)}" title="Ablegen" style="padding:2px 8px;font-size:11px;">✕</button>
            </div>`;
        }).join('') : '';
        const modeHint = editMode
            ? `<div style="font-size:11px;color:var(--text-muted);font-style:italic;margin-bottom:4px;">Set-Editor — Aenderungen greifen erst nach "Speichern" bzw. "Anziehen".</div>`
            : '';
        equippedEl.innerHTML = modeHint + rows + eqItemRows;
        equippedEl.querySelectorAll('.wardrobe-unequip-item').forEach(b => {
            b.onclick = () => _wardrobeUnequip({ item_id: b.dataset.item });
        });
        equippedEl.querySelectorAll('.wardrobe-color-dot').forEach(btn => {
            btn.onclick = (ev) => {
                ev.stopPropagation();
                const slot = btn.dataset.slot;
                const metaColor = ((_wardrobeState.equipped.equipped_pieces_meta || {})[slot] || {}).color || '';
                _openColorPopover(btn, slot, metaColor);
            };
        });
        equippedEl.querySelectorAll('.wardrobe-slot-action').forEach(b => {
            b.onclick = () => {
                const slot = b.dataset.slot;
                const state = b.dataset.state;
                if (state === 'equipped' || state === 'mirror') {
                    _wardrobeState.setRemoveSlots.delete(slot);
                    if (editMode) {
                        // Im Set-Editor: item_id des Slots kennen, um alle Spiegel-
                        // Slots zu leeren (Mirror-Slots halten dieselbe item_id).
                        const iid = (_wardrobeState.setEditPieces || {})[slot];
                        if (iid) {
                            for (const s of Object.keys(_wardrobeState.setEditPieces)) {
                                if (_wardrobeState.setEditPieces[s] === iid) {
                                    delete _wardrobeState.setEditPieces[s];
                                }
                            }
                        } else {
                            delete _wardrobeState.setEditPieces[slot];
                        }
                        _renderWardrobeStudio();
                        _loadWardrobePreview(_wardrobeState.character);
                    } else {
                        _wardrobeUnequip({ slot });
                    }
                } else if (state === 'empty') {
                    _wardrobeState.setRemoveSlots.add(slot);
                    _renderWardrobeStudio();
                } else if (state === 'remove') {
                    _wardrobeState.setRemoveSlots.delete(slot);
                    _renderWardrobeStudio();
                }
            };
        });
    }

    // 3) Verfuegbar im Inventar — Pieces + Items mit prompt_fragment.
    // Generische Items wie Schluessel ohne Fragment gehoeren nicht in die
    // Garderobe.
    _renderWardrobeAvailableFilter();
    const availEl = document.getElementById('wardrobe-available');
    if (availEl) {
        const editMode2 = !!_wardrobeState.setEditMode;
        const eqPieceIds = editMode2
            ? new Set(Object.values(_wardrobeState.setEditPieces || {}))
            : new Set(Object.values(_wardrobeState.equipped.equipped_pieces || {}));
        const eqItemSet = editMode2
            ? new Set()
            : new Set(_wardrobeState.equipped.equipped_items || []);
        const filter = (_wardrobeState.availableFilter || '').trim();
        const otypeFilter = (_wardrobeState.availableOutfitTypeFilter || '').trim();
        const allItems = _wardrobeState.inventory.filter(it => {
            const isPiece = it.item_category === 'outfit_piece';
            const hasFragment = !!(it.item_prompt_fragment || '').trim();
            // Im Set-Editor sind nur outfit_pieces zulaessig (Sets kennen
            // keine generischen Equipped-Items). Live-Modus: outfit_pieces
            // UND alles was ein prompt_fragment hat (Spells, Tools, ...)
            // — sonst wuerde das Anlegen-Panel sie nie zeigen.
            if (editMode2) {
                if (!isPiece) return false;
            } else {
                if (!isPiece && !hasFragment) return false;
            }
            // Slot- und Outfit-Type-Filter gelten nur fuer outfit_pieces;
            // bei Equipment-Items ohne Slot-Schema ueberspringen.
            if (filter && isPiece) {
                const slots = (it.outfit_piece && it.outfit_piece.slots) || [];
                if (!slots.includes(filter)) return false;
            }
            if (otypeFilter && isPiece) {
                const types = (it.outfit_piece && it.outfit_piece.outfit_types) || [];
                if (!types.includes(otypeFilter)) return false;
            }
            return true;
        });
        if (!allItems.length) {
            availEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No equippable items in inventory. Outfit pieces and any item with a prompt fragment can be equipped.'))}</p>`;
        } else {
            availEl.innerHTML = allItems.map(it => {
                const isPiece = it.item_category === 'outfit_piece';
                const itemSlots = isPiece ? ((it.outfit_piece && it.outfit_piece.slots) || []) : [];
                const slot = itemSlots[0] || '';
                const slotLabel = itemSlots.map(s => SLOT_LABELS_DE[s] || s).join(' + ');
                const hasFragment = !!(it.item_prompt_fragment || '').trim();
                const equipped = isPiece ? eqPieceIds.has(it.item_id) : eqItemSet.has(it.item_id);
                // Im Set-Edit-Modus sind nur Pieces zulaessig (Sets kennen
                // aktuell keine generischen Equipped-Items).
                const equippable = editMode2 ? isPiece : (isPiece || hasFragment);
                let metaText = '';
                if (isPiece) metaText = slotLabel || '— ohne Slot —';
                else if (hasFragment) metaText = 'Ausruestung';
                else metaText = `${it.item_category || 'Item'} · kein Prompt-Text`;
                let actionBtn = '';
                if (equipped) {
                    actionBtn = `<button disabled title="Bereits im Slot — entfernen ueber den Slot-Button in Spalte 2" style="opacity:0.4;cursor:not-allowed;">angelegt</button>`;
                } else if (equippable) {
                    actionBtn = `<button class="wardrobe-card-equip save-btn" data-item="${escapeHtml(it.item_id)}">Anlegen</button>`;
                } else if (editMode2 && !isPiece) {
                    actionBtn = `<button disabled title="Im Set-Editor koennen nur Outfit-Teile aufgenommen werden" style="opacity:0.4;cursor:not-allowed;">—</button>`;
                } else {
                    actionBtn = `<button disabled title="Item hat kein prompt_fragment — kann nicht angelegt werden" style="opacity:0.4;cursor:not-allowed;">—</button>`;
                }
                return `<div class="wardrobe-piece-card${equipped ? ' equipped' : ''}" data-item="${escapeHtml(it.item_id)}" style="${equippable ? '' : 'opacity:0.6;'}">
                    ${it.item_image
                        ? `<img class="wardrobe-piece-img" src="${_wardrobeItemImg(it.item_id)}" alt="">`
                        : `<div class="wardrobe-piece-img" style="display:flex;align-items:center;justify-content:center;font-size:20px;">${isPiece ? '👕' : (hasFragment ? '🔧' : '📦')}</div>`}
                    <div class="wardrobe-piece-info">
                        <span class="wardrobe-piece-name">${escapeHtml(it.item_name || it.item_id)}</span>
                        <span class="wardrobe-piece-meta">${escapeHtml(metaText)}</span>
                    </div>
                    <div class="wardrobe-piece-actions">${actionBtn}</div>
                </div>`;
            }).join('');
            availEl.querySelectorAll('.wardrobe-card-equip').forEach(b => {
                b.onclick = () => {
                    const iid = b.dataset.item;
                    if (_wardrobeState.setEditMode) {
                        // Set-Editor: in alle slot-Felder des Pieces ablegen
                        // (ueberschreibt bestehende Eintraege, Remove-Markierungen geclearT).
                        const piece = _wardrobePieces().find(p => p.item_id === iid);
                        const slots = (piece && piece.outfit_piece && piece.outfit_piece.slots) || [];
                        if (!slots.length) { showStatusToast(t('Item has no slots'), 'error'); return; }
                        for (const slot of slots) {
                            _wardrobeState.setEditPieces[slot] = iid;
                            _wardrobeState.setRemoveSlots.delete(slot);
                        }
                        _renderWardrobeStudio();
                        _loadWardrobePreview(_wardrobeState.character);
                    } else {
                        _wardrobeEquip(iid);
                    }
                };
            });
        }
    }
}

function _findMatchingSetId() {
    // Liefert die Set-ID deren pieces exakt den aktuell in Spalte 2
    // sichtbaren Piece-Items entsprechen. Beruecksichtigt Edit-Modus
    // (setEditPieces) und Live-Modus (equipped_pieces). Sonst "".
    // Dedup ueber item_id, damit Multi-Slot-Pieces (ein Item in mehreren
    // Slots via additional_slots) nicht als mehrfach gezaehlt werden.
    const eq = _wardrobeState.setEditMode
        ? (_wardrobeState.setEditPieces || {})
        : (_wardrobeState.equipped.equipped_pieces || {});
    const currentPieces = Array.from(new Set(Object.values(eq).filter(Boolean)));
    if (!currentPieces.length) return '';
    for (const o of (_wardrobeState.outfits || [])) {
        const setPieces = Array.from(new Set(o.pieces || []));
        if (!setPieces.length) continue;
        if (setPieces.length !== currentPieces.length) continue;
        const match = setPieces.every(p => currentPieces.includes(p));
        if (match) return o.id || '';
    }
    return '';
}

// Dropdown auf das Set setzen, dessen Pieces exakt den aktuell angelegten
// entsprechen. Feuert onchange nicht — rein visueller Sync ohne Auto-Equip.
function _syncSetSelectToEquipped() {
    const sel = document.getElementById('wardrobe-set-select');
    if (!sel) return;
    const matchId = _findMatchingSetId();
    const target = matchId || '';
    if (sel.value !== target && Array.from(sel.options).some(o => o.value === target)) {
        sel.value = target;
    }
}

function _renderWardrobeSetSelect() {
    const sel = document.getElementById('wardrobe-set-select');
    if (!sel) return;
    const previousValue = sel.value || '';
    const opts = [
        '<option value="">— Set auswaehlen —</option>',
        '<option value="__new__">✨ + Neues Set</option>',
    ];
    for (const o of (_wardrobeState.outfits || [])) {
        if (!(o.pieces || []).length) continue; // Legacy-Outfits ignorieren
        opts.push(`<option value="${escapeHtml(o.id || '')}">👕 ${escapeHtml(o.name || '?')}</option>`);
    }
    sel.innerHTML = opts.join('');
    // Beim Oeffnen: KEIN Auto-Select eines Sets — immer Live-Modus mit
    // den tatsaechlich angelegten Pieces starten. User kann Set manuell waehlen.
    // Bei programmatischem Refresh (z.B. nach Save): bisherige Auswahl beibehalten.
    if (previousValue && Array.from(sel.options).some(o => o.value === previousValue)) {
        sel.value = previousValue;
    }
    // User-Auswahl -> auto-equip; programmatischer Refresh -> nur Buttons aktualisieren
    sel.onchange = () => _onWardrobeSetSelected(true);
    _onWardrobeSetSelected(false);
    // Buttons verdrahten (idempotent — kein Doppel-Bind dank ueberschreiben)
    const applyBtn = document.getElementById('wardrobe-equipped-apply');
    const saveBtn = document.getElementById('wardrobe-set-save');
    const previewBtn = document.getElementById('wardrobe-set-preview');
    const delBtn = document.getElementById('wardrobe-set-delete');
    const refreshBtn = document.getElementById('wardrobe-preview-refresh');
    const variantsClearBtn = document.getElementById('wardrobe-variants-clear');
    if (applyBtn) applyBtn.onclick = () => applyEquippedFromColumn();
    if (saveBtn) saveBtn.onclick = () => saveWardrobeAsSet();
    if (previewBtn) previewBtn.onclick = () => previewWardrobeSetImage();
    if (delBtn) delBtn.onclick = () => deleteWardrobeSet();
    if (refreshBtn) refreshBtn.onclick = () => _loadWardrobePreview(_wardrobeState.character);
    if (variantsClearBtn) variantsClearBtn.onclick = () => clearAllVariantsForWardrobeChar();
}

async function clearAllVariantsForWardrobeChar() {
    const charName = _wardrobeState.character;
    if (!charName) return;
    if (!confirm(`Alle generierten Variant/Expression-Bilder von "${charName}" loeschen?\n\nDie Bilder werden beim naechsten Aufruf neu generiert.`)) return;
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(charName)}/outfit-expression/cache`, {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({})
        });
        if (resp.ok) {
            const d = await resp.json().catch(() => ({}));
            showStatusToast(`${d.cleared || 0} ` + t('variant images of') + ` ${charName} ` + t('deleted.'), 'success');
            _loadWardrobePreview(charName);
        } else {
            showStatusToast(t('Could not delete variants.'), 'error');
        }
    } catch (e) {
        showStatusToast(t('Delete error') + ': ' + e.message, 'error');
    }
}

async function _onWardrobeSetSelected(triggeredByUser) {
    const sel = document.getElementById('wardrobe-set-select');
    if (!sel) return;
    const outfitId = sel.value;

    // Buttons sind immer aktiv — sie wirken auf Spalte 2 (Live-Modus: real
    // equipped, Edit-Modus: setEditPieces). Semantik:
    //   Anziehen (in Spalte 2): Spalte-2-Pieces + remove_slots aufs Profil
    //   Save (unter Spalte 1): Spalte 2 als Set speichern
    //   Vorschau (in Spalte 2): Variant fuer Spalte 2 erzwingen
    //   Delete (unter Spalte 1): selektiertes Set loeschen

    if (!outfitId) {
        // Leeres Dropdown -> Live-Modus (direkte Wirkung, kein Set-Buffer).
        _wardrobeState.setEditMode = false;
        _wardrobeState.setEditPieces = {};
        _wardrobeState.setEditColors = {};
        _wardrobeState.setRemoveSlots = new Set();
        _renderWardrobeStudio();
        _loadWardrobePreview(_wardrobeState.character);
        return;
    }

    if (outfitId === '__new__') {
        // Neues Set: leere Editor-Ansicht, User baut frisch auf
        _wardrobeState.setEditMode = true;
        _wardrobeState.setEditPieces = {};
        _wardrobeState.setRemoveSlots = new Set();
        _wardrobeState.setEditColors = {};
        _renderWardrobeStudio();
        _loadWardrobePreview(_wardrobeState.character);
        return;
    }
    // Set-Editor: Set-Inhalt in ephemeralen Edit-State laden und rendern.
    const o = (_wardrobeState.outfits || []).find(x => x.id === outfitId);
    _wardrobeState.setEditMode = true;
    _wardrobeState.setEditPieces = _wardrobeSetToSlotMap(o);
    _wardrobeState.setRemoveSlots = new Set(o && o.remove_slots ? o.remove_slots : []);
    // Gespeicherte Farben des Sets laden
    const _pc = (o && o.pieces_colors) || {};
    _wardrobeState.setEditColors = Object.assign({}, _pc);
    _renderWardrobeStudio();
    _loadWardrobePreview(_wardrobeState.character);
}

function _wardrobeSetToSlotMap(outfit) {
    // Mappt ein Set (outfit.pieces = [item_id,...]) auf {slot: item_id}.
    // Multi-Slot-Pieces werden in alle ihre Slots gespiegelt — die UI nutzt
    // das fuer "blockiert"-Anzeigen, und Equip-Aktionen sehen so den vollen
    // Belegungs-Soll-State.
    const map = {};
    if (!outfit || !Array.isArray(outfit.pieces)) return map;
    const pieces = _wardrobePieces();
    for (const pid of outfit.pieces) {
        const it = pieces.find(p => p.item_id === pid);
        if (!it) continue;
        const op = it.outfit_piece || {};
        for (const s of (op.slots || [])) {
            const slot = (s || '').trim();
            if (slot && !map[slot]) map[slot] = pid;
        }
    }
    return map;
}

function _renderEquippedColumnPreview(outfitId) {
    const equippedEl = document.getElementById('wardrobe-equipped');
    if (!equippedEl) return;
    const o = (_wardrobeState.outfits || []).find(x => x.id === outfitId);
    if (!o || !(o.pieces || []).length) {
        equippedEl.innerHTML = '<p class="scheduler-empty">Set hat keine Pieces.</p>';
        return;
    }
    const pieces = _wardrobePieces();
    const setPieceMap = {};
    for (const pid of o.pieces) {
        const it = pieces.find(p => p.item_id === pid);
        if (!it) continue;
        const op = it.outfit_piece || {};
        for (const s of (op.slots || [])) {
            const slot = (s || '').trim();
            if (slot && !setPieceMap[slot]) setPieceMap[slot] = it;
        }
    }
    const removeSet = new Set(o.remove_slots || []);
    const rows = SLOT_ORDER.map(slot => {
        const it = setPieceMap[slot];
        const willRemove = removeSet.has(slot);
        if (it) {
            return `<div class="wardrobe-slot-row">
                <div class="wardrobe-slot-label">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
                <div class="wardrobe-slot-piece">
                    ${it.item_image
                        ? `<img class="wardrobe-slot-img" src="${_wardrobeItemImg(it.item_id)}" alt="">`
                        : `<div class="wardrobe-slot-img" style="display:flex;align-items:center;justify-content:center;font-size:18px;">📦</div>`}
                    <span class="wardrobe-slot-name">${escapeHtml(it.item_name || it.item_id)}</span>
                </div>
            </div>`;
        }
        if (willRemove) {
            return `<div class="wardrobe-slot-row empty marked-remove">
                <div class="wardrobe-slot-label">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
                <div class="wardrobe-slot-piece"><span class="wardrobe-slot-empty">⊘ wird beim Anziehen geleert</span></div>
            </div>`;
        }
        return `<div class="wardrobe-slot-row empty">
            <div class="wardrobe-slot-label">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
            <div class="wardrobe-slot-piece"><span class="wardrobe-slot-empty">— leer (bleibt wie vorher) —</span></div>
        </div>`;
    }).join('');
    equippedEl.innerHTML = `<div style="font-size:11px;color:var(--text-muted);font-style:italic;margin-bottom:4px;">Vorschau — klicke "Anziehen" um zu uebernehmen.</div>` + rows;
}

// --- Item-Suche + zum Inventar hinzufuegen (Wardrobe Tab 2, Spalte 1) ---
let _wardrobeAllItems = null;  // Cache aller outfit_piece Items aus der Bibliothek
let _wardrobeAddSelected = null;  // aktuell gewaehlte Item-ID

async function _initWardrobeAddExisting() {
    const searchEl = document.getElementById('wardrobe-add-search');
    const resultsEl = document.getElementById('wardrobe-add-results');
    const addBtn = document.getElementById('wardrobe-add-btn');
    if (!searchEl || !resultsEl || !addBtn) return;

    // Alle outfit_piece-Items aus der Bibliothek laden (bei jedem Aufruf
    // frisch, damit neu angelegte Items sofort auftauchen). Shared-Items
    // mit aufnehmen — sonst findet die Suche keine welt-uebergreifenden
    // Outfit-Teile aus der globalen Library.
    try {
        const r = await fetch(`/inventory/items?include_shared=1`);
        if (r.ok) {
            const d = await r.json();
            _wardrobeAllItems = (d.items || []).filter(it => it.category === 'outfit_piece');
        }
    } catch (_) { /* bei Fehler alten Cache behalten */ }

    // Schon im Inventar?
    const invIds = new Set(_wardrobeState.inventory.map(e => e.item_id));

    searchEl.oninput = () => {
        const q = (searchEl.value || '').trim().toLowerCase();
        _wardrobeAddSelected = null;
        if (!q || q.length < 2) { resultsEl.style.display = 'none'; return; }
        // Name-Matches zuerst, dann Fragment-Matches (damit "White Shirt"
        // bei Suche "white" vor "Diego — Business Outfit (white shirt in fragment)" steht)
        const nameMatches = [];
        const fragMatches = [];
        for (const it of (_wardrobeAllItems || [])) {
            const name = (it.name || '').toLowerCase();
            const frag = (it.prompt_fragment || '').toLowerCase();
            if (name.includes(q)) nameMatches.push(it);
            else if (frag.includes(q)) fragMatches.push(it);
        }
        const matches = [...nameMatches, ...fragMatches].slice(0, 20);
        if (!matches.length) {
            resultsEl.innerHTML = '<div style="padding:6px;font-size:11px;color:var(--text-muted);">Nichts gefunden</div>';
            resultsEl.style.display = '';
            return;
        }
        resultsEl.innerHTML = matches.map(it => {
            const inInv = invIds.has(it.id);
            const slotsArr = (it.outfit_piece && it.outfit_piece.slots) || [];
            const slot = slotsArr.map(s => SLOT_LABELS_DE[s] || s).join(' + ');
            return `<div class="wardrobe-add-result${inInv ? ' disabled' : ''}" data-id="${escapeHtml(it.id)}"
                style="padding:4px 8px;cursor:${inInv ? 'not-allowed' : 'pointer'};font-size:12px;display:flex;gap:6px;align-items:center;${inInv ? 'opacity:0.4;' : ''}"
                title="${inInv ? 'Bereits im Inventar' : 'Klicken zum Auswaehlen'}">
                <span style="flex:1;">${escapeHtml(it.name || it.id)}</span>
                <span style="font-size:10px;color:var(--text-muted);">${escapeHtml(slot)}</span>
                ${inInv ? '<span style="font-size:10px;">✓</span>' : ''}
            </div>`;
        }).join('');
        resultsEl.style.display = '';
        resultsEl.querySelectorAll('.wardrobe-add-result:not(.disabled)').forEach(el => {
            el.onclick = () => {
                _wardrobeAddSelected = el.dataset.id;
                searchEl.value = el.querySelector('span').textContent;
                resultsEl.style.display = 'none';
                // Visuelles Feedback
                resultsEl.querySelectorAll('.wardrobe-add-result').forEach(r => r.style.background = '');
                el.style.background = 'var(--accent, #58a6ff)';
            };
        });
    };

    addBtn.onclick = async () => {
        if (!_wardrobeAddSelected) {
            showStatusToast(t('Choose an item from the search first'), 'info');
            return;
        }
        const c = _wardrobeState.character;
        try {
            const r = await fetch(`/inventory/characters/${encodeURIComponent(c)}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ item_id: _wardrobeAddSelected }),
            });
            if (r.ok) {
                const it = (_wardrobeAllItems || []).find(x => x.id === _wardrobeAddSelected);
                showStatusToast(`'${it ? it.name : _wardrobeAddSelected}' ` + t('added to inventory'), 'success');
                _wardrobeAddSelected = null;
                searchEl.value = '';
                resultsEl.style.display = 'none';
                await _wardrobeRefresh();
            } else {
                const d = await r.json().catch(() => ({}));
                showStatusToast(d.detail || t('Add failed'), 'error');
            }
        } catch (e) { showStatusToast(t('Error') + ': ' + e.message, 'error'); }
    };

    // Ergebnisse schliessen bei Klick ausserhalb
    searchEl.onfocus = () => { if (searchEl.value.trim().length >= 2) searchEl.oninput(); };
}

function _renderWardrobeInventory() {
    _initWardrobeAddExisting();
    const listEl = document.getElementById('wardrobe-inv-list');
    if (!listEl) return;
    const pieces = _wardrobePieces();
    if (!pieces.length) {
        listEl.innerHTML = '<p class="scheduler-empty">Noch keine Outfit-Teile im Inventar. Lege links eins an.</p>';
        _setPiecePreview(null);
        return;
    }
    listEl.innerHTML = pieces.map(it => {
        const slotsArr = (it.outfit_piece && it.outfit_piece.slots) || [];
        const slot = slotsArr.map(s => SLOT_LABELS_DE[s] || s).join(' + ');
        const isSelected = (_wardrobeState.previewItemId === it.item_id);
        return `<div class="wardrobe-piece-card${isSelected ? ' equipped' : ''}" data-item="${escapeHtml(it.item_id)}" style="cursor:pointer;">
            ${it.item_image
                ? `<img class="wardrobe-piece-img" src="${_wardrobeItemImg(it.item_id)}" alt="">`
                : `<div class="wardrobe-piece-img" style="display:flex;align-items:center;justify-content:center;font-size:20px;">👕</div>`}
            <div class="wardrobe-piece-info">
                <span class="wardrobe-piece-name">${escapeHtml(it.item_name || it.item_id)}</span>
                <span class="wardrobe-piece-meta">${escapeHtml(slot || '— ohne Slot —')} · ${escapeHtml((it.item_prompt_fragment || '').slice(0, 60))}</span>
            </div>
            <div class="wardrobe-piece-actions">
                <button class="danger wardrobe-piece-delete" data-item="${escapeHtml(it.item_id)}">Loeschen</button>
            </div>
        </div>`;
    }).join('');
    listEl.querySelectorAll('.wardrobe-piece-card').forEach(card => {
        card.onclick = (e) => {
            if (e.target.classList.contains('wardrobe-piece-delete')) return;
            const iid = card.dataset.item;
            const item = _wardrobeState.inventory.find(x => x.item_id === iid);
            _wardrobeState.previewItemId = iid;
            _wardrobeFormLoad(item);   // ins Formular laden -> Edit-Modus
            _setPiecePreview(iid);     // Bild rechts
            _renderWardrobeInventory();  // Auswahl markieren
        };
    });
    listEl.querySelectorAll('.wardrobe-piece-delete').forEach(b => {
        b.onclick = (e) => { e.stopPropagation(); deleteWardrobePiece(b.dataset.item); };
    });
    // "+ Neu"-Button: Formular leeren, kein Edit-Modus
    const newBtn = document.getElementById('wpc-new-btn');
    if (newBtn) newBtn.onclick = () => {
        _wardrobeState.previewItemId = null;
        _wardrobeFormReset();
        _renderWardrobeInventory();
    };
    // Wenn aktuell etwas selektiert ist, Preview aktualisieren
    if (_wardrobeState.previewItemId) {
        _setPiecePreview(_wardrobeState.previewItemId);
    }
}

function _setPiecePreview(itemId) {
    _wardrobeState.previewItemId = itemId || null;
    const previewEl = document.getElementById('wardrobe-piece-preview');
    const actionsEl = document.getElementById('wardrobe-piece-preview-actions');
    const metaEl = document.getElementById('wardrobe-piece-preview-meta');
    const genBtn = document.getElementById('wardrobe-piece-gen-btn');
    if (!previewEl) return;
    if (!itemId) {
        previewEl.innerHTML = '<p class="scheduler-empty">Klicke ein Teil rechts an, um das Bild zu sehen oder zu generieren.</p>';
        if (actionsEl) actionsEl.style.display = 'none';
        if (metaEl) metaEl.textContent = '';
        return;
    }
    const it = _wardrobeState.inventory.find(x => x.item_id === itemId);
    if (!it) { _setPiecePreview(null); return; }
    if (it.item_image) {
        previewEl.innerHTML = `<img src="${_wardrobeItemImg(itemId)}" alt="${escapeHtml(it.item_name || '')}">`;
    } else {
        previewEl.innerHTML = `<div style="text-align:center;color:var(--text-muted);font-size:13px;padding:20px;">
            Noch kein Bild erzeugt.<br><br>
            Image-Prompt im Item: ${it.item_image_prompt ? `<code>${escapeHtml(it.item_image_prompt.slice(0, 120))}</code>` : '<i>(leer — bitte Item-Editor nutzen)</i>'}
        </div>`;
    }
    if (actionsEl) actionsEl.style.display = '';
    if (genBtn) {
        genBtn.textContent = it.item_image ? '🔄 Bild neu generieren' : '📷 Bild erzeugen';
        genBtn.onclick = () => _generateWardrobePieceImage(itemId);
    }
    if (metaEl) {
        const slotsArr = (it.outfit_piece && it.outfit_piece.slots) || [];
        const label = slotsArr.map(s => SLOT_LABELS_DE[s] || s).join(' + ');
        metaEl.textContent = `${it.item_name} · ${label || 'kein Slot'}`;
    }
}

async function _generateWardrobePieceImage(itemId) {
    // Fire-and-forget: Request abschicken, Toast zeigen, sofort weiter.
    // Die GPU-Queue serialisiert im Backend — User kann mehrere Items
    // hintereinander anklicken ohne zu warten.
    const c = _wardrobeState.character;
    if (!itemId || !c) return;
    const it = _wardrobeState.inventory.find(x => x.item_id === itemId);
    const label = it ? (it.item_name || itemId) : itemId;
    try {
        const r = await fetch(`/inventory/items/${encodeURIComponent(itemId)}/generate-image`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({  }),
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(t('Image') + ` '${label}': ${d.detail || t('Error')}`, 'error');
        } else {
            showStatusToast(t('Image for') + ` '${label}' ` + t('queued'), 'success');
        }
    } catch (e) {
        showStatusToast(t('Image') + ` '${label}': ${e.message || e}`, 'error');
    }
}

async function _wardrobeEquip(itemId) {
    if (!itemId) return;
    const c = _wardrobeState.character;
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(c)}/equip`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ item_id: itemId }),
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || t('Equip failed'), 'error');
            return;
        }
    } catch (e) { showStatusToast(t('Equip failed'), 'error'); return; }
    await _wardrobeRefresh();
    _loadWardrobePreview(_wardrobeState.character);
}

async function _wardrobeUnequip(payload) {
    const c = _wardrobeState.character;
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(c)}/unequip`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ ...payload }),
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || t('Unequip failed'), 'error');
            return;
        }
    } catch (e) { showStatusToast(t('Unequip failed'), 'error'); return; }
    await _wardrobeRefresh();
    _loadWardrobePreview(_wardrobeState.character);
}

async function _wardrobeRefresh() {
    await _loadWardrobeData();
    // KEIN _loadWardrobePreview hier — _wardrobeRefresh wird auch von
    // Piece-Save/Create/Delete gerufen die den Equipped-State nicht aendern.
    // Preview nur bei echten Equip/Unequip-Aktionen (explizit vom Caller).
    // Header-Bilder + Scenes mitziehen
    const c = _wardrobeState.character;
    try { if (typeof updatePlayerExpression === 'function') updatePlayerExpression(getPlayerCharacterName()); } catch (_) {}
    try { if (typeof updateCharacterScene === 'function' && currentCharacterName) updateCharacterScene(currentCharacterName); } catch (_) {}
}

async function _loadWardrobePreview(characterName) {
    const previewEl = document.getElementById('wardrobe-preview');
    if (!previewEl) return;
    // Variant-Vorschau: Default-Pose + Default-Expression + Equipped-Hash im
    // Cache-Key. Bei aktiven Set-Editor werden dessen Pieces als Override
    // mitgeschickt — sonst zeigt der Endpoint die Variant des real-equipped
    // Zustands (z.B. vorheriges Office, obwohl Casual im Dropdown).
    //
    // UX: Das aktuell angezeigte Bild bleibt stehen, solange die Generierung
    // laeuft (202). Kein Placeholder-Flash. Nur bei 200 wird ersetzt.
    // Ein Placeholder erscheint nur, wenn vorher noch kein Bild da war.
    _updateWardrobePreviewLabel();
    const hasImage = !!previewEl.querySelector('img');
    if (!hasImage) {
        previewEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Loading preview…'))}</p>`;
    }
    // Garderoben-Vorschau soll immer in DEFAULT Pose + Expression laufen,
    // nicht im Variant des aktuellen Mood/Activity. override=1 zwingt das
    // Backend in den Override-Pfad — dann werden mood/activity NICHT mehr
    // aus dem Character-State auto-gefuellt und resolven leer auf Default.
    let params = `mood=&activity=&t=${Date.now()}&override=1`;
    if (_wardrobeState.setEditMode) {
        const pieces = _wardrobeState.setEditPieces || {};
        const pairs = Object.entries(pieces)
            .filter(([, iid]) => !!iid)
            .map(([slot, iid]) => `${slot}:${iid}`)
            .join(',');
        const colorsSrc = _wardrobeState.setEditColors || {};
        const colorPairs = Object.entries(colorsSrc)
            .filter(([slot, color]) => !!color && !!pieces[slot])
            .map(([slot, color]) => `${slot}:${color}`)
            .join(',');
        params += `&pieces=${encodeURIComponent(pairs)}&items=`
            + `&piece_colors=${encodeURIComponent(colorPairs)}`;
    } else {
        // Real-equipped State explizit mitschicken — sonst rendert das
        // Backend in override-Mode den Char ohne Equipment.
        const eq = _wardrobeState.equipped || {};
        const pieces = eq.equipped_pieces || {};
        const pairs = Object.entries(pieces)
            .filter(([, iid]) => !!iid)
            .map(([slot, iid]) => `${slot}:${iid}`)
            .join(',');
        const itemsArr = (eq.equipped_items || []).filter(Boolean);
        const colorsMeta = eq.equipped_pieces_meta || {};
        const colorPairs = Object.entries(colorsMeta)
            .filter(([slot, m]) => m && m.color && !!pieces[slot])
            .map(([slot, m]) => `${slot}:${m.color}`)
            .join(',');
        params += `&pieces=${encodeURIComponent(pairs)}`
            + `&items=${encodeURIComponent(itemsArr.join(','))}`
            + `&piece_colors=${encodeURIComponent(colorPairs)}`;
    }
    // fallback=default: wenn kein Variant im Cache und Generierung laeuft,
    // liefert das Backend das Profilbild als Platzhalter (200 + Header
    // X-Variant-Status=fallback-default). Sonst kaem 202 mit "Keine Vorschau".
    const url = `/characters/${encodeURIComponent(characterName)}/outfit-expression?${params}&fallback=default`;
    const attempt = async (tries) => {
        try {
            const r = await fetch(url);
            if (r.status === 200) {
                const blob = await r.blob();
                const objUrl = URL.createObjectURL(blob);
                previewEl.innerHTML = `<img src="${objUrl}" alt="Vorschau">`;
                return;
            }
            if (r.status === 202) {
                // Asynchrone Generierung laeuft — bestehendes Bild NICHT ueberschreiben.
                // Kein weiteres Polling; der User kann manuell refreshen.
                if (!hasImage) {
                    previewEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No preview available'))}</p>`;
                }
                return;
            }
            // 404 o.ae. — nur setzen wenn noch kein Bild da war
            if (!hasImage) {
                previewEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No preview available'))}</p>`;
            }
        } catch (e) {
            if (!hasImage) {
                previewEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No preview available'))}</p>`;
            }
        }
    };
    attempt(1);
}

function _setWardrobePieceFormReadOnly(readOnly) {
    const ids = [
        'wpc-name', 'wpc-slots-add', 'wpc-prompt-fragment',
        'wpc-outfit-type-select', 'wpc-outfit-type-new',
        'wpc-description', 'wpc-image-prompt',
    ];
    for (const id of ids) {
        const el = document.getElementById(id);
        if (el) el.disabled = !!readOnly;
    }
    // Slot-Tags klickbarkeit (Entfernen) im Read-Only-Modus abschalten
    document.querySelectorAll('#wpc-slots-tags .wpc-cover-tag').forEach(el => {
        el.style.pointerEvents = readOnly ? 'none' : '';
        el.style.opacity = readOnly ? '0.6' : '';
    });
    // Outfit-Type-Tags: Lösch-Buttons abschalten
    document.querySelectorAll('#wpc-outfit-type-tags button').forEach(b => {
        b.disabled = !!readOnly;
    });
    // Covers / partially_covers checkboxes
    document.querySelectorAll('#wpc-covers input[type=checkbox], #wpc-partially-covers input[type=checkbox]').forEach(cb => {
        cb.disabled = !!readOnly;
    });
    // Save-Button ausblenden / Hinweis zeigen
    const saveBtn = document.getElementById('wpc-save-btn');
    if (saveBtn) saveBtn.style.display = readOnly ? 'none' : '';
    const status = document.getElementById('wpc-status');
    if (status) status.textContent = readOnly ? '🌐 Shared-Item — nur lesen. Farbe darf im Studio gesetzt werden.' : '';
}


let _wpcLoraCache = { character: null, data: null };

async function _loadWpcLoraOptions(characterName) {
    if (_wpcLoraCache.character === characterName && _wpcLoraCache.data) {
        return _wpcLoraCache.data;
    }
    let data = { workflow: "", filter: "", loras: [] };
    try {
        const url = characterName
            ? `/characters/outfit-lora-options?character_name=${encodeURIComponent(characterName)}`
            : '/characters/outfit-lora-options';
        const r = await fetch(url);
        if (r.ok) data = await r.json();
    } catch (e) {
        console.warn('[WpcLora] Optionen-Fetch fehlgeschlagen:', e);
    }
    _wpcLoraCache = { character: characterName, data };
    return data;
}

async function _renderWpcLora(lora) {
    const charName = _wardrobeState.character || '';
    const data = await _loadWpcLoraOptions(charName);
    const obj = (Array.isArray(lora) ? (lora[0] || {}) : (lora || {})) || {};
    const name = obj.name || '';
    const strength = (obj.strength !== undefined && obj.strength !== null) ? obj.strength : 1.0;

    const sel = document.getElementById('wpc-lora-name');
    if (sel) {
        const opts = ['<option value="None">— keins —</option>'];
        let found = false;
        for (const l of (data.loras || [])) {
            const selAttr = l === name ? ' selected' : '';
            if (l === name) found = true;
            opts.push(`<option value="${escapeHtml(l)}"${selAttr}>${escapeHtml(l)}</option>`);
        }
        if (name && name !== 'None' && !found) {
            opts.splice(1, 0, `<option value="${escapeHtml(name)}" selected>${escapeHtml(name)} (${escapeHtml(t('not available'))})</option>`);
        }
        sel.innerHTML = opts.join('');
    }

    const strengthEl = document.getElementById('wpc-lora-strength');
    if (strengthEl) strengthEl.value = strength;

    const info = document.getElementById('wpc-lora-filter-info');
    if (info) {
        if (data.workflow) {
            info.textContent = ` — Workflow: ${data.workflow}` + (data.filter ? ` (Filter: ${data.filter})` : '');
        } else {
            info.textContent = '';
        }
    }
}

function _readWpcLora() {
    const name = (document.getElementById('wpc-lora-name')?.value || '').trim();
    if (!name || name === 'None') return {};
    return {
        name,
        strength: parseFloat(document.getElementById('wpc-lora-strength')?.value) || 1.0,
    };
}


function _wardrobeFormReset() {
    document.getElementById('wpc-edit-id').value = '';
    document.getElementById('wpc-name').value = '';
    document.getElementById('wpc-prompt-fragment').value = '';
    document.getElementById('wpc-description').value = '';
    document.getElementById('wpc-image-prompt').value = '';
    _setWardrobePieceFormReadOnly(false);
    _renderOutfitTypeTags([]);
    _renderWpcSlots(['outer']);
    _renderWpcCovers([], [], ['outer']);
    _renderWpcLora({});
    const _sel = document.getElementById('wpc-outfit-type-select');
    if (_sel) _sel.value = '';
    const _ni = document.getElementById('wpc-outfit-type-new');
    if (_ni) { _ni.value = ''; _ni.style.display = 'none'; }
    const status = document.getElementById('wpc-status');
    if (status) status.textContent = '';
    const title = document.getElementById('wpc-form-title');
    if (title) title.textContent = 'Neues Teil anlegen';
    const btn = document.getElementById('wpc-save-btn');
    if (btn) btn.textContent = 'Anlegen + ins Inventar';
    _setPiecePreview(null);
}

function _wardrobeFormLoad(item) {
    if (!item) { _wardrobeFormReset(); return; }
    document.getElementById('wpc-edit-id').value = item.item_id || '';
    document.getElementById('wpc-name').value = item.item_name || '';
    document.getElementById('wpc-prompt-fragment').value = item.item_prompt_fragment || '';
    document.getElementById('wpc-description').value = item.item_description || '';
    document.getElementById('wpc-image-prompt').value = item.item_image_prompt || '';
    // Shared-Items sind read-only (globale Bibliothek — nicht aus der Welt editierbar)
    _setWardrobePieceFormReadOnly(!!item._shared);
    const types = (item.outfit_piece && item.outfit_piece.outfit_types) || [];
    _renderOutfitTypeTags(Array.isArray(types) ? types : []);
    const _sel = document.getElementById('wpc-outfit-type-select');
    if (_sel) _sel.value = '';
    const _ni = document.getElementById('wpc-outfit-type-new');
    if (_ni) { _ni.value = ''; _ni.style.display = 'none'; }
    // Symmetrische Slots-Liste — komplett im Slot-Tag-Picker.
    const allSlots = (item.outfit_piece && Array.isArray(item.outfit_piece.slots))
        ? item.outfit_piece.slots : [];
    _renderWpcSlots(allSlots);
    const covers = (item.outfit_piece && item.outfit_piece.covers) || [];
    const partCovers = (item.outfit_piece && item.outfit_piece.partially_covers) || [];
    _renderWpcCovers(Array.isArray(covers) ? covers : [],
                      Array.isArray(partCovers) ? partCovers : [],
                      allSlots);
    const lora = (item.outfit_piece && (item.outfit_piece.lora || item.outfit_piece.loras)) || {};
    _renderWpcLora(lora);
    const status = document.getElementById('wpc-status');
    if (status) status.textContent = '';
    const title = document.getElementById('wpc-form-title');
    if (title) title.textContent = 'Outfit-Teil bearbeiten';
    const btn = document.getElementById('wpc-save-btn');
    if (btn) btn.textContent = '💾 Speichern';
}

// Outfit-Type Picker — state cache fuer die aktuelle Vorschlagsliste
let _outfitTypeCache = [];

function _readOutfitTypes() {
    // Tags aus dem Container auslesen (wpc-outfit-type-tags)
    const wrap = document.getElementById('wpc-outfit-type-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.outfit-type-tag'))
        .map(el => el.dataset.type || '')
        .filter(Boolean);
}

function _renderOutfitTypeTags(tags) {
    const wrap = document.getElementById('wpc-outfit-type-tags');
    if (!wrap) return;
    wrap.innerHTML = (tags || []).map(t =>
        `<span class="outfit-type-tag" data-type="${escapeHtml(t)}">${escapeHtml(t)}<button type="button" onclick="_wpcRemoveOutfitType('${escapeHtml(t).replace(/'/g, '&#39;')}')">×</button></span>`
    ).join('');
}

function _wpcAddOutfitType(rawValue) {
    const sel = document.getElementById('wpc-outfit-type-select');
    const newInput = document.getElementById('wpc-outfit-type-new');
    const value = (rawValue || '').trim();
    if (!value) return;
    const current = _readOutfitTypes();
    if (!current.some(t => t.toLowerCase() === value.toLowerCase())) {
        current.push(value);
        _renderOutfitTypeTags(current);
    }
    // Reset picker
    if (sel) sel.value = '';
    if (newInput) { newInput.value = ''; newInput.style.display = 'none'; }
    // Vorschlagsliste aktualisieren (neue Werte werden sofort als Option sichtbar)
    if (!_outfitTypeCache.some(t => t.toLowerCase() === value.toLowerCase())) {
        _outfitTypeCache.push(value);
        _rebuildOutfitTypeSelect('wpc-outfit-type-select');
    }
}

function _wpcRemoveOutfitType(value) {
    const current = _readOutfitTypes().filter(t => t !== value);
    _renderOutfitTypeTags(current);
}

function _renderWpcCovers(covered, partiallyCovers, slots) {
    // Eigene Slots des Pieces duerfen nicht in covers/partially_covers
    // auftauchen — Slot ist physisch belegt, nichts zu verdecken.
    const own = new Set((slots || []).map(s => String(s).trim().toLowerCase()).filter(Boolean));
    const coversAvailable = SLOT_ORDER.filter(s => !own.has(s));
    _renderWpcCoverGroup('wpc-covers-tags', 'wpc-covers-add', covered, coversAvailable);
    _renderWpcCoverGroup('wpc-partially-covers-tags', 'wpc-partially-covers-add', partiallyCovers, coversAvailable);
}

function _renderWpcSlots(slots) {
    // Symmetrische Slots-Auswahl. onChange-Callback triggert ein Cover-Re-Render
    // damit eigene Slots aus dem Cover-Picker fliegen sobald sich die Auswahl
    // aendert.
    _renderWpcCoverGroup('wpc-slots-tags', 'wpc-slots-add', slots || [], SLOT_ORDER, (newSlots) => {
        _renderWpcCovers(_readWpcCovers(), _readWpcPartiallyCovers(), newSlots);
    });
    _renderWpcCovers(_readWpcCovers(), _readWpcPartiallyCovers(), _readWpcSlots());
}

function _readWpcSlots() {
    const wrap = document.getElementById('wpc-slots-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.wpc-cover-tag')).map(el => el.dataset.slot);
}

function _renderWpcCoverGroup(tagsId, addId, selected, allSlots, onChange) {
    const tagsEl = document.getElementById(tagsId);
    const addSel = document.getElementById(addId);
    if (!tagsEl || !addSel) return;
    const set = new Set((selected || []).map(s => String(s).trim().toLowerCase()).filter(Boolean));
    // Tags rendern (klickbar zum Entfernen)
    tagsEl.innerHTML = Array.from(set).map(s => {
        const label = SLOT_LABELS_DE[s] || s;
        return `<span class="wpc-cover-tag" data-slot="${escapeHtml(s)}" style="display:inline-flex;align-items:center;gap:3px;padding:2px 6px;background:var(--bg-alt);color:var(--text);border:1px solid var(--border);border-radius:3px;font-size:11px;cursor:pointer;" title="Klick zum Entfernen">${escapeHtml(label)} <span style="color:var(--text-muted);">✕</span></span>`;
    }).join('');
    tagsEl.querySelectorAll('.wpc-cover-tag').forEach(el => {
        el.onclick = () => {
            const slot = el.dataset.slot;
            set.delete(slot);
            _renderWpcCoverGroup(tagsId, addId, Array.from(set), allSlots, onChange);
            if (typeof onChange === 'function') onChange(Array.from(set));
        };
    });
    // Add-Dropdown: nur Slots die noch nicht ausgewaehlt sind
    const remaining = allSlots.filter(s => !set.has(s));
    addSel.innerHTML = '<option value="">+ hinzufuegen</option>' + remaining.map(s =>
        `<option value="${escapeHtml(s)}">${escapeHtml(SLOT_LABELS_DE[s] || s)}</option>`
    ).join('');
    addSel.onchange = () => {
        if (!addSel.value) return;
        set.add(addSel.value);
        _renderWpcCoverGroup(tagsId, addId, Array.from(set), allSlots, onChange);
        if (typeof onChange === 'function') onChange(Array.from(set));
    };
}

function _readWpcCovers() {
    const wrap = document.getElementById('wpc-covers-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.wpc-cover-tag')).map(el => el.dataset.slot);
}

function _readWpcPartiallyCovers() {
    const wrap = document.getElementById('wpc-partially-covers-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.wpc-cover-tag')).map(el => el.dataset.slot);
}

function _rebuildOutfitTypeSelect(selectId, allowEmpty = true) {
    const sel = document.getElementById(selectId);
    if (!sel) return;
    const previousValue = sel.value || '';
    const opts = [];
    if (allowEmpty) opts.push('<option value="">— auswaehlen —</option>');
    for (const t of [..._outfitTypeCache].sort((a, b) => a.localeCompare(b))) {
        opts.push(`<option value="${escapeHtml(t)}">${escapeHtml(t)}</option>`);
    }
    sel.innerHTML = opts.join('');
    if (previousValue && Array.from(sel.options).some(o => o.value === previousValue)) {
        sel.value = previousValue;
    }
}

function _bindOutfitTypePicker(selectId, newInputId) {
    const sel = document.getElementById(selectId);
    const newInput = document.getElementById(newInputId);
    if (!sel) return;
    if (newInput) newInput.style.display = 'none';
    sel.onchange = () => {
        const v = sel.value;
        if (v) _wpcAddOutfitType(v);
    };
}

async function _loadOutfitTypeSuggestions() {
    try {
        const r = await fetch(`/inventory/outfit-types`);
        if (r.ok) {
            const data = await r.json();
            _outfitTypeCache = (data.outfit_types || []).slice();
        }
    } catch (_) {}
    _rebuildOutfitTypeSelect('wpc-outfit-type-select');
    _bindOutfitTypePicker('wpc-outfit-type-select', 'wpc-outfit-type-new');
}

// Backwards-Compat (wird noch aus Location-Form gerufen)
async function _fillOutfitTypeSuggestList(datalistId) {
    // Datalists werden nicht mehr genutzt — als No-Op beibehalten.
}

// Single-Value Outfit-Type Picker (Location + Room): Select mit Optionen +
// Hidden-Input das den finalen Wert haelt (fuer save-Funktionen), plus
// Text-Input der bei "__new__"-Auswahl sichtbar wird.
let _knowledgeItemCache = null;
async function _populateKnowledgeItemSelect(selectId, currentValue) {
    const sel = document.getElementById(selectId);
    if (!sel) return;
    if (!_knowledgeItemCache) {
        try {
            const r = await fetch(`/inventory/items`);
            if (r.ok) _knowledgeItemCache = (await r.json()).items || [];
            else _knowledgeItemCache = [];
        } catch (_) { _knowledgeItemCache = []; }
    }
    const items = (_knowledgeItemCache || []).slice().sort((a, b) =>
        (a.name || '').localeCompare(b.name || ''));
    const opts = ['<option value="">— keins, fuer alle sichtbar —</option>'];
    for (const it of items) {
        const selected = it.id === currentValue ? ' selected' : '';
        const cat = it.category || 'item';
        opts.push(`<option value="${escapeHtml(it.id)}"${selected}>${escapeHtml(it.name || it.id)} (${escapeHtml(cat)})</option>`);
    }
    sel.innerHTML = opts.join('');
}

// Conditions-Cache fuer das apply_condition-Dropdown im Item-/Activity-Editor.
// Quelle: /world/conditions/list (gemergt aus shared baseline + world overlay).
let _conditionsCache = null;
async function _populateConditionSelect(sel, currentValue) {
    if (!sel) return;
    if (!_conditionsCache) {
        try {
            const r = await fetch(`/world/conditions/list`);
            _conditionsCache = r.ok ? ((await r.json()).conditions || []) : [];
        } catch (_) { _conditionsCache = []; }
    }
    const cur = (currentValue || '').trim().toLowerCase();
    const opts = ['<option value="">-- keine --</option>'];
    let found = false;
    for (const c of _conditionsCache) {
        const sel2 = c.name === cur ? ' selected' : '';
        if (c.name === cur) found = true;
        const icon = c.icon ? `${c.icon} ` : '';
        const label = c.label ? ` — ${c.label}` : '';
        opts.push(`<option value="${escapeHtml(c.name)}"${sel2}>${escapeHtml(icon + c.name + label)}</option>`);
    }
    // Falls der bisher gespeicherte Wert keinen Filter mehr hat: trotzdem anzeigen
    if (cur && !found) {
        opts.push(`<option value="${escapeHtml(cur)}" selected>${escapeHtml(cur)} (nicht in Zustaenden definiert)</option>`);
    }
    sel.innerHTML = opts.join('');
}
function _invalidateConditionsCache() { _conditionsCache = null; }

// Befuellt das Cast-Activity-Dropdown im Item-Editor mit allen Library-
// Aktivitaeten. Wert ist die Activity-ID — die Spell-Engine setzt sie nach
// erfolgreichem Cast beim Avatar (Auto-Ablauf via duration_minutes).
async function _populateCastActivitySelect(currentValue) {
    const sel = document.getElementById('item-edit-cast-activity');
    if (!sel) return;
    if (!_libActivityGroups) {
        try { await _loadActivityLibraryList(); } catch (_) { /* ignore */ }
    }
    sel.innerHTML = _buildGroupedActivityOptions(currentValue || '');
}

// _populateCloneItemSelect liest aus dem globalen _itemsCache (siehe weiter
// unten in "Items (Game Admin)") — wenn der noch leer ist, einmal nachladen.
async function _populateCloneItemSelect(currentValue, excludeId) {
    const sel = document.getElementById('item-edit-clone-item');
    if (!sel) return;
    if (!Array.isArray(_itemsCache) || _itemsCache.length === 0) {
        try {
            const r = await fetch(`/inventory/items`);
            if (r.ok) _itemsCache = (await r.json()).items || [];
        } catch (_) { /* leer lassen */ }
    }
    const items = (_itemsCache || []).slice().sort((a, b) =>
        (a.name || '').localeCompare(b.name || ''));
    const cur = (currentValue || '').trim();
    const opts = ['<option value="">-- dieses Item selbst (Default) --</option>'];
    for (const it of items) {
        if (excludeId && it.id === excludeId) continue;  // self nicht doppelt anbieten
        const sel2 = it.id === cur ? ' selected' : '';
        const cat = it.category || 'item';
        opts.push(`<option value="${escapeHtml(it.id)}"${sel2}>${escapeHtml((it.name || it.id) + ' (' + cat + ')')}</option>`);
    }
    sel.innerHTML = opts.join('');
}

async function _setupSingleOutfitTypePicker(selectId, newInputId, hiddenId,
                                             initialValue) {
    // Suggestions laden
    let types = _outfitTypeCache.slice();
    if (!types.length) {
        try {
            const r = await fetch(`/inventory/outfit-types`);
            if (r.ok) {
                const data = await r.json();
                types = data.outfit_types || [];
                _outfitTypeCache = types.slice();
            }
        } catch (_) {}
    }
    const sel = document.getElementById(selectId);
    const newInput = document.getElementById(newInputId);
    const hidden = document.getElementById(hiddenId);
    if (!sel || !hidden) return;

    const opts = ['<option value="">— kein Dress-Code —</option>'];
    for (const t of [...types].sort((a, b) => a.localeCompare(b))) {
        opts.push(`<option value="${escapeHtml(t)}">${escapeHtml(t)}</option>`);
    }
    sel.innerHTML = opts.join('');
    if (newInput) newInput.style.display = 'none';

    const init = (initialValue || '').trim();
    if (init && Array.from(sel.options).some(o => o.value === init)) {
        sel.value = init;
        hidden.value = init;
    } else if (init) {
        // Typ existiert nicht mehr in der Liste — trotzdem als Option aufnehmen
        // (mit Hinweis) damit der gespeicherte Wert sichtbar bleibt.
        const stale = document.createElement('option');
        stale.value = init;
        stale.textContent = `${init} (nicht in Admin-Typen)`;
        stale.selected = true;
        sel.appendChild(stale);
        hidden.value = init;
    } else {
        sel.value = '';
        hidden.value = '';
    }

    sel.onchange = () => {
        hidden.value = sel.value;
    };
}

async function saveWardrobePiece() {
    const editId = document.getElementById('wpc-edit-id').value.trim();
    const name = document.getElementById('wpc-name').value.trim();
    const slots = _readWpcSlots();
    const promptFragment = document.getElementById('wpc-prompt-fragment').value.trim();
    const description = document.getElementById('wpc-description').value.trim();
    const imagePrompt = document.getElementById('wpc-image-prompt').value.trim();
    const status = document.getElementById('wpc-status');
    if (!name) { if (status) status.textContent = 'Bitte Name angeben.'; return; }
    if (!promptFragment) { if (status) status.textContent = 'Bitte Prompt-Fragment angeben.'; return; }
    if (!slots.length) { if (status) status.textContent = 'Bitte mindestens einen Slot waehlen.'; return; }
    const c = _wardrobeState.character;

    if (editId) {
        // UPDATE existing
        if (status) status.textContent = 'Speichere...';
        try {
            const r = await fetch(`/inventory/items/${encodeURIComponent(editId)}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({

                    name,
                    description,
                    category: 'outfit_piece',
                    image_prompt: imagePrompt,
                    prompt_fragment: promptFragment,
                    outfit_piece: { slots, outfit_types: _readOutfitTypes(), covers: _readWpcCovers(), partially_covers: _readWpcPartiallyCovers(), lora: _readWpcLora() },
                }),
            });
            if (!r.ok) {
                const d = await r.json().catch(() => ({}));
                if (status) status.textContent = t('Error') + `: ${d.detail || t('Save failed')}`;
                return;
            }
            if (status) status.textContent = `'${name}' aktualisiert.`;
        } catch (e) {
            if (status) status.textContent = `Fehler: ${e.message || e}`;
            return;
        }
        await _wardrobeRefresh();
        // Wieder im Edit-Modus halten — Form behaelt Inhalt
        _wardrobeState.previewItemId = editId;
        _wardrobeFormLoad(_wardrobeState.inventory.find(x => x.item_id === editId));
        _setPiecePreview(editId);
        return;
    }

    // CREATE new
    if (status) status.textContent = 'Lege an...';
    try {
        const itemRes = await fetch('/inventory/items', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                name,
                description,
                category: 'outfit_piece',
                image_prompt: imagePrompt,
                prompt_fragment: promptFragment,
                outfit_piece: { slots, outfit_types: _readOutfitTypes(), covers: _readWpcCovers(), partially_covers: _readWpcPartiallyCovers(), lora: _readWpcLora() },
            }),
        });
        if (!itemRes.ok) {
            const d = await itemRes.json().catch(() => ({}));
            if (status) status.textContent = t('Error') + `: ${d.detail || t('Item creation failed')}`;
            return;
        }
        const { item } = await itemRes.json();
        const invRes = await fetch(`/inventory/characters/${encodeURIComponent(c)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ item_id: item.id }),
        });
        if (!invRes.ok) {
            const d = await invRes.json().catch(() => ({}));
            if (status) status.textContent = t('Item created, but inventory add failed') + `: ${d.detail || ''}`;
        } else {
            if (status) status.textContent = `'${name}' angelegt + im Inventar.`;
        }
        await _wardrobeRefresh();
        // Direkt in Edit-Modus wechseln, damit Bild-Generierung greift
        _wardrobeState.previewItemId = item.id;
        const enriched = _wardrobeState.inventory.find(x => x.item_id === item.id);
        if (enriched) _wardrobeFormLoad(enriched);
        _setPiecePreview(item.id);
    } catch (e) {
        if (status) status.textContent = `Fehler: ${e.message || e}`;
    }
}

// Backwards-Compat — alte Funktion ruft die neue
async function createWardrobePiece() { return saveWardrobePiece(); }

async function deleteWardrobePiece(itemId) {
    if (!confirm('Outfit-Teil endgueltig loeschen?')) return;
    try {
        const r = await fetch(`/inventory/items/${encodeURIComponent(itemId)}`, {
            method: 'DELETE',
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || t('Delete failed'), 'error');
            return;
        }
    } catch (e) { showStatusToast(t('Delete failed'), 'error'); return; }
    await _wardrobeRefresh();
}

async function saveWardrobeAsSet() {
    const c = _wardrobeState.character;
    // Quelle je nach Modus: Set-Editor nutzt ephemeralen Edit-State,
    // sonst faellt er auf den real-Equipped-State zurueck (z.B. Erstanlage).
    const eq = _wardrobeState.setEditMode
        ? (_wardrobeState.setEditPieces || {})
        : (_wardrobeState.equipped.equipped_pieces || {});
    const pieces = Object.values(eq).filter(Boolean);
    if (!pieces.length && !(_wardrobeState.setRemoveSlots || new Set()).size) {
        showStatusToast(t('No pieces in set — nothing to save.'), 'error');
        return;
    }

    const existingSets = (_wardrobeState.outfits || []).filter(o => (o.pieces || []).length);
    _openWardrobeSaveAsDialog(existingSets, (targetName, updateId) => {
        _doSaveWardrobeSet(c, pieces, targetName, updateId);
    });
}

function _openWardrobeSaveAsDialog(existingSets, onChoose) {
    const overlay = document.createElement('div');
    overlay.className = 'caption-mode-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    const dialog = document.createElement('div');
    dialog.className = 'prompt-edit-dialog';
    dialog.style.maxWidth = '480px';
    dialog.style.width = 'min(480px, 92vw)';

    const listHtml = existingSets.length
        ? existingSets.map(o => `
            <button type="button" class="wardrobe-saveas-pick"
                    data-id="${escapeHtml(o.id || '')}" data-name="${escapeHtml(o.name || '')}"
                    style="display:block;width:100%;text-align:left;padding:8px 12px;margin-bottom:4px;border-radius:6px;border:1px solid var(--border);background:var(--bg-alt);cursor:pointer;color:var(--text);">
                👕 ${escapeHtml(o.name || '(unbenannt)')}
                <span style="color:var(--text-muted);font-size:11px;margin-left:6px;">${escapeHtml(t('overwrite'))}</span>
            </button>`).join('')
        : '<p class="scheduler-empty" style="font-size:12px;">Noch keine Sets vorhanden.</p>';

    dialog.innerHTML = `
        <div class="caption-mode-title">Speichern unter…</div>
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:6px;">${escapeHtml(t('Overwrite existing set:'))}</div>
        <div style="max-height:40vh;overflow-y:auto;margin-bottom:12px;">${listHtml}</div>
        <label style="font-size:12px;color:var(--text-muted);">Oder neuer Name:</label>
        <input type="text" class="agent-status-input wardrobe-saveas-new" placeholder="${escapeHtml(t('Name for new set'))}" style="margin-top:4px;">
        <div class="prompt-edit-actions" style="margin-top:12px;">
            <button class="prompt-edit-btn prompt-edit-cancel">Abbrechen</button>
            <button class="prompt-edit-btn prompt-edit-submit save-btn">Neu anlegen</button>
        </div>
    `;
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);

    const input = dialog.querySelector('.wardrobe-saveas-new');
    input.focus();

    dialog.querySelectorAll('.wardrobe-saveas-pick').forEach(b => {
        b.onclick = () => {
            overlay.remove();
            onChoose(b.dataset.name || '', b.dataset.id || '');
        };
    });
    dialog.querySelector('.prompt-edit-cancel').onclick = () => overlay.remove();
    const submit = () => {
        const name = (input.value || '').trim();
        if (!name) { showStatusToast(t('Name missing'), 'error'); return; }
        // Kollision mit bestehendem Namen → Update auf dieses Set
        const existing = existingSets.find(o => (o.name || '').toLowerCase() === name.toLowerCase());
        overlay.remove();
        onChoose(name, existing ? (existing.id || '') : '');
    };
    dialog.querySelector('.prompt-edit-submit').onclick = submit;
    input.onkeydown = (e) => { if (e.key === 'Enter') submit(); };
}

async function _doSaveWardrobeSet(characterName, pieces, name, updateId) {
    // Outfit-Beschreibung aus Pieces zusammenbauen (Backwards-Compat)
    const fragments = [];
    for (const pid of pieces) {
        const it = _wardrobeState.inventory.find(x => x.item_id === pid);
        if (it && (it.item_prompt_fragment || '').trim()) {
            fragments.push(it.item_prompt_fragment.trim());
        }
    }
    const outfitText = fragments.length ? `wearing: ${fragments.join(', ')}` : '';
    // Farben pro Slot aus dem Set-Editor mitspeichern
    const pieces_colors = {};
    const _ec = _wardrobeState.setEditColors || {};
    for (const [slot, color] of Object.entries(_ec)) {
        if (color) pieces_colors[slot] = color;
    }
    try {
        const body = {
            name, pieces, outfit: outfitText,
            remove_slots: Array.from(_wardrobeState.setRemoveSlots || []),
            pieces_colors,
        };
        if (updateId) body.id = updateId;
        const r = await fetch(`/characters/${encodeURIComponent(characterName)}/outfits`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || t('Saving set failed'), 'error');
            return;
        }
        const data = await r.json();
        showStatusToast(updateId ? `${t('Set')} '${name}' ${t('updated')}` : `${t('Set')} '${name}' ${t('saved')}`, 'success');
        await _loadWardrobeData();
        const newId = data.id || updateId;
        const sel = document.getElementById('wardrobe-set-select');
        if (newId && sel) {
            sel.value = newId;
            _onWardrobeSetSelected();
        }
    } catch (e) {
        showStatusToast(t('Saving set failed'), 'error');
    }
}

async function previewWardrobeSetImage() {
    const c = _wardrobeState.character;
    if (!c) return;
    // Vorschau geht unabhaengig vom Dropdown: sie generiert immer fuer die
    // Items die gerade in Spalte 2 stehen — im Set-Editor die setEditPieces,
    // im Live-Modus die real-equipped Pieces des Characters.
    const pieces = _wardrobeState.setEditMode
        ? (_wardrobeState.setEditPieces || {})
        : (_wardrobeState.equipped.equipped_pieces || {});
    // Label fuer den Toast: Set-Name falls ausgewaehlt, sonst "aktuell angelegt"
    const sel = document.getElementById('wardrobe-set-select');
    const outfitId = sel ? sel.value : '';
    let label = 'aktuell angelegt';
    if (outfitId && outfitId !== '__new__') {
        const o = (_wardrobeState.outfits || []).find(x => x.id === outfitId);
        if (o && o.name) label = o.name;
    } else if (outfitId === '__new__') {
        label = 'neues Set';
    }
    const pairs = Object.entries(pieces)
        .filter(([, iid]) => !!iid)
        .map(([slot, iid]) => `${slot}:${iid}`)
        .join(',');
    // Farben aus dem Edit-State (Set-Editor) oder live aus Character-Meta
    const _colorsSrc = _wardrobeState.setEditMode
        ? (_wardrobeState.setEditColors || {})
        : Object.fromEntries(Object.entries(
            _wardrobeState.equipped.equipped_pieces_meta || {}
          ).map(([s, m]) => [s, (m && m.color) || '']));
    const colorPairs = Object.entries(_colorsSrc)
        .filter(([slot, color]) => !!color && !!pieces[slot])
        .map(([slot, color]) => `${slot}:${color}`)
        .join(',');
    // Leere pieces -> valider "naked" Variant (Hash von leerem Equipped).
    // force=1 loescht einen evtl. vorhandenen Cache-Eintrag und erzwingt
    // Neugenerierung — der User hat Vorschau aktiv angefordert.
    const url = `/characters/${encodeURIComponent(c)}/outfit-expression`
        + `?mood=&activity=&override=1&trigger=1&force=1&pieces=${encodeURIComponent(pairs)}&items=`
        + `&piece_colors=${encodeURIComponent(colorPairs)}&t=${Date.now()}`;

    try {
        const r = await fetch(url);
        if (r.status === 202 || r.status === 200) {
            showStatusToast(
                r.status === 202
                    ? `Vorschau fuer '${label}' in Warteschlange`
                    : `Vorschau fuer '${label}' aktualisiert`,
                'success',
            );
            // Preview-Panel pollt selbst bis das Bild fertig ist (202 → retry).
            _loadWardrobePreview(c);
        } else {
            const d = await r.json().catch(() => ({}));
            showStatusToast(t('Error') + `: ${d.detail || t('Generation failed')}`, 'error');
        }
    } catch (e) {
        showStatusToast(t('Error') + `: ${e.message || e}`, 'error');
    }
}

async function deleteWardrobeSet() {
    const sel = document.getElementById('wardrobe-set-select');
    if (!sel || !sel.value) return;
    const outfitId = sel.value;
    const o = (_wardrobeState.outfits || []).find(x => x.id === outfitId);
    if (!o) return;
    if (!confirm(`Set '${o.name || outfitId}' loeschen?`)) return;
    const c = _wardrobeState.character;
    try {
        const r = await fetch(`/characters/${encodeURIComponent(c)}/outfits`, {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ id: outfitId }),
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || t('Delete failed'), 'error');
            return;
        }
        showStatusToast(t('Set') + ` '${o.name || ''}' ` + t('deleted'), 'success');
        await _loadWardrobeData();
        if (sel) sel.value = '';
        _onWardrobeSetSelected();
    } catch (e) {
        showStatusToast(t('Delete failed'), 'error');
    }
}

async function applyEquippedFromColumn() {
    // Wendet Spalte 2 aufs Profil an — unabhaengig davon ob ein Set ausgewaehlt
    // ist. Im Live-Modus ist Spalte 2 == real equipped -> no-op Toast.
    const c = _wardrobeState.character;
    if (!c) return;
    const editMode = !!_wardrobeState.setEditMode;
    const pieces = editMode
        ? (_wardrobeState.setEditPieces || {})
        : (_wardrobeState.equipped.equipped_pieces || {});
    const removeSlots = Array.from(_wardrobeState.setRemoveSlots || []);
    // Farb-Overrides: im Edit-Mode kommt's aus setEditColors, sonst pieces_meta im Profil.
    const pieces_meta = {};
    if (editMode) {
        const ec = _wardrobeState.setEditColors || {};
        for (const [slot, color] of Object.entries(ec)) {
            if (color) pieces_meta[slot] = { color };
        }
    }
    if (!editMode && !removeSlots.length) {
        showStatusToast(t('Current items are already worn'), 'info');
        return;
    }
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(c)}/apply-equipped`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                pieces,
                remove_slots: removeSlots,
                pieces_meta,
            }),
        });
        if (!r.ok) {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || t('Apply failed'), 'error');
            return;
        }
        const data = await r.json();
        const applied = (data.applied || []).length;
        const skipped = (data.skipped || []).length;
        const cleared = (data.cleared || []).length;
        showStatusToast(
            skipped
                ? `Angezogen: ${applied} OK, ${cleared} geleert, ${skipped} fehlend`
                : `Angezogen: ${applied} OK, ${cleared} geleert`,
            skipped ? 'info' : 'success',
        );
    } catch (e) { showStatusToast(t('Apply failed'), 'error'); return; }
    // Nach Anziehen: zurueck in Live-Modus (Dropdown reset), damit
    // die frisch angelegten Pieces aus dem Server angezeigt werden —
    // nicht der alte Set-Editor-Stand.
    _wardrobeState.setEditMode = false;
    _wardrobeState.setEditPieces = {};
    _wardrobeState.setEditColors = {};
    _wardrobeState.setRemoveSlots = new Set();
    const sel = document.getElementById('wardrobe-set-select');
    if (sel) sel.value = '';
    await _wardrobeRefresh();
    _loadWardrobePreview(_wardrobeState.character);
}

// --- Garderobe-Picker (Outfit-Pieces-basiert, fuer Avatar UND Chat-Character) ---
// Eine Funktion fuer beide Seiten — characterName entscheidet wer angesprochen
// wird. Faellt zurueck auf den alten Freitext-Outfit-Picker wenn der Character
// keine outfit_piece-Items im Inventar hat (Backwards-Compat).

const SLOT_LABELS_DE = {
    head: 'Kopf', neck: 'Hals',
    underwear_top: 'Unterwaesche oben', underwear_bottom: 'Unterwaesche unten',
    legs: 'Beine', feet: 'Fuesse',
    top: 'Oberteil', bottom: 'Unterteil',
    outer: 'Mantel & Jacke',
};
// Anzeige-Reihenfolge: Kopf, Hals, Jacke, Oberteil, Unterwaesche oben,
// Unterteil, Unterwaesche unten, Beine, Fuesse.
const SLOT_ORDER = [
    'head', 'neck', 'outer', 'top', 'underwear_top',
    'bottom', 'underwear_bottom', 'legs', 'feet',
];

// Schematische Silhouette einer Person (Front-View). Jeder Slot hat ein
// oder mehrere Shapes (z.B. legs/feet jeweils zwei). Reihenfolge im Render
// bestimmt Z-Index — Innenliegende (underwear) liegen ueber den aeusseren.
// Trapezformen geben dem Body anatomisch glaubwuerdige Proportionen
// (Schultern > Taille, Beine konisch).
// Schultern (Top oben) und Arme (Outer) sind ggu der ersten Variante 20% schmaler.
// Die obere Aussenkante der Schulter (Outer) und die obere Top-Ecke sind als
// Bezier-Kurven gezeichnet, damit der Schulter-Bereich anatomisch rund wirkt.
const SLOT_SHAPES = {
    head: [{ t: 'ellipse', cx: 90, cy: 32, rx: 20, ry: 24 }],
    neck: [{ t: 'polygon', points: '82,55 98,55 102,68 78,68' }],
    outer: [
        { t: 'path', d: 'M 43,70 L 58,70 L 56,180 L 34,180 L 39,76 Q 39,70 43,70 Z' },
        { t: 'path', d: 'M 122,70 L 137,70 Q 141,70 141,76 L 146,180 L 124,180 L 122,70 Z' },
    ],
    top: [{ t: 'path', d: 'M 62,70 L 118,70 Q 122,70 122,75 L 122,130 L 58,130 L 58,75 Q 58,70 62,70 Z' }],
    underwear_top: [{ t: 'polygon', points: '62,80 118,80 114,112 66,112' }],
    bottom: [{ t: 'polygon', points: '58,130 122,130 126,186 54,186' }],
    // Slip sitzt am unteren Rand des Bottoms (knapp ueberm Hosen-Saum).
    underwear_bottom: [{ t: 'polygon', points: '70,160 110,160 106,184 74,184' }],
    legs: [
        { t: 'polygon', points: '56,186 88,186 82,310 64,310' },
        { t: 'polygon', points: '92,186 124,186 116,310 98,310' },
    ],
    feet: [
        { t: 'ellipse', cx: 73, cy: 320, rx: 18, ry: 8 },
        { t: 'ellipse', cx: 107, cy: 320, rx: 18, ry: 8 },
    ],
};
// Render-Reihenfolge so, dass Underwear ueber Top/Bottom liegt (visuell sichtbar
// auch wenn Top selektiert ist). Outer wird zuerst gezeichnet, head/neck/legs/feet
// am Schluss (haben keine Ueberlappung).
const SLOT_RENDER_ORDER = [
    'outer', 'top', 'underwear_top', 'bottom', 'underwear_bottom',
    'legs', 'feet', 'neck', 'head',
];

// Generelle Silhouette-Render-Funktion. Liest die aktuellen Slot-Listen und
// faerbt die Slot-Zonen entsprechend ein:
//   slots: blau — alle Slots, die das Piece physisch belegt (symmetrisch)
//   partially_covers: grau gestreift (Diagonal-Pattern)
//   covers: grau (solid)
function renderSlotSilhouette(container, opts) {
    if (!container) return;
    const slots = new Set((opts.slots || []).map(s => String(s).trim()).filter(Boolean));
    const covers = new Set((opts.covers || []).map(s => String(s).trim()));
    const partial = new Set((opts.partiallyCovers || []).map(s => String(s).trim()));
    const labels = opts.labels || SLOT_LABELS_DE;

    const STRIPE_PATTERN_ID = 'silhouette-stripe-pattern';
    const SLOT_FILL = '#3b82f6';      // blau
    const SLOT_STROKE = '#1d4ed8';
    const COVER_FILL = '#9ca3af';     // grau
    const COVER_STROKE = '#6b7280';
    const PARTIAL_STROKE = '#6b7280';

    const _fill = (slot) => {
        if (slots.has(slot)) return { fill: SLOT_FILL, stroke: SLOT_STROKE };
        if (covers.has(slot)) return { fill: COVER_FILL, stroke: COVER_STROKE };
        if (partial.has(slot)) return { fill: `url(#${STRIPE_PATTERN_ID})`, stroke: PARTIAL_STROKE };
        return { fill: 'rgba(255,255,255,0.05)', stroke: 'rgba(255,255,255,0.25)' };
    };

    let svg = `<svg viewBox="0 0 180 340" style="width:100%;max-width:144px;height:auto;display:block;">`;
    // Diagonale Blau/Grau-Schraffur fuer "teilweise verdeckt" — kombiniert
    // visuell die "Slot"-Farbe (blau) mit der "Cover"-Farbe (grau) in
    // gleich breiten Streifen.
    svg += `<defs><pattern id="${STRIPE_PATTERN_ID}" patternUnits="userSpaceOnUse" width="8" height="8" patternTransform="rotate(45)">
        <rect x="0" width="4" height="8" fill="${SLOT_FILL}"/>
        <rect x="4" width="4" height="8" fill="${COVER_FILL}"/>
    </pattern></defs>`;
    for (const slot of SLOT_RENDER_ORDER) {
        const shapes = SLOT_SHAPES[slot] || [];
        const { fill, stroke } = _fill(slot);
        const title = `<title>${escapeHtml(labels[slot] || slot)}</title>`;
        for (const s of shapes) {
            if (s.t === 'circle') {
                svg += `<circle cx="${s.cx}" cy="${s.cy}" r="${s.r}" fill="${fill}" stroke="${stroke}" stroke-width="1.5">${title}</circle>`;
            } else if (s.t === 'rect') {
                svg += `<rect x="${s.x}" y="${s.y}" width="${s.w}" height="${s.h}" rx="3" fill="${fill}" stroke="${stroke}" stroke-width="1.5">${title}</rect>`;
            } else if (s.t === 'ellipse') {
                svg += `<ellipse cx="${s.cx}" cy="${s.cy}" rx="${s.rx}" ry="${s.ry}" fill="${fill}" stroke="${stroke}" stroke-width="1.5">${title}</ellipse>`;
            } else if (s.t === 'polygon') {
                svg += `<polygon points="${s.points}" fill="${fill}" stroke="${stroke}" stroke-width="1.5" stroke-linejoin="round">${title}</polygon>`;
            } else if (s.t === 'path') {
                svg += `<path d="${s.d}" fill="${fill}" stroke="${stroke}" stroke-width="1.5" stroke-linejoin="round">${title}</path>`;
            }
        }
    }
    svg += `</svg>`;

    // Legende: kleine Patches mit denselben Stilen wie in der Silhouette.
    // Die Schraffur fuer "teilweise" wird ueber CSS-Hintergrund nachgebildet,
    // damit sie auch ohne SVG-<defs> in einem normalen <span> sichtbar ist.
    const stripeBg = `repeating-linear-gradient(45deg, ${SLOT_FILL} 0 3px, ${COVER_FILL} 3px 6px)`;
    const legend = `<div style="display:flex;flex-wrap:wrap;gap:8px;font-size:10px;margin-top:6px;justify-content:center;color:var(--text-muted);">
        <span style="display:inline-flex;align-items:center;gap:3px;"><span style="width:10px;height:10px;background:${SLOT_FILL};border:1px solid ${SLOT_STROKE};border-radius:2px;"></span>Slot(s)</span>
        <span style="display:inline-flex;align-items:center;gap:3px;"><span style="width:10px;height:10px;background:${stripeBg};border:1px solid ${PARTIAL_STROKE};border-radius:2px;"></span>teilweise verdeckt</span>
        <span style="display:inline-flex;align-items:center;gap:3px;"><span style="width:10px;height:10px;background:${COVER_FILL};border:1px solid ${COVER_STROKE};border-radius:2px;"></span>komplett verdeckt</span>
    </div>`;

    container.innerHTML = svg + legend;
}

async function openGarderobePicker(characterName) {
    if (!characterName) return;

    // Inventar + Equipped-Zustand parallel laden
    let inventory = [];
    let equipped = { equipped_pieces: {}, equipped_items: [] };
    try {
        const [invRes, eqRes] = await Promise.all([
            fetch(`/inventory/characters/${encodeURIComponent(characterName)}?include_equipped=true`),
            fetch(`/inventory/characters/${encodeURIComponent(characterName)}/equipped`),
        ]);
        if (invRes.ok) inventory = ((await invRes.json()).inventory || []);
        if (eqRes.ok) equipped = await eqRes.json();
    } catch (e) { /* mit leerem Stand fortfahren */ }

    const pieceItems = inventory.filter(it => it.item_category === 'outfit_piece');
    const otherItems = inventory.filter(it =>
        it.item_category !== 'outfit_piece' && (it.item_prompt_fragment || '').trim()
    );

    // Backwards-Compat: keine Pieces -> alter Freitext-Picker
    if (!pieceItems.length) {
        return openAvatarOutfitPicker(characterName);
    }

    // Pieces nach Slot gruppieren (nur Pieces in Inventar). Multi-Slot-Pieces
    // tauchen in jeder ihrer Slot-Gruppen auf, damit der Picker sie unter jeder
    // Kategorie anzeigt — Equip kuemmert sich um die symmetrische Belegung.
    const piecesBySlot = {};
    for (const it of pieceItems) {
        const slots = (it.outfit_piece && it.outfit_piece.slots) || [];
        for (const slot of slots) {
            if (!slot) continue;
            (piecesBySlot[slot] ||= []).push(it);
        }
    }

    const overlay = document.createElement('div');
    overlay.className = 'caption-mode-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    const dialog = document.createElement('div');
    dialog.className = 'prompt-edit-dialog';
    dialog.style.maxWidth = '720px';
    dialog.style.width = 'min(720px, 92vw)';

    const _itemImg = (id) =>
        `/inventory/items/${encodeURIComponent(id)}/image`;

    const _renderChip = (it, slot) => {
        const id = it.item_id;
        const name = it.item_name || id;
        return `<div class="garderobe-chip" data-slot="${escapeHtml(slot)}" data-item="${escapeHtml(id)}"
                     style="display:flex;align-items:center;gap:6px;padding:4px 8px;border:1px solid var(--accent);background:var(--bg);border-radius:8px;">
            ${it.item_image ? `<img src="${_itemImg(id)}" style="height:32px;width:auto;max-width:56px;object-fit:contain;border-radius:4px;background:var(--bg-alt);">` : '📦'}
            <span style="font-size:12px;">${escapeHtml(name)}</span>
            <button class="reset-btn garderobe-unequip" data-slot="${escapeHtml(slot)}" data-item="${escapeHtml(id)}"
                    title="Ablegen" style="padding:2px 6px;font-size:11px;">✕</button>
        </div>`;
    };

    // Slot-Reihen
    const slotRowsHtml = SLOT_ORDER.map(slot => {
        const equippedId = equipped.equipped_pieces[slot] || '';
        const candidates = piecesBySlot[slot] || [];
        const equippedItem = equippedId
            ? pieceItems.find(it => it.item_id === equippedId)
            : null;

        let chip = '';
        if (equippedItem) {
            chip = _renderChip(equippedItem, slot);
        } else if (candidates.length) {
            // Add-Dropdown: zeigt verfuegbare Pieces fuer diesen Slot
            const opts = ['<option value="">+ Anlegen...</option>']
                .concat(candidates.map(it =>
                    `<option value="${escapeHtml(it.item_id)}">${escapeHtml(it.item_name)}</option>`
                )).join('');
            chip = `<select class="garderobe-add agent-status-input" data-slot="${escapeHtml(slot)}"
                            style="font-size:12px;padding:4px 6px;">${opts}</select>`;
        } else {
            chip = `<span style="font-size:11px;color:var(--text-muted);font-style:italic;">— nichts im Inventar —</span>`;
        }
        return `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;">
            <div style="font-size:11px;color:var(--text-muted);min-width:140px;">${escapeHtml(SLOT_LABELS_DE[slot] || slot)}</div>
            ${chip}
        </div>`;
    }).join('');

    // Equipped-Items-Sektion
    const equippedItemIds = new Set(equipped.equipped_items || []);
    const equippedNonPieces = otherItems.filter(it => equippedItemIds.has(it.item_id));
    const availableNonPieces = otherItems.filter(it => !equippedItemIds.has(it.item_id));
    const itemsSection = `
        <div style="margin-top:14px;border-top:1px solid var(--border);padding-top:10px;">
            <div style="font-size:13px;color:var(--text-muted);margin-bottom:6px;">Ausruestung (Hand / sonstiges)</div>
            <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:6px;">
                ${equippedNonPieces.length
                    ? equippedNonPieces.map(it => _renderChip(it, '__item__')).join('')
                    : '<span style="font-size:11px;color:var(--text-muted);font-style:italic;">— nichts angelegt —</span>'}
            </div>
            ${availableNonPieces.length ? `
                <select class="garderobe-add-item agent-status-input" style="font-size:12px;padding:4px 6px;">
                    <option value="">+ Item anlegen...</option>
                    ${availableNonPieces.map(it =>
                        `<option value="${escapeHtml(it.item_id)}">${escapeHtml(it.item_name)}</option>`
                    ).join('')}
                </select>` : ''}
        </div>`;

    dialog.innerHTML = `
        <div class="caption-mode-title">Garderobe — ${escapeHtml(characterName)}</div>
        <div style="display:flex;flex-direction:column;gap:0;max-height:55vh;overflow-y:auto;">
            ${slotRowsHtml}
        </div>
        ${itemsSection}
        <div class="prompt-edit-actions" style="margin-top:12px;">
            <button class="prompt-edit-btn prompt-edit-cancel">Schliessen</button>
        </div>
    `;
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);

    const refresh = async () => {
        overlay.remove();
        // Sowohl Avatar- als auch NPC-Expression neu laden — die Funktion
        // weiss selbst welcher Character welches Bild bedient.
        if (typeof updatePlayerExpression === 'function') {
            try { updatePlayerExpression(getPlayerCharacterName()); } catch (_) {}
        }
        if (typeof updateCharacterScene === 'function' && currentCharacterName) {
            try { updateCharacterScene(currentCharacterName); } catch (_) {}
        }
        await openGarderobePicker(characterName);
    };

    // Equip per Dropdown (Piece)
    dialog.querySelectorAll('.garderobe-add').forEach(sel => {
        sel.onchange = async () => {
            const itemId = sel.value;
            if (!itemId) return;
            try {
                const r = await fetch(`/inventory/characters/${encodeURIComponent(characterName)}/equip`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ item_id: itemId }),
                });
                if (!r.ok) {
                    const d = await r.json().catch(() => ({}));
                    showStatusToast(d.detail || t('Equip failed'), 'error');
                    return;
                }
                await refresh();
            } catch (e) {
                showStatusToast(t('Equip failed'), 'error');
            }
        };
    });

    // Equip per Dropdown (Item)
    const itemSel = dialog.querySelector('.garderobe-add-item');
    if (itemSel) {
        itemSel.onchange = async () => {
            const itemId = itemSel.value;
            if (!itemId) return;
            try {
                const r = await fetch(`/inventory/characters/${encodeURIComponent(characterName)}/equip`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ item_id: itemId }),
                });
                if (!r.ok) {
                    const d = await r.json().catch(() => ({}));
                    showStatusToast(d.detail || t('Equip failed'), 'error');
                    return;
                }
                await refresh();
            } catch (e) {
                showStatusToast(t('Equip failed'), 'error');
            }
        };
    }

    // Unequip per [✕]
    dialog.querySelectorAll('.garderobe-unequip').forEach(btn => {
        btn.onclick = async (e) => {
            e.stopPropagation();
            const slot = btn.dataset.slot;
            const itemId = btn.dataset.item;
            const body = (slot && slot !== '__item__')
                ? { slot }
                : { item_id: itemId };
            try {
                const r = await fetch(`/inventory/characters/${encodeURIComponent(characterName)}/unequip`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(body),
                });
                if (!r.ok) {
                    const d = await r.json().catch(() => ({}));
                    showStatusToast(d.detail || t('Unequip failed'), 'error');
                    return;
                }
                await refresh();
            } catch (e) {
                showStatusToast(t('Unequip failed'), 'error');
            }
        };
    });

    dialog.querySelector('.prompt-edit-cancel').onclick = () => overlay.remove();
}

// --- Avatar Outfit Picker (manuelle Wahl, kein Auto-Picker, kein Cooldown) ---

async function openAvatarOutfitPicker(avatarName) {
    if (!avatarName) return;
    let outfits = [];
    let equippedIds = new Set();
    try {
        const [oRes, eqRes] = await Promise.all([
            fetch(`/characters/${encodeURIComponent(avatarName)}/outfits`),
            fetch(`/inventory/characters/${encodeURIComponent(avatarName)}/equipped`),
        ]);
        if (oRes.ok) outfits = (await oRes.json()).outfits || [];
        if (eqRes.ok) {
            const eq = await eqRes.json();
            equippedIds = new Set(Object.values(eq.equipped_pieces || {}));
        }
    } catch (e) { /* trotzdem leer rendern */ }
    const _isCurrent = (o) => {
        const ids = new Set(o.pieces || []);
        if (!ids.size) return false;
        if (ids.size !== equippedIds.size) return false;
        for (const i of ids) if (!equippedIds.has(i)) return false;
        return true;
    };

    const overlay = document.createElement('div');
    overlay.className = 'caption-mode-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };

    const dialog = document.createElement('div');
    dialog.className = 'prompt-edit-dialog';
    dialog.style.maxWidth = '720px';
    dialog.style.width = 'min(720px, 92vw)';

    let gridHtml = '';
    if (!outfits.length) {
        gridHtml = `<p class="scheduler-empty">${escapeHtml(t('No outfits configured.'))}</p>`;
    } else {
        gridHtml = '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;max-height:65vh;overflow-y:auto;padding:4px;">';
        for (const o of outfits) {
            const name = o.name || '';
            const isActive = _isCurrent(o);
            const imgSrc = o.image
                ? `/characters/${encodeURIComponent(avatarName)}/outfits/${encodeURIComponent(o.image)}?t=${Date.now()}`
                : '';
            gridHtml += `
                <div class="avatar-outfit-card${isActive ? ' avatar-outfit-active' : ''}"
                     data-outfit="${escapeHtml(name)}"
                     style="border:2px solid ${isActive ? 'var(--accent)' : 'var(--border)'};border-radius:10px;padding:6px;cursor:pointer;background:var(--bg-alt);text-align:center;">
                    ${imgSrc
                        ? `<img src="${imgSrc}" style="width:100%;aspect-ratio:2/3;object-fit:contain;background:var(--bg);border-radius:6px;" alt="${escapeHtml(name)}">`
                        : `<div style="width:100%;aspect-ratio:2/3;display:flex;align-items:center;justify-content:center;color:var(--text-muted);font-size:12px;background:var(--bg);border-radius:6px;">kein Bild</div>`}
                    <div style="font-size:12px;margin-top:4px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(name)}</div>
                </div>`;
        }
        gridHtml += '</div>';
    }

    dialog.innerHTML = `
        <div class="caption-mode-title">Outfit fuer ${escapeHtml(avatarName)} waehlen</div>
        ${gridHtml}
        <div class="prompt-edit-actions" style="margin-top:12px;">
            <button class="prompt-edit-btn prompt-edit-cancel">Schliessen</button>
        </div>
    `;
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);

    dialog.querySelector('.prompt-edit-cancel').onclick = () => overlay.remove();
    dialog.querySelectorAll('.avatar-outfit-card').forEach(card => {
        card.onclick = async () => {
            const outfitName = card.dataset.outfit;
            try {
                const resp = await fetch(`/inventory/characters/${encodeURIComponent(avatarName)}/apply-outfit-set`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ name: outfitName }),
                });
                if (resp.ok) {
                    const data = await resp.json().catch(() => ({}));
                    showStatusToast(t('Outfit') + `: ${outfitName}`, 'success');
                    overlay.remove();
                    if (data.changed !== false) updatePlayerExpression(avatarName);
                } else {
                    showStatusToast(t('Outfit change failed'), 'error');
                }
            } catch (e) {
                showStatusToast(t('Outfit change failed'), 'error');
            }
        };
    });
}

// Spiegelung von updateCharacterScene() fuer den Avatar: laedt das
// aktuelle Outfit + Expression-Variante in die GROSSE Avatar-Szene
// rechts vom Chat (`#player-scene-img`).
async function updatePlayerExpression(avatarName) {
    const sceneImg = document.getElementById('player-scene-img');
    if (!sceneImg) return;
    if (!avatarName) {
        sceneImg.style.display = 'none';
        sceneImg.src = '';
        _setPlayerSceneOutfitLabel('');
        _updateOutfitLockButton('avatar', null);
        _updateSceneWardrobeButton('avatar', null);
        return;
    }
    // Wardrobe / Inventory / Lock buttons should be available as soon as an
    // avatar is selected — the wardrobe button is the entry point for
    // creating the very first outfit, so it must not be gated on an outfit
    // already existing. Lock is per-character, also fine to show empty.
    _updateOutfitLockButton('avatar', avatarName);
    _updateSceneWardrobeButton('avatar', avatarName);
    _setPlayerSceneOutfitLabel(avatarName);
    sceneImg.onclick = null;
    sceneImg.style.cursor = '';
    sceneImg.title = '';

    // Try to find an outfit with a rendered image as placeholder. If none,
    // _loadExpressionImage falls back to the default profile image while
    // the per-mood expression variant renders in the background.
    let target = null;
    try {
        const outfitsRes = await fetch(`/characters/${encodeURIComponent(avatarName)}/outfits`);
        const outfits = outfitsRes.ok ? ((await outfitsRes.json()).outfits || []) : [];
        target = outfits.find(o => o.image) || null;
    } catch (e) { /* no placeholder; expression endpoint will provide fallback */ }
    await _loadExpressionImage(avatarName, sceneImg, target, _PLAYER_EXPR);
}

function _setPlayerSceneOutfitLabel(characterName) {
    _setEquippedPiecesLabel('player-scene-outfit', characterName);
}

// --- Tool Status Labels ---
const TOOL_STATUS_LABELS = {
    'ImageGenerator': 'Bild wird generiert',
    'Instagram': 'Instagram-Post wird erstellt',
    'WebSearch': 'Websuche laeuft',
    'SetLocation': 'Standort wird gesetzt',
    'SetMood': 'Stimmung wird gesetzt',
};

function getToolStatusLabel(toolName) {
    return TOOL_STATUS_LABELS[toolName] || `${toolName} wird ausgefuehrt`;
}

// --- Authentifizierung (Cookie-basiert — kein Client-State mehr) ---
let currentUsername = null;
let currentUserRole = '';
let currentUserAllowedChars = [];

// --- UI Language ---
// Default from localStorage or browser language; overridden after user profile loads
let uiLang = localStorage.getItem('uiLang') || (navigator.language || 'de').split('-')[0];

// Translation map for static UI strings (English source -> translated string).
// Loaded lazily from /i18n/translations/<lang>; empty when uiLang === 'en'.
let _uiTranslations = {};
const _uiMissingLogged = new Set();

async function loadTranslations(lang) {
    if (!lang || lang === 'en') {
        _uiTranslations = {};
        return;
    }
    try {
        const res = await fetch(`/i18n/translations/${encodeURIComponent(lang)}`);
        if (res.ok) {
            const data = await res.json();
            _uiTranslations = data.translations || {};
        } else {
            _uiTranslations = {};
        }
    } catch (e) {
        console.warn('loadTranslations failed:', e);
        _uiTranslations = {};
    }
}

// Translate an English UI source string. Falls back to the source on miss.
// Each missing key is warned about once so dev can spot coverage gaps.
function t(en) {
    if (!en) return en;
    if (uiLang === 'en') return en;
    const hit = _uiTranslations[en];
    if (hit) return hit;
    const k = `${uiLang}::${en}`;
    if (!_uiMissingLogged.has(k)) {
        _uiMissingLogged.add(k);
        if (typeof console !== 'undefined') console.debug(`[i18n] missing [${uiLang}]: ${en}`);
    }
    return en;
}

// Walk the DOM and translate all elements marked for i18n:
//   <span data-i18n="Save">Save</span>
//     -> textContent is set to t('Save'); the original English source is
//        captured in data-i18n-src on first run so a later language change
//        can re-translate from the same source.
//   <button data-i18n-title="Cancel" title="Cancel">×</button>
//     -> title attribute translated.
//   <input data-i18n-placeholder="Enter your name" placeholder="...">
//     -> placeholder attribute translated.
// data-i18n="" (empty) means: take the existing textContent as the English
// source on first run. Useful when the source string is already in the HTML.
function applyTranslations(root) {
    const scope = root || document;
    // textContent
    scope.querySelectorAll('[data-i18n]').forEach(el => {
        let src = el.getAttribute('data-i18n');
        if (!src) {
            src = (el.getAttribute('data-i18n-src') || el.textContent || '').trim();
            if (src && !el.getAttribute('data-i18n-src')) el.setAttribute('data-i18n-src', src);
        } else if (!el.getAttribute('data-i18n-src')) {
            el.setAttribute('data-i18n-src', src);
        }
        if (src) el.textContent = t(src);
    });
    // title attribute
    scope.querySelectorAll('[data-i18n-title]').forEach(el => {
        const src = el.getAttribute('data-i18n-title');
        if (src) el.setAttribute('title', t(src));
    });
    // placeholder attribute
    scope.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
        const src = el.getAttribute('data-i18n-placeholder');
        if (src) el.setAttribute('placeholder', t(src));
    });
    // alt attribute (images)
    scope.querySelectorAll('[data-i18n-alt]').forEach(el => {
        const src = el.getAttribute('data-i18n-alt');
        if (src) el.setAttribute('alt', t(src));
    });
}

// Early bootstrap — runs as soon as the DOM is ready, before auth completes.
// Loads translations for the cached uiLang (LocalStorage / browser-default) and
// translates all static [data-i18n] markers in the page. After login, the
// user's profile language may differ — `loadUiLanguage()` then re-runs both.
document.addEventListener('DOMContentLoaded', async () => {
    try {
        await loadTranslations(uiLang);
        applyTranslations();
        // Reflect uiLang on the <html> element so CSS / a11y tooling sees it.
        try { document.documentElement.setAttribute('lang', uiLang || 'en'); } catch (_) {}
    } catch (e) {
        console.warn('[i18n] bootstrap failed:', e);
    }
});

// Return the localized label from a template object (section, field, option, tab).
// Falls back to 'label' if no language-specific key exists.
function tLabel(obj) {
    if (!obj) return '';
    return obj[`label_${uiLang}`] || obj.label || '';
}

// Return the localized hint from a template object.
function tHint(obj) {
    if (!obj) return '';
    return obj[`hint_${uiLang}`] || obj.hint || '';
}

// DOM-Elemente
const chatMessages = document.getElementById('chat-messages');
const userInput = document.getElementById('user-input');
const sendButton = document.getElementById('send-button');

// Globale Variable für aktuellen Character-Namen
// 'KI' bedeutet: kein Character ausgewählt (Platzhalter, kein gültiger Character-Name)
let currentCharacterName = 'KI';

// --- Group Chat State ---
let chatMode = 'direct';  // 'direct' | 'group'
let _groupSession = null;  // {session_id, participants, location_name, location_id}

// Aktuelles Chat-Medium fuer Direct-Chat: 'in_person' (default, am gleichen Ort)
// oder 'messaging' (Phone-Chat — Avatar nicht im Raum).
// WIRD AUTOMATISCH aus dem Vergleich Avatar-Location vs. Partner-Location
// abgeleitet via _recomputeChatMedium(). Manuelles Setzen ist nicht mehr noetig.
let currentChatMedium = 'in_person';

async function _recomputeChatMedium(forceMedium) {
    // forceMedium='messaging' setzt unabhaengig von Locations (z.B. Phone-Picker
    // explizit fuer Charactere ohne Location/Chatbots), sonst aus Locations
    // abgeleitet.
    const partner = currentCharacterName;
    if (!partner || partner === 'KI') {
        currentChatMedium = 'in_person';
        return currentChatMedium;
    }
    const prev = currentChatMedium;
    if (forceMedium) {
        currentChatMedium = forceMedium;
    } else {
        try {
            // Avatar-Name aus DOM-Select; bei Page-Init ist der ggf. noch
            // nicht populated -> dann vom Server holen, sonst faellt der Phone-
            // Chat-Mode nach jedem Refresh faelschlich auf face-to-face zurueck.
            let avatarName = (typeof getPlayerCharacterName === 'function')
                ? getPlayerCharacterName() : '';
            if (!avatarName) {
                try {
                    const _ar = await fetch('/account/active-character');
                    if (_ar.ok) {
                        const _ad = await _ar.json();
                        avatarName = _ad.active_character || '';
                    }
                } catch {}
            }
            if (!avatarName) {
                currentChatMedium = 'in_person';
            } else {
                const [aResp, pResp] = await Promise.all([
                    fetch(`/characters/${encodeURIComponent(avatarName)}/current-location`),
                    fetch(`/characters/${encodeURIComponent(partner)}/current-location`),
                ]);
                let aLoc = '', pLoc = '', aRoom = '', pRoom = '';
                if (aResp.ok) {
                    const d = await aResp.json();
                    aLoc = (d.current_location_id || d.current_location || '').toString();
                    aRoom = (d.current_room || '').toString();
                }
                if (pResp.ok) {
                    const d = await pResp.json();
                    pLoc = (d.current_location_id || d.current_location || '').toString();
                    pRoom = (d.current_room || '').toString();
                }
                // in_person nur wenn beide im SELBEN Ort UND SELBEN Raum sind.
                // Verschiedene Raeume am gleichen Ort = raeumlich getrennt =
                // Phone-Chat. Wenn Partner gar keine Location hat (Chatbot),
                // bleibt es in_person damit Variant-Bild gezeigt werden kann.
                let _medium = 'in_person';
                if (aLoc && pLoc) {
                    if (aLoc !== pLoc) {
                        _medium = 'messaging';
                    } else if (aRoom && pRoom && aRoom !== pRoom) {
                        _medium = 'messaging';
                    }
                }
                currentChatMedium = _medium;
            }
        } catch (e) {
            // Bei Fehler bisherigen Wert beibehalten
            console.warn('[ChatMedium] recompute failed:', e);
        }
    }
    if (currentChatMedium !== prev) {
        // UI-Folgeeffekte: Phone-Btn-Highlight + Scene-Bild umschalten
        const _phoneBtn = document.getElementById('btn-phone-chat');
        if (_phoneBtn) _phoneBtn.classList.toggle('active', currentChatMedium === 'messaging');
        if (typeof updateCharacterScene === 'function') {
            updateCharacterScene(currentCharacterName);
        }
    }
    return currentChatMedium;
}

function _renderPhoneBookDialog(chars) {
    return new Promise((resolve) => {
        const overlay = document.createElement('div');
        overlay.className = 'modal';
        overlay.style.display = 'flex';
        overlay.style.zIndex = '4000';

        const content = document.createElement('div');
        content.className = 'modal-content phonebook-modal';
        content.style.width = 'min(440px, 92vw)';
        content.style.maxHeight = 'min(80vh, 700px)';
        content.style.display = 'flex';
        content.style.flexDirection = 'column';
        content.style.padding = '0';

        const header = document.createElement('div');
        header.className = 'modal-header phonebook-header';
        header.innerHTML = `
            <h2>📞 Telefonbuch</h2>
            <button type="button" class="modal-close" aria-label="Schliessen">×</button>
        `;
        content.appendChild(header);

        const search = document.createElement('input');
        search.type = 'text';
        search.placeholder = 'Suchen...';
        search.className = 'agent-status-input phonebook-search';
        content.appendChild(search);

        const list = document.createElement('div');
        list.className = 'phonebook-list';
        content.appendChild(list);

        function render(filter) {
            list.innerHTML = '';
            const f = (filter || '').trim().toLowerCase();
            const visible = chars.filter(c =>
                !f || c.name.toLowerCase().includes(f) ||
                (c.location || '').toLowerCase().includes(f)
            );
            if (!visible.length) {
                list.innerHTML = '<div class="phonebook-empty">Niemand gefunden</div>';
                return;
            }
            for (const c of visible) {
                const row = document.createElement('button');
                row.type = 'button';
                row.className = 'phonebook-row';
                if (c.unread > 0) row.classList.add('has-unread');
                const av = c.avatar || generateDefaultAvatar(c.name);
                const loc = c.location ? c.location : '— unbekannter Ort —';
                const badge = c.unread > 0
                    ? `<span class="phonebook-unread-badge">${c.unread > 99 ? '99+' : c.unread}</span>`
                    : '';
                row.innerHTML = `
                    <img class="phonebook-avatar" src="${escapeHtml(av)}" alt="${escapeHtml(c.name)}" onerror="this.src='${generateDefaultAvatar(c.name).replace(/'/g, "\\'")}'">
                    <div class="phonebook-info">
                        <div class="phonebook-name">${escapeHtml(c.name)}</div>
                        <div class="phonebook-location">📍 ${escapeHtml(loc)}</div>
                    </div>
                    ${badge}
                `;
                row.addEventListener('click', () => {
                    cleanup();
                    resolve(c.name);
                });
                list.appendChild(row);
            }
        }

        function cleanup() {
            try { overlay.remove(); } catch (_) {}
            document.removeEventListener('keydown', onKey);
        }
        function onKey(e) {
            if (e.key === 'Escape') { cleanup(); resolve(null); }
        }
        document.addEventListener('keydown', onKey);
        header.querySelector('.modal-close').addEventListener('click', () => { cleanup(); resolve(null); });
        overlay.addEventListener('click', (e) => {
            if (e.target === overlay) { cleanup(); resolve(null); }
        });
        search.addEventListener('input', () => render(search.value));

        overlay.appendChild(content);
        document.body.appendChild(overlay);
        render('');
        setTimeout(() => search.focus(), 30);
    });
}

async function openPhoneChatPicker() {
    if (isChatBusy) {
        showStatusToast(t('Phone-chat switch not possible while chat is active'), 'error');
        return;
    }
    let allChars = [];
    try {
        const r = await fetch(`/characters/list`);
        if (r.ok) {
            const d = await r.json();
            allChars = (d.characters || []).map(c => typeof c === 'string' ? {name: c} : c);
        }
    } catch (e) {
        showStatusToast(t('Could not load character list.'), 'error');
        return;
    }
    let avatar = '';
    try {
        avatar = (typeof getPlayerCharacterName === 'function') ? getPlayerCharacterName() : '';
    } catch (e) {}
    const filtered = allChars.filter(c => c.name && c.name !== avatar);
    if (!filtered.length) {
        showStatusToast(t('No characters available for phone chat.'), 'info');
        return;
    }
    // Pro Character: Location + Profilbild parallel laden (fuer Telefonbuch-View)
    const charsRich = await Promise.all(filtered.map(async (c) => {
        let locName = '', avatarUrl = '';
        try {
            const lr = await fetch(`/characters/${encodeURIComponent(c.name)}/current-location`);
            if (lr.ok) {
                const ld = await lr.json();
                locName = ld.current_location || '';
            }
        } catch (_) {}
        try {
            const ir = await fetch(`/characters/${encodeURIComponent(c.name)}/images`);
            if (ir.ok) {
                const id = await ir.json();
                if (id.profile_image) {
                    avatarUrl = `/characters/${encodeURIComponent(c.name)}/images/${encodeURIComponent(id.profile_image)}`;
                }
            }
        } catch (_) {}
        return {
            name: c.name,
            location: locName,
            avatar: avatarUrl,
            unread: _unreadCountFor(c.name),
        };
    }));
    // Sortierung: ungelesene zuerst (count desc), dann alphabetisch
    charsRich.sort((a, b) => {
        if (b.unread !== a.unread) return b.unread - a.unread;
        return a.name.localeCompare(b.name);
    });
    const name = await _renderPhoneBookDialog(charsRich);
    if (!name) return;
    if (chatMode === 'group') {
        chatMode = 'direct';
        _groupSession = null;
        _updateGroupHeader(false);
        _showGroupChatBar(false);
    }
    if (name !== currentCharacterName) {
        await fetch(`/store/default/chat_partner`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: name })
        });
        currentCharacterName = name;
        // Medium aus Locations herleiten — wenn Picker-Char zufaellig am
        // gleichen Ort steht, wird automatisch in_person.
        await _recomputeChatMedium();
        updateCharacterScene(name);
        _closeOverlayPanels();
        chatMessages.innerHTML = '';
        _currentCharacterRoom = '';
        _updateHeaderActivity('', '', '');
        setAgentButtonsVisible(true);
        await Promise.all([loadKnownInfo(), _loadCharacterHeaderState(name), loadHeaderMood(), loadStatusEffectsBars(), loadConditionBadges()]);
        await loadChatHistory();
        loadInitialPrompt();
        loadCharacterSidebar();
    } else {
        await _recomputeChatMedium();
    }
    const _label = currentChatMedium === 'messaging'
        ? `📞 Phone-Chat mit ${name}.`
        : `Chat mit ${name} (am gleichen Ort).`;
    showStatusToast(_label, 'info', 5000);
}

function hasValidCharacter() {
    return currentCharacterName && currentCharacterName !== 'KI';
}

function getPlayerCharacterName() {
    return document.getElementById('active-character-select')?.value || '';
}

// === Chat-Gift-Picker — neben Chat-Input ===

async function _openChatGiftPicker() {
    const box = document.getElementById('chat-gift-picker');
    const body = document.getElementById('chat-gift-picker-body');
    if (!box || !body) return;
    const avatar = getPlayerCharacterName();
    const partner = (typeof currentCharacterName !== 'undefined' ? currentCharacterName : '') || '';
    if (!avatar) {
        showStatusToast(t('No avatar active — please choose a character at the top'), 'error');
        return;
    }
    if (!partner || partner === 'KI') {
        showStatusToast(t('No chat partner active'), 'error');
        return;
    }
    body.innerHTML = `<div style="color:var(--text-muted);">${escapeHtml(t('Loading inventory…'))}</div>`;
    box.style.display = 'block';
    setTimeout(() => document.addEventListener('click', _chatGiftPickerOutsideClick), 0);
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(avatar)}?include_equipped=false`);
        if (!r.ok) {
            body.innerHTML = '<div style="color:var(--error-color);">Inventar konnte nicht geladen werden.</div>';
            return;
        }
        const data = await r.json();
        const items = (data.inventory || []).filter(e => e.item_transferable !== false);
        if (!items.length) {
            body.innerHTML = `<div style="color:var(--text-muted);">${escapeHtml(avatar)} hat keine uebertragbaren Items.</div>`;
            return;
        }
        body.innerHTML = `<div style="font-size:11px;color:var(--text-muted);margin-bottom:6px;">→ ${escapeHtml(partner)}</div>` +
            items.map(e => {
                const qty = (e.quantity && e.quantity > 1) ? ` ×${e.quantity}` : '';
                const cat = e.item_category || '';
                const rarity = e.item_rarity || '';
                return `<div onclick="_chatGiftClickItem('${escapeHtml(e.item_id)}','${escapeHtml(e.item_name)}')"
                    style="display:flex;align-items:center;gap:8px;padding:6px;cursor:pointer;border-radius:4px;border-bottom:1px solid var(--border-light);"
                    onmouseenter="this.style.background='var(--bg-elev)'" onmouseleave="this.style.background='transparent'">
                    <span style="font-weight:600;">${escapeHtml(e.item_name)}</span>${qty}
                    <span style="font-size:10px;color:var(--text-muted);margin-left:auto;">${escapeHtml(rarity)} · ${escapeHtml(cat)}</span>
                </div>`;
            }).join('');
    } catch (e) {
        body.innerHTML = `<div style="color:var(--error-color);">Fehler: ${escapeHtml(String(e))}</div>`;
    }
}

function _closeChatGiftPicker() {
    const box = document.getElementById('chat-gift-picker');
    if (box) box.style.display = 'none';
    document.removeEventListener('click', _chatGiftPickerOutsideClick);
}

function _chatGiftPickerOutsideClick(e) {
    if (e.target.closest('#chat-gift-picker') ||
        e.target.id === 'btn-gift-item') return;
    _closeChatGiftPicker();
}

async function _chatGiftClickItem(itemId, itemName) {
    const avatar = getPlayerCharacterName();
    const partner = (typeof currentCharacterName !== 'undefined' ? currentCharacterName : '') || '';
    if (!avatar || !partner) return;
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(avatar)}/${encodeURIComponent(itemId)}/give`, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({to_character: partner}),
        });
        if (!r.ok) {
            const t = await r.text();
            showStatusToast(t('Gift failed') + ': ' + t.slice(0, 80), 'error');
            return;
        }
        const data = await r.json();
        showStatusToast(`'${data.item_name || itemName}' ` + t('gifted to') + ` ${partner} (` + t('relationship boost') + ` +${data.boost || 0})`, 'success');
    } catch (e) {
        showStatusToast(t('Gift error') + ': ' + e.message, 'error');
    }
    _closeChatGiftPicker();
}

// The character being edited — set explicitly by every modal-open function.
// Unlike the old _editorTargetCharacter, this is ALWAYS set at open time,
// never read-then-forget. Every openXxxModal(char) sets it.
let _modalCharacter = '';

function getEditorCharacterName() {
    return _modalCharacter || currentCharacterName;
}

function _closeOverlayPanels() {
    const gallery = document.getElementById('gallery-panel');
    if (gallery && galleryPanelOpen) { gallery.style.display = 'none'; galleryPanelOpen = false; }
    const insta = document.getElementById('instagram-panel');
    if (insta && instagramPanelOpen) { insta.style.display = 'none'; instagramPanelOpen = false; }
}

function setAgentButtonsVisible(visible) {
    const ids = ['btn-edit-agent', 'btn-knowledge'];
    const display = visible ? '' : 'none';
    ids.forEach(id => {
        const el = document.getElementById(id);
        if (el) el.style.display = display;
    });
    // Beim Verstecken (kein Agent): 📷 + 💭-Header-Mood-Line clearen.
    // Beim Anzeigen NICHT explizit anschalten — die werden vom Profil-Load
    // bzw. loadHeaderMood gesetzt, je nach Datenverfuegbarkeit.
    if (!visible) {
        const genBtn = document.getElementById('btn-generate-profile-image');
        if (genBtn) genBtn.style.display = 'none';
        const moodLine = document.getElementById('header-mood-line');
        if (moodLine) { moodLine.textContent = ''; moodLine.style.display = 'none'; }
    }
}

async function updateStoryTabVisibility() {
    const chatBtn = document.querySelector('.tab-btn[data-tab="chat"]');
    const storyBtn = document.querySelector('.tab-btn[data-tab="story"]');
    const storyDevBtn = document.querySelector('.tab-btn[data-tab="storydev"]');
    const worldDevBtn = document.querySelector('.tab-btn[data-tab="worlddev"]');

    // World Dev tab: always visible when logged in
    if (worldDevBtn) {
        worldDevBtn.style.display = '';
    }

    if (!hasValidCharacter()) {
        // Kein Agent → alle agent-gebundenen Tabs ausblenden (Chat, Story, StoryDev)
        if (chatBtn) chatBtn.style.display = 'none';
        if (storyBtn) storyBtn.style.display = 'none';
        if (storyDevBtn) storyDevBtn.style.display = 'none';
        const activeTab = document.querySelector('.tab-btn.tab-active');
        if (activeTab && ['chat', 'story', 'storydev'].includes(activeTab.dataset.tab)) {
            // Aktiven Tab abwaehlen — kein Hinweis-Inhalt
            activeTab.classList.remove('tab-active');
            document.querySelectorAll('.tab-content').forEach(c => {
                c.classList.remove('tab-content-active');
                c.style.display = 'none';
            });
        }
        return;
    }

    // Agent vorhanden: Chat IMMER sichtbar
    if (chatBtn) chatBtn.style.display = '';

    // Wenn nach Re-Selektion kein Tab aktiv ist (User kam aus Kein-Agent-Zustand)
    // → Chat aktivieren, sonst bleibt der Content-Bereich leer.
    if (!document.querySelector('.tab-btn.tab-active')) {
        switchTab('chat');
    }

    if (!storyBtn || !storyDevBtn) return;

    try {
        const profileResp = await fetch(`/characters/${encodeURIComponent(currentCharacterName)}/profile`);
        if (!profileResp.ok) return;
        const profileData = await profileResp.json();
        const templateName = (profileData.profile && profileData.profile.template) || 'default';

        const templateResp = await fetch(`/templates/${encodeURIComponent(templateName)}`);
        let features = {};
        if (templateResp.ok) {
            const template = await templateResp.json();
            features = template.features || {};
        }

        // Default true fuer Rueckwaertskompatibilitaet (alte Templates ohne features)
        const storyEnabled = features.story_enabled !== false;
        const storyDevEnabled = features.storydev_enabled !== false;

        storyBtn.style.display = storyEnabled ? '' : 'none';
        storyDevBtn.style.display = storyDevEnabled ? '' : 'none';

        // Falls aktiver Tab jetzt versteckt ist, zu Chat wechseln
        const activeTab = document.querySelector('.tab-btn.tab-active');
        if (activeTab) {
            const tabName = activeTab.dataset.tab;
            if ((tabName === 'story' && !storyEnabled) || (tabName === 'storydev' && !storyDevEnabled)) {
                switchTab('chat');
            }
        }
    } catch (e) {
        console.warn('[TabVisibility] Fehler:', e);
    }
}

// Chat-Busy-State: Deaktiviert nur Chat-Eingabe während LLM-Antwort.
// Character-Management (Bilder, Persönlichkeit, Aussehen) bleibt nutzbar.
let isChatBusy = false;
let chatBusySafetyTimer = null;

function setChatBusy(busy) {
    isChatBusy = busy;
    sendButton.disabled = busy;
    userInput.disabled = busy;

    // Visueller Indikator
    document.body.classList.toggle('chat-busy', busy);

    // Beim Stream-Ende: Polling-Baseline aktualisieren. Client-Uhr als
    // Provisorium (sofortige Wirkung), und parallel die *echte* Server-
    // Timestamp aus /chat/.../history?limit=1 holen — sonst sieht der
    // naechste Poll-Tick "ts != lastSeenTs" wegen Client/Server-Clock-Skew
    // und nuked die DOM kurz, was als Flicker erscheint.
    if (!busy) {
        try { _chatLastSeenTs = new Date().toISOString(); } catch (_) {}
        _chatPollMuteUntil = Date.now() + 7000;
        // limit=5 deckt Multi-Message-Persistenz (User-Send + Assistant-
        // Reply +/- Notification etc.) ab — Diff-Poller braucht die
        // hoechste DB-id als Baseline, sonst rendert er die eben optimistisch
        // angezeigten Bubbles spaeter erneut.
        fetch('/chat/default/history?limit=5')
            .then(r => r.ok ? r.json() : null)
            .then(d => {
                const arr = (d && d.messages) || [];
                if (!arr.length) return;
                const last = arr[arr.length - 1];
                if (last && last.timestamp) _chatLastSeenTs = last.timestamp;
                let maxId = _chatLastSeenId;
                for (const m of arr) { if ((m.id || 0) > maxId) maxId = m.id; }
                _chatLastSeenId = maxId;
            })
            .catch(() => {})
            .finally(() => { _chatPollMuteUntil = 0; });
        // Sofortiger Live-Tick — Skill-Effekte (Inventar/Conditions/Stats/
        // Mood/Activity-Aenderungen aus dem Stream) sollen sichtbar werden,
        // ohne auf den 3s-Tick zu warten.
        if (typeof _triggerImmediateTick === 'function') _triggerImmediateTick();
    }

    // Safety-Valve: Automatischer Reset nach 3 Minuten falls stuck
    if (chatBusySafetyTimer) {
        clearTimeout(chatBusySafetyTimer);
        chatBusySafetyTimer = null;
    }
    if (busy) {
        chatBusySafetyTimer = setTimeout(() => {
            if (isChatBusy) {
                console.warn('[Chat] Safety-Valve: Busy-State war >3min aktiv, setze zurück');
                setChatBusy(false);
            }
        }, 180000);
    }
}

// --- Authentication Functions ---

function applyAdminOnlyVisibility() {
    const show = currentUserRole === 'admin';
    document.querySelectorAll('[data-admin-only]').forEach(el => {
        if (!show) el.style.display = 'none';
        else el.style.removeProperty('display');
    });
}

async function verifyToken() {
    try {
        const response = await fetch('/auth/status', { credentials: 'same-origin' });
        if (response.ok) {
            const data = await response.json();
            if (data.authenticated && data.user) {
                currentUsername = data.user.username;
                currentUserRole = data.user.role || '';
                currentUserAllowedChars = data.user.allowed_characters || [];
                applyAdminOnlyVisibility();
                return true;
            }
        }
    } catch (e) {
        console.error('Auth status check failed:', e);
    }
    currentUsername = null;
    currentUserRole = '';
    currentUserAllowedChars = [];
    applyAdminOnlyVisibility();
    localStorage.removeItem('currentUsername');
    return false;
}

function showAuthModal() {
    document.getElementById('auth-modal').style.display = 'flex';
    const u = document.getElementById('login-username');
    if (u) u.focus();
}

function hideAuthModal() {
    document.getElementById('auth-modal').style.display = 'none';
    const pw = document.getElementById('login-password');
    if (pw) pw.value = '';
    const err = document.getElementById('login-error');
    if (err) err.style.display = 'none';
}

// ── Character Selection (shown after login) ─────────────────────────────────

async function showCharacterSelector(loginData) {
    const chars = loginData.characters || [];
    const activeChar = loginData.active_character || loginData.default_character || '';

    // If only one character exists, skip selection and go straight to chat
    if (chars.length === 1) {
        await selectCharacterAndStart(chars[0]);
        return;
    }
    // If no characters exist, go straight to app (user needs to create one first)
    if (chars.length === 0) {
        await initializeApp();
        return;
    }

    const grid = document.getElementById('character-select-list');
    grid.innerHTML = '';

    for (const name of chars) {
        const card = document.createElement('div');
        card.className = 'character-select-card' + (name === activeChar ? ' active' : '');

        // Try to load profile image
        let imgSrc = '';
        try {
            const resp = await fetch(`/characters/${encodeURIComponent(name)}/images`);
            if (resp.ok) {
                const d = await resp.json();
                if (d.profile_image) {
                    imgSrc = `/characters/${encodeURIComponent(name)}/images/${d.profile_image}`;
                }
            }
        } catch(e) {}

        card.innerHTML = `
            <img src="${imgSrc || '/static/themes/default-avatar.png'}" alt="${name}"
                 onerror="this.style.display='none'">
            <span class="cs-name">${name}</span>
        `;
        card.addEventListener('click', async () => {
            document.getElementById('character-select-modal').style.display = 'none';
            await selectCharacterAndStart(name);
        });
        grid.appendChild(card);
    }

    document.getElementById('character-select-modal').style.display = 'flex';
}

async function selectCharacterAndStart(characterName) {
    // Tell backend which character we're controlling
    try {
        await fetch('/account/switch-character', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ character_name: characterName }),
        });
    } catch(e) {
        console.warn('switch-character failed:', e);
    }

    // Set chat partner to the first OTHER character (not ourselves)
    let chatPartner = '';
    try {
        const resp = await fetch(`/account/characters`);
        if (resp.ok) {
            const data = await resp.json();
            const others = (data.characters || []).filter(c => c !== characterName);
            if (others.length > 0) chatPartner = others[0];
        }
    } catch(e) {}

    // Store the chat partner as agent_name (this is who we talk TO)
    if (chatPartner) {
        try {
            await fetch(`/store/default/chat_partner`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ value: chatPartner }),
            });
        } catch(e) {}
    }

    await initializeApp();
    showStatusToast(t('Playing as') + ` ${characterName}`, 'success');
}

async function populateActiveCharacterDropdown() {
    const select = document.getElementById('active-character-select');
    if (!select) return;

    try {
        const resp = await fetch(`/account/characters`);
        if (!resp.ok) return;
        const data = await resp.json();
        const chars = data.characters || [];
        const active = data.active_character || '';

        if (chars.length === 0) {
            select.style.display = 'none';
            return;
        }

        select.innerHTML = '';
        for (const name of chars) {
            const opt = document.createElement('option');
            opt.value = name;
            opt.textContent = name;
            if (name === active) opt.selected = true;
            select.appendChild(opt);
        }
        select.style.display = '';

        // Remove old listener and attach new one
        select.onchange = async function() {
            const newChar = this.value;
            if (!newChar) return;
            await selectCharacterAndStart(newChar);
        };
    } catch(e) {
        select.style.display = 'none';
    }
}

async function loadPlayerAvatar() {
    // Notice-Banner mitziehen — Avatar-Wechsel = anderer Force/Event-Kontext.
    if (typeof refreshCharNotice === 'function') refreshCharNotice();
    const img = document.getElementById('player-profile-image');
    const barsDiv = document.getElementById('player-status-bars');
    const genBtn = document.getElementById('btn-player-gen-image');
    if (!img) return;

    let activeChar = document.getElementById('active-character-select')?.value || '';
    if (!activeChar) {
        try {
            const _r = await fetch(`/account/characters`);
            if (_r.ok) { const _d = await _r.json(); activeChar = _d.active_character || ''; }
        } catch(e) {}
    }
    if (!activeChar) {
        img.style.display = 'none';
        if (barsDiv) { barsDiv.style.display = 'none'; barsDiv.innerHTML = ''; }
        if (genBtn) genBtn.style.display = 'none';
        return;
    }

    // Load profile image (same API as the chat header uses)
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(activeChar)}/images`);
        if (resp.ok) {
            const data = await resp.json();
            const profileImageName = data.profile_image;
            if (profileImageName) {
                img.src = `/characters/${encodeURIComponent(activeChar)}/images/${profileImageName}`;
                img.style.display = 'block';
            } else {
                img.src = generateDefaultAvatar(activeChar);
                img.style.display = 'block';
            }
            img.title = '';
            img.style.cursor = '';
            img.onclick = null;
        }
    } catch(e) { img.style.display = 'none'; }

    // Show gen button — opens image generation dialog for the player character
    if (genBtn) {
        genBtn.style.display = '';
        genBtn.onclick = async () => {
            if (!activeChar) return;
            let appearance = '';
            try {
                const r = await fetch(`/characters/${encodeURIComponent(activeChar)}/profile`);
                if (r.ok) {
                    const d = await r.json();
                    // /profile-Endpoint wrappt: {character, profile: {...}} — d.profile lesen!
                    const p = d.profile || d;
                    // Reihenfolge: face_appearance_resolved (Tokens aufgeloest) > face_appearance (raw) >
                    // character_appearance_resolved > character_appearance.
                    appearance = (p.face_appearance_resolved
                        || p.face_appearance
                        || p.character_appearance_resolved
                        || p.character_appearance
                        || '').trim();
                }
            } catch(e) {}
            await generateProfileImage(activeChar, appearance);
            // Refresh player avatar after generation
            setTimeout(() => loadPlayerAvatar(), 3000);
        };
    }

    // Player-Status-Bars (Stamina etc.) wie beim Agenten — kleiner gerendert
    loadPlayerStatusBars();

    // Load player activity display (room, activity, mood)
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(activeChar)}/current-location`);
        if (resp.ok) {
            const d = await resp.json();
            const roomEl = document.getElementById('player-room-line');
            const actEl = document.getElementById('player-activity-line');
            if (roomEl) {
                roomEl.textContent = d.current_room_name
                    ? `${d.current_location || ''} — ${d.current_room_name} 📍`
                    : (d.current_location ? `${d.current_location} 📍` : '(Ort setzen) 📍');
                roomEl.style.cursor = 'pointer';
                roomEl.title = 'Ort/Raum aendern';
                roomEl.onclick = () => openAvatarRoomPicker(activeChar);
            }
            if (actEl) {
                const detail = d.current_activity_detail || '';
                const act = d.current_activity || '';
                actEl.textContent = detail ? `${act} (${detail}) 🎭` : (act ? `${act} 🎭` : '(Aktivitaet setzen) 🎭');
                actEl.style.cursor = 'pointer';
                actEl.title = 'Aktivitaet aendern';
                actEl.onclick = () => openAvatarActivityPicker(activeChar);
            }
        }
    } catch(e) {}

    // Mood is stored separately — fetch from profile
    try {
        const moodEl = document.getElementById('player-mood-line');
        if (moodEl) {
            const r = await fetch(`/characters/${encodeURIComponent(activeChar)}/current-feeling`);
            if (r.ok) {
                const d = await r.json();
                const feeling = d.current_feeling || '';
                moodEl.textContent = feeling ? `${feeling} 💭` : '(Stimmung setzen) 💭';
            }
            moodEl.style.cursor = 'pointer';
            moodEl.title = 'Stimmung aendern';
            moodEl.onclick = () => openAvatarMoodPicker(activeChar);
        }
    } catch(e) {}

    // Expression-Variante ueberlagert das statische Profilbild sobald verfuegbar.
    updatePlayerExpression(activeChar);
}

