// --- Action Mode (Storyteller-driven action) ---
// chatMode === 'act' takes over the chat panel: the input field is
// repurposed for the action description, the regular send button posts to
// /act, the Storyteller-LLM narrates the consequence and the result is
// rendered as a narrator bubble. May resolve active disruption/danger events.

let _actScope = 'here';

function _renderActionBubble(senderName, text, scope, narration, resolved, eventId) {
    if (!chatMessages) return;
    const msgDiv = document.createElement('div');
    msgDiv.classList.add('message', 'action-message');
    const scopeLabel = scope === 'location'
        ? t('addressing the whole location')
        : t('in this room');
    const resolvedTag = resolved
        ? `<div class="action-resolved">${escapeHtml(t('Event resolved'))}${eventId ? ` (${escapeHtml(eventId)})` : ''}</div>`
        : '';
    const narrationHtml = narration
        ? `<div class="action-narration">${escapeHtml(narration)}</div>`
        : `<div class="action-narration action-narration-empty">${escapeHtml(t('No narration returned.'))}</div>`;
    msgDiv.innerHTML = `
        <div class="action-header">
            <span class="action-icon">🎭</span>
            <span class="action-sender">${escapeHtml(senderName)}</span>
            <span class="action-scope">${escapeHtml(scopeLabel)}</span>
        </div>
        <div class="action-input">${escapeHtml(text)}</div>
        ${narrationHtml}
        ${resolvedTag}
    `;
    chatMessages.appendChild(msgDiv);
    chatMessages.scrollTop = chatMessages.scrollHeight;
}

function _renderActionHistoryEntry(entry) {
    if (!chatMessages) return;
    const div = document.createElement('div');
    div.classList.add('message', 'action-message', 'action-history');
    const ts = entry.timestamp ? new Date(entry.timestamp).toLocaleString() : '';
    const resolvedTag = entry.event_resolved
        ? `<div class="action-resolved">${escapeHtml(t('Event resolved'))}</div>`
        : '';
    div.innerHTML = `
        <div class="action-header">
            <span class="action-icon">🎭</span>
            <span class="action-sender">${escapeHtml(t('You acted'))}</span>
            <span class="action-scope">${escapeHtml(ts)}</span>
        </div>
        <div class="action-input">${escapeHtml(entry.user_input || '')}</div>
        ${entry.storyteller_response ? `<div class="action-narration">${escapeHtml(entry.storyteller_response)}</div>` : ''}
        ${resolvedTag}
    `;
    chatMessages.appendChild(div);
}

async function _enterActMode() {
    const avatar = getPlayerCharacterName();
    if (!avatar) {
        showStatusToast(t('No active character'), 'error');
        return;
    }
    chatMode = 'act';
    if (typeof _groupSession !== 'undefined' && _groupSession) {
        _groupSession = null;
        try { _updateGroupHeader(false); _showGroupChatBar(false); } catch (e) {}
    }
    chatMessages.innerHTML = '';

    // Header banner: explanation + scope picker.
    const banner = document.createElement('div');
    banner.className = 'action-mode-banner';
    banner.innerHTML = `
        <div class="action-mode-title">🎭 ${escapeHtml(t('Action mode'))}</div>
        <div class="action-mode-desc">
            ${escapeHtml(t('Describe what you do. A Storyteller narrates the consequence. Active disruption/danger events may be resolved if your action fixes them.'))}
        </div>
        <div class="action-mode-scope">
            <label>${escapeHtml(t('Scope'))}:</label>
            <select id="act-scope-select" class="agent-status-input">
                <option value="here">${escapeHtml(t('This room'))}</option>
                <option value="location">${escapeHtml(t('Whole location'))}</option>
            </select>
        </div>
    `;
    chatMessages.appendChild(banner);
    const sel = document.getElementById('act-scope-select');
    if (sel) {
        sel.value = _actScope;
        sel.addEventListener('change', () => { _actScope = sel.value; });
    }

    // Past actions.
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(avatar)}/actions`);
        if (resp.ok) {
            const data = await resp.json();
            const entries = data.entries || [];
            if (entries.length) {
                const sep = document.createElement('div');
                sep.className = 'action-history-header';
                sep.textContent = t('Recent actions');
                chatMessages.appendChild(sep);
                for (const e of entries) {
                    _renderActionHistoryEntry(e);
                }
            } else {
                const empty = document.createElement('div');
                empty.className = 'action-history-empty';
                empty.textContent = t('No actions yet.');
                chatMessages.appendChild(empty);
            }
        }
    } catch (e) {
        console.warn('[Act] history load failed:', e);
    }

    if (typeof userInput !== 'undefined' && userInput) {
        userInput.placeholder = t('e.g. draws her bow and scares off the wolves');
        userInput.focus();
    }
    if (typeof loadCharacterSidebar === 'function') loadCharacterSidebar();
}

function _exitActMode() {
    chatMode = 'direct';
    chatMessages.innerHTML = '';
    if (typeof userInput !== 'undefined' && userInput) {
        userInput.placeholder = '';
    }
    if (typeof loadChatHistory === 'function') loadChatHistory();
    if (typeof loadCharacterSidebar === 'function') loadCharacterSidebar();
}

async function _sendActionFromChatInput(text) {
    const avatar = getPlayerCharacterName();
    if (!avatar) {
        showStatusToast(t('No active character'), 'error');
        return;
    }
    const scope = (document.getElementById('act-scope-select')?.value) || _actScope || 'here';
    _actScope = scope;
    // Show a pending bubble while the Storyteller LLM works.
    const pending = document.createElement('div');
    pending.className = 'message action-message action-pending';
    pending.innerHTML = `<div class="action-header"><span class="action-icon">🎭</span><span class="action-sender">${escapeHtml(avatar)}</span><span class="action-scope">${escapeHtml(t('Narrating…'))}</span></div><div class="action-input">${escapeHtml(text)}</div>`;
    chatMessages.appendChild(pending);
    chatMessages.scrollTop = chatMessages.scrollHeight;
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(avatar)}/act`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ text, scope }),
        });
        pending.remove();
        if (!resp.ok) {
            const err = await resp.json().catch(() => ({}));
            showStatusToast(err.detail || t('Action failed'), 'error');
            return;
        }
        const data = await resp.json();
        _renderActionBubble(avatar, text, scope, data.narration || '', !!data.resolved, data.event_id || '');
        // If an event was resolved, refresh the character-notice banner so
        // the now-cleared block-rule disappears immediately.
        if (data.resolved && typeof refreshCharNotice === 'function') {
            try { refreshCharNotice(); } catch (e) {}
        }
    } catch (e) {
        pending.remove();
        showStatusToast(t('Action failed'), 'error');
    }
}

async function handleLogin() {
    const username = (document.getElementById('login-username').value || '').trim();
    const password = document.getElementById('login-password').value || '';
    const errorDiv = document.getElementById('login-error');

    if (!username || !password) {
        errorDiv.textContent = 'Benutzername und Passwort erforderlich';
        errorDiv.style.display = 'block';
        return;
    }

    try {
        const response = await fetch('/auth/login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            credentials: 'same-origin',
            body: JSON.stringify({ username, password })
        });

        if (!response.ok) {
            const data = await response.json().catch(() => ({}));
            errorDiv.textContent = data.detail || t('Login failed');
            errorDiv.style.display = 'block';
            return;
        }

        const data = await response.json();
        currentUsername = data.user?.username || username;
        currentUserRole = data.user?.role || '';
        currentUserAllowedChars = data.user?.allowed_characters || [];

        // Return-URL-Flow: wenn /?return=... gesetzt, dorthin redirecten
        const params = new URLSearchParams(window.location.search);
        const returnTo = params.get('return');
        if (returnTo && returnTo.startsWith('/')) {
            window.location.href = returnTo;
            return;
        }

        hideAuthModal();
        applyAdminOnlyVisibility();
        await initializeApp();
        populateActiveCharacterDropdown?.();
        showStatusToast(t('Welcome,') + ` ${currentUsername}!`, 'success');
    } catch (e) {
        errorDiv.textContent = 'Verbindungsfehler: ' + e.message;
        errorDiv.style.display = 'block';
    }
}

document.getElementById('btn-login')?.addEventListener('click', handleLogin);
document.getElementById('login-password')?.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') handleLogin();
});
document.getElementById('login-username')?.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') handleLogin();
});
document.getElementById('new-password-confirm')?.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') handleRegister();
});

// Hilfsfunktion: Formatiert Timestamp für Anzeige
function formatTimestamp(isoString) {
    const date = new Date(isoString);
    const now = new Date();
    const diffMs = now - date;
    const diffDays = Math.floor(diffMs / 86400000);

    // Wenn heute: "DD.MM. HH:MM"
    if (diffDays === 0) {
        return date.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' }) +
               ' ' + date.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });
    }
    // Wenn gestern: "Gestern HH:MM"
    else if (diffDays === 1) {
        return 'Gestern ' + date.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });
    }
    // Sonst: "DD.MM.YYYY HH:MM"
    else {
        return date.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' }) +
               ' ' + date.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });
    }
}

// Nachricht anzeigen (gibt das Element zurück)
function addMessage(sender, text, isUser = false) {
    const messageDiv = document.createElement('div');
    messageDiv.classList.add('message');
    messageDiv.classList.add(isUser ? 'user-message' : 'bot-message');
    if (currentChatMedium === 'messaging' || currentChatMedium === 'telegram') {
        messageDiv.classList.add('chat-msg-phone');
        messageDiv.dataset.medium = currentChatMedium;
    }
    messageDiv.innerHTML = `<strong>${sender}:</strong> ${text}`;
    chatMessages.appendChild(messageDiv);
    chatMessages.scrollTop = chatMessages.scrollHeight;
    return messageDiv;
}

/**
 * Entfernt Markdown-Bild-Tags mit externen URLs aus dem Text.
 * Behaelt nur lokale /characters/-Bilder. Externe Bild-Markdown
 * (z.B. halluzinierte URLs vom LLM) werden zum Alt-Text konvertiert.
 */
function stripExternalImages(text) {
    // Externe Bild-URLs entfernen: ![alt](http...) → alt
    // Lokale /characters/-URLs bleiben erhalten
    return text.replace(
        /!\[([^\]]*)\]\((?!\/characters\/)[^)]+\)/g,
        '$1'
    );
}

function extractImageUrls(text) {
    const urls = new Set();
    const markdownRegex = /!\[[^\]]*\]\((\/characters\/[^)]+)\)/g;
    let match = null;

    while ((match = markdownRegex.exec(text)) !== null) {
        urls.add(match[1]);
    }

    // Nur Markdown-Bilder extrahieren, kein zusätzliches Pattern
    // Das verhindert, dass nicht-existierende URLs aus dem Text geladen werden

    return Array.from(urls);
}

function appendImageGallery(messageElement, imageUrls) {
    if (!imageUrls || imageUrls.length === 0) {
        return;
    }

    // Bestehende Elemente entfernen
    const existing = messageElement.querySelector('.chat-image-gallery');
    if (existing) existing.remove();
    messageElement.querySelectorAll('.chat-inline-video').forEach(el => el.remove());

    // Videos und Bilder trennen
    const videoUrls = imageUrls.filter(url => isVideoUrl(url));
    const imageOnlyUrls = imageUrls.filter(url => !isVideoUrl(url));

    // Videos: full-width, inline abspielbar (vor der Bild-Gallery)
    videoUrls.forEach((url) => {
        const wrap = document.createElement('div');
        wrap.className = 'chat-inline-video';
        const video = document.createElement('video');
        video.src = url;
        video.autoplay = true;
        video.loop = true;
        video.muted = true;
        video.playsInline = true;
        video.controls = true;
        video.addEventListener('error', () => {
            console.log(`[Video] Video nicht gefunden: ${url}`);
            wrap.style.display = 'none';
        });
        video.addEventListener('click', (e) => {
            e.preventDefault();
            openLightbox(url);
        });
        wrap.appendChild(video);
        messageElement.appendChild(wrap);
    });

    // Bilder: Grid-Gallery (nur wenn es Bilder gibt)
    if (imageOnlyUrls.length === 0) return;

    const gallery = document.createElement('div');
    gallery.className = 'chat-image-gallery';

    imageOnlyUrls.forEach((url) => {
        const link = document.createElement('a');
        link.href = url;
        link.target = '_blank';
        link.rel = 'noopener noreferrer';
        link.addEventListener('click', (event) => {
            event.preventDefault();
            openLightbox(url);
        });

        const img = document.createElement('img');
        img.src = url;
        img.alt = 'Character image';
        img.addEventListener('error', () => {
            console.log(`[Image] Bild nicht gefunden: ${url}`);
            link.style.display = 'none';
        });
        link.appendChild(img);

        gallery.appendChild(link);
    });

    messageElement.appendChild(gallery);
}

function appendProfileImageButton(messageElement, fullText) {
    if (!fullText || !fullText.toLowerCase().includes('profilbild')) {
        return;
    }

    const existing = messageElement.querySelector('.profile-image-action');
    if (existing) {
        return;
    }

    const action = document.createElement('button');
    action.className = 'profile-image-action';
    action.textContent = 'Profilbild erstellen';
    action.addEventListener('click', async () => {
        // Hole Character-Aussehen vom Backend
        let appearance = '';
        try {
            const resp = await fetch(`/store/default/character_appearance`);
            if (resp.ok) { const d = await resp.json(); appearance = (d.resolved || d.value || '').trim(); }
        } catch (e) { /* ignore */ }
        const prompt = appearance
            ? `Erstelle ein Profilbild von Dir mit folgenden Merkmalen: ${appearance}`
            : 'Erstelle ein Profilbild von Dir';
        sendMessageWithText(prompt);
    });

    messageElement.appendChild(action);
}

function appendVisualizeGallery(messageElement, imageUrls) {
    if (!imageUrls || imageUrls.length === 0) return;
    const existing = messageElement.querySelector('.visualize-image-gallery');
    if (existing) existing.remove();
    const existingComment = messageElement.querySelector('.visualize-comment');
    if (existingComment) existingComment.remove();

    const gallery = document.createElement('div');
    gallery.className = 'visualize-image-gallery';

    imageUrls.forEach((url) => {
        const link = document.createElement('a');
        link.href = url;
        link.target = '_blank';
        link.rel = 'noopener noreferrer';
        link.addEventListener('click', (event) => {
            event.preventDefault();
            openLightbox(url);
        });
        const img = document.createElement('img');
        img.src = url;
        img.alt = 'Visualized scene';
        link.appendChild(img);
        gallery.appendChild(link);
    });

    // Regenerate button
    const regenBtn = document.createElement('button');
    regenBtn.className = 'visualize-regen-action';
    regenBtn.innerHTML = '&#x1F504; Neues Bild';
    regenBtn.title = 'Anderes Bild generieren';
    regenBtn.addEventListener('click', async () => {
        // Selektion VOR dem Dialog speichern (Klick/Dialog loescht window.getSelection)
        const preSelection = window.getSelection();
        const preSelectedText = preSelection && preSelection.toString().trim();
        const savedSelection = (preSelectedText && messageElement.contains(preSelection.anchorNode))
            ? preSelectedText : null;

        // Text fuer Character-Erkennung ermitteln
        let detectText;
        if (savedSelection) {
            detectText = savedSelection;
        } else {
            const textSpan = messageElement.querySelector('span[id]');
            detectText = textSpan ? textSpan.textContent.trim() : messageElement.textContent.trim();
        }

        // Characters erkennen und im Dialog anzeigen
        const charData = await _detectCharactersForText(currentCharacterName, detectText);
        const prevCharMeta = messageElement._visualizeMeta || null;

        const dialogResult = await showRegenerateDialog('Neues Bild generieren', currentCharacterName, null, prevCharMeta, charData);
        if (dialogResult === null) return;

        regenBtn.disabled = true;
        regenBtn.innerHTML = '&#9203; Generiere...';
        setChatBusy(true);

        const body = { agent_name: currentCharacterName, text: detectText };
        if (dialogResult.workflow) body.workflow = dialogResult.workflow;
        if (dialogResult.backend) body.backend = dialogResult.backend;
        if (dialogResult.loras) body.loras = dialogResult.loras;
        if (dialogResult.model_override) body.model_override = dialogResult.model_override;
        if (dialogResult.character_names) body.character_names = dialogResult.character_names;
        if (dialogResult.room_id) body.room_id = dialogResult.room_id;
        // Items-Auswahl aus dem Regenerate-Dialog — dort konnten die vom Panel
        // vorausgewaehlten Items nach-korrigiert werden.
        const _itemsForImg = (dialogResult.item_ids && dialogResult.item_ids.length)
            ? dialogResult.item_ids
            : _getSelectedRoomItemIds();
        if (_itemsForImg.length) body.item_ids = _itemsForImg;

        try {
            const resp = await fetch('/chat/visualize', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify(body)
            });
            const result = await resp.json();
            if (!resp.ok) {
                showStatusToast(result.detail || result.error || t('Visualization failed'), 'error');
            } else if (result.error) {
                showStatusToast(result.error, 'error');
            } else {
                // Meta-Daten am Element speichern fuer Regenerierung
                messageElement._visualizeMeta = {
                    workflow: dialogResult.workflow,
                    backend: dialogResult.backend,
                    model_override: dialogResult.model_override,
                    loras: dialogResult.loras,
                    character_names: result.character_names || dialogResult.character_names,
                    room_id: dialogResult.room_id,
                    item_ids: _itemsForImg,
                };
                if (result.image_urls && result.image_urls.length > 0) {
                    appendVisualizeGallery(messageElement, result.image_urls);
                }
                if (result.comment) {
                    const commentDiv = document.createElement('div');
                    commentDiv.className = 'visualize-comment';
                    commentDiv.textContent = result.comment;
                    messageElement.appendChild(commentDiv);
                }
            }
        } catch (e) {
            console.error('[Visualize] Regen error:', e);
            showStatusToast(t('Visualization failed'), 'error');
        } finally {
            regenBtn.innerHTML = '&#x1F504; Neues Bild';
            regenBtn.disabled = false;
            setChatBusy(false);
        }
    });
    gallery.appendChild(regenBtn);

    messageElement.appendChild(gallery);
}

// Floating speak button for selected text anywhere in chat
(function initSelectionSpeakButton() {
    const floatBtn = document.createElement('button');
    floatBtn.className = 'speak-selection-float';
    floatBtn.innerHTML = '&#128266; Vorlesen';
    floatBtn.style.display = 'none';
    document.body.appendChild(floatBtn);

    document.addEventListener('selectionchange', () => {
        const sel = window.getSelection();
        const text = sel ? sel.toString().trim() : '';
        const chatBox = document.getElementById('chat-messages');
        const storyBox = document.getElementById('story-scene-content');
        const inChat = chatBox && chatBox.contains(sel.anchorNode);
        const inStory = storyBox && storyBox.contains(sel.anchorNode);
        if (text.length > 0 && (inChat || inStory)) {
            const range = sel.getRangeAt(0);
            const rect = range.getBoundingClientRect();
            floatBtn.style.display = 'flex';
            floatBtn.style.top = (rect.top + window.scrollY - 36) + 'px';
            floatBtn.style.left = (rect.left + rect.width / 2) + 'px';
        } else {
            floatBtn.style.display = 'none';
        }
    });

    floatBtn.addEventListener('mousedown', async (e) => {
        e.preventDefault();
        const sel = window.getSelection();
        const text = sel ? sel.toString().trim() : '';
        if (!text) return;
        // Find parent container (chat message or story scene)
        let msgEl = sel.anchorNode;
        while (msgEl && !msgEl.classList?.contains('message') && msgEl.id !== 'story-scene-content') msgEl = msgEl.parentElement;
        floatBtn.innerHTML = '&#9203;';
        floatBtn.disabled = true;
        try {
            const resp = await fetch('/tts/speak', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    text: text,
                    
                    character_name: currentCharacterName,
                })
            });
            const result = await resp.json();
            if (result.audio_url && msgEl) {
                appendAudioPlayer(msgEl, result.audio_url);
            } else if (result.error) {
                showStatusToast(result.error, 'error');
            }
        } catch (err) {
            console.error('[TTS] Selection speak error:', err);
            showStatusToast(t('Audio generation failed'), 'error');
        }
        floatBtn.innerHTML = '&#128266; Vorlesen';
        floatBtn.disabled = false;
        floatBtn.style.display = 'none';
    });
})();

function appendAudioPlayer(container, audioUrl) {
    let player = container.querySelector('.tts-audio-player');
    if (player) player.remove();
    const audio = document.createElement('audio');
    audio.className = 'tts-audio-player';
    audio.controls = true;
    audio.autoplay = true;
    const source = document.createElement('source');
    source.src = audioUrl;
    source.type = audioUrl.endsWith('.mp3') ? 'audio/mpeg' : 'audio/wav';
    audio.appendChild(source);
    container.appendChild(audio);
}

// --- Chunked TTS Audio Queue ---
function createTtsChunkPlayer(container) {
    const queue = [];
    let playing = false;
    let preloadedAudio = null;
    let preloadedData = null;
    let receivedFinal = false;
    const MIN_BUFFER = 2; // Mindestens N Chunks buffern bevor Playback startet

    function _createAudio(url) {
        const audio = document.createElement('audio');
        audio.preload = 'auto';
        const source = document.createElement('source');
        source.src = url;
        source.type = url.endsWith('.mp3') ? 'audio/mpeg' : 'audio/wav';
        audio.appendChild(source);
        return audio;
    }

    function _preloadNext() {
        if (preloadedAudio || queue.length === 0) return;
        queue.sort((a, b) => a.index - b.index);
        const next = queue[0];
        if (!next || !next.url) return;
        preloadedData = next;
        preloadedAudio = _createAudio(next.url);
        preloadedAudio.load();
    }

    function _canStart() {
        // Starte Playback wenn genug Chunks gebuffert oder Stream fertig
        if (receivedFinal) return queue.length > 0;
        return queue.length >= MIN_BUFFER;
    }

    function playNext() {
        if (playing || queue.length === 0) return;
        // Initiales Buffering: warte auf MIN_BUFFER Chunks
        if (!container.querySelector('.tts-audio-player') && !_canStart()) return;

        queue.sort((a, b) => a.index - b.index);
        const next = queue.shift();
        if (!next.url) {
            playNext();
            return;
        }
        playing = true;

        const sp = container.querySelector('.tts-chunk-loading');
        if (sp) sp.remove();
        const old = container.querySelector('.tts-audio-player');
        if (old) old.remove();

        let audio;
        if (preloadedAudio && preloadedData === next) {
            audio = preloadedAudio;
            preloadedAudio = null;
            preloadedData = null;
        } else {
            preloadedAudio = null;
            preloadedData = null;
            audio = _createAudio(next.url);
        }

        audio.className = 'tts-audio-player';
        audio.controls = true;
        audio.autoplay = true;

        audio.onended = () => {
            playing = false;
            playNext();
        };
        audio.onerror = () => {
            console.error('[TTS Chunk] Playback error:', next.url);
            playing = false;
            playNext();
        };

        container.appendChild(audio);
        audio.play().catch(err => {
            console.warn('[TTS Chunk] Autoplay blocked, waiting for user interaction:', err);
        });
        _preloadNext();
    }

    return {
        addChunk(data) {
            if (data.final) receivedFinal = true;
            queue.push(data);
            if (!playing && !container.querySelector('.tts-audio-player')) {
                if (!container.querySelector('.tts-chunk-loading')) {
                    const sp = document.createElement('div');
                    sp.className = 'tts-chunk-loading tts-loading';
                    sp.innerHTML = '<span class="story-spinner"></span> Audio wird erzeugt...';
                    container.appendChild(sp);
                }
            }
            if (playing) _preloadNext();
            else playNext();
        }
    };
}

function appendSpeakButton(messageElement) {
    const existing = messageElement.querySelector('.speak-action');
    if (existing) return;
    const btn = document.createElement('button');
    btn.className = 'speak-action';
    btn.innerHTML = '&#128266;';
    btn.title = 'Vorlesen (Text markieren = nur Auswahl)';
    btn.addEventListener('click', async () => {
        btn.disabled = true;
        btn.innerHTML = '&#9203;';
        // Use selected text if selection is within this message
        const selection = window.getSelection();
        let text = '';
        if (selection && selection.toString().trim() && messageElement.contains(selection.anchorNode)) {
            text = selection.toString().trim();
        } else {
            const textSpan = messageElement.querySelector('span[id]');
            text = textSpan ? textSpan.innerText.trim() : messageElement.innerText.trim();
        }
        try {
            const resp = await fetch('/tts/speak', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    text: text,
                    
                    character_name: messageElement._groupCharName || currentCharacterName,
                })
            });
            const result = await resp.json();
            if (result.audio_url) {
                appendAudioPlayer(messageElement, result.audio_url);
            } else if (result.error) {
                showStatusToast(result.error, 'error');
            }
        } catch (e) {
            console.error('[TTS] Error:', e);
            showStatusToast(t('Audio generation failed'), 'error');
        }
        btn.innerHTML = '&#128266;';
        btn.disabled = false;
    });
    messageElement.appendChild(btn);
}

function appendVisualizeButton(messageElement) {
    const existing = messageElement.querySelector('.visualize-action');
    if (existing) return;

    const btn = document.createElement('button');
    btn.className = 'visualize-action';
    btn.textContent = '\uD83C\uDFA8';
    btn.title = 'Szene visualisieren';
    btn.addEventListener('click', async () => {
        // Selektion VOR dem Dialog speichern (Klick/Dialog loescht window.getSelection)
        const preSelection = window.getSelection();
        const preSelectedText = preSelection && preSelection.toString().trim();
        const savedSelection = (preSelectedText && messageElement.contains(preSelection.anchorNode))
            ? preSelectedText : null;

        // Text fuer Character-Erkennung ermitteln
        let detectText;
        if (savedSelection) {
            detectText = savedSelection;
        } else {
            const textSpan = messageElement.querySelector('span[id]');
            detectText = textSpan ? textSpan.textContent.trim() : messageElement.textContent.trim();
        }

        // Characters erkennen und im Dialog anzeigen
        const _vizCharName = messageElement._groupCharName || currentCharacterName;
        const charData = await _detectCharactersForText(_vizCharName, detectText);
        const prevCharMeta = messageElement._visualizeMeta || null;

        const dialogResult = await showRegenerateDialog('Szene visualisieren', _vizCharName, null, prevCharMeta, charData);
        if (dialogResult === null) return;

        btn.disabled = true;
        btn.textContent = '\u23F3';
        setChatBusy(true);
        showStatusToast(t('Visualizing scene…'), 'info');

        const body = { agent_name: _vizCharName, text: detectText };
        if (dialogResult.workflow) body.workflow = dialogResult.workflow;
        if (dialogResult.backend) body.backend = dialogResult.backend;
        if (dialogResult.loras) body.loras = dialogResult.loras;
        if (dialogResult.model_override) body.model_override = dialogResult.model_override;
        if (dialogResult.character_names) body.character_names = dialogResult.character_names;
        if (dialogResult.room_id) body.room_id = dialogResult.room_id;
        // Items-Auswahl vom Regenerate-Dialog (User hat ggf. nach-korrigiert)
        const _itemsForImg2 = (dialogResult.item_ids && dialogResult.item_ids.length)
            ? dialogResult.item_ids
            : (prevCharMeta && Array.isArray(prevCharMeta.item_ids) && prevCharMeta.item_ids.length
                ? prevCharMeta.item_ids
                : _getSelectedRoomItemIds());
        if (_itemsForImg2.length) body.item_ids = _itemsForImg2;

        try {
            const resp = await fetch('/chat/visualize', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify(body)
            });
            const result = await resp.json();

            if (!resp.ok) {
                showStatusToast(result.detail || result.error || t('Visualization failed'), 'error');
            } else if (result.error) {
                showStatusToast(result.error, 'error');
            } else {
                // Meta-Daten am Element speichern fuer Regenerierung
                messageElement._visualizeMeta = {
                    workflow: dialogResult.workflow,
                    backend: dialogResult.backend,
                    model_override: dialogResult.model_override,
                    loras: dialogResult.loras,
                    item_ids: _itemsForImg2,
                    character_names: result.character_names || dialogResult.character_names,
                    room_id: dialogResult.room_id,
                };
                if (result.image_urls && result.image_urls.length > 0) {
                    appendVisualizeGallery(messageElement, result.image_urls);
                }
                if (result.comment) {
                    const commentDiv = document.createElement('div');
                    commentDiv.className = 'visualize-comment';
                    commentDiv.textContent = result.comment;
                    messageElement.appendChild(commentDiv);
                }
            }
        } catch (e) {
            console.error('[Visualize] Error:', e);
            showStatusToast(t('Visualization failed'), 'error');
        } finally {
            btn.textContent = '\uD83C\uDFA8';
            btn.disabled = false;
            setChatBusy(false);
        }
    });
    messageElement.appendChild(btn);
}

function showCaptionModeDialog() {
    return new Promise((resolve) => {
        const overlay = document.createElement('div');
        overlay.className = 'caption-mode-overlay';
        const dialog = document.createElement('div');
        dialog.className = 'caption-mode-dialog';
        dialog.innerHTML = `
            <div class="caption-mode-title">Caption-Quelle</div>
            <button class="caption-mode-btn" data-mode="vision">
                <span class="caption-mode-icon">🔍</span>
                <span class="caption-mode-label">Bildanalyse</span>
                <span class="caption-mode-desc">Vision-LLM analysiert das generierte Bild</span>
            </button>
            <button class="caption-mode-btn" data-mode="text">
                <span class="caption-mode-icon">💬</span>
                <span class="caption-mode-label">Chat-Text</span>
                <span class="caption-mode-desc">Caption aus der Bot-Antwort ableiten</span>
            </button>
        `;
        overlay.appendChild(dialog);
        const cleanup = (mode) => { overlay.remove(); resolve(mode); };
        dialog.querySelectorAll('.caption-mode-btn').forEach(b =>
            b.addEventListener('click', () => cleanup(b.dataset.mode))
        );
        overlay.addEventListener('click', (e) => { if (e.target === overlay) cleanup(null); });
        document.body.appendChild(overlay);
    });
}

function appendInstagramButton(messageElement) {
    const existing = messageElement.querySelector('.instagram-post-action');
    if (existing) return;

    const btn = document.createElement('button');
    btn.className = 'instagram-post-action';
    btn.textContent = '\uD83D\uDCF7';
    btn.title = 'Auf Instagram posten (Text markieren = nur Auswahl verwenden)';
    btn.addEventListener('click', async () => {
        const sel = window.getSelection();
        let text = '';
        if (sel && sel.toString().trim().length > 0 && messageElement.contains(sel.anchorNode)) {
            text = sel.toString().trim();
        } else {
            const textSpan = messageElement.querySelector('span[id]');
            text = textSpan ? textSpan.textContent.trim() : '';
        }
        // Gedanken-Nachricht Prefix entfernen
        text = text.replace(/^\[Gedanken-Nachricht[^\]]*\]\s*/, '').trim();
        // Mood- und Location-Zeile am Ende entfernen
        text = text.replace(/\n?\*{0,2}I feel\s+[^*\n]+\*{0,2}\s*$/i, '').trim();
        text = text.replace(/\n?\*{0,2}I am at\s+[^*\n]+\*{0,2}\s*$/i, '').trim();

        if (!text) {
            showStatusToast(t('No text available'), 'error');
            return;
        }

        // Caption-Modus waehlen lassen
        const captionMode = await showCaptionModeDialog();
        if (!captionMode) return;

        btn.disabled = true;
        btn.textContent = '\u23F3';
        setChatBusy(true);
        showStatusToast(t('Creating Instagram post…'), 'info');

        try {
            const resp = await fetch('/chat/instagram-post', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({
                    
                    agent_name: currentCharacterName,
                    text: text,
                    caption_mode: captionMode
                })
            });
            const result = await resp.json();

            if (result.post_id) {
                showStatusToast(t('Instagram post created!'), 'success');
                if (instagramPanelOpen) {
                    loadInstagramFeed();
                }
            }
            if (result.error) {
                showStatusToast(result.error, 'error');
            }
        } catch (e) {
            console.error('[Instagram] Error:', e);
            showStatusToast(t('Instagram post failed'), 'error');
        } finally {
            btn.textContent = '\uD83D\uDCF7';
            btn.disabled = false;
            setChatBusy(false);
        }
    });
    messageElement.appendChild(btn);
}

function sendMessageWithText(text) {
    if (!text || !text.trim()) {
        return;
    }
    userInput.value = text;
    sendMessage();
}

function ensureLightbox() {
    let overlay = document.getElementById('image-lightbox');
    if (overlay) {
        return overlay;
    }

    overlay = document.createElement('div');
    overlay.id = 'image-lightbox';
    overlay.className = 'image-lightbox';
    overlay.innerHTML = `
        <div class="lightbox-content">
            <img id="lightbox-image" alt="Preview">
            <video id="lightbox-video" autoplay loop muted playsinline style="display: none;"></video>
            <button class="lightbox-close" aria-label="Close">&times;</button>
        </div>
    `;
    document.body.appendChild(overlay);

    overlay.addEventListener('click', (event) => {
        if (event.target.id === 'image-lightbox') {
            closeLightbox();
        }
    });

    const closeButton = overlay.querySelector('.lightbox-close');
    closeButton.addEventListener('click', closeLightbox);

    document.addEventListener('keydown', (event) => {
        if (event.key === 'Escape') {
            closeLightbox();
        }
    });

    return overlay;
}

function openLightbox(mediaUrl) {
    const overlay = ensureLightbox();
    const img = overlay.querySelector('#lightbox-image');
    const vid = overlay.querySelector('#lightbox-video');
    if (isVideoUrl(mediaUrl)) {
        img.style.display = 'none';
        vid.src = mediaUrl;
        vid.style.display = 'block';
    } else {
        vid.style.display = 'none';
        vid.src = '';
        img.src = mediaUrl;
        img.style.display = 'block';
    }
    overlay.classList.add('lightbox-visible');
}

function closeLightbox() {
    const overlay = document.getElementById('image-lightbox');
    if (overlay) {
        overlay.classList.remove('lightbox-visible');
        const vid = overlay.querySelector('#lightbox-video');
        if (vid) { vid.src = ''; vid.style.display = 'none'; }
    }
}

function showStatusToast(message, variant = 'success', durationMs = 10000) {
    let stack = document.getElementById('status-toast-stack');
    if (!stack) {
        stack = document.createElement('div');
        stack.id = 'status-toast-stack';
        document.body.appendChild(stack);
    }

    const toast = document.createElement('div');
    toast.className = 'status-toast';
    if (variant === 'error') toast.classList.add('status-error');
    else if (variant === 'info') toast.classList.add('status-info');
    else toast.classList.add('status-success');
    toast.textContent = message;
    stack.appendChild(toast);

    // animate in on next frame
    requestAnimationFrame(() => toast.classList.add('status-visible'));

    const dismiss = () => {
        if (toast._dismissed) return;
        toast._dismissed = true;
        clearTimeout(toast._hideTimer);
        toast.classList.remove('status-visible');
        setTimeout(() => toast.remove(), 250);
    };
    toast.addEventListener('click', dismiss);
    toast._hideTimer = setTimeout(dismiss, Math.max(1000, durationMs|0));
}

/**
 * Generischer Picker-Dialog fuer Auswahl aus einer Liste (Activities, Items, ...).
 *
 * Einheitliches UI statt der bisher unterschiedlichen Pattern (Library-Spalte,
 * Dropdown-Form, Autocomplete-Liste). Verwendet bestehende .modal / .modal-*
 * Klassen, die per Theme-CSS-Variablen Dark/Light automatisch abdecken.
 *
 * @param {Object} opts
 * @param {string} opts.title - Dialog-Ueberschrift
 * @param {Array|Function} opts.items - Array oder async Funktion die ein Array liefert
 * @param {Function} opts.renderItem - (item) => {label, subtitle?, meta?, disabled?, disabledReason?}
 * @param {Array<string>} [opts.searchFields] - Felder fuer Substring-Suche (default: ['name'])
 * @param {string} [opts.searchPlaceholder] - Placeholder fuer Suchfeld
 * @param {string} [opts.emptyText] - Text wenn Liste leer
 * @param {Array} [opts.extraFields] - Optionale Felder die NACH Auswahl abgefragt werden:
 *     [{id, label, type: 'text'|'number'|'checkbox'|'textarea', default?, min?, max?, placeholder?}]
 * @param {string} [opts.submitLabel] - Label des Confirm-Buttons in Extra-Feldern-Step (default: 'Hinzufuegen')
 * @returns {Promise<{id: string, item: Object, extras: Object}|null>}
 */
async function openPicker(opts) {
    const {
        title = 'Auswaehlen',
        items,
        renderItem,
        searchFields = ['name'],
        searchPlaceholder = 'Suchen...',
        emptyText = 'Nichts gefunden',
        extraFields = null,
        submitLabel = 'Hinzufuegen',
    } = opts || {};

    // Items laden (Array oder async Funktion)
    let list;
    try {
        list = (typeof items === 'function') ? await items() : (items || []);
    } catch (e) {
        console.error('openPicker items() Fehler:', e);
        list = [];
    }
    if (!Array.isArray(list)) list = [];

    return new Promise((resolve) => {
        // Overlay + Content
        const overlay = document.createElement('div');
        overlay.className = 'modal';
        overlay.style.display = 'flex';

        const content = document.createElement('div');
        content.className = 'modal-content';
        content.style.width = 'min(520px, 90vw)';
        content.style.maxHeight = 'min(80vh, 600px)';
        content.style.display = 'flex';
        content.style.flexDirection = 'column';

        // Header
        const header = document.createElement('div');
        header.className = 'modal-header';
        header.innerHTML = `<h2>${escapeHtml(title)}</h2>
            <button type="button" class="modal-close" aria-label="Schliessen">×</button>`;

        // Body (search + list, or extra fields step)
        const body = document.createElement('div');
        body.className = 'modal-body';
        body.style.flex = '1';
        body.style.overflow = 'hidden';
        body.style.display = 'flex';
        body.style.flexDirection = 'column';
        body.style.padding = '12px 16px';

        content.appendChild(header);
        content.appendChild(body);
        overlay.appendChild(content);
        document.body.appendChild(overlay);

        let chosenItem = null;  // In Step 2 gesetzt, wenn extraFields aktiv

        function cleanup(result) {
            document.removeEventListener('keydown', onKey);
            overlay.remove();
            resolve(result);
        }

        function onKey(e) {
            if (e.key === 'Escape') { e.preventDefault(); cleanup(null); }
        }
        document.addEventListener('keydown', onKey);

        overlay.addEventListener('click', (e) => {
            if (e.target === overlay) cleanup(null);
        });
        header.querySelector('.modal-close').onclick = () => cleanup(null);

        // --- Step 1: Suche + Liste ---
        function renderStep1() {
            body.innerHTML = '';
            const searchInput = document.createElement('input');
            searchInput.type = 'text';
            searchInput.className = 'agent-status-input';
            searchInput.placeholder = searchPlaceholder;
            searchInput.style.marginBottom = '8px';
            searchInput.style.flexShrink = '0';
            body.appendChild(searchInput);

            const listWrap = document.createElement('div');
            listWrap.style.flex = '1';
            listWrap.style.overflowY = 'auto';
            listWrap.style.border = '1px solid var(--border)';
            listWrap.style.borderRadius = '6px';
            listWrap.style.background = 'var(--bg-alt)';
            body.appendChild(listWrap);

            function matches(item, q) {
                if (!q) return true;
                const ql = q.toLowerCase();
                for (const f of searchFields) {
                    const v = (item[f] ?? '').toString().toLowerCase();
                    if (v.includes(ql)) return true;
                }
                return false;
            }

            function renderList(q) {
                const filtered = list.filter(it => matches(it, q));
                if (filtered.length === 0) {
                    listWrap.innerHTML = `<div style="padding:12px;font-size:12px;color:var(--text-muted);">${escapeHtml(emptyText)}</div>`;
                    return;
                }
                listWrap.innerHTML = '';
                for (const it of filtered) {
                    const rendered = renderItem ? renderItem(it) : { label: it.name || it.id };
                    const row = document.createElement('div');
                    row.style.padding = '8px 12px';
                    row.style.borderBottom = '1px solid var(--border)';
                    row.style.cursor = rendered.disabled ? 'not-allowed' : 'pointer';
                    row.style.opacity = rendered.disabled ? '0.4' : '1';
                    row.title = rendered.disabled ? (rendered.disabledReason || t('Not available')) : '';

                    const lbl = document.createElement('div');
                    lbl.style.fontSize = '13px';
                    lbl.style.color = 'var(--text)';
                    lbl.style.fontWeight = '500';
                    lbl.textContent = rendered.label || '';
                    row.appendChild(lbl);

                    if (rendered.subtitle) {
                        const sub = document.createElement('div');
                        sub.style.fontSize = '11px';
                        sub.style.color = 'var(--text-muted)';
                        sub.style.marginTop = '2px';
                        sub.textContent = rendered.subtitle;
                        row.appendChild(sub);
                    }
                    if (rendered.meta) {
                        const meta = document.createElement('div');
                        meta.style.fontSize = '10px';
                        meta.style.color = 'var(--text-muted)';
                        meta.style.marginTop = '2px';
                        meta.textContent = rendered.meta;
                        row.appendChild(meta);
                    }
                    if (!rendered.disabled) {
                        row.addEventListener('mouseenter', () => { row.style.background = 'var(--bg)'; });
                        row.addEventListener('mouseleave', () => { row.style.background = ''; });
                        row.addEventListener('click', () => {
                            if (extraFields && extraFields.length) {
                                chosenItem = it;
                                renderStep2();
                            } else {
                                const id = it.id ?? it.name;
                                cleanup({ id, item: it, extras: {} });
                            }
                        });
                    }
                    listWrap.appendChild(row);
                }
            }

            searchInput.addEventListener('input', () => renderList(searchInput.value));
            renderList('');
            setTimeout(() => searchInput.focus(), 10);
        }

        // --- Step 2: Extra-Felder nach Auswahl ---
        function renderStep2() {
            body.innerHTML = '';
            const info = document.createElement('div');
            info.style.fontSize = '13px';
            info.style.color = 'var(--text)';
            info.style.marginBottom = '10px';
            info.style.padding = '8px 10px';
            info.style.background = 'var(--bg-alt)';
            info.style.border = '1px solid var(--border)';
            info.style.borderRadius = '6px';
            const rendered = renderItem ? renderItem(chosenItem) : { label: chosenItem.name || chosenItem.id };
            info.innerHTML = `<strong>${escapeHtml(rendered.label || '')}</strong>`
                + (rendered.subtitle ? `<div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${escapeHtml(rendered.subtitle)}</div>` : '');
            body.appendChild(info);

            const fieldRefs = {};
            for (const f of extraFields) {
                const wrap = document.createElement('div');
                wrap.style.marginBottom = '8px';
                const lbl = document.createElement('label');
                lbl.style.fontSize = '12px';
                lbl.style.color = 'var(--text-muted)';
                lbl.style.display = 'block';
                lbl.style.marginBottom = '3px';
                lbl.textContent = f.label || f.id;

                let input;
                if (f.type === 'checkbox') {
                    input = document.createElement('input');
                    input.type = 'checkbox';
                    input.checked = !!f.default;
                    const row = document.createElement('label');
                    row.style.display = 'flex';
                    row.style.alignItems = 'center';
                    row.style.gap = '6px';
                    row.style.fontSize = '13px';
                    row.appendChild(input);
                    const span = document.createElement('span');
                    span.textContent = f.label || f.id;
                    row.appendChild(span);
                    wrap.appendChild(row);
                } else if (f.type === 'textarea') {
                    input = document.createElement('textarea');
                    input.className = 'agent-status-input';
                    input.rows = 3;
                    if (f.placeholder) input.placeholder = f.placeholder;
                    if (f.default !== undefined) input.value = f.default;
                    wrap.appendChild(lbl);
                    wrap.appendChild(input);
                } else {
                    input = document.createElement('input');
                    input.type = f.type === 'number' ? 'number' : 'text';
                    input.className = 'agent-status-input';
                    if (f.placeholder) input.placeholder = f.placeholder;
                    if (f.default !== undefined) input.value = f.default;
                    if (f.min !== undefined) input.min = f.min;
                    if (f.max !== undefined) input.max = f.max;
                    wrap.appendChild(lbl);
                    wrap.appendChild(input);
                }
                fieldRefs[f.id] = { input, type: f.type };
                body.appendChild(wrap);
            }

            // Action row
            const actions = document.createElement('div');
            actions.style.display = 'flex';
            actions.style.gap = '8px';
            actions.style.justifyContent = 'flex-end';
            actions.style.marginTop = '10px';
            actions.style.paddingTop = '10px';
            actions.style.borderTop = '1px solid var(--border)';

            const backBtn = document.createElement('button');
            backBtn.type = 'button';
            backBtn.textContent = '← Zurueck';
            backBtn.className = 'save-btn';
            backBtn.style.background = 'var(--bg-alt)';
            backBtn.style.color = 'var(--text)';
            backBtn.onclick = () => { chosenItem = null; renderStep1(); };

            const confirmBtn = document.createElement('button');
            confirmBtn.type = 'button';
            confirmBtn.className = 'save-btn';
            confirmBtn.textContent = submitLabel;
            confirmBtn.onclick = () => {
                const extras = {};
                for (const [id, ref] of Object.entries(fieldRefs)) {
                    if (ref.type === 'checkbox') extras[id] = !!ref.input.checked;
                    else if (ref.type === 'number') extras[id] = parseFloat(ref.input.value) || 0;
                    else extras[id] = (ref.input.value || '').trim();
                }
                cleanup({ id: chosenItem.id ?? chosenItem.name, item: chosenItem, extras });
            };

            actions.appendChild(backBtn);
            actions.appendChild(confirmBtn);
            body.appendChild(actions);
        }

        renderStep1();
    });
}

/**
 * Polls the task tracker for a regeneration task until completed or failed.
 * Uses the queue/status endpoint which includes active_tasks and recent_tasks.
 */
function _pollRegenTask(trackId, onSuccess, onError, maxPollMs = 600000) {
    const start = Date.now();
    const interval = setInterval(async () => {
        if (Date.now() - start > maxPollMs) {
            clearInterval(interval);
            onError('Timeout');
            return;
        }
        try {
            const resp = await fetch('/queue/status');
            if (!resp.ok) return;
            const data = await resp.json();
            // Check active tasks
            const active = (data.active_tasks || []).find(t => t.task_id === trackId);
            if (active) return; // still running
            // Check recent tasks (completed/failed)
            const recent = (data.recent_tasks || []).find(t => t.task_id === trackId);
            if (recent) {
                clearInterval(interval);
                if (recent.error) onError(recent.error);
                else onSuccess();
                return;
            }
            // Not found in active or recent — might have completed between polls
            // Wait a few more cycles before giving up
        } catch (e) { /* ignore poll errors */ }
    }, 3000);
}

