// Liest einen SSE-Stream von einer URL und aktualisiert ein Bot-Message-Element.
// Gibt { fullResponse, toolImageUrls, tokenInfo, timestamp } zurück.
async function _readChatStream(streamUrl, botMessageId, botMessage, abortSignal, onActivity) {
    const streamResponse = await fetch(streamUrl, { signal: abortSignal });
    if (!streamResponse.ok) {
        throw new Error(`Stream-Fehler: ${streamResponse.status}`);
    }

    const reader = streamResponse.body.getReader();
    const decoder = new TextDecoder();
    const botResponseElement = document.getElementById(botMessageId);
    let fullResponse = '';
    let toolImageUrls = [];
    let tokenInfo = null;
    let timestamp = null;
    let imageStatusShown = false;
    let ttsChunkPlayer = null;

    while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        if (onActivity) onActivity(); // Timeout bei jedem Datenempfang zuruecksetzen
        const lines = chunk.split('\n').filter(line => line.trim() !== '');

        for (const line of lines) {
            if (!line.startsWith('data: ')) continue;
            try {
                const data = JSON.parse(line.substring(6));
                if (data.error) {
                    if (botResponseElement) botResponseElement.textContent = `Fehler: ${data.error}`;
                    return { fullResponse, toolImageUrls, tokenInfo, timestamp, hadError: true };
                }
                if (data.wake_up) {
                    showStatusToast(`${currentCharacterName} ` + t('was woken up'), 'info');
                    _updateHeaderActivity('', '', '');
                }
                if (data.model_info) {
                    console.log('[Chat] Model info:', data.model_info);
                    if (data.model_info.tool_model) {
                        console.log(`[Chat] Separate Tool-LLM: ${data.model_info.tool_model}`);
                    }
                }
                if (data.spell_routing_missing) {
                    // Sticky Toast: ohne LLM-Routing fuer spell_detect kann
                    // der Cast nicht laufen. User-Aktion noetig.
                    showStatusToast(
                        '⚠️ Spell-Detection nicht aktiv: kein LLM dem Task ' +
                        '"spell_detect" zugewiesen. Admin → LLM Routing → ' +
                        'einen Tool-LLM zum Task hinzufuegen.',
                        'error', 8000);
                }
                if (data.spell_event) {
                    const ev = data.spell_event;
                    const okIcon = ev.success ? '🪄' : '✨';
                    const verdict = ev.success ? t('succeeded') : t('failed');
                    const roll = (ev.chance && ev.roll)
                        ? ` <span class="spell-roll">(${ev.roll}/${ev.chance})</span>` : '';
                    const delivered = (ev.success && ev.delivered_item_name)
                        ? `<div class="spell-delivered">→ ${escapeHtml(ev.delivered_item_name)} an ${escapeHtml(ev.target)} uebergeben</div>` : '';
                    const note = document.createElement('div');
                    note.className = 'spell-event-note ' + (ev.success ? 'spell-success' : 'spell-fail');
                    note.innerHTML = `
                        <div class="spell-headline">${okIcon} Zauber <strong>${escapeHtml(ev.spell_name || ev.spell_id)}</strong> auf ${escapeHtml(ev.target)} — ${verdict}${roll}</div>
                        ${delivered}
                    `;
                    if (chatMessages) {
                        chatMessages.appendChild(note);
                        chatMessages.scrollTop = chatMessages.scrollHeight;
                    }
                    // Bei chat_substitute: das letzte User-Bubble (= die rohe
                    // Incantation, die der User gerade getippt hat) auf die
                    // narrative Beobachtung umschreiben — so passt das
                    // Bubble-Layout zur gespeicherten Chat-History und der
                    // User sieht nicht "ich habe X getippt aber NPC reagiert
                    // auf Y". Die spell_event-Note dient als Quittung.
                    if (ev.chat_substitute && chatMessages) {
                        const userBubbles = chatMessages.querySelectorAll('.user-message .message-content, .message.user-message');
                        const last = userBubbles.length ? userBubbles[userBubbles.length - 1] : null;
                        if (last) {
                            try { last.innerHTML = marked.parse(ev.chat_substitute); }
                            catch (_) { last.textContent = ev.chat_substitute; }
                        }
                    }
                    console.log('[Chat] Spell event:', ev);
                }
                if (data.status === 'tool_start') {
                    const statusEl = document.createElement('div');
                    statusEl.className = 'tool-status-indicator';
                    statusEl.id = 'tool-status-active';
                    statusEl.innerHTML = `<span class="tool-status-spinner"></span> ${getToolStatusLabel(data.tool)}...`;
                    if (botResponseElement) botResponseElement.appendChild(statusEl);
                    chatMessages.scrollTop = chatMessages.scrollHeight;
                }
                if (data.status === 'tool_end') {
                    const s = document.getElementById('tool-status-active');
                    if (s) s.remove();
                }
                if (data.tool_result) {
                    const imgMatches = data.tool_result.match(/!\[[^\]]*\]\(\/characters\/[^)]+\)/g);
                    if (imgMatches) toolImageUrls.push(...imgMatches);
                }
                if (data.retry_hint) {
                    // rp_first: Antwort wird verworfen und neu generiert
                    fullResponse = '';
                    if (botResponseElement) {
                        botResponseElement.innerHTML = `<div class="tool-status-indicator"><span class="tool-status-spinner"></span> ${escapeHtml(data.retry_hint)}</div>`;
                    }
                }
                if (data.content) {
                    const s = document.getElementById('tool-status-active');
                    if (s) s.remove();
                    fullResponse += data.content;
                    const streamText = stripExternalImages(fullResponse).replace(
                        /!\[([^\]]*)\]\(\/characters\/[^)]+\)/g,
                        '\n\n**🖼 $1**\n\n'
                    );
                    if (botResponseElement) {
                        botResponseElement.innerHTML = marked.parse(streamText);
                        chatMessages.scrollTop = chatMessages.scrollHeight;
                    }
                    if (!imageStatusShown && (data.content.includes('Bilddatei:') || data.content.includes('Bild generiert und gespeichert'))) {
                        showStatusToast(t('Image saved and shown in chat'), 'success');
                        imageStatusShown = true;
                    }
                }
                if (data.mood) {
                    const moodEl = document.getElementById('header-mood-display');
                    if (moodEl) { moodEl.textContent = data.mood; moodEl.title = `Stimmung: ${data.mood}`; }
                    // Refresh expression image on mood change
                    if (currentCharacterName) updateCharacterScene(currentCharacterName);
                }
                if (data.location) {
                    _currentCharacterRoom = data.room || '';
                    // Header komplett neu laden (inkl. activity_detail)
                    if (currentCharacterName) _loadCharacterHeaderState(currentCharacterName);
                    // Background NICHT auf Partner-Location umschalten — der
                    // Hintergrund bleibt am Avatar-Standort. Sonst springt das
                    // Bild beim Phone-Chat zur Location des Gespraechspartners.
                    loadCharacterSidebar();
                    // Partner hat Location gewechselt → Medium neu auflösen
                    // (vorher in_person, jetzt vielleicht messaging falls weg).
                    if (currentCharacterName) {
                        _recomputeChatMedium().then(() => updateCharacterScene(currentCharacterName));
                    }
                    showStatusToast(`📍 ${currentCharacterName} ` + t('is now:') + ` ${locationIdToName(data.location)}`, 'info');
                }
                if (data.activity && !data.location) {
                    // Header komplett neu laden (inkl. activity_detail)
                    if (currentCharacterName) _loadCharacterHeaderState(currentCharacterName);
                    if (currentCharacterName) updateCharacterScene(currentCharacterName);
                }
                if (data.audio_chunk) {
                    if (!ttsChunkPlayer) ttsChunkPlayer = createTtsChunkPlayer(botMessage);
                    ttsChunkPlayer.addChunk(data.audio_chunk);
                }
                if (data.tts_auto) {
                    (async () => {
                        let spinner = botMessage.querySelector('.tts-loading');
                        if (!spinner) {
                            spinner = document.createElement('div');
                            spinner.className = 'tts-loading';
                            spinner.innerHTML = '<span class="story-spinner"></span> Audio wird erzeugt...';
                            botMessage.appendChild(spinner);
                        }
                        try {
                            const resp = await fetch('/tts/speak', {
                                method: 'POST',
                                headers: {'Content-Type': 'application/json'},
                                body: JSON.stringify({ text: fullResponse, character_name: currentCharacterName }),
                            });
                            const result = await resp.json();
                            const sp = botMessage.querySelector('.tts-loading');
                            if (sp) sp.remove();
                            if (result.audio_url) appendAudioPlayer(botMessage, result.audio_url);
                        } catch (e) {
                            console.error('[TTS] Auto-TTS error:', e);
                            const sp = botMessage.querySelector('.tts-loading');
                            if (sp) sp.remove();
                        }
                    })();
                }
                if (data.extraction) {
                    const items = data.extraction.knowledge || [];
                    const addr = data.extraction.address_form || '';
                    if (items.length || addr) {
                        let exEl = botMessage.querySelector('.extraction-info');
                        if (!exEl) {
                            exEl = document.createElement('div');
                            exEl.className = 'extraction-info';
                            botMessage.appendChild(exEl);
                        }
                        let html = '<span class="extraction-label">Gemerkt:</span> ';
                        const parts = items.map(i => `<span class="extraction-item">${escapeHtml(i.content)}</span>`);
                        if (addr) parts.push(`<span class="extraction-item">Anrede: ${escapeHtml(addr)}</span>`);
                        html += parts.join(' · ');
                        exEl.innerHTML = html;
                    }
                }
                if (data.tokens) tokenInfo = data.tokens;
                if (data.timestamp) timestamp = data.timestamp;
            } catch (e) {
                console.error('[Chat] SSE parse error:', e, 'line:', line);
            }
        }
    }
    return { fullResponse, toolImageUrls, tokenInfo, timestamp, hadError: false };
}

// Finalisiert eine Bot-Message nach Ende des Streams (Rendering, Buttons, etc.)
function _finalizeBotMessage(botMessage, botMessageId, fullResponse, toolImageUrls, tokenInfo, timestamp) {
    if (toolImageUrls.length > 0) fullResponse += '\n\n' + toolImageUrls.join('\n');
    const botResponseElement = document.getElementById(botMessageId);
    if (botResponseElement) {
        botResponseElement.innerHTML = marked.parse(stripExternalImages(fullResponse));
        botResponseElement.querySelectorAll('img').forEach(img => {
            img.addEventListener('error', () => { img.style.display = 'none'; });
        });
    }
    const imageUrls = extractImageUrls(fullResponse);
    appendImageGallery(botMessage, imageUrls);
    appendProfileImageButton(botMessage, fullResponse);
    appendSpeakButton(botMessage);
    appendVisualizeButton(botMessage);
    appendInstagramButton(botMessage);
    if (timestamp) {
        const tsEl = document.createElement('div');
        tsEl.classList.add('timestamp');
        tsEl.textContent = formatTimestamp(timestamp);
        botMessage.appendChild(tsEl);
    }
    if (tokenInfo) {
        const tokEl = document.createElement('div');
        tokEl.classList.add('token-info');
        tokEl.textContent = `📊 Tokens: ${tokenInfo.total} (In: ${tokenInfo.input}, Out: ${tokenInfo.output})`;
        botMessage.appendChild(tokEl);
    }
    // Den seen-ts des aktuellen Chat-Partners auf den frischen Bot-Response-
    // Timestamp setzen — sonst zeigt der Unread-Poll danach die gerade gelesene
    // Nachricht als "neu" an.
    if (typeof _markChatSeen === 'function' && currentCharacterName
            && currentCharacterName !== 'KI') {
        _markChatSeen(currentCharacterName);
    }
}

// --- Chat Image Attachment State ---
let _chatAttachedImage = null; // { type: 'upload'|'library', image_id?, image_url?, previewUrl, filename }

function _setChatImageAttachment(attachment) {
    _chatAttachedImage = attachment;
    const previewDiv = document.getElementById('chat-image-preview');
    const previewImg = document.getElementById('chat-image-preview-img');
    const previewName = document.getElementById('chat-image-preview-name');
    if (!previewDiv) return;

    if (attachment) {
        previewImg.src = attachment.previewUrl;
        previewName.textContent = attachment.filename || 'Bild';
        previewDiv.style.display = 'flex';
    } else {
        previewImg.src = '';
        previewName.textContent = '';
        previewDiv.style.display = 'none';
    }
}

function _clearChatImageAttachment() {
    _setChatImageAttachment(null);
    // Reset file input
    const fileInput = document.getElementById('chat-image-upload');
    if (fileInput) fileInput.value = '';
}

// Upload image for chat
async function _uploadChatImage(file) {
    const formData = new FormData();
    formData.append('file', file);
    try {
        const resp = await fetch(`/chat/default/upload-image`, {
            method: 'POST',
            body: formData,
        });
        if (!resp.ok) throw new Error('Upload failed');
        const data = await resp.json();
        // Preview via local object URL
        const previewUrl = URL.createObjectURL(file);
        _setChatImageAttachment({
            type: 'upload',
            image_id: data.image_id,
            previewUrl,
            filename: file.name,
        });
    } catch (e) {
        console.error('Image upload error:', e);
        alert(t('Image upload failed') + ': ' + e.message);
    }
}

// Open image library picker
async function _openImageLibrary() {
    const modal = document.getElementById('image-library-modal');
    const grid = document.getElementById('image-library-grid');
    if (!modal || !grid) return;

    grid.innerHTML = `<div class="image-library-loading">${escapeHtml(t('Loading library…'))}</div>`;
    modal.style.display = 'flex';

    try {
        const resp = await fetch(`/chat/default/image-library`);
        if (!resp.ok) throw new Error('Error loading');
        const data = await resp.json();
        const characters = data.characters || {};

        grid.innerHTML = '';
        let hasImages = false;

        for (const [charName, images] of Object.entries(characters)) {
            if (!images.length) continue;
            hasImages = true;

            const section = document.createElement('div');
            section.className = 'image-library-section';
            section.innerHTML = `<h4>${charName}</h4>`;

            const imagesRow = document.createElement('div');
            imagesRow.className = 'image-library-images';

            for (const img of images) {
                const thumb = document.createElement('img');
                thumb.src = img.url;
                thumb.alt = img.filename;
                thumb.title = img.filename;
                thumb.className = 'image-library-thumb';
                thumb.addEventListener('click', () => {
                    _setChatImageAttachment({
                        type: 'library',
                        image_url: img.url,
                        previewUrl: img.url,
                        filename: `${charName}/${img.filename}`,
                    });
                    modal.style.display = 'none';
                });
                imagesRow.appendChild(thumb);
            }

            section.appendChild(imagesRow);
            grid.appendChild(section);
        }

        if (!hasImages) {
            grid.innerHTML = `<div class="image-library-loading">${escapeHtml(t('No images in the library.'))}</div>`;
        }
    } catch (e) {
        console.error('Image library error:', e);
        grid.innerHTML = `<div class="image-library-loading">Fehler: ${e.message}</div>`;
    }
}

// Init image attachment UI handlers
function _initChatImageUI() {
    const uploadBtn = document.getElementById('btn-attach-image');
    const fileInput = document.getElementById('chat-image-upload');
    const linkBtn = document.getElementById('btn-link-image');
    const removeBtn = document.getElementById('chat-image-preview-remove');
    const closeLibrary = document.getElementById('image-library-close');
    const modal = document.getElementById('image-library-modal');

    if (uploadBtn && fileInput) {
        uploadBtn.addEventListener('click', () => fileInput.click());
        fileInput.addEventListener('change', (e) => {
            if (e.target.files && e.target.files[0]) {
                _uploadChatImage(e.target.files[0]);
            }
        });
    }
    if (linkBtn) {
        linkBtn.addEventListener('click', () => _openImageLibrary());
    }
    if (removeBtn) {
        removeBtn.addEventListener('click', () => _clearChatImageAttachment());
    }
    if (closeLibrary && modal) {
        closeLibrary.addEventListener('click', () => { modal.style.display = 'none'; });
        modal.addEventListener('click', (e) => {
            if (e.target === modal) modal.style.display = 'none';
        });
    }

    // Drag & Drop on chat input
    const chatInput = document.getElementById('user-input');
    if (chatInput) {
        chatInput.addEventListener('dragover', (e) => { e.preventDefault(); chatInput.classList.add('drag-over'); });
        chatInput.addEventListener('dragleave', () => { chatInput.classList.remove('drag-over'); });
        chatInput.addEventListener('drop', (e) => {
            e.preventDefault();
            chatInput.classList.remove('drag-over');
            const files = e.dataTransfer.files;
            if (files && files[0] && files[0].type.startsWith('image/')) {
                _uploadChatImage(files[0]);
            }
        });

        // Paste image from clipboard
        chatInput.addEventListener('paste', (e) => {
            const items = e.clipboardData && e.clipboardData.items;
            if (!items) return;
            for (const item of items) {
                if (item.type.startsWith('image/')) {
                    e.preventDefault();
                    const file = item.getAsFile();
                    if (file) _uploadChatImage(file);
                    break;
                }
            }
        });
    }
}

async function sendMessage() {
    const message = userInput.value.trim();
    if (!message && !_chatAttachedImage) return;
    if (isChatBusy) return;
    // Action mode: input text becomes a Storyteller-narrated action.
    // No chat partner needed, no busy state — Storyteller-LLM is called inside.
    if (chatMode === 'act') {
        if (!message) return;
        userInput.value = '';
        _clearChatImageAttachment();
        await _sendActionFromChatInput(message);
        return;
    }
    // Kein Chat-Partner gewaehlt (z.B. nach Location-Wechsel ohne Character-Klick)
    // Im Gruppenchat nicht zwingend ein einzelner Character noetig.
    if (chatMode !== 'group' && (!currentCharacterName || currentCharacterName === 'KI')) {
        showStatusToast(t('Please choose a character in the sidebar first'), 'warning');
        return;
    }

    // 1. Benutzer-Nachricht anzeigen (with image preview if attached)
    let displayMsg = message;
    if (_chatAttachedImage) {
        const imgHtml = `<img src="${_chatAttachedImage.previewUrl}" class="chat-attached-image-inline" alt="Bild">`;
        displayMsg = imgHtml + (message ? `\n${message}` : '');
    }
    // Whisper-Indikator wenn im Gruppenmodus geflsuestert wird
    const _whisperTgt = (chatMode === 'group' && _groupSession)
        ? (document.getElementById('gcb-whisper-to')?.value || '').trim() : '';
    if (_whisperTgt) {
        displayMsg = `<span class="whisper-msg">🤫 (fluestert zu ${escapeHtml(_whisperTgt)}) ${displayMsg}</span>`;
    }
    addMessage('Du', displayMsg, true);
    userInput.value = '';

    // Capture image data before clearing
    const attachedImage = _chatAttachedImage;
    _clearChatImageAttachment();

    // 2. Zeige Typing-Indikator & setze Busy-State
    setChatBusy(true);

    // === GROUP CHAT MODE ===
    if (chatMode === 'group' && _groupSession) {
        try {
            showTypingIndicator();
            const whisperTo = (document.getElementById('gcb-whisper-to')?.value || '').trim();
            const response = await fetch(`/chat/default/group`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    message,
                    session_id: _groupSession.session_id,
                    turn_taking: _groupTurnTaking,
                    ...(whisperTo ? { whisper_to: whisperTo } : {}),
                }),
            });
            if (!response.ok) throw new Error(`Serverfehler: ${response.status}`);
            const { task_id } = await response.json();
            removeTypingIndicator();
            const streamUrl = `/chat/default/group/stream/${task_id}`;
            await _readGroupChatStream(streamUrl);
        } catch (error) {
            removeTypingIndicator();
            console.error('[GroupChat] Fehler:', error);
            addMessage('System', `Fehler: ${error.message}`, false);
        } finally {
            setChatBusy(false);
        }
        return;
    }

    // === DIRECT CHAT MODE (unchanged) ===
    showTypingIndicator();

    const controller = new AbortController();
    let timeoutId = null;
    const _streamTimeoutMs = 180000; // 3 Minuten Inaktivitaets-Timeout
    function _resetStreamTimeout() {
        if (timeoutId) clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            console.warn('[Chat] Stream-Timeout: keine Daten seit 3 Minuten, breche ab');
            controller.abort();
        }, _streamTimeoutMs);
    }
    _resetStreamTimeout();

    let botMessageId;
    try {
        // 3. Anfrage an den Server — startet Background-Task, gibt task_id zurück
        const chatBody = { message };
        if (attachedImage) {
            if (attachedImage.type === 'upload') {
                chatBody.image_id = attachedImage.image_id;
            } else if (attachedImage.type === 'library') {
                chatBody.image_url = attachedImage.image_url;
            }
        }
        // Markierte Raum-Items mitschicken — Backend packt sie in System-Prompt
        // (NPC kann auf markierte Items Bezug nehmen, z.B. "zeigt auf den Stuhl").
        const _selItems = _getSelectedRoomItemIds();
        if (_selItems.length) chatBody.room_item_ids = _selItems;
        // Phone-Chat: wenn User mit Character chattet der nicht im selben Raum
        // ist — System-Prompt + Bubble-Styling beruecksichtigen das.
        if (currentChatMedium && currentChatMedium !== 'in_person') {
            chatBody.medium = currentChatMedium;
        }
        const response = await fetch(`/chat/default`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(chatBody),
            signal: controller.signal
        });

        if (!response.ok) {
            throw new Error(`Serverfehler: ${response.status} ${response.statusText}`);
        }

        const { task_id } = await response.json();

        // Task-ID in SessionStorage speichern (für Page-Reload Reconnect)
        sessionStorage.setItem(`chatTask_default`, task_id);

        // 4. Entferne Typing-Indikator und erstelle Bot-Message-Element
        removeTypingIndicator();

        // 5. KI-Nachrichten-Element vorbereiten
        botMessageId = `bot-response-${Date.now()}`;
        const botMessage = document.createElement('div');
        botMessage.classList.add('message', 'bot-message');
        if (currentChatMedium === 'messaging' || currentChatMedium === 'telegram') {
            botMessage.classList.add('chat-msg-phone');
            botMessage.dataset.medium = currentChatMedium;
        }
        botMessage.innerHTML = `<strong>${currentCharacterName}:</strong> <span id="${botMessageId}"></span>`;
        chatMessages.appendChild(botMessage);
        chatMessages.scrollTop = chatMessages.scrollHeight;

        // 6. SSE-Stream lesen
        const streamUrl = `/chat/default/stream/${task_id}`;
        const { fullResponse, toolImageUrls, tokenInfo, timestamp, hadError } =
            await _readChatStream(streamUrl, botMessageId, botMessage, controller.signal, _resetStreamTimeout);

        sessionStorage.removeItem(`chatTask_default`);
        if (hadError) return;

        // Tool-generierte Bilder an Response anhaengen (z.B. ImageGeneration)
        // (finalisiert auch Rendering + Buttons)
        _finalizeBotMessage(botMessage, botMessageId, fullResponse, toolImageUrls, tokenInfo, timestamp);

        // 7. Header aktualisieren nach der Antwort
        await loadKnownInfo();
        // Avatar-Header (Location/Activity/Mood) + Scene refreshen — kann sich
        // durch Follow-Logik, SetLocation-Tool oder Outfit-Skills geaendert haben
        // ohne dass ein explizites location/outfit-Event kam.
        await loadPlayerAvatar();
        if (currentCharacterName) updateCharacterScene(currentCharacterName);

        // 8. Instagram-Feed aktualisieren wenn Panel offen
        if (instagramPanelOpen) {
            loadInstagramFeed();
        }
    } catch (error) {
        removeTypingIndicator();
        sessionStorage.removeItem(`chatTask_default`);
        if (error.name === 'AbortError') {
            console.warn('[Chat] Anfrage wurde abgebrochen (Timeout)');
            const el = document.getElementById(botMessageId);
            if (el) el.textContent = t('Request timeout – please try again.');
        } else {
            const el = document.getElementById(botMessageId);
            if (el) el.textContent = `Fehler: ${error.message}`;
        }
        console.error('Fetch-Fehler:', error);
    } finally {
        clearTimeout(timeoutId);
        setChatBusy(false);
    }
}

// Lade initialen Prompt vom Server (z.B. "Wie möchtest du genannt werden?")
async function loadInitialPrompt() {
    const controller = new AbortController();
    let timeoutId = null;
    function _resetInitTimeout() {
        if (timeoutId) clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            console.warn('[Chat] Initial-Prompt Timeout: keine Daten seit 3 Minuten');
            controller.abort();
        }, 180000);
    }
    _resetInitTimeout();

    let botMessage;
    try {
        showTypingIndicator();

        const response = await fetch(`/chat/default`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ message: '' }),
            signal: controller.signal
        });
        if (!response.ok) return;

        const { task_id } = await response.json();

        removeTypingIndicator();
        const botMessageId = `bot-response-init-${Date.now()}`;
        botMessage = document.createElement('div');
        botMessage.classList.add('message', 'bot-message');
        if (currentChatMedium === 'messaging' || currentChatMedium === 'telegram') {
            botMessage.classList.add('chat-msg-phone');
            botMessage.dataset.medium = currentChatMedium;
        }
        botMessage.innerHTML = `<strong>${currentCharacterName}:</strong> <span id="${botMessageId}"></span>`;
        chatMessages.appendChild(botMessage);
        chatMessages.scrollTop = chatMessages.scrollHeight;

        const streamUrl = `/chat/default/stream/${task_id}`;
        const { fullResponse, toolImageUrls, tokenInfo, timestamp, hadError } =
            await _readChatStream(streamUrl, botMessageId, botMessage, controller.signal, _resetInitTimeout);

        if (hadError || !fullResponse.trim()) {
            botMessage.remove();
            return;
        }

        _finalizeBotMessage(botMessage, botMessageId, fullResponse, toolImageUrls, tokenInfo, timestamp);
    } catch (e) {
        if (e.name === 'AbortError') {
            console.warn('[Chat] Initial-Prompt abgebrochen (Timeout)');
        } else {
            console.error('Initial prompt error', e);
        }
        removeTypingIndicator();
        if (botMessage && botMessage.parentNode) botMessage.remove();
    } finally {
        clearTimeout(timeoutId);
    }
}

// Versucht, einen unterbrochenen Chat-Stream nach Page-Reload wiederherzustellen.
async function _tryReconnectChatStream() {
    const savedTaskId = sessionStorage.getItem(`chatTask_default`);
    if (!savedTaskId) return false;

    console.log('[Chat] Reconnecting to task', savedTaskId);
    try {
        // Kurzer Probe-Request um zu sehen ob der Task noch existiert
        const probeResponse = await fetch(`/chat/default/stream/${savedTaskId}`);
        if (!probeResponse.ok) {
            sessionStorage.removeItem(`chatTask_default`);
            return false;
        }

        // Task läuft noch — Reader für den Probe-Response nutzen
        setChatBusy(true);
        const botMessageId = `bot-response-reconnect-${Date.now()}`;
        const botMessage = document.createElement('div');
        botMessage.classList.add('message', 'bot-message');
        if (currentChatMedium === 'messaging' || currentChatMedium === 'telegram') {
            botMessage.classList.add('chat-msg-phone');
            botMessage.dataset.medium = currentChatMedium;
        }
        botMessage.innerHTML = `<strong>${currentCharacterName}:</strong> <span id="${botMessageId}"></span>`;

        // Kleiner Hinweis dass es sich um eine wiederhergestellte Antwort handelt
        const reconnectBadge = document.createElement('div');
        reconnectBadge.style.cssText = 'font-size:11px;color:var(--text-muted);margin-bottom:4px;';
        reconnectBadge.textContent = '🔄 Antwort wird wiederhergestellt...';
        botMessage.insertBefore(reconnectBadge, botMessage.firstChild);

        chatMessages.appendChild(botMessage);
        chatMessages.scrollTop = chatMessages.scrollHeight;

        // Stream direkt aus dem bereits geöffneten probe-Response lesen
        const reader = probeResponse.body.getReader();
        const decoder = new TextDecoder();
        const botResponseElement = document.getElementById(botMessageId);
        let fullResponse = '';
        let toolImageUrls = [];
        let tokenInfo = null;
        let timestamp = null;

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            const chunk = decoder.decode(value);
            const lines = chunk.split('\n').filter(l => l.trim());
            for (const line of lines) {
                if (!line.startsWith('data: ')) continue;
                try {
                    const data = JSON.parse(line.substring(6));
                    if (data.error) { sessionStorage.removeItem(`chatTask_default`); break; }
                    if (data.tool_result) {
                        const m = data.tool_result.match(/!\[[^\]]*\]\(\/characters\/[^)]+\)/g);
                        if (m) toolImageUrls.push(...m);
                    }
                    if (data.content) {
                        fullResponse += data.content;
                        const txt = stripExternalImages(fullResponse).replace(/!\[([^\]]*)\]\(\/characters\/[^)]+\)/g, '\n\n**🖼 $1**\n\n');
                        if (botResponseElement) { botResponseElement.innerHTML = marked.parse(txt); chatMessages.scrollTop = chatMessages.scrollHeight; }
                    }
                    if (data.mood) { const el = document.getElementById('header-mood-display'); if (el) { el.textContent = data.mood; el.title = `Stimmung: ${data.mood}`; } if (currentCharacterName) updateCharacterScene(currentCharacterName); }
                    if (data.location) {
                        // data.location/.room sind die Agent-Position. Wir
                        // refreshen Header + Scene des Agenten, aber den
                        // Body-Background NICHT — der gehoert zur Avatar-
                        // Sicht. Bei face-to-face ist die Avatar-Location
                        // sowieso schon gleich; bei Remote-Chat wuerde der
                        // Background sonst falsch zum Agenten springen.
                        _currentCharacterRoom = data.room || '';
                        if (currentCharacterName) _loadCharacterHeaderState(currentCharacterName);
                        loadCharacterSidebar();
                        loadPlayerAvatar();
                        if (currentCharacterName) updateCharacterScene(currentCharacterName);
                    }
                    if (data.room && !data.location) { _currentCharacterRoom = data.room; if (currentCharacterName) _loadCharacterHeaderState(currentCharacterName); }
                    if (data.activity) { if (currentCharacterName) { _loadCharacterHeaderState(currentCharacterName); updateCharacterScene(currentCharacterName); } loadPlayerAvatar(); }
                    if (data.tokens) tokenInfo = data.tokens;
                    if (data.timestamp) timestamp = data.timestamp;
                } catch (e) { /* ignore parse errors */ }
            }
        }

        sessionStorage.removeItem(`chatTask_default`);
        reconnectBadge.remove();

        if (!fullResponse.trim()) {
            botMessage.remove();
        } else {
            _finalizeBotMessage(botMessage, botMessageId, fullResponse, toolImageUrls, tokenInfo, timestamp);
        }

        setChatBusy(false);
        return true;
    } catch (e) {
        console.warn('[Chat] Reconnect fehlgeschlagen:', e);
        sessionStorage.removeItem(`chatTask_default`);
        setChatBusy(false);
        return false;
    }
}

// Request initial prompt on load
// Load known user/character info and request initial prompt on load
async function loadKnownInfo() {
    try {
        // user name
        const resUser = await fetch(`/store/default/user_name`);
        if (resUser.ok) {
            const data = await resUser.json();
            const uname = data.value || '';
            const _unEl = document.getElementById('user-name');
            if (_unEl) _unEl.textContent = uname || '—';
        }

        // character name and available characters
        const resCharacter = await fetch(`/store/default/chat_partner`);
        const resCharactersList = await fetch(`/characters/list`);

        let currentCharacter = '—';
        let availableCharacters = [];

        if (resCharacter.ok) {
            const data = await resCharacter.json();
            currentCharacter = data.value || '—';
            // Setze globalen Character-Namen nur wenn noch nicht gesetzt (vermeidet Race Condition)
            if (!hasValidCharacter()) {
                currentCharacterName = currentCharacter !== '—' ? currentCharacter : 'KI';
            } else {
                currentCharacter = currentCharacterName;
            }
            _cachedWorldLocations = null;
            // Medium aus Locations herleiten BEVOR Scene-Bild laedt — sonst
            // zeigt es ggf. das Variant statt Profilbild (Phone-Chat).
            if (typeof _recomputeChatMedium === 'function') {
                await _recomputeChatMedium();
            }
            updateCharacterScene(currentCharacterName);
        }

        if (resCharactersList.ok) {
            const data = await resCharactersList.json();
            availableCharacters = data.characters || [];
        }

        // Filter out current character from available characters list
        const otherCharacters = availableCharacters.filter(a => a !== currentCharacter);

        // Display current character
        document.getElementById('agent-name').textContent = currentCharacter;

        // Available characters stored for switching
        window.availableOtherCharacters = otherCharacters;


        // Load character profile image/video
        if (currentCharacter !== '—') {
            try {
                const resImages = await fetch(`/characters/${currentCharacter}/images`);
                if (resImages.ok) {
                    const imagesData = await resImages.json();
                    const profileImageName = imagesData.profile_image;
                    if (profileImageName) {
                        const mediaUrl = `/characters/${currentCharacter}/images/${profileImageName}`;
                        setProfileMedia(mediaUrl, false);
                    } else {
                        setProfileMedia(generateDefaultAvatar(currentCharacter), true);
                    }
                }
            } catch (e) {
                console.log('No profile image:', e);
            }
            // Profilbild-Generieren-Button: Appearance wird on-click vom Backend geholt
            const _genBtn = document.getElementById('btn-generate-profile-image');
            if (_genBtn) {
                _genBtn.style.display = '';
                const _charForGen = currentCharacter;
                _genBtn.onclick = async () => {
                    let _app = '';
                    try {
                        const r = await fetch(`/characters/${encodeURIComponent(_charForGen)}/profile`);
                        if (r.ok) {
                            const d = await r.json();
                            // /profile-Endpoint wrappt: {character, profile: {...}}
                            const _p = d.profile || d;
                            _app = (_p.face_appearance_resolved
                                || _p.face_appearance
                                || _p.character_appearance_resolved
                                || _p.character_appearance
                                || '').trim();
                        }
                    } catch(e) {}
                    generateProfileImage(_charForGen, _app);
                };
            }
        } else {
            document.getElementById('agent-profile-image').style.display = 'none';
            const _genBtn2 = document.getElementById('btn-generate-profile-image');
            if (_genBtn2) _genBtn2.style.display = 'none';
            const vidEl = document.getElementById('agent-profile-video');
            if (vidEl) { vidEl.style.display = 'none'; vidEl.src = ''; }
        }

        // Load theme preference
        await loadTheme();

        // Agent-Buttons + Header-State nur wenn Agent ausgewählt
        setAgentButtonsVisible(hasValidCharacter());
        updateStoryTabVisibility();
        if (hasValidCharacter()) {
            _loadCharacterHeaderState(currentCharacterName);
            loadHeaderMood();
            loadStatusEffectsBars();
            loadConditionBadges();
        } else {
            const moodEl = document.getElementById('header-mood-display');
            if (moodEl) { moodEl.style.display = 'none'; moodEl.textContent = ''; }
            const seEl = document.getElementById('status-effects-bars');
            if (seEl) seEl.style.display = 'none';
        }
        // Character-Sidebar laden (ortsbezogen)
        loadCharacterSidebar();

        // Location-Hintergrundbild laden — IMMER vom Avatar, nicht vom Chat-
        // Partner. Sonst wechselt der Hintergrund beim Phone-Chat zum Ort des
        // Partners, obwohl der Avatar wo anders steht.
        // Avatar-Resolve: zuerst aus dem DOM (Dropdown), sonst direkt aus der
        // Account-API. Der Dropdown wird erst nach loadKnownInfo() befuellt
        // (populateActiveCharacterDropdown), darum war der Hintergrund nach
        // Browser-Refresh leer bis man den Raum manuell wechselte.
        try {
            let _avatarName = (typeof getPlayerCharacterName === 'function')
                ? getPlayerCharacterName() : '';
            if (!_avatarName) {
                try {
                    const _ac = await fetch(`/account/characters`);
                    if (_ac.ok) {
                        const _acd = await _ac.json();
                        _avatarName = _acd.active_character || '';
                    }
                } catch (_) {}
            }
            if (_avatarName) {
                const _locResp = await fetch(`/characters/${encodeURIComponent(_avatarName)}/current-location`);
                if (_locResp.ok) {
                    const _locData = await _locResp.json();
                    updateLocationBackground(_locData.current_location_id || '', _locData.current_room || '');
                }
            }
        } catch (bgErr) {
            console.warn('[Background] Avatar-Hintergrund laden fehlgeschlagen:', bgErr);
        }
    } catch (e) {
        console.error('Error loading known data', e);
    }

}

// --- Character & User Management ---
async function resetUser() {
    // Setze das komplette User-Profil zurück
    try {
        // Rufe den Reset-Endpunkt auf
        const response = await fetch(`/reset/user/default`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });

        if (!response.ok) {
            throw new Error('Reset failed');
        }

        // Leere den Chat
        chatMessages.innerHTML = '';
        // Aktualisiere die Anzeige
        await loadKnownInfo();
        // Lade die initiale Frage erneut
        loadInitialPrompt();
    } catch (e) {
        console.error('Fehler beim Zurücksetzen des Benutzers', e);
        alert(t('Failed to reset user') + ': ' + e.message);
    }
}

// Initialize app after authentication
async function initializeApp() {
    chatMessages.innerHTML = ''; // Clear messages
    _initChatImageUI();
    await loadUiLanguage();
    // Unread-Polling sehr frueh starten — Daten sind dann verfuegbar bevor die
    // Sidebar aus loadKnownInfo zum ersten Mal rendert. Sonst Badge-Flash:
    // erst kein Badge, dann ploetzlich da.
    _startUnreadPolling();
    await loadKnownInfo();
    await loadChatHistory(); // Load existing chat history

    // Versuche unterbrochenen Chat wiederherzustellen; nur wenn kein Task läuft, Initial-Prompt starten
    const reconnected = await _tryReconnectChatStream();
    if (!reconnected) {
        loadInitialPrompt();
    }

    // Start notification polling + load style
    startNotificationPolling();
    loadNotificationStyle();

    // Populate character switch dropdown, player avatar, and language selector
    await populateActiveCharacterDropdown();
    await loadPlayerAvatar();
    initLanguageSelector();
    // Direction-Pad: erreichbare Richtungen einmal initial pruefen.
    if (typeof _refreshDpad === 'function') _refreshDpad();

    // Outfit-SSE: refresht Scene/Avatar bei Hintergrund-Wechseln (Scheduler,
    // Skills im naechsten Tab, Telegram).
    _connectOutfitEventStream();
    // Event-Image-SSE: tauscht den CSS-Background sobald ein Event-Bild
    // fertig generiert wurde oder ein After-Bild bereitsteht.
    _connectEventImageStream();
}

// --- Outfit-Change SSE-Subscription ---
let _outfitEventSource = null;
function _connectOutfitEventStream() {
    try { if (_outfitEventSource) _outfitEventSource.close(); } catch (_) {}
    const es = new EventSource(`/events/outfit-stream`);
    _outfitEventSource = es;
    es.onmessage = (ev) => {
        try {
            const data = JSON.parse(ev.data);
            if (data.type !== 'outfit_changed') return;
            const name = data.character || '';
            if (!name) return;
            if (name === currentCharacterName && typeof updateCharacterScene === 'function') {
                updateCharacterScene(name);
            }
            const avatarSel = document.getElementById('active-character-select');
            const avatarName = avatarSel ? avatarSel.value : '';
            if (avatarName && name === avatarName) {
                if (typeof updatePlayerExpression === 'function') updatePlayerExpression(avatarName);
                if (typeof loadPlayerAvatar === 'function') loadPlayerAvatar();
            }
        } catch (_) { /* ignore parse errors */ }
    };
    es.onerror = () => {
        try { es.close(); } catch (_) {}
        _outfitEventSource = null;
        // Reconnect nach Delay (Netzwerk-Glitches, Server-Restart)
        setTimeout(_connectOutfitEventStream, 5000);
    };
}

// --- Event-Image SSE-Subscription ---
let _eventImageEventSource = null;
async function _fetchAvatarLocationId() {
    const avatar = (typeof getPlayerCharacterName === 'function') ? getPlayerCharacterName() : '';
    if (!avatar) return '';
    try {
        const r = await fetch(`/characters/${encodeURIComponent(avatar)}/current-location`);
        if (!r.ok) return '';
        const d = await r.json();
        return (d.current_location_id || d.current_location || '').toString();
    } catch (_) { return ''; }
}
function _connectEventImageStream() {
    try { if (_eventImageEventSource) _eventImageEventSource.close(); } catch (_) {}
    const es = new EventSource(`/events/image-stream`);
    _eventImageEventSource = es;
    es.onmessage = async (ev) => {
        try {
            const data = JSON.parse(ev.data);
            if (data.type !== 'event_image_ready') return;
            const locId = data.location_id || '';
            if (!locId) return;
            // Background-Swap NUR wenn der Avatar wirklich an dieser Location
            // steht. Avatar-Location + Raum frisch holen, damit wir nicht
            // den partner-Raum mitgeben (der ist in `_currentCharacterRoom`
            // gecached und gehoert nicht zum Background-Lookup).
            const avatar = (typeof getPlayerCharacterName === 'function') ? getPlayerCharacterName() : '';
            if (!avatar) return;
            let avatarLoc = '', avatarRoom = '';
            try {
                const r = await fetch(`/characters/${encodeURIComponent(avatar)}/current-location`);
                if (!r.ok) return;
                const d = await r.json();
                avatarLoc = (d.current_location_id || d.current_location || '').toString();
                avatarRoom = (d.current_room || '').toString();
            } catch (_) { return; }
            if (!avatarLoc || avatarLoc !== locId) return;
            if (typeof updateLocationBackground === 'function') {
                updateLocationBackground(locId, avatarRoom);
            }
            // Notice-Banner aktualisieren — neues Event evtl. mit Block-Rule.
            if (typeof refreshCharNotice === 'function') {
                try { refreshCharNotice(); } catch (_) {}
            }
        } catch (_) { /* ignore parse errors */ }
    };
    es.onerror = () => {
        try { es.close(); } catch (_) {}
        _eventImageEventSource = null;
        setTimeout(_connectEventImageStream, 5000);
    };
}

// Load UI language preference from user profile and the matching translation map.
async function loadUiLanguage() {
    try {
        const res = await fetch(`/store/default/user_profile`);
        if (res.ok) {
            const data = await res.json();
            const lang = (data.value || {}).system_language;
            if (lang) {
                uiLang = lang;
                localStorage.setItem('uiLang', lang);
            }
        }
    } catch (e) { /* ignore */ }
    await loadTranslations(uiLang);
    applyTranslations();
    try { document.documentElement.setAttribute('lang', uiLang || 'en'); } catch (_) {}
}

// Load chat history from server
let _chatHistoryLoaded = 0;   // how many messages are already shown
let _chatHistoryTotal = 0;    // total messages available on server

function _renderHistoryMessage(msg, agentName) {
    const div = document.createElement('div');
    // Stable DB id — used by the diff-poller to dedup against existing
    // bubbles. Falls back to a generated marker so we never produce a
    // collidable selector.
    if (msg.id != null) {
        div.dataset.msgId = String(msg.id);
    }
    // Phone-Chat-Markierung: Nachrichten mit medium=messaging bekommen eine
    // visuelle Unterscheidung (Border + Phone-Icon), damit klar ist dass
    // diese Nachricht remote/per Chat gefuehrt wurde, nicht im selben Raum.
    const _medium = msg.medium || (msg.metadata && msg.metadata.medium) || '';
    if (_medium === 'messaging' || _medium === 'telegram') {
        div.classList.add('chat-msg-phone');
        div.dataset.medium = _medium;
    }
    if (msg.role === 'user') {
        div.classList.add('message', 'user-message');
        div.textContent = msg.content;
    } else {
        div.classList.add('message', 'bot-message');
        const botId = `bot-hist-${Date.now()}-${Math.random().toString(36).slice(2,6)}`;
        div.innerHTML = `<strong>${agentName || ''}:</strong> <span id="${botId}"></span>`;
        // Temporarily add to DOM so getElementById works for marked.parse
        chatMessages.appendChild(div);
        const span = document.getElementById(botId);
        const cleanedContent = msg.content.replace(/^\[Gedanken-Nachricht[^\]]*\]\s*/, '');
        span.innerHTML = marked.parse(stripExternalImages(cleanedContent));
        span.querySelectorAll('img').forEach(img => {
            img.addEventListener('error', () => { img.style.display = 'none'; });
        });
        const imageUrls = extractImageUrls(msg.content);
        appendImageGallery(div, imageUrls);
        appendSpeakButton(div);
        appendVisualizeButton(div);
        appendInstagramButton(div);
        if (msg.timestamp) {
            const ts = document.createElement('div');
            ts.classList.add('timestamp');
            ts.textContent = formatTimestamp(msg.timestamp);
            div.appendChild(ts);
        }
    }
    return div;
}

function _updateLoadMoreButton() {
    let btn = document.getElementById('load-more-history');
    if (_chatHistoryLoaded < _chatHistoryTotal) {
        if (!btn) {
            btn = document.createElement('button');
            btn.id = 'load-more-history';
            btn.classList.add('load-more-btn');
            btn.addEventListener('click', () => loadOlderMessage());
        }
        const remaining = _chatHistoryTotal - _chatHistoryLoaded;
        btn.textContent = `▲ ${t('Load older message')} (${remaining})`;
        // Always ensure it's the first child
        if (chatMessages.firstChild !== btn) {
            chatMessages.prepend(btn);
        }
    } else if (btn) {
        btn.remove();
    }
}

// ── Chat-Polling: holt regelmaessig die neueste Message und rendert neu wenn
// der Chat-Partner uns angesprochen hat (TalkTo, Notification, etc.). Pausiert
// waehrend isChatBusy (aktiver eigener Stream) und ohne Chat-Partner.
let _chatLastSeenTs = '';
let _chatLastSeenId = 0;     // highest chat_messages.id currently rendered
let _chatPollMuteUntil = 0;  // epoch ms — poller skips while > Date.now()
let _chatPollInterval = null;
const CHAT_POLL_INTERVAL_MS = 5000;

function _startChatPolling() {
    if (_chatPollInterval) return;
    _chatPollInterval = setInterval(_pollChatForUpdates, CHAT_POLL_INTERVAL_MS);
}
function _stopChatPolling() {
    if (_chatPollInterval) { clearInterval(_chatPollInterval); _chatPollInterval = null; }
}
// === Unread Chats per Character (Sidebar-Badge) =============================
// Server liefert per /chat/unread-summary den jeweils neuesten Assistant-
// Timestamp pro Character (Chat mit dem Avatar als Partner). FE vergleicht
// gegen localStorage `chat_seen_<char>` und setzt einen Badge in der Sidebar
// wenn server-ts > seen-ts.
// Format: { characterName: { latest: ts, recent: [ts1, ts2, ...] } }
let _unreadChats = {};
let _unreadPollInterval = null;
const UNREAD_POLL_INTERVAL_MS = 10000;

function _seenKey(name) { return 'chat_seen_' + name; }
function _latestFor(name) {
    const slot = _unreadChats[name];
    if (!slot) return '';
    if (typeof slot === 'string') return slot;  // Backwards compat
    return (slot.latest || '').trim();
}
function _recentFor(name) {
    const slot = _unreadChats[name];
    if (!slot || typeof slot === 'string') return [];
    return slot.recent || [];
}
function _unreadCountFor(name) {
    const seen = (localStorage.getItem(_seenKey(name)) || '').trim();
    const recent = _recentFor(name);
    if (!recent.length) {
        // Fallback: nur latest vergleichen (dann ist count 0 oder 1)
        return _latestFor(name) > seen ? 1 : 0;
    }
    let n = 0;
    for (const ts of recent) {
        if (ts && ts > seen) n++;
    }
    return n;
}
function _isChatUnread(name) {
    // Aktiven Chat-Partner nie als unread markieren — Du siehst die Nachrichten
    // ja gerade. Sonst nervt der Badge auf dem Sidebar-Eintrag mit dem Du
    // gerade chattest.
    if (name && name === currentCharacterName) return false;
    return _unreadCountFor(name) > 0;
}
function _totalUnread() {
    let total = 0;
    for (const name of Object.keys(_unreadChats)) {
        // Aktiven Chat-Partner aus dem Total ausnehmen — Du siehst dessen
        // Nachrichten ja schon.
        if (name === currentCharacterName) continue;
        total += _unreadCountFor(name);
    }
    return total;
}
function _markChatSeen(name) {
    // Vorwaerts-Bewegung garantieren: spaeterer Wert von (server-latest, jetzt).
    // Reine `latest`-Uebernahme war zu schwach — wenn der Stream-End markSeen
    // VOR dem naechsten Unread-Poll laeuft, ist `latest` noch der vorherige
    // Server-Stand und der gerade gelesene Bot-Reply taucht nach dem Poll als
    // "unread" auf. Mit ISO-Strings ist der String-Vergleich sortierbar.
    const latest = _latestFor(name) || '';
    const now = new Date().toISOString();
    const seen = latest > now ? latest : now;
    localStorage.setItem(_seenKey(name), seen);
    if (typeof loadCharacterSidebar === 'function') loadCharacterSidebar();
    _updatePhoneBtnBadge();
}
function _updatePhoneBtnBadge() {
    const btn = document.getElementById('btn-phone-chat');
    if (!btn) return;
    const total = _totalUnread();
    let badge = btn.querySelector('.phone-toggle-badge');
    if (total > 0) {
        if (!badge) {
            badge = document.createElement('span');
            badge.className = 'phone-toggle-badge';
            btn.appendChild(badge);
        }
        badge.textContent = total > 99 ? '99+' : String(total);
    } else if (badge) {
        badge.remove();
    }
}
async function _pollUnreadChats() {
    try {
        const r = await fetch('/chat/unread-summary');
        if (!r.ok) return;
        const d = await r.json();
        const wasEmpty = !Object.keys(_unreadChats).length;
        _unreadChats = d.chats || {};

        // Erste Befuellung in diesem Browser: localStorage kennt keine
        // seen-ts (frischer Browser, Inkognito, Cache geloescht). Statt
        // alle Chats als "neu" zu zeigen, markieren wir hier den
        // aktuellen Stand pro Character als gesehen — neue Nachrichten
        // ab JETZT erzeugen den Badge.
        if (wasEmpty && Object.keys(_unreadChats).length) {
            for (const name of Object.keys(_unreadChats)) {
                if (localStorage.getItem(_seenKey(name)) === null) {
                    const latest = _latestFor(name);
                    if (latest) localStorage.setItem(_seenKey(name), latest);
                }
            }
        }

        if (typeof loadCharacterSidebar === 'function') {
            loadCharacterSidebar();
        }
        _updatePhoneBtnBadge();
    } catch (e) { /* ignore */ }
}
// Frueher: 10s _pollUnreadChats — jetzt im 3s-Live-Tick mitgepullt.
// Funktionen bleiben als Aliase, damit andere Aufrufer nicht brechen.
function _startUnreadPolling() {
    _startLiveTick();
}
function _stopUnreadPolling() {
    _stopLiveTick();
}

async function _pollChatForUpdates() {
    if (typeof isChatBusy !== 'undefined' && isChatBusy) return;
    if (Date.now() < _chatPollMuteUntil) return;
    if (typeof currentCharacterName === 'undefined' || !currentCharacterName
            || currentCharacterName === 'KI') return;
    // Diff-Polling braucht eine valide Baseline — vor dem ersten
    // loadChatHistory ist sie 0, dann wuerde since_id=0 die ganze
    // History zurueckliefern. Beim leeren Chat (kein Initial-Load
    // wegen leerer DB) bleibt die Baseline 0; das ist korrekt, ein
    // erstes since_id=0 liefert dann genau alles was inzwischen kam.
    try {
        const since = _chatLastSeenId || 0;
        const r = await fetch(`/chat/default/history?since_id=${since}`);
        if (!r.ok) return;
        const d = await r.json();
        const msgs = d.messages || [];
        if (!msgs.length) return;

        // Scroll-Position erfassen BEVOR wir was anfuegen, damit wir bei
        // bereits am Ende stehendem User automatisch nachziehen, sonst aber
        // nicht den Lese-Punkt stoehren.
        const nearBottom = (chatMessages.scrollHeight - chatMessages.scrollTop
                            - chatMessages.clientHeight) < 120;

        let appended = 0;
        let hadAssistant = false;
        for (const m of msgs) {
            const id = m.id || 0;
            if (id <= _chatLastSeenId) continue;
            // Safety: schon im DOM (z.B. optimistisch gerendert)?
            if (id && document.querySelector(
                    `[data-msg-id="${CSS.escape(String(id))}"]`)) {
                _chatLastSeenId = Math.max(_chatLastSeenId, id);
                continue;
            }
            const div = _renderHistoryMessage(m, d.agent_name);
            // Bot-Messages werden in _renderHistoryMessage selbst appended;
            // User-Messages muessen wir hier einhaengen.
            if (m.role === 'user') chatMessages.appendChild(div);
            if (m.role === 'assistant') hadAssistant = true;
            if (id) _chatLastSeenId = Math.max(_chatLastSeenId, id);
            if (m.timestamp) _chatLastSeenTs = m.timestamp;
            appended++;
        }

        if (!appended) return;
        if (nearBottom) chatMessages.scrollTop = chatMessages.scrollHeight;
        if (hadAssistant) showStatusToast(t('New message'), 'info');
    } catch (e) {
        // ignore
    }
}

async function loadChatHistory(limit = 2, fromPoll = false) {
    _chatHistoryLoaded = 0;
    _chatHistoryTotal = 0;
    try {
        const resp = await fetch(`/chat/default/history?limit=${limit}`);
        if (!resp.ok) return;
        const data = await resp.json();
        const msgs = data.messages || [];
        _chatHistoryTotal = data.total || msgs.length;

        if (msgs.length === 0) {
            _updateLoadMoreButton();
            return;
        }

        for (const msg of msgs) {
            const div = _renderHistoryMessage(msg, data.agent_name);
            // bot messages are already appended inside _renderHistoryMessage;
            // user messages need to be appended here
            if (msg.role === 'user') {
                chatMessages.appendChild(div);
            }
        }
        _chatHistoryLoaded = msgs.length;
        _updateLoadMoreButton();
        chatMessages.scrollTop = chatMessages.scrollHeight;

        // Polling-Baseline aus den geladenen Messages ableiten — sowohl die
        // hoechste DB-id (fuer den Diff-Poller) als auch den neuesten ts
        // (fuer Unread-Logik). Nur setzen wenn nicht aus Polling getriggert.
        if (!fromPoll && msgs.length) {
            _chatLastSeenTs = (msgs[msgs.length - 1].timestamp || '');
            let maxId = _chatLastSeenId;
            for (const m of msgs) { if ((m.id || 0) > maxId) maxId = m.id; }
            _chatLastSeenId = maxId;
        }
        _startChatPolling();
        _startUnreadPolling();
        // Aktuell offener Character: dessen Chat als "gesehen" markieren
        if (currentCharacterName && currentCharacterName !== 'KI') {
            _markChatSeen(currentCharacterName);
        }
    } catch (e) {
        console.error('[History] Error:', e);
    }
}

async function loadOlderMessage() {
    try {
        const resp = await fetch(`/chat/default/history?limit=1&offset=${_chatHistoryLoaded}`);
        if (!resp.ok) return;
        const data = await resp.json();
        const msgs = data.messages || [];
        if (msgs.length === 0) return;

        // Remember scroll position to keep view stable
        const prevHeight = chatMessages.scrollHeight;

        // Insert messages at the top (after the load-more button)
        const loadBtn = document.getElementById('load-more-history');
        const insertRef = loadBtn ? loadBtn.nextSibling : chatMessages.firstChild;

        for (const msg of msgs) {
            const div = _renderHistoryMessage(msg, data.agent_name);
            // _renderHistoryMessage appends bot msgs to the end; move them to the right spot
            // For all messages, place them right after the load-more button
            chatMessages.insertBefore(div, insertRef);
        }

        _chatHistoryLoaded += msgs.length;
        _chatHistoryTotal = data.total || _chatHistoryTotal;
        _updateLoadMoreButton();

        // Restore scroll position so it doesn't jump
        const newHeight = chatMessages.scrollHeight;
        chatMessages.scrollTop += (newHeight - prevHeight);
    } catch (e) {
        console.error('[History] Load older error:', e);
    }
}

