document.getElementById('btn-new-character').addEventListener('click', createNewCharacter);

async function createNewCharacter() {
    try {
        // 1) Lade verfuegbare Templates
        const templatesRes = await fetch('/templates/list?template_type=character');
        let templates = [];
        if (templatesRes.ok) {
            const data = await templatesRes.json();
            templates = data.templates || [];
        }

        // 2) Template-Auswahl (immer anzeigen)
        let selectedTemplate = 'default';
        if (templates.length === 0) {
            alert('Keine Templates vorhanden.');
            return;
        } else if (templates.length === 1) {
            selectedTemplate = templates[0].name;
        } else {
            const options = templates.map((t, i) => `${i + 1}) ${t.label || t.name}`).join('\n');
            const choice = prompt(`Template waehlen:\n${options}\n\nNummer eingeben:`, '1');
            if (!choice) return;
            const idx = parseInt(choice, 10) - 1;
            if (idx >= 0 && idx < templates.length) {
                selectedTemplate = templates[idx].name;
            }
        }

        // 3) Character-Name
        const name = prompt('Name des neuen Characters:');
        if (!name || !name.trim()) return;

        const characterName = name.trim();

        // 4) Erstellen
        const response = await fetch('/characters/create', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                character_name: characterName,
                template: selectedTemplate
            })
        });

        if (!response.ok) {
            const err = await response.json();
            alert(t('Error') + ': ' + (err.detail || 'Unbekannter Fehler'));
            return;
        }

        // Update global state
        currentCharacterName = characterName;
        updateCharacterScene(characterName);
        updateStoryTabVisibility();

        // Refresh header info
        await loadKnownInfo();

        showStatusToast(t('Character') + ` "${characterName}" ` + t('created'), 'success');

        // Open the editor so user can fill in properties
        document.getElementById('modal-agent-name').textContent = characterName;
        document.getElementById('agent-modal').style.display = 'flex';
        await renderCharacterEditor(characterName);
    } catch (e) {
        console.error('Fehler beim Erstellen des Characters:', e);
        alert('Fehler beim Erstellen: ' + e.message);
    }
}


// --- Character Image Management ---

async function openCharacterModal(targetCharacter) {
    // If called as event listener, targetCharacter is the Event object — ignore it
    const characterName = (typeof targetCharacter === 'string' && targetCharacter) ? targetCharacter : currentCharacterName;
    if (!characterName || characterName === 'KI') {
        alert('Bitte waehle zuerst einen Character aus');
        return;
    }

    _modalCharacter = characterName;
    document.getElementById('modal-agent-name').textContent = characterName;
    document.getElementById('agent-modal').style.display = 'flex';

    // Tab beim Oeffnen auf Profil zuruecksetzen
    switchAgentEditorTab('profil');

    // Lade Template und Profildaten, render Editor
    await renderCharacterEditor(characterName);
}

function closeCharacterModal() {
    document.getElementById('agent-modal').style.display = 'none';
}

function switchAgentEditorTab(tabName) {
    document.querySelectorAll('.agent-editor-tab-btn').forEach(btn => {
        btn.classList.toggle('tab-active', btn.dataset.agentEditorTab === tabName);
    });
    document.querySelectorAll('.agent-editor-tab-content').forEach(content => {
        const id = content.id || '';
        content.style.display = id === ('agent-editor-tab-' + tabName) ? '' : 'none';
    });
    if (tabName === 'tagesablauf') {
        // Lazy-Load: Cache invalidieren damit aktuelle Locations frisch geladen werden,
        // dann Tagesablauf des aktuell editierten Characters laden.
        _cachedWorldLocations = null;
        loadDailySchedule();
    }
}

function exportCharacter() {
    const charName = getEditorCharacterName();
    if (!charName) return;
    const params = new URLSearchParams({include_chats: 'false', include_stories: 'false'});
    window.location.href = `/characters/${charName}/export?${params}`;
}

async function deleteCharacterFromEditor() {
    const charName = getEditorCharacterName();
    if (!charName) return;
    const ok = confirm(t('Really completely delete character') + ` "${charName}"?\n\n` + t('DB entries, outfits, images, memories and the storage directory will be removed. This action is irreversible.'));
    if (!ok) return;
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(charName)}`, {method: 'DELETE'});
        if (!resp.ok) {
            const txt = await resp.text();
            showStatusToast(t('Delete failed') + `: ${txt}`, 'error');
            return;
        }
        showStatusToast(t('Character') + ` "${charName}" ` + t('deleted.'), 'success');
        closeCharacterModal();
        // Trigger UI refresh if the consumer page exposes a hook
        if (typeof window.refreshCharacterListsAfterDelete === 'function') {
            try { window.refreshCharacterListsAfterDelete(charName); } catch (_) {}
        }
        // Fallback: hard reload (the editor was open from various contexts)
        setTimeout(() => window.location.reload(), 400);
    } catch (e) {
        showStatusToast(t('Delete failed') + `: ${e.message}`, 'error');
    }
}

function _summarizeImportResult(data) {
    const fileCount = data.files_imported || 0;
    const dbStats = data.db_rows_imported || {};
    const dbTotal = Object.values(dbStats).reduce((a, b) => a + b, 0);
    const dbTables = Object.keys(dbStats).length;
    return `Character "${data.character}" imported: ${fileCount} files, `
        + `${dbTotal} DB rows across ${dbTables} tables.`;
}

async function _postImport(file, overwrite) {
    const fd = new FormData();
    fd.append('file', file);
    const url = `/characters/import?overwrite=${overwrite ? 'true' : 'false'}`;
    const resp = await fetch(url, { method: 'POST', body: fd });
    const data = await resp.json().catch(() => ({}));
    return { resp, data };
}

async function importCharacter(event) {
    const file = event.target.files[0];
    if (!file) return;
    event.target.value = '';

    try {
        let { resp, data } = await _postImport(file, false);
        if (resp.status === 409) {
            if (!confirm(`${data.detail}\n\nOverwrite?`)) return;
            ({ resp, data } = await _postImport(file, true));
        }
        if (resp.ok) {
            alert(_summarizeImportResult(data));
            location.reload();
        } else {
            alert(`Error: ${data.detail || resp.statusText}`);
        }
    } catch (e) {
        alert(`Import failed: ${e.message}`);
    }
}

// --- Template Switch with Diff + Confirmation ---

async function _handleTemplateSwitch(characterName, newTemplate, selectEl) {
    try {
        // 1. Diff holen
        const diffResp = await fetch(`/characters/${encodeURIComponent(characterName)}/switch-template`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ new_template: newTemplate, mode: 'diff' })
        });
        if (!diffResp.ok) { showStatusToast(t('Template diff error'), 'error'); return; }
        const diff = await diffResp.json();

        // 2. Bestaetigungsdialog wenn es Aenderungen gibt
        const hasChanges = diff.added.length > 0 || diff.removed.length > 0;
        if (hasChanges) {
            let msg = `Template wechseln: ${diff.old_template} → ${newTemplate}\n\n`;
            if (diff.added.length > 0) {
                msg += `NEUE Felder (werden mit Default gefuellt):\n`;
                diff.added.forEach(f => {
                    const name = f.label_de || f.label;
                    const def = f.default !== null && f.default !== undefined && f.default !== '' ? ` = ${f.default}` : '';
                    msg += `  + ${name}${def}\n`;
                });
                msg += '\n';
            }
            if (diff.removed.length > 0) {
                msg += `ENTFERNTE Felder (Werte gehen verloren!):\n`;
                diff.removed.forEach(f => {
                    const name = f.label_de || f.label;
                    const val = f.current_value ? ` (aktuell: ${String(f.current_value).substring(0, 50)})` : '';
                    msg += `  - ${name}${val}\n`;
                });
                msg += '\n';
            }
            msg += 'Fortfahren?';
            if (!confirm(msg)) {
                // Zuruecksetzen auf altes Template
                if (selectEl) selectEl.value = diff.old_template;
                return;
            }
        }

        // 3. Migration durchfuehren
        const applyResp = await fetch(`/characters/${encodeURIComponent(characterName)}/switch-template`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ new_template: newTemplate, mode: 'apply' })
        });
        if (applyResp.ok) {
            const result = await applyResp.json();
            const addedCount = result.added.length;
            const removedCount = result.removed.length;
            if (addedCount || removedCount) {
                showStatusToast(t('Template switched') + `: +${addedCount} ` + t('new,') + ` -${removedCount} ` + t('removed fields'), 'success');
            } else {
                showStatusToast(t('Template switched'), 'success');
            }
        } else {
            showStatusToast(t('Template switch error'), 'error');
        }

        // 4. Editor neu rendern
        await renderCharacterEditor(characterName, newTemplate);

    } catch (error) {
        console.error('[TemplateSwitch] Fehler:', error);
        showStatusToast(t('Template switch error'), 'error');
    }
}

// --- Character Editor: Template-based dynamic form ---

async function renderCharacterEditor(characterName, forceTemplateName) {
    const container = document.getElementById('editor-sections');
    const badgesContainer = document.getElementById('editor-readiness-badges');
    container.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Loading…'))}</p>`;
    badgesContainer.innerHTML = '';

    try {
        // Fetch profile + template list + config in parallel
        const [profileRes, templatesRes, configRes] = await Promise.all([
            fetch(`/characters/${encodeURIComponent(characterName)}/profile`),
            fetch('/templates/list?template_type=character'),
            fetch(`/characters/${encodeURIComponent(characterName)}/config`)
        ]);
        let profile = {};
        if (profileRes.ok) {
            const profileData = await profileRes.json();
            profile = profileData.profile || {};
        }
        let allTemplates = [];
        if (templatesRes.ok) {
            const tData = await templatesRes.json();
            allTemplates = tData.templates || [];
        }
        let charConfig = {};
        if (configRes.ok) {
            const cData = await configRes.json();
            charConfig = cData.config || {};
        }

        // Expose profile data for visible_when option filtering
        window._editorProfileData = profile;

        // Determine active template
        const templateName = forceTemplateName || profile.template || '';

        // Load the template (if one is selected)
        let template = null;
        if (templateName) {
            const templateRes = await fetch(`/templates/${encodeURIComponent(templateName)}`);
            if (templateRes.ok) {
                template = await templateRes.json();
            }
        }

        // Build HTML: template selector always at top
        let html = '';
        html += `<div class="modal-section editor-section" style="display:flex;align-items:center;gap:8px;margin-top:0;margin-bottom:6px;padding:0;">`;
        html += `<label style="margin:0;white-space:nowrap;font-size:12px;color:var(--text-muted);">Template</label>`;
        html += `<select class="agent-status-input" id="editor-template-select" style="flex:1;padding:3px 6px;font-size:12px;">`;
        html += `<option value="">-- Template waehlen --</option>`;
        for (const t of allTemplates) {
            const sel = t.name === templateName ? ' selected' : '';
            html += `<option value="${escapeHtml(t.name)}"${sel}>${escapeHtml(t.label || t.name)}</option>`;
        }
        html += `</select>`;
        html += `</div>`;

        if (!template || !template.sections) {
            html += `<p class="scheduler-empty">${escapeHtml(t('Please choose a template to show fields.'))}</p>`;
            container.innerHTML = html;
            // Wire up template change handler
            document.getElementById('editor-template-select').addEventListener('change', async (e) => {
                const newTemplate = e.target.value;
                if (!newTemplate) return;
                await _handleTemplateSwitch(characterName, newTemplate, e.target);
            });
            return;
        }

        // Pre-load dynamic sources (world locations/activities)
        const dynamicData = {};
        const sourcesToLoad = new Set();
        for (const section of template.sections) {
            for (const field of (section.fields || [])) {
                if (field.source) sourcesToLoad.add(field.source);
            }
        }

        if (sourcesToLoad.has('world_locations') || sourcesToLoad.has('world_activities')) {
            try {
                const [locRes, actRes] = await Promise.all([
                    fetch(`/world/locations?agent_name=${encodeURIComponent(characterName)}`),
                    fetch(`/world/activities?agent_name=${encodeURIComponent(characterName)}`)
                ]);
                if (locRes.ok) {
                    const d = await locRes.json();
                    dynamicData.world_locations = (d.locations || []).map(l => ({ value: l.name, label: l.name }));
                }
                if (actRes.ok) {
                    const d = await actRes.json();
                    dynamicData.world_activities = (d.activities || []).map(a => ({ value: a.name, label: a.name }));
                }
            } catch (e) {
                console.warn('[Editor] World data load failed:', e);
            }
        }

        // TTS Voices und Speaker WAVs laden
        if (sourcesToLoad.has('tts_voices') || sourcesToLoad.has('tts_speakers')) {
            try {
                const fetches = [];
                if (sourcesToLoad.has('tts_voices')) fetches.push(fetch('/tts/voices'));
                else fetches.push(Promise.resolve(null));
                if (sourcesToLoad.has('tts_speakers')) fetches.push(fetch('/tts/speakers'));
                else fetches.push(Promise.resolve(null));
                const [voiceRes, speakerRes] = await Promise.all(fetches);
                if (voiceRes && voiceRes.ok) {
                    const d = await voiceRes.json();
                    dynamicData.tts_voices = d.voices || [];
                }
                if (speakerRes && speakerRes.ok) {
                    const d = await speakerRes.json();
                    dynamicData.tts_speakers = d.speakers || [];
                }
            } catch (e) {
                console.warn('[Editor] TTS data load failed:', e);
            }
        }

        // Available LLM Models laden
        if (sourcesToLoad.has('available_models')) {
            try {
                const res = await fetch('/characters/available-models');
                if (res.ok) {
                    const data = await res.json();
                    // Gruppiert nach Provider fuer <optgroup>
                    const groups = [];
                    const capsMap = {};  // "Provider::model" -> capabilities
                    for (const [provName, provInfo] of Object.entries(data.providers || {})) {
                        const items = [];
                        for (const m of (provInfo.models || [])) {
                            const name = m.name || '';
                            if (!name) continue;
                            const sizeGb = m.size_gb || 0;
                            const paramSize = m.parameter_size || '';
                            const caps = m.capabilities || {};
                            const capBadges = [];
                            if (caps.tool_calling === true) capBadges.push('[Tools]');
                            if (caps.vision === true) capBadges.push('[Vision]');
                            const capStr = capBadges.length > 0 ? ' ' + capBadges.join(' ') : '';
                            const label = sizeGb > 0 ? `${name} (${sizeGb} GB)${capStr}` : (paramSize ? `${name} (${paramSize})${capStr}` : `${name}${capStr}`);
                            const fullKey = `${provName}::${name}`;
                            items.push({ value: fullKey, label });
                            capsMap[fullKey] = caps;
                        }
                        items.sort((a, b) => a.label.localeCompare(b.label));
                        if (items.length > 0) {
                            groups.push({ provider: provName, type: provInfo.type || '', models: items });
                        }
                    }
                    groups.sort((a, b) => a.provider.localeCompare(b.provider));
                    dynamicData.available_models = groups;
                    dynamicData.model_capabilities = capsMap;
                    // Task-Defaults entfernt (LLM-Wahl jetzt zentral via Router)
                    dynamicData.available_models_defaults = {};
                }
            } catch (e) {
                console.warn('[Editor] Available models load failed:', e);
            }
        }

        // Characters list laden (fuer checkboxes source=characters)
        if (sourcesToLoad.has('characters')) {
            try {
                const res = await fetch(`/characters/list`);
                if (res.ok) {
                    const d = await res.json();
                    dynamicData.characters = (d.characters || []).filter(c => c !== characterName);
                }
                // User name
                const uRes = await fetch(`/store/default/user_name`);
                if (uRes.ok) {
                    const ud = await uRes.json();
                    dynamicData.user_name = ud.value || '';
                }
            } catch (e) {
                console.warn('[Editor] Characters load failed:', e);
            }
        }

        // Sort sections by column, then row
        const sections = [...template.sections].sort((a, b) => {
            const colDiff = (a.column || 1) - (b.column || 1);
            return colDiff !== 0 ? colDiff : (a.row ?? 1) - (b.row ?? 1);
        });

        // Check if a field is visible given current profile/config data
        function isFieldVisible(field, profileData, configData) {
            const vw = field.visible_when;
            if (!vw) return true;
            const depKey = vw.field;
            const depValue = (configData[depKey] ?? '') || (profileData[depKey] || '');
            return (vw.values || []).includes(depValue);
        }

        function renderSectionHtml(section) {
            // Section ueberspringen wenn alle Felder editor_visible=false haben
            const visibleFields = (section.fields || []).filter(f => f.editor_visible !== false);
            if (visibleFields.length === 0) return '';
            // Section-Level visible_when (z.B. Beliefs/Lessons/Goals nur
            // sichtbar wenn retrospect_enabled=true). Reactor unten aktualisiert
            // beim Toggle live, hier wird der initiale Render-State gesetzt.
            const secVw = section.visible_when;
            let secHidden = false;
            if (secVw && secVw.field) {
                const dv = (charConfig[secVw.field] ?? '') || (profile[secVw.field] || '');
                secHidden = !((secVw.values || []).includes(String(dv)));
            }
            const secVwAttr = secVw ? ` data-section-visible-when="${escapeHtml(JSON.stringify(secVw))}"` : '';
            const secStyle = secHidden ? ' style="display:none;"' : '';
            let s = `<div class="modal-section editor-section"${secVwAttr}${secStyle}>`;
            s += `<h3>${escapeHtml(tLabel(section) || section.id)}</h3>`;
            for (const field of (section.fields || [])) {
                if (field.editor_visible === false) continue;
                const visible = isFieldVisible(field, profile, charConfig);
                let value = field.store === 'config' ? (charConfig[field.key] ?? '') : (profile[field.key] || '');
                if ((value === '' || value === null || value === undefined) && field.default !== undefined) {
                    value = field.default;
                }
                const requiredMark = field.required ? ' <span class="editor-required">*</span>' : '';
                const workflowHint = (field.workflow_required || []).length > 0
                    ? `<span class="editor-workflow-hint">${field.workflow_required.join(', ')}</span>`
                    : '';
                const visibleWhenAttr = field.visible_when ? ` data-visible-when="${escapeHtml(JSON.stringify(field.visible_when))}"` : '';
                s += `<div class="editor-field"${visibleWhenAttr}${!visible ? ' style="display:none;"' : ''}>`;
                let tokenTooltip = '';
                if (field.replacement) {
                    const token = field.replacement.token || field.key;
                    tokenTooltip = ` <span class="editor-token-tooltip" title="Im Aussehen verwendbar als {${token}}">{${token}}</span>`;
                }
                s += `<label class="editor-label">${escapeHtml(tLabel(field) || field.key)}${requiredMark}${tokenTooltip} ${workflowHint}</label>`;
                s += renderEditorField(field, value, dynamicData);
                if (field.computed_display === 'age' && value) {
                    const age = calculateAge(value);
                    if (age !== null) s += `<span class="editor-computed-age">(${age} Jahre)</span>`;
                }
                if (field.key === 'character_appearance') {
                    s += `<div class="editor-appearance-preview" id="appearance-preview"></div>`;
                }
                if (field.key === 'face_appearance') {
                    s += `<div class="editor-appearance-preview" id="face-appearance-preview"></div>`;
                }
                const hint = tHint(field);
                if (hint) {
                    s += `<span class="editor-hint">${escapeHtml(hint)}</span>`;
                }
                s += `</div>`;
            }
            s += `</div>`;
            return s;
        }

        // Skills section — labels from template section.labels (with inline fallbacks)
        function renderSkillsSection(section) {
            const L = (section && section.labels) || {};
            const lTitle   = tLabel(section   || {label: 'Skills',           label_de: 'Skills'});
            const lLoading = tLabel(L.loading  || {label: 'Loading skills...', label_de: 'Lade Skills...'});
            const lSelect  = tLabel(L.select   || {label: 'Select a skill',    label_de: 'Skill auswählen'});
            let s = `<div class="modal-section editor-section">`;
            s += `<h3>${escapeHtml(lTitle)}</h3>`;
            s += `<div class="skills-split-layout">`;
            s += `<div id="editor-skills-list" class="editor-skills-list"><p class="scheduler-empty">${escapeHtml(lLoading)}</p></div>`;
            s += `<div id="editor-skills-config" class="editor-skills-config"><p class="scheduler-empty">${escapeHtml(lSelect)}</p></div>`;
            s += `</div>`;
            s += `</div>`;
            return s;
        }

        // Activities panel (allowed locations + referenced activities list)
        function renderActivitiesPanel(section) {
            const L = (section && section.labels) || {};
            const lAllowed   = tLabel(L.allowed_locations   || {label: 'Allowed Locations',      label_de: 'Erlaubte Orte'});
            const lHome      = tLabel(L.home_location       || {label: 'Home (Sleep Location)',  label_de: 'Zuhause (Schlaf-Ort)'});
            let s = '';
            // Home Location / Room
            s += `<div class="modal-section editor-section">`;
            s += `<h3>${escapeHtml(lHome)}</h3>`;
            s += `<div class="home-location-row">`;
            s += `<select id="editor-home-location" class="agent-status-input" onchange="_onHomeLocationChange()"><option value="">-- No home --</option></select>`;
            s += `<select id="editor-home-room" class="agent-status-input"><option value="">-- No room --</option></select>`;
            s += `<button class="save-btn" onclick="_saveHomeLocation()">Save</button>`;
            s += `</div></div>`;
            // Allowed locations wurde abgeschafft — Stub-Platzhalter bleibt,
            // damit der bestehende _loadEditorAllowedLocations-Aufruf greift.
            s += `<div id="editor-allowed-locations" style="display:none;"></div>`;
            // Zugewiesene Aktivitaeten (Referenzen + Legacy)
            s += `<div class="modal-section editor-section">`;
            s += `<div class="scheduler-header" style="display:flex;justify-content:space-between;align-items:center;">`;
            s += `<h3 style="margin:0;">Zugewiesene Aktivitaeten</h3>`;
            s += `<button class="save-btn" style="font-size:12px;padding:4px 10px;" onclick="_pickExtraActivity()">+ Aktivitaet</button>`;
            s += `</div>`;
            s += `<div id="editor-activities-list" class="world-list"><p class="scheduler-empty">Keine Aktivitaeten zugewiesen</p></div>`;
            s += `</div>`;
            return s;
        }

        // Activity library browser (right column) — DEPRECATED: ersetzt durch openPicker-Dialog
        // via "+ Aktivitaet" Button in der Zugewiesene-Aktivitaeten-Sektion.
        // Spalte bleibt leer, falls Template sie noch referenziert.
        function renderActivityForm(section) {
            return '';
        }

        // Outfit Image Generator Override — im Konfiguration-Tab Spalte 2.
        // Gleicher Aufbau wie Image-Generation-Skill Config:
        //   Service-Select (Workflow) + Model-Select + 4 LoRA-Slots (Name + Strength).
        function renderOutfitImagegenSection(section) {
            const title = tLabel({label: 'Outfit Image Generator (Override)',
                                   label_de: 'Outfit-Bild Generator (Override)'});
            let s = `<div class="modal-section editor-section">`;
            s += `<h3>${escapeHtml(title)}</h3>`;
            s += `<div id="editor-outfit-imagegen-section">`;
            s += `<p class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading…'))}</p>`;
            s += `</div></div>`;
            return s;
        }

        function renderSlotOverridesSection(section) {
            const title = tLabel(section || {label: 'Image Appearance',
                                              label_de: 'Bild-Darstellung'});
            let s = `<div class="modal-section editor-section">`;
            s += `<h3>${escapeHtml(title)}</h3>`;
            s += `<div id="editor-slot-overrides-section">`;
            s += `<p class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading…'))}</p>`;
            s += `</div></div>`;
            return s;
        }

        // Secrets panel (list of character secrets)
        function renderSecretsPanel(section) {
            const L = (section && section.labels) || {};
            const lTitle     = tLabel(L.title            || {label: 'Secrets',               label_de: 'Geheimnisse'});
            const lNew       = tLabel(L.new_secret       || {label: '+ New Secret',          label_de: '+ Neues Geheimnis'});
            const lNoSecrets = tLabel(L.no_secrets       || {label: 'No secrets yet',        label_de: 'Noch keine Geheimnisse vorhanden'});
            let s = '';
            s += `<div class="modal-section editor-section">`;
            s += `<div class="scheduler-header"><h3>${escapeHtml(lTitle)}</h3>`;
            s += `<div style="display:flex;gap:6px;">`;
            s += `<button class="save-btn" onclick="generateEditorSecrets()" title="LLM generiert passende Geheimnisse basierend auf Profil, Beziehungen und Verlauf">Generieren</button>`;
            s += `<button class="save-btn" onclick="toggleEditorSecretForm()">${escapeHtml(lNew)}</button>`;
            s += `</div></div>`;
            s += `<div id="editor-secrets-list" class="world-list"><p class="scheduler-empty">${escapeHtml(lNoSecrets)}</p></div>`;
            s += `</div>`;
            return s;
        }

        // Secrets edit form (right column)
        function renderSecretsForm(section) {
            const L = (section && section.labels) || {};
            const lNewTitle    = tLabel(L.new_title         || {label: 'New Secret',                 label_de: 'Neues Geheimnis'});
            const lContent     = tLabel(L.content           || {label: 'Secret text',                label_de: 'Geheimnis-Text'});
            const lCategory    = tLabel(L.category          || {label: 'Category',                   label_de: 'Kategorie'});
            const lSeverity    = tLabel(L.severity          || {label: 'Severity (1-5)',             label_de: 'Schwere (1-5)'});
            const lRelChars    = tLabel(L.related_chars     || {label: 'Related characters',         label_de: 'Beteiligte Charaktere'});
            const lConsequence = tLabel(L.consequences      || {label: 'Consequences if revealed',   label_de: 'Konsequenzen bei Enthuellung'});
            const lKnownBy     = tLabel(L.known_by          || {label: 'Known by (comma-separated)', label_de: 'Bekannt bei (kommagetrennt)'});
            const lSave        = tLabel(L.save              || {label: 'Save',                        label_de: 'Speichern'});
            const lCancel      = tLabel(L.cancel            || {label: 'Cancel',                      label_de: 'Abbrechen'});
            const lPlaceholder = tLabel(L.placeholder       || {label: 'Click + or edit to manage secrets', label_de: 'Klicke auf + oder Bearbeiten um Geheimnisse zu verwalten'});
            let s = '';
            s += `<div id="editor-secret-form" class="world-inline-form" style="display: none;">`;
            s += `<h3 id="editor-secret-form-title">${escapeHtml(lNewTitle)}</h3>`;
            s += `<textarea id="editor-secret-content" class="agent-status-input" rows="6" placeholder="${escapeHtml(lContent)}"></textarea>`;
            s += `<select id="editor-secret-category" class="agent-status-input">`;
            s += `<option value="personal">${escapeHtml(tLabel({label:'Personal', label_de:'Persoenlich'}))}</option>`;
            s += `<option value="relationship">${escapeHtml(tLabel({label:'Relationship', label_de:'Beziehung'}))}</option>`;
            s += `<option value="location">${escapeHtml(tLabel({label:'Location', label_de:'Ort'}))}</option>`;
            s += `<option value="criminal">${escapeHtml(tLabel({label:'Criminal', label_de:'Kriminell'}))}</option>`;
            s += `</select>`;
            s += `<div class="form-row-inline">`;
            s += `<label>${escapeHtml(lSeverity)}</label>`;
            s += `<input type="range" id="editor-secret-severity" min="1" max="5" value="2" class="agent-status-input" oninput="document.getElementById('editor-secret-severity-val').textContent=this.value">`;
            s += `<span id="editor-secret-severity-val">2</span>`;
            s += `</div>`;
            s += `<input type="text" id="editor-secret-related-chars" class="agent-status-input" placeholder="${escapeHtml(lRelChars)}">`;
            s += `<input type="text" id="editor-secret-consequences" class="agent-status-input" placeholder="${escapeHtml(lConsequence)}">`;
            s += `<input type="text" id="editor-secret-known-by" class="agent-status-input" placeholder="${escapeHtml(lKnownBy)}">`;
            s += `<div class="form-actions">`;
            s += `<button class="save-btn" onclick="saveEditorSecret()">${escapeHtml(lSave)}</button>`;
            s += `<button class="reset-btn" onclick="toggleEditorSecretForm()">${escapeHtml(lCancel)}</button>`;
            s += `</div></div>`;
            s += `<div id="editor-secret-placeholder" class="scheduler-empty">${escapeHtml(lPlaceholder)}</div>`;
            return s;
        }

        // Inventory panel (character inventory list)
        function renderInventoryPanel(section) {
            const L = (section && section.labels) || {};
            const lTitle   = tLabel(L.title    || {label: 'Inventory',          label_de: 'Inventar'});
            const lAdd     = tLabel(L.add_item || {label: '+ Add Item',         label_de: '+ Item hinzufuegen'});
            const lNoItems = tLabel(L.no_items || {label: 'Inventory is empty', label_de: 'Inventar ist leer'});
            let s = '';
            s += `<div class="modal-section editor-section">`;
            s += `<div class="scheduler-header"><h3>${escapeHtml(lTitle)}</h3>`;
            s += `<button class="save-btn" onclick="toggleEditorInventoryForm()">${escapeHtml(lAdd)}</button></div>`;
            s += `<div id="editor-inventory-list" class="world-list"><p class="scheduler-empty">${escapeHtml(lNoItems)}</p></div>`;
            s += `</div>`;
            return s;
        }

        // Inventory add form (right column)
        function renderInventoryForm(section) {
            const L = (section && section.labels) || {};
            const lTitle       = tLabel(L.title        || {label: 'Add Item to Inventory', label_de: 'Item zum Inventar hinzufuegen'});
            const lSelect      = tLabel(L.select_item  || {label: 'Select item',           label_de: 'Item auswaehlen'});
            const lQuantity    = tLabel(L.quantity      || {label: 'Quantity',               label_de: 'Anzahl'});
            const lSave        = tLabel(L.save          || {label: 'Add',                     label_de: 'Hinzufuegen'});
            const lCancel      = tLabel(L.cancel        || {label: 'Cancel',                  label_de: 'Abbrechen'});
            const lPlaceholder = tLabel(L.placeholder   || {label: 'Click + to add items',   label_de: 'Klicke auf + um Items hinzuzufuegen'});
            let s = '';
            s += `<div id="editor-inventory-form" class="world-inline-form" style="display: none;">`;
            s += `<h3 id="editor-inventory-form-title">${escapeHtml(lTitle)}</h3>`;
            s += `<select id="editor-inventory-item-select" class="agent-status-input"><option value="">${escapeHtml(lSelect)}</option></select>`;
            s += `<div id="editor-inventory-item-preview" class="scheduler-empty" style="font-size:12px;"></div>`;
            s += `<div class="form-row-inline">`;
            s += `<label>${escapeHtml(lQuantity)}</label>`;
            s += `<input type="number" id="editor-inventory-quantity" class="agent-status-input" value="1" min="1" max="99" style="width:80px;">`;
            s += `</div>`;
            s += `<div class="form-actions">`;
            s += `<button class="save-btn" onclick="saveEditorInventoryItem()">${escapeHtml(lSave)}</button>`;
            s += `<button class="reset-btn" onclick="toggleEditorInventoryForm()">${escapeHtml(lCancel)}</button>`;
            s += `</div></div>`;
            s += `<div id="editor-inventory-placeholder" class="scheduler-empty">${escapeHtml(lPlaceholder)}</div>`;
            s += `<div style="margin-top: 16px; padding: 10px; background: rgba(255,255,255,0.03); border-radius: 6px; font-size: 11px; color: var(--text-muted);">`;
            s += `Item-Bibliothek verwalten: Game Admin (🎮) → Tab "Items"`;
            s += `</div>`;
            return s;
        }

        // Render a grid for given column numbers
        function renderColumnsGrid(columns) {
            const colCount = columns.length;
            const colSecs = columns.map(c => sections.filter(s => (s.column || 1) === c));
            const hasActivitiesLayout = colSecs.some(cs => cs.some(s => s.special === 'activities'));
            const hasSecretsLayout = colSecs.some(cs => cs.some(s => s.special === 'secrets'));
            const hasInventoryLayout = colSecs.some(cs => cs.some(s => s.special === 'inventory'));
            const gridCols = (hasActivitiesLayout || hasSecretsLayout || hasInventoryLayout) ? '3fr 2fr' : `repeat(${colCount}, 1fr)`;
            let g = `<div class="editor-grid" style="grid-template-columns: ${gridCols};">`;
            const _skipCols = new Set();
            for (const col of columns) {
                if (_skipCols.has(col)) continue;
                const colSections = sections.filter(s => (s.column || 1) === col);
                // Wenn eine Section column_span > 1 hat, ueberspringt die folgende(n)
                // Spalte(n) und das col-div spannt im Parent-Grid.
                let _span = 1;
                for (const s of colSections) {
                    const cs = parseInt(s.column_span || 1, 10) || 1;
                    if (cs > _span) _span = cs;
                }
                if (_span > 1) {
                    for (let k = 1; k < _span; k++) _skipCols.add(col + k);
                }
                const _spanStyle = _span > 1 ? ` style="grid-column: span ${_span};"` : '';
                g += `<div class="editor-grid-col"${_spanStyle}>`;
                for (const section of colSections) {
                    if (section.special === 'skills') {
                        g += renderSkillsSection(section);
                    } else if (section.special === 'activities') {
                        g += renderActivitiesPanel(section);
                    } else if (section.special === 'activity_form') {
                        g += renderActivityForm(section);
                    } else if (section.special === 'secrets') {
                        g += renderSecretsPanel(section);
                    } else if (section.special === 'secrets_form') {
                        g += renderSecretsForm(section);
                    } else if (section.special === 'inventory') {
                        g += renderInventoryPanel(section);
                    } else if (section.special === 'inventory_form') {
                        g += renderInventoryForm(section);
                    } else if (section.special === 'outfit_imagegen') {
                        g += renderOutfitImagegenSection(section);
                    } else if (section.special === 'slot_overrides') {
                        g += renderSlotOverridesSection(section);
                    } else {
                        g += renderSectionHtml(section);
                    }
                }
                g += `</div>`;
            }
            g += `</div>`;
            return g;
        }

        // Tabs from template (fallback: all columns in one tab)
        const tabs = template.tabs || [{ id: 'all', label: 'Alle', columns: [1, 2, 3, 4] }];

        if (tabs.length > 1) {
            // Tab bar
            html += `<div class="editor-tabs">`;
            for (let i = 0; i < tabs.length; i++) {
                const active = i === 0 ? ' active' : '';
                html += `<button class="editor-tab${active}" data-tab="${tabs[i].id}">${escapeHtml(tLabel(tabs[i]) || tabs[i].id)}</button>`;
            }
            html += `</div>`;
            // Tab contents
            for (let i = 0; i < tabs.length; i++) {
                const tab = tabs[i];
                const hidden = i === 0 ? '' : ' style="display:none;"';
                html += `<div class="editor-tab-content" data-tab="${tab.id}"${hidden}>`;
                if (tab.special === 'soul') {
                    html += renderSoulTab(characterName);
                } else if (Array.isArray(tab.columns)) {
                    html += renderColumnsGrid(tab.columns);
                }
                html += `</div>`;
            }
        } else {
            // No tabs — single grid with all columns
            html += renderColumnsGrid(tabs[0].columns);
        }

        container.innerHTML = html;

        // Fix tab container height to the tallest tab so the modal doesn't resize on switch
        const tabContents = container.querySelectorAll('.editor-tab-content');
        if (tabContents.length > 1) {
            // Briefly show all tabs to measure their natural height
            tabContents.forEach(el => { el.style.display = ''; });
            let maxH = 0;
            tabContents.forEach(el => { if (el.scrollHeight > maxH) maxH = el.scrollHeight; });
            // Restore: show only first tab, hide others
            tabContents.forEach((el, i) => { el.style.display = i === 0 ? '' : 'none'; });
            // Set fixed min-height so switching tabs won't shrink the modal
            if (maxH > 0) tabContents.forEach(el => { el.style.minHeight = maxH + 'px'; });
        }

        // Wire up tab switching
        for (const tabBtn of container.querySelectorAll('.editor-tab')) {
            tabBtn.addEventListener('click', () => {
                const tabId = tabBtn.dataset.tab;
                for (const btn of container.querySelectorAll('.editor-tab')) btn.classList.remove('active');
                tabBtn.classList.add('active');
                for (const content of container.querySelectorAll('.editor-tab-content')) {
                    content.style.display = content.dataset.tab === tabId ? '' : 'none';
                }
                // Lazy-init Soul-Editor wenn der Tab geoeffnet wird
                if (tabId === 'soul') {
                    const tabContent = container.querySelector('.editor-tab-content[data-tab="soul"]');
                    if (tabContent) SoulEditor.init(tabContent);
                }
            });
        }
        // Falls Soul Tab beim ersten Render als aktiver Tab gewaehlt ist (selten)
        const initialSoulTab = container.querySelector('.editor-tab.active[data-tab="soul"]');
        if (initialSoulTab) {
            const tabContent = container.querySelector('.editor-tab-content[data-tab="soul"]');
            if (tabContent) SoulEditor.init(tabContent);
        }

        // Wire up template change handler
        document.getElementById('editor-template-select').addEventListener('change', async (e) => {
            const newTemplate = e.target.value;
            if (!newTemplate) return;
            await _handleTemplateSwitch(characterName, newTemplate, e.target);
        });

        // Wire up live appearance preview (body + face)
        setupAppearancePreview(container, sections);
        setupAppearancePreview(container, sections, 'face_appearance', 'face-appearance-preview');

        // Wire up visible_when reactivity: show/hide fields and filter options when controlling field changes
        setupVisibleWhen(container, sections, profile, charConfig, dynamicData);

        // Wire up allow_custom: switch between select and text input
        setupAllowCustom(container, sections, profile, charConfig, dynamicData);

        // Fetch readiness
        try {
            const readinessRes = await fetch(`/templates/readiness/${encodeURIComponent(characterName)}`);
            if (readinessRes.ok) {
                const readinessData = await readinessRes.json();
                renderReadinessBadges(readinessData.capabilities || {}, badgesContainer);
            }
        } catch (e) {
            console.warn('[Editor] Readiness check failed:', e);
        }

        // Load skills into config column
        loadEditorSkills(characterName);

        // Load activities data (if activities tab exists)
        if (container.querySelector('#editor-activities-list')) {
            _loadEditorActivities(characterName);
            _loadEditorAllowedLocations(characterName);
            _loadEditorHomeLocation(characterName);
            _loadLibraryActivities();
        }

        // Outfit-Imagegen-Override Section (Konfiguration-Tab, Spalte 2)
        if (container.querySelector('#editor-outfit-imagegen-section')) {
            _loadEditorOutfitImagegen(characterName);
        }

        // Slot-Overrides Matrix (Prompt+LoRA pro leerem Slot)
        if (container.querySelector('#editor-slot-overrides-section')) {
            _loadEditorSlotOverrides(characterName);
        }

        // Load secrets data (if secrets tab exists)
        if (container.querySelector('#editor-secrets-list')) {
            _loadEditorSecrets(characterName);
        }

        // Load inventory data (if inventory tab exists)
        if (container.querySelector('#editor-inventory-list')) {
            _loadEditorInventory(characterName);
            _populateEditorInventoryItemDropdown();
        }

        // Capability-Warnungen fuer Model+Tools Kombination
        wireEditorCapabilityWarnings(container, dynamicData);

        // Telegram Bot Status in telegram_config section anzeigen
        loadTelegramBotStatus(characterName);

    } catch (error) {
        console.error('[Editor] Error loading template/profile:', error);
        container.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading editor'))}</p>`;
    }
}


// ---------------------------------------------------------------------------
// Soul Editor — MD-Files mit Vorschau + Editor
// ---------------------------------------------------------------------------

function renderSoulTab(characterName) {
    return `
        <div class="soul-tab" data-character="${escapeHtml(characterName)}" data-loaded="0">
            <div class="soul-files-bar" id="soul-files-bar">
                <span class="scheduler-empty">Lade Dateien...</span>
            </div>
            <div class="soul-editor-grid">
                <div class="soul-editor-col">
                    <div class="soul-col-header">
                        <span>Editor (Markdown)</span>
                        <button class="save-btn soul-save-btn" id="soul-save-btn" disabled>Speichern</button>
                    </div>
                    <textarea class="soul-editor" id="soul-editor" placeholder="MD-Datei oben waehlen..." spellcheck="false"></textarea>
                </div>
                <div class="soul-preview-col">
                    <div class="soul-col-header">
                        <span>Vorschau</span>
                        <span class="soul-legend">
                            <span class="soul-legend-item soul-legend-editable">Editierbar (Character)</span>
                            <span class="soul-legend-item soul-legend-locked">Gesperrt</span>
                        </span>
                    </div>
                    <div class="soul-preview" id="soul-preview">
                        <p class="scheduler-empty">Datei oben waehlen...</p>
                    </div>
                </div>
            </div>
        </div>
    `;
}

const SoulEditor = {
    state: {character: '', file: '', dirty: false, currentRaw: ''},

    init(rootEl) {
        const tab = rootEl.querySelector('.soul-tab');
        if (!tab || tab.dataset.loaded === '1') return;
        tab.dataset.loaded = '1';
        const character = tab.dataset.character;
        SoulEditor.state.character = character;
        SoulEditor.loadFiles(rootEl);

        const editor = rootEl.querySelector('#soul-editor');
        editor.addEventListener('input', () => {
            SoulEditor.state.dirty = true;
            const btn = rootEl.querySelector('#soul-save-btn');
            if (btn) btn.disabled = false;
            // Live-Preview update
            SoulEditor.renderPreview(rootEl, editor.value);
        });
        const saveBtn = rootEl.querySelector('#soul-save-btn');
        saveBtn.addEventListener('click', () => SoulEditor.save(rootEl));
    },

    async loadFiles(rootEl) {
        const character = SoulEditor.state.character;
        const bar = rootEl.querySelector('#soul-files-bar');
        try {
            const r = await fetch(`/characters/${encodeURIComponent(character)}/soul/files`);
            const data = await r.json();
            const files = data.files || [];
            if (files.length === 0) {
                bar.innerHTML = `<span class="scheduler-empty">${escapeHtml(t('No soul files enabled for this template.'))}</span>`;
                return;
            }
            bar.innerHTML = files.map(f => {
                const lock = f.file_default === 'editable' ? '🟢' : '🔒';
                const name = f.section.charAt(0).toUpperCase() + f.section.slice(1);
                const exists = f.exists ? '' : ' (leer)';
                return `<button class="soul-file-btn" data-section="${escapeHtml(f.section)}" title="${f.path}">${lock} ${escapeHtml(name)}${exists}</button>`;
            }).join('');
            for (const btn of bar.querySelectorAll('.soul-file-btn')) {
                btn.addEventListener('click', () => SoulEditor.selectFile(rootEl, btn.dataset.section, btn));
            }
            // Erste Datei vorauswaehlen
            const first = bar.querySelector('.soul-file-btn');
            if (first) SoulEditor.selectFile(rootEl, first.dataset.section, first);
        } catch (e) {
            bar.innerHTML = `<span class="scheduler-empty">Fehler: ${escapeHtml(String(e))}</span>`;
        }
    },

    async selectFile(rootEl, section, btn) {
        if (SoulEditor.state.dirty) {
            if (!confirm('Ungespeicherte Aenderungen verwerfen?')) return;
        }
        for (const b of rootEl.querySelectorAll('.soul-file-btn')) b.classList.remove('active');
        if (btn) btn.classList.add('active');
        const character = SoulEditor.state.character;
        try {
            const r = await fetch(`/characters/${encodeURIComponent(character)}/soul/file/${encodeURIComponent(section)}`);
            const data = await r.json();
            SoulEditor.state.file = section;
            SoulEditor.state.currentRaw = data.raw || '';
            SoulEditor.state.dirty = false;
            const editor = rootEl.querySelector('#soul-editor');
            editor.value = data.raw || '';
            const saveBtn = rootEl.querySelector('#soul-save-btn');
            saveBtn.disabled = true;
            // Vorschau rendern
            SoulEditor.renderPreviewFromData(rootEl, data);
        } catch (e) {
            rootEl.querySelector('#soul-preview').innerHTML = `<p class="scheduler-empty">Fehler: ${escapeHtml(String(e))}</p>`;
        }
    },

    renderPreview(rootEl, rawText) {
        // Live-Preview waehrend Editor-Eingabe — parse client-seitig
        const sections = SoulEditor.parseSections(rawText);
        const fileDefault = SoulEditor.deriveFileDefault();
        SoulEditor.renderSectionsHtml(rootEl, sections, fileDefault);
    },

    renderPreviewFromData(rootEl, data) {
        SoulEditor.renderSectionsHtml(rootEl, data.sections || [], data.file_default || 'unknown');
    },

    renderSectionsHtml(rootEl, sections, fileDefault) {
        const target = rootEl.querySelector('#soul-preview');
        if (!sections.length) {
            target.innerHTML = '<p class="scheduler-empty">(leer)</p>';
            return;
        }
        let html = '';
        for (const sec of sections) {
            if (sec.level === 1) {
                html += `<h3 class="soul-h1">${escapeHtml(sec.heading)}</h3>`;
                if (sec.body) html += `<div class="soul-body">${escapeHtml(sec.body).replace(/\n/g, '<br>')}</div>`;
            } else if (sec.level === 2) {
                // Section-Lock-Status: file-default, ggf. ueberschrieben durch EDITABLE-Marker
                let isEditable;
                if (fileDefault === 'editable') {
                    isEditable = true;
                } else {
                    isEditable = !!sec.editable_marker;
                }
                const cls = isEditable ? 'soul-section soul-editable' : 'soul-section soul-locked';
                const badge = isEditable ? '🟢 editierbar' : '🔒 gesperrt';
                html += `<div class="${cls}">`;
                html += `<h4 class="soul-h2"><span class="soul-section-name">${escapeHtml(sec.heading)}</span><span class="soul-section-badge">${badge}</span></h4>`;
                if (sec.body) {
                    html += `<div class="soul-body">${escapeHtml(sec.body).replace(/\n/g, '<br>')}</div>`;
                } else {
                    html += `<div class="soul-body soul-empty">(leer)</div>`;
                }
                html += `</div>`;
            }
        }
        target.innerHTML = html;
    },

    deriveFileDefault() {
        const file = SoulEditor.state.file;
        const editable = ['beliefs', 'lessons', 'goals'];
        return editable.includes(file) ? 'editable' : 'locked';
    },

    parseSections(text) {
        // Client-side mini parser (mirror of backend _parse_soul_sections)
        const sections = [];
        let curH = null, curLvl = 0, curBody = [];
        const flush = () => {
            if (curH === null && curBody.length === 0) return;
            const bodyLines = curBody.slice();
            const hasMarker = bodyLines.some(l => l.includes('<!-- EDITABLE -->'));
            const cleanLines = bodyLines.filter(l => !l.includes('<!-- EDITABLE -->'));
            const body = cleanLines.join('\n').trim();
            sections.push({level: curLvl, heading: curH || '', body, editable_marker: hasMarker});
        };
        for (const line of text.split('\n')) {
            if (line.startsWith('# ') && !line.startsWith('## ')) {
                flush(); curH = line.slice(2).trim(); curLvl = 1; curBody = [];
            } else if (line.startsWith('## ')) {
                flush(); curH = line.slice(3).trim(); curLvl = 2; curBody = [];
            } else {
                curBody.push(line);
            }
        }
        flush();
        return sections;
    },

    async save(rootEl) {
        const character = SoulEditor.state.character;
        const section = SoulEditor.state.file;
        if (!section) return;
        const editor = rootEl.querySelector('#soul-editor');
        const content = editor.value;
        const btn = rootEl.querySelector('#soul-save-btn');
        btn.disabled = true;
        btn.textContent = 'Speichere...';
        try {
            const r = await fetch(`/characters/${encodeURIComponent(character)}/soul/file/${encodeURIComponent(section)}`, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({content}),
            });
            if (!r.ok) {
                const err = await r.text();
                alert('Fehler beim Speichern: ' + err);
                btn.disabled = false;
            } else {
                SoulEditor.state.dirty = false;
                SoulEditor.state.currentRaw = content;
            }
        } catch (e) {
            alert(t('Error') + ': ' + e);
            btn.disabled = false;
        } finally {
            btn.textContent = 'Speichern';
        }
    },
};

async function loadEditorSkills(characterName) {
    const listContainer = document.getElementById('editor-skills-list');
    const configContainer = document.getElementById('editor-skills-config');
    if (!listContainer) return;
    try {
        const res = await fetch(`/characters/${encodeURIComponent(characterName)}/skills/available`);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();
        const skills = data.skills || [];
        const _skillLocations = data.locations || [];
        if (skills.length === 0) {
            listContainer.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No skills available'))}</p>`;
            return;
        }
        // Left column: Skill list with checkboxes
        const _dynamicCfgSkills = ['image_generation', 'video_generation'];
        let html = '';
        for (const skill of skills) {
            const checked = skill.enabled ? ' checked' : '';
            const hasConfig = (skill.config_fields && Object.keys(skill.config_fields).length > 0) || _dynamicCfgSkills.includes(skill.skill_id);
            html += `<div class="editor-skill-item${hasConfig ? ' has-config' : ''}" data-skill-id="${escapeHtml(skill.skill_id)}">`;
            html += `<input type="checkbox" data-skill-id="${escapeHtml(skill.skill_id)}"${checked}>`;
            html += `<span class="editor-skill-name">${escapeHtml(skill.name)}</span>`;
            html += `</div>`;
        }
        listContainer.innerHTML = html;

        // Show config panel for selected skill
        function showSkillConfig(skillId) {
            if (!configContainer) return;
            const skill = skills.find(s => s.skill_id === skillId);
            if (!skill) return;
            // Highlight selected skill
            listContainer.querySelectorAll('.editor-skill-item').forEach(el => {
                el.classList.toggle('selected', el.dataset.skillId === skillId);
            });
            const hasConfig = skill.config_fields && Object.keys(skill.config_fields).length > 0;
            let ch = `<h4>${escapeHtml(skill.name)}</h4>`;
            ch += `<p class="skill-config-desc">${escapeHtml(skill.description)}</p>`;
            // Skills mit dynamischer Config (eigene Sektion) nicht blockieren
            const hasDynamicConfig = skill.skill_id === 'image_generation' || skill.skill_id === 'video_generation';
            if (!hasConfig && !hasDynamicConfig) {
                ch += `<p class="scheduler-empty">${escapeHtml(t('No configuration available'))}</p>`;
                configContainer.innerHTML = ch;
                return;
            }
            for (const [fieldName, fieldInfo] of Object.entries(skill.config_fields || {})) {
                const val = fieldInfo.value !== undefined ? fieldInfo.value : fieldInfo.default;
                const label = fieldInfo.label || fieldName;
                ch += `<div class="skill-config-field">`;
                ch += `<label>${escapeHtml(label)}</label>`;
                if (fieldInfo.type === 'locations') {
                    // Location-Checkboxen
                    const selectedIds = Array.isArray(val) ? val : [];
                    ch += `<div class="skill-cfg-locations" data-field="${escapeHtml(fieldName)}">`;
                    if (_skillLocations.length === 0) {
                        ch += `<p class="scheduler-empty">${escapeHtml(t('No locations available'))}</p>`;
                    } else {
                        ch += `<p style="font-size:11px;color:var(--text-muted);margin:0 0 6px;">Leer = alle erlaubten Locations</p>`;
                        for (const loc of _skillLocations) {
                            const locChecked = selectedIds.includes(loc.id) ? ' checked' : '';
                            ch += `<label class="skill-cfg-loc-item"><input type="checkbox" value="${escapeHtml(loc.id)}"${locChecked}> ${escapeHtml(loc.name)}</label>`;
                        }
                    }
                    ch += `</div>`;
                } else if (fieldInfo.type === 'bool') {
                    const boolChecked = val ? ' checked' : '';
                    ch += `<input type="checkbox" class="skill-cfg-input" data-field="${escapeHtml(fieldName)}" data-type="bool"${boolChecked}>`;
                    if (fieldInfo.help) ch += `<span class="skill-cfg-help">${escapeHtml(fieldInfo.help)}</span>`;
                } else if (fieldInfo.type === 'select' && fieldInfo.options) {
                    ch += `<select class="skill-cfg-input agent-status-input" data-field="${escapeHtml(fieldName)}" data-type="select">`;
                    for (const opt of fieldInfo.options) {
                        const selected = String(val) === String(opt.value) ? ' selected' : '';
                        ch += `<option value="${escapeHtml(opt.value)}"${selected}>${escapeHtml(opt.label)}</option>`;
                    }
                    ch += `</select>`;
                    if (fieldInfo.help) ch += `<span class="skill-cfg-help">${escapeHtml(fieldInfo.help)}</span>`;
                } else if (fieldInfo.type === 'int' || fieldInfo.type === 'float') {
                    const step = fieldInfo.type === 'float' ? '0.1' : '1';
                    ch += `<input type="number" class="skill-cfg-input agent-status-input" data-field="${escapeHtml(fieldName)}" data-type="${fieldInfo.type}" value="${escapeHtml(String(val))}" step="${step}">`;
                    if (fieldInfo.help) ch += `<span class="skill-cfg-help">${escapeHtml(fieldInfo.help)}</span>`;
                } else {
                    const isLong = fieldName.includes('prompt') || fieldName.includes('description');
                    if (isLong) {
                        ch += `<textarea class="skill-cfg-input agent-status-input" data-field="${escapeHtml(fieldName)}" data-type="str" rows="3">${escapeHtml(String(val))}</textarea>`;
                    } else {
                        ch += `<input type="text" class="skill-cfg-input agent-status-input" data-field="${escapeHtml(fieldName)}" data-type="str" value="${escapeHtml(String(val))}" placeholder="${escapeHtml(String(fieldInfo.default))}">`;
                    }
                    if (fieldInfo.help) ch += `<span class="skill-cfg-help">${escapeHtml(fieldInfo.help)}</span>`;
                    if (fieldInfo.examples && fieldInfo.examples.length > 0) {
                        ch += `<div class="skill-cfg-examples">`;
                        ch += `<span class="skill-cfg-examples-label">Beispiele:</span>`;
                        for (const ex of fieldInfo.examples) {
                            ch += `<button type="button" class="skill-cfg-example-btn" data-target="${escapeHtml(fieldName)}">${escapeHtml(ex)}</button>`;
                        }
                        ch += `</div>`;
                    }
                }
                ch += `</div>`;
            }
            // Spezieller Abschnitt fuer Image-Generation: per-Workflow Modell-Auswahl
            if (skill.skill_id === 'image_generation') {
                ch += `<div id="imagegen-workflow-models-section"></div>`;
            }
            // Spezieller Abschnitt fuer Video-Generation: ImageGen + Animation Config
            if (skill.skill_id === 'video_generation') {
                ch += `<div id="videogen-config-section"></div>`;
            }

            configContainer.innerHTML = ch;

            // Image-Generation: Workflow-Modell-Sektion laden
            if (skill.skill_id === 'image_generation') {
                _loadImagegenWorkflowModels(characterName);
            }
            // Video-Generation: Config-Sektion laden
            if (skill.skill_id === 'video_generation') {
                _loadVideoGenConfig(characterName);
            }

            // Wire example buttons (click to append into target field)
            for (const exBtn of configContainer.querySelectorAll('.skill-cfg-example-btn')) {
                exBtn.addEventListener('click', () => {
                    const target = configContainer.querySelector(`.skill-cfg-input[data-field="${exBtn.dataset.target}"]`);
                    if (target) {
                        const current = target.value.trim();
                        target.value = current ? current + ', ' + exBtn.textContent : exBtn.textContent;
                        target.focus();
                    }
                });
            }
        }

        // Wire skill item clicks (select to show config)
        for (const item of listContainer.querySelectorAll('.editor-skill-item')) {
            item.addEventListener('click', (e) => {
                // Don't trigger on checkbox click
                if (e.target.tagName === 'INPUT') return;
                showSkillConfig(item.dataset.skillId);
            });
        }
        // Wire checkbox toggle events
        for (const cb of listContainer.querySelectorAll('input[type="checkbox"]')) {
            cb.addEventListener('change', async (e) => {
                const skillId = e.target.dataset.skillId;
                const enabled = e.target.checked;
                try {
                    await fetch(`/characters/${encodeURIComponent(characterName)}/skills/${encodeURIComponent(skillId)}/enabled`, {
                        method: 'PUT',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ enabled })
                    });
                } catch (err) {
                    console.error('[Editor] Skill toggle error:', err);
                }
            });
        }
        // Auto-select first skill with config
        const firstWithConfig = skills.find(s => (s.config_fields && Object.keys(s.config_fields).length > 0) || _dynamicCfgSkills.includes(s.skill_id));
        if (firstWithConfig) showSkillConfig(firstWithConfig.skill_id);
    } catch (e) {
        console.warn('[Editor] Failed to load skills:', e);
        listContainer.innerHTML = '<p class="scheduler-empty">Skills konnten nicht geladen werden</p>';
    }
}

function calculateAge(dateStr) {
    if (!dateStr) return null;
    const birth = new Date(dateStr);
    if (isNaN(birth.getTime())) return null;
    const today = new Date();
    let age = today.getFullYear() - birth.getFullYear();
    const monthDiff = today.getMonth() - birth.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birth.getDate())) age--;
    return age >= 0 ? age : null;
}

function setupAppearancePreview(container, sections, appearanceKey, previewId) {
    const targetKey = appearanceKey || 'character_appearance';
    const targetPreviewId = previewId || 'appearance-preview';
    const appearanceEl = container.querySelector(`[data-key="${targetKey}"]`);
    const previewEl = document.getElementById(targetPreviewId);
    if (!appearanceEl || !previewEl) return;

    // Build replacement map from template: token -> {sourceKey, compute}
    const replacementDefs = {};
    if (sections) {
        for (const section of sections) {
            for (const field of (section.fields || [])) {
                const repl = field.replacement;
                if (!repl) continue;
                const targets = Array.isArray(repl.target) ? repl.target : [repl.target];
                if (!targets.includes(targetKey)) continue;
                const token = repl.token || field.key;
                replacementDefs[token] = { sourceKey: field.key, compute: repl.compute || null };
            }
        }
    }

    function computeAge(dateStr) {
        if (!dateStr) return null;
        const birth = new Date(dateStr);
        if (isNaN(birth.getTime())) return null;
        const today = new Date();
        let age = today.getFullYear() - birth.getFullYear();
        const m = today.getMonth() - birth.getMonth();
        if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
        return age >= 0 ? String(age) : null;
    }

    function updatePreview() {
        const raw = appearanceEl.value || '';
        if (!raw || !raw.includes('{')) {
            previewEl.style.display = 'none';
            return;
        }
        // Collect current values from all editor inputs
        const values = {};
        container.querySelectorAll('.editor-input').forEach(el => {
            if (el.dataset.key) values[el.dataset.key] = el.value || '';
        });

        const resolved = raw.replace(/\{(\w+)\}/g, (match, token) => {
            const def = replacementDefs[token];
            if (!def) return match; // not a configured replacement
            const rawVal = values[def.sourceKey] || '';
            if (!rawVal.trim() || rawVal === '__custom__') return match;
            if (def.compute === 'age') {
                const age = computeAge(rawVal);
                return age || match;
            }
            return rawVal;
        });

        if (resolved !== raw) {
            previewEl.textContent = tLabel({label: 'Preview', label_de: 'Vorschau'}) + ': ' + resolved;
            previewEl.style.display = 'block';
        } else {
            previewEl.style.display = 'none';
        }
    }

    // Listen on appearance field itself
    appearanceEl.addEventListener('input', updatePreview);
    // Delegated listeners on container so dynamically replaced inputs (allow_custom) also trigger updates
    container.addEventListener('input', (e) => {
        if (e.target.classList.contains('editor-input') && e.target !== appearanceEl) updatePreview();
    });
    container.addEventListener('change', (e) => {
        if (e.target.classList.contains('editor-input') && e.target !== appearanceEl) updatePreview();
    });
    // Initial render
    updatePreview();
}

/**
 * Set up visible_when reactivity for field-level and option-level visibility.
 * When a controlling field (e.g. gender) changes, dependent fields are shown/hidden
 * and select options are re-filtered.
 */
function setupVisibleWhen(container, sections, profile, charConfig, dynamicData) {
    // Collect all fields with visible_when (field-level or options with visible_when)
    const allFields = [];
    for (const section of sections) {
        for (const field of (section.fields || [])) {
            allFields.push(field);
        }
    }

    // Find which keys are controlling fields (referenced by visible_when)
    const controllingKeys = new Set();
    for (const section of sections) {
        // Section-level visible_when (z.B. retrospect_enabled steuert ganze Beliefs-Section)
        if (section.visible_when) controllingKeys.add(section.visible_when.field);
    }
    for (const field of allFields) {
        if (field.visible_when) controllingKeys.add(field.visible_when.field);
        if (field.options) {
            for (const opt of field.options) {
                if (opt.visible_when) controllingKeys.add(opt.visible_when.field);
            }
        }
    }
    if (controllingKeys.size === 0) return;

    // For each controlling key, attach a change listener
    for (const ctrlKey of controllingKeys) {
        const ctrlEl = container.querySelector(`.editor-input[data-key="${ctrlKey}"]`);
        if (!ctrlEl) continue;

        ctrlEl.addEventListener('change', () => {
            const newValue = ctrlEl.value;
            // Update profile data for option filtering
            profile[ctrlKey] = newValue;
            window._editorProfileData = profile;

            // Field-level visibility
            container.querySelectorAll('.editor-field[data-visible-when]').forEach(fieldEl => {
                try {
                    const vw = JSON.parse(fieldEl.dataset.visibleWhen);
                    if (vw.field === ctrlKey) {
                        fieldEl.style.display = (vw.values || []).includes(newValue) ? '' : 'none';
                    }
                } catch (e) { /* ignore parse errors */ }
            });

            // Section-level visibility (z.B. ganze Beliefs/Lessons-Section)
            container.querySelectorAll('.editor-section[data-section-visible-when]').forEach(secEl => {
                try {
                    const vw = JSON.parse(secEl.dataset.sectionVisibleWhen);
                    if (vw.field === ctrlKey) {
                        secEl.style.display = (vw.values || []).includes(newValue) ? '' : 'none';
                    }
                } catch (e) { /* ignore parse errors */ }
            });

            // Option-level visibility: re-render select/datalist options for fields with option-level visible_when
            for (const field of allFields) {
                if (!field.options || !field.options.some(o => o.visible_when && o.visible_when.field === ctrlKey)) continue;

                // allow_custom fields: if currently in custom-input mode, skip; otherwise re-filter select options
                if (field.allow_custom) {
                    const customWrap = container.querySelector(`.custom-input-wrap[data-key="${field.key}"]`);
                    if (customWrap) continue; // in custom text mode, nothing to re-filter
                }

                const selectEl = container.querySelector(`select.editor-input[data-key="${field.key}"]`);
                if (!selectEl) continue;
                const currentValue = selectEl.value;
                // Rebuild options
                let opts = '<option value="">-- Auswahl --</option>';
                for (const opt of field.options) {
                    if (opt.visible_when) {
                        const depValue = profile[opt.visible_when.field] || '';
                        if (!(opt.visible_when.values || []).includes(depValue)) continue;
                    }
                    const selected = String(opt.value) === String(currentValue) ? ' selected' : '';
                    opts += `<option value="${escapeHtml(String(opt.value))}"${selected}>${escapeHtml(tLabel(opt) || opt.label)}</option>`;
                }
                if (field.allow_custom) {
                    opts += `<option value="__custom__">✏ ${window._currentLang === 'de' ? 'Eigener Wert…' : 'Custom…'}</option>`;
                }
                selectEl.innerHTML = opts;
            }
        });
    }
}

/**
 * Set up allow_custom: when user selects "__custom__", replace select with text input.
 * Back-button returns to the select dropdown.
 */
function setupAllowCustom(container, sections, profile, charConfig, dynamicData) {
    const allFields = [];
    for (const section of sections) {
        for (const field of (section.fields || [])) {
            if (field.allow_custom) allFields.push(field);
        }
    }
    if (allFields.length === 0) return;

    container.addEventListener('change', (e) => {
        const selectEl = e.target.closest('select.editor-input');
        if (!selectEl || selectEl.value !== '__custom__') return;
        const key = selectEl.dataset.key;
        const field = allFields.find(f => f.key === key);
        if (!field) return;

        const store = field.store ? ` data-store="${field.store}"` : '';
        const wrap = document.createElement('div');
        wrap.className = 'custom-input-wrap';
        wrap.dataset.key = key;
        wrap.innerHTML = `<input type="text" class="agent-status-input editor-input editor-custom-input" data-key="${key}"${store} value="" placeholder="${window._currentLang === 'de' ? 'Eigenen Wert eingeben…' : 'Enter custom value…'}"><button type="button" class="custom-input-back" title="Back to dropdown">▼</button>`;
        selectEl.replaceWith(wrap);
        const inp = wrap.querySelector('input');
        inp.focus();
        // Trigger preview update so __custom__ sentinel is cleared
        inp.addEventListener('input', () => {
            inp.dispatchEvent(new Event('change', { bubbles: true }));
        });
        // Immediate preview refresh (clears __custom__ from preview)
        inp.dispatchEvent(new Event('input', { bubbles: true }));
    });

    container.addEventListener('click', (e) => {
        const btn = e.target.closest('.custom-input-back');
        if (!btn) return;
        const wrap = btn.closest('.custom-input-wrap');
        if (!wrap) return;
        const key = wrap.dataset.key;
        const field = allFields.find(f => f.key === key);
        if (!field) return;

        // Re-render as select with empty value
        const store = field.store ? ` data-store="${field.store}"` : '';
        const options = field.source && dynamicData ? (dynamicData[field.source] || []) : (field.options || []);
        let opts = '<option value="">-- ' + (window._currentLang === 'de' ? 'Auswahl' : 'Select') + ' --</option>';
        for (const opt of options) {
            if (opt.visible_when) {
                const depValue = profile[opt.visible_when.field] || '';
                if (!(opt.visible_when.values || []).includes(depValue)) continue;
            }
            opts += `<option value="${escapeHtml(String(opt.value))}">${escapeHtml(tLabel(opt) || opt.label)}</option>`;
        }
        opts += `<option value="__custom__">✏ ${window._currentLang === 'de' ? 'Eigener Wert…' : 'Custom…'}</option>`;
        const sel = document.createElement('select');
        sel.className = 'agent-status-input editor-input';
        sel.dataset.key = key;
        if (field.store) sel.dataset.store = field.store;
        sel.innerHTML = opts;
        wrap.replaceWith(sel);
    });
}

function renderEditorField(field, value, dynamicData) {
    const key = field.key;
    const store = field.store ? ` data-store="${field.store}"` : '';
    const escapedValue = escapeHtml(String(value ?? ''));
    const placeholder = field.placeholder ? ` placeholder="${escapeHtml(field.placeholder)}"` : '';

    // Readonly fields: show as disabled display
    if (field.readonly) {
        let displayValue = escapedValue;
        if (key === 'current_location' && value) {
            displayValue = escapeHtml(locationIdToName(value) || value);
        }
        return `<input type="text" class="agent-status-input editor-input editor-readonly" data-key="${key}"${store} value="${displayValue}" disabled>`;
    }

    switch (field.type) {
        case 'text':
            if (field.multiline) {
                return `<textarea class="agent-textarea editor-input" data-key="${key}"${store} rows="8"${placeholder}>${escapedValue}</textarea>`;
            }
            return `<input type="text" class="agent-status-input editor-input" data-key="${key}"${store} value="${escapedValue}"${placeholder}>`;

        case 'number':
            return `<input type="number" class="agent-status-input editor-input" data-key="${key}"${store} value="${escapedValue}">`;

        case 'date':
            return `<input type="date" class="agent-status-input editor-input" data-key="${key}"${store} value="${escapedValue}">`;

        case 'select': {
            // Grouped select for available_models (optgroup per provider)
            if (field.source === 'available_models' && dynamicData) {
                const groups = dynamicData.available_models || [];
                const defaultLabel = '-- Router-Default --';
                let opts = `<option value="">${escapeHtml(defaultLabel)}</option>`;
                for (const group of groups) {
                    opts += `<optgroup label="${escapeHtml(group.provider)}">`;
                    for (const m of group.models) {
                        // Match: exact "provider::model" or legacy "model" (without provider)
                        const modelOnly = m.value.includes('::') ? m.value.split('::').slice(1).join('::') : m.value;
                        const selected = (String(m.value) === String(value) || String(modelOnly) === String(value)) ? ' selected' : '';
                        opts += `<option value="${escapeHtml(m.value)}"${selected}>${escapeHtml(m.label)}</option>`;
                    }
                    opts += `</optgroup>`;
                }
                const totalModels = groups.reduce((sum, g) => sum + g.models.length, 0);
                const emptyHint = totalModels === 0
                    ? `<small class="editor-hint">${escapeHtml(t('No models available (check provider)'))}</small>` : '';
                return `<select class="agent-status-input editor-input" data-key="${key}"${store}>${opts}</select>${emptyHint}`;
            }
            // Standard flat select (static options or other dynamic sources)
            const options = field.source && dynamicData
                ? (dynamicData[field.source] || [])
                : (field.options || []);

            // allow_custom: select with a "Custom..." option that switches to text input
            if (field.allow_custom) {
                const isCustom = value && !options.some(o => String(o.value) === String(value));
                if (isCustom) {
                    // Current value is custom text – show text input with back-button
                    return `<div class="custom-input-wrap" data-key="${key}"><input type="text" class="agent-status-input editor-input editor-custom-input" data-key="${key}"${store} value="${escapedValue}"${placeholder}><button type="button" class="custom-input-back" title="Back to dropdown">▼</button></div>`;
                }
                let opts = '<option value="">-- ' + (window._currentLang === 'de' ? 'Auswahl' : 'Select') + ' --</option>';
                for (const opt of options) {
                    if (opt.visible_when) {
                        const depKey = opt.visible_when.field;
                        const depValue = window._editorProfileData ? (window._editorProfileData[depKey] || '') : '';
                        if (!(opt.visible_when.values || []).includes(depValue)) continue;
                    }
                    const sel = String(opt.value) === String(value) ? ' selected' : '';
                    opts += `<option value="${escapeHtml(String(opt.value))}"${sel}>${escapeHtml(tLabel(opt) || opt.label)}</option>`;
                }
                opts += `<option value="__custom__">✏ ${window._currentLang === 'de' ? 'Eigener Wert…' : 'Custom…'}</option>`;
                return `<select class="agent-status-input editor-input" data-key="${key}"${store}>${opts}</select>`;
            }

            let opts = '<option value="">-- Auswahl --</option>';
            for (const opt of options) {
                // Option-level visible_when: hide options not matching the controlling field
                if (opt.visible_when) {
                    const depKey = opt.visible_when.field;
                    const depValue = window._editorProfileData ? (window._editorProfileData[depKey] || '') : '';
                    if (!(opt.visible_when.values || []).includes(depValue)) continue;
                }
                const selected = String(opt.value) === String(value) ? ' selected' : '';
                opts += `<option value="${escapeHtml(String(opt.value))}"${selected}>${escapeHtml(tLabel(opt) || opt.label)}</option>`;
            }
            let emptyHint = '';
            if (field.source && options.length === 0) {
                emptyHint = `<small class="editor-hint">${escapeHtml(t('No entries available'))}</small>`;
            }
            return `<select class="agent-status-input editor-input" data-key="${key}"${store}>${opts}</select>${emptyHint}`;
        }

        case 'checkboxes': {
            let items = [];
            if (field.source === 'characters' && dynamicData) {
                items = (dynamicData.characters || []).map(c => ({ id: c, label: c }));
                if (dynamicData.user_name) items.push({ id: dynamicData.user_name, label: dynamicData.user_name + ' (Du)' });
            } else if (field.options) {
                items = field.options.map(o => typeof o === 'string' ? { id: o, label: o } : o);
            }
            const selected = Array.isArray(value) ? value : [];
            let cbHtml = `<div class="editor-checkboxes editor-input" data-key="${key}"${store}>`;
            for (const item of items) {
                const checked = selected.some(s => s.toLowerCase() === item.id.toLowerCase()) ? ' checked' : '';
                cbHtml += `<label class="editor-checkbox-label"><input type="checkbox" value="${escapeHtml(item.id)}"${checked}> ${escapeHtml(item.label)}</label>`;
            }
            cbHtml += `</div>`;
            return cbHtml;
        }

        case 'json': {
            let jsonStr = '';
            if (typeof value === 'string') {
                jsonStr = value;
            } else if (value !== '' && value !== null && value !== undefined) {
                try { jsonStr = JSON.stringify(value, null, 2); } catch (e) { jsonStr = String(value); }
            }
            return `<textarea class="agent-textarea editor-input" data-key="${key}"${store} rows="6"${placeholder}>${escapeHtml(jsonStr)}</textarea>`;
        }

        default:
            return `<input type="text" class="agent-status-input editor-input" data-key="${key}"${store} value="${escapedValue}"${placeholder}>`;
    }
}

function renderReadinessBadges(capabilities, container) {
    // capabilities: {key: {ready, missing[], label}, ...}
    let html = '';
    for (const [key, info] of Object.entries(capabilities || {})) {
        const ready = info.ready;
        const label = info.label || key;
        const icon = ready ? '&#10003;' : '&#10007;';
        const cls = ready ? 'readiness-ok' : 'readiness-missing';
        const missingLabels = (info.missing || [])
            .map(m => m.label || m.key || m)
            .join('\n• ');
        const title = ready
            ? `${label}: bereit`
            : `${label}: fehlt:\n• ${missingLabels}`;
        html += `<span class="readiness-badge ${cls}" title="${escapeHtml(title)}">${icon} ${escapeHtml(label)}</span>`;
    }
    container.innerHTML = html;
}

