async function saveCharacterEditor() {
    const characterName = getEditorCharacterName();
    if (!characterName || characterName === 'KI') return;

    const profileFields = {};
    const configFields = {};

    document.querySelectorAll('#editor-sections .editor-input').forEach(el => {
        const key = el.dataset.key;
        if (!key) return;

        let value;
        // Checkboxes type: collect checked values as array
        if (el.classList.contains('editor-checkboxes')) {
            value = Array.from(el.querySelectorAll('input[type="checkbox"]:checked')).map(cb => cb.value);
        } else {
            value = el.value || '';
        }
        // Never save the __custom__ sentinel – treat as empty
        if (value === '__custom__') value = '';

        if (el.dataset.store === 'config') {
            // Boolean conversion
            if (value === 'true') value = true;
            else if (value === 'false') value = false;

            // JSON textarea parsing
            if (el.tagName === 'TEXTAREA' && typeof value === 'string' && value.trim().startsWith('[')) {
                try {
                    const parsed = JSON.parse(value);
                    if (Array.isArray(parsed) || typeof parsed === 'object') {
                        value = parsed;
                    }
                } catch (e) {
                    showStatusToast(t('Invalid JSON in') + ` "${key}"`, 'error');
                    return;
                }
            }
            configFields[key] = value;
        } else {
            profileFields[key] = value;
        }
    });

    try {
        const promises = [];
        if (Object.keys(profileFields).length > 0) {
            promises.push(
                fetch(`/characters/${encodeURIComponent(characterName)}/profile`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ fields: profileFields })
                })
            );
        }
        if (Object.keys(configFields).length > 0) {
            promises.push(
                fetch(`/characters/${encodeURIComponent(characterName)}/config`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ fields: configFields })
                })
            );
        }

        // Skill configs mitspeichern (falls Config-Panel offen)
        const skillCfgContainer = document.getElementById('editor-skills-config');
        const skillListContainer = document.getElementById('editor-skills-list');
        const activeSkillItem = skillListContainer ? skillListContainer.querySelector('.editor-skill-item.selected') : null;
        if (skillCfgContainer && activeSkillItem) {
            const activeSkillId = activeSkillItem.dataset.skillId;
            const cfgInputs = skillCfgContainer.querySelectorAll('.skill-cfg-input');
            // Location-Checkboxen auslesen
            const locContainers = skillCfgContainer.querySelectorAll('.skill-cfg-locations');
            if (cfgInputs.length > 0 || locContainers.length > 0) {
                const skillConfig = {};
                for (const input of cfgInputs) {
                    const field = input.dataset.field;
                    const type = input.dataset.type;
                    if (type === 'bool') skillConfig[field] = input.checked;
                    else if (type === 'int') skillConfig[field] = parseInt(input.value) || 0;
                    else if (type === 'float') skillConfig[field] = parseFloat(input.value) || 0;
                    else skillConfig[field] = input.value;
                }
                for (const locCont of locContainers) {
                    const field = locCont.dataset.field;
                    const checked = Array.from(locCont.querySelectorAll('input[type="checkbox"]:checked')).map(cb => cb.value);
                    skillConfig[field] = checked;
                }
                const enabledCb = skillListContainer.querySelector(`input[data-skill-id="${activeSkillId}"]`);
                if (enabledCb) skillConfig.enabled = enabledCb.checked;
                promises.push(
                    fetch(`/characters/${encodeURIComponent(characterName)}/skills/${encodeURIComponent(activeSkillId)}`, {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ config: skillConfig })
                    })
                );
            }
        }

        const responses = await Promise.all(promises);
        const allOk = responses.every(r => r.ok);

        if (allOk) {
            showStatusToast(t('Profile saved'), 'success');
            await loadKnownInfo();
            try {
                const readinessRes = await fetch(`/templates/readiness/${encodeURIComponent(characterName)}`);
                if (readinessRes.ok) {
                    const readinessData = await readinessRes.json();
                    const badgesContainer = document.getElementById('editor-readiness-badges');
                    if (badgesContainer) renderReadinessBadges(readinessData.capabilities || {}, badgesContainer);
                }
            } catch (e) { /* ignore */ }
        } else {
            showStatusToast(t('Save error'), 'error');
        }
    } catch (error) {
        console.error('[Editor] Save error:', error);
        showStatusToast(t('Save error'), 'error');
    }
}

function escapeHtml(str) {
    if (str == null) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

// Formatiert ein /workflows-Option-Label mit Cost, Target-Style und Verfuegbarkeit
// Beispiel: "ComfyUI: Z-Image — Cost 1.0 · Style: z_image" oder
//           "Together-Qwen — Cost 20 · Style: qwen · nicht verfuegbar"
function _formatImagegenOptionLabel(opt) {
    const base = opt.label || opt.name || '';
    const parts = [base];
    if (opt.cost != null) parts.push(`Cost ${opt.cost}`);
    if (opt.target_model) parts.push(`Style: ${opt.target_model}`);
    if (opt.available === false) parts.push(t('not available'));
    return parts.length > 1 ? `${parts[0]} — ${parts.slice(1).join(' · ')}` : base;
}

