// --- Gallery Panel (Drawer) ---

let galleryPanelOpen = false;
let _galleryActiveTab = null;     // null = User-Gallery, sonst Character-Name
let _galleryViewMode = 'grid';    // 'grid' | 'list'
let _galleryEntries = [];         // cached entries for detail navigation
let _galleryDetailIndex = -1;     // current index in detail view

function toggleGalleryPanel() {
    const panel = document.getElementById('gallery-panel');
    if (!panel) return;

    galleryPanelOpen = !galleryPanelOpen;

    if (galleryPanelOpen) {
        panel.style.display = 'flex';
        _restorePanelWidth('gallery-panel');
        // Aktuellen Character vorauswaehlen, falls vorhanden
        if (_galleryActiveTab === null && currentCharacterName && currentCharacterName !== 'KI') {
            _galleryActiveTab = currentCharacterName;
        }
        _buildGalleryTabs();
        _reloadCurrentGallery();
    } else {
        panel.style.display = 'none';
    }
}

function setGalleryView(mode) {
    _galleryViewMode = mode;
    document.querySelectorAll('.gallery-view-btn').forEach(b =>
        b.classList.toggle('active', b.dataset.view === mode));
    _reloadCurrentGallery();
}

// Reusable: rendert einen Custom-Dropdown mit Avatar+Name pro Eintrag
// in den uebergebenen Container. options = [{name, avatarUrl}].
function _renderCharacterSelector(containerEl, options, currentValue, onChange) {
    if (!containerEl) return;
    containerEl.innerHTML = '';
    const wrap = document.createElement('div');
    wrap.className = 'char-select';
    const trigger = document.createElement('button');
    trigger.type = 'button';
    trigger.className = 'char-select-trigger';
    const dropdown = document.createElement('div');
    dropdown.className = 'char-select-dropdown';
    dropdown.style.display = 'none';

    const renderTrigger = (val) => {
        const found = options.find(o => o.name === val) || options[0] || null;
        trigger.innerHTML = '';
        if (!found) {
            const span = document.createElement('span');
            span.className = 'char-select-trigger-name';
            span.textContent = '—';
            trigger.appendChild(span);
            return;
        }
        const img = document.createElement('img');
        img.src = found.avatarUrl || generateDefaultAvatar(found.name);
        img.alt = found.name;
        img.onerror = function() { this.src = generateDefaultAvatar(found.name); };
        const span = document.createElement('span');
        span.className = 'char-select-trigger-name';
        span.textContent = found.name;
        const arrow = document.createElement('span');
        arrow.className = 'char-select-trigger-arrow';
        arrow.textContent = '▾';
        trigger.appendChild(img);
        trigger.appendChild(span);
        trigger.appendChild(arrow);
    };

    const renderOptions = (val) => {
        dropdown.innerHTML = '';
        for (const opt of options) {
            const row = document.createElement('div');
            row.className = 'char-select-option' + (opt.name === val ? ' active' : '');
            const img = document.createElement('img');
            img.src = opt.avatarUrl || generateDefaultAvatar(opt.name);
            img.alt = opt.name;
            img.onerror = function() { this.src = generateDefaultAvatar(opt.name); };
            const span = document.createElement('span');
            span.textContent = opt.name;
            row.appendChild(img);
            row.appendChild(span);
            row.addEventListener('click', (e) => {
                e.stopPropagation();
                renderTrigger(opt.name);
                renderOptions(opt.name);
                dropdown.style.display = 'none';
                if (typeof onChange === 'function') onChange(opt.name);
            });
            dropdown.appendChild(row);
        }
    };

    trigger.addEventListener('click', (e) => {
        e.stopPropagation();
        const open = dropdown.style.display === 'none';
        dropdown.style.display = open ? 'block' : 'none';
    });
    const closeOnOutside = (e) => {
        if (!wrap.contains(e.target)) dropdown.style.display = 'none';
    };
    document.addEventListener('click', closeOnOutside);

    renderTrigger(currentValue);
    renderOptions(currentValue);
    wrap.appendChild(trigger);
    wrap.appendChild(dropdown);
    containerEl.appendChild(wrap);
}

// Sammelt die Charakter-Optionen fuer Gallery + Diary: Avatar (Player),
// aktueller Chat-Partner (oder Group-Teilnehmer) + restliche bekannte
// Characters. Avatar-URL aus den jeweiligen DOM-Quellen (kein Refetch).
function _buildCharacterSelectorOptions() {
    const _playerName = getPlayerCharacterName();
    const _shown = new Set();
    const out = [];
    const _addOpt = (name, avatarUrl) => {
        // Defensiv: leere/undefined Namen filtern (sonst erscheint
        // "undefined" als Character — passierte z.B. wenn _groupSession
        // String-Participants statt Objekte enthielt).
        const _n = (name || '').toString().trim();
        if (!_n || _shown.has(_n)) return;
        out.push({ name: _n, avatarUrl: avatarUrl || '' });
        _shown.add(_n);
    };
    if (_playerName) {
        const _playerImg = document.getElementById('player-profile-image');
        _addOpt(_playerName, (_playerImg && _playerImg.src) || '');
    }
    if (chatMode === 'group' && _groupSession) {
        for (const p of (_groupSession.participants || [])) {
            // Participants koennen Strings ODER {name, avatar_url}-Objekte sein
            if (typeof p === 'string') {
                _addOpt(p, '');
            } else if (p && typeof p === 'object') {
                _addOpt(p.name, p.avatar_url);
            }
        }
    } else {
        if (currentCharacterName && currentCharacterName !== 'KI') {
            const profileImg = document.getElementById('agent-profile-image');
            _addOpt(currentCharacterName, (profileImg && profileImg.src) || '');
        }
    }
    if (window.availableOtherCharacters) {
        for (const name of window.availableOtherCharacters) {
            _addOpt(name, '');
        }
    }
    return out;
}

function _createGalleryCharButton(name, avatarUrl, isActive) {
    const btn = document.createElement('button');
    btn.className = 'gallery-char-btn' + (isActive ? ' active' : '');
    const img = document.createElement('img');
    img.src = avatarUrl || generateDefaultAvatar(name);
    img.alt = name;
    img.onerror = function() { this.src = generateDefaultAvatar(name); };
    const span = document.createElement('span');
    span.textContent = name;
    btn.appendChild(img);
    btn.appendChild(span);
    btn.addEventListener('click', () => _switchGalleryTab(name));
    return btn;
}

function _buildGalleryTabs() {
    const container = document.getElementById('gallery-tabs');
    if (!container) return;
    container.innerHTML = '';

    const allOptions = _buildCharacterSelectorOptions();
    const _playerName = getPlayerCharacterName();
    const avatarOpt = allOptions.find(o => o.name === _playerName) || null;
    const _agentName = (currentCharacterName && currentCharacterName !== 'KI')
        ? currentCharacterName : '';
    const agentOpt = (_agentName && _agentName !== _playerName)
        ? (allOptions.find(o => o.name === _agentName) || null)
        : null;

    // Default: Avatar; falls Active-Tab nicht (mehr) verfuegbar -> auf Avatar zurueck
    if (_galleryActiveTab === null && avatarOpt) {
        _galleryActiveTab = avatarOpt.name;
    }
    if (_galleryActiveTab !== null && !allOptions.find(o => o.name === _galleryActiveTab)) {
        _galleryActiveTab = (avatarOpt && avatarOpt.name)
            || (allOptions[0] && allOptions[0].name) || null;
    }

    // Reihenfolge: Avatar-Button, Agent-Button, Dropdown mit Rest
    if (avatarOpt) {
        container.appendChild(_createGalleryCharButton(
            avatarOpt.name, avatarOpt.avatarUrl,
            _galleryActiveTab === avatarOpt.name));
    }
    if (agentOpt) {
        container.appendChild(_createGalleryCharButton(
            agentOpt.name, agentOpt.avatarUrl,
            _galleryActiveTab === agentOpt.name));
    }

    const fixedNames = new Set([avatarOpt && avatarOpt.name, agentOpt && agentOpt.name]
        .filter(Boolean));
    const remaining = allOptions.filter(o => !fixedNames.has(o.name));
    if (remaining.length) {
        const ddWrap = document.createElement('div');
        ddWrap.style.display = 'inline-block';
        // Dropdown zeigt aktuell-aktiven Eintrag wenn er in der Restliste ist,
        // sonst ersten Eintrag (kein Active-Highlight am Trigger).
        const inDropdown = remaining.find(o => o.name === _galleryActiveTab);
        const triggerValue = inDropdown ? _galleryActiveTab : remaining[0].name;
        _renderCharacterSelector(ddWrap, remaining, triggerValue,
            (name) => _switchGalleryTab(name));
        container.appendChild(ddWrap);
    }
}

function _switchGalleryTab(tabName) {
    _galleryActiveTab = tabName;
    _buildGalleryTabs();      // Active-State auf Buttons aktualisieren
    _reloadCurrentGallery();
}

function _reloadCurrentGallery() {
    // All tabs are character tabs now (no separate user gallery)
    const tab = _galleryActiveTab || getPlayerCharacterName();
    if (tab) {
        _loadCharacterGallery(tab);
    }
}

// --- Time Grouping ---

function _getTimeGroupLabel(dateStr) {
    if (!dateStr) return t('Older');
    const date = new Date(dateStr);
    const now = new Date();
    const diffMs = now - date;
    const diffDays = Math.floor(diffMs / 86400000);
    if (diffDays === 0) return 'Heute';
    if (diffDays === 1) return 'Gestern';
    if (diffDays < 7) return 'Diese Woche';
    if (diffDays < 30) return 'Diesen Monat';
    return date.toLocaleDateString('de-DE', { month: 'long', year: 'numeric' });
}

function _groupEntriesByDate(entries) {
    const groups = {};
    const order = [];
    for (const entry of entries) {
        const created = entry.meta?.created_at || null;
        const label = _getTimeGroupLabel(created);
        if (!groups[label]) {
            groups[label] = [];
            order.push(label);
        }
        groups[label].push(entry);
    }
    // Sort groups: fixed labels first (newest→oldest), then month labels newest first, "Älter" last
    const fixedOrder = ['Heute', 'Gestern', 'Diese Woche', 'Diesen Monat'];
    order.sort((a, b) => {
        const ai = fixedOrder.indexOf(a);
        const bi = fixedOrder.indexOf(b);
        if (a === t('Older')) return 1;
        if (b === t('Older')) return -1;
        if (ai >= 0 && bi >= 0) return ai - bi;
        if (ai >= 0) return -1;
        if (bi >= 0) return 1;
        // Both are month labels like "März 2026" — sort descending
        return b.localeCompare(a);
    });
    return { groups, order };
}

// --- Metadata HTML Builder ---

function _buildMetaTableHtml(meta, truncateAnalysis) {
    const rows = [];
    if (meta.location_name) rows.push(`<tr><td class="git-label">Ort</td><td class="git-value">${escapeHtml(meta.location_name)}</td></tr>`);
    if (meta.model) rows.push(`<tr><td class="git-label">Model</td><td class="git-value">${escapeHtml(meta.model)}</td></tr>`);
    if (meta.loras && meta.loras.length) {
        const loraStrs = meta.loras.map(l => typeof l === 'object' ? `${l.name || '?'} (${l.strength ?? 1})` : String(l)).filter(s => !s.startsWith('None'));
        if (loraStrs.length) rows.push(`<tr><td class="git-label">LoRAs</td><td class="git-value">${escapeHtml(loraStrs.join(', '))}</td></tr>`);
    }
    if (meta.backend) rows.push(`<tr><td class="git-label">Backend</td><td class="git-value">${escapeHtml(meta.backend)}</td></tr>`);
    if (meta.workflow) rows.push(`<tr><td class="git-label">Workflow</td><td class="git-value">${escapeHtml(meta.workflow)}</td></tr>`);
    if (meta.guidance_scale != null && meta.guidance_scale !== '') rows.push(`<tr><td class="git-label">Guidance Scale</td><td class="git-value">${escapeHtml(String(meta.guidance_scale))}</td></tr>`);
    if (meta.num_inference_steps != null && meta.num_inference_steps !== '') rows.push(`<tr><td class="git-label">Inference Steps</td><td class="git-value">${escapeHtml(String(meta.num_inference_steps))}</td></tr>`);
    if (meta.faceswap !== undefined) {
        // Methoden-Label: multiswap (Flux MultiSwap) | comfyui (ReActor) | internal (Face Service)
        const _methodMap = { multiswap: 'MultiSwap', comfyui: 'ComfyUI ReActor', internal: 'Face Service' };
        const _m = meta.faceswap_method ? (_methodMap[meta.faceswap_method] || meta.faceswap_method) : '';
        const _icon = meta.faceswap ? '\u2714' : '\u2718';
        const _status = meta.faceswap ? t('successful') : t('failed');
        const _fallback = meta.faceswap_fallback ? ' (Fallback)' : '';
        const _val = _m
            ? `${_icon} ${_m}${_fallback} \u2014 ${_status}`
            : `${_icon} ${_status}`;
        rows.push(`<tr><td class="git-label">FaceSwap</td><td class="git-value">${escapeHtml(_val)}</td></tr>`);
    }
    if (meta.face_enhance !== undefined) {
        const _icon = meta.face_enhance ? '\u2714' : '\u2718';
        const _status = meta.face_enhance ? 'GFPGAN erfolgreich' : 'nicht angewendet';
        rows.push(`<tr><td class="git-label">FaceEnhance</td><td class="git-value">${_icon} ${escapeHtml(_status)}</td></tr>`);
    }
    if (meta.duration_s) rows.push(`<tr><td class="git-label">Dauer</td><td class="git-value">${meta.duration_s}s</td></tr>`);
    if (meta.seed !== undefined && meta.seed !== null) rows.push(`<tr><td class="git-label">Seed</td><td class="git-value">${meta.seed}</td></tr>`);
    if (meta.created_at) rows.push(`<tr><td class="git-label">Erstellt</td><td class="git-value">${escapeHtml(meta.created_at.replace('T', ' '))}</td></tr>`);
    if (meta.character_names && meta.character_names.length) rows.push(`<tr><td class="git-label">Personen</td><td class="git-value">${escapeHtml(meta.character_names.join(', '))}</td></tr>`);
    if (meta.sent_by) rows.push(`<tr><td class="git-label">Von</td><td class="git-value">${escapeHtml(meta.sent_by)}</td></tr>`);
    if (meta.from_character) rows.push(`<tr><td class="git-label">Erstellt von</td><td class="git-value">${escapeHtml(meta.from_character)}</td></tr>`);
    if (meta.image_analysis) {
        let txt = meta.image_analysis;
        if (truncateAnalysis && txt.length > 200) txt = txt.substring(0, 200) + '\u2026';
        rows.push(`<tr><td colspan="2" class="git-analysis">${escapeHtml(txt)}</td></tr>`);
    }
    return `<table class="git-table">${rows.join('')}</table>`;
}

// --- User Gallery ---

async function _loadUserGallery() {
    const gallery = document.getElementById('gallery-images');
    if (!gallery) return;
    gallery.innerHTML = `<p class="gallery-empty">${escapeHtml(t('Loading…'))}</p>`;

    try {
        const resp = await fetch(`/user/gallery`);
        if (!resp.ok) throw new Error('Error loading');
        const data = await resp.json();
        const images = data.images || [];
        const metadata = data.image_metadata || {};
        const comments = data.image_comments || {};

        if (images.length === 0) {
            gallery.innerHTML = '<p class="gallery-empty">Noch keine Bilder vorhanden</p>';
            _galleryEntries = [];
            return;
        }

        _galleryEntries = images.map(imageName => ({
            type: 'user',
            characterName: null,
            imageName,
            imageUrl: `/user/gallery/${imageName}`,
            videoUrl: '',
            isProfile: false,
            meta: metadata[imageName] || null,
            comment: comments[imageName] || '',
            prompt: '',
        }));

        _renderGalleryEntries(_galleryEntries, gallery);
    } catch (e) {
        gallery.innerHTML = `<p class="gallery-empty">${escapeHtml(t('Error loading'))}</p>`;
        console.error('[UserGallery]', e);
    }
}

// --- Character Gallery ---

async function _loadCharacterGallery(characterName) {
    const gallery = document.getElementById('gallery-images');
    if (!gallery) return;
    gallery.innerHTML = `<p class="gallery-empty">${escapeHtml(t('Loading…'))}</p>`;

    try {
        const resp = await fetch(`/characters/${characterName}/images`);
        if (!resp.ok) throw new Error('Error loading');
        const data = await resp.json();
        const images = data.images || [];
        const imgMeta = data.image_metadata || {};
        const imgVideos = data.image_videos || {};
        const imgComments = data.image_comments || {};
        const imgPrompts = data.image_prompts || {};

        if (images.length === 0) {
            gallery.innerHTML = '<p class="gallery-empty">Noch keine Bilder vorhanden</p>';
            _galleryEntries = [];
            return;
        }

        _galleryEntries = images.map(imageName => {
            const videoName = imgVideos[imageName] || '';
            const m = imgMeta[imageName] || null;
            // Cache-Bust pro Bild: wenn der Server eine regenerated_at oder
            // created_at Timestamp liefert, haengen wir den als ?v=... an die
            // URL. Bei Regenerierung aendert sich regenerated_at -> Browser
            // sieht eine neue URL und laedt frisch. Ohne diesen Trick zeigt
            // er das alte gecachte Bild bis F5/Cache-Loeschung.
            const _ver = encodeURIComponent((m && (m.regenerated_at || m.created_at)) || '');
            const _verSuffix = _ver ? `?v=${_ver}` : '';
            return {
                type: 'character',
                characterName,
                imageName,
                imageUrl: `/characters/${characterName}/images/${imageName}${_verSuffix}`,
                videoUrl: videoName ? `/characters/${characterName}/images/${videoName}${_verSuffix}` : '',
                isProfile: data.profile_image === imageName,
                meta: m,
                comment: imgComments[imageName] || '',
                prompt: imgPrompts[imageName] || '',
            };
        });

        _renderGalleryEntries(_galleryEntries, gallery);
    } catch (e) {
        gallery.innerHTML = `<p class="gallery-empty">${escapeHtml(t('Error loading'))}</p>`;
        console.error('[CharGallery]', e);
    }
}

// --- Render entries (grid or list) ---

function _renderGalleryEntries(entries, container) {
    container.innerHTML = '';
    const { groups, order } = _groupEntriesByDate(entries);

    if (_galleryViewMode === 'grid') {
        for (const label of order) {
            const groupEl = document.createElement('div');
            groupEl.className = 'gallery-time-group';
            groupEl.innerHTML = `<div class="gallery-time-group-label">${escapeHtml(label)}</div>`;
            const grid = document.createElement('div');
            grid.className = 'gallery-grid';

            for (const entry of groups[label]) {
                const idx = entries.indexOf(entry);
                const item = document.createElement('div');
                item.className = 'gallery-grid-item';
                const displayUrl = entry.videoUrl || entry.imageUrl;
                const isVideo = !!entry.videoUrl;

                if (isVideo) {
                    item.innerHTML = `<video src="${displayUrl}" muted loop playsinline></video><span class="gallery-grid-video-icon">\u25B6</span>`;
                } else {
                    item.innerHTML = `<img src="${entry.imageUrl}" alt="${entry.imageName}" loading="lazy">`;
                }

                if (entry.isProfile) {
                    item.innerHTML += '<span class="gallery-grid-badge">\u2605</span>';
                }
                if (entry.meta?.sent_by) {
                    item.innerHTML += `<span class="gallery-grid-sender">${escapeHtml(entry.meta.sent_by)}</span>`;
                }
                // Bild stammt von einem anderen Character (z.B. via Chat/Intent
                // an den Avatar gesendet) \u2014 schmaler Rand-Marker plus Tooltip
                if (entry.meta?.from_character) {
                    item.classList.add('gallery-grid-from-other');
                    item.title = `Erstellt von ${entry.meta.from_character}`;
                    item.innerHTML += `<span class="gallery-grid-from-character">${escapeHtml(entry.meta.from_character)}</span>`;
                }

                item.addEventListener('click', () => _openGalleryDetail(idx));
                grid.appendChild(item);
            }
            groupEl.appendChild(grid);
            container.appendChild(groupEl);
        }
    } else {
        // List view
        for (const label of order) {
            const groupEl = document.createElement('div');
            groupEl.className = 'gallery-time-group';
            groupEl.innerHTML = `<div class="gallery-time-group-label">${escapeHtml(label)}</div>`;

            for (const entry of groups[label]) {
                const idx = entries.indexOf(entry);
                const card = _renderListCard(entry, idx);
                groupEl.appendChild(card);
            }
            container.appendChild(groupEl);
        }
    }
}

function _renderListCard(entry, idx) {
    const card = document.createElement('div');
    card.className = 'gallery-list-card';

    const displayUrl = entry.videoUrl || entry.imageUrl;
    const isVideo = !!entry.videoUrl;
    const meta = entry.meta;

    // Sender label (User gallery)
    let senderHtml = '';
    if (entry.meta?.sent_by) {
        senderHtml = `<div class="gallery-list-card-sender">Von: ${escapeHtml(entry.meta.sent_by)}</div>`;
    }

    const mediaTag = isVideo
        ? `<video src="${displayUrl}" class="gallery-list-card-image" autoplay loop muted playsinline></video>`
        : `<img src="${entry.imageUrl}" alt="${entry.imageName}" class="gallery-list-card-image">`;

    let regenBtn = '', animBtn = '';
    if (entry.prompt) {
        regenBtn = `<button class="btn-regenerate" title="Bild neu generieren">&#128260;</button>`;
        const animTitle = isVideo ? 'Animation neu generieren' : 'Bild animieren';
        animBtn = `<button class="btn-animate" title="${animTitle}">&#127916;</button>`;
    }

    const charName = entry.characterName || '';
    const imgName = entry.imageName;

    card.innerHTML = `
        ${senderHtml}
        <div class="gallery-list-card-img-wrap">
            ${mediaTag}
            <div class="gallery-list-card-actions">
                <button class="btn-zoom" title="Vergroessern">\uD83D\uDD0D</button>
                ${regenBtn}
                ${animBtn}
                ${(entry.type === 'character' && !entry.isProfile) ? `<button class="btn-profile" title="Als Profil setzen">\uD83D\uDC64</button>` : ''}
                <button class="btn-delete" title="Loeschen">\uD83D\uDDD1\uFE0F</button>
            </div>
            ${entry.isProfile ? '<div class="gallery-list-card-badge">Profil</div>' : ''}
        </div>
        ${entry.comment ? `<div class="gallery-list-card-comment-wrap"><div class="gallery-list-card-comment">${escapeHtml(entry.comment)}</div></div>` : ''}
    `;

    // Event listeners
    const mediaEl = card.querySelector('.gallery-list-card-image');
    mediaEl.addEventListener('click', () => _openGalleryDetail(idx));
    card.querySelector('.btn-zoom').addEventListener('click', () => _openGalleryDetail(idx));

    const regenBtnEl = card.querySelector('.btn-regenerate');
    if (regenBtnEl && charName) {
        const _regenMeta = meta ? { ...meta, prompt: entry.prompt } : (entry.prompt ? { prompt: entry.prompt } : null);
        regenBtnEl.addEventListener('click', () => regenerateImage(charName, imgName, card, _regenMeta));
    }
    const animBtnEl = card.querySelector('.btn-animate');
    if (animBtnEl && charName) {
        const animPrompt = (meta && meta.animate_prompt) || '';
        animBtnEl.addEventListener('click', () => animateGalleryImage(charName, imgName, entry.imageUrl, animPrompt, card));
    }
    const profBtn = card.querySelector('.btn-profile');
    if (profBtn && charName) {
        profBtn.addEventListener('click', () => setProfileImage(charName, imgName));
    }
    const delBtn = card.querySelector('.btn-delete');
    delBtn.addEventListener('click', () => {
        if (entry.type === 'user') {
            _deleteUserGalleryImage(imgName);
        } else {
            deleteImage(charName, imgName);
        }
    });

    return card;
}

// --- Gallery Detail Overlay (erweiterte Lightbox fuer Grid-Items) ---

function _openGalleryDetail(index) {
    if (index < 0 || index >= _galleryEntries.length) return;
    _galleryDetailIndex = index;
    _renderGalleryDetail();
}

function _renderGalleryDetail() {
    // Remove existing
    const existing = document.getElementById('gallery-detail-overlay');
    if (existing) existing.remove();

    const entry = _galleryEntries[_galleryDetailIndex];
    if (!entry) return;

    const displayUrl = entry.videoUrl || entry.imageUrl;
    const isVideo = !!entry.videoUrl;
    const meta = entry.meta;
    const charName = entry.characterName || '';

    const overlay = document.createElement('div');
    overlay.id = 'gallery-detail-overlay';
    overlay.className = 'gallery-detail-overlay';

    const mediaTag = isVideo
        ? `<video src="${displayUrl}" autoplay loop muted playsinline></video>`
        : `<img src="${entry.imageUrl}">`;

    // Nav buttons
    const hasPrev = _galleryDetailIndex > 0;
    const hasNext = _galleryDetailIndex < _galleryEntries.length - 1;
    const prevBtn = hasPrev ? `<button class="gallery-detail-nav prev" title="Vorheriges">&lsaquo;</button>` : '';
    const nextBtn = hasNext ? `<button class="gallery-detail-nav next" title="Naechstes">&rsaquo;</button>` : '';

    // Action buttons
    let actions = '';
    if (entry.type === 'character' && charName) {
        if (entry.prompt) {
            actions += `<button class="btn-regenerate">&#128260; Regenerieren</button>`;
            actions += `<button class="btn-animate">&#127916; Animieren</button>`;
        }
        if (isVideo) {
            actions += `<button class="btn-delete-animation">&#128465; Animation l\u00f6schen</button>`;
        }
        if (!entry.isProfile) {
            actions += `<button class="btn-profile">&#128100; Profil</button>`;
        }
    }
    actions += `<button class="btn-delete">&#128465; L\u00f6schen</button>`;

    // Sender info
    let senderHtml = '';
    if (entry.meta?.sent_by) {
        senderHtml = `<div class="gallery-detail-sender">Gesendet von: ${escapeHtml(entry.meta.sent_by)}</div>`;
    }

    // Metadata HTML fuer Sidebar
    let metaHtml = '';
    if (meta) {
        metaHtml = `<div class="gallery-detail-meta">${_buildMetaTableHtml(meta, false)}</div>`;
    }

    overlay.innerHTML = `
        <div class="gallery-detail-container">
            <div class="gallery-detail-media">
                <button class="gallery-detail-close">&times;</button>
                ${prevBtn}
                ${mediaTag}
                ${nextBtn}
            </div>
            <div class="gallery-detail-sidebar">
                ${senderHtml}
                ${metaHtml}
                ${entry.comment ? `<div class="gallery-detail-comment">${escapeHtml(entry.comment)}</div>` : ''}
                <div class="gallery-detail-actions">${actions}</div>
            </div>
        </div>
    `;

    document.body.appendChild(overlay);

    // Close
    const closeDetail = () => overlay.remove();
    overlay.querySelector('.gallery-detail-close').addEventListener('click', closeDetail);
    overlay.addEventListener('click', (e) => { if (e.target === overlay) closeDetail(); });

    // Navigation
    const prevBtnEl = overlay.querySelector('.gallery-detail-nav.prev');
    if (prevBtnEl) prevBtnEl.addEventListener('click', (e) => { e.stopPropagation(); _galleryDetailIndex--; _renderGalleryDetail(); });
    const nextBtnEl = overlay.querySelector('.gallery-detail-nav.next');
    if (nextBtnEl) nextBtnEl.addEventListener('click', (e) => { e.stopPropagation(); _galleryDetailIndex++; _renderGalleryDetail(); });

    // Keyboard navigation (nur wenn kein Dialog offen ist)
    const keyHandler = (e) => {
        if (document.querySelector('.caption-mode-overlay')) return;
        if (e.key === 'Escape') { closeDetail(); document.removeEventListener('keydown', keyHandler); }
        if (e.key === 'ArrowLeft' && _galleryDetailIndex > 0) { _galleryDetailIndex--; _renderGalleryDetail(); }
        if (e.key === 'ArrowRight' && _galleryDetailIndex < _galleryEntries.length - 1) { _galleryDetailIndex++; _renderGalleryDetail(); }
    };
    document.addEventListener('keydown', keyHandler);

    // Action listeners
    const regenBtn = overlay.querySelector('.btn-regenerate');
    if (regenBtn && charName) {
        const _regenMeta = meta ? { ...meta, prompt: entry.prompt } : { prompt: entry.prompt };
        regenBtn.addEventListener('click', () => { closeDetail(); regenerateImage(charName, entry.imageName, null, _regenMeta); });
    }
    const animBtn = overlay.querySelector('.btn-animate');
    if (animBtn && charName) {
        const animPrompt = (meta && meta.animate_prompt) || '';
        animBtn.addEventListener('click', () => { closeDetail(); animateGalleryImage(charName, entry.imageName, entry.imageUrl, animPrompt, null); });
    }
    const delAnimBtn = overlay.querySelector('.btn-delete-animation');
    if (delAnimBtn && charName) {
        delAnimBtn.addEventListener('click', async () => {
            if (!confirm('Animation wirklich l\u00f6schen? Das Bild bleibt erhalten.')) return;
            try {
                const resp = await fetch(`/characters/${encodeURIComponent(charName)}/images/${encodeURIComponent(entry.imageName)}/animation`, { method: 'DELETE' });
                if (!resp.ok) throw new Error('Delete failed');
                showStatusToast(t('Animation deleted'), 'success');
                // Video-URL entfernen und Detail neu rendern
                entry.videoUrl = '';
                if (entry.meta) { delete entry.meta.animate_prompt; delete entry.meta.animate_created_at; }
                _renderGalleryDetail();
            } catch (e) {
                showStatusToast(t('Could not delete animation'), 'error');
                console.error(e);
            }
        });
    }
    const profBtn = overlay.querySelector('.btn-profile');
    if (profBtn && charName) {
        profBtn.addEventListener('click', () => { closeDetail(); setProfileImage(charName, entry.imageName); });
    }
    const delBtn = overlay.querySelector('.btn-delete');
    delBtn.addEventListener('click', async () => {
        if (!confirm('Bild wirklich loeschen?')) return;
        try {
            let url;
            if (entry.type === 'user') {
                url = `/user/gallery/${entry.imageName}`;
            } else {
                url = `/characters/${charName}/images/${entry.imageName}`;
            }
            const resp = await fetch(url, { method: 'DELETE' });
            if (!resp.ok) throw new Error('Delete failed');
            showStatusToast(t('Image deleted'), 'success');

            // Aus Cache entfernen
            _galleryEntries.splice(_galleryDetailIndex, 1);
            // Gallery-Feed im Hintergrund aktualisieren
            const galleryEl = document.getElementById('gallery-images');
            if (galleryEl && _galleryEntries.length > 0) _renderGalleryEntries(_galleryEntries, galleryEl);

            if (_galleryEntries.length === 0) {
                closeDetail();
            } else {
                // Naechstes Bild zeigen (oder letztes wenn am Ende)
                if (_galleryDetailIndex >= _galleryEntries.length) _galleryDetailIndex = _galleryEntries.length - 1;
                _renderGalleryDetail();
            }
        } catch (e) {
            showStatusToast(t('Could not delete image'), 'error');
            console.error(e);
        }
    });

}

// --- Gallery Upload Handler ---

document.getElementById('gallery-image-upload')?.addEventListener('change', async function(event) {
    const file = event.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);

    try {
        let url;
        if (_galleryActiveTab === null) {
            // Upload to user gallery
            url = `/user/gallery`;
        } else {
            const characterName = _galleryActiveTab;
            if (!characterName || characterName === 'KI') {
                alert('Bitte waehle zuerst einen Character-Tab aus');
                return;
            }
            url = `/characters/${characterName}/images`;
        }

        const response = await fetch(url, { method: 'POST', body: formData });
        if (!response.ok) throw new Error('Upload failed');

        showStatusToast(t('Image uploaded'), 'success');
        _reloadCurrentGallery();
        await loadKnownInfo();
    } catch (error) {
        showStatusToast(t('Upload failed'), 'error');
        console.error('Error:', error);
    }

    event.target.value = '';
});

// --- Comment Save ---

const _commentSaveTimers = {};

function _debounceSaveGalleryComment(entry, comment) {
    const key = `${entry.type}/${entry.characterName || 'user'}/${entry.imageName}`;
    clearTimeout(_commentSaveTimers[key]);
    _commentSaveTimers[key] = setTimeout(() => _saveGalleryComment(entry, comment), 2000);
}

async function _saveGalleryComment(entry, comment) {
    try {
        let url;
        if (entry.type === 'user') {
            url = `/user/gallery/${entry.imageName}/comment`;
        } else {
            url = `/characters/${entry.characterName}/images/${entry.imageName}/comment`;
        }
        await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ comment }),
        });
        // Update cached entry
        entry.comment = comment;
    } catch (error) {
        showStatusToast(t('Could not save description'), 'error');
        console.error('Error:', error);
    }
}

// --- User Gallery Delete ---

async function _deleteUserGalleryImage(imageName) {
    if (!confirm('Bild wirklich loeschen?')) return;
    try {
        const resp = await fetch(`/user/gallery/${imageName}`, { method: 'DELETE' });
        if (!resp.ok) throw new Error('Delete failed');
        showStatusToast(t('Image deleted'), 'success');
        _reloadCurrentGallery();
    } catch (e) {
        showStatusToast(t('Could not delete image'), 'error');
        console.error(e);
    }
}

// --- Info Modal (shared) ---

function openImageInfoModal(imageName, tableHtml) {
    const existing = document.getElementById('image-info-modal');
    if (existing) existing.remove();

    const overlay = document.createElement('div');
    overlay.id = 'image-info-modal';
    overlay.className = 'image-info-modal-overlay';
    overlay.innerHTML = `
        <div class="image-info-modal-dialog">
            <div class="image-info-modal-header">
                <span class="image-info-modal-title">${escapeHtml(imageName)}</span>
                <button class="image-info-modal-close">&times;</button>
            </div>
            <div class="image-info-modal-body">${tableHtml}</div>
        </div>
    `;
    document.body.appendChild(overlay);

    const close = () => overlay.remove();
    overlay.querySelector('.image-info-modal-close').addEventListener('click', close);
    overlay.addEventListener('click', (e) => { if (e.target === overlay) close(); });
}

// --- Legacy compat wrappers ---

function saveImageComment(characterName, imageName, comment) {
    _saveGalleryComment({ type: 'character', characterName, imageName }, comment);
}

function debounceSaveImageComment(textarea, characterName, imageName) {
    const entry = { type: 'character', characterName, imageName };
    _debounceSaveGalleryComment(entry, textarea.value);
}

// Compat: loadGalleryImages used by regenerate/animate callbacks
async function loadGalleryImages(characterName) {
    if (galleryPanelOpen && _galleryActiveTab === characterName) {
        _reloadCurrentGallery();
    }
}

async function regenerateImage(characterName, imageName, cardElement, prevMeta) {
    // Textarea-Kommentar sichern bevor Regenerierung startet
    if (cardElement) {
        const textarea = cardElement.querySelector('.gallery-list-card-comment') || cardElement.querySelector('.gallery-card-comment');
        if (textarea && textarea.value.trim()) {
            try {
                await fetch(`/characters/${characterName}/images/${imageName}/comment`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ comment: textarea.value })
                });
            } catch (e) { /* ignore */ }
        }
    }

    // Characters aus gespeichertem Prompt erkennen
    let charData = null;
    try {
        const cdResp = await fetch(`/characters/${encodeURIComponent(characterName)}/images/${encodeURIComponent(imageName)}/detect-characters`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({  }),
        });
        if (cdResp.ok) charData = await cdResp.json();
    } catch (e) { console.warn('[CharDetect] Gallery detect failed:', e); }

    const result = await showRegenerateDialog(`Regenerieren: ${imageName}`, characterName, null, prevMeta, charData);
    if (result === null) return;

    const btn = cardElement ? cardElement.querySelector('.btn-regenerate') : null;
    if (btn) { btn.disabled = true; btn.textContent = '\u23F3'; btn.title = 'Regenerierung laeuft...'; }
    showStatusToast(t('Regenerating image…'), 'info');

    try {
        const body = {  };
        if (result.workflow) body.workflow = result.workflow;
        if (result.backend) body.backend = result.backend;
        if (result.loras) body.loras = result.loras;
        if (result.model_override) body.model_override = result.model_override;
        if (result.character_names) body.character_names = result.character_names;
        if (result.room_id) body.room_id = result.room_id;
        if (result.custom_prompt) body.custom_prompt = result.custom_prompt;
        if (result.negative_prompt) body.negative_prompt = result.negative_prompt;
        if (result.create_new) body.create_new = true;

        const response = await fetch(`/characters/${characterName}/images/${imageName}/regenerate`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body)
        });
        if (!response.ok) {
            const err = await response.json().catch(() => ({ detail: 'Unbekannter Fehler' }));
            throw new Error(err.detail || `HTTP ${response.status}`);
        }

        const resData = await response.json();
        showStatusToast(t('Regeneration started…'), 'info');

        if (resData.track_id) {
            const imgEl = cardElement ? (cardElement.querySelector('.gallery-list-card-image') || cardElement.querySelector('.gallery-card-image')) : null;
            _pollRegenTask(resData.track_id, () => {
                showStatusToast(t('Image regenerated successfully'), 'success');
                if (imgEl) imgEl.src = `/characters/${characterName}/images/${imageName}?t=${Date.now()}`;
                if (galleryPanelOpen) _reloadCurrentGallery();
                if (btn) { btn.disabled = false; btn.textContent = '\uD83D\uDD04'; btn.title = 'Bild regenerieren'; }
            }, (err) => {
                showStatusToast(t('Regeneration failed') + `: ${err}`, 'error');
                if (btn) { btn.disabled = false; btn.textContent = '\uD83D\uDD04'; btn.title = 'Bild regenerieren'; }
            });
        } else {
            if (btn) { btn.disabled = false; btn.textContent = '\uD83D\uDD04'; btn.title = 'Bild regenerieren'; }
        }
    } catch (error) {
        showStatusToast(t('Regeneration failed') + `: ${error.message}`, 'error');
        console.error('Regenerate error:', error);
        if (btn) { btn.disabled = false; btn.textContent = '\uD83D\uDD04'; btn.title = 'Bild regenerieren'; }
    }
}

