// --- Theme Management ---

async function loadTheme() {

    try {
        const response = await fetch(`/store/default/theme`);
        if (response.ok) {
            const data = await response.json();
            let theme = data.value || 'light';
            if (theme === 'default') theme = 'light';
            if (theme === 'minimal') theme = 'light';
            applyTheme(theme);
            document.getElementById('theme-select').value = theme;
        }
    } catch (e) {
        console.error('Failed to load theme:', e);
    }
}

function applyTheme(themeName) {
    const stylesheet = document.getElementById('theme-stylesheet');
    stylesheet.href = `/static/themes/${themeName}.css?v=${Date.now()}`;
}

// --- Tab Switching (Chat / Story) ---
function switchTab(tabName) {
    // Buttons aktualisieren
    document.querySelectorAll('.tab-btn').forEach(btn => {
        btn.classList.toggle('tab-active', btn.dataset.tab === tabName);
    });
    // Content-Bereiche umschalten (ohne Inhalt zu zerstoeren)
    document.querySelectorAll('.tab-content').forEach(content => {
        content.classList.remove('tab-content-active');
        content.style.display = 'none';
    });
    const active = document.getElementById('tab-' + tabName);
    if (active) {
        active.style.display = '';
        active.classList.add('tab-content-active');
    }
    // Story-Tab: Liste laden
    if (tabName === 'story') {
        loadStoryList();
    }
    // Story Dev-Tab: Models laden
    if (tabName === 'storydev') {
        storyDevLoadModels();
    }
    // Tabs that hide the chat-partner character (player-only context)
    const _hideCharTabs = ['worlddev', 'story', 'storydev'];
    const charFloat = document.querySelector('.header-character-float');
    const charScene = document.getElementById('character-scene');
    const _isHideCharTab = _hideCharTabs.includes(tabName);

    if (tabName === 'worlddev') {
        worldDevLoadModels();
        worldDevLoadSchemas();
        worldDevLoadLocations();
        worldDevLoadCharacters();
        worldDevLoadContextOptions();
    }

    // Im World-Dev-Modus alle Schwebe-Buttons (Phone, Weltkarte, Tagebuch,
    // Galerie, Events, Notifications, Story-Arc, Instagram) + die Avatar-
    // Scene (mit Garderobe/Inventar/Outfit-Lock-Buttons) ausblenden.
    // Die Agent-Scene wird via charScene.style.display unten gesteuert.
    const _floatBtnIds = [
        'btn-instagram', 'btn-gallery', 'btn-storyarc', 'btn-events',
        'btn-notifications', 'btn-phone-chat', 'btn-worldmap', 'btn-diary',
        'character-sidebar', 'player-scene',
    ];
    if (_isHideCharTab) {
        if (charFloat) charFloat.style.display = 'none';
        if (charScene) charScene.style.display = 'none';
        document.body.dataset.worlddev = '1';
        document.body.style.backgroundImage = '';
        _floatBtnIds.forEach(id => {
            const el = document.getElementById(id);
            if (el) el.style.display = 'none';
        });
    } else {
        if (charFloat) charFloat.style.display = '';
        if (charScene) charScene.style.display = '';
        delete document.body.dataset.worlddev;
        _floatBtnIds.forEach(id => {
            const el = document.getElementById(id);
            if (el) el.style.display = '';
        });
        // Hintergrundbild wiederherstellen — vom AVATAR (nicht Editor-Character),
        // sonst springt der Hintergrund zur Location des bearbeiteten NPCs.
        const _avatar = (typeof getPlayerCharacterName === 'function')
            ? getPlayerCharacterName() : '';
        if (_avatar) {
            fetch(`/characters/${encodeURIComponent(_avatar)}/current-location`)
                .then(r => r.ok ? r.json() : null)
                .then(d => { if (d) updateLocationBackground(d.current_location_id || d.current_location || '', d.current_room || ''); })
                .catch(() => {});
        }
    }
}

async function saveTheme(themeName) {

    try {
        await fetch(`/store/default/theme`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: themeName })
        });
    } catch (e) {
        console.error('Failed to save theme:', e);
    }
}

// Theme-Selector Event Listener
document.getElementById('theme-select').addEventListener('change', async (e) => {
    const selectedTheme = e.target.value;
    applyTheme(selectedTheme);
    await saveTheme(selectedTheme);
});

// --- Language Selector (Account-level setting) ---
// The supported-language list is loaded from /i18n/languages — single source
// of truth in shared/config/languages.json. No client-side duplicate.

let _LANGUAGES = [];

async function _fetchLanguages() {
    try {
        const res = await fetch('/i18n/languages');
        if (res.ok) {
            const data = await res.json();
            _LANGUAGES = data.languages || [];
        }
    } catch (e) {
        console.warn('Failed to load language list:', e);
    }
    return _LANGUAGES;
}

async function initLanguageSelector() {
    const sel = document.getElementById('language-select');
    if (!sel) return;
    if (!_LANGUAGES.length) await _fetchLanguages();
    sel.innerHTML = '';
    for (const lang of _LANGUAGES) {
        const opt = document.createElement('option');
        opt.value = lang.value;
        // Selector uses the localized native label when available (label_<uiLang>),
        // else the English label from languages.json.
        opt.textContent = lang[`label_${uiLang}`] || lang.label || lang.value;
        if (lang.value === (uiLang || 'de')) opt.selected = true;
        sel.appendChild(opt);
    }
    sel.addEventListener('change', async (e) => {
        const newLang = e.target.value;
        uiLang = newLang;
        localStorage.setItem('uiLang', newLang);
        await loadTranslations(newLang);
        applyTranslations();
        try { document.documentElement.setAttribute('lang', newLang || 'en'); } catch (_) {}
        try {
            await fetch(`/store/default/user_profile`, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({fields: {system_language: newLang}}),
            });
        } catch(e) { console.warn('Language save failed:', e); }
        const langName = (_LANGUAGES.find(l => l.value === newLang) || {}).label || newLang;
        showStatusToast(`${t('Language')}: ${langName}`, 'success');
    });
}

