// Editing-State: null = neuer Job, string = Job-ID wird bearbeitet
let editingJobId = null;

async function openSchedulerModal(targetCharacter) {
    const characterName = targetCharacter || currentCharacterName;
    if (!characterName || characterName === 'KI') {
        alert(t('Please choose an agent first'));
        return;
    }

    _modalCharacter = characterName;
    document.getElementById('scheduler-agent-name').textContent = characterName;
    document.getElementById('scheduler-modal').style.display = 'flex';

    // Formular verstecken und Reset beim Oeffnen
    cancelJobForm();

    // Cache invalidieren damit Orte/Aktivitaeten frisch geladen werden
    _cachedWorldLocations = null;

    // Tab auf "Aufgaben" zuruecksetzen
    switchSchedulerTab('jobs');

    await loadSchedulerJobs();
}

function closeSchedulerModal() {
    document.getElementById('scheduler-modal').style.display = 'none';
    cancelJobForm();
}

// Scheduler-Modal: NICHT schliessen bei Klick ausserhalb
// Nur ueber den X-Button im Header schliessbar

// Backspace in allen Modals abfangen (nicht schliessen)
document.addEventListener('keydown', (e) => {
    const schedulerModal = document.getElementById('scheduler-modal');
    const characterModal = document.getElementById('agent-modal');
    // world-modal entfernt — der Welt-Editor lebt jetzt im Game-Admin-Modal.
    const gameAdminModal = document.getElementById('game-admin-modal');

    const isModalOpen =
        (schedulerModal && schedulerModal.style.display === 'flex') ||
        (characterModal && characterModal.style.display === 'flex') ||
        (gameAdminModal && gameAdminModal.style.display === 'flex');
    
    if (isModalOpen) {
        // Backspace nur verhindern wenn kein Input/Textarea fokussiert ist
        if (e.key === 'Backspace') {
            const active = document.activeElement;
            const isInput = active && (active.tagName === 'INPUT' || active.tagName === 'TEXTAREA' || active.tagName === 'SELECT');
            if (!isInput) {
                e.preventDefault();
            }
        }
    }
});

function toggleJobForm() {
    const form = document.getElementById('scheduler-job-form');
    const placeholder = document.getElementById('scheduler-editor-placeholder');
    const isVisible = form.style.display !== 'none';

    if (isVisible) {
        cancelJobForm();
    } else {
        // Neuer Job Modus
        editingJobId = null;
        resetJobForm();
        document.getElementById('job-form-title').textContent = 'Neuer Job';
        document.getElementById('btn-job-submit').textContent = 'Job erstellen';
        document.getElementById('btn-toggle-job-form').textContent = 'Abbrechen';
        form.style.display = 'block';
        if (placeholder) placeholder.style.display = 'none';
    }
}

function cancelJobForm() {
    editingJobId = null;
    const form = document.getElementById('scheduler-job-form');
    if (form) form.style.display = 'none';
    const placeholder = document.getElementById('scheduler-editor-placeholder');
    if (placeholder) placeholder.style.display = 'block';
    const toggleBtn = document.getElementById('btn-toggle-job-form');
    if (toggleBtn) toggleBtn.textContent = '+ Neuer Job';
    resetJobForm();
}

function resetJobForm() {
    // Trigger zuruecksetzen
    const triggerType = document.getElementById('job-trigger-type');
    if (triggerType) triggerType.value = 'interval';
    updateTriggerFields();

    // Intervall-Defaults
    const ih = document.getElementById('job-interval-hours');
    const im = document.getElementById('job-interval-minutes');
    const is = document.getElementById('job-interval-seconds');
    if (ih) ih.value = '0';
    if (im) im.value = '30';
    if (is) is.value = '0';

    // Offset-Default
    const ro = document.getElementById('job-random-offset');
    if (ro) ro.value = '0';

    // Cron-Defaults
    const ch = document.getElementById('job-cron-hour');
    const cm = document.getElementById('job-cron-minute');
    const cd = document.getElementById('job-cron-dow');
    if (ch) ch.value = '8';
    if (cm) cm.value = '0';
    if (cd) cd.value = '*';

    // Datum-Default
    const now = new Date();
    now.setMinutes(now.getMinutes() + 60);
    const dd = document.getElementById('job-date-datetime');
    if (dd) dd.value = now.toISOString().slice(0, 16);

    // Action zuruecksetzen
    const actionType = document.getElementById('job-action-type');
    if (actionType) actionType.value = 'send_message';
    updateActionFields();

    // Felder leeren
    const msg = document.getElementById('job-message');
    const apiUrl = document.getElementById('job-api-url');
    const apiBody = document.getElementById('job-api-body');
    const apiMethod = document.getElementById('job-api-method');
    if (msg) msg.value = '';
    if (apiUrl) apiUrl.value = '';
    if (apiBody) apiBody.value = '';
    if (apiMethod) apiMethod.value = 'GET';

    // Extract-Felder zuruecksetzen
    const ef = document.getElementById('job-extract-folder');
    const ep = document.getElementById('job-extract-pattern');
    const es = document.getElementById('job-extract-subdirs');
    const eex = document.getElementById('job-extract-exclude');
    const epr = document.getElementById('job-extract-prompt');
    const em = document.getElementById('job-extract-model');
    if (ef) ef.value = '';
    if (ep) ep.value = '*.json';
    if (es) es.value = 'false';
    if (eex) eex.value = '';
    if (epr) epr.value = '';
    if (em) em.value = '';

}

function editSchedulerJob(jobDataJson) {
    const job = JSON.parse(decodeURIComponent(jobDataJson));
    editingJobId = job.id;

    // Formular oeffnen
    const form = document.getElementById('scheduler-job-form');
    const placeholder = document.getElementById('scheduler-editor-placeholder');
    form.style.display = 'block';
    if (placeholder) placeholder.style.display = 'none';
    document.getElementById('job-form-title').textContent = 'Job bearbeiten';
    document.getElementById('btn-job-submit').textContent = 'Speichern';
    document.getElementById('btn-toggle-job-form').textContent = 'Abbrechen';

    // Trigger befuellen
    const trigger = job.trigger || {};
    document.getElementById('job-trigger-type').value = trigger.type || 'interval';
    updateTriggerFields();

    if (trigger.type === 'interval') {
        document.getElementById('job-interval-hours').value = trigger.hours || 0;
        document.getElementById('job-interval-minutes').value = trigger.minutes || 0;
        document.getElementById('job-interval-seconds').value = trigger.seconds || 0;
    } else if (trigger.type === 'cron') {
        document.getElementById('job-cron-hour').value = trigger.hour ?? 8;
        document.getElementById('job-cron-minute').value = trigger.minute ?? 0;
        document.getElementById('job-cron-dow').value = trigger.day_of_week || '*';
    } else if (trigger.type === 'date') {
        document.getElementById('job-date-datetime').value = trigger.run_date || '';
    }

    // Random Offset befuellen
    const offsetEl = document.getElementById('job-random-offset');
    if (offsetEl) offsetEl.value = trigger.random_offset_minutes || 0;

    // Action befuellen
    const action = job.action || {};
    document.getElementById('job-action-type').value = action.type || 'send_message';
    updateActionFields();

    if (action.type === 'send_message') {
        document.getElementById('job-message').value = action.message || '';
    } else if (action.type === 'execute_tool') {
        document.getElementById('job-tool-name').value = action.tool_name || 'Instagram';
        document.getElementById('job-tool-input').value = action.tool_input || '';
    } else if (action.type === 'set_status') {
        // Dropdowns werden async befuellt, danach Werte setzen
        populateSchedulerLocationDropdown().then(() => {
            document.getElementById('job-status-location').value = action.location || '';
            onSchedulerLocationChange().then(() => {
                document.getElementById('job-status-activity').value = action.activity || '';
            });
        });
        document.getElementById('job-status-mood').value = action.mood || '';
    } else if (action.type === 'extract_files') {
        document.getElementById('job-extract-prompt').value = action.extraction_prompt || '';
    }

    form.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function updateTriggerFields() {
    const el = document.getElementById('job-trigger-type');
    if (!el) return;
    const type = el.value;
    const intervalEl = document.getElementById('trigger-interval-fields');
    const cronEl = document.getElementById('trigger-cron-fields');
    const dateEl = document.getElementById('trigger-date-fields');
    const offsetEl = document.getElementById('trigger-offset-fields');
    if (intervalEl) intervalEl.style.display = type === 'interval' ? 'block' : 'none';
    if (cronEl) cronEl.style.display = type === 'cron' ? 'block' : 'none';
    if (dateEl) dateEl.style.display = type === 'date' ? 'block' : 'none';
    if (offsetEl) offsetEl.style.display = (type === 'interval' || type === 'cron') ? 'block' : 'none';
}

function updateActionFields() {
    const el = document.getElementById('job-action-type');
    if (!el) return;
    const type = el.value;
    const msgEl = document.getElementById('action-message-fields');
    const toolEl = document.getElementById('action-tool-fields');
    const statusEl = document.getElementById('action-status-fields');
    const extractEl = document.getElementById('action-extract-fields');
    if (msgEl) msgEl.style.display = type === 'send_message' ? 'block' : 'none';
    if (toolEl) toolEl.style.display = type === 'execute_tool' ? 'block' : 'none';
    if (statusEl) statusEl.style.display = type === 'set_status' ? 'block' : 'none';
    if (extractEl) extractEl.style.display = type === 'extract_files' ? 'block' : 'none';
    if (type === 'set_status') populateSchedulerLocationDropdown();
}

function describeTrigger(trigger) {
    const type = trigger.type;
    const offset = trigger.random_offset_minutes;
    const offsetStr = offset ? ` (\u00b1${offset}min)` : '';
    if (type === 'interval') {
        const parts = [];
        if (trigger.days) parts.push(`${trigger.days} Tage`);
        if (trigger.hours) parts.push(`${trigger.hours}h`);
        if (trigger.minutes) parts.push(`${trigger.minutes}min`);
        if (trigger.seconds) parts.push(`${trigger.seconds}s`);
        return `Alle ${parts.join(' ')}${offsetStr}`;
    } else if (type === 'cron') {
        const h = String(trigger.hour ?? 0).padStart(2, '0');
        const m = String(trigger.minute ?? 0).padStart(2, '0');
        const dow = trigger.day_of_week || '*';
        const dowLabel = {
            '*': 'Taeglich', 'mon-fri': 'Mo-Fr', 'sat,sun': 'Sa-So',
            'mon': 'Mo', 'tue': 'Di', 'wed': 'Mi', 'thu': 'Do',
            'fri': 'Fr', 'sat': 'Sa', 'sun': 'So'
        }[dow] || dow;
        return `${dowLabel} um ${h}:${m}${offsetStr}`;
    } else if (type === 'date') {
        const d = new Date(trigger.run_date);
        return `Einmalig: ${d.toLocaleDateString('de')} ${d.toLocaleTimeString('de', {hour:'2-digit', minute:'2-digit'})}`;
    }
    return type;
}

function describeAction(action) {
    if (action.type === 'send_message') {
        const msg = action.message || '';
        return msg.length > 80 ? msg.substring(0, 80) + '...' : msg;
    } else if (action.type === 'execute_tool') {
        const input = action.tool_input || '';
        const desc = input.length > 60 ? input.substring(0, 60) + '...' : input;
        return `${action.tool_name || 'Tool'}: ${desc}`;
    } else if (action.type === 'set_status') {
        const loc = action.location || '';
        const act = action.activity === '__random__' ? '🎲 Zufall' : (action.activity || '');
        const mood = action.mood || '';
        const parts = [];
        if (loc) parts.push(act ? `${loc} → ${act}` : loc);
        if (mood) parts.push(`😊 ${mood}`);
        return parts.join(', ') || 'Status';
    } else if (action.type === 'extract_files') {
        return action.extraction_prompt ? action.extraction_prompt.substring(0, 60) : 'Dateien lesen';
    }
    return action.type;
}

function triggerIcon(type) {
    if (type === 'interval') return '🔁';
    if (type === 'cron') return '📅';
    if (type === 'date') return '📌';
    return '⏱️';
}

function formatCreatedAt(isoStr) {
    if (!isoStr) return '';
    try {
        const d = new Date(isoStr);
        return d.toLocaleDateString('de', { day: '2-digit', month: '2-digit', year: '2-digit' }) +
               ' ' + d.toLocaleTimeString('de', { hour: '2-digit', minute: '2-digit' });
    } catch { return ''; }
}

async function loadSchedulerJobs() {
    const characterName = getEditorCharacterName();
    const listEl = document.getElementById('scheduler-jobs-list');

    try {
        const response = await fetch(`/scheduler/jobs?character=${encodeURIComponent(characterName)}`);
        if (!response.ok) throw new Error('Error loading jobs');

        const data = await response.json();
        const jobs = data.data || [];

        if (jobs.length === 0) {
            listEl.innerHTML = '<p class="scheduler-empty">Noch keine geplanten Aufgaben vorhanden.<br>Erstelle einen neuen Job mit dem Button oben.</p>';
            return;
        }

        const actionIcons = { 'send_message': '💬', 'execute_tool': '🔧', 'set_status': '📍', 'extract_files': '📂' };

        const rows = jobs.map(job => {
            const isDailyJob = job.source === 'daily_schedule';
            const jobJson = encodeURIComponent(JSON.stringify(job)).replace(/'/g, '%27');
            const icon = isDailyJob ? '🕐' : (actionIcons[job.action.type] || '⚙️');
            const actionDesc = isDailyJob
                ? `Tagesablauf: ${escapeHtml(describeAction(job.action))}`
                : escapeHtml(describeAction(job.action));
            // Letzte Ausfuehrung
            const le = job.last_execution;
            let lastExecHtml = '<span class="job-lastexec-none">—</span>';
            if (le && le.timestamp) {
                const d = new Date(le.timestamp);
                const pad = n => String(n).padStart(2, '0');
                const ts = `${pad(d.getDate())}.${pad(d.getMonth() + 1)}. ${pad(d.getHours())}:${pad(d.getMinutes())}`;
                const badge = le.success
                    ? '<span class="job-exec-ok" title="Erfolgreich">✓</span>'
                    : '<span class="job-exec-fail" title="Fehlgeschlagen">✗</span>';
                lastExecHtml = `${badge} ${ts}`;
            }
            return `<tr class="${job.enabled ? '' : 'job-inactive'}${isDailyJob ? ' job-daily' : ''}" title="${escapeHtml(describeAction(job.action))}">
                <td><span class="job-status-dot ${job.enabled ? 'dot-active' : 'dot-inactive'}"></span></td>
                <td class="job-trigger-cell">${triggerIcon(job.trigger.type)} ${describeTrigger(job.trigger)}</td>
                <td class="job-action-cell">${icon} ${actionDesc}</td>
                <td class="job-lastexec-cell">${lastExecHtml}</td>
                <td class="job-actions-cell">${isDailyJob ? `<button onclick="switchSchedulerTab('tagesablauf')" title="Im Tagesablauf bearbeiten">📋</button>` : `
                    <button onclick="runSchedulerJobNow('${job.id}')" title="Jetzt starten">▶</button>
                    <button onclick="editSchedulerJob('${jobJson}')" title="Bearbeiten">✏️</button>
                    <button onclick="toggleSchedulerJob('${job.id}')" title="${job.enabled ? 'Deaktivieren' : 'Aktivieren'}">${job.enabled ? '●' : '○'}</button>
                    <button onclick="deleteSchedulerJob('${job.id}')" title="Loeschen">🗑️</button>`}
                </td>
            </tr>`;
        }).join('');

        listEl.innerHTML = `<table class="scheduler-table">
            <thead><tr><th></th><th>Zeitplan</th><th>Aktion</th><th>Zuletzt</th><th></th></tr></thead>
            <tbody>${rows}</tbody>
        </table>`;

    } catch (error) {
        console.error('[Scheduler] Fehler:', error);
        listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading jobs'))}</p>`;
    }
}

function _buildJobPayload() {
    const triggerType = document.getElementById('job-trigger-type').value;
    const actionType = document.getElementById('job-action-type').value;

    // Trigger
    let trigger = { type: triggerType };
    if (triggerType === 'interval') {
        const hours = parseInt(document.getElementById('job-interval-hours').value) || 0;
        const minutes = parseInt(document.getElementById('job-interval-minutes').value) || 0;
        const seconds = parseInt(document.getElementById('job-interval-seconds').value) || 0;
        if (hours === 0 && minutes === 0 && seconds === 0) {
            showStatusToast(t('Please provide at least one interval'), 'error');
            return null;
        }
        trigger.hours = hours;
        trigger.minutes = minutes;
        trigger.seconds = seconds;
    } else if (triggerType === 'cron') {
        trigger.hour = parseInt(document.getElementById('job-cron-hour').value) || 0;
        trigger.minute = parseInt(document.getElementById('job-cron-minute').value) || 0;
        const dow = document.getElementById('job-cron-dow').value;
        if (dow !== '*') trigger.day_of_week = dow;
    } else if (triggerType === 'date') {
        const dt = document.getElementById('job-date-datetime').value;
        if (!dt) {
            showStatusToast(t('Please provide date and time'), 'error');
            return null;
        }
        trigger.run_date = dt;
    }

    // Random Offset (fuer interval und cron)
    if (triggerType === 'interval' || triggerType === 'cron') {
        const offset = parseInt(document.getElementById('job-random-offset').value) || 0;
        if (offset > 0) trigger.random_offset_minutes = offset;
    }

    // Action
    let action = { type: actionType };
    if (actionType === 'send_message') {
        const message = document.getElementById('job-message').value.trim();
        if (!message) {
            showStatusToast(t('Please enter a message'), 'error');
            return null;
        }
        action.message = message;
    } else if (actionType === 'execute_tool') {
        const toolName = document.getElementById('job-tool-name').value;
        const toolInput = document.getElementById('job-tool-input').value.trim();
        if (!toolInput) {
            showStatusToast(t('Please enter a tool input'), 'error');
            return null;
        }
        action.tool_name = toolName;
        action.tool_input = toolInput;
    } else if (actionType === 'set_status') {
        const location = document.getElementById('job-status-location').value;
        const activity = document.getElementById('job-status-activity').value;
        const mood = document.getElementById('job-status-mood').value.trim();
        if (!location) {
            showStatusToast(t('Please provide a location'), 'error');
            return null;
        }
        action.location = location;
        action.activity = activity;
        if (mood) action.mood = mood;
    } else if (actionType === 'extract_files') {
        const extractPrompt = document.getElementById('job-extract-prompt').value.trim();
        if (extractPrompt) action.extraction_prompt = extractPrompt;
    }

    return { trigger, action };
}

async function submitSchedulerJob() {
    const payload = _buildJobPayload();
    if (!payload) return;

    const characterName = getEditorCharacterName();

    try {
        // Bei Bearbeitung: alten Job loeschen
        if (editingJobId) {
            const delResp = await fetch(`/scheduler/jobs/${encodeURIComponent(editingJobId)}`, { method: 'DELETE' });
            if (!delResp.ok) {
                console.warn('[Scheduler] Alter Job konnte nicht geloescht werden');
            }
        }

        // Neuen Job erstellen
        const response = await fetch('/scheduler/jobs', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                character: characterName,
                trigger: payload.trigger,
                action: payload.action
            })
        });

        if (!response.ok) {
            const err = await response.json();
            throw new Error(err.detail || 'Fehler beim Speichern');
        }

        showStatusToast(editingJobId ? t('Job updated') : t('Job created'), 'success');
        cancelJobForm();
        await loadSchedulerJobs();

    } catch (error) {
        console.error('[Scheduler] Speichern fehlgeschlagen:', error);
        showStatusToast(t('Error') + ': ' + error.message, 'error');
    }
}

async function toggleSchedulerJob(jobId) {
    try {
        const response = await fetch(`/scheduler/jobs/${encodeURIComponent(jobId)}/toggle`, {
            method: 'PUT'
        });
        if (!response.ok) throw new Error('Toggle failed');

        const data = await response.json();
        showStatusToast(data.message, 'success');
        await loadSchedulerJobs();
    } catch (error) {
        console.error('[Scheduler] Toggle-Fehler:', error);
        showStatusToast(t('Toggle error'), 'error');
    }
}

async function deleteSchedulerJob(jobId) {
    if (!confirm('Job wirklich loeschen?')) return;

    try {
        const response = await fetch(`/scheduler/jobs/${encodeURIComponent(jobId)}`, {
            method: 'DELETE'
        });
        if (!response.ok) throw new Error('Delete failed');

        showStatusToast(t('Job deleted'), 'success');
        // Falls der geloeschte Job gerade bearbeitet wird, Formular schliessen
        if (editingJobId === jobId) cancelJobForm();
        await loadSchedulerJobs();
    } catch (error) {
        console.error('[Scheduler] Loeschen-Fehler:', error);
        showStatusToast(t('Delete error'), 'error');
    }
}

async function runSchedulerJobNow(jobId) {
    try {
        const response = await fetch(`/scheduler/jobs/${encodeURIComponent(jobId)}/run`, {
            method: 'POST'
        });
        if (!response.ok) throw new Error('Execution failed');

        showStatusToast(t('Job running'), 'success');
    } catch (error) {
        console.error('[Scheduler] Ausfuehrung-Fehler:', error);
        showStatusToast(t('Execution error'), 'error');
    }
}


// === TAGESABLAUF (Daily Schedule) ===

function switchSchedulerTab(tabName) {
    document.querySelectorAll('.scheduler-tab-btn').forEach(btn => {
        btn.classList.toggle('tab-active', btn.dataset.schedulerTab === tabName);
    });
    document.querySelectorAll('.scheduler-tab-content').forEach(el => {
        el.style.display = 'none';
    });
    const target = document.getElementById('scheduler-tab-' + tabName);
    if (target) target.style.display = '';

    if (tabName === 'tagesablauf') {
        loadDailySchedule();
    }
}

async function loadDailySchedule() {
    const character = getEditorCharacterName();
    if (!character || character === 'KI') return;

    try {
        const [schedResp, configResp] = await Promise.all([
            fetch(`/scheduler/daily-schedule?character=${encodeURIComponent(character)}`),
            fetch(`/characters/${encodeURIComponent(character)}/config`),
        ]);
        if (!schedResp.ok) throw new Error('Loading failed');
        const schedData = await schedResp.json();
        const schedule = schedData.schedule || { enabled: false, slots: [] };

        let roles = [];
        if (configResp.ok) {
            const cfgData = await configResp.json();
            const rawRoles = (cfgData.config || {}).roles || '';
            roles = String(rawRoles).split(',').map(r => r.trim()).filter(Boolean);
        }

        document.getElementById('tagesablauf-enabled').checked = schedule.enabled !== false;
        await renderDailyScheduleGrid(schedule.slots || [], roles);
    } catch (e) {
        console.error('[Tagesablauf] Fehler:', e);
        document.getElementById('tagesablauf-grid').innerHTML =
            `<p class="scheduler-empty">${escapeHtml(t('Error loading daily schedule'))}</p>`;
    }
}

// --- Tagesablauf: Drag-to-Paint Grid (Schritt 7, May 2026) ---
// Pro Stunde max. ein {location, role, sleep}. Location und Rolle sind
// UNABHAENGIG setzbar — eine Stunde kann Location ODER Rolle ODER beides
// oder nichts haben. Sleep ist exklusiv (schliesst Location+Rolle aus).
// Slot-Map ist die Quelle der Wahrheit; das Grid wird daraus gerendert.
// Leere Stunden = LLM waehlt selbst.
const _taDrag = { active: false, key: '', startH: -1, curH: -1 };
let _taSlots = {};                // Hour -> {location, role, sleep}
let _taIdToCanonical = {};        // Location-ID -> kanonische ID (Name-Dedup)
let _taRoles = [];                // Char-Rollen-Liste

async function renderDailyScheduleGrid(slots, roles) {
    const grid = document.getElementById('tagesablauf-grid');
    if (!grid) return;

    let locations = _cachedWorldLocations || await _fetchWorldLocations();
    const byName = new Map();
    _taIdToCanonical = {};
    for (const loc of locations || []) {
        const name = (loc.name || loc.id || '').trim();
        if (!name) continue;
        const id = loc.id || name;
        if (!byName.has(name)) byName.set(name, { id, name });
        _taIdToCanonical[id] = byName.get(name).id;
    }
    const uniqueLocs = Array.from(byName.values());
    _taRoles = (roles || []).filter(Boolean);

    // Slot-Map aufbauen
    _taSlots = {};
    for (const s of slots || []) {
        const sleep = !!s.sleep;
        const rawLoc = (s.location || '').trim();
        const canonical = sleep ? '' : (_taIdToCanonical[rawLoc] || rawLoc);
        _taSlots[s.hour] = {
            location: sleep ? '' : canonical,
            role: sleep ? '' : (s.role || '').trim(),
            sleep,
        };
    }

    _taRenderTable(grid, uniqueLocs);

    grid.addEventListener('mousedown', _taOnMouseDown);
    grid.addEventListener('mouseover', _taOnMouseOver);
    document.addEventListener('mouseup', _taOnMouseUp);
    grid.addEventListener('touchstart', _taOnTouchStart, { passive: false });
    grid.addEventListener('touchmove', _taOnTouchMove, { passive: false });
    document.addEventListener('touchend', _taOnMouseUp);
}

function _taRenderTable(grid, uniqueLocs) {
    let html = '<table class="tagesablauf-table"><thead><tr><th class="tagesablauf-corner"></th>';
    for (let h = 0; h < 24; h++) html += `<th>${String(h).padStart(2, '0')}</th>`;
    html += '</tr></thead><tbody>';

    // --- Sleep ---
    html += `<tr class="tagesablauf-loc-header tagesablauf-sleep-header"><td colspan="25">Schlafen <span class="tagesablauf-section-hint">(Hint — eigentlich entscheidet die Energie)</span></td></tr>`;
    html += _taBuildRow('sleep||', 'Schlafen', '');

    // --- Orte (jede Location eigene Zeile, unabhaengig setzbar) ---
    html += `<tr class="tagesablauf-loc-header"><td colspan="25">Orte <span class="tagesablauf-section-hint">(unabhaengig von der Rolle)</span></td></tr>`;
    if (uniqueLocs.length === 0) {
        html += `<tr><td colspan="25" class="scheduler-empty">Keine Orte in der Welt definiert.</td></tr>`;
    } else {
        for (const loc of uniqueLocs) {
            html += _taBuildRow(`loc|${loc.id}|`, loc.name, '');
        }
    }

    // --- Rollen (jede Rolle eigene Zeile, unabhaengig setzbar) ---
    html += `<tr class="tagesablauf-loc-header"><td colspan="25">Rollen <span class="tagesablauf-section-hint">(unabhaengig vom Ort)</span></td></tr>`;
    if (!_taRoles || _taRoles.length === 0) {
        html += `<tr><td colspan="25" class="scheduler-empty" style="padding:6px 8px;">Keine Rollen im Charakter-Profil definiert.</td></tr>`;
    } else {
        for (const role of _taRoles) {
            html += _taBuildRow(`role||${role}`, role, '');
        }
    }

    html += '</tbody></table>';
    grid.innerHTML = html;
}

function _taParseKey(key) {
    // Formate: "sleep||"  /  "loc|<id>|"  /  "role||<name>"
    const parts = key.split('|');
    return { kind: parts[0], loc: parts[1] || '', role: parts[2] || '' };
}

function _taSlotMatchesKey(slot, key) {
    if (!slot) return false;
    const k = _taParseKey(key);
    if (k.kind === 'sleep') return !!slot.sleep;
    if (slot.sleep) return false;  // sleep schliesst Location/Rolle aus
    if (k.kind === 'loc')  return slot.location === k.loc;
    if (k.kind === 'role') return (slot.role || '') === k.role;
    return false;
}

function _taBuildRow(key, label, locGroup) {
    const isSleep = key.startsWith('sleep');
    const groupAttr = locGroup ? ` data-ta-loc-row="${escapeHtml(locGroup)}"` : '';
    let row = `<tr${groupAttr}>`;
    row += `<td class="tagesablauf-row-label">${escapeHtml(label)}</td>`;
    for (let h = 0; h < 24; h++) {
        const filled = _taSlotMatchesKey(_taSlots[h], key);
        const sleepCls = isSleep && filled ? ' tagesablauf-sleep' : '';
        row += `<td class="tagesablauf-cell${filled ? ' tagesablauf-filled' + sleepCls : ''}" data-key="${escapeHtml(key)}" data-hour="${h}"></td>`;
    }
    return row + '</tr>';
}

function _taApplyKeyToHour(key, hour, clear) {
    // Wendet einen Key auf Stunde an. Wenn clear=true → loescht die Achse
    // des Keys, ohne andere Achsen anzufassen.
    const k = _taParseKey(key);
    const slot = _taSlots[hour] || { location: '', role: '', sleep: false };
    if (k.kind === 'sleep') {
        if (clear) {
            slot.sleep = false;
        } else {
            slot.sleep = true;
            slot.location = '';
            slot.role = '';
        }
    } else if (k.kind === 'loc') {
        if (clear) {
            slot.location = '';
        } else {
            slot.location = k.loc;
            slot.sleep = false;  // Location aktiviert → kein Sleep
        }
    } else if (k.kind === 'role') {
        if (clear) {
            slot.role = '';
        } else {
            slot.role = k.role;
            slot.sleep = false;
        }
    }
    // Stunde-Eintrag rausnehmen wenn komplett leer
    if (!slot.sleep && !slot.location && !slot.role) {
        delete _taSlots[hour];
    } else {
        _taSlots[hour] = slot;
    }
}

function _taRefreshCells() {
    const grid = document.getElementById('tagesablauf-grid');
    if (!grid) return;
    grid.querySelectorAll('.tagesablauf-cell').forEach(cell => {
        const h = parseInt(cell.dataset.hour);
        const k = cell.dataset.key;
        const filled = _taSlotMatchesKey(_taSlots[h], k);
        const isSleep = k.startsWith('sleep');
        cell.classList.toggle('tagesablauf-filled', filled);
        cell.classList.toggle('tagesablauf-sleep', isSleep && filled);
    });
}

function _taOnMouseDown(e) {
    const cell = e.target.closest('.tagesablauf-cell');
    if (!cell) return;
    e.preventDefault();
    _taDrag.active = true;
    _taDrag.key = cell.dataset.key;
    _taDrag.startH = parseInt(cell.dataset.hour);
    _taDrag.curH = _taDrag.startH;
    _taUpdatePreview();
}

function _taOnMouseOver(e) {
    if (!_taDrag.active) return;
    const cell = e.target.closest('.tagesablauf-cell');
    if (!cell || cell.dataset.key !== _taDrag.key) return;
    _taDrag.curH = parseInt(cell.dataset.hour);
    _taUpdatePreview();
}

function _taOnTouchStart(e) {
    const touch = e.touches[0];
    const cell = document.elementFromPoint(touch.clientX, touch.clientY);
    if (!cell || !cell.classList.contains('tagesablauf-cell')) return;
    e.preventDefault();
    _taDrag.active = true;
    _taDrag.key = cell.dataset.key;
    _taDrag.startH = parseInt(cell.dataset.hour);
    _taDrag.curH = _taDrag.startH;
    _taUpdatePreview();
}

function _taOnTouchMove(e) {
    if (!_taDrag.active) return;
    e.preventDefault();
    const touch = e.touches[0];
    const cell = document.elementFromPoint(touch.clientX, touch.clientY);
    if (!cell || !cell.classList.contains('tagesablauf-cell') || cell.dataset.key !== _taDrag.key) return;
    _taDrag.curH = parseInt(cell.dataset.hour);
    _taUpdatePreview();
}

function _taOnMouseUp() {
    if (!_taDrag.active) return;
    _taDrag.active = false;

    const grid = document.getElementById('tagesablauf-grid');
    if (!grid) return;

    const minH = Math.min(_taDrag.startH, _taDrag.curH);
    const maxH = Math.max(_taDrag.startH, _taDrag.curH);
    const key = _taDrag.key;

    // Toggle bei Einzelklick: wenn die Zelle bereits "matched" → diese Achse leeren.
    if (minH === maxH) {
        const slot = _taSlots[minH];
        if (slot && _taSlotMatchesKey(slot, key)) {
            _taApplyKeyToHour(key, minH, true);
            _taRefreshCells();
            _taClearPreview(grid);
            return;
        }
    }

    for (let h = minH; h <= maxH; h++) {
        _taApplyKeyToHour(key, h, false);
    }
    _taRefreshCells();
    _taClearPreview(grid);
}

function _taUpdatePreview() {
    const grid = document.getElementById('tagesablauf-grid');
    if (!grid) return;
    _taClearPreview(grid);
    const minH = Math.min(_taDrag.startH, _taDrag.curH);
    const maxH = Math.max(_taDrag.startH, _taDrag.curH);
    for (let h = minH; h <= maxH; h++) {
        const cell = grid.querySelector(`.tagesablauf-cell[data-key="${CSS.escape(_taDrag.key)}"][data-hour="${h}"]`);
        if (cell && !cell.classList.contains('tagesablauf-filled')) cell.classList.add('tagesablauf-preview');
    }
}

function _taClearPreview(grid) {
    grid.querySelectorAll('.tagesablauf-preview').forEach(c => c.classList.remove('tagesablauf-preview'));
}

async function saveDailySchedule() {
    const grid = document.getElementById('tagesablauf-grid');
    if (!grid) return;

    const enabled = document.getElementById('tagesablauf-enabled').checked;
    // Slot-Map ist die Quelle — alle Eintraege mit mind. einem Feld werden gespeichert.
    const slots = [];
    for (const [hourStr, slot] of Object.entries(_taSlots)) {
        const h = parseInt(hourStr, 10);
        if (slot.sleep) {
            slots.push({ hour: h, location: '', role: '', sleep: true });
        } else if (slot.location || slot.role) {
            slots.push({ hour: h, location: slot.location || '',
                                  role: slot.role || '',
                                  sleep: false });
        }
    }
    slots.sort((a, b) => a.hour - b.hour);

    try {
        const resp = await fetch('/scheduler/daily-schedule', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                character: getEditorCharacterName(),
                enabled: enabled,
                slots: slots,
            })
        });
        if (!resp.ok) throw new Error('Speichern fehlgeschlagen');
        const data = await resp.json();
        const jobs = data.jobs_created;
        showStatusToast(jobs !== undefined
            ? `Tagesablauf gespeichert (${jobs} Jobs)`
            : 'Tagesablauf gespeichert', 'success');
    } catch (e) {
        console.error('[Tagesablauf] Speichern Fehler:', e);
        showStatusToast(t('Error') + ': ' + e.message, 'error');
    }
}


