function _resolveRoomName(locationId, roomId) {
    const locInfo = _locationIdMap[locationId];
    if (locInfo && locInfo.rooms) {
        const room = locInfo.rooms.find(r => r.id === roomId);
        if (room) return room.name;
    }
    return roomId;
}

// === ACTIVITY IMPORT DIALOG ===

// === EDITOR ACTIVITIES TAB (inline in character profile) ===

async function _loadEditorActivities(charName) {
    const listEl = document.getElementById('editor-activities-list');
    if (!listEl) return;
    const cName = charName || getEditorCharacterName();
    try {
        // extra_activities (Referenzen auf Bibliothek) + Template-Basis
        const extraResp = await fetch(`/activities/extra/${encodeURIComponent(cName)}`);
        const extraData = extraResp.ok ? await extraResp.json() : {};
        const extraIds = extraData.extra_activities || [];
        const templateExtras = extraData.template_extras || [];

        // Coverage-Diagnose: welche Template-Activities sind in der Library?
        let coverage = { missing: [], present: [] };
        try {
            const covResp = await fetch(`/templates/coverage/${encodeURIComponent(cName)}`);
            if (covResp.ok) coverage = await covResp.json();
        } catch (_) {}
        const missingSet = new Set(coverage.missing || []);

        let html = '';
        const _actCatLabels = {normal:'Normal',secret:'Geheim',dangerous:'Gefaehrlich',social:'Sozial',creative:'Kreativ',investigation:'Ermittlung',training:'Training',rest:'Erholung'};
        const _actVisLabels = {visible:'Sichtbar',hidden:'Versteckt',disguised:'Getarnt'};

        // Template-Basis zuerst (read-only, mit Hinweis)
        if (templateExtras.length) {
            const missingCount = missingSet.size;
            const seedBtn = missingCount > 0
                ? `<button class="save-btn" style="font-size:10px;padding:2px 8px;margin-left:6px;" onclick="_seedTemplateActivities('${escapeHtml(cName)}')">${missingCount} fehlende anlegen</button>`
                : '';
            const headColor = missingCount > 0 ? 'var(--error-color, #c44)' : 'var(--text-muted)';
            html += `<div style="font-size:10px;color:${headColor};padding:2px 8px 4px;display:flex;align-items:center;">
                Vom Template geerbt (automatisch verfuegbar):${seedBtn}
            </div>`;
            for (const actId of templateExtras) {
                const isMissing = missingSet.has(actId);
                if (isMissing) {
                    html += `<div class="world-item" style="background:rgba(200,50,50,0.08);padding:4px 8px;border-left:2px solid var(--error-color, #c44);">
                        <div class="world-item-info" style="gap:1px;">
                            <strong style="font-size:12px;">⚠ ${escapeHtml(actId)}</strong>
                            <span class="world-item-desc" style="font-size:11px;color:var(--error-color, #c44);">Fehlt in der Library — Char hat diese Activity nicht. Klick "fehlende anlegen" oder lege sie manuell unter Game Admin → Aktivitaeten an (id muss exakt "${escapeHtml(actId)}" sein).</span>
                        </div>
                    </div>`;
                    continue;
                }
                try {
                    const libResp = await fetch(`/activities/library/${encodeURIComponent(actId)}`);
                    const a = libResp.ok ? (await libResp.json()).activity : null;
                    const label = a ? a.name : actId;
                    const desc = a && a.description ? a.description : '';
                    html += `<div class="world-item" style="background:rgba(120,120,120,0.08);padding:4px 8px;opacity:0.75;">
                        <div class="world-item-info" style="gap:1px;">
                            <strong style="font-size:12px;">${escapeHtml(label)}</strong>
                            ${desc ? `<span class="world-item-desc" style="font-size:11px;">${escapeHtml(desc)}</span>` : ''}
                            <span class="world-item-activities" style="font-size:9px;">${escapeHtml(actId)} · Template</span>
                        </div>
                    </div>`;
                } catch(e) {}
            }
            if (extraIds.length) {
                html += `<div style="font-size:10px;color:var(--text-muted);padding:6px 8px 4px;">Zusaetzlich fuer diesen Character:</div>`;
            }
        }

        for (const actId of extraIds) {
            try {
                const libResp = await fetch(`/activities/library/${encodeURIComponent(actId)}`);
                const a = libResp.ok ? (await libResp.json()).activity : null;
                if (!a) {
                    html += `<div class="world-item" style="background:rgba(200,50,50,0.08);padding:4px 8px;">
                        <div class="world-item-info"><strong style="font-size:12px;">${escapeHtml(actId)}</strong>
                        <span class="world-item-desc" style="color:var(--error-color);">Nicht in Bibliothek gefunden</span></div>
                        <button class="job-delete-btn" onclick="_removeExtraActivity('${escapeHtml(actId)}')" title="Referenz entfernen">✕</button>
                    </div>`;
                    continue;
                }
                const cat = _actCatLabels[a.category] || '';
                const vis = a.visibility && a.visibility !== 'visible' ? ` · ${_actVisLabels[a.visibility] || a.visibility}` : '';
                const eff = a.effects ? Object.entries(a.effects).filter(([,v]) => v).map(([k,v]) => `${k.replace('_change','')}: ${v > 0 ? '+' : ''}${v}`).join(', ') : '';
                const cum = a.cumulative_effect ? ` · ${a.cumulative_effect.threshold}x→${a.cumulative_effect.condition_name}` : '';
                html += `<div class="world-item" style="background:rgba(70,130,180,0.08);padding:4px 8px;">
                    <div class="world-item-info" style="gap:1px;">
                        <strong style="font-size:12px;">${escapeHtml(a.name)}</strong>
                        ${a.description ? `<span class="world-item-desc" style="font-size:11px;">${escapeHtml(a.description)}${eff ? ' · ' + eff : ''}${cum}</span>` : ''}
                        <span class="world-item-activities" style="font-size:9px;">
                            ${escapeHtml(actId)}${cat && cat !== 'Normal' ? ' · ' + cat : ''}${vis}
                        </span>
                    </div>
                    <button class="job-delete-btn" onclick="_removeExtraActivity('${escapeHtml(actId)}')" title="Referenz entfernen">✕</button>
                </div>`;
            } catch(e) {}
        }

        listEl.innerHTML = html || `<p class="scheduler-empty">${escapeHtml(t('No activities assigned'))}</p>`;
    } catch (error) {
        console.error('[EditorAct] Fehler:', error);
    }
}

// Legt fuer alle fehlenden Template-extra_activities Stubs in der Welt-
// Library an. Anschliessend Editor-Aktivitaetenliste neu laden, damit die
// neuen Eintraege auftauchen.
async function _seedTemplateActivities(cName) {
    if (!cName) return;
    if (!confirm("Skelett-Eintraege fuer alle fehlenden Template-Activities anlegen?\n\nDie Stubs haben keinen Effekt-/Condition-Inhalt — du musst sie unter Game Admin → Aktivitaeten editieren.")) return;
    try {
        const r = await fetch(`/templates/coverage/${encodeURIComponent(cName)}/seed`, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
        });
        if (!r.ok) {
            const t = await r.text();
            showStatusToast(t('Seeding failed') + ': ' + t.slice(0, 80), 'error');
            return;
        }
        const data = await r.json();
        showStatusToast(`${data.count} ` + t('stub(s) created') + `: ${(data.created||[]).join(', ')}`, 'success');
        await _loadEditorActivities(cName);
    } catch (e) {
        showStatusToast(t('Seeding error') + ': ' + e.message, 'error');
    }
}

