// --- Outfit-Image-Generator Override pro Character ---
// Nutzt dieselben character-spezifischen ImageGen-Endpoints wie die
// ImageGeneration-Skill-Config (keine Admin-Auth noetig) und filtert
// Models + LoRAs per Service-Name (Workflow-Prefix bzw. IMAGEGEN_X_FILTER).

const _editorOutfitImagegenState = {
    workflows: [],           // Workflow-Options aus /workflows
    allModels: [],           // Checkpoints flach
    modelsByService: {},     // {service: [checkpoints]}
    availableLoras: ['None'],// Alle LoRA-Namen
    currentModel: '',        // Gespeichertes Model aus Char-Override
    currentLoras: [],        // Gespeicherte LoRAs aus Char-Override
};

async function _loadEditorOutfitImagegen(charName) {
    const section = document.getElementById('editor-outfit-imagegen-section');
    if (!section || !charName) return;
    section.innerHTML = `<p class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading…'))}</p>`;

    try {
        const [wfResp, ckptResp, loraResp, ovResp] = await Promise.all([
            fetch(`/characters/${encodeURIComponent(charName)}/skills/image_generation/workflows`),
            fetch(`/characters/${encodeURIComponent(charName)}/skills/image_generation/available-checkpoints`),
            fetch(`/characters/${encodeURIComponent(charName)}/skills/image_generation/available-loras`),
            fetch(`/characters/${encodeURIComponent(charName)}/outfit-imagegen`),
        ]);
        const wfData = wfResp.ok ? await wfResp.json() : {};
        _editorOutfitImagegenState.workflows = (wfData.options || []).filter(o => o.type === 'workflow');
        if (ckptResp.ok) {
            const d = await ckptResp.json();
            _editorOutfitImagegenState.allModels = d.models || [];
            _editorOutfitImagegenState.modelsByService = d.models_by_service || {};
        }
        if (loraResp.ok) {
            const d = await loraResp.json();
            _editorOutfitImagegenState.availableLoras = d.loras || ['None'];
        }
        let current = { workflow: '', model: '', loras: [] };
        if (ovResp.ok) current = await ovResp.json();
        _editorOutfitImagegenState.currentModel = (current.model || '').trim();
        _editorOutfitImagegenState.currentLoras = current.loras || [];

        // Initial-Workflow: Char-Override -> active_workflow -> erster Workflow
        const initialWorkflow = (current.workflow || '').trim()
            || (wfData.active_workflow || '')
            || (_editorOutfitImagegenState.workflows[0]?.name || '');

        _renderEditorOutfitImagegen(initialWorkflow);
    } catch (e) {
        section.innerHTML = `<p class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading failed'))}</p>`;
    }
}

function _renderEditorOutfitImagegen(currentWorkflow) {
    const section = document.getElementById('editor-outfit-imagegen-section');
    if (!section) return;
    const st = _editorOutfitImagegenState;

    // Service-Optionen
    const svcOpts = ['<option value="">— Workflow-Default —</option>']
        .concat((st.workflows || []).map(w => {
            const sel = w.name === currentWorkflow ? ' selected' : '';
            const dis = w.available === false ? ' disabled' : '';
            const lbl = _formatImagegenOptionLabel({label: w.label || w.name, cost: w.cost, available: w.available});
            return `<option value="${escapeHtml(w.name)}"${sel}${dis}>${escapeHtml(lbl)}</option>`;
        })).join('');

    // Models nach Workflow filtern (Filter-Pattern aus Workflow-Options)
    const wfObj = (st.workflows || []).find(w => w.name === currentWorkflow);
    const filterPattern = wfObj?.filter || '';
    let modelCandidates = [];
    if (Object.keys(st.modelsByService).length > 0 && currentWorkflow) {
        // per-service gruppiert: fuer den gewaehlten Workflow Models aus allen
        // Services durchreichen und nach Workflow-Name/Filter sieben.
        for (const svcName of Object.keys(st.modelsByService)) {
            const svcModels = _filterByWorkflowName(
                st.modelsByService[svcName] || [],
                currentWorkflow, filterPattern,
            );
            modelCandidates = modelCandidates.concat(svcModels);
        }
        // Doppel-Eintraege entfernen
        modelCandidates = Array.from(new Set(modelCandidates));
    } else {
        modelCandidates = _filterByWorkflowName(
            st.allModels || [], currentWorkflow, filterPattern,
        );
    }
    if (!modelCandidates.length) modelCandidates = st.allModels || [];

    // Gespeichertes Modell in Liste garantieren
    if (st.currentModel && !modelCandidates.includes(st.currentModel)) {
        modelCandidates = [st.currentModel, ...modelCandidates];
    }
    const modelOpts = ['<option value="">— Workflow-Default —</option>']
        .concat(modelCandidates.map(m => {
            const sel = m === st.currentModel ? ' selected' : '';
            return `<option value="${escapeHtml(m)}"${sel}>${escapeHtml(m)}</option>`;
        })).join('');

    // LoRAs nach Workflow filtern (None bleibt immer drin)
    const loraRaw = (st.availableLoras || []).filter(l => l !== 'None');
    const filteredLoras = _filterByWorkflowName(loraRaw, currentWorkflow, filterPattern);
    const lorasForDropdown = ['None', ...filteredLoras];

    let html = '';
    html += `<p style="font-size:11px;color:var(--text-muted);margin:0 0 10px 0;">`
          + `Leere Felder = Default aus dem gewaehlten Workflow. `
          + `Wird beim Generieren der Outfit-/Expression-Variants dieses Characters angewendet.</p>`;

    html += `<div class="skill-config-field" style="margin-bottom:10px;">`;
    html += `<label style="font-weight:600;margin-bottom:6px;display:block;font-size:12px;">Service</label>`;
    html += `<select id="editor-outfit-imagegen-service" class="agent-status-input" style="width:100%;font-size:13px;padding:5px 8px;"`
         + ` onchange="_onEditorOutfitServiceChange()">${svcOpts}</select>`;
    html += `</div>`;

    html += `<div class="skill-config-field" style="margin-bottom:10px;">`;
    html += `<label style="font-weight:600;margin-bottom:6px;display:block;font-size:12px;">Modell</label>`;
    html += `<select id="editor-outfit-imagegen-model" class="agent-status-input" style="width:100%;font-size:13px;padding:5px 8px;">${modelOpts}</select>`;
    html += `</div>`;

    html += `<div class="skill-config-field" style="margin-bottom:10px;">`;
    html += `<label style="font-weight:600;margin-bottom:6px;display:block;font-size:12px;">LoRAs</label>`;
    for (let i = 0; i < 4; i++) {
        const active = st.currentLoras[i] || { name: 'None', strength: 1.0 };
        const slotLoras = (active.name && active.name !== 'None' && !lorasForDropdown.includes(active.name))
            ? [active.name, ...lorasForDropdown] : lorasForDropdown;
        const loraOpts = slotLoras.map(l =>
            `<option value="${escapeHtml(l)}"${l === active.name ? ' selected' : ''}>${escapeHtml(l)}</option>`
        ).join('');
        html += `<div style="display:flex;gap:6px;align-items:center;margin-bottom:4px;">`;
        html += `<span style="font-size:11px;color:var(--text-muted);min-width:50px;">LoRA ${i+1}</span>`;
        html += `<select class="agent-status-input editor-outfit-lora-name" data-slot="${i}" style="flex:1;font-size:12px;padding:4px 6px;">${loraOpts}</select>`;
        html += `<input type="number" class="agent-status-input editor-outfit-lora-strength" data-slot="${i}" value="${active.strength ?? 1.0}" min="-2" max="2" step="0.05" style="width:60px;font-size:12px;padding:4px 6px;">`;
        html += `</div>`;
    }
    html += `</div>`;

    html += `<div style="display:flex;gap:6px;margin-top:10px;">`;
    html += `<button class="save-btn" onclick="_saveEditorOutfitImagegen()">Speichern</button>`;
    html += `<button class="reset-btn" onclick="_clearEditorOutfitImagegen()" title="Override loeschen — Workflow-Default aktiv">Override entfernen</button>`;
    html += `</div>`;

    section.innerHTML = html;
}

function _onEditorOutfitServiceChange() {
    // Aktuelle Model/LoRA-Auswahl aus dem DOM einsammeln, dann neu rendern —
    // damit die DropDown-Listen auf den neuen Service gefiltert werden.
    const modelSel = document.getElementById('editor-outfit-imagegen-model');
    const loraNames = document.querySelectorAll('.editor-outfit-lora-name');
    const loraStrs = document.querySelectorAll('.editor-outfit-lora-strength');
    if (modelSel) _editorOutfitImagegenState.currentModel = (modelSel.value || '').trim();
    const lorasNow = [];
    for (let i = 0; i < loraNames.length; i++) {
        const nm = (loraNames[i].value || '').trim();
        const st = parseFloat(loraStrs[i]?.value) || 1.0;
        lorasNow.push({ name: nm, strength: st });
    }
    _editorOutfitImagegenState.currentLoras = lorasNow;
    const newService = (document.getElementById('editor-outfit-imagegen-service')?.value || '').trim();
    _renderEditorOutfitImagegen(newService);
}

async function _saveEditorOutfitImagegen() {
    const charName = getEditorCharacterName();
    if (!charName) return;
    const workflow = (document.getElementById('editor-outfit-imagegen-service')?.value || '').trim();
    const model = (document.getElementById('editor-outfit-imagegen-model')?.value || '').trim();
    const nameEls = document.querySelectorAll('.editor-outfit-lora-name');
    const strEls = document.querySelectorAll('.editor-outfit-lora-strength');
    const loras = [];
    for (let i = 0; i < nameEls.length; i++) {
        const nm = (nameEls[i].value || '').trim();
        if (!nm || nm === 'None') continue;
        const st = parseFloat(strEls[i]?.value) || 1.0;
        loras.push({ name: nm, strength: st });
    }
    try {
        const r = await fetch(`/characters/${encodeURIComponent(charName)}/outfit-imagegen`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ workflow, model, loras }),
        });
        if (r.ok) showStatusToast(t('Outfit imagegen override saved'), 'success');
        else showStatusToast(t('Save failed'), 'error');
    } catch (e) { showStatusToast(t('Save failed'), 'error'); }
}

// ---- Slot-Overrides Matrix (Prompt + LoRA pro leerem Slot) ----

const _editorSlotOverridesState = {
    order: [],
    slots: {},          // {slot: {prompt, lora:{name,strength}}}
    availableLoras: ['None'],
    workflow: '',       // zum Filtern der LoRAs
    filter: '',
};

const _SLOT_LABELS = {
    head: 'Kopf',
    neck: 'Hals',
    outer: 'Oberbekleidung',
    top: 'Oberteil',
    underwear_top: 'Unterwaesche oben',
    bottom: 'Unterteil',
    underwear_bottom: 'Unterwaesche unten',
    legs: 'Beine',
    feet: 'Fuesse',
};

async function _loadEditorSlotOverrides(charName) {
    const section = document.getElementById('editor-slot-overrides-section');
    if (!section || !charName) return;
    section.innerHTML = `<p class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading…'))}</p>`;
    try {
        const [ovResp, loraResp] = await Promise.all([
            fetch(`/characters/${encodeURIComponent(charName)}/slot-overrides`),
            fetch(`/characters/outfit-lora-options?character_name=${encodeURIComponent(charName)}`),
        ]);
        const ovData = ovResp.ok ? await ovResp.json() : { slots: {}, order: [] };
        const loraData = loraResp.ok ? await loraResp.json() : { loras: ['None'] };
        _editorSlotOverridesState.order = ovData.order || [];
        _editorSlotOverridesState.slots = ovData.slots || {};
        _editorSlotOverridesState.availableLoras = loraData.loras || ['None'];
        _editorSlotOverridesState.workflow = loraData.workflow || '';
        _editorSlotOverridesState.filter = loraData.filter || '';
        _renderEditorSlotOverrides();
    } catch (e) {
        section.innerHTML = `<p class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading failed'))}</p>`;
    }
}

function _renderEditorSlotOverrides() {
    const section = document.getElementById('editor-slot-overrides-section');
    if (!section) return;
    const st = _editorSlotOverridesState;
    const loras = st.availableLoras || ['None'];
    let html = '';
    html += `<p style="font-size:11px;color:var(--text-muted);margin:0 0 10px 0;">`
          + `Pro Slot: Prompt-Text wird zum Bild-Prompt hinzugefuegt wenn der Slot leer und nicht verdeckt ist. `
          + `LoRA wird zusaetzlich in freie Workflow-Slots gemerged.`;
    if (st.workflow) {
        html += ` LoRA-Filter: Workflow <b>${escapeHtml(st.workflow)}</b>`;
        if (st.filter) html += ` (Pattern: ${escapeHtml(st.filter)})`;
    }
    html += `</p>`;

    const _renderRow = (slot) => {
        const entry = st.slots[slot] || {};
        const lora = entry.lora || {};
        const loraName = lora.name || '';
        const strength = (lora.strength !== undefined && lora.strength !== null) ? lora.strength : 1.0;
        const slotLabel = _SLOT_LABELS[slot] || slot;
        const opts = ['<option value="">— keins —</option>']
            .concat(loras.filter(l => l !== 'None').map(l =>
                `<option value="${escapeHtml(l)}"${l === loraName ? ' selected' : ''}>${escapeHtml(l)}</option>`
            ));
        if (loraName && !loras.includes(loraName)) {
            opts.splice(1, 0, `<option value="${escapeHtml(loraName)}" selected>${escapeHtml(loraName)} (nicht verfuegbar)</option>`);
        }
        let r = `<div class="slot-override-row" data-slot="${escapeHtml(slot)}" style="border:1px solid var(--border);border-radius:6px;padding:8px;margin-bottom:8px;">`;
        r += `<div style="font-weight:600;font-size:12px;margin-bottom:4px;">${escapeHtml(slotLabel)}</div>`;
        r += `<input type="text" class="agent-status-input slot-override-prompt" placeholder="Prompt-Fragment (z.B. 'bare feet')" value="${escapeHtml(entry.prompt || '')}" style="width:100%;font-size:12px;padding:4px 6px;margin-bottom:4px;">`;
        r += `<div style="display:flex;gap:6px;align-items:center;">`;
        r += `<span style="font-size:11px;color:var(--text-muted);min-width:40px;">LoRA</span>`;
        r += `<select class="agent-status-input slot-override-lora" style="flex:1;font-size:12px;padding:4px 6px;">${opts.join('')}</select>`;
        r += `<input type="number" class="agent-status-input slot-override-strength" value="${strength}" min="-2" max="2" step="0.05" style="width:60px;font-size:12px;padding:4px 6px;">`;
        r += `</div>`;
        r += `</div>`;
        return r;
    };

    // Aufteilung in zwei Spalten: ab 'underwear_top' beginnt die zweite Spalte.
    const _splitIdx = SLOT_ORDER.indexOf('underwear_top');
    const _colA = SLOT_ORDER.slice(0, _splitIdx);
    const _colB = SLOT_ORDER.slice(_splitIdx);
    html += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">`;
    html += `<div>${_colA.map(_renderRow).join('')}</div>`;
    html += `<div>${_colB.map(_renderRow).join('')}</div>`;
    html += `</div>`;

    html += `<div style="display:flex;gap:6px;margin-top:8px;">`;
    html += `<button class="save-btn" onclick="_saveEditorSlotOverrides()">Speichern</button>`;
    html += `</div>`;
    section.innerHTML = html;
}

async function _saveEditorSlotOverrides() {
    const charName = getEditorCharacterName();
    if (!charName) return;
    const rows = document.querySelectorAll('.slot-override-row');
    const payload = {};
    for (const row of rows) {
        const slot = row.dataset.slot;
        const prompt = (row.querySelector('.slot-override-prompt')?.value || '').trim();
        const loraName = (row.querySelector('.slot-override-lora')?.value || '').trim();
        const strength = parseFloat(row.querySelector('.slot-override-strength')?.value) || 1.0;
        payload[slot] = {
            prompt,
            lora: loraName ? { name: loraName, strength } : {},
        };
    }
    try {
        const r = await fetch(`/characters/${encodeURIComponent(charName)}/slot-overrides`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ slots: payload }),
        });
        if (r.ok) showStatusToast(t('Slot overrides saved'), 'success');
        else showStatusToast(t('Save failed'), 'error');
    } catch (e) { showStatusToast(t('Save failed'), 'error'); }
}

async function _clearEditorOutfitImagegen() {
    const charName = getEditorCharacterName();
    if (!charName) return;
    try {
        const r = await fetch(`/characters/${encodeURIComponent(charName)}/outfit-imagegen`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ workflow: '', model: '', loras: [] }),
        });
        if (r.ok) {
            showStatusToast(t('Override removed — workflow default active'), 'success');
            _loadEditorOutfitImagegen(charName);
        } else showStatusToast(t('Remove failed'), 'error');
    } catch (e) { showStatusToast(t('Remove failed'), 'error'); }
}

async function _loadEditorHomeLocation(charName) {
    const locSelect = document.getElementById('editor-home-location');
    const roomSelect = document.getElementById('editor-home-room');
    if (!locSelect || !roomSelect) return;
    const cName = charName || getEditorCharacterName();
    const locations = await _fetchWorldLocations();
    // Config laden
    let homeLoc = '', homeRoom = '';
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(cName)}/home-location`);
        if (resp.ok) {
            const data = await resp.json();
            homeLoc = data.home_location || '';
            homeRoom = data.home_room || '';
        }
    } catch (e) { /* ignore */ }
    // Location-Dropdown fuellen
    // Sondereintrag "__offmap__": Character schlaeft ausserhalb der Welt
    // (kein Ort in der Karte). Verschwindet beim Schlafen aus der Karte.
    const offmapSel = homeLoc === '__offmap__' ? ' selected' : '';
    locSelect.innerHTML =
        '<option value="">-- No home --</option>' +
        `<option value="__offmap__"${offmapSel}>🌙 Sleeps off-world</option>` +
        locations.map(l => `<option value="${escapeHtml(l.id || l.name)}"${(l.id || l.name) === homeLoc ? ' selected' : ''}>${escapeHtml(l.name)}</option>`).join('');
    // Rooms laden fuer gewaehlte Location
    _populateHomeRoomDropdown(locations, homeLoc, homeRoom);
}

async function _onHomeLocationChange() {
    const locSelect = document.getElementById('editor-home-location');
    if (!locSelect) return;
    const locId = locSelect.value;
    const locations = _cachedWorldLocations || await _fetchWorldLocations();
    _populateHomeRoomDropdown(locations, locId, '');
}

function _populateHomeRoomDropdown(locations, locId, selectedRoom) {
    const roomSelect = document.getElementById('editor-home-room');
    if (!roomSelect) return;
    // Off-map: kein Raum auswaehlbar (Sleeper hat keinen Raum)
    if (!locId || locId === '__offmap__') {
        roomSelect.innerHTML = '<option value="">-- No room --</option>';
        roomSelect.disabled = (locId === '__offmap__');
        return;
    }
    roomSelect.disabled = false;
    const loc = locations.find(l => (l.id || l.name) === locId);
    const rooms = loc ? (loc.rooms || []) : [];
    roomSelect.innerHTML = '<option value="">-- No room --</option>' +
        rooms.map(r => `<option value="${escapeHtml(r.id || r.name)}"${(r.id || r.name) === selectedRoom ? ' selected' : ''}>${escapeHtml(r.name)}</option>`).join('');
}

async function _saveHomeLocation() {
    const locSelect = document.getElementById('editor-home-location');
    const roomSelect = document.getElementById('editor-home-room');
    if (!locSelect || !roomSelect) return;
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(getEditorCharacterName())}/home-location`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                home_location: locSelect.value,
                home_room: roomSelect.value
            })
        });
        if (resp.ok) showStatusToast(t('Home saved'), 'success');
    } catch (e) { console.error('[HomeLocation] Speichern fehlgeschlagen:', e); }
}

// --- Activity Library (Bibliothek) ---

async function _loadLibraryActivities() {
    const container = document.getElementById('editor-library-activities');
    if (!container) return;
    try {
        const charName = getEditorCharacterName();
        // Bibliothek + Character-Overrides parallel laden
        const [libResp, ovResp] = await Promise.all([
            fetch(`/activities/library`),
            charName ? fetch(`/activities/overrides/character/${encodeURIComponent(charName)}`) : Promise.resolve(null),
        ]);
        if (!libResp.ok) throw new Error('Fehler');
        const data = await libResp.json();
        const groups = data.groups || {};
        const charOverrides = ovResp && ovResp.ok ? (await ovResp.json()).activity_overrides || {} : {};
        if (Object.keys(groups).length === 0) {
            container.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No activities in the library'))}</p>`;
            return;
        }
        let html = '';
        for (const [groupName, acts] of Object.entries(groups)) {
            html += `<div style="margin-bottom:8px;"><strong style="font-size:12px;color:var(--text-muted);">${escapeHtml(groupName)}</strong>`;
            for (const act of acts) {
                const eff = act.effects ? Object.entries(act.effects).filter(([,v]) => v).map(([k,v]) => `${k.replace('_change','')}: ${v > 0 ? '+' : ''}${v}`).join(', ') : '';
                const cum = act.cumulative_effect ? ` · ${act.cumulative_effect.threshold}x→${act.cumulative_effect.condition_name}` : '';
                const hasOverride = charOverrides[act.id];
                const ovBadge = hasOverride ? '<span style="font-size:9px;padding:1px 4px;border-radius:3px;background:rgba(200,150,50,0.3);margin-left:4px;">OV</span>' : '';
                const origin = act._origin || 'world';
                const bgColor = origin === 'shared' ? 'rgba(70,130,180,0.08)' : 'rgba(80,160,80,0.08)';
                html += `<div class="world-item" style="padding:4px 8px;background:${bgColor};">`;
                html += `<div class="world-item-info" style="gap:2px;">`;
                html += `<strong style="font-size:12px;">${escapeHtml(act.name)}${ovBadge}</strong>`;
                html += `<span class="world-item-desc" style="font-size:11px;">${escapeHtml(act.description || '')}${eff ? ' · ' + eff : ''}${cum}</span>`;
                html += `</div>`;
                html += `<div style="display:flex;gap:3px;flex-shrink:0;">`;
                html += `<button class="save-btn" style="font-size:10px;padding:2px 6px;" onclick="_assignLibraryActivity('${escapeHtml(act.id)}')" title="Diesem Character zuweisen">+</button>`;
                html += `<button class="save-btn" style="font-size:10px;padding:2px 6px;" onclick="_assignLibraryToTemplate('${escapeHtml(act.id)}')" title="Allen Characters mit gleichem Template zuweisen">++</button>`;
                html += `</div>`;
                html += `</div>`;
            }
            html += `</div>`;
        }
        container.innerHTML = html;
    } catch (e) {
        console.error('[Library] Fehler:', e);
        container.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

/**
 * Oeffnet den Picker fuer extra_activities. Blendet bereits zugewiesene
 * + template-geerbte Activities aus (disabled statt versteckt, damit der
 * User sieht was bereits da ist).
 */
async function _pickExtraActivity() {
    const charName = getEditorCharacterName();
    if (!charName) {
        showStatusToast(t('No character selected'), 'error');
        return;
    }
    const [libResp, extraResp] = await Promise.all([
        fetch('/activities/library'),
        fetch(`/activities/extra/${encodeURIComponent(charName)}`),
    ]);
    if (!libResp.ok) { showStatusToast(t('Library not reachable'), 'error'); return; }
    const libData = await libResp.json();
    const extraData = extraResp.ok ? await extraResp.json() : {};
    const alreadyCharExtras = new Set(extraData.extra_activities || []);
    const templateExtras = new Set(extraData.template_extras || []);

    const result = await openPicker({
        title: 'Aktivitaet hinzufuegen',
        items: libData.activities || [],
        searchFields: ['name', 'description', 'category', '_group'],
        searchPlaceholder: 'Aktivitaet suchen...',
        emptyText: 'Keine Aktivitaeten in der Bibliothek',
        renderItem: (a) => {
            const inCharExtras = alreadyCharExtras.has(a.id);
            const inTemplate = templateExtras.has(a.id);
            const parts = [];
            if (a.category && a.category !== 'normal') parts.push(a.category);
            if (a._group) parts.push(a._group);
            return {
                label: a.name || a.id,
                subtitle: a.description || '',
                meta: parts.join(' · '),
                disabled: inCharExtras || inTemplate,
                disabledReason: inCharExtras ? 'Schon zugewiesen' : (inTemplate ? 'Vom Template geerbt' : ''),
            };
        },
    });
    if (!result) return;
    await _assignLibraryActivity(result.id);
}

async function _assignLibraryActivity(activityId) {
    const charName = getEditorCharacterName();
    if (!charName) return;
    try {
        // Referenz in extra_activities speichern (keine Kopie)
        const saveResp = await fetch(`/activities/extra/${encodeURIComponent(charName)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ activity_id: activityId })
        });
        if (saveResp.ok) {
            showStatusToast(`"${activityId}" ` + t('assigned (reference)'), 'success');
            await _loadEditorActivities();
        } else {
            showStatusToast(t('Assignment error'), 'error');
        }
    } catch (e) {
        console.error('[Library] Assign Fehler:', e);
        showStatusToast(t('Assignment error'), 'error');
    }
}

async function _assignLibraryToTemplate(activityId) {
    const charName = getEditorCharacterName();
    if (!charName) return;
    if (!confirm(`"${activityId}" allen Characters mit dem gleichen Template zuweisen?`)) return;
    try {
        const resp = await fetch(`/activities/extra-broadcast`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ source_character: charName, activity_id: activityId })
        });
        if (resp.ok) {
            const data = await resp.json();
            showStatusToast(`"${activityId}" ` + t('assigned to') + ` ${data.count} ` + t('characters'), 'success');
            await _loadEditorActivities();
        } else {
            const err = await resp.json().catch(() => ({}));
            showStatusToast(err.detail || 'Fehler', 'error');
        }
    } catch (e) {
        console.error('[Library] Broadcast Fehler:', e);
        showStatusToast(t('Assignment error'), 'error');
    }
}

async function _removeExtraActivity(activityId) {
    const charName = getEditorCharacterName();
    if (!charName) return;
    if (!confirm(`Referenz "${activityId}" entfernen?`)) return;
    try {
        const resp = await fetch(`/activities/extra/${encodeURIComponent(charName)}/${encodeURIComponent(activityId)}`, { method: 'DELETE' });
        if (resp.ok) {
            showStatusToast(t('Reference removed'), 'success');
            await _loadEditorActivities();
        } else {
            showStatusToast(t('Error'), 'error');
        }
    } catch(e) {
        console.error('[Library] Remove Fehler:', e);
    }
}

// --- Activity Library Modal (Admin-UI) ---

let _libEditingId = null;
let _libActivityGroups = null; // cached for follow-up dropdowns
let _actFollowUps = [];  // [{activity_id, probability}, ...]

function _buildGroupedActivityOptions(selectedId) {
    let html = '<option value="">-- Keine --</option>';
    if (!_libActivityGroups) return html;
    for (const [groupName, acts] of Object.entries(_libActivityGroups)) {
        html += `<optgroup label="${escapeHtml(groupName)}">`;
        for (const act of acts) {
            const sel = act.id === selectedId ? ' selected' : '';
            html += `<option value="${escapeHtml(act.id)}"${sel}>${escapeHtml(act.name)}</option>`;
        }
        html += '</optgroup>';
    }
    return html;
}

function _renderFollowUps(_type) {
    const container = document.getElementById('lib-act-followups');
    if (!container) return;
    if (_actFollowUps.length === 0) { container.innerHTML = ''; return; }
    container.innerHTML = _actFollowUps.map((fu, i) => `
        <div class="form-row-inline" style="margin-bottom:3px;">
            <select class="agent-status-input" style="flex:1;" onchange="_updateFollowUp(${i},'id',this.value)">
                ${_buildGroupedActivityOptions(fu.activity_id || '')}
            </select>
            <input type="number" class="agent-status-input" value="${fu.probability || ''}" min="0" max="100" placeholder="%" style="width:55px;" onchange="_updateFollowUp(${i},'prob',this.value)">
            <button class="job-delete-btn" onclick="_removeFollowUp(${i})" title="Entfernen">\u2715</button>
        </div>
    `).join('');
}

function _updateFollowUp(idx, field, value) {
    if (!_actFollowUps[idx]) return;
    if (field === 'id') _actFollowUps[idx].activity_id = value;
    else _actFollowUps[idx].probability = parseInt(value) || 0;
}

function _removeFollowUp(idx) {
    _actFollowUps.splice(idx, 1);
    _renderFollowUps();
}

function _addFollowUpRow() {
    _actFollowUps.push({ activity_id: '', probability: 50 });
    _renderFollowUps();
}

function _loadFollowUps(activity) {
    _actFollowUps = (activity.follow_up_activities || []).map(fu => ({
        activity_id: fu.activity_id || fu.activity || '',
        probability: fu.probability != null ? fu.probability : 50,
    }));
    _renderFollowUps();
}

function openGameAdminModal(tab) {
    // Game-Admin moved to its own React SPA at /game-admin. The old in-page
    // modal is no longer used — its markup and tab-specific render functions
    // remain in this file as dead code until the next cleanup pass.
    // Translate legacy tab names to the React app's tab IDs.
    const tabAliases = { prompt_filters: 'states' };
    const raw = (tab && typeof tab === 'string' ? tab : 'activities');
    const t = tabAliases[raw] || raw.replace('_', '-');
    window.location.href = '/game-admin#/' + t;
}

function closeGameAdminModal() {
    // No-op — the modal is gone. Kept so legacy onclick handlers in the
    // existing markup don't throw before that markup is removed.
}

function switchGameAdminTab(tabName) {
    // Alle Admin-Tab-Bodies verstecken
    document.querySelectorAll('[id^="game-admin-tab-"]').forEach(el => el.style.display = 'none');
    // Alle Tab-Buttons deaktivieren
    document.querySelectorAll('[data-admin-tab]').forEach(btn => btn.classList.remove('tab-active'));
    // Aktiven Tab zeigen — Tab-Body scrollt statt das Modal, damit Modal-Hoehe stabil bleibt
    const tabEl = document.getElementById(`game-admin-tab-${tabName}`);
    if (tabEl) {
        tabEl.style.display = 'flex';
        tabEl.style.flex = '1';
        tabEl.style.minHeight = '0';
        tabEl.style.overflow = 'auto';
    }
    const btnEl = document.querySelector(`[data-admin-tab="${tabName}"]`);
    if (btnEl) btnEl.classList.add('tab-active');
    // Tab-spezifisches Laden
    if (tabName === 'activities') { _loadActivityLibraryList(); _loadOverrides(); }
    if (tabName === 'items') {
        _loadItemsList();
        // Outfit-Type-Vorschlaege beim ersten Tab-Open laden, dann Item-Select rebuilden
        if (typeof _outfitTypeCache !== 'undefined' && _outfitTypeCache.length === 0) {
            _loadOutfitTypeSuggestions().then(() => _rebuildItemOutfitTypeSelect());
        } else {
            _rebuildItemOutfitTypeSelect();
        }
        // Category-Wechsel toggelt outfit_piece-Sektion, Slot-Wechsel rendert
        // Covers-Checkboxen neu (eigener Slot darf sich nicht selbst verdecken).
        const catSel = document.getElementById('item-edit-category');
        if (catSel && !catSel.dataset.bound) {
            catSel.addEventListener('change', _toggleOutfitPieceSection);
            catSel.dataset.bound = '1';
        }
        // (Slot-Wechsel-Binding entfaellt — _renderItemEditSlots verdrahtet
        // die Cover/Silhouette-Aktualisierung jetzt direkt ueber den
        // onChange-Callback des Slot-Tag-Pickers.)
        const consChk = document.getElementById('item-edit-consumable');
        if (consChk && !consChk.dataset.bound) {
            consChk.addEventListener('change', _toggleConsumableEffectSection);
            consChk.dataset.bound = '1';
        }
    }
    if (tabName === 'rules') {
        if (!_libActivityGroups) _loadActivityLibraryList();
        if (!_cachedWorldLocations) loadLocations().then(() => _loadRulesList()); else _loadRulesList();
    }
    if (tabName === 'prompt_filters') { _loadPromptFiltersList(); }
    if (tabName === 'world') {
        // Editor-State zuruecksetzen damit das Right-Panel nicht den letzten
        // Eintrag zeigt
        const lf = document.getElementById('location-form');
        if (lf) lf.style.display = 'none';
        const _ph = document.getElementById('world-editor-placeholder');
        if (_ph) _ph.style.display = 'block';
        editingLocationName = null;
        editingLocationId = null;
        editingRoomId = null;
        _cachedWorldLocations = null;
        if (typeof _resetLocationGallery === 'function') _resetLocationGallery();
        if (typeof loadLocations === 'function') loadLocations();
    }
}

// Legacy alias
function openActivityLibraryModal() { openGameAdminModal('activities'); }
function closeActivityLibraryModal() { closeGameAdminModal(); }

async function _loadActivityLibraryList() {
    const listEl = document.getElementById('activity-library-list');
    if (!listEl) return;
    try {
        const resp = await fetch(`/activities/library`);
        const data = await resp.json();
        const groups = data.groups || {};
        _libActivityGroups = groups;
        if (Object.keys(groups).length === 0) {
            listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No activities'))}</p>`;
            return;
        }
        let html = '';
        for (const [groupName, acts] of Object.entries(groups)) {
            html += `<div style="margin-bottom:10px;"><strong style="font-size:12px;color:var(--text-muted);">${escapeHtml(groupName)}</strong>`;
            for (const act of acts) {
                const eff = act.effects ? Object.entries(act.effects).filter(([,v]) => v).map(([k,v]) => `${k.replace('_change','')}: ${v > 0 ? '+' : ''}${v}`).join(', ') : '';
                const cum = act.cumulative_effect ? ` · ${act.cumulative_effect.threshold}x→${act.cumulative_effect.condition_name}` : '';
                const cat = act.category && act.category !== 'normal' ? ` [${act.category}]` : '';
                // Hintergrundfarbe nach Herkunft: shared=blau, world=gruen, override=orange
                const origin = act._origin || 'world';
                const bgColor = origin === 'shared' ? 'rgba(70,130,180,0.08)' : 'rgba(80,160,80,0.08)';
                const originLabel = origin === 'shared' ? 'Allgemein' : 'Weltspezifisch';
                const originBadge = `<span style="font-size:9px;padding:1px 5px;border-radius:3px;background:${origin === 'shared' ? 'rgba(70,130,180,0.25)' : 'rgba(80,160,80,0.25)'};">${originLabel}</span>`;
                html += `<div class="world-item" style="padding:4px 8px;cursor:pointer;background:${bgColor};" onclick="editLibraryActivity('${escapeHtml(act.id)}')">`;
                html += `<div class="world-item-info" style="gap:1px;">`;
                html += `<strong style="font-size:12px;">${escapeHtml(act.name)}${cat}</strong>`;
                html += `<span class="world-item-desc" style="font-size:10px;">${escapeHtml(act.description || '')}${eff ? ' · ' + eff : ''}${cum}</span>`;
                html += `<span class="world-item-activities" style="font-size:9px;">${originBadge} ${escapeHtml(act.id)}</span>`;
                html += `</div>`;
                html += `<button class="job-delete-btn" onclick="event.stopPropagation();deleteLibraryActivity('${escapeHtml(act.id)}')" title="Loeschen">🗑️</button>`;
                html += `</div>`;
            }
            html += `</div>`;
        }
        listEl.innerHTML = html;
        // Filter erneut anwenden falls Suchfeld einen Wert hat
        const searchEl = document.getElementById('lib-act-search');
        if (searchEl && searchEl.value.trim()) {
            _filterActivityList('activity-library-list', searchEl.value);
        }
    } catch (e) {
        console.error('[LibModal] Fehler:', e);
        listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

function _filterActivityList(containerId, query) {
    const container = document.getElementById(containerId);
    if (!container) return;
    const q = query.toLowerCase().trim();
    // Gruppen-Container sind direkte Kinder mit <strong> + .world-item
    for (const group of container.children) {
        if (group.nodeType !== 1) continue;
        const items = group.querySelectorAll('.world-item');
        let visibleCount = 0;
        for (const item of items) {
            const text = item.textContent.toLowerCase();
            const match = !q || text.includes(q);
            item.style.display = match ? '' : 'none';
            if (match) visibleCount++;
        }
        // Gruppe verstecken wenn keine sichtbaren Items
        group.style.display = visibleCount > 0 || !q ? '' : 'none';
    }
}

function _showActivityColumns() {
    // Spalte 2+3 fuer Aktivitaet anzeigen, Override-Formulare verstecken
    const form = document.getElementById('activity-library-form');
    const cumForm = document.getElementById('activity-cum-form');
    const ph = document.getElementById('activity-library-placeholder');
    const ovForm = document.getElementById('override-edit-form');
    const ovCum = document.getElementById('override-cum-form');
    if (form) form.style.display = 'flex';
    if (cumForm) cumForm.style.display = 'flex';
    if (ph) ph.style.display = 'none';
    if (ovForm) ovForm.style.display = 'none';
    if (ovCum) ovCum.style.display = 'none';
}

function _showOverrideColumns() {
    // Spalte 2+3 fuer Override anzeigen, Aktivitaet-Formulare verstecken
    const form = document.getElementById('activity-library-form');
    const cumForm = document.getElementById('activity-cum-form');
    const ph = document.getElementById('activity-library-placeholder');
    const ovForm = document.getElementById('override-edit-form');
    const ovCum = document.getElementById('override-cum-form');
    if (form) form.style.display = 'none';
    if (cumForm) cumForm.style.display = 'none';
    if (ph) ph.style.display = 'none';
    if (ovForm) ovForm.style.display = 'flex';
    if (ovCum) ovCum.style.display = 'flex';
}

function _hideAllEditForms() {
    ['activity-library-form','activity-cum-form','override-edit-form','override-cum-form'].forEach(id => {
        const el = document.getElementById(id); if (el) el.style.display = 'none';
    });
    const ph = document.getElementById('activity-library-placeholder');
    if (ph) ph.style.display = 'block';
}

async function copyLibraryActivity() {
    // Dupliziert die aktuell im Editor offene Aktivitaet — alle Felder
    // werden uebernommen, neue ID mit "_copy"-Suffix vorgeschlagen, der
    // Editor wechselt in den "Neu"-Modus damit beim Save ein NEUER
    // Eintrag entsteht (statt das Original zu ueberschreiben).
    if (!_libEditingId) {
        showStatusToast(t('Please choose an activity first'), 'error');
        return;
    }
    const sourceId = _libEditingId;
    // Felder via editLibraryActivity befuellen — danach in den Neu-Modus wechseln
    await editLibraryActivity(sourceId);
    _libEditingId = null;
    // Neue, eindeutige ID vorschlagen — zaehlt _copy / _copy2 / _copy3 hoch
    let newId = `${sourceId}_copy`;
    let n = 2;
    const usedIds = new Set();
    if (typeof _libActivityGroups === 'object' && _libActivityGroups) {
        for (const list of Object.values(_libActivityGroups)) {
            for (const a of (list || [])) usedIds.add(a.id);
        }
    }
    while (usedIds.has(newId)) {
        newId = `${sourceId}_copy${n++}`;
    }
    const idEl = document.getElementById('lib-act-id');
    const nameEl = document.getElementById('lib-act-name');
    if (idEl) {
        idEl.value = newId;
        idEl.focus();
        idEl.select && idEl.select();
    }
    if (nameEl && nameEl.value) {
        nameEl.value = `${nameEl.value} (Kopie)`;
    }
    document.getElementById('activity-library-form-title').textContent = 'Aktivitaet duplizieren';
    showStatusToast(t('Copied from') + ` "${sourceId}" — ` + t('adjust ID + save'), 'success');
}

async function newLibraryActivity() {
    _libEditingId = null;
    _actFollowUps = [];
    _showActivityColumns();
    document.getElementById('activity-library-form-title').textContent = 'Neue Aktivitaet';
    ['lib-act-id','lib-act-name','lib-act-description','lib-act-condition','lib-act-cum-mood'].forEach(id => {
        const el = document.getElementById(id); if (el) el.value = '';
    });
    await _populateConditionSelect(document.getElementById('lib-act-cum-name'), '');
    document.getElementById('lib-act-category').value = 'normal';
    document.getElementById('lib-act-visibility').value = 'visible';
    document.getElementById('lib-act-effects').value = '';
    document.getElementById('lib-act-cooldown').value = '0';
    document.getElementById('lib-act-duration').value = '0';
    const etDef = document.getElementById('lib-act-effect-type');
    if (etDef) etDef.value = 'ongoing';
    const apDef = document.getElementById('lib-act-auto-pick');
    if (apDef) apDef.value = 'true';
    document.getElementById('lib-act-cum-threshold').value = '';
    document.getElementById('lib-act-cum-duration').value = '';
    document.getElementById('lib-act-cum-effects').value = '';
    document.getElementById('lib-act-target').value = 'world';
    _populateLibActGroupSelect('');
    _setLibActOutfitType('');
    _populateOutfitTypeDatalist();
    const paEl = document.getElementById('lib-act-partner-activity');
    if (paEl) paEl.innerHTML = _buildGroupedActivityOptions('');
    const rpEl = document.getElementById('lib-act-requires-partner');
    if (rpEl) rpEl.checked = false;
    const fbEl = document.getElementById('lib-act-fallback-activity');
    if (fbEl) fbEl.innerHTML = _buildGroupedActivityOptions('');
    const invEl = document.getElementById('lib-act-invitation-text');
    if (invEl) invEl.value = '';
    const fbRow = document.getElementById('lib-act-fallback-row');
    if (fbRow) fbRow.style.display = 'none';
    _renderFollowUps();
    document.getElementById('lib-act-id').focus();
}

async function _populateOutfitTypeDatalist() {
    // Wird nur einmal pro Formular-Load aufgerufen. Setzt die Dropdown-Optionen
    // fuer den Outfit-Type-Picker der Activity (analog Verdeckt bei Pieces).
    const sel = document.getElementById('lib-act-outfit-type-add');
    if (!sel) return;
    try {
        const resp = await fetch('/characters/outfit-rules');
        if (!resp.ok) return;
        const data = await resp.json();
        const types = Object.keys(data.outfit_types || {}).sort((a,b) => a.localeCompare(b));
        const current = _readLibActOutfitType();
        const remaining = types.filter(t => t !== current);
        sel.innerHTML = '<option value="">+ auswaehlen</option>'
            + remaining.map(t => `<option value="${escapeHtml(t)}">${escapeHtml(t)}</option>`).join('');
        sel.onchange = () => {
            if (!sel.value) return;
            _setLibActOutfitType(sel.value);
            sel.value = '';
            _populateOutfitTypeDatalist();  // remaining neu filtern
        };
    } catch(e) {}
}

function _populateLibActGroupSelect(currentGroup) {
    // Befuellt das Group-Dropdown mit allen bekannten Gruppen + "+ new group".
    // Wenn currentGroup gesetzt ist und nicht in der Liste vorkommt, wird sie
    // als ausgewaehlte Option ergaenzt (z.B. wenn ein Activity seine Gruppe
    // verloren hat).
    const sel = document.getElementById('lib-act-group-select');
    const inp = document.getElementById('lib-act-group');
    if (!sel || !inp) return;
    const groups = Object.keys(_libActivityGroups || {})
        .filter(g => g && g !== 'Sonstige')
        .sort((a, b) => a.localeCompare(b));
    if (currentGroup && !groups.includes(currentGroup)) groups.unshift(currentGroup);
    let html = '<option value="">-- group --</option>';
    for (const g of groups) {
        html += `<option value="${escapeHtml(g)}"${g === currentGroup ? ' selected' : ''}>${escapeHtml(g)}</option>`;
    }
    html += '<option value="__new__">+ new group</option>';
    sel.innerHTML = html;
    sel.value = currentGroup && groups.includes(currentGroup) ? currentGroup : '';
    inp.value = '';
    inp.style.display = 'none';
}

function _onLibActGroupSelectChange() {
    const sel = document.getElementById('lib-act-group-select');
    const inp = document.getElementById('lib-act-group');
    if (!sel || !inp) return;
    if (sel.value === '__new__') {
        inp.style.display = '';
        inp.value = '';
        inp.focus();
    } else {
        inp.style.display = 'none';
        inp.value = '';
    }
}

function _readLibActGroup() {
    // Liefert den aktuell gewaehlten Gruppennamen — entweder aus dem Select
    // oder, falls "+ new group", aus dem Text-Input.
    const sel = document.getElementById('lib-act-group-select');
    const inp = document.getElementById('lib-act-group');
    if (!sel) return '';
    if (sel.value === '__new__') {
        return (inp?.value || '').trim();
    }
    return sel.value || '';
}

function _readLibActOutfitType() {
    // Aktivitaet hat genau 0 oder 1 outfit_type — Chip-Container liefert den
    // Wert ueber data-type oder leer-String.
    const wrap = document.getElementById('lib-act-outfit-type-tags');
    if (!wrap) return '';
    const tag = wrap.querySelector('.lib-act-outfit-type-tag');
    return tag ? (tag.dataset.type || '') : '';
}

function _setLibActOutfitType(value) {
    const wrap = document.getElementById('lib-act-outfit-type-tags');
    if (!wrap) return;
    const v = (value || '').trim();
    if (!v) {
        wrap.innerHTML = '';
        return;
    }
    wrap.innerHTML = `<span class="lib-act-outfit-type-tag" data-type="${escapeHtml(v)}"
        style="display:inline-flex;align-items:center;gap:3px;padding:2px 6px;background:var(--bg-alt);color:var(--text);border:1px solid var(--border);border-radius:3px;font-size:11px;cursor:pointer;"
        title="Klick zum Entfernen">${escapeHtml(v)} <span style="color:var(--text-muted);">✕</span></span>`;
    wrap.querySelector('.lib-act-outfit-type-tag').onclick = () => {
        _setLibActOutfitType('');
        _populateOutfitTypeDatalist();
    };
}

async function editLibraryActivity(actId) {
    try {
        const resp = await fetch(`/activities/library/${encodeURIComponent(actId)}`);
        if (!resp.ok) return;
        const data = await resp.json();
        const act = data.activity;
        _libEditingId = act.id;
        _populateOutfitTypeDatalist();
        _showActivityColumns();
        document.getElementById('activity-library-form-title').textContent = 'Aktivitaet bearbeiten';
        document.getElementById('lib-act-id').value = act.id || '';
        document.getElementById('lib-act-name').value = act.name || '';
        document.getElementById('lib-act-description').value = act.description || '';
        document.getElementById('lib-act-category').value = act.category || 'normal';
        document.getElementById('lib-act-visibility').value = act.visibility || 'visible';
        document.getElementById('lib-act-condition').value = act.condition || '';
        // Partner-Aktivitaet Dropdown
        const paEl = document.getElementById('lib-act-partner-activity');
        if (paEl) paEl.innerHTML = _buildGroupedActivityOptions(act.partner_activity || '');
        document.getElementById('lib-act-cooldown').value = String(act.cooldown_minutes || 0);
        document.getElementById('lib-act-duration').value = String(act.duration_minutes || 0);
        const etEl = document.getElementById('lib-act-effect-type');
        if (etEl) etEl.value = (act.effect_type === 'once') ? 'once' : 'ongoing';
        _setLibActOutfitType(act.outfit_type || '');
        _populateOutfitTypeDatalist();
        _populateLibActGroupSelect(act._group || '');
        document.getElementById('lib-act-target').value = act._origin || 'world';
        // Effects
        const effEl = document.getElementById('lib-act-effects');
        if (effEl && act.effects) {
            effEl.value = Object.entries(act.effects).filter(([,v]) => v !== 0 && v !== null && v !== '').map(([k,v]) => `${k}: ${v}`).join('\n');
        } else if (effEl) { effEl.value = ''; }
        // Interruptible
        const intEl = document.getElementById('lib-act-interruptible');
        if (intEl) intEl.checked = act.interruptible !== false;
        // Auto-Pick (Selectable vs Follow-up only)
        const apEl = document.getElementById('lib-act-auto-pick');
        if (apEl) apEl.value = (act.auto_pick === false) ? 'false' : 'true';
        // Required Roles
        const rrEl = document.getElementById('lib-act-required-roles');
        if (rrEl) rrEl.value = (act.required_roles || []).join(', ');
        // Requires Partner + Fallback
        const rpEl = document.getElementById('lib-act-requires-partner');
        if (rpEl) rpEl.checked = !!act.requires_partner;
        const fbEl = document.getElementById('lib-act-fallback-activity');
        if (fbEl) fbEl.innerHTML = _buildGroupedActivityOptions(act.fallback_activity || '');
        const invEl = document.getElementById('lib-act-invitation-text');
        if (invEl) invEl.value = act.invitation_text || '';
        const fbRow = document.getElementById('lib-act-fallback-row');
        if (fbRow) fbRow.style.display = act.requires_partner ? '' : 'none';
        // Cumulative
        const cum = act.cumulative_effect || {};
        document.getElementById('lib-act-cum-threshold').value = cum.threshold ? String(cum.threshold) : '';
        await _populateConditionSelect(document.getElementById('lib-act-cum-name'), cum.condition_name || '');
        // prompt_modifier entfernt — wird ueber Zustaende (status_modifiers) konfiguriert
        document.getElementById('lib-act-cum-mood').value = cum.mood_influence || '';
        document.getElementById('lib-act-cum-duration').value = cum.duration_hours ? String(cum.duration_hours) : '';
        // Cumulative sub-effects
        const cumEffEl = document.getElementById('lib-act-cum-effects');
        if (cumEffEl && cum.effects) {
            cumEffEl.value = Object.entries(cum.effects).filter(([,v]) => v !== 0 && v !== null).map(([k,v]) => `${k}: ${v}`).join('\n');
        } else if (cumEffEl) { cumEffEl.value = ''; }
        // Follow-up activities
        _loadFollowUps(act);
    } catch (e) {
        console.error('[LibModal] Edit Fehler:', e);
    }
}

async function saveLibraryActivity() {
    const id = document.getElementById('lib-act-id').value.trim();
    const name = document.getElementById('lib-act-name').value.trim();
    if (!id || !name) { showStatusToast(t('ID and name are required'), 'error'); return; }
    // Effects parsen
    const effectsText = document.getElementById('lib-act-effects').value || '';
    const effects = {};
    effectsText.split('\n').forEach(line => {
        if (!line.trim()) return;
        const m = line.match(/^\s*(\S+)\s*:\s*(.+)\s*$/);
        if (m) { const val = m[2].trim(); effects[m[1]] = isNaN(Number(val)) ? val : Number(val); }
    });
    // Cumulative
    const cumTh = parseInt(document.getElementById('lib-act-cum-threshold').value) || 0;
    const cumName = document.getElementById('lib-act-cum-name').value.trim();
    // prompt_modifier entfernt — wird ueber Zustaende (Game Admin) konfiguriert
    const cumMood = document.getElementById('lib-act-cum-mood').value.trim();
    const cumDur = parseInt(document.getElementById('lib-act-cum-duration').value) || 2;
    // Cumulative sub-effects parsen
    const cumEffText = document.getElementById('lib-act-cum-effects').value || '';
    const cumEffects = {};
    cumEffText.split('\n').forEach(line => {
        if (!line.trim()) return;
        const m = line.match(/^\s*(\S+)\s*:\s*(.+)\s*$/);
        if (m) { const val = m[2].trim(); cumEffects[m[1]] = isNaN(Number(val)) ? val : Number(val); }
    });
    let cumulative_effect = null;
    if (cumTh > 0 && cumName) {
        cumulative_effect = { threshold: cumTh, condition_name: cumName, mood_influence: cumMood, duration_hours: cumDur };
        if (Object.keys(cumEffects).length > 0) cumulative_effect.effects = cumEffects;
    }
    // Aktivitaets-Folge-Aktivitaeten
    const validActFu = _actFollowUps.filter(fu => fu.activity_id);
    const interruptible = document.getElementById('lib-act-interruptible')?.checked ?? true;
    const autoPick = (document.getElementById('lib-act-auto-pick')?.value || 'true') === 'true';

    const effectType = (document.getElementById('lib-act-effect-type')?.value || 'ongoing');
    const cooldownMinutes = parseInt(document.getElementById('lib-act-cooldown').value) || 0;
    const groupValue = _readLibActGroup() || 'custom';
    const activity = {
        id, name,
        description: document.getElementById('lib-act-description').value.trim(),
        category: document.getElementById('lib-act-category').value,
        visibility: document.getElementById('lib-act-visibility').value,
        condition: document.getElementById('lib-act-condition').value.trim(),
        effect_type: effectType,
        cooldown_minutes: cooldownMinutes,
        duration_minutes: parseInt(document.getElementById('lib-act-duration').value) || 0,
        outfit_type: _readLibActOutfitType(),
        effects,
        interruptible,
        auto_pick: autoPick,
        _group: groupValue,
    };
    // Required Roles parsen
    const rolesRaw = document.getElementById('lib-act-required-roles')?.value || '';
    const requiredRoles = rolesRaw.split(',').map(s => s.trim()).filter(Boolean);
    if (requiredRoles.length) activity.required_roles = requiredRoles;
    if (validActFu.length > 0) activity.follow_up_activities = validActFu;
    const partnerAct = document.getElementById('lib-act-partner-activity')?.value || '';
    if (partnerAct) activity.partner_activity = partnerAct;
    const requiresPartner = document.getElementById('lib-act-requires-partner')?.checked || false;
    if (requiresPartner) {
        activity.requires_partner = true;
        const fallbackAct = document.getElementById('lib-act-fallback-activity')?.value || '';
        if (fallbackAct) activity.fallback_activity = fallbackAct;
        const invText = document.getElementById('lib-act-invitation-text')?.value.trim() || '';
        if (invText) activity.invitation_text = invText;
    }
    if (cumulative_effect) activity.cumulative_effect = cumulative_effect;

    const target = document.getElementById('lib-act-target').value;
    try {
        // Bei Speicherort-Wechsel: alte Version am anderen Ort loeschen
        if (_libEditingId) {
            const otherTarget = target === 'shared' ? 'world' : 'shared';
            await fetch(`/activities/library/${encodeURIComponent(_libEditingId)}?target=${otherTarget}`, { method: 'DELETE' }).catch(() => {});
        }
        const resp = await fetch('/activities/library', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ activity, target })
        });
        if (resp.ok) {
            showStatusToast(`"${name}" ` + t('saved'), 'success');
            _libEditingId = id;
            document.getElementById('activity-library-form-title').textContent = 'Aktivitaet bearbeiten';
            await _loadActivityLibraryList();
        } else {
            let msg = 'Fehler beim Speichern';
            try { const err = await resp.json(); if (err && err.detail) msg = String(err.detail); } catch (_) {}
            showStatusToast(msg, 'error');
        }
    } catch (e) {
        console.error('[LibModal] Save Fehler:', e);
        showStatusToast(t('Save error'), 'error');
    }
}

async function deleteLibraryActivity(actId) {
    if (!confirm(`Aktivitaet "${actId}" aus der Bibliothek loeschen?`)) return;
    try {
        const resp = await fetch(`/activities/library/${encodeURIComponent(actId)}?target=world`, { method: 'DELETE' });
        if (!resp.ok) {
            // Versuche shared
            await fetch(`/activities/library/${encodeURIComponent(actId)}?target=shared`, { method: 'DELETE' });
        }
        showStatusToast(t('Deleted'), 'success');
        await _loadActivityLibraryList();
    } catch (e) {
        console.error('[LibModal] Delete Fehler:', e);
    }
}

function cancelLibraryEdit() {
    _libEditingId = null;
    _hideAllEditForms();
}

// --- Items (Game Admin) ---

// Cache der zuletzt geladenen Items, damit Filter/Sortierung clientseitig
// rendern koennen ohne erneuten Fetch.
let _itemsCache = [];

const _ITEM_CAT_LABELS = {
    key: 'Schluessel', tool: 'Werkzeuge', consumable: 'Verbrauchbar',
    evidence: 'Beweise', gift: 'Geschenke', spell: 'Zauber', quest: 'Quest',
    decoration: 'Deko', outfit_piece: 'Outfits', other: 'Sonstige',
};
const _ITEM_CAT_ICONS = {
    key: '🔑', tool: '🔧', consumable: '🧪', evidence: '🔍',
    gift: '🎁', spell: '🪄', quest: '📜', decoration: '🖼️', outfit_piece: '👕',
    other: '📦',
};
const _RARITY_RANK = { common: 0, rare: 1, unique: 2 };
// Kategorien bei denen Magic/TTL-Felder + Evidence-Felder sichtbar sind.
// Outfit-Teile, Werkzeuge, Schluessel, Deko etc. brauchen das nicht.
const _ITEM_CATS_WITH_MAGIC = new Set(['spell', 'consumable', 'gift']);
const _ITEM_CATS_WITH_EVIDENCE = new Set(['gift', 'quest', 'evidence']);

async function _loadItemsList() {
    const listEl = document.getElementById('items-list');
    if (!listEl) return;
    try {
        const resp = await fetch(`/inventory/items?include_shared=1`);
        const data = await resp.json();
        _itemsCache = data.items || [];
        _renderItemsList();
    } catch (e) { console.error('Items load error:', e); }
}

function _renderItemsList() {
    const listEl = document.getElementById('items-list');
    if (!listEl) return;
    const items = _itemsCache || [];
    if (!items.length) { listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No items'))}</p>`; return; }

    const search = (document.getElementById('items-search')?.value || '').trim().toLowerCase();
    const filterCat = document.getElementById('items-filter-category')?.value || '';
    const filterRar = document.getElementById('items-filter-rarity')?.value || '';
    const sortMode = document.getElementById('items-sort')?.value || 'default';

    const filtered = items.filter(it => {
        if (filterCat && (it.category || 'other') !== filterCat) return false;
        if (filterRar && (it.rarity || 'common') !== filterRar) return false;
        if (search) {
            const hay = `${it.name || ''} ${it.description || ''} ${it.prompt_fragment || ''}`.toLowerCase();
            if (!hay.includes(search)) return false;
        }
        return true;
    });

    if (!filtered.length) { listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No matches'))}</p>`; return; }

    const cardHtml = (item, scope, cat) => {
        const icon = _ITEM_CAT_ICONS[cat] || '📦';
        const isPiece = cat === 'outfit_piece';
        const slotMeta = isPiece
            ? (((item.outfit_piece && item.outfit_piece.slots) || []).map(s => SLOT_LABELS_DE[s] || s).join(' + ') || '— ohne Slot —')
            : '';
        const fragment = (item.prompt_fragment || item.description || '').slice(0, 60);
        const metaLine = [slotMeta, fragment].filter(Boolean).join(' · ');
        const imgHtml = item.image
            ? `<img class="wardrobe-piece-img" src="/inventory/items/${encodeURIComponent(item.id)}/image?t=${Date.now()}" alt="">`
            : `<div class="wardrobe-piece-img" style="display:flex;align-items:center;justify-content:center;font-size:20px;">${icon}</div>`;
        const isSelected = _editingItemId === item.id;
        const isShared = scope === 'shared';
        const sharedBadge = isShared ? '<span style="font-size:10px;padding:1px 5px;border-radius:3px;background:#2b5a8e;color:#fff;margin-left:4px;">shared</span>' : '';
        const rarity = item.rarity || 'common';
        const rarityBadge = `<span style="font-size:10px;padding:1px 5px;border-radius:3px;background:var(--bg-alt);border:1px solid var(--border);color:var(--text-muted);margin-left:4px;">${escapeHtml(rarity)}</span>`;
        const moveBtn = isShared
            ? `<button class="save-btn items-list-move-world" data-item="${escapeHtml(item.id)}" title="In die Welt verschieben">← Welt</button>`
            : `<button class="save-btn items-list-move-shared" data-item="${escapeHtml(item.id)}" title="In die Shared Library verschieben">→ Shared</button>`;
        const delBtn = `<button class="danger items-list-delete" data-item="${escapeHtml(item.id)}">Loeschen</button>`;
        return `<div class="wardrobe-piece-card${isSelected ? ' equipped' : ''}" data-item="${escapeHtml(item.id)}" style="cursor:pointer;">
            ${imgHtml}
            <div class="wardrobe-piece-info">
                <span class="wardrobe-piece-name">${escapeHtml(item.name || '?')}${sharedBadge}${rarityBadge}</span>
                <span class="wardrobe-piece-meta">${escapeHtml(metaLine)}</span>
            </div>
            <div class="wardrobe-piece-actions">
                ${moveBtn}
                ${delBtn}
            </div>
        </div>`;
    };

    let html = '';
    if (sortMode === 'default') {
        const groups = {};
        for (const item of filtered) {
            const scope = item._shared ? 'shared' : 'world';
            const cat = item.category || 'other';
            const key = `${scope}:${cat}`;
            (groups[key] = groups[key] || []).push(item);
        }
        const keyOrder = Object.keys(groups).sort((a, b) => {
            const [sa, ca] = a.split(':'); const [sb, cb] = b.split(':');
            if (sa !== sb) return sa === 'world' ? -1 : 1;
            if (ca === 'outfit_piece') return -1;
            if (cb === 'outfit_piece') return 1;
            return (_ITEM_CAT_LABELS[ca] || ca).localeCompare(_ITEM_CAT_LABELS[cb] || cb);
        });
        let lastScope = '';
        for (const key of keyOrder) {
            const [scope, cat] = key.split(':');
            if (scope !== lastScope) {
                const scopeLabel = scope === 'shared' ? '🌐 Shared Library' : '🌍 Welt';
                html += `<div style="font-size:12px;color:var(--accent);font-weight:600;margin:${lastScope ? '14px' : '2px'} 0 6px;border-bottom:1px solid var(--border);padding-bottom:3px;">${scopeLabel}</div>`;
                lastScope = scope;
            }
            html += `<div style="margin-bottom:10px;"><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.3px;margin-bottom:4px;padding:0 2px;">${escapeHtml(_ITEM_CAT_LABELS[cat] || cat)}</div>`;
            for (const item of groups[key]) {
                html += cardHtml(item, scope, cat);
            }
            html += '</div>';
        }
    } else {
        const sorted = [...filtered];
        if (sortMode === 'name') {
            sorted.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
        } else if (sortMode === 'rarity') {
            sorted.sort((a, b) => (_RARITY_RANK[b.rarity || 'common'] || 0) - (_RARITY_RANK[a.rarity || 'common'] || 0)
                || (a.name || '').localeCompare(b.name || ''));
        } else if (sortMode === 'category') {
            sorted.sort((a, b) => (_ITEM_CAT_LABELS[a.category || 'other'] || '').localeCompare(_ITEM_CAT_LABELS[b.category || 'other'] || '')
                || (a.name || '').localeCompare(b.name || ''));
        }
        for (const item of sorted) {
            const scope = item._shared ? 'shared' : 'world';
            const cat = item.category || 'other';
            html += cardHtml(item, scope, cat);
        }
    }

    listEl.innerHTML = html;
    listEl.querySelectorAll('.wardrobe-piece-card').forEach(card => {
        card.onclick = (e) => {
            if (e.target.classList.contains('items-list-delete')) return;
            if (e.target.classList.contains('items-list-move-shared')) return;
            if (e.target.classList.contains('items-list-move-world')) return;
            _editItem(card.dataset.item);
        };
    });
    listEl.querySelectorAll('.items-list-delete').forEach(b => {
        b.onclick = (e) => { e.stopPropagation(); _deleteItemById(b.dataset.item); };
    });
    listEl.querySelectorAll('.items-list-move-shared').forEach(b => {
        b.onclick = async (e) => {
            e.stopPropagation();
            if (!confirm('Item in die Shared Library verschieben? Es ist dann fuer alle Welten verfuegbar.')) return;
            const r = await fetch(`/inventory/items/${encodeURIComponent(b.dataset.item)}/move-to-shared`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({}),
            });
            if (r.ok) { showStatusToast(t('→ Moved to shared'), 'success'); _loadItemsList(); }
            else { const d = await r.json().catch(() => ({})); showStatusToast(d.detail || 'Move fehlgeschlagen', 'error'); }
        };
    });
    listEl.querySelectorAll('.items-list-move-world').forEach(b => {
        b.onclick = async (e) => {
            e.stopPropagation();
            if (!confirm('Item aus Shared in die Welt holen?')) return;
            const r = await fetch(`/inventory/items/${encodeURIComponent(b.dataset.item)}/move-to-world`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({}),
            });
            if (r.ok) { showStatusToast(t('← World adopted'), 'success'); _loadItemsList(); }
            else { const d = await r.json().catch(() => ({})); showStatusToast(d.detail || 'Move fehlgeschlagen', 'error'); }
        };
    });
}

async function _loadItemOwners(itemId) {
    const panel = document.getElementById('item-owners-panel');
    const listEl = document.getElementById('item-owners-list');
    if (!panel || !listEl) return;
    if (!itemId) { panel.style.display = 'none'; return; }
    panel.style.display = '';
    listEl.innerHTML = `<span class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Loading…'))}</span>`;
    // Add-Picker mit Charakteren befuellen (parallel — der Picker veraltet nicht zwischen Items)
    _populateItemOwnerAddPicker();
    try {
        const r = await fetch(`/inventory/items/${encodeURIComponent(itemId)}/owners`);
        if (!r.ok) { listEl.innerHTML = '<span class="scheduler-empty" style="font-size:11px;">—</span>'; return; }
        const data = await r.json();
        const owners = data.owners || [];
        if (!owners.length) {
            listEl.innerHTML = '<span class="scheduler-empty" style="font-size:11px;">Niemand besitzt dieses Item.</span>';
            return;
        }
        listEl.innerHTML = owners.map(o => {
            const qty = o.quantity > 1 ? ` ×${o.quantity}` : '';
            const eq = o.equipped ? ' <span style="color:#6c6;font-size:10px;">(angelegt)</span>' : '';
            return `<div style="display:flex;align-items:center;justify-content:space-between;padding:2px 0;gap:6px;">
                <span>• ${escapeHtml(o.character)}${qty}${eq}</span>
                <button class="danger item-owner-remove" data-character="${escapeHtml(o.character)}" style="font-size:10px;padding:1px 6px;" title="Aus Inventar entfernen">– entfernen</button>
            </div>`;
        }).join('');
        listEl.querySelectorAll('.item-owner-remove').forEach(b => {
            b.onclick = (e) => { e.stopPropagation(); _removeItemOwner(b.dataset.character); };
        });
    } catch (e) {
        listEl.innerHTML = `<span class="scheduler-empty" style="font-size:11px;">${escapeHtml(t('Error loading'))}</span>`;
    }
}

async function _populateItemOwnerAddPicker() {
    const sel = document.getElementById('item-owners-add-character');
    if (!sel || sel.dataset.loaded) return;
    try {
        const r = await fetch('/characters/list');
        if (!r.ok) return;
        const data = await r.json();
        const chars = (data.characters || []).map(c => typeof c === 'string' ? c : c.name).filter(Boolean);
        sel.innerHTML = '<option value="">-- Character --</option>' +
            chars.map(c => `<option value="${escapeHtml(c)}">${escapeHtml(c)}</option>`).join('');
        sel.dataset.loaded = '1';
    } catch (e) { console.warn('[ItemOwners] character load failed', e); }
}

async function _addItemOwner() {
    if (!_editingItemId) return;
    const sel = document.getElementById('item-owners-add-character');
    const qtyEl = document.getElementById('item-owners-add-qty');
    const character = (sel?.value || '').trim();
    const qty = Math.max(1, parseInt(qtyEl?.value || '1', 10) || 1);
    if (!character) { showStatusToast(t('Choose a character'), 'error'); return; }
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(character)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ item_id: _editingItemId, quantity: qty, obtained_method: 'manual' }),
        });
        if (r.ok) {
            showStatusToast(t('Given to') + ` ${character}`, 'success');
            if (sel) sel.value = '';
            if (qtyEl) qtyEl.value = '1';
            _loadItemOwners(_editingItemId);
        } else {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || 'Fehler', 'error');
        }
    } catch (e) { showStatusToast(t('Error'), 'error'); }
}

async function _removeItemOwner(character) {
    if (!_editingItemId || !character) return;
    if (!confirm(`Item bei ${character} aus dem Inventar entfernen?`)) return;
    try {
        const r = await fetch(`/inventory/characters/${encodeURIComponent(character)}/${encodeURIComponent(_editingItemId)}`, {
            method: 'DELETE',
        });
        if (r.ok) {
            showStatusToast(t('Removed'), 'success');
            _loadItemOwners(_editingItemId);
        } else {
            const d = await r.json().catch(() => ({}));
            showStatusToast(d.detail || 'Fehler', 'error');
        }
    } catch (e) { showStatusToast(t('Error'), 'error'); }
}

let _editingItemId = null;

function _showItemImagePanel(show) {
    const panel = document.getElementById('item-image-panel');
    const ph = document.getElementById('item-image-placeholder-col');
    if (panel) panel.style.display = show ? 'flex' : 'none';
    if (ph) ph.style.display = show ? 'none' : 'block';
}

function _setItemImagePreview(url) {
    const img = document.getElementById('item-image-img');
    const ph = document.getElementById('item-image-placeholder');
    if (!img || !ph) return;
    if (url) {
        img.src = url;
        img.style.display = 'block';
        ph.style.display = 'none';
    } else {
        img.src = '';
        img.style.display = 'none';
        ph.style.display = 'flex';
    }
}

async function _newItem() {
    _editingItemId = null;
    document.getElementById('item-edit-form').style.display = 'flex';
    document.getElementById('item-placeholder').style.display = 'none';
    document.getElementById('item-edit-id').value = '';
    ['item-edit-name','item-edit-description',
     'item-edit-image-prompt','item-edit-prompt-fragment',
     'item-edit-incantation','item-edit-success-text','item-edit-fail-text',
     'item-edit-success-chance'].forEach(id => {
        const el = document.getElementById(id); if (el) el.value = '';
    });
    _renderItemOutfitTypeTags([]);
    _rebuildItemOutfitTypeSelect();
    document.getElementById('item-edit-category').value = 'tool';
    document.getElementById('item-edit-rarity').value = 'common';
    document.getElementById('item-edit-stackable').checked = false;
    document.getElementById('item-edit-transferable').checked = true;
    document.getElementById('item-edit-consumable').checked = false;
    document.getElementById('item-edit-spell-mode').value = 'force';
    document.getElementById('item-edit-copy-on-give').checked = false;
    await _populateCloneItemSelect('');
    _renderItemEditSlots(['outer']);
    _renderItemEditCovers([], [], ['outer']);
    const effEl = document.getElementById('item-edit-effects');
    if (effEl) effEl.value = '';
    const acEl = document.getElementById('item-edit-apply-condition');
    if (acEl) await _populateConditionSelect(acEl, '');
    const cdEl = document.getElementById('item-edit-condition-duration');
    if (cdEl) cdEl.value = '';
    _toggleOutfitPieceSection();
    _showItemImagePanel(false);
    _populateRevealsOwnerSelect();
    document.getElementById('item-edit-reveals-secret').innerHTML = '<option value="">-- Geheimnis --</option>';
    _populateTracksCharacterSelect('');
    // Kein Item -> Owner-Panel ausblenden
    const ownPanel = document.getElementById('item-owners-panel');
    if (ownPanel) ownPanel.style.display = 'none';
}

function _toggleOutfitPieceSection() {
    const cat = (document.getElementById('item-edit-category')?.value || '').trim();
    const sec = document.getElementById('item-edit-outfit-piece-section');
    if (sec) sec.style.display = cat === 'outfit_piece' ? 'block' : 'none';
    // Evidence-Sektion: nur Kategorien wo ein Item ein Geheimnis enthuellen kann
    // (Beweis/Geschenk/Quest). Outfit, Tool, Spell, Consumable haben das nicht.
    const evSec = document.getElementById('item-edit-evidence-section');
    if (evSec) evSec.style.display = _ITEM_CATS_WITH_EVIDENCE.has(cat) ? 'block' : 'none';
    // Magic/Spell-Sektion: nur Spell/Consumable/Gift. Andere Kategorien
    // brauchen die Spell-Felder nicht.
    const magicSec = document.getElementById('item-edit-magic-section');
    if (magicSec) magicSec.style.display = _ITEM_CATS_WITH_MAGIC.has(cat) ? 'block' : 'none';
    // Prompt-Fragment (Character-Bild) bei Spell ausblenden — Spells haengen
    // visuell nicht am Avatar, das Feld waere irrefuehrend.
    const fragWrap = document.getElementById('item-edit-prompt-fragment-wrap');
    if (fragWrap) fragWrap.style.display = cat === 'spell' ? 'none' : '';
    // Consumable-Effekt-Sektion: bei Spell + Consumable + Gift (alle die
    // Effects/apply_condition tragen koennen). Manuell setzbare Checkbox
    // bleibt als zusaetzlicher Override.
    _toggleConsumableEffectSection();
}

function _toggleConsumableEffectSection() {
    const cat = (document.getElementById('item-edit-category')?.value || '').trim();
    const isConsumable = !!document.getElementById('item-edit-consumable')?.checked;
    const sec = document.getElementById('item-edit-consumable-section');
    // Sektion fuer alle Kategorien sichtbar machen die Effects tragen koennen
    // (gleicher Set wie Magic). Plus manueller Consumable-Toggle als Override.
    if (sec) sec.style.display = (_ITEM_CATS_WITH_MAGIC.has(cat) || isConsumable) ? 'block' : 'none';
}

function _renderItemEditCovers(covered, partiallyCovers, slots) {
    // Eigene Slots des Pieces sind nicht-gueltige Cover-Ziele.
    const own = new Set((slots || []).map(s => String(s).trim().toLowerCase()).filter(Boolean));
    const order = (typeof SLOT_ORDER !== 'undefined' ? SLOT_ORDER : []);
    const coversAvailable = order.filter(s => !own.has(s));
    _renderItemEditCoverGroup('item-edit-covers-tags', 'item-edit-covers-add', covered, coversAvailable);
    _renderItemEditCoverGroup('item-edit-partially-covers-tags', 'item-edit-partially-covers-add', partiallyCovers, coversAvailable);
    _updateItemEditSilhouette();
}

function _renderItemEditSlots(slots) {
    // Symmetrische Slots-Auswahl. onChange-Callback synchronisiert
    // Cover-Picker und Silhouette mit der neuen Slot-Auswahl.
    const order = (typeof SLOT_ORDER !== 'undefined' ? SLOT_ORDER : []);
    _renderItemEditCoverGroup('item-edit-slots-tags', 'item-edit-slots-add', slots || [], order, (newSlots) => {
        _renderItemEditCovers(_readItemEditCovers(), _readItemEditPartiallyCovers(), newSlots);
    });
}

function _readItemEditSlots() {
    const wrap = document.getElementById('item-edit-slots-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.item-edit-cover-tag')).map(el => el.dataset.slot);
}

function _updateItemEditSilhouette() {
    const container = document.getElementById('item-edit-silhouette');
    if (!container) return;
    renderSlotSilhouette(container, {
        slots: _readItemEditSlots(),
        covers: _readItemEditCovers(),
        partiallyCovers: _readItemEditPartiallyCovers(),
        labels: SLOT_LABELS_DE,
    });
}

function _renderItemEditCoverGroup(tagsId, addId, selected, allSlots, onChange) {
    const tagsEl = document.getElementById(tagsId);
    const addSel = document.getElementById(addId);
    if (!tagsEl || !addSel) return;
    const labels = (typeof SLOT_LABELS_DE !== 'undefined' ? SLOT_LABELS_DE : {});
    const set = new Set((selected || []).map(s => String(s).trim().toLowerCase()).filter(Boolean));
    tagsEl.innerHTML = Array.from(set).map(s => {
        const label = labels[s] || s;
        return `<span class="item-edit-cover-tag" data-slot="${escapeHtml(s)}" style="display:inline-flex;align-items:center;gap:3px;padding:2px 6px;background:var(--bg-alt);color:var(--text);border:1px solid var(--border);border-radius:3px;font-size:11px;cursor:pointer;" title="Klick zum Entfernen">${escapeHtml(label)} <span style="color:var(--text-muted);">✕</span></span>`;
    }).join('');
    tagsEl.querySelectorAll('.item-edit-cover-tag').forEach(el => {
        el.onclick = () => {
            set.delete(el.dataset.slot);
            _renderItemEditCoverGroup(tagsId, addId, Array.from(set), allSlots, onChange);
            _updateItemEditSilhouette();
            if (typeof onChange === 'function') onChange(Array.from(set));
        };
    });
    const remaining = allSlots.filter(s => !set.has(s));
    addSel.innerHTML = '<option value="">+ hinzufuegen</option>' + remaining.map(s =>
        `<option value="${escapeHtml(s)}">${escapeHtml(labels[s] || s)}</option>`
    ).join('');
    addSel.onchange = () => {
        if (!addSel.value) return;
        set.add(addSel.value);
        _renderItemEditCoverGroup(tagsId, addId, Array.from(set), allSlots, onChange);
        _updateItemEditSilhouette();
        if (typeof onChange === 'function') onChange(Array.from(set));
    };
}

function _readItemEditCovers() {
    const wrap = document.getElementById('item-edit-covers-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.item-edit-cover-tag')).map(el => el.dataset.slot);
}

function _readItemEditPartiallyCovers() {
    const wrap = document.getElementById('item-edit-partially-covers-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.item-edit-cover-tag')).map(el => el.dataset.slot);
}

// --- Outfit-Type Picker (Item-Editor, parallel zur WPC-Variante) ---

function _renderItemOutfitTypeTags(tags) {
    const wrap = document.getElementById('item-edit-outfit-types-tags');
    if (!wrap) return;
    wrap.innerHTML = (tags || []).map(t =>
        `<span class="outfit-type-tag" data-type="${escapeHtml(t)}">${escapeHtml(t)}<button type="button" onclick="_itemRemoveOutfitType('${escapeHtml(t).replace(/'/g, '&#39;')}')">×</button></span>`
    ).join('');
}

function _readItemOutfitTypes() {
    const wrap = document.getElementById('item-edit-outfit-types-tags');
    if (!wrap) return [];
    return Array.from(wrap.querySelectorAll('.outfit-type-tag'))
        .map(el => el.dataset.type || '')
        .filter(Boolean);
}

function _itemAddOutfitType(rawValue) {
    const value = (rawValue || '').trim();
    if (!value) return;
    const current = _readItemOutfitTypes();
    if (!current.some(t => t.toLowerCase() === value.toLowerCase())) {
        current.push(value);
        _renderItemOutfitTypeTags(current);
    }
    if (typeof _outfitTypeCache !== 'undefined' && !_outfitTypeCache.some(t => t.toLowerCase() === value.toLowerCase())) {
        _outfitTypeCache.push(value);
    }
    _rebuildItemOutfitTypeSelect();
}

function _itemRemoveOutfitType(value) {
    const current = _readItemOutfitTypes().filter(t => t !== value);
    _renderItemOutfitTypeTags(current);
    _rebuildItemOutfitTypeSelect();
}

function _rebuildItemOutfitTypeSelect() {
    const sel = document.getElementById('item-edit-outfit-types-add');
    if (!sel) return;
    const cache = (typeof _outfitTypeCache !== 'undefined') ? _outfitTypeCache : [];
    const selected = new Set(_readItemOutfitTypes().map(t => t.toLowerCase()));
    const opts = ['<option value="">+ Outfit-Typ</option>'];
    for (const t of [...cache].sort((a, b) => a.localeCompare(b))) {
        if (!selected.has(t.toLowerCase())) {
            opts.push(`<option value="${escapeHtml(t)}">${escapeHtml(t)}</option>`);
        }
    }
    sel.innerHTML = opts.join('');
    if (!sel.dataset.bound) {
        sel.onchange = () => {
            const v = sel.value;
            if (!v) return;
            _itemAddOutfitType(v);
            sel.value = '';
        };
        sel.dataset.bound = '1';
    }
}

async function _populateRevealsOwnerSelect(selectedOwner = '') {
    const sel = document.getElementById('item-edit-reveals-owner');
    if (!sel) return;
    try {
        const resp = await fetch(`/characters/list`);
        if (!resp.ok) return;
        const data = await resp.json();
        const chars = (data.characters || []).map(c => typeof c === 'string' ? c : c.name).filter(Boolean);
        sel.innerHTML = '<option value="">-- Character (Geheimnis-Inhaber) --</option>' +
            chars.map(c => `<option value="${escapeHtml(c)}"${c === selectedOwner ? ' selected' : ''}>${escapeHtml(c)}</option>`).join('');
        sel.onchange = async () => {
            await _populateRevealsSecretSelect(sel.value, '');
        };
    } catch (e) { console.warn('[Reveals] owner load failed', e); }
}

async function _populateTracksCharacterSelect(selectedTarget = '') {
    const sel = document.getElementById('item-edit-tracks-character');
    if (!sel) return;
    try {
        const resp = await fetch(`/characters/list`);
        if (!resp.ok) return;
        const data = await resp.json();
        const chars = (data.characters || []).map(c => typeof c === 'string' ? c : c.name).filter(Boolean);
        sel.innerHTML = '<option value="">-- none --</option>' +
            chars.map(c => `<option value="${escapeHtml(c)}"${c === selectedTarget ? ' selected' : ''}>${escapeHtml(c)}</option>`).join('');
    } catch (e) { console.warn('[Tracker] character load failed', e); }
}

async function _populateRevealsSecretSelect(owner, selectedSecretId = '') {
    const sel = document.getElementById('item-edit-reveals-secret');
    if (!sel) return;
    if (!owner) {
        sel.innerHTML = '<option value="">-- Geheimnis --</option>';
        return;
    }
    try {
        const resp = await fetch(`/secrets/${encodeURIComponent(owner)}`);
        const data = resp.ok ? await resp.json() : { secrets: [] };
        const secrets = data.secrets || [];
        sel.innerHTML = '<option value="">-- Geheimnis --</option>' +
            secrets.map(s => `<option value="${escapeHtml(s.id)}"${s.id === selectedSecretId ? ' selected' : ''}>${escapeHtml(s.title || s.id)}</option>`).join('');
    } catch (e) { console.warn('[Reveals] secrets load failed', e); }
}

async function _editItem(itemId) {
    try {
        const resp = await fetch(`/inventory/items/${itemId}`);
        if (!resp.ok) return;
        const data = await resp.json();
        const item = data.item;
        _editingItemId = item.id;
        document.getElementById('item-edit-form').style.display = 'flex';
        document.getElementById('item-placeholder').style.display = 'none';
        document.getElementById('item-edit-id').value = item.id;
        document.getElementById('item-edit-name').value = item.name || '';
        document.getElementById('item-edit-description').value = item.description || '';
        document.getElementById('item-edit-category').value = item.category || 'tool';
        document.getElementById('item-edit-rarity').value = item.rarity || 'common';
        document.getElementById('item-edit-stackable').checked = !!item.stackable;
        document.getElementById('item-edit-transferable').checked = item.transferable !== false;
        document.getElementById('item-edit-consumable').checked = !!item.consumable;
        document.getElementById('item-edit-image-prompt').value = item.image_prompt || '';
        const fragEl = document.getElementById('item-edit-prompt-fragment');
        if (fragEl) fragEl.value = item.prompt_fragment || '';
        const op = item.outfit_piece || {};
        const itemSlots = Array.isArray(op.slots) ? op.slots : [];
        _renderItemEditSlots(itemSlots.length ? itemSlots : ['outer']);
        _renderItemOutfitTypeTags(Array.isArray(op.outfit_types) ? op.outfit_types : []);
        _rebuildItemOutfitTypeSelect();
        _renderItemEditCovers(op.covers || [], op.partially_covers || [], itemSlots);
        // Consumable-Effects befuellen
        const effObj = item.effects || {};
        const effLines = Object.entries(effObj)
            .filter(([k]) => k !== 'apply_condition' && k !== 'condition_duration_hours')
            .map(([k, v]) => `${k}: ${v}`);
        const effEl = document.getElementById('item-edit-effects');
        if (effEl) effEl.value = effLines.join('\n');
        const acEl = document.getElementById('item-edit-apply-condition');
        if (acEl) {
            await _populateConditionSelect(acEl, effObj.apply_condition || '');
        }
        // Magic / Spell-Felder
        document.getElementById('item-edit-incantation').value = item.incantation || '';
        document.getElementById('item-edit-spell-mode').value = item.spell_mode || 'force';
        await _populateCloneItemSelect(item.clone_item_id || '', item.id);
        await _populateCastActivitySelect(item.cast_activity || '');
        document.getElementById('item-edit-success-chance').value =
            (item.success_chance !== undefined && item.success_chance !== null && item.success_chance !== '')
                ? String(item.success_chance) : '';
        document.getElementById('item-edit-copy-on-give').checked = !!item.copy_on_give;
        document.getElementById('item-edit-success-text').value = item.success_text || '';
        document.getElementById('item-edit-fail-text').value = item.fail_text || '';
        const cdEl = document.getElementById('item-edit-condition-duration');
        if (cdEl) cdEl.value = effObj.condition_duration_hours || '';
        _toggleOutfitPieceSection();
        // Tracker: tracks_character restaurieren
        await _populateTracksCharacterSelect(item.tracks_character || '');
        // Evidence: reveals_secret restaurieren
        const _rs = item.reveals_secret || {};
        await _populateRevealsOwnerSelect(_rs.owner || '');
        if (_rs.owner) {
            await _populateRevealsSecretSelect(_rs.owner, _rs.secret_id || '');
        } else {
            document.getElementById('item-edit-reveals-secret').innerHTML = '<option value="">-- Geheimnis --</option>';
        }
        _showItemImagePanel(true);
        if (item.image) {
            _setItemImagePreview(`/inventory/items/${encodeURIComponent(item.id)}/image?t=${Date.now()}`);
        } else {
            _setItemImagePreview('');
        }
        // Game Admin darf alles editieren — auch Shared-Items.
        _setGameAdminItemFormReadOnly(false);
        // Besitzer-Panel frisch laden
        _loadItemOwners(item.id);
    } catch (e) { console.error('Item edit error:', e); }
}

function _setGameAdminItemFormReadOnly(readOnly) {
    const ids = [
        'item-edit-name', 'item-edit-description',
        'item-edit-category', 'item-edit-rarity',
        'item-edit-stackable', 'item-edit-transferable', 'item-edit-consumable',
        'item-edit-image-prompt', 'item-edit-prompt-fragment',
        'item-edit-slots-add', 'item-edit-outfit-types-add',
        'item-edit-effects', 'item-edit-apply-condition', 'item-edit-condition-duration',
        'item-edit-incantation', 'item-edit-spell-mode', 'item-edit-clone-item',
        'item-edit-success-chance', 'item-edit-copy-on-give',
        'item-edit-success-text', 'item-edit-fail-text',
        'item-edit-tracks-character',
    ];
    for (const id of ids) {
        const el = document.getElementById(id);
        if (el) el.disabled = !!readOnly;
    }
    for (const id of ['item-edit-covers-add', 'item-edit-partially-covers-add']) {
        const el = document.getElementById(id);
        if (el) el.disabled = !!readOnly;
    }
    document.querySelectorAll('#item-edit-slots-tags .item-edit-cover-tag, #item-edit-covers-tags .item-edit-cover-tag, #item-edit-partially-covers-tags .item-edit-cover-tag').forEach(el => {
        el.style.pointerEvents = readOnly ? 'none' : '';
        el.style.opacity = readOnly ? '0.6' : '';
    });
    // Save / Delete / Image-Gen Buttons ausblenden im Read-Only-Modus
    for (const sel of ['#item-edit-save-btn', '#item-edit-delete-btn', '#item-image-gen-btn']) {
        const el = document.querySelector(sel);
        if (el) el.style.display = readOnly ? 'none' : '';
    }
}

async function _saveItem() {
    const item = {
        name: document.getElementById('item-edit-name').value.trim(),
        description: document.getElementById('item-edit-description').value.trim(),
        category: document.getElementById('item-edit-category').value,
        rarity: document.getElementById('item-edit-rarity').value,
        stackable: document.getElementById('item-edit-stackable').checked,
        transferable: document.getElementById('item-edit-transferable').checked,
        consumable: document.getElementById('item-edit-consumable').checked,
        image_prompt: document.getElementById('item-edit-image-prompt').value.trim(),
        prompt_fragment: (document.getElementById('item-edit-prompt-fragment')?.value || '').trim(),
    };
    // outfit_piece-Daten nur mitschicken wenn die Kategorie es verlangt —
    // sonst wuerde das Backend ohne gueltigen Slot einen Fehler werfen.
    if (item.category === 'outfit_piece') {
        item.outfit_piece = {
            slots: _readItemEditSlots(),
            outfit_types: _readItemOutfitTypes(),
            covers: _readItemEditCovers(),
            partially_covers: _readItemEditPartiallyCovers(),
        };
    }
    // Evidence: reveals_secret nur wenn Sektion sichtbar UND beide Werte gesetzt.
    // Bei outfit_piece/consumable wird die Sektion ausgeblendet und reveals_secret bewusst geleert,
    // damit alte Werte nicht hartnaeckig im Item haengenbleiben.
    const evVisible = document.getElementById('item-edit-evidence-section')?.style.display !== 'none';
    const _rOwner = (document.getElementById('item-edit-reveals-owner')?.value || '').trim();
    const _rSecret = (document.getElementById('item-edit-reveals-secret')?.value || '').trim();
    item.reveals_secret = (evVisible && _rOwner && _rSecret) ? {owner: _rOwner, secret_id: _rSecret} : null;
    // Tracker: only persist when a target is chosen.
    const _trackTarget = (document.getElementById('item-edit-tracks-character')?.value || '').trim();
    item.tracks_character = _trackTarget || null;
    // Consumable-Effects nur wenn Sektion sichtbar parsen — so verschwinden alte Effects
    // automatisch wenn Item nicht mehr consumable ist.
    const consVisible = document.getElementById('item-edit-consumable-section')?.style.display !== 'none';
    if (consVisible) {
        const effects = {};
        const effText = document.getElementById('item-edit-effects')?.value || '';
        effText.split('\n').forEach(line => {
            if (!line.trim()) return;
            const m = line.match(/^\s*(\S+)\s*:\s*(.+)\s*$/);
            if (m) { const val = m[2].trim(); effects[m[1]] = isNaN(Number(val)) ? val : Number(val); }
        });
        const condName = (document.getElementById('item-edit-apply-condition')?.value || '').trim();
        const condDur = parseInt(document.getElementById('item-edit-condition-duration')?.value || '0', 10);
        if (condName) {
            effects.apply_condition = condName;
            if (condDur > 0) effects.condition_duration_hours = condDur;
        }
        item.effects = Object.keys(effects).length > 0 ? effects : null;
    } else {
        item.effects = null;
    }
    // Magic / Spell-Felder — leer = nicht persistieren (null), sonst Wert
    const _incant = (document.getElementById('item-edit-incantation')?.value || '').trim();
    item.incantation = _incant || null;
    if (_incant) {
        item.spell_mode = (document.getElementById('item-edit-spell-mode')?.value || 'force');
        item.clone_item_id = (document.getElementById('item-edit-clone-item')?.value || '').trim() || null;
        const _sc = parseInt(document.getElementById('item-edit-success-chance')?.value || '0', 10);
        item.success_chance = (_sc > 0 && _sc <= 100) ? _sc : 100;
        item.copy_on_give = !!document.getElementById('item-edit-copy-on-give')?.checked;
        item.success_text = (document.getElementById('item-edit-success-text')?.value || '').trim();
        item.fail_text = (document.getElementById('item-edit-fail-text')?.value || '').trim();
        item.cast_activity = (document.getElementById('item-edit-cast-activity')?.value || '').trim() || null;
    } else {
        // Felder leeren wenn keine Incantation gesetzt
        item.spell_mode = null;
        item.clone_item_id = null;
        item.success_chance = null;
        item.copy_on_give = null;
        item.success_text = null;
        item.fail_text = null;
        item.cast_activity = null;
    }
    if (!item.name) { showStatusToast(t('Name missing'), 'error'); return; }
    try {
        const url = _editingItemId ? `/inventory/items/${_editingItemId}` : '/inventory/items';
        const method = _editingItemId ? 'PUT' : 'POST';
        const body = { ...item };
        const resp = await fetch(url, { method, headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) });
        if (resp.ok) {
            const data = await resp.json();
            _editingItemId = data.item?.id || _editingItemId;
            showStatusToast(t('Item saved'), 'success');
            _showItemImagePanel(true);
            await _loadItemsList();  // refresht _itemsCache automatisch
        } else showStatusToast(t('Error'), 'error');
    } catch (e) { showStatusToast(t('Error'), 'error'); }
}

async function _deleteItemById(itemId) {
    if (!confirm('Item loeschen?')) return;
    try {
        await fetch(`/inventory/items/${itemId}`, { method: 'DELETE' });
        if (_editingItemId === itemId) {
            _editingItemId = null;
            document.getElementById('item-edit-form').style.display = 'none';
            document.getElementById('item-placeholder').style.display = 'block';
            _showItemImagePanel(false);
        }
        showStatusToast(t('Deleted'), 'success');
        await _loadItemsList();
    } catch (e) { showStatusToast(t('Error'), 'error'); }
}

async function _generateItemImage() {
    if (!_editingItemId) { showStatusToast(t('Please save the item first'), 'error'); return; }
    // Item-Daten fuer Default-Prompt holen
    let item = null;
    try {
        const r = await fetch(`/inventory/items/${_editingItemId}`);
        if (r.ok) { const d = await r.json(); item = d.item; }
    } catch (_) {}
    const defaultPrompt = (item && item.image_prompt) ||
        (item ? `${item.description || item.name}, isolated object on neutral background, product photography, sharp focus, realistic` : '');
    // prevMeta-aehnliches Konstrukt fuer Dialog (nur Prompt; keine Personen, kein Raum)
    const prevMeta = { prompt: defaultPrompt };

    // Dialog ohne characterName/characterData (kein Charakter-Kontext bei Items)
    const result = await showRegenerateDialog(
        `Item-Bild: ${item?.name || ''}`, '', null, prevMeta, null,
        { itemMode: true }
    );
    if (!result) return;

    const btn = document.getElementById('btn-generate-item-image');
    if (btn) { btn.disabled = true; btn.textContent = 'Generiere...'; }
    try {
        const body = {  };
        if (result.workflow) body.workflow = result.workflow;
        if (result.backend) body.backend = result.backend;
        if (result.model_override) body.model_override = result.model_override;
        if (result.loras) body.loras = result.loras;
        if (result.custom_prompt) body.prompt = result.custom_prompt;
        if (result.negative_prompt) body.negative_prompt = result.negative_prompt;
        const resp = await fetch(`/inventory/items/${_editingItemId}/generate-image`, {
            method: 'POST',
            headers: {'Content-Type':'application/json'},
            body: JSON.stringify(body),
        });
        if (resp.ok) {
            const data = await resp.json();
            showStatusToast(t('Image generated'), 'success');
            if (data.image) {
                _setItemImagePreview(`/inventory/items/${encodeURIComponent(_editingItemId)}/image?t=${Date.now()}`);
            }
        } else {
            const err = await resp.json().catch(() => ({}));
            showStatusToast(err.detail || 'Fehler', 'error');
        }
    } catch (e) { showStatusToast(t('Error'), 'error'); }
    finally { if (btn) { btn.disabled = false; btn.textContent = 'Bild generieren'; } }
}

// --- Rules Engine (Game Admin) ---

async function _loadRulesList() {
    const listEl = document.getElementById('rules-list');
    if (!listEl) return;
    try {
        const resp = await fetch('/rules');
        const data = await resp.json();
        const rules = data.rules || [];
        if (!rules.length) { listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No rules'))}</p>`; return; }
        const blocks = rules.filter(r => r.type === 'block');
        const forces = rules.filter(r => r.type === 'force');
        const discovers = rules.filter(r => r.type === 'discover');
        let html = '';
        const _renderRuleItem = (r) => {
            // Einheitlich mit Activities: Shared=blau, World/World-Override=gruen.
            const isShared = (r._origin || '') === 'shared';
            const bgColor = isShared ? 'rgba(70,130,180,0.08)' : 'rgba(80,160,80,0.08)';
            const badgeBg = isShared ? 'rgba(70,130,180,0.25)' : 'rgba(80,160,80,0.25)';
            const originLabel = isShared ? 'Allgemein' : 'Weltspezifisch';
            const originBadge = `<span style="font-size:9px;padding:1px 5px;border-radius:3px;background:${badgeBg};margin-right:4px;">${originLabel}</span>`;
            return `<div class="world-item" style="padding:4px 8px;cursor:pointer;background:${bgColor};" onclick="_editRule('${escapeHtml(r.id)}')">
                <div class="world-item-info"><strong style="font-size:12px;">${originBadge}${escapeHtml(r.name || '?')}</strong>
                <span class="world-item-desc" style="font-size:10px;">${escapeHtml(r.condition || '')}</span></div>
                <button class="job-delete-btn" onclick="event.stopPropagation();_deleteRuleById('${escapeHtml(r.id)}')" title="Loeschen">&times;</button></div>`;
        };
        if (blocks.length) {
            html += '<div style="margin-bottom:8px;"><strong style="font-size:12px;color:var(--text-muted);">Blockaden</strong>';
            for (const r of blocks) html += _renderRuleItem(r);
            html += '</div>';
        }
        if (forces.length) {
            html += '<div style="margin-bottom:8px;"><strong style="font-size:12px;color:var(--text-muted);">Zwaenge</strong>';
            for (const r of forces) html += _renderRuleItem(r);
            html += '</div>';
        }
        if (discovers.length) {
            html += '<div><strong style="font-size:12px;color:var(--text-muted);">Entdeckungen</strong>';
            for (const r of discovers) html += _renderRuleItem(r);
            html += '</div>';
        }
        listEl.innerHTML = html;
        // Dropdowns befuellen — nur Unique-Orte als Regel-Ziel (passable=false).
        // Templates + Klone sind als Rule-Target irrefuehrend (Regel wuerde
        // entweder am Template oder an einem zufaelligen Klon haengen).
        const locSel = document.getElementById('rule-target-location');
        if (locSel && _cachedWorldLocations) {
            const onlyUnique = _cachedWorldLocations.filter(l => !l.passable);
            locSel.innerHTML = '<option value="">-- Ort waehlen --</option>' + onlyUnique.map(l => `<option value="${escapeHtml(l.id)}">${escapeHtml(l.name)}</option>`).join('');
            locSel.onchange = () => _updateRuleRoomDropdown();
        }
        // Aktivitaets-Dropdown fuer Zwang
        const actSel = document.getElementById('rule-force-activity');
        if (actSel && _libActivityGroups) {
            actSel.innerHTML = _buildGroupedActivityOptions('');
        }
    } catch (e) { console.error('Rules load error:', e); }
}

let _editingRuleId = null;

let _editingRuleOrigin = '';

function _setRuleOriginBanner(origin) {
    const banner = document.getElementById('rule-edit-origin-banner');
    const removeBtn = document.getElementById('rule-edit-remove-override');
    if (!banner) return;
    if (!origin) {
        banner.style.display = 'none';
        if (removeBtn) removeBtn.style.display = 'none';
        return;
    }
    const isShared = (origin === 'shared');
    banner.style.display = 'block';
    banner.style.background = isShared ? 'rgba(70,130,180,0.15)' : 'rgba(80,160,80,0.15)';
    banner.style.color = isShared ? '#79c0ff' : '#7fbf7f';
    if (isShared) {
        banner.textContent = '🌐 Allgemein — Aenderung gilt fuer ALLE Welten.';
    } else if (origin === 'world override') {
        banner.textContent = '🌍 Weltspezifisch — ueberschreibt eine gleichnamige Allgemein-Rule. Override entfernen, um zurueck auf die Baseline zu fallen.';
    } else {
        banner.textContent = '🌍 Weltspezifisch — nur in dieser Welt aktiv.';
    }
    if (removeBtn) removeBtn.style.display = (origin === 'world override') ? '' : 'none';
}

function _newRule() {
    _editingRuleId = null;
    _editingRuleOrigin = '';
    document.getElementById('rule-edit-form').style.display = 'flex';
    document.getElementById('rule-placeholder').style.display = 'none';
    document.getElementById('rule-edit-id').value = '';
    document.getElementById('rule-edit-name').value = '';
    document.getElementById('rule-edit-type').value = 'block';
    document.getElementById('rule-edit-condition').value = '';
    document.getElementById('rule-edit-message').value = '';
    const _targetEl = document.getElementById('rule-edit-target');
    if (_targetEl) _targetEl.value = 'world';
    _setRuleOriginBanner('');
    const _probEl = document.getElementById('rule-discover-probability');
    if (_probEl) _probEl.value = '0.05';
    const _charSel = document.getElementById('rule-edit-character');
    if (_charSel) { _populateRuleCharacterDropdown(''); }
    const _faSelNew = document.getElementById('rule-force-activity');
    if (_faSelNew && _libActivityGroups) _faSelNew.innerHTML = _buildGroupedActivityOptions('');
    _toggleRuleFields();
}

async function _populateRuleCharacterDropdown(selected) {
    const sel = document.getElementById('rule-edit-character');
    if (!sel) return;
    let chars = [];
    try {
        const r = await fetch('/characters/list');
        if (r.ok) {
            const d = await r.json();
            chars = (d.characters || []).map(c => typeof c === 'string' ? c : c.name).filter(Boolean);
        }
    } catch (_) {}
    chars.sort((a, b) => a.localeCompare(b));
    const opts = ['<option value="">— alle Characters —</option>'];
    for (const c of chars) {
        const sel_attr = c === selected ? ' selected' : '';
        opts.push(`<option value="${escapeHtml(c)}"${sel_attr}>${escapeHtml(c)}</option>`);
    }
    sel.innerHTML = opts.join('');
    if (selected && !chars.includes(selected)) {
        // Unbekannter Character (gelöscht?) — trotzdem darstellen
        sel.insertAdjacentHTML('beforeend',
            `<option value="${escapeHtml(selected)}" selected>${escapeHtml(selected)} (nicht gefunden)</option>`);
    }
}

async function _editRule(ruleId) {
    try {
        const resp = await fetch(`/rules/${ruleId}`);
        if (!resp.ok) return;
        const data = await resp.json();
        const r = data.rule;
        _editingRuleId = r.id;
        _editingRuleOrigin = r._origin || 'world';
        document.getElementById('rule-edit-form').style.display = 'flex';
        document.getElementById('rule-placeholder').style.display = 'none';
        document.getElementById('rule-edit-id').value = r.id;
        document.getElementById('rule-edit-name').value = r.name || '';
        document.getElementById('rule-edit-type').value = r.type || 'block';
        document.getElementById('rule-edit-condition').value = r.condition || '';
        document.getElementById('rule-edit-message').value = r.message || '';
        const _targetEl = document.getElementById('rule-edit-target');
        if (_targetEl) {
            // Bei world-override defaultet auf "world" — speichern updated den Override.
            _targetEl.value = (_editingRuleOrigin === 'shared') ? 'shared' : 'world';
        }
        _setRuleOriginBanner(_editingRuleOrigin);
        await _populateRuleCharacterDropdown(r.character || '');
        if (r.target) {
            // 'room' und 'location' teilen sich den Picker — UI zeigt 'location'
            const _scopeUi = (r.target.scope === 'room') ? 'location' : (r.target.scope || 'location');
            document.getElementById('rule-target-scope').value = _scopeUi;
            document.getElementById('rule-target-action').value = r.action || 'enter';
            if (r.target.location_id) document.getElementById('rule-target-location').value = r.target.location_id;
            if (r.target.min_danger) document.getElementById('rule-target-min-danger').value = r.target.min_danger;
        }
        if (r.force_action) {
            document.getElementById('rule-force-goto').value = r.force_action.go_to || 'stay';
            // Aktivitaets-Dropdown befuellen und Wert setzen
            const faSel = document.getElementById('rule-force-activity');
            if (faSel && _libActivityGroups) faSel.innerHTML = _buildGroupedActivityOptions(r.force_action.set_activity || '');
        }
        const probEl = document.getElementById('rule-discover-probability');
        if (probEl) probEl.value = (r.probability != null) ? String(r.probability) : '0.05';
        // Ort-Dropdown: Raum laden wenn Location gesetzt
        if (r.target?.location_id) {
            setTimeout(() => {
                document.getElementById('rule-target-location').value = r.target.location_id;
                _updateRuleRoomDropdown();
                const roomSel = document.getElementById('rule-target-room');
                const ids = Array.isArray(r.target.room_ids) ? r.target.room_ids : [];
                if (roomSel && ids.length) {
                    Array.from(roomSel.options).forEach(o => { o.selected = ids.includes(o.value); });
                }
            }, 50);
        }
        _toggleRuleFields();
    } catch (e) { console.error('Rule edit error:', e); }
}

function _toggleRuleFields() {
    const type = document.getElementById('rule-edit-type').value;
    document.getElementById('rule-block-fields').style.display = type === 'block' ? '' : 'none';
    document.getElementById('rule-force-fields').style.display = type === 'force' ? '' : 'none';
    const discEl = document.getElementById('rule-discover-fields');
    if (discEl) discEl.style.display = type === 'discover' ? '' : 'none';
    // Bedingung-Block bei Block-Typ in die rechte Spalte einhaengen, sonst zurueck
    // an seine Default-Position (vor dem Meldung-Label).
    const condBlock = document.getElementById('rule-condition-block');
    const condSlot = document.getElementById('rule-condition-slot');
    if (condBlock && condSlot) {
        if (type === 'block') {
            if (condBlock.parentElement !== condSlot) condSlot.appendChild(condBlock);
        } else {
            const msgLabel = document.querySelector('#rule-edit-form > label[for], #rule-edit-form > label');
            const msgInput = document.getElementById('rule-edit-message');
            const form = document.getElementById('rule-edit-form');
            if (form && msgInput) {
                const msgLabelEl = msgInput.previousElementSibling;
                if (msgLabelEl && condBlock.parentElement !== form) {
                    form.insertBefore(condBlock, msgLabelEl);
                }
            }
        }
    }
    _toggleRuleTargetFields();
}

function _toggleRuleTargetFields() {
    const scope = document.getElementById('rule-target-scope').value;
    // any_room: kein Location/Room-Picker noetig (gilt global)
    const showLocFields = scope !== 'danger_level' && scope !== 'any_room';
    document.getElementById('rule-target-loc-fields').style.display = showLocFields ? '' : 'none';
    document.getElementById('rule-target-room').style.display = showLocFields ? '' : 'none';
    document.getElementById('rule-target-danger-fields').style.display = scope === 'danger_level' ? '' : 'none';
    if (showLocFields) _updateRuleRoomDropdown();
}

async function _saveRule() {
    const type = document.getElementById('rule-edit-type').value;
    const name = document.getElementById('rule-edit-name').value.trim();
    if (!name) {
        showStatusToast(t('Name is required'), 'error');
        document.getElementById('rule-edit-name').focus();
        return;
    }
    const rule = {
        name,
        type,
        condition: document.getElementById('rule-edit-condition').value.trim(),
        message: document.getElementById('rule-edit-message').value.trim(),
    };
    const character = (document.getElementById('rule-edit-character')?.value || '').trim();
    if (character) rule.character = character;
    if (type === 'block') {
        const scopeRaw = document.getElementById('rule-target-scope').value;
        rule.action = document.getElementById('rule-target-action').value;
        if (scopeRaw === 'danger_level') {
            rule.target = { scope: 'danger_level', min_danger: parseInt(document.getElementById('rule-target-min-danger').value) || 3 };
        } else if (scopeRaw === 'any_room') {
            rule.target = { scope: 'any_room' };
        } else {
            const locId = document.getElementById('rule-target-location').value;
            const roomSel = document.getElementById('rule-target-room');
            const roomIds = roomSel ? Array.from(roomSel.selectedOptions).map(o => o.value).filter(Boolean) : [];
            rule.target = { scope: roomIds.length ? 'room' : 'location', location_id: locId };
            if (roomIds.length) rule.target.room_ids = roomIds;
        }
    } else if (type === 'force') {
        const actSel = document.getElementById('rule-force-activity');
        rule.force_action = {
            go_to: document.getElementById('rule-force-goto').value,
            set_activity: actSel?.value || '',
        };
    } else if (type === 'discover') {
        const probRaw = document.getElementById('rule-discover-probability').value;
        let prob = parseFloat(probRaw);
        if (!isFinite(prob)) prob = 0;
        rule.probability = Math.max(0, Math.min(1, prob));
    }
    const target = (document.getElementById('rule-edit-target')?.value || 'world');
    // Bestimmen ob das ein "Speicherort-Wechsel" ist — dann POST (Upsert) statt
    // PUT, weil der Eintrag im neuen Target noch nicht existiert.
    const _currentLayer = (_editingRuleOrigin === 'shared') ? 'shared' : 'world';
    const _isMove = !!_editingRuleId && (_currentLayer !== target);
    try {
        let url, method;
        if (!_editingRuleId || _isMove) {
            // Neu oder Move → POST (upsert, ID wird mitgesendet wenn vorhanden)
            url = '/rules';
            method = 'POST';
            if (_editingRuleId) rule.id = _editingRuleId;
        } else {
            url = `/rules/${_editingRuleId}`;
            method = 'PUT';
        }
        // Bei Move zuerst alten Ort loeschen, damit die Rule nicht parallel
        // in shared+world existiert (analog Activities-Editor).
        if (_isMove) {
            await fetch(`/rules/${_editingRuleId}?target=${_currentLayer}`, { method: 'DELETE' }).catch(() => {});
        }
        const resp = await fetch(url, { method, headers: {'Content-Type':'application/json'}, body: JSON.stringify({rule, target}) });
        if (resp.ok) {
            showStatusToast(t('Rule saved') + ` (${target === 'shared' ? t('Shared') : t('World-specific')})`, 'success');
            await _loadRulesList();
        } else {
            let detail = `HTTP ${resp.status}`;
            try { const err = await resp.json(); if (err?.detail) detail = err.detail; } catch (_) {}
            showStatusToast(t('Error') + `: ${detail}`, 'error');
        }
    } catch (e) {
        showStatusToast(t('Error') + `: ${e.message || e}`, 'error');
    }
}

async function _deleteRule() {
    if (!_editingRuleId) return;
    await _deleteRuleById(_editingRuleId);
    _editingRuleId = null;
    _editingRuleOrigin = '';
    document.getElementById('rule-edit-form').style.display = 'none';
    document.getElementById('rule-placeholder').style.display = 'block';
}

async function _deleteRuleById(ruleId) {
    if (!confirm('Regel loeschen? (Shared baseline wird bei reinem World-Eintrag nicht angetastet.)')) return;
    try {
        await fetch(`/rules/${ruleId}`, { method: 'DELETE' });
        showStatusToast(t('Deleted'), 'success');
        await _loadRulesList();
    } catch (e) { showStatusToast(t('Error'), 'error'); }
}

async function _deleteRuleOverride() {
    // Nur fuer "world override" — entfernt den Welt-Eintrag, damit die
    // Shared-Baseline wieder durchgereicht wird.
    if (!_editingRuleId) return;
    if (!confirm('World-Override entfernen? Die Shared-Baseline wird wieder aktiv.')) return;
    try {
        const resp = await fetch(`/rules/${_editingRuleId}?target=world`, { method: 'DELETE' });
        if (resp.ok) {
            showStatusToast(t('Override removed — shared baseline active'), 'success');
            _editingRuleId = null;
            _editingRuleOrigin = '';
            document.getElementById('rule-edit-form').style.display = 'none';
            document.getElementById('rule-placeholder').style.display = 'block';
            await _loadRulesList();
        } else {
            let detail = `HTTP ${resp.status}`;
            try { const err = await resp.json(); if (err?.detail) detail = err.detail; } catch (_) {}
            showStatusToast(t('Error') + `: ${detail}`, 'error');
        }
    } catch (e) { showStatusToast(t('Error'), 'error'); }
}

function _updateRuleRoomDropdown() {
    const locId = document.getElementById('rule-target-location')?.value || '';
    const roomSel = document.getElementById('rule-target-room');
    if (!roomSel) return;
    if (!locId || !_cachedWorldLocations) {
        roomSel.innerHTML = '';
        return;
    }
    const loc = _cachedWorldLocations.find(l => l.id === locId);
    const rooms = loc?.rooms || [];
    roomSel.innerHTML = rooms.map(r => `<option value="${escapeHtml(r.id)}">${escapeHtml(r.name)}</option>`).join('');
}

// --- Prompt Filters (state-driven prompt block dropping) ---

let _pfBlockKeys = [];
let _pfCachedFilters = [];

async function _loadPromptFiltersList() {
    const listEl = document.getElementById('prompt-filters-list');
    if (!listEl) return;
    try {
        const resp = await fetch('/admin/prompt-filters/data');
        if (!resp.ok) {
            listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
            return;
        }
        const data = await resp.json();
        _pfBlockKeys = data.block_keys || [];
        _pfCachedFilters = data.filters || [];
        if (!_pfCachedFilters.length) {
            listEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No filters'))}</p>`;
            return;
        }
        let html = '';
        _pfCachedFilters.forEach((f, i) => {
            const src = f.source || 'shared';
            const srcColor = src === 'shared' ? '#79c0ff'
                           : src === 'world override' ? '#f0b04c'
                           : '#56d364';
            const enabledMark = f.enabled === false ? ' (off)' : '';
            html += `<div class="world-item" style="padding:4px 8px;cursor:pointer;" onclick="_editPromptFilter(${i})">
                <div class="world-item-info">
                    <strong style="font-size:12px;font-family:monospace;">${escapeHtml(f.id || '?')}${enabledMark}</strong>
                    <span class="world-item-desc" style="font-size:10px;">${escapeHtml(f.condition || '')}</span>
                    <span style="font-size:9px;color:${srcColor};text-transform:uppercase;letter-spacing:0.5px;">${escapeHtml(src)}</span>
                </div>
            </div>`;
        });
        listEl.innerHTML = html;
    } catch (e) {
        console.error('Prompt filters load error:', e);
        listEl.innerHTML = '<p class="scheduler-empty">Fehler</p>';
    }
}

function _renderPfBlockChips(selected) {
    const container = document.getElementById('pf-edit-blocks');
    if (!container) return;
    container.innerHTML = '';
    const sel = new Set(selected || []);
    _pfBlockKeys.forEach(key => {
        const chip = document.createElement('span');
        chip.dataset.block = key;
        chip.textContent = key;
        chip.style.cssText = 'font-size:11px;padding:3px 9px;border-radius:12px;cursor:pointer;user-select:none;font-family:monospace;border:1px solid var(--border);';
        if (sel.has(key)) {
            chip.classList.add('selected');
            chip.style.background = '#1a5132';
            chip.style.borderColor = '#2ea043';
            chip.style.color = '#56d364';
        } else {
            chip.style.background = 'var(--bg-secondary, #21262d)';
            chip.style.color = 'var(--text-muted)';
        }
        chip.onclick = () => {
            const isSelected = chip.classList.toggle('selected');
            if (isSelected) {
                chip.style.background = '#1a5132';
                chip.style.borderColor = '#2ea043';
                chip.style.color = '#56d364';
            } else {
                chip.style.background = 'var(--bg-secondary, #21262d)';
                chip.style.borderColor = 'var(--border)';
                chip.style.color = 'var(--text-muted)';
            }
        };
        container.appendChild(chip);
    });
}

