function _togglePfIconPicker() {
    const box = document.getElementById('pf-edit-icon-picker');
    if (!box) return;
    if (box.style.display === 'none' || !box.style.display) {
        _renderPfIconPicker();
        box.style.display = 'block';
        // Outside-Click Listener einmalig
        setTimeout(() => document.addEventListener('click', _pfIconPickerOutsideClick), 0);
    } else {
        _closePfIconPicker();
    }
}

function _closePfIconPicker() {
    const box = document.getElementById('pf-edit-icon-picker');
    if (box) box.style.display = 'none';
    document.removeEventListener('click', _pfIconPickerOutsideClick);
}

function _pfIconPickerOutsideClick(e) {
    if (e.target.closest('#pf-edit-icon-picker') ||
        e.target.id === 'pf-edit-icon-picker-btn' ||
        e.target.id === 'pf-edit-icon') return;
    _closePfIconPicker();
}

function _renderPfIconPicker() {
    const box = document.getElementById('pf-edit-icon-picker');
    if (!box) return;
    let html = '';
    for (const g of _PF_ICON_GROUPS) {
        html += `<div style="font-size:10px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.3px;margin:4px 2px 2px 2px;">${g.label}</div>`;
        html += '<div style="display:flex;flex-wrap:wrap;gap:2px;">';
        for (const em of g.emojis) {
            html += `<button type="button" onclick="_pickPfIcon('${em}')" title="${em}" style="width:26px;height:26px;border:none;background:transparent;cursor:pointer;font-size:18px;border-radius:4px;padding:0;line-height:1;">${em}</button>`;
        }
        html += '</div>';
    }
    box.innerHTML = html;
    // Hover-Style fuer Buttons via inline event
    box.querySelectorAll('button').forEach(b => {
        b.addEventListener('mouseenter', () => b.style.background = 'var(--bg-elev)');
        b.addEventListener('mouseleave', () => b.style.background = 'transparent');
    });
}

function _pickPfIcon(emoji) {
    const inp = document.getElementById('pf-edit-icon');
    if (inp) {
        inp.value = emoji;
        inp.focus();
    }
    _closePfIconPicker();
}

function _newPromptFilter() {
    document.getElementById('prompt-filter-edit-form').style.display = 'flex';
    document.getElementById('prompt-filter-placeholder').style.display = 'none';
    document.getElementById('pf-edit-original-id').value = '';
    document.getElementById('pf-edit-source').value = 'world';
    document.getElementById('pf-edit-id').value = '';
    document.getElementById('pf-edit-id').readOnly = false;
    document.getElementById('pf-edit-label').value = '';
    document.getElementById('pf-edit-condition').value = '';
    document.getElementById('pf-edit-modifier').value = '';
    document.getElementById('pf-edit-icon').value = '';
    document.getElementById('pf-edit-image').value = '';
    document.getElementById('pf-edit-enabled').checked = true;
    document.getElementById('pf-edit-source-info').textContent = 'Neuer World-Zustand.';
    document.getElementById('pf-edit-delete-btn').style.display = 'none';
    _renderPfBlockChips([]);
}

function _editPromptFilter(idx) {
    const f = _pfCachedFilters[idx];
    if (!f) return;
    document.getElementById('prompt-filter-edit-form').style.display = 'flex';
    document.getElementById('prompt-filter-placeholder').style.display = 'none';
    document.getElementById('pf-edit-original-id').value = f.id || '';
    document.getElementById('pf-edit-source').value = f.source || 'shared';
    document.getElementById('pf-edit-id').value = f.id || '';
    document.getElementById('pf-edit-id').readOnly = true;  // Vorhandene id nicht aenderbar
    document.getElementById('pf-edit-label').value = f.label || '';
    document.getElementById('pf-edit-condition').value = f.condition || '';
    document.getElementById('pf-edit-modifier').value = f.prompt_modifier || '';
    document.getElementById('pf-edit-icon').value = f.icon || '';
    document.getElementById('pf-edit-image').value = f.image_modifier || '';
    document.getElementById('pf-edit-enabled').checked = f.enabled !== false;
    const src = f.source || 'shared';
    let info;
    if (src === 'shared') {
        info = 'Shared baseline. Speichern erstellt einen World-Override.';
    } else if (src === 'world override') {
        info = 'World-Override. Delete revert auf Shared baseline.';
    } else {
        info = 'World-only Zustand. Delete entfernt komplett.';
    }
    document.getElementById('pf-edit-source-info').textContent = info;
    document.getElementById('pf-edit-delete-btn').style.display = (src === 'shared') ? 'none' : '';
    _renderPfBlockChips(f.drop_blocks || []);
}

async function _savePromptFilter() {
    const idEl = document.getElementById('pf-edit-id');
    const id = (idEl.value || '').trim();
    if (!id) { showStatusToast(t('id missing'), 'error'); return; }
    if (!/^[a-z0-9_]+$/i.test(id)) {
        showStatusToast(t('id may only contain letters/numbers/_'), 'error');
        return;
    }
    // condition optional — Filter-id triggert ueber den Profil-Tag,
    // diese Expression ist nur Zusatz-Trigger (z.B. stamina<10).
    const condition = document.getElementById('pf-edit-condition').value.trim();
    const label = document.getElementById('pf-edit-label').value.trim();
    const prompt_modifier = document.getElementById('pf-edit-modifier').value.trim();
    const icon = document.getElementById('pf-edit-icon').value.trim();
    const image_modifier = document.getElementById('pf-edit-image').value.trim();
    const enabled = document.getElementById('pf-edit-enabled').checked;
    const drop_blocks = [...document.querySelectorAll('#pf-edit-blocks .selected')]
        .map(c => c.dataset.block);
    try {
        const resp = await fetch('/admin/prompt-filters/save', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({id, condition, label,
                drop_blocks, prompt_modifier, icon, image_modifier, enabled}),
        });
        if (!resp.ok) {
            const t = await resp.text();
            showStatusToast(t('Save failed') + ': ' + t.slice(0, 80), 'error');
            return;
        }
        showStatusToast(t('Filter saved'), 'success');
        _invalidateConditionsCache();
        await _loadPromptFiltersList();
    } catch (e) {
        showStatusToast(t('Save error'), 'error');
    }
}

async function _deletePromptFilter() {
    const id = document.getElementById('pf-edit-original-id').value;
    const src = document.getElementById('pf-edit-source').value;
    if (!id) return;
    const msg = src === 'world override'
        ? `World-Override fuer "${id}" entfernen? Shared baseline bleibt aktiv.`
        : `Filter "${id}" komplett entfernen?`;
    if (!confirm(msg)) return;
    try {
        const resp = await fetch('/admin/prompt-filters/' + encodeURIComponent(id), {method: 'DELETE'});
        if (!resp.ok) {
            const t = await resp.text();
            showStatusToast(t('Delete failed') + ': ' + t.slice(0, 80), 'error');
            return;
        }
        document.getElementById('prompt-filter-edit-form').style.display = 'none';
        document.getElementById('prompt-filter-placeholder').style.display = 'block';
        showStatusToast(t('Deleted'), 'success');
        _invalidateConditionsCache();
        await _loadPromptFiltersList();
    } catch (e) {
        showStatusToast(t('Delete error'), 'error');
    }
}

// --- Activity Overrides (Character + Location) ---

async function _loadOverrides() {
    const listEl = document.getElementById('activity-override-list');
    if (!listEl) return;
    try {
        // Alle Characters und Locations laden
        const [charsResp, locsResp] = await Promise.all([
            fetch(`/account/characters`),
            fetch(`/world/locations`),
        ]);
        const chars = charsResp.ok ? (await charsResp.json()).characters || [] : [];
        const locs = locsResp.ok ? (await locsResp.json()).locations || [] : [];

        let html = '';
        // Character-Overrides
        for (const charName of chars) {
            try {
                const resp = await fetch(`/activities/overrides/character/${encodeURIComponent(charName)}`);
                if (!resp.ok) continue;
                const data = await resp.json();
                const overrides = data.activity_overrides || {};
                for (const [actId, ov] of Object.entries(overrides)) {
                    const effStr = ov.effects ? Object.entries(ov.effects).filter(([,v]) => v).map(([k,v]) => `${k.replace('_change','')}: ${v > 0 ? '+' : ''}${v}`).join(', ') : '';
                    html += `<div class="world-item" style="padding:3px 8px;background:rgba(200,150,50,0.08);cursor:pointer;" onclick="_editOverride('character','${escapeHtml(charName)}','${escapeHtml(actId)}')">`;
                    html += `<div class="world-item-info" style="gap:1px;">`;
                    html += `<strong style="font-size:11px;">${escapeHtml(actId)} → ${escapeHtml(charName)}</strong>`;
                    html += `<span class="world-item-desc" style="font-size:10px;">${effStr || JSON.stringify(ov).substring(0, 80)}</span>`;
                    html += `</div>`;
                    html += `<button class="job-delete-btn" style="font-size:10px;" onclick="event.stopPropagation();_deleteOverride('character','${escapeHtml(charName)}','${escapeHtml(actId)}')" title="Loeschen">🗑️</button>`;
                    html += `</div>`;
                }
            } catch(e) {}
        }
        // Location-Overrides
        for (const loc of locs) {
            const locOv = loc.activity_overrides || {};
            for (const [actId, ov] of Object.entries(locOv)) {
                const effStr = ov.effects ? Object.entries(ov.effects).filter(([,v]) => v).map(([k,v]) => `${k.replace('_change','')}: ${v > 0 ? '+' : ''}${v}`).join(', ') : '';
                html += `<div class="world-item" style="padding:3px 8px;background:rgba(200,100,50,0.08);cursor:pointer;" onclick="_editOverride('location','${escapeHtml(loc.id)}','${escapeHtml(actId)}')">`;
                html += `<div class="world-item-info" style="gap:1px;">`;
                html += `<strong style="font-size:11px;">${escapeHtml(actId)} → ${escapeHtml(loc.name || loc.id)}</strong>`;
                html += `<span class="world-item-desc" style="font-size:10px;">${effStr || JSON.stringify(ov).substring(0, 80)}</span>`;
                html += `</div>`;
                html += `<button class="job-delete-btn" style="font-size:10px;" onclick="event.stopPropagation();_deleteOverride('location','${escapeHtml(loc.id)}','${escapeHtml(actId)}')" title="Loeschen">🗑️</button>`;
                html += `</div>`;
            }
        }
        listEl.innerHTML = html || `<p class="scheduler-empty">${escapeHtml(t('No overrides'))}</p>`;
    } catch(e) {
        console.error('[Overrides] Fehler:', e);
    }
}

// Override-Daten fuer aktuellen Edit
let _overrideEditing = null; // { type, target, actId } wenn bestehender Override bearbeitet wird

async function _newOverrideForm() {
    _overrideEditing = null;
    _showOverrideColumns();
    document.getElementById('override-form-title').textContent = 'Neuer Override';
    // Aktivitaeten-Dropdown befuellen
    await _populateOverrideActivityList();
    document.getElementById('override-act-id').value = '';
    document.getElementById('override-type').value = 'character';
    await _updateOverrideTargetList();
    document.getElementById('override-target').value = '';
    document.getElementById('override-effects').value = '';
    document.getElementById('override-condition').value = '';
    document.getElementById('override-visibility').value = '';
    // Cumulative Override leeren
    ['override-cum-threshold','override-cum-modifier','override-cum-mood','override-cum-duration'].forEach(id => {
        const el = document.getElementById(id); if (el) el.value = '';
    });
    await _populateConditionSelect(document.getElementById('override-cum-name'), '');
}

async function _editOverride(type, target, actId) {
    _overrideEditing = { type, target, actId };
    _showOverrideColumns();
    document.getElementById('override-form-title').textContent = 'Override bearbeiten';
    await _populateOverrideActivityList();
    document.getElementById('override-act-id').value = actId;
    document.getElementById('override-type').value = type;
    await _updateOverrideTargetList();
    document.getElementById('override-target').value = target;
    // Override-Daten laden
    try {
        const resp = await fetch(`/activities/overrides/${type}/${encodeURIComponent(target)}`);
        if (resp.ok) {
            const data = await resp.json();
            const overrides = (type === 'character') ? (data.activity_overrides || {}) : (data.activity_overrides || {});
            const ov = overrides[actId] || {};
            // Effects
            const effEl = document.getElementById('override-effects');
            if (effEl && ov.effects) {
                effEl.value = Object.entries(ov.effects).filter(([,v]) => v !== 0 && v !== null).map(([k,v]) => `${k}: ${v}`).join('\n');
            } else if (effEl) { effEl.value = ''; }
            document.getElementById('override-condition').value = ov.condition || '';
            document.getElementById('override-visibility').value = ov.visibility || '';
            // Cumulative Override
            const cum = ov.cumulative_effect || {};
            document.getElementById('override-cum-threshold').value = cum.threshold ? String(cum.threshold) : '';
            await _populateConditionSelect(document.getElementById('override-cum-name'), cum.condition_name || '');
            document.getElementById('override-cum-modifier').value = cum.prompt_modifier || '';
            document.getElementById('override-cum-mood').value = cum.mood_influence || '';
            document.getElementById('override-cum-duration').value = cum.duration_hours ? String(cum.duration_hours) : '';
        }
    } catch(e) {
        console.error('[Override] Load Fehler:', e);
    }
}

function _cancelOverrideEdit() {
    _overrideEditing = null;
    _hideAllEditForms();
}

async function _prefillOverrideFromActivity() {
    const actId = document.getElementById('override-act-id').value;
    if (!actId) return;
    // Nur vorbelegen wenn es ein neuer Override ist (nicht beim Bearbeiten)
    if (_overrideEditing && _overrideEditing.actId === actId) return;
    try {
        const resp = await fetch(`/activities/library/${encodeURIComponent(actId)}`);
        if (!resp.ok) return;
        const act = (await resp.json()).activity;
        // Effects vorbelegen
        const effEl = document.getElementById('override-effects');
        if (effEl && act.effects) {
            effEl.value = Object.entries(act.effects).filter(([,v]) => v !== 0 && v !== null && v !== '').map(([k,v]) => `${k}: ${v}`).join('\n');
        } else if (effEl) { effEl.value = ''; }
        // Condition
        document.getElementById('override-condition').value = act.condition || '';
        // Visibility
        document.getElementById('override-visibility').value = act.visibility || '';
        // Cumulative vorbelegen
        const cum = act.cumulative_effect || {};
        document.getElementById('override-cum-threshold').value = cum.threshold ? String(cum.threshold) : '';
        await _populateConditionSelect(document.getElementById('override-cum-name'), cum.condition_name || '');
        document.getElementById('override-cum-modifier').value = cum.prompt_modifier || '';
        document.getElementById('override-cum-mood').value = cum.mood_influence || '';
        document.getElementById('override-cum-duration').value = cum.duration_hours ? String(cum.duration_hours) : '';
    } catch(e) {
        console.error('[Override] Prefill Fehler:', e);
    }
}

async function _populateOverrideActivityList() {
    const sel = document.getElementById('override-act-id');
    if (!sel) return;
    try {
        const resp = await fetch(`/activities/library`);
        const data = await resp.json();
        const groups = data.groups || {};
        let html = '<option value="">-- Aktivitaet waehlen --</option>';
        for (const [groupName, acts] of Object.entries(groups)) {
            html += `<optgroup label="${escapeHtml(groupName)}">`;
            for (const act of acts) {
                html += `<option value="${escapeHtml(act.id)}">${escapeHtml(act.name)}</option>`;
            }
            html += `</optgroup>`;
        }
        sel.innerHTML = html;
    } catch(e) {}
}

async function _updateOverrideTargetList() {
    const type = document.getElementById('override-type').value;
    const sel = document.getElementById('override-target');
    if (!sel) return;
    try {
        if (type === 'character') {
            const resp = await fetch(`/account/characters`);
            const data = resp.ok ? await resp.json() : {};
            const chars = data.characters || [];
            sel.innerHTML = '<option value="">-- Character waehlen --</option>' +
                chars.map(c => `<option value="${escapeHtml(c)}">${escapeHtml(c)}</option>`).join('');
        } else {
            const resp = await fetch(`/world/locations`);
            const data = resp.ok ? await resp.json() : {};
            const locs = data.locations || [];
            sel.innerHTML = '<option value="">-- Location waehlen --</option>' +
                locs.map(l => `<option value="${escapeHtml(l.id || l.name)}">${escapeHtml(l.name)}</option>`).join('');
        }
    } catch(e) {}
    // Vorherigen Wert wiederherstellen wenn moeglich
    if (_overrideEditing) sel.value = _overrideEditing.target;
}

async function _saveOverrideForm() {
    const actId = document.getElementById('override-act-id').value;
    const type = document.getElementById('override-type').value;
    const target = document.getElementById('override-target').value;
    if (!actId || !target) { showStatusToast(t('Activity and target are required'), 'error'); return; }

    const override = {};
    // Effects parsen
    const effText = document.getElementById('override-effects').value || '';
    if (effText.trim()) {
        override.effects = {};
        effText.split('\n').forEach(line => {
            if (!line.trim()) return;
            const m = line.match(/^\s*(\S+)\s*:\s*(.+)\s*$/);
            if (m) { const v = m[2].trim(); override.effects[m[1]] = isNaN(Number(v)) ? v : Number(v); }
        });
    }
    const cond = document.getElementById('override-condition').value.trim();
    if (cond) override.condition = cond;
    const vis = document.getElementById('override-visibility').value;
    if (vis) override.visibility = vis;
    // Cumulative Override
    const cumTh = parseInt(document.getElementById('override-cum-threshold').value) || 0;
    const cumName = document.getElementById('override-cum-name').value.trim();
    if (cumTh > 0 && cumName) {
        override.cumulative_effect = {
            threshold: cumTh,
            condition_name: cumName,
            prompt_modifier: document.getElementById('override-cum-modifier').value.trim(),
            mood_influence: document.getElementById('override-cum-mood').value.trim(),
            duration_hours: parseInt(document.getElementById('override-cum-duration').value) || 2,
        };
    }

    // Alten Override loeschen wenn Aktivitaet/Ziel geaendert
    if (_overrideEditing && (_overrideEditing.actId !== actId || _overrideEditing.target !== target || _overrideEditing.type !== type)) {
        try {
            await fetch(`/activities/overrides/${_overrideEditing.type}/${encodeURIComponent(_overrideEditing.target)}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ activity_id: _overrideEditing.actId, override: {} })
            });
        } catch(e) {}
    }

    try {
        const resp = await fetch(`/activities/overrides/${type}/${encodeURIComponent(target)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ activity_id: actId, override })
        });
        if (resp.ok) {
            showStatusToast(t('Override saved'), 'success');
            _overrideEditing = { type, target, actId };
            await _loadOverrides();
        } else {
            showStatusToast(t('Error'), 'error');
        }
    } catch(e) {
        showStatusToast(t('Error') + ': ' + e, 'error');
    }
}

async function _deleteOverride(type, target, actId) {
    if (!confirm(`Override "${actId}" fuer ${target} loeschen?`)) return;
    try {
        await fetch(`/activities/overrides/${type}/${encodeURIComponent(target)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ activity_id: actId, override: {} })
        });
        showStatusToast(t('Override deleted'), 'success');
        // Wenn aktuell bearbeiteter Override geloescht wurde, Formular schliessen
        if (_overrideEditing && _overrideEditing.type === type && _overrideEditing.target === target && _overrideEditing.actId === actId) {
            _cancelOverrideEdit();
        }
        await _loadOverrides();
    } catch(e) {}
}

// === EDITOR INVENTORY TAB (inline in character profile) ===

const _itemCategoryIcons = {
    tool: '🔧', key: '🔑', consumable: '💊', evidence: '📄',
    gift: '🎁', quest: '⭐', decoration: '✨'
};

const _itemRarityColors = {
    common: 'var(--text-muted)', uncommon: '#4CAF50',
    rare: '#2196F3', unique: '#FF9800'
};

function _getInventoryCharName() {
    // Gebundener Name am DOM (vom renderCharacterEditor gesetzt).
    // Fallback auf _modalCharacter nur wenn nichts gebunden.
    const listEl = document.getElementById('editor-inventory-list');
    const bound = listEl?.dataset?.charName || '';
    return bound || _modalCharacter || '';
}

async function _loadEditorInventory(charName) {
    const listEl = document.getElementById('editor-inventory-list');
    if (!listEl) return;
    // Bei erstmaligem Aufruf mit charName: am DOM binden, damit spaetere
    // Mutations-Aufrufe garantiert den gleichen Character ansprechen.
    if (charName) listEl.dataset.charName = charName;
    const effectiveName = charName || _getInventoryCharName();
    if (!effectiveName) return;
    try {
        const response = await fetch(`/inventory/characters/${encodeURIComponent(effectiveName)}`);
        if (!response.ok) throw new Error('Fehler');
        const data = await response.json();
        const inventory = data.inventory || [];
        if (inventory.length === 0) {
            listEl.innerHTML = '<p class="scheduler-empty">Inventar ist leer</p>';
            return;
        }
        listEl.innerHTML = inventory.map(entry => {
            const icon = _itemCategoryIcons[entry.item_category] || '📦';
            const rarityColor = _itemRarityColors[entry.item_rarity] || 'var(--text-muted)';
            const qty = entry.quantity > 1 ? ` x${entry.quantity}` : '';
            const equipped = entry.equipped ? ' [E]' : '';
            const imgHtml = entry.item_image
                ? `<img src="/inventory/items/${encodeURIComponent(entry.item_id)}/image" alt="" style="width:40px;height:40px;object-fit:contain;background:rgba(0,0,0,0.15);border-radius:4px;margin-right:8px;flex-shrink:0;">`
                : `<span style="width:40px;height:40px;display:inline-flex;align-items:center;justify-content:center;font-size:22px;margin-right:8px;flex-shrink:0;">${icon}</span>`;
            const incantHtml = entry.item_incantation
                ? `<span class="world-item-desc" style="color:#d2a8ff;font-style:italic;">✨ &quot;${escapeHtml(entry.item_incantation)}&quot;</span>`
                : '';
            return `
            <div class="world-item" style="display:flex;align-items:center;" title="Item-Details werden zentral in Game Admin → Items gepflegt">
                ${imgHtml}
                <div class="world-item-info" style="flex:1;min-width:0;">
                    <strong>${escapeHtml(entry.item_name)}${qty}${equipped}</strong>
                    ${entry.item_description ? `<span class="world-item-desc">${escapeHtml(entry.item_description)}</span>` : ''}
                    ${incantHtml}
                    <span class="world-item-activities" style="color:${rarityColor}">${escapeHtml(entry.item_rarity || 'common')} · ${escapeHtml(entry.item_category || '')}</span>
                </div>
                <div class="world-item-actions">
                    ${(entry.item_consumable && entry.item_category !== 'spell') ? `<button class="job-edit-btn" onclick="useEditorInventoryItem('${escapeHtml(entry.item_id)}')" title="Verbrauchen">🥤</button>` : ''}
                    ${entry.item_incantation ? `<button class="job-edit-btn" onclick="castSpellOnSelf('${escapeHtml(entry.item_id)}', '${escapeHtml(entry.item_name)}')" title="Cast on self (Avatar)">✨</button>` : ''}
                    <button class="job-edit-btn" onclick="toggleEquipInventoryItem('${escapeHtml(entry.item_id)}', ${!entry.equipped})" title="${entry.equipped ? 'Ablegen' : 'Ausruesten'}">
                        ${entry.equipped ? '🔕' : '🔔'}
                    </button>
                    <button class="job-delete-btn" onclick="removeEditorInventoryItem('${escapeHtml(entry.item_id)}')" title="Entfernen">🗑️</button>
                </div>
            </div>`;
        }).join('');
    } catch (error) {
        console.error('[EditorInventory] Fehler:', error);
    }
}

async function _populateEditorInventoryItemDropdown() {
    const select = document.getElementById('editor-inventory-item-select');
    if (!select) return;
    try {
        const response = await fetch(`/inventory/items`);
        if (!response.ok) return;
        const data = await response.json();
        const items = data.items || [];
        select.innerHTML = '<option value="">-- Item auswaehlen --</option>' +
            items.map(i => {
                const icon = _itemCategoryIcons[i.category] || '📦';
                return `<option value="${escapeHtml(i.id)}">${icon} ${escapeHtml(i.name)} (${escapeHtml(i.rarity)})</option>`;
            }).join('');
        select.onchange = () => {
            const preview = document.getElementById('editor-inventory-item-preview');
            if (!preview) return;
            const item = items.find(i => i.id === select.value);
            if (!item) { preview.innerHTML = ''; return; }
            const imgHtml = item.image
                ? `<img src="/inventory/items/${encodeURIComponent(item.id)}/image" alt="" style="width:72px;height:72px;object-fit:contain;background:rgba(0,0,0,0.15);border-radius:6px;flex-shrink:0;">`
                : `<span style="width:72px;height:72px;display:inline-flex;align-items:center;justify-content:center;font-size:40px;background:var(--bg-alt);border-radius:6px;flex-shrink:0;">${_itemCategoryIcons[item.category] || '📦'}</span>`;
            preview.innerHTML = `
                <div style="display:flex;gap:10px;align-items:flex-start;text-align:left;">
                    ${imgHtml}
                    <div style="flex:1;min-width:0;">
                        <strong>${escapeHtml(item.name)}</strong>
                        <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">${escapeHtml(item.category || '')} · ${escapeHtml(item.rarity || 'common')}</div>
                        ${item.description ? `<div style="font-size:12px;margin-top:4px;">${escapeHtml(item.description)}</div>` : ''}
                    </div>
                </div>`;
        };
    } catch (error) {
        console.error('[EditorInventory] Error loading items:', error);
    }
}

function toggleEditorInventoryForm() {
    const form = document.getElementById('editor-inventory-form');
    const placeholder = document.getElementById('editor-inventory-placeholder');
    if (!form) return;
    if (form.style.display === 'none') {
        form.style.display = 'flex';
        if (placeholder) placeholder.style.display = 'none';
        document.getElementById('editor-inventory-item-select').value = '';
        document.getElementById('editor-inventory-quantity').value = '1';
        const preview = document.getElementById('editor-inventory-item-preview');
        if (preview) preview.innerHTML = '';
    } else {
        form.style.display = 'none';
        if (placeholder) placeholder.style.display = 'block';
    }
}

async function saveEditorInventoryItem() {
    const itemId = document.getElementById('editor-inventory-item-select').value;
    const quantity = parseInt(document.getElementById('editor-inventory-quantity').value) || 1;
    if (!itemId) {
        showStatusToast(t('Please choose an item'), 'error');
        return;
    }
    const charName = _getInventoryCharName();
    if (!charName) { showStatusToast(t('No character bound'), 'error'); return; }
    try {
        const response = await fetch(`/inventory/characters/${encodeURIComponent(charName)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ item_id: itemId, quantity, obtained_method: 'manual' })
        });
        if (response.ok) {
            showStatusToast(t('Item added'), 'success');
            toggleEditorInventoryForm();
            await _loadEditorInventory(charName);
        } else {
            const err = await response.json().catch(() => ({}));
            showStatusToast(err.detail || 'Fehler', 'error');
        }
    } catch (error) {
        console.error('[EditorInventory] Fehler:', error);
        showStatusToast(t('Add error'), 'error');
    }
}

async function removeEditorInventoryItem(itemId) {
    if (!confirm('Item aus dem Inventar entfernen?')) return;
    const charName = _getInventoryCharName();
    if (!charName) return;
    try {
        const response = await fetch(`/inventory/characters/${encodeURIComponent(charName)}/${encodeURIComponent(itemId)}`, { method: 'DELETE' });
        if (response.ok) {
            showStatusToast(t('Item removed'), 'success');
            await _loadEditorInventory(charName);
        } else {
            showStatusToast(t('Remove error'), 'error');
        }
    } catch (error) {
        console.error('[EditorInventory] Fehler:', error);
    }
}

async function toggleEquipInventoryItem(itemId, equip) {
    const charName = _getInventoryCharName();
    if (!charName) return;
    try {
        const response = await fetch(`/inventory/characters/${encodeURIComponent(charName)}/${encodeURIComponent(itemId)}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ equipped: equip })
        });
        if (response.ok) {
            showStatusToast(equip ? 'Ausgeruestet' : 'Abgelegt', 'success');
            await _loadEditorInventory(charName);
        }
    } catch (error) {
        console.error('[EditorInventory] Fehler:', error);
    }
}

async function useEditorInventoryItem(itemId) {
    const charName = _getInventoryCharName();
    if (!charName) return;
    if (!confirm('Item verbrauchen?')) return;
    try {
        const resp = await fetch(`/inventory/characters/${encodeURIComponent(charName)}/${encodeURIComponent(itemId)}/use`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({  })
        });
        if (resp.ok) {
            const data = await resp.json();
            showStatusToast(`'${data.item_name}' ` + t('consumed'), 'success');
            await _loadEditorInventory(charName);
        } else {
            const err = await resp.json().catch(() => ({}));
            showStatusToast(err.detail || 'Fehler', 'error');
        }
    } catch (e) {
        showStatusToast(t('Consume error'), 'error');
    }
}

async function castSpellOnSelf(itemId, itemName) {
    // Wirkt den Spell auf den Character selbst (Avatar = Target).
    // Geht durch dieselbe spell_engine.execute_cast wie Chat-getriggerter
    // Cast — Erfolgswurf, copy_on_give-Verbrauch, Effekt-Item ans Ziel,
    // Cast-Activity beim Caster (= sich selbst).
    const charName = _getInventoryCharName();
    if (!charName) return;
    if (!confirm(`Spell '${itemName}' auf ${charName} wirken?`)) return;
    try {
        const resp = await fetch(`/inventory/characters/${encodeURIComponent(charName)}/${encodeURIComponent(itemId)}/cast-self`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({})
        });
        if (resp.ok) {
            const data = await resp.json();
            const verdict = data.success ? 'gelungen' : 'fehlgeschlagen';
            showStatusToast(
                `${data.spell_name}: ${verdict} (${data.roll}/${data.chance})`,
                data.success ? 'success' : 'warning');
            await _loadEditorInventory(charName);
            // Wardrobe-Modal schliessen — Cast-Effekte (Teleport, Outfit-Wechsel,
            // Activity) sieht der User nur wenn die Hauptszene wieder sichtbar ist.
            try {
                const _modal = document.getElementById('wardrobe-modal');
                if (_modal && _modal.style.display !== 'none') closeWardrobeModal();
            } catch (_) {}
            // Bei Anker-Teleport: Hintergrund + Avatar-/Character-Scene refreshen,
            // damit der neue Ort sichtbar wird (gleiche Sequenz wie der
            // SSE-Handler im Chat nach data.location).
            try {
                const tp = data.teleport || {};
                if (tp.to_location) {
                    if (typeof updateLocationBackground === 'function') {
                        updateLocationBackground(tp.to_location, tp.to_room || '');
                    }
                    if (typeof _loadCharacterHeaderState === 'function' && typeof currentCharacterName !== 'undefined' && currentCharacterName) {
                        _loadCharacterHeaderState(currentCharacterName);
                    }
                    if (typeof loadCharacterSidebar === 'function') loadCharacterSidebar();
                    if (typeof loadPlayerAvatar === 'function') loadPlayerAvatar();
                    if (typeof updateCharacterScene === 'function' && typeof currentCharacterName !== 'undefined' && currentCharacterName) {
                        updateCharacterScene(currentCharacterName);
                    }
                    if (typeof updatePlayerExpression === 'function') {
                        try { updatePlayerExpression(getPlayerCharacterName()); } catch (_) {}
                    }
                }
            } catch (_) {}
        } else {
            const err = await resp.json().catch(() => ({}));
            showStatusToast(err.detail || 'Cast fehlgeschlagen', 'error');
        }
    } catch (e) {
        showStatusToast(t('Cast error'), 'error');
    }
}

async function giveEditorInventoryItem(itemId, itemName) {
    const charName = _getInventoryCharName();
    if (!charName) return;
    // Verfuegbare Charaktere holen (alle ausser sender)
    let chars = [];
    try {
        const resp = await fetch(`/characters/list`);
        if (resp.ok) {
            const data = await resp.json();
            chars = (data.characters || []).filter(c => {
                const n = typeof c === 'string' ? c : (c.name || '');
                return n && n !== charName;
            }).map(c => typeof c === 'string' ? c : c.name);
        }
    } catch (e) { console.warn('[Give] chars load failed', e); }

    if (!chars.length) { showStatusToast(t('No other characters available'), 'error'); return; }

    const recipient = prompt(`'${itemName}' verschenken an:\n\n${chars.map((c, i) => `${i+1}. ${c}`).join('\n')}\n\nName eingeben:`);
    if (!recipient) return;
    const target = chars.find(c => c.toLowerCase() === recipient.trim().toLowerCase());
    if (!target) { showStatusToast(t('Character') + ` '${recipient}' ` + t('not found'), 'error'); return; }

    try {
        const resp = await fetch(`/inventory/characters/${encodeURIComponent(charName)}/${encodeURIComponent(itemId)}/give`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ to_character: target })
        });
        if (resp.ok) {
            const data = await resp.json();
            showStatusToast(`'${data.item_name}' ` + t('gifted to') + ` ${target} (` + t('relationship boost') + ` +${data.boost})`, 'success');
            await _loadEditorInventory(charName);
        } else {
            const err = await resp.json().catch(() => ({}));
            showStatusToast(err.detail || 'Fehler', 'error');
        }
    } catch (e) {
        showStatusToast(t('Gift error'), 'error');
    }
}

// === EDITOR SECRETS TAB (inline in character profile) ===

let _editorEditingSecretId = null;

const _secretCategoryLabels = {
    personal: 'Persoenlich',
    relationship: 'Beziehung',
    location: 'Ort',
    criminal: 'Kriminell'
};

const _secretSeverityLabels = {
    1: 'Harmlos',
    2: 'Peinlich',
    3: 'Ernst',
    4: 'Gefaehrlich',
    5: 'Verheerend'
};

async function _loadEditorSecrets(charName) {
    const listEl = document.getElementById('editor-secrets-list');
    if (!listEl) return;
    try {
        const response = await fetch(`/secrets/${encodeURIComponent(charName || getEditorCharacterName())}`);
        if (!response.ok) throw new Error('Fehler');
        const data = await response.json();
        const secrets = data.secrets || [];
        if (secrets.length === 0) {
            listEl.innerHTML = '<p class="scheduler-empty">Noch keine Geheimnisse vorhanden</p>';
            return;
        }
        listEl.innerHTML = secrets.map(s => {
            const secJson = encodeURIComponent(JSON.stringify(s)).replace(/'/g, '%27');
            const catLabel = _secretCategoryLabels[s.category] || s.category;
            const sevLabel = _secretSeverityLabels[s.severity] || s.severity;
            const knownCount = (s.known_by || []).length;
            const knownInfo = knownCount > 0 ? ` · Bekannt bei: ${s.known_by.join(', ')}` : '';
            return `
            <div class="world-item">
                <div class="world-item-info">
                    <strong>${escapeHtml(s.content.length > 80 ? s.content.substring(0, 80) + '...' : s.content)}</strong>
                    <span class="world-item-desc">${escapeHtml(catLabel)} · Schwere: ${escapeHtml(String(sevLabel))}${knownInfo}</span>
                    ${s.consequences_if_revealed ? `<span class="world-item-activities">Konsequenzen: ${escapeHtml(s.consequences_if_revealed)}</span>` : ''}
                </div>
                <div class="world-item-actions">
                    <button class="job-edit-btn" onclick="editEditorSecret('${secJson}')" title="Bearbeiten">✏️</button>
                    <button class="job-delete-btn" onclick="deleteEditorSecret('${escapeHtml(s.id)}')" title="Loeschen">🗑️</button>
                </div>
            </div>`;
        }).join('');
    } catch (error) {
        console.error('[EditorSecrets] Fehler:', error);
    }
}

function toggleEditorSecretForm() {
    const form = document.getElementById('editor-secret-form');
    const placeholder = document.getElementById('editor-secret-placeholder');
    if (!form) return;
    if (form.style.display === 'none') {
        form.style.display = 'flex';
        if (placeholder) placeholder.style.display = 'none';
        document.getElementById('editor-secret-form-title').textContent = 'Neues Geheimnis';
        document.getElementById('editor-secret-content').value = '';
        document.getElementById('editor-secret-category').value = 'personal';
        document.getElementById('editor-secret-severity').value = '2';
        document.getElementById('editor-secret-severity-val').textContent = '2';
        document.getElementById('editor-secret-related-chars').value = '';
        document.getElementById('editor-secret-consequences').value = '';
        document.getElementById('editor-secret-known-by').value = '';
        _editorEditingSecretId = null;
        document.getElementById('editor-secret-content').focus();
    } else {
        form.style.display = 'none';
        _editorEditingSecretId = null;
        if (placeholder) placeholder.style.display = 'block';
    }
}

function editEditorSecret(dataJson) {
    const sec = JSON.parse(decodeURIComponent(dataJson));
    const form = document.getElementById('editor-secret-form');
    const placeholder = document.getElementById('editor-secret-placeholder');
    if (!form) return;
    form.style.display = 'flex';
    if (placeholder) placeholder.style.display = 'none';
    document.getElementById('editor-secret-form-title').textContent = 'Geheimnis bearbeiten';
    _editorEditingSecretId = sec.id;
    document.getElementById('editor-secret-content').value = sec.content || '';
    document.getElementById('editor-secret-category').value = sec.category || 'personal';
    document.getElementById('editor-secret-severity').value = String(sec.severity || 2);
    document.getElementById('editor-secret-severity-val').textContent = String(sec.severity || 2);
    document.getElementById('editor-secret-related-chars').value = (sec.related_characters || []).join(', ');
    document.getElementById('editor-secret-consequences').value = sec.consequences_if_revealed || '';
    document.getElementById('editor-secret-known-by').value = (sec.known_by || []).join(', ');
    document.getElementById('editor-secret-content').focus();
}

async function saveEditorSecret() {
    const content = document.getElementById('editor-secret-content').value.trim();
    const category = document.getElementById('editor-secret-category').value;
    const severity = parseInt(document.getElementById('editor-secret-severity').value) || 2;
    const relatedChars = document.getElementById('editor-secret-related-chars').value.split(',').map(s => s.trim()).filter(Boolean);
    const consequences = document.getElementById('editor-secret-consequences').value.trim();
    const knownBy = document.getElementById('editor-secret-known-by').value.split(',').map(s => s.trim()).filter(Boolean);

    if (!content) {
        showStatusToast(t('Secret text is required'), 'error');
        return;
    }
    try {
        if (_editorEditingSecretId) {
            // Update existing secret
            const response = await fetch(`/secrets/${encodeURIComponent(getEditorCharacterName())}/${_editorEditingSecretId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content, category, severity, related_characters: relatedChars, consequences_if_revealed: consequences, known_by: knownBy })
            });
            if (response.ok) {
                showStatusToast(t('Secret updated'), 'success');
            } else {
                showStatusToast(t('Update error'), 'error');
                return;
            }
        } else {
            // Create new secret
            const response = await fetch(`/secrets/${encodeURIComponent(getEditorCharacterName())}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content, category, severity, related_characters: relatedChars, consequences_if_revealed: consequences, known_by: knownBy })
            });
            if (response.ok) {
                showStatusToast(t('Secret saved'), 'success');
            } else {
                showStatusToast(t('Save error'), 'error');
                return;
            }
        }
        _editorEditingSecretId = null;
        toggleEditorSecretForm();
        await _loadEditorSecrets();
    } catch (error) {
        console.error('[EditorSecrets] Fehler:', error);
        showStatusToast(t('Save error'), 'error');
    }
}

async function deleteEditorSecret(secretId) {
    if (!confirm('Geheimnis wirklich loeschen?')) return;
    try {
        const response = await fetch(`/secrets/${encodeURIComponent(getEditorCharacterName())}/${encodeURIComponent(secretId)}`, { method: 'DELETE' });
        if (response.ok) {
            showStatusToast(t('Secret deleted'), 'success');
            await _loadEditorSecrets();
        } else {
            showStatusToast(t('Delete error'), 'error');
        }
    } catch (error) {
        console.error('[EditorSecrets] Fehler:', error);
        showStatusToast(t('Delete error'), 'error');
    }
}

let _secretGenerating = false;
async function generateEditorSecrets() {
    if (_secretGenerating) return;
    if (!confirm('Geheimnisse via LLM generieren? Basierend auf Profil, Beziehungen und Verlauf werden 2 neue Geheimnisse erstellt.')) return;
    _secretGenerating = true;
    // Button deaktivieren + Loading-State
    const btns = document.querySelectorAll('[onclick="generateEditorSecrets()"]');
    btns.forEach(b => { b.disabled = true; b.textContent = 'Generiere...'; });
    const listEl = document.getElementById('editor-secrets-list');
    const prevHtml = listEl ? listEl.innerHTML : '';
    if (listEl) listEl.innerHTML = '<p class="scheduler-empty">LLM generiert Geheimnisse — das kann einige Sekunden dauern...</p>';
    try {
        const response = await fetch(`/secrets/${encodeURIComponent(getEditorCharacterName())}/generate`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ count: 2 })
        });
        if (response.ok) {
            const data = await response.json();
            showStatusToast(`${data.count} ` + t('secret(s) generated'), 'success');
            await _loadEditorSecrets();
        } else {
            const err = await response.json().catch(() => ({}));
            showStatusToast(err.detail || 'Generierung fehlgeschlagen', 'error');
            if (listEl) listEl.innerHTML = prevHtml;
        }
    } catch (error) {
        console.error('[EditorSecrets] Generierung fehlgeschlagen:', error);
        showStatusToast(t('Generation failed'), 'error');
        if (listEl) listEl.innerHTML = prevHtml;
    } finally {
        _secretGenerating = false;
        btns.forEach(b => { b.disabled = false; b.textContent = t('Generate'); });
    }
}

