// === Wiederverwendbarer 2D-Karten-Renderer ===
//
// Rendert eine flache 2D-Karte aus Orten mit grid_x/grid_y in einen Container.
// Orte ohne Koordinaten landen in einer "Ohne Koordinaten"-Liste darunter.
//
// container : HTMLElement
// options   : {
//   locations:        [{id, name, grid_x, grid_y, is_known, is_current,
//                       visit_count, last_visit, passable, ...}],
//   showOnlyKnown:    bool   \u2014 true: ungekannte ausblenden; false: gedimmt zeigen
//   onClick:          fn(loc)? \u2014 optional Click-Handler
//   showVisitCount:   bool   \u2014 Visit-Badge anzeigen (default true)
// }
function renderLocationMap(container, options) {
    const opts = options || {};
    const locs = opts.locations || [];
    const showOnlyKnown = !!opts.showOnlyKnown;
    const showVisits = opts.showVisitCount !== false;
    const onClick = typeof opts.onClick === 'function' ? opts.onClick : null;

    const visible = locs.filter(loc => !(showOnlyKnown && !loc.is_known));
    const placed = visible.filter(l => l.grid_x != null && l.grid_y != null
                                      && l.grid_x >= 0 && l.grid_y >= 0);
    const unplaced = visible.filter(l => !(l.grid_x != null && l.grid_y != null
                                          && l.grid_x >= 0 && l.grid_y >= 0));

    if (!visible.length) {
        container.innerHTML = '<p class="scheduler-empty" data-i18n="No places">No places</p>';
        return;
    }

    let minX = 0, maxX = 0, minY = 0, maxY = 0;
    if (placed.length) {
        minX = Math.min(...placed.map(l => l.grid_x));
        maxX = Math.max(...placed.map(l => l.grid_x));
        minY = Math.min(...placed.map(l => l.grid_y));
        maxY = Math.max(...placed.map(l => l.grid_y));
    }
    const cols = placed.length ? maxX - minX + 1 : 0;
    const rows = placed.length ? maxY - minY + 1 : 0;
    const byPos = new Map();
    for (const l of placed) {
        byPos.set(`${l.grid_x - minX},${l.grid_y - minY}`, l);
    }

    function locTile(loc) {
        const cls = [
            'loc-tile',
            loc.is_known ? 'known' : 'unknown',
            loc.is_current ? 'current' : '',
            loc.passable ? 'passable' : '',
        ].filter(Boolean).join(' ');
        const visitTitle = loc.last_visit ? _fmtDateTime(loc.last_visit) : '';
        const visit = (showVisits && loc.is_known && loc.visit_count > 0)
            ? `<span class="loc-tile-visits" title="${escapeHtml(visitTitle)}">${loc.visit_count}\u00D7</span>` : '';
        const icon = loc.is_current ? '\uD83D\uDCCD' : (loc.passable ? '\uD83D\uDEB6' : '\uD83C\uDFE0');
        const click = onClick ? ` data-click-id="${escapeHtml(loc.id)}"` : '';
        return `<div class="${cls}" title="${escapeHtml(loc.name)}"${click}>
            <div class="loc-tile-icon">${icon}</div>
            <div class="loc-tile-name">${escapeHtml(loc.name)}</div>
            ${visit}
        </div>`;
    }

    let html = '';
    if (placed.length) {
        html += `<div class="loc-map-grid" style="grid-template-columns:repeat(${cols},minmax(80px,1fr));">`;
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                const loc = byPos.get(`${x},${y}`);
                html += loc ? locTile(loc) : '<div class="loc-tile empty"></div>';
            }
        }
        html += '</div>';
    }
    if (unplaced.length) {
        html += `<div class="loc-map-unplaced">
            <div class="loc-map-unplaced-title" data-i18n="Without coordinates">Without coordinates</div>
            <div class="loc-map-unplaced-list">${unplaced.map(locTile).join('')}</div>
        </div>`;
    }

    container.innerHTML = html;

    if (onClick) {
        container.querySelectorAll('[data-click-id]').forEach(el => {
            el.addEventListener('click', () => {
                const id = el.dataset.clickId;
                const loc = locs.find(l => l.id === id);
                if (loc) onClick(loc);
            });
        });
    }
}

// === Tab "Bekannte Orte" ===
async function loadMemoryLocations() {
    if (!_modalCharacter) return;
    const mapEl = document.getElementById('locations-map');
    const countEl = document.getElementById('locations-count');
    try {
        const r = await fetch(`/characters/${encodeURIComponent(_modalCharacter)}/memory/locations`);
        if (!r.ok) throw new Error('locations fetch failed');
        const d = await r.json();
        const items = d.items || [];
        const known = items.filter(it => it.is_known);
        const showAllEl = document.getElementById('locations-show-all');
        const renderNow = () => {
            const showAll = showAllEl.checked;
            countEl.textContent = showAll
                ? `${known.length} bekannt / ${items.length} gesamt`
                : `${known.length} bekannte Orte`;
            renderLocationMap(mapEl, {
                locations: items,
                showOnlyKnown: !showAll,
            });
        };
        if (!showAllEl._wired) {
            showAllEl._wired = true;
            showAllEl.addEventListener('change', renderNow);
        }
        renderNow();
    } catch (e) {
        console.error('[Memory/locations]', e);
        mapEl.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

function _renderTodayLanes(lanes, nowIso) {
    const canvas = document.getElementById('today-lanes-canvas');
    const empty = document.getElementById('today-lanes-empty');
    const list = document.getElementById('today-lanes-list');
    const total = (lanes.activity.points.length + lanes.location.points.length + lanes.mood.points.length);
    if (total === 0) {
        canvas.style.display = 'none';
        list.innerHTML = '';
        empty.style.display = 'block';
        return;
    }
    canvas.style.display = 'block';
    empty.style.display = 'none';
    _drawLanes(canvas, lanes, nowIso);
    _renderLanesList(list, lanes);
}

function _renderLanesList(el, lanes) {
    // Kompakte Liste unter dem Canvas: pro Lane die EINDEUTIGEN Werte.
    // Hover auf einen Eintrag leuchtet ALLE seine Bands im Zeitstrahl auf.
    function laneRow(laneKey, label, points, color) {
        if (!points.length) return '';
        const counts = new Map();
        for (const p of points) {
            const v = p.value || '';
            counts.set(v, (counts.get(v) || 0) + 1);
        }
        // Sortieren: häufigste zuerst
        const sorted = [...counts.entries()].sort((a, b) => b[1] - a[1]);
        const items = sorted.map(([value, n]) => {
            const cnt = n > 1 ? ` <span class="lane-list-count">×${n}</span>` : '';
            return `<span class="lane-list-item" data-lane="${laneKey}" data-value="${escapeHtml(value)}">${escapeHtml(value || '—')}${cnt}</span>`;
        }).join('');
        return `<div class="lane-list-row">
            <span class="lane-list-label" style="color:${color}">${label}</span>
            <div class="lane-list-items">${items}</div>
        </div>`;
    }
    el.innerHTML =
        laneRow(t('Activity (lane)'), t('Activity (lane)'), lanes.activity.points, 'var(--primary)') +
        laneRow('Ort', 'Ort', lanes.location.points, 'var(--primary)') +
        laneRow('Stimmung', 'Stimmung', lanes.mood.points, '#eab308');

    if (!el._hoverWired) {
        el._hoverWired = true;
        el.addEventListener('mouseover', e => {
            const item = e.target.closest('.lane-list-item');
            if (!item) return;
            item.classList.add('hover');
            _highlightLane(item.dataset.lane, item.dataset.value);
        });
        el.addEventListener('mouseout', e => {
            const item = e.target.closest('.lane-list-item');
            if (!item) return;
            item.classList.remove('hover');
            _highlightLane(null, null);
        });
    }
}

function _highlightLane(lane, value) {
    const canvas = document.getElementById('today-lanes-canvas');
    if (!canvas || !canvas._redraw) return;
    canvas._redraw(lane != null && value != null ? {lane, value} : null);
}

function _drawLanes(canvas, lanes, nowIso, highlight) {
    // Closure-Cache fuer Re-Draw aus Hover-Linking
    canvas._redraw = (hl) => _drawLanes(canvas, lanes, nowIso, hl);
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.parentElement.getBoundingClientRect();
    const W = Math.max(600, rect.width - 16);
    const H = 220;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = W + 'px';
    canvas.style.height = H + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, W, H);

    const PAD_L = 70, PAD_R = 16, PAD_T = 14, PAD_B = 28;
    const innerW = W - PAD_L - PAD_R;
    const now = nowIso ? new Date(nowIso) : new Date();
    const t1 = now.getTime();
    const t0 = t1 - 24 * 3600 * 1000;
    const x = ts => PAD_L + ((new Date(ts).getTime() - t0) / (t1 - t0)) * innerW;

    const muted = getComputedStyle(document.documentElement).getPropertyValue('--text-muted').trim() || '#999';
    const border = getComputedStyle(document.documentElement).getPropertyValue('--border').trim() || '#333';
    const primary = getComputedStyle(document.documentElement).getPropertyValue('--primary').trim() || '#6366f1';

    // 3 Lanes (mood, activity, location) \u2014 Mood als Farbverlauf, andere als Marker
    const laneH = (H - PAD_T - PAD_B) / 3;
    const laneYs = [PAD_T + laneH * 0.5, PAD_T + laneH * 1.5, PAD_T + laneH * 2.5];

    // Lane-Labels
    ctx.fillStyle = muted; ctx.font = '11px sans-serif'; ctx.textAlign = 'right';
    ctx.fillText('Stimmung', PAD_L - 6, laneYs[0] + 4);
    ctx.fillText('Aktivit\u00E4t', PAD_L - 6, laneYs[1] + 4);
    ctx.fillText('Ort', PAD_L - 6, laneYs[2] + 4);

    // Grid (Stunden)
    ctx.strokeStyle = border; ctx.lineWidth = 0.5;
    for (let h = 0; h <= 24; h += 6) {
        const xx = PAD_L + (h / 24) * innerW;
        ctx.beginPath(); ctx.moveTo(xx, PAD_T); ctx.lineTo(xx, H - PAD_B); ctx.stroke();
        ctx.fillStyle = muted; ctx.font = '10px sans-serif'; ctx.textAlign = 'center';
        const labelTs = new Date(t0 + (h / 24) * (t1 - t0));
        ctx.fillText(labelTs.getHours().toString().padStart(2,'0') + ':00', xx, H - 12);
    }

    // Mood-Lane: Farbflaechen pro Punkt (Sentiment -> Farbe)
    const moodPts = lanes.mood.points;
    if (moodPts.length) {
        for (let i = 0; i < moodPts.length; i++) {
            const p = moodPts[i];
            const xs = x(p.ts);
            const xe = i + 1 < moodPts.length ? x(moodPts[i+1].ts) : PAD_L + innerW;
            const s = _moodToSentiment(p.value);
            const color = s > 0.6 ? '#22c55e' : s > 0.4 ? '#eab308' : '#ef4444';
            ctx.fillStyle = color;
            ctx.globalAlpha = 0.35;
            ctx.fillRect(xs, laneYs[0] - laneH * 0.35, Math.max(2, xe - xs), laneH * 0.7);
            ctx.globalAlpha = 1;
        }
    }

    // Berechnet das Band-Ende fuer ein Lane-Event:
    // - mit useDuration & p.duration_min: cappe auf ts + duration_min
    // - sonst: bis zum naechsten Wechsel oder zum Lane-Ende
    function bandEndX(points, i, useDuration) {
        const p = points[i];
        const naturalEnd = i + 1 < points.length ? x(points[i+1].ts) : PAD_L + innerW;
        if (useDuration && typeof p.duration_min === 'number' && p.duration_min > 0) {
            const ts = new Date(p.ts).getTime();
            const cappedTs = ts + p.duration_min * 60 * 1000;
            const cappedX = PAD_L + ((cappedTs - t0) / (t1 - t0)) * innerW;
            return Math.min(naturalEnd, Math.max(x(p.ts) + 2, cappedX));
        }
        return naturalEnd;
    }

    // Activity- und Location-Lane: Marker + dominierende Value-Bands
    function drawValueLane(points, laneY, opts) {
        if (!points.length) return;
        const isLocation = opts.isLocation;
        const useDuration = opts.useDuration;
        for (let i = 0; i < points.length; i++) {
            const p = points[i];
            const xs = x(p.ts);
            const xe = bandEndX(points, i, useDuration);
            const naturalEnd = i + 1 < points.length ? x(points[i+1].ts) : PAD_L + innerW;
            const expired = useDuration && xe < naturalEnd - 1;
            // Band
            ctx.fillStyle = primary;
            ctx.globalAlpha = isLocation ? 0.22 : 0.14;
            ctx.fillRect(xs, laneY - laneH * 0.30, Math.max(2, xe - xs), laneH * 0.6);
            ctx.globalAlpha = 1;
            // Wenn Aktivitaet laenger als ihre Dauer her ist: gestrichelte
            // "kein neuer State"-Linie bis zum naechsten Eintrag/jetzt.
            if (expired) {
                ctx.save();
                ctx.strokeStyle = muted;
                ctx.setLineDash([4, 3]);
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.moveTo(xe, laneY);
                ctx.lineTo(naturalEnd, laneY);
                ctx.stroke();
                ctx.restore();
            }
            // Marker
            ctx.fillStyle = primary;
            ctx.beginPath(); ctx.arc(xs, laneY, 3.5, 0, Math.PI * 2); ctx.fill();
            // Label (nur wenn genug Platz)
            if (xe - xs > 70 && p.value) {
                ctx.fillStyle = muted; ctx.font = '10px sans-serif'; ctx.textAlign = 'left';
                const lbl = (p.value || '').substring(0, 24);
                ctx.fillText(lbl, xs + 5, laneY - 2);
            }
        }
    }
    drawValueLane(lanes.activity.points, laneYs[1], {isLocation: false, useDuration: true});
    drawValueLane(lanes.location.points, laneYs[2], {isLocation: true, useDuration: false});

    // Bucketed-Hint
    if (lanes.activity.bucketed || lanes.location.bucketed || lanes.mood.bucketed) {
        ctx.fillStyle = muted; ctx.font = '10px sans-serif'; ctx.textAlign = 'right';
        ctx.fillText('(stundenweise verdichtet)', W - PAD_R, PAD_T - 2);
    }

    // Hit-Test-Daten fuer Tooltip + Highlight auf Canvas haengen.
    // Activity-Bands nutzen das gecappte Ende (siehe bandEndX), damit
    // der Hover nicht auf der gestrichelten Lücke triggert.
    canvas._lanesHitData = {
        bands: [
            ...lanes.mood.points.map((p, i, a) => ({
                lane: 'Stimmung', label: p.value, ts: p.ts, count: p.count,
                xs: x(p.ts), xe: i + 1 < a.length ? x(a[i+1].ts) : PAD_L + innerW,
                ys: laneYs[0] - laneH * 0.35, ye: laneYs[0] + laneH * 0.35,
            })),
            ...lanes.activity.points.map((p, i, a) => ({
                lane: t('Activity (lane)'), label: p.value, ts: p.ts, count: p.count,
                xs: x(p.ts), xe: bandEndX(a, i, true),
                ys: laneYs[1] - laneH * 0.30, ye: laneYs[1] + laneH * 0.30,
            })),
            ...lanes.location.points.map((p, i, a) => ({
                lane: 'Ort', label: p.value, ts: p.ts, count: p.count,
                xs: x(p.ts), xe: i + 1 < a.length ? x(a[i+1].ts) : PAD_L + innerW,
                ys: laneYs[2] - laneH * 0.30, ye: laneYs[2] + laneH * 0.30,
            })),
        ],
    };

    // Highlight-Overlay: alle Bands der Lane mit passendem Wert hervorheben.
    if (highlight && highlight.lane != null && highlight.value != null) {
        const matches = canvas._lanesHitData.bands.filter(
            b => b.lane === highlight.lane && (b.label || '') === highlight.value);
        if (matches.length) {
            ctx.save();
            ctx.strokeStyle = '#fbbf24';
            ctx.lineWidth = 2;
            ctx.fillStyle = 'rgba(251,191,36,0.30)';
            for (const hit of matches) {
                const w = Math.max(4, hit.xe - hit.xs);
                const h = hit.ye - hit.ys;
                ctx.fillRect(hit.xs, hit.ys, w, h);
                ctx.strokeRect(hit.xs, hit.ys, w, h);
            }
            ctx.restore();
        }
    }
    if (!canvas._tooltipWired) {
        canvas._tooltipWired = true;
        canvas.addEventListener('mousemove', _lanesTooltipMove);
        canvas.addEventListener('mouseleave', _lanesTooltipHide);
    }
}

function _lanesTooltipMove(e) {
    const canvas = e.currentTarget;
    const tip = document.getElementById('today-lanes-tooltip');
    if (!tip || !canvas._lanesHitData) return;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const hit = canvas._lanesHitData.bands.find(
        b => x >= b.xs && x <= b.xe && y >= b.ys && y <= b.ye);
    if (!hit) { tip.style.display = 'none'; return; }
    const time = new Date(hit.ts).toLocaleTimeString('de-DE', {hour:'2-digit', minute:'2-digit'});
    const cnt = hit.count > 1 ? ` (×${hit.count})` : '';
    tip.textContent = `${hit.lane}: ${hit.label || '—'} — ${time}${cnt}`;
    tip.style.display = 'block';
    // Position relativ zum Container
    const container = canvas.parentElement;
    const cRect = container.getBoundingClientRect();
    tip.style.left = (e.clientX - cRect.left + 12) + 'px';
    tip.style.top = (e.clientY - cRect.top + 12) + 'px';
}
function _lanesTooltipHide() {
    const tip = document.getElementById('today-lanes-tooltip');
    if (tip) tip.style.display = 'none';
}

function _renderActiveMemories(items) {
    const el = document.getElementById('today-active-memories');
    if (!items.length) {
        el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No relevant memories'))}</p>`;
        return;
    }
    el.innerHTML = items.map(m => {
        const date = _fmtDateTime(m.ts);
        const related = m.related_character
            ? `<span class="knowledge-related">${escapeHtml(m.related_character)}</span>` : '';
        const stars = '\u2605'.repeat(m.importance) + '\u2606'.repeat(5 - m.importance);
        return `
        <div class="active-memory memory-entry-${m.memory_type}">
            <div class="active-memory-head">
                <span class="knowledge-type">${_memoryTypeIcon(m.memory_type)} ${_memoryTypeLabel(m.memory_type)}</span>
                ${related}
                <span class="memory-stars admin-only" title="Wichtigkeit ${m.importance}">${stars}</span>
                <span class="memory-score admin-only" title="Score">${m.score}</span>
                <span class="knowledge-date">${escapeHtml(date)}</span>
            </div>
            <div class="knowledge-content">${escapeHtml(m.content)}</div>
        </div>`;
    }).join('');
}

// ---- Tab "Erinnerungen" ----
async function loadMemoryList() {
    if (!_modalCharacter) return;
    // Toolbar-Listener einmalig setzen
    if (!loadMemoryList._wired) {
        loadMemoryList._wired = true;
        document.getElementById('memlist-q').addEventListener('input', _debounce(() => {
            _memlistState.q = document.getElementById('memlist-q').value;
            _memlistState.offset = 0;
            _fetchMemList();
        }, 250));
        ['memlist-tier','memlist-imp','memlist-related','memlist-source','memlist-sort'].forEach(id => {
            document.getElementById(id).addEventListener('change', () => {
                _memlistState.offset = 0;
                _memlistState.tier = document.getElementById('memlist-tier').value;
                _memlistState.min_importance = parseInt(document.getElementById('memlist-imp').value, 10) || 0;
                _memlistState.related = document.getElementById('memlist-related').value;
                _memlistState.source = document.getElementById('memlist-source').value;
                _memlistState.sort = document.getElementById('memlist-sort').value;
                _fetchMemList();
            });
        });
        document.getElementById('memlist-completed').addEventListener('change', e => {
            _memlistState.include_completed = e.target.checked;
            _memlistState.offset = 0;
            _fetchMemList();
        });
    }
    await _fetchMemList(true);
}

async function _fetchMemList(populateRelated) {
    const s = _memlistState;
    const params = new URLSearchParams({
        limit: s.limit, offset: s.offset, tier: s.tier,
        min_importance: s.min_importance, q: s.q, related: s.related,
        source: s.source, sort: s.sort,
        include_completed: s.include_completed ? 'true' : 'false',
    });
    try {
        const r = await fetch(`/characters/${encodeURIComponent(_modalCharacter)}/memory/list?${params}`);
        if (!r.ok) throw new Error('list fetch failed');
        const d = await r.json();
        _renderMemList(d, populateRelated);
    } catch (e) {
        console.error('[Memory/list]', e);
        document.getElementById('memory-list').innerHTML =
            `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

function _renderMemList(d, populateRelated) {
    const list = document.getElementById('memory-list');
    const count = document.getElementById('memlist-count');
    const pag = document.getElementById('memlist-pagination');
    count.textContent = `${d.total} / ${d.total_unfiltered} ${t('memories')}`;
    if (populateRelated) {
        const sel = document.getElementById('memlist-related');
        const current = sel.value;
        sel.innerHTML = '<option value="">Alle Bezuege</option>' +
            (d.facets.related_characters || []).map(rc =>
                `<option value="${escapeHtml(rc.name)}">${escapeHtml(rc.name)} (${rc.count})</option>`
            ).join('');
        sel.value = current;
    }
    if (!d.items.length) {
        list.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No memories match these filters'))}</p>`;
        pag.innerHTML = '';
        return;
    }
    list.innerHTML = d.items.map(m => {
        const date = _fmtDateTime(m.timestamp);
        const related = m.related_character
            ? `<span class="knowledge-related">${escapeHtml(m.related_character)}</span>` : '';
        const tags = (m.tags || []).map(t => `<span class="memory-tag">${escapeHtml(t)}</span>`).join('');
        const stars = '\u2605'.repeat(m.importance || 3) + '\u2606'.repeat(5 - (m.importance || 3));
        return `
        <div class="knowledge-entry memory-entry-${m.memory_type || 'semantic'}">
            <div class="knowledge-entry-header">
                <span class="knowledge-type">${_memoryTypeIcon(m.memory_type)} ${_memoryTypeLabel(m.memory_type)}</span>
                ${related}
                <span class="memory-stars admin-only" title="Wichtigkeit ${m.importance}">${stars}</span>
                <span class="knowledge-date">${escapeHtml(date)}</span>
            </div>
            <div class="knowledge-content">${escapeHtml(m.content)}</div>
            <div class="memory-entry-footer">
                <div class="memory-tags">${tags}</div>
                <div class="memory-entry-meta admin-only">
                    ${_decayBar(m.decay_factor)}
                    <span class="memory-access-count" title="Abrufe">${m.access_count || 0}\u00D7</span>
                </div>
                <button class="job-delete-btn admin-only" onclick="deleteKnowledgeEntry('${m.id}')" title="Loeschen">\uD83D\uDDD1\uFE0F</button>
            </div>
        </div>`;
    }).join('');
    // Pagination
    const start = d.offset;
    const end = d.offset + d.items.length;
    const hasPrev = d.offset > 0;
    const hasNext = end < d.total;
    pag.innerHTML = `
        <button ${hasPrev ? '' : 'disabled'} onclick="memlistPage(-1)">\u2190 zur\u00FCck</button>
        <span>${start + 1}\u2013${end} von ${d.total}</span>
        <button ${hasNext ? '' : 'disabled'} onclick="memlistPage(1)">weiter \u2192</button>
    `;
}

function memlistPage(delta) {
    _memlistState.offset = Math.max(0, _memlistState.offset + delta * _memlistState.limit);
    _fetchMemList();
}

function _debounce(fn, ms) {
    let t; return (...args) => { clearTimeout(t); t = setTimeout(() => fn(...args), ms); };
}

// ---- Tab "Beziehungen" ----
async function loadMemoryRelationships() {
    if (!_modalCharacter) return;
    try {
        const r = await fetch(`/characters/${encodeURIComponent(_modalCharacter)}/memory/relationships`);
        if (!r.ok) throw new Error('rel fetch failed');
        const d = await r.json();
        _renderRelationships(d.items);
    } catch (e) {
        console.error('[Memory/relationships]', e);
        document.getElementById('relationships-list').innerHTML =
            `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

function _renderRelationships(items) {
    const el = document.getElementById('relationships-list');
    if (!items.length) {
        el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No relationships'))}</p>`;
        return;
    }
    el.innerHTML = items.map((it, idx) => {
        const sentBar = (val, label) => {
            const pct = Math.round((val + 1) * 50);  // -1..1 -> 0..100
            const color = val > 0.2 ? '#22c55e' : val < -0.2 ? '#ef4444' : '#eab308';
            return `<div class="sent-bar" title="${label}: ${val.toFixed(2)}">
                <div class="sent-fill" style="width:${pct}%;background:${color}"></div></div>`;
        };
        const tens = it.romantic_tension > 0
            ? `<span class="rel-tension" title="Romantische Spannung">\uD83D\uDC95 ${it.romantic_tension.toFixed(2)}</span>` : '';
        const memChip = it.memories_count
            ? `<button class="rel-mem-chip" onclick="memlistOpenForRelated('${escapeHtml(it.partner)}')">${it.memories_count} ${escapeHtml(t('memories'))}</button>`
            : `<span class="rel-mem-chip muted">0 ${escapeHtml(t('memories'))}</span>`;
        const histRows = (it.history_recent || []).map(h => `
            <div class="rel-hist-row">
                <span class="rel-hist-type">${escapeHtml(h.type || '')}</span>
                <span class="rel-hist-summary">${escapeHtml(h.summary || '')}</span>
                <span class="rel-hist-ts">${escapeHtml(_fmtRelative(h.timestamp))}</span>
            </div>`).join('');
        return `
        <div class="rel-card">
            <div class="rel-card-head">
                <span class="rel-partner">${escapeHtml(it.partner)}</span>
                <span class="rel-type">${escapeHtml(it.type)}</span>
                <span class="rel-strength" title="Strength">${it.strength}</span>
                ${tens}
            </div>
            <div class="rel-sent-grid">
                <div><span class="rel-sent-label">${escapeHtml(_modalCharacter)} \u2192 ${escapeHtml(it.partner)}</span>
                     ${sentBar(it.sentiment_self_to_other, 'self->other')}</div>
                <div><span class="rel-sent-label">${escapeHtml(it.partner)} \u2192 ${escapeHtml(_modalCharacter)}</span>
                     ${sentBar(it.sentiment_other_to_self, 'other->self')}</div>
            </div>
            <div class="rel-meta">
                <span>${it.interaction_count} Interaktionen</span>
                <span>letzte: ${escapeHtml(_fmtRelative(it.last_interaction))}</span>
                ${memChip}
                <button class="rel-expand-btn" onclick="this.parentElement.parentElement.querySelector('.rel-history').classList.toggle('open')">Verlauf</button>
            </div>
            <div class="rel-history">${histRows || `<p class="scheduler-empty">${escapeHtml(t('No events'))}</p>`}</div>
        </div>`;
    }).join('');
}

function memlistOpenForRelated(partner) {
    _memlistState.related = partner;
    _memlistState.offset = 0;
    switchMemoryTab('memories');
    // related-Dropdown wird durch _fetchMemList neu befuellt; Wert danach setzen
    setTimeout(() => {
        const sel = document.getElementById('memlist-related');
        if (sel) sel.value = partner;
    }, 150);
}

// ---- Tab "Verlauf" ----
function switchHistorySubtab(kind) {
    _historySubtab = kind;
    document.querySelectorAll('.history-subtab').forEach(b =>
        b.classList.toggle('active', b.dataset.kind === kind));
    loadMemoryHistory(kind);
}

async function loadMemoryHistory(kind) {
    if (!_modalCharacter) return;
    const el = document.getElementById('history-content');
    el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Loading…'))}</p>`;
    try {
        const r = await fetch(`/characters/${encodeURIComponent(_modalCharacter)}/memory/history?kind=${encodeURIComponent(kind)}&limit=200`);
        if (!r.ok) throw new Error('history fetch failed');
        const d = await r.json();
        _renderHistory(d);
    } catch (e) {
        console.error('[Memory/history]', e);
        el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

function _renderHistory(d) {
    const el = document.getElementById('history-content');
    if (d.kind === 'history') {
        el.innerHTML = d.content
            ? `<div class="knowledge-entry knowledge-summary-entry">
                 <div class="knowledge-entry-header"><span class="knowledge-type">\uD83D\uDCDC Chat-History</span></div>
                 <div class="knowledge-content">${escapeHtml(d.content)}</div>
               </div>`
            : `<p class="scheduler-empty">${escapeHtml(t('No chat summary'))}</p>`;
        return;
    }
    if (d.kind === 'daily') {
        if (!d.items.length) { el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No daily summaries'))}</p>`; return; }
        // Gruppieren nach Monat
        const byMonth = {};
        for (const it of d.items) {
            const m = (it.date || '').substring(0, 7);
            (byMonth[m] = byMonth[m] || []).push(it);
        }
        el.innerHTML = Object.keys(byMonth).sort().reverse().map(mk => `
            <details class="history-month" open>
                <summary>\uD83D\uDCC5 ${escapeHtml(mk)}</summary>
                ${byMonth[mk].map(ds => {
                    const lbl = new Date(ds.date + 'T00:00').toLocaleDateString('de-DE', {day:'2-digit', month:'short'});
                    const partner = ds.partner ? ` \u00B7 mit ${escapeHtml(ds.partner)}` : '';
                    return `<div class="knowledge-entry knowledge-summary-entry">
                        <div class="knowledge-entry-header">
                            <span class="knowledge-type">${escapeHtml(lbl)}${partner}</span>
                        </div>
                        <div class="knowledge-content">${escapeHtml(ds.content)}</div>
                    </div>`;
                }).join('')}
            </details>`).join('');
        return;
    }
    if (d.kind === 'weekly' || d.kind === 'monthly') {
        if (!d.items.length) { el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No entries'))}</p>`; return; }
        const key = d.kind === 'weekly' ? 'week' : 'month';
        const icon = d.kind === 'weekly' ? '\uD83D\uDCC6' : '\uD83D\uDDD3\uFE0F';
        el.innerHTML = d.items.map(it => `
            <div class="knowledge-entry knowledge-summary-entry">
                <div class="knowledge-entry-header"><span class="knowledge-type">${icon} ${escapeHtml(it[key])}</span></div>
                <div class="knowledge-content">${escapeHtml(it.content)}</div>
            </div>`).join('');
        return;
    }
    if (d.kind === 'diary') {
        if (!d.items.length) { el.innerHTML = '<p class="scheduler-empty">Kein Tagebuch</p>'; return; }
        el.innerHTML = d.items.map(it => {
            const tags = (it.tags || []).map(t => `<span class="memory-tag">${escapeHtml(t)}</span>`).join('');
            return `
            <div class="knowledge-entry">
                <div class="knowledge-entry-header">
                    <span class="knowledge-type">\uD83D\uDCD3 Tagebuch</span>
                    <span class="knowledge-date">${escapeHtml(_fmtDateTime(it.ts))}</span>
                </div>
                <div class="knowledge-content">${escapeHtml(it.content)}</div>
                <div class="memory-tags">${tags}</div>
            </div>`;
        }).join('');
        return;
    }
    if (d.kind === 'evolution') {
        if (!d.items.length) { el.innerHTML = `<p class="scheduler-empty">${escapeHtml(t('No self-image snapshots'))}</p>`; return; }
        el.innerHTML = d.items.map((s, i) => {
            const diff = s.diff;
            const renderField = (field, label) => {
                if (!diff) return `
                    <div class="evo-field"><span class="evo-field-label">${label}</span>
                        <div class="evo-field-text">${escapeHtml(s[field] || '')}</div></div>`;
                const dd = diff[field] || {removed:[], added:[]};
                const rem = dd.removed.map(l => `<div class="evo-line removed">\u2212 ${escapeHtml(l)}</div>`).join('');
                const add = dd.added.map(l => `<div class="evo-line added">+ ${escapeHtml(l)}</div>`).join('');
                if (!rem && !add) return `<div class="evo-field"><span class="evo-field-label">${label}</span>
                    <div class="evo-field-empty">unver\u00E4ndert</div></div>`;
                return `<div class="evo-field"><span class="evo-field-label">${label}</span>
                    ${rem}${add}</div>`;
            };
            return `
            <details class="evo-snapshot" ${i === 0 ? 'open' : ''}>
                <summary>${escapeHtml(_fmtDateTime(s.ts))} \u2014 ${escapeHtml(s.trigger || '')} ${diff ? '' : '<span class="muted">(initial)</span>'}</summary>
                ${renderField('beliefs', 'Beliefs')}
                ${renderField('lessons', 'Lessons')}
                ${renderField('goals', 'Goals')}
            </details>`;
        }).join('');
        return;
    }
    el.innerHTML = '<p class="scheduler-empty">Unbekannte Ansicht</p>';
}

async function deleteKnowledgeEntry(entryId) {
    if (!_modalCharacter) return;
    try {
        const response = await fetch(`/characters/${encodeURIComponent(_modalCharacter)}/knowledge/${entryId}`, { method: 'DELETE' });
        if (response.ok) {
            showStatusToast(t('Entry deleted'), 'success');
            // Aktuelle Tab neu laden (Liste / Heute betroffen)
            _loadedMemoryTabs.delete('memories');
            _loadedMemoryTabs.delete('today');
            const active = document.querySelector('.memory-tab.active')?.dataset.tab;
            if (active) _loadMemoryTabIfNeeded(active);
        } else {
            showStatusToast(t('Delete error'), 'error');
        }
    } catch (error) {
        console.error('[Memory] Fehler:', error);
        showStatusToast(t('Delete error'), 'error');
    }
}

async function clearAllKnowledge() {
    if (!_modalCharacter) return;
    if (!confirm(t('Really delete all memories of') + ` ${_modalCharacter}?`)) return;
    try {
        const response = await fetch(`/characters/${encodeURIComponent(_modalCharacter)}/knowledge`, { method: 'DELETE' });
        if (response.ok) {
            const data = await response.json();
            showStatusToast(`${data.deleted_count} ` + t('entries deleted'), 'success');
            _loadedMemoryTabs.clear();
            const active = document.querySelector('.memory-tab.active')?.dataset.tab || 'today';
            _loadMemoryTabIfNeeded(active);
        } else {
            showStatusToast(t('Delete error'), 'error');
        }
    } catch (error) {
        console.error('[Memory] Fehler:', error);
        showStatusToast(t('Delete error'), 'error');
    }
}


// === SCHEDULER: SET_STATUS LOCATION/ACTIVITY DROPDOWNS ===

let _cachedWorldLocations = null;
let _locationIdMap = {};  // {id: {name, description}} fuer schnellen ID→Name Lookup

function locationIdToName(id) {
    if (!id) return '';
    if (_locationIdMap[id]) return _locationIdMap[id].name;
    // Fallback: In Cache nach Name suchen (Backwards-Compat)
    if (_cachedWorldLocations) {
        const loc = _cachedWorldLocations.find(l => l.name === id);
        if (loc) return loc.name;
    }
    return id;
}

function _buildLocationIdMap(locations) {
    _locationIdMap = {};
    for (const loc of locations) {
        if (loc.id) _locationIdMap[loc.id] = { name: loc.name, description: loc.description || '', rooms: loc.rooms || [], image_prompt_day: loc.image_prompt_day || '', image_prompt_night: loc.image_prompt_night || '', image_prompt_map: loc.image_prompt_map || '', prompt_changed: loc.prompt_changed || false };
    }
}

async function _fetchWorldLocations() {
    try {
        const response = await fetch(`/world/locations`);
        if (response.ok) {
            const data = await response.json();
            _cachedWorldLocations = data.locations || [];
            _buildLocationIdMap(_cachedWorldLocations);
            return _cachedWorldLocations;
        }
    } catch (error) {
        console.error('[Location] Error loading locations:', error);
    }
    return [];
}

async function populateSchedulerLocationDropdown() {
    let locations = await _fetchWorldLocations();
    const select = document.getElementById('job-status-location');
    if (!select) return;
    // Erlaubte Orte filtern (allowed_locations speichert IDs)
    if (hasValidCharacter()) {
        try {
            const alResp = await fetch(`/characters/${getEditorCharacterName()}/allowed-locations`);
            if (alResp.ok) {
                const alData = await alResp.json();
                const allowed = alData.allowed_locations || [];
                if (allowed.length > 0) locations = locations.filter(l => allowed.includes(l.id) || allowed.includes(l.name));
            }
        } catch (e) { /* ignore */ }
    }
    select.innerHTML = '<option value="">-- Ort waehlen --</option>' +
        locations.map(l => `<option value="${escapeHtml(l.id || l.name)}">${escapeHtml(l.name)}</option>`).join('');
}

async function onSchedulerLocationChange() {
    const locationId = document.getElementById('job-status-location').value;
    const actSelect = document.getElementById('job-status-activity');
    if (!actSelect) return;

    if (!locationId) {
        actSelect.innerHTML = '<option value="">-- Aktivitaet waehlen --</option>';
        return;
    }

    const locations = _cachedWorldLocations || await _fetchWorldLocations();
    const loc = locations.find(l => (l.id || l.name) === locationId);
    const rawActivities = loc ? (loc.activities || []) : [];
    const activityNames = rawActivities.map(a => typeof a === 'string' ? a : (a.name || ''));

    actSelect.innerHTML = '<option value="">-- Aktivitaet waehlen --</option>' +
        '<option value="__random__">🎲 Zufaellig</option>' +
        activityNames.map(a => `<option value="${escapeHtml(a)}">${escapeHtml(a)}</option>`).join('');

    // Auto-Select wenn nur eine Activity
    if (activityNames.length === 1) {
        actSelect.value = activityNames[0];
    }
}

async function loadHeaderMood() {
    const el = document.getElementById('header-mood-display');
    if (!hasValidCharacter()) return;

    try {
        // Pruefen ob Mood Tracking fuer diesen Character aktiv ist
        const configResp = await fetch(`/characters/${encodeURIComponent(currentCharacterName)}/config`);
        if (configResp.ok) {
            const configData = await configResp.json();
            const cfg = configData.config || {};
            if (!cfg.mood_tracking || cfg.mood_tracking === 'false' || cfg.mood_tracking === false) {
                if (el) { el.style.display = 'none'; el.textContent = ''; }
                const moodLine = document.getElementById('header-mood-line');
                if (moodLine) { moodLine.textContent = ''; moodLine.style.display = 'none'; }
                return;
            }
        }
        // Mood-Overlay im Bild bleibt versteckt — Mood wird nur im Header angezeigt
        if (el) el.style.display = 'none';

        const resp = await fetch(`/characters/${encodeURIComponent(currentCharacterName)}/current-feeling`);
        if (resp.ok) {
            const data = await resp.json();
            const mood = data.current_feeling || '';
            if (el) { el.textContent = mood || '—'; el.title = mood ? `Stimmung: ${mood}` : 'Aktuelle Stimmung'; }
            // Update header mood line (neben dem Bild)
            const moodLine = document.getElementById('header-mood-line');
            if (moodLine) {
                const moodText = mood ? `💭 ${mood}` : '';
                moodLine.textContent = moodText;
                moodLine.style.display = moodText ? '' : 'none';
            }
        }
    } catch (error) {
        console.error('[HeaderMood] Fehler:', error);
    }

}

// Status-Bar Farben: Feste Palette, wird zyklisch vergeben pro Stat-Key
const _statusBarPalette = [
    '#00BCD4', '#FF9800', '#4CAF50', '#3F51B5', '#FFD700',
    '#00E676', '#FF80AB', '#7C4DFF', '#f44336', '#E91E63',
    '#9C27B0', '#CE93D8', '#795548', '#607D8B', '#FF5722',
];
// Dynamische Farb-Zuordnung: Key -> Farbe (wird beim ersten Mal vergeben)
const _statusBarColorCache = {};
function _getStatusBarColor(key, index) {
    if (!_statusBarColorCache[key]) {
        _statusBarColorCache[key] = _statusBarPalette[index % _statusBarPalette.length];
    }
    return _statusBarColorCache[key];
}
// Label: Erste 3 Buchstaben des Keys, uppercase
function _getStatusBarLabel(key) {
    return key.substring(0, 3).toUpperCase();
}

// Reine Render-Funktion ohne Fetch — wird vom Live-Tick genutzt mit
// pre-fetched Daten aus /state/snapshot.
function _renderStatusBarsData(containerId, status, barMeta) {
    const container = document.getElementById(containerId);
    if (!container) return;
    status = status || {};
    barMeta = barMeta || {};

    const metaOrder = Object.keys(barMeta);
    const bars = [];
    for (const [key, val] of Object.entries(status)) {
        if (typeof val === 'number') bars.push({ key, value: val });
    }
    bars.sort((a, b) => {
        const ia = metaOrder.indexOf(a.key);
        const ib = metaOrder.indexOf(b.key);
        if (ia >= 0 && ib >= 0) return ia - ib;
        if (ia >= 0) return -1;
        if (ib >= 0) return 1;
        return a.key.localeCompare(b.key);
    });

    if (bars.length === 0) { container.style.display = 'none'; container.innerHTML = ''; return; }

    container.style.display = 'grid';
    container.innerHTML = bars.map((b, i) => {
        const meta = barMeta[b.key] || {};
        const color = meta.color || _getStatusBarColor(b.key, i);
        const label = meta.label || _getStatusBarLabel(b.key);
        const pct = Math.max(0, Math.min(100, b.value));
        const displayName = meta[`name_${uiLang}`] || meta.name_de || meta.name || b.key;
        return `<div class="status-bar-row" title="${displayName}: ${pct}/100">
            <span class="status-bar-label">${label}</span>
            <div class="status-bar-track"><div class="status-bar-fill" style="width:${pct}%;background:${color};"></div></div>
            <span class="status-bar-value">${pct}</span>
        </div>`;
    }).join('');
}

async function _renderStatusBarsFor(containerId, characterName, expectedFn) {
    // expectedFn liefert den aktuell erwarteten Charakter-Namen, damit ein
    // schneller Wechsel waehrend des Fetch nicht das falsche Bild rendert.
    const container = document.getElementById(containerId);
    if (!container) return;
    if (!characterName) {
        container.style.display = 'none';
        container.innerHTML = '';
        return;
    }
    container.dataset.forChar = characterName;

    try {
        const resp = await fetch(`/characters/${encodeURIComponent(characterName)}/status-effects`);
        if (!resp.ok) { container.style.display = 'none'; return; }
        if (container.dataset.forChar !== (expectedFn ? expectedFn() : characterName)) return;
        const data = await resp.json();
        _renderStatusBarsData(containerId, data.status_effects, data.bar_meta);
    } catch (e) {
        console.warn('[StatusBars]', e);
        container.style.display = 'none';
    }
}

async function loadStatusEffectsBars() {
    const container = document.getElementById('status-effects-bars');
    if (!container) return;
    if (!hasValidCharacter()) {
        container.style.display = 'none';
        container.innerHTML = '';
        return;
    }
    await _renderStatusBarsFor('status-effects-bars', currentCharacterName,
                               () => currentCharacterName);
}

async function loadPlayerStatusBars() {
    const playerName = typeof getPlayerCharacterName === 'function'
        ? getPlayerCharacterName() : '';
    await _renderStatusBarsFor('player-status-bars', playerName,
                               () => (typeof getPlayerCharacterName === 'function'
                                      ? getPlayerCharacterName() : ''));
}

// Reine Render-Funktion fuer den Live-Tick.
function _renderConditionBadgesData(containerId, conditions) {
    const container = document.getElementById(containerId);
    if (!container) return;
    const conds = conditions || [];
    if (conds.length === 0) { container.innerHTML = ''; return; }
    container.innerHTML = conds.map(c => {
        const icon = c.icon || '⚠';
        const label = c.label || c.name;
        const rem = (c.remaining_hours !== null && c.remaining_hours !== undefined)
            ? ` · noch ${c.remaining_hours}h` : '';
        const title = `${label}${rem}`;
        return `<span class="condition-badge" title="${escapeHtml(title)}">${escapeHtml(icon)}</span>`;
    }).join('');
}

async function _loadConditionBadgesFor(characterName, containerId) {
    const container = document.getElementById(containerId);
    if (!container) return;
    if (!characterName) { container.innerHTML = ''; return; }
    try {
        const resp = await fetch(`/characters/${encodeURIComponent(characterName)}/active-conditions`);
        if (!resp.ok) { container.innerHTML = ''; return; }
        const data = await resp.json();
        _renderConditionBadgesData(containerId, data.conditions);
    } catch (e) {
        console.warn('[ConditionBadges]', e);
    }
}

async function loadConditionBadges() {
    const agentBadges = document.getElementById('agent-condition-badges');
    if (!hasValidCharacter()) {
        if (agentBadges) agentBadges.innerHTML = '';
    } else {
        await _loadConditionBadgesFor(currentCharacterName, 'agent-condition-badges');
    }
    const playerName = typeof getPlayerCharacterName === 'function' ? getPlayerCharacterName() : '';
    if (playerName) await _loadConditionBadgesFor(playerName, 'player-condition-badges');
}

// ============================================================================
// LIVE-STATE-TICK (3s)
// ============================================================================
// Pollt /state/snapshot, verteilt das Ergebnis an die Render-Funktionen.
// Ersetzt den 10s-_pollUnreadChats und deckt Mood/Activity/Location/Status/
// Conditions/Sidebar/Medium ab. Stream-Events bleiben fuer Sub-Sekunden-
// Latenz waehrend einer aktiven Antwort verantwortlich.

let _liveTickTimer = null;
let _liveTickETag = '';
let _liveTickLastAgentExprKey = '';
let _liveTickLastAvatarExprKey = '';
const LIVE_TICK_INTERVAL_MS = 3000;

function _renderPlayerHeaderLines(avatarBlock) {
    if (!avatarBlock) return;
    const pRoom = document.getElementById('player-room-line');
    const pAct  = document.getElementById('player-activity-line');
    const pMood = document.getElementById('player-mood-line');
    if (pRoom) {
        const loc = avatarBlock.location_name || '';
        const room = avatarBlock.room_name || '';
        const txt = loc ? (room ? `📍 ${loc} — ${room}` : `📍 ${loc}`) : '';
        pRoom.textContent = txt; pRoom.style.display = txt ? '' : 'none';
    }
    if (pAct) {
        const act = avatarBlock.activity || '';
        const det = avatarBlock.activity_detail || '';
        let txt = '';
        if (act && det && det.toLowerCase() !== act.toLowerCase()) txt = `🎯 ${act} (${det})`;
        else if (act) txt = `🎯 ${act}`;
        else if (det) txt = `🎯 ${det}`;
        pAct.textContent = txt; pAct.style.display = txt ? '' : 'none';
    }
    if (pMood) {
        const mood = avatarBlock.mood || '';
        const txt = mood ? `💭 ${mood}` : '';
        pMood.textContent = txt; pMood.style.display = txt ? '' : 'none';
    }
}

function _renderAgentHeaderLines(agentBlock) {
    if (!agentBlock) return;
    // Header-State (Room + Activity-Lines + Title)
    _updateHeaderActivity(
        agentBlock.location_name || '',
        agentBlock.activity || '',
        agentBlock.room_id || '',
        agentBlock.room_name || '',
        agentBlock.activity_detail || ''
    );
    // Mood-Line
    const moodLine = document.getElementById('header-mood-line');
    if (moodLine) {
        const mood = agentBlock.mood || '';
        const txt = mood ? `💭 ${mood}` : '';
        moodLine.textContent = txt;
        moodLine.style.display = txt ? '' : 'none';
    }
    // Mood-Overlay im Bild bleibt versteckt — Mood ist im Header.
}

function _applySnapshot(snap) {
    if (!snap) return;

    // Unread-Cache aus Snapshot fuettern (frueher von _pollUnreadChats gemacht)
    if (snap.unread && typeof snap.unread === 'object') {
        const wasEmpty = !Object.keys(_unreadChats).length;
        _unreadChats = snap.unread.chats || {};
        if (wasEmpty && Object.keys(_unreadChats).length) {
            // Erste Befuellung: aktuellen Stand als gesehen markieren, damit
            // nicht alle bekannten Chats als "neu" leuchten.
            for (const name of Object.keys(_unreadChats)) {
                if (localStorage.getItem(_seenKey(name)) === null) {
                    const latest = _latestFor(name);
                    if (latest) localStorage.setItem(_seenKey(name), latest);
                }
            }
        }
    }

    // Agent
    if (snap.agent && hasValidCharacter() && snap.agent.name === currentCharacterName) {
        _renderAgentHeaderLines(snap.agent);
        _renderStatusBarsData('status-effects-bars', snap.agent.status_effects, snap.agent.bar_meta);
        _renderConditionBadgesData('agent-condition-badges', snap.agent.conditions);
    } else if (!hasValidCharacter()) {
        // Sicherheits-Clear (Tick koennte direkt nach Char-Deselect feuern)
        const seBars = document.getElementById('status-effects-bars');
        if (seBars) { seBars.innerHTML = ''; seBars.style.display = 'none'; }
        const acb = document.getElementById('agent-condition-badges');
        if (acb) acb.innerHTML = '';
    }

    // Avatar
    if (snap.avatar) {
        _renderPlayerHeaderLines(snap.avatar);
        _renderStatusBarsData('player-status-bars', snap.avatar.status_effects, snap.avatar.bar_meta);
        _renderConditionBadgesData('player-condition-badges', snap.avatar.conditions);
    }

    // Sidebar aus Snapshot rendern — keine extra Fetches.
    if (typeof loadCharacterSidebar === 'function') {
        const playerName = (typeof getPlayerCharacterName === 'function')
            ? getPlayerCharacterName() : '';
        loadCharacterSidebar({
            sidebar: snap.sidebar || {},
            playerName: playerName,
        });
    }
    _updatePhoneBtnBadge();

    // Chat-Medium aus Server-Hint (mirrors FE-Logik exakt)
    if (snap.medium && snap.medium !== currentChatMedium) {
        _recomputeChatMedium(snap.medium);
    }

    // Expression-Refresh nur wenn Mood/Activity sich geaendert haben
    // (vermeidet unnoetige Bild-Requests).
    if (snap.agent && hasValidCharacter()) {
        const k = `${snap.agent.mood}|${snap.agent.activity}|${snap.agent.activity_detail}`;
        if (k !== _liveTickLastAgentExprKey) {
            _liveTickLastAgentExprKey = k;
            if (typeof updateCharacterScene === 'function') {
                updateCharacterScene(currentCharacterName);
            }
        }
    }
    if (snap.avatar) {
        const k = `${snap.avatar.mood}|${snap.avatar.activity}|${snap.avatar.activity_detail}`;
        if (k !== _liveTickLastAvatarExprKey) {
            _liveTickLastAvatarExprKey = k;
            if (typeof updatePlayerExpression === 'function') {
                const playerName = (typeof getPlayerCharacterName === 'function')
                    ? getPlayerCharacterName() : '';
                if (playerName) updatePlayerExpression(playerName);
            }
        }
    }
}

async function _tickLiveState() {
    // Pause waehrend aktiver Chat-Antwort — Stream-Events uebernehmen
    if (typeof isChatBusy !== 'undefined' && isChatBusy) return;
    // Nur wenn Chat-Tab aktiv (oder kein Tab — z.B. Init) ticken
    const activeTab = document.querySelector('.tab-btn.tab-active')?.dataset.tab;
    if (activeTab && activeTab !== 'chat') return;

    // JS-Null-Strings rausfiltern — sonst landet "undefined"/"null" als
    // Character-Name auf dem Backend und legt dort Geister-Verzeichnisse an.
    const _isBogus = (n) => !n || n === 'KI' ||
        ['undefined','null','none','nan'].includes(String(n).toLowerCase());
    const _agentRaw = currentCharacterName;
    const agent = _isBogus(_agentRaw) ? '' : _agentRaw;
    const _avatarRaw = (typeof getPlayerCharacterName === 'function')
        ? getPlayerCharacterName() : '';
    const avatar = _isBogus(_avatarRaw) ? '' : _avatarRaw;
    if (!agent && !avatar) return;

    try {
        const headers = {};
        if (_liveTickETag) headers['If-None-Match'] = `"${_liveTickETag}"`;
        const url = `/state/snapshot?agent=${encodeURIComponent(agent)}&avatar=${encodeURIComponent(avatar)}`;
        const resp = await fetch(url, { headers, cache: 'no-store' });
        if (resp.status === 304) return;
        if (!resp.ok) return;
        const etag = resp.headers.get('ETag') || '';
        if (etag) _liveTickETag = etag.replace(/^"|"$/g, '');
        const snap = await resp.json();
        _applySnapshot(snap);
    } catch (e) {
        console.warn('[Tick]', e);
    }
}

function _startLiveTick() {
    if (_liveTickTimer) return;
    _tickLiveState();  // sofort einmal
    _liveTickTimer = setInterval(_tickLiveState, LIVE_TICK_INTERVAL_MS);
}

function _stopLiveTick() {
    if (_liveTickTimer) { clearInterval(_liveTickTimer); _liveTickTimer = null; }
    _liveTickETag = '';
}

// Sofortiger Tick z.B. nach Stream-Ende, Char-Wechsel, Avatar-Move
function _triggerImmediateTick() {
    _liveTickETag = '';  // ETag ignorieren — wir wollen den frischen State
    _tickLiveState();
}

// === INTERACTIVE STORY SYSTEM ===

let _currentStory = null;       // Geladene Story-Daten
let _currentStoryFile = null;   // Aktueller Dateiname
let _storyAbortCtrl = null;     // AbortController fuer laufenden Stream

async function loadStoryList() {
    const cardsEl = document.getElementById('story-cards');
    const badgeEl = document.getElementById('story-character-name');
    if (!cardsEl) return;

    const _storyChar = getPlayerCharacterName() || currentCharacterName;

    if (badgeEl) badgeEl.textContent = _storyChar;

    try {
        const resp = await fetch(`/story/list?character_name=${encodeURIComponent(_storyChar)}`);
        if (!resp.ok) throw new Error('Error loading');
        const data = await resp.json();
        const stories = data.stories || [];

        if (stories.length === 0) {
            cardsEl.innerHTML = `<p class="story-empty">${escapeHtml(t('No matching stories for this character.'))}</p>`;
            return;
        }

        cardsEl.innerHTML = stories.map(s => {
            const hasSaved = s.has_saved_state;
            const btnLabel = hasSaved ? 'Fortsetzen' : 'Starten';
            const btnClass = hasSaved ? 'story-continue-btn' : 'story-start-btn';
            const savedInfo = hasSaved && s.current_section ? `<span class="story-saved-badge">⏸ ${escapeHtml(s.current_section)}</span>` : '';
            return `
            <div class="story-card">
                <div class="story-card-body">
                    <h3 class="story-card-title">${escapeHtml(s.title || s.filename)}</h3>
                    <p class="story-card-desc">${escapeHtml(s.description || '')}</p>
                    ${savedInfo}
                </div>
                <div class="story-card-footer">
                    <button class="${btnClass}" onclick="startStory('${escapeHtml(s.filename)}')">${btnLabel}</button>
                    <button class="story-restart-small" onclick="loadStoryIntoDev('${escapeHtml(s.filename)}')">In Dev laden</button>
                    ${hasSaved ? `<button class="story-restart-small" onclick="restartStoryFromList('${escapeHtml(s.filename)}')">Neustart</button>` : ''}
                </div>
            </div>`;
        }).join('');
    } catch (error) {
        console.error('[Story] Fehler:', error);
        cardsEl.innerHTML = `<p class="story-empty">${escapeHtml(t('Error loading stories'))}</p>`;
    }
}

async function startStory(filename) {
    const _storyChar = getPlayerCharacterName();
    if (!_storyChar) return;

    try {
        const resp = await fetch(`/story/detail/${encodeURIComponent(filename)}?character_name=${encodeURIComponent(_storyChar)}`);
        if (!resp.ok) throw new Error('Story nicht gefunden');
        const data = await resp.json();

        _currentStory = data.story;
        _currentStoryFile = filename;

        // Zur Play-Ansicht wechseln
        document.getElementById('story-list-view').style.display = 'none';
        document.getElementById('story-play-view').style.display = 'block';
        document.getElementById('story-play-title').textContent = _currentStory.meta.title || filename;
        document.getElementById('story-scene-content').innerHTML = '';
        document.getElementById('story-scene-image').innerHTML = '';
        document.getElementById('story-options').innerHTML = '';

        // Start-Section oder gespeicherte Position
        const state = data.state;
        const sectionId = (state && state.current_section) ? state.current_section : 'start';
        playSection(sectionId, null);
    } catch (error) {
        console.error('[Story] Start-Fehler:', error);
        showStatusToast(t('Error loading story'), 'error');
    }
}

async function playSection(sectionId, userChoice) {
    if (!_currentStory || !_currentStoryFile) return;

    const contentEl = document.getElementById('story-scene-content');
    const imageEl = document.getElementById('story-scene-image');
    const optionsEl = document.getElementById('story-options');

    // Reset
    contentEl.innerHTML = `<div class="story-loading">${escapeHtml(t('Loading…'))}</div>`;
    imageEl.innerHTML = '';
    optionsEl.innerHTML = '';
    // Remove previous speak button and audio player
    const oldSpeakBtn = contentEl.parentElement.querySelector('.story-speak-action');
    if (oldSpeakBtn) oldSpeakBtn.remove();
    const oldAudio = contentEl.parentElement.querySelector('.tts-audio-player');
    if (oldAudio) oldAudio.remove();
    const oldSpinner = document.getElementById('story-audio-loading');
    if (oldSpinner) oldSpinner.remove();

    // Vorherigen Stream abbrechen
    if (_storyAbortCtrl) _storyAbortCtrl.abort();
    _storyAbortCtrl = new AbortController();

    try {
        const resp = await fetch('/story/play', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                character_name: getPlayerCharacterName(),
                story_filename: _currentStoryFile,
                section_id: sectionId,
                user_choice: userChoice,
            }),
            signal: _storyAbortCtrl.signal,
        });

        if (!resp.ok) throw new Error('Play-Fehler');

        const reader = resp.body.getReader();
        const decoder = new TextDecoder();
        let fullText = '';
        let _storyChunkPlayer = null;
        contentEl.innerHTML = '';

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            const chunk = decoder.decode(value, { stream: true });
            const lines = chunk.split('\n');

            for (const line of lines) {
                if (!line.startsWith('data: ')) continue;
                const jsonStr = line.slice(6).trim();
                if (!jsonStr) continue;

                try {
                    const evt = JSON.parse(jsonStr);

                    if (evt.content) {
                        fullText += evt.content;
                        contentEl.innerHTML = marked.parse(stripExternalImages(fullText));
                        contentEl.scrollTop = contentEl.scrollHeight;
                    }

                    if (evt.options) {
                        renderStoryOptions(evt.options, sectionId);
                    }

                    if (evt.story_end) {
                        optionsEl.innerHTML = `
                            <div class="story-end-banner">Geschichte beendet</div>
                            <button class="story-start-btn" onclick="restartStory()">Nochmal spielen</button>
                            <button class="story-back-btn" onclick="exitStory()">Zurueck zur Liste</button>
                        `;
                    }

                    if (evt.generating_image === true) {
                        imageEl.innerHTML = '<div class="story-image-loading"><span class="story-spinner"></span> Bild wird erzeugt...</div>';
                    }

                    if (evt.generating_image === false) {
                        imageEl.innerHTML = '';
                    }

                    if (evt.visualization && evt.visualization.image_urls) {
                        const urls = evt.visualization.image_urls;
                        imageEl.innerHTML = urls.map(u =>
                            `<img src="${u}" class="story-viz-img" onclick="openLightbox('${u}')" alt="Szene">`
                        ).join('');
                    }

                    if (evt.generating_audio === true) {
                        let spinner = document.getElementById('story-audio-loading');
                        if (!spinner) {
                            spinner = document.createElement('div');
                            spinner.id = 'story-audio-loading';
                            spinner.className = 'tts-loading';
                            spinner.innerHTML = '<span class="story-spinner"></span> Audio wird erzeugt...';
                            contentEl.parentElement.appendChild(spinner);
                        }
                    }
                    if (evt.generating_audio === false) {
                        const spinner = document.getElementById('story-audio-loading');
                        if (spinner) spinner.remove();
                    }
                    if (evt.audio_chunk) {
                        if (!_storyChunkPlayer) {
                            const sp = document.getElementById('story-audio-loading');
                            if (sp) sp.remove();
                            _storyChunkPlayer = createTtsChunkPlayer(contentEl.parentElement);
                        }
                        _storyChunkPlayer.addChunk(evt.audio_chunk);
                    }
                    if (evt.audio && evt.audio.url) {
                        // Fallback: Komplettes Audio (wenn Chunked TTS deaktiviert)
                        const spinner = document.getElementById('story-audio-loading');
                        if (spinner) spinner.remove();
                        appendAudioPlayer(contentEl.parentElement, evt.audio.url);
                    }

                    if (evt.error) {
                        contentEl.innerHTML += `<div class="story-error">Fehler: ${escapeHtml(evt.error)}</div>`;
                    }
                } catch (parseErr) {
                    // Ignoriere ungueltige JSON-Zeilen
                }
            }
        }
        // Add TTS speak button after stream completes
        const existingSpeakBtn = contentEl.parentElement.querySelector('.story-speak-action');
        if (existingSpeakBtn) existingSpeakBtn.remove();
        const speakBtn = document.createElement('button');
        speakBtn.className = 'story-speak-action';
        speakBtn.innerHTML = '&#128266; Vorlesen';
        speakBtn.title = 'Vorlesen (Text markieren = nur Auswahl)';
        speakBtn.addEventListener('click', async () => {
            speakBtn.disabled = true;
            speakBtn.innerHTML = '&#9203; Lade...';
            const selection = window.getSelection();
            let text = '';
            if (selection && selection.toString().trim() && contentEl.contains(selection.anchorNode)) {
                text = selection.toString().trim();
            } else {
                text = contentEl.innerText.trim();
            }
            try {
                const resp = await fetch('/tts/speak', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        text: text,
                        
                        character_name: getPlayerCharacterName(),
                    })
                });
                const result = await resp.json();
                if (result.audio_url) {
                    appendAudioPlayer(contentEl.parentElement, result.audio_url);
                } else if (result.error) {
                    showStatusToast(result.error, 'error');
                }
            } catch (e) {
                console.error('[Story TTS] Error:', e);
                showStatusToast(t('Audio generation failed'), 'error');
            }
            speakBtn.innerHTML = '&#128266; Vorlesen';
            speakBtn.disabled = false;
        });
        contentEl.parentElement.insertBefore(speakBtn, imageEl);

    } catch (error) {
        if (error.name === 'AbortError') return;
        console.error('[Story] Stream-Fehler:', error);
        contentEl.innerHTML = `<div class="story-error">${escapeHtml(t('Error loading scene'))}</div>`;
    }
}

function renderStoryOptions(options, currentSectionId) {
    const optionsEl = document.getElementById('story-options');
    if (!optionsEl || !options || options.length === 0) return;

    const section = _currentStory ? _currentStory.sections[currentSectionId] : null;
    const optionsMap = section ? (section.options_map || {}) : {};

    optionsEl.innerHTML = options.map(opt => {
        const nextSection = optionsMap[opt.letter] || currentSectionId;
        if (nextSection === '_end') {
            return `<button class="story-option-btn story-option-end" onclick="endStoryFromOption(this)">
                <span class="story-option-letter">${escapeHtml(opt.letter)}</span>
                <span class="story-option-text">${escapeHtml(opt.text)}</span>
            </button>`;
        }
        return `<button class="story-option-btn" onclick="chooseOption('${escapeHtml(opt.letter)}', '${escapeHtml(nextSection)}', this)">
            <span class="story-option-letter">${escapeHtml(opt.letter)}</span>
            <span class="story-option-text">${escapeHtml(opt.text)}</span>
        </button>`;
    }).join('');
}

function endStoryFromOption(btnEl) {
    // Alle Buttons deaktivieren, gewahlten hervorheben
    document.querySelectorAll('.story-option-btn').forEach(btn => {
        btn.disabled = true;
        btn.classList.remove('chosen');
    });
    if (btnEl) btnEl.classList.add('chosen');

    const optionsEl = document.getElementById('story-options');
    setTimeout(() => {
        optionsEl.innerHTML = `
            <div class="story-end-banner">Geschichte beendet</div>
            <button class="story-start-btn" onclick="restartStory()">Nochmal spielen</button>
            <button class="story-back-btn" onclick="exitStory()">Zurueck zur Liste</button>
        `;
    }, 600);
}

function chooseOption(letter, nextSection, btnEl) {
    if (!letter || !nextSection) return;

    // Alle Buttons deaktivieren, gewahlten hervorheben
    document.querySelectorAll('.story-option-btn').forEach(btn => {
        btn.disabled = true;
        btn.classList.remove('chosen');
    });
    if (btnEl) btnEl.classList.add('chosen');

    const choiceText = btnEl ? btnEl.querySelector('.story-option-text')?.textContent || '' : '';
    playSection(nextSection, { letter, text: choiceText });
}

function exitStory() {
    if (_storyAbortCtrl) _storyAbortCtrl.abort();
    _currentStory = null;
    _currentStoryFile = null;

    document.getElementById('story-play-view').style.display = 'none';
    document.getElementById('story-list-view').style.display = 'block';
    loadStoryList();
}

async function restartStory() {
    if (!_currentStoryFile || !hasValidCharacter()) return;
    if (!confirm('Story wirklich neu starten?')) return;

    try {
        await fetch('/story/restart', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                character_name: getPlayerCharacterName(),
                story_filename: _currentStoryFile,
            }),
        });

        // Zurueck zum Start
        document.getElementById('story-scene-content').innerHTML = '';
        document.getElementById('story-scene-image').innerHTML = '';
        document.getElementById('story-options').innerHTML = '';
        playSection('start', null);
    } catch (error) {
        console.error('[Story] Restart-Fehler:', error);
        showStatusToast(t('Restart error'), 'error');
    }
}

async function restartStoryFromList(filename) {
    if (!confirm('Fortschritt loeschen und neu starten?')) return;

    try {
        await fetch('/story/restart', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                character_name: getPlayerCharacterName(),
                story_filename: filename,
            }),
        });
        showStatusToast(t('Progress cleared'), 'success');
        loadStoryList();
    } catch (error) {
        console.error('[Story] Restart-Fehler:', error);
        showStatusToast(t('Error'), 'error');
    }
}

async function loadStoryIntoDev(filename) {
    try {
        const resp = await fetch(`/story/raw/${encodeURIComponent(filename)}`);
        if (!resp.ok) throw new Error('Story nicht gefunden');
        const data = await resp.json();

        // Model muss im StoryDev ausgewaehlt sein
        const selectEl = document.getElementById('storydev-model-select');
        const modelJson = selectEl.value;
        if (!modelJson) {
            showStatusToast(t('Please choose a model in the Story Dev tab first'), 'error');
            switchTab('storydev');
            return;
        }
        const { model, provider } = JSON.parse(modelJson);

        // Session im Backend anlegen
        const loadResp = await fetch('/story-dev/load', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ model, provider, content: data.content, source_filename: filename }),
        });
        if (!loadResp.ok) throw new Error('Session konnte nicht erstellt werden');
        const loadData = await loadResp.json();

        // Frontend-State setzen
        _storyDevSessionId = loadData.session_id;
        _storyDevRawResult = data.content;
        _storyDevSourceFilename = filename;

        // Zum StoryDev Tab wechseln und Ergebnis anzeigen
        switchTab('storydev');
        document.getElementById('storydev-config').style.display = 'none';
        document.getElementById('storydev-result').style.display = '';
        document.getElementById('storydev-result-title').textContent = 'Story bearbeiten: ' + filename;
        document.getElementById('storydev-result-content').innerHTML = marked.parse(stripExternalImages(data.content));
        document.getElementById('storydev-overwrite-btn').style.display = '';

        showStatusToast(t('Story loaded into Dev — refine now'), 'success');
    } catch (error) {
        console.error('[Story] Load-into-Dev Fehler:', error);
        showStatusToast(t('Error') + ': ' + error.message, 'error');
    }
}

async function randomizeActivity() {
    if (!hasValidCharacter()) return;

    const btn = document.getElementById('btn-random-activity');
    if (btn) btn.disabled = true;

    try {
        // Aktuelle Location ermitteln
        const locResp = await fetch(`/characters/${currentCharacterName}/current-location`);
        if (!locResp.ok) {
            showStatusToast(t('No location set'), 'error');
            return;
        }
        const locData = await locResp.json();
        const locationName = locData.current_location || '';
        if (!locationName) {
            showStatusToast(t('Choose a location first'), 'error');
            return;
        }

        // Activities fuer diese Location holen (Bibliothek + Location + Character)
        const locations = _cachedWorldLocations || await _fetchWorldLocations();
        const loc = locations.find(l => l.name === locationName);
        let activities = loc ? (loc.activities || []).map(a => typeof a === 'string' ? a : (a.name || '')) : [];

        // Fallback: alle Activities wenn Location keine hat
        if (activities.length === 0) {
            try {
                const actResp = await fetch(`/world/activities`);
                if (actResp.ok) {
                    const actData = await actResp.json();
                    activities = (actData.activities || []).map(a => a.name || a);
                }
            } catch (e) {
                console.error('[RandomActivity] Activities laden fehlgeschlagen:', e);
            }
        }

        if (activities.length === 0) {
            showStatusToast(t('No activities available'), 'error');
            return;
        }

        // Zufaellige Activity waehlen
        const randomActivity = activities[Math.floor(Math.random() * activities.length)];

        // Activity setzen (Backend leitet Room automatisch ab)
        const actResp = await fetch(`/characters/${currentCharacterName}/current-activity`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ current_activity: randomActivity })
        });
        if (actResp.ok) {
            const actData = await actResp.json();
            if (actData.current_room_id) {
                _currentCharacterRoom = actData.current_room_id;
                // Background NICHT auf Partner-Raum umschalten — der Hintergrund
                // bleibt am Avatar-Standort (Prinzip: Background = Avatar-Sicht).
            }
        }

        // Mood auf "normal" zuruecksetzen
        await fetch(`/characters/${currentCharacterName}/current-feeling`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ current_feeling: 'normal' })
        });

        // Header aktualisieren
        _updateHeaderActivity('', randomActivity, _currentCharacterRoom);
        await loadHeaderMood();
        loadStatusEffectsBars();
        loadConditionBadges();

        showStatusToast(`🎲 ${randomActivity}`, 'success');
    } catch (error) {
        console.error('[RandomActivity] Fehler:', error);
        showStatusToast(t('Error'), 'error');
    } finally {
        if (btn) btn.disabled = false;
    }
}

// =====================================================================
// Aufgaben Panel (Queue)
// =====================================================================
let _queuePanelOpen = false;
let _queuePollInterval = null;
let _queueTimerInterval = null;

function _tickQueueTimers() {
    const now = Date.now();
    document.querySelectorAll('.queue-elapsed[data-started]').forEach(el => {
        const ts = el.dataset.started;
        // Server sendet lokale Zeit ohne TZ-Suffix — als lokale Zeit interpretieren
        const started = new Date(ts).getTime();
        if (isNaN(started)) return;
        const secs = Math.max(0, Math.floor((now - started) / 1000));
        if (secs < 60) el.textContent = `${secs}s`;
        else el.textContent = `${Math.floor(secs / 60)}m ${secs % 60}s`;
        const p90 = parseFloat(el.dataset.p90 || '0');
        if (p90 > 0 && secs > p90) el.classList.add('queue-elapsed-overdue');
        else el.classList.remove('queue-elapsed-overdue');
    });
}

function toggleQueuePanel() {
    const panel = document.getElementById('queue-panel');
    if (!panel) return;
    _queuePanelOpen = !_queuePanelOpen;
    panel.style.display = _queuePanelOpen ? 'flex' : 'none';
    if (_queuePanelOpen) {
        _restorePanelWidth('queue-panel');
        fetchQueueStatus();
        _queuePollInterval = setInterval(fetchQueueStatus, 2000);
        _queueTimerInterval = setInterval(_tickQueueTimers, 1000);
    } else {
        if (_queuePollInterval) { clearInterval(_queuePollInterval); _queuePollInterval = null; }
        if (_queueTimerInterval) { clearInterval(_queueTimerInterval); _queueTimerInterval = null; }
    }
}

// --- Panel Resize Handle ---
function _restorePanelWidth(panelId) {
    const saved = localStorage.getItem('panelWidth_' + panelId);
    if (saved) {
        const panel = document.getElementById(panelId);
        if (panel) panel.style.width = saved + 'px';
    }
}

(function initPanelResize() {
    document.addEventListener('pointerdown', function(e) {
        const handle = e.target.closest('.panel-resize-handle');
        if (!handle) return;
        const panelId = handle.dataset.panel;
        const side = handle.dataset.side; // "right" = Panel rechts, "left" = Panel links
        const panel = document.getElementById(panelId);
        if (!panel) return;

        e.preventDefault();
        handle.classList.add('dragging');
        document.body.classList.add('panel-resizing');
        handle.setPointerCapture(e.pointerId);

        const minWidth = 260;
        const maxWidth = Math.floor(window.innerWidth * 0.8);

        function onMove(ev) {
            let newWidth;
            if (side === 'left') {
                // Panel links fixiert: Breite = Mausposition
                newWidth = ev.clientX;
            } else {
                // Panel rechts fixiert: Breite = Fensterbreite - Mausposition
                newWidth = window.innerWidth - ev.clientX;
            }
            panel.style.width = Math.min(maxWidth, Math.max(minWidth, newWidth)) + 'px';
        }

        function onUp() {
            handle.classList.remove('dragging');
            document.body.classList.remove('panel-resizing');
            handle.removeEventListener('pointermove', onMove);
            handle.removeEventListener('pointerup', onUp);
            localStorage.setItem('panelWidth_' + panelId, parseInt(panel.style.width));
        }

        handle.addEventListener('pointermove', onMove);
        handle.addEventListener('pointerup', onUp);
    });
})();

async function fetchQueueStatus() {
    try {
        const resp = await fetch('/queue/status');
        if (!resp.ok) return;
        const data = await resp.json();
        renderQueueStatus(data);
    } catch (e) {
        console.error('[Queue] Fetch error:', e);
    }
}

async function forceResumeQueues() {
    try {
        const resp = await fetch('/queue/force-resume', {method: 'POST'});
        const data = await resp.json();
        if (data.status === 'resumed') {
            showToast(`Queue fortgesetzt (${data.cleared.length} bereinigt)`, 'success');
        } else {
            showToast('Keine pausierten Queues', 'info');
        }
        fetchQueueStatus();
    } catch (e) {
        console.error('[Queue] Force-resume error:', e);
        showToast('Fehler beim Fortsetzen', 'error');
    }
}

// Cancel a ProviderQueue (LLM) task
async function cancelQueueTask(taskId) {
    try {
        const resp = await fetch(`/queue/tasks/${encodeURIComponent(taskId)}`, {method: 'DELETE'});
        const data = await resp.json();
        if (data.status === 'cancelled') {
            showToast('Task abgebrochen', 'success');
        } else {
            showToast(t('Task not found or already running'), 'warning');
        }
        fetchQueueStatus();
    } catch (e) {
        console.error('[Queue] Cancel error:', e);
        showToast('Fehler beim Abbrechen', 'error');
    }
}

// Cancel a background TaskQueue task
async function cancelBgTask(taskId) {
    try {
        const resp = await fetch(`/queue/tasks/item/${encodeURIComponent(taskId)}`, {method: 'DELETE'});
        if (resp.ok) {
            const data = await resp.json();
            showToast('Task abgebrochen', 'success');
        } else {
            showToast('Task nicht mehr pending', 'warning');
        }
        fetchQueueStatus();
    } catch (e) {
        console.error('[Queue] BG cancel error:', e);
        showToast('Fehler beim Abbrechen', 'error');
    }
}

// Move a background task to another queue
async function moveBgTask(taskId, targetQueue) {
    if (!targetQueue) return;
    try {
        const resp = await fetch(
            `/queue/tasks/item/${encodeURIComponent(taskId)}/move?queue_name=${encodeURIComponent(targetQueue)}`,
            {method: 'POST'}
        );
        if (resp.ok) {
            showToast(`Task → ${targetQueue}`, 'success');
        } else {
            showToast('Verschieben fehlgeschlagen', 'warning');
        }
        fetchQueueStatus();
    } catch (e) {
        showToast('Fehler beim Verschieben', 'error');
    }
}

// Pause / resume a background queue
async function pauseBgQueue(queueName) {
    try {
        await fetch(`/queue/tasks/${encodeURIComponent(queueName)}/pause`, {method: 'POST'});
        showToast(`Queue "${queueName}" pausiert`, 'info');
        fetchQueueStatus();
    } catch (e) { showToast('Fehler', 'error'); }
}

async function resumeBgQueue(queueName) {
    try {
        await fetch(`/queue/tasks/${encodeURIComponent(queueName)}/resume`, {method: 'POST'});
        showToast(`Queue "${queueName}" fortgesetzt`, 'success');
        fetchQueueStatus();
    } catch (e) { showToast('Fehler', 'error'); }
}

function _renderTaskMeta(t) {
    // Provider + Model meta line
    // GPU-Tasks (image_generation etc.): Provider steht schon im Section-Header,
    // model enthält Backend-Name — nur diesen anzeigen
    const isGpuTask = t.task_id && t.task_id.startsWith('gpu_');
    if (isGpuTask) {
        return t.model ? escapeHtml(t.model) : '';
    }
    const parts = [];
    // Tracked Image-Gen-Tasks tragen den Backend-Namen in `provider` (z.B.
    // "Together", "CivitAI") — fuer Cloud-Backends ohne eigenen Channel
    // ist das die einzige Sichtbarkeit.
    if (t.provider_name) parts.push(escapeHtml(t.provider_name));
    else if (t.provider) parts.push(escapeHtml(t.provider));
    if (t.model) parts.push(escapeHtml(t.model));
    // Iteration progress for chat_active tasks (StreamingAgent reports
    // current/max iteration each time it starts a new LLM call).
    if (t.iteration && t.max_iterations) {
        parts.push(`<span class="queue-task-iter" title="Iteration des Agent-Turns">iter ${t.iteration}/${t.max_iterations}</span>`);
    }
    return parts.length > 0 ? parts.join(' / ') : '';
}

function _renderTaskEstimate(task) {
    const est = task.estimated_duration_s;
    if (!est || est <= 0) return '';
    const samples = task.estimated_samples || 0;
    const title = `${t('estimated from')} ${samples} ${t('historic calls')}`;
    return `<span class="queue-task-estimate" title="${escapeHtml(title)}">~${est.toFixed(1)}s</span>`;
}

// Bildet aus dem Channel-Key (z.B. "Evo-X2:gpu0") + den dazugehoerigen
// gpu_configs einen lesbaren Display-Namen (z.B. "Evo-X2 RTX 3090").
// Wenn keine Label-Konfiguration vorliegt, bleibt der Channel-Key unveraendert.
function _formatChannelName(channelKey, gpuConfigs) {
    if (!channelKey || !channelKey.includes(':gpu')) return channelKey;
    const label = gpuConfigs && gpuConfigs[0] && gpuConfigs[0].label
        ? gpuConfigs[0].label
        : '';
    if (!label) return channelKey;
    const providerBase = channelKey.split(':')[0];
    return `${providerBase} ${label}`;
}

function renderQueueStatus(data) {
    const container = document.getElementById('queue-content');
    if (!container) return;

    let html = '';

    // ── PROVIDER SECTION (with inline task details) ─────────────────
    const providers = data.providers || {};
    const providerNames = Object.keys(providers).sort();
    if (providerNames.length > 0) {
        html += `<div class="queue-section queue-provider-section">`;
        for (const pName of providerNames) {
            const p = providers[pName];
            const pRunning = p.current_tasks || [];
            const pPending = p.pending || [];

            // Provider ohne Aktivität ausblenden (z.B. nicht erreichbare oder ungenutzte Cloud-Provider wie Anthropic)
            const pRecent = p.recent || [];
            const hasActivity = pRunning.length > 0 || pPending.length > 0 || pRecent.length > 0 || p.chat_active;
            const hasVram = p.vram && p.vram.vram_total_mb;
            if (!hasActivity && (!p.available || !hasVram)) continue;

            const vram = p.vram;
            // healthy = Provider erreichbar UND (bei comfyui-Channels) Backend erreichbar.
            // Fallback auf p.available wenn das Backend das Feld noch nicht liefert.
            const isHealthy = (p.healthy !== undefined) ? p.healthy : p.available;
            const statusDot = isHealthy ? 'dot-active' : 'dot-inactive';
            const statusTitle = isHealthy
                ? ''
                : (p.available
                    ? 'Backend nicht erreichbar (Channel)'
                    : 'Provider nicht erreichbar');
            const pendingCnt = pPending.length;
            const runningCnt = pRunning.length;
            const taskInfo = (pendingCnt || runningCnt)
                ? `<span class="queue-provider-tasks">${runningCnt ? `${runningCnt} aktiv` : ''}${runningCnt && pendingCnt ? ' · ' : ''}${pendingCnt ? `${pendingCnt} wartend` : ''}</span>`
                : '';

            if (vram && vram.vram_total_mb) {
                const loadedNames = (vram.loaded_models || []).map(m => m.size_mb ? `${m.name} (${m.size_mb} MB)` : m.name).join(', ');
                const gpuList = vram.gpus && vram.gpus.length ? vram.gpus : null;
                // Channel-Display: "Provider:gpuN" -> "Provider <GPU-Label>" sofern
                // der GPU-Eintrag ein konfiguriertes Label hat (z.B. "RTX 3090").
                const _displayName = _formatChannelName(pName, p.gpu_configs);

                html += `<div class="queue-provider-row">
                    <div class="queue-provider-header">
                        <span class="queue-provider-name"><span class="job-status-dot ${statusDot}"${statusTitle ? ` title="${escapeHtml(statusTitle)}"` : ''}></span>${escapeHtml(_displayName)}</span>
                    </div>`;

                // Per-GPU bars (each queue only has its own GPU(s))
                if (gpuList) {
                    for (const g of gpuList) {
                        const gUsed = g.used_mb || 0;
                        const gTotal = g.total_mb || 0;
                        const gFree = gTotal - gUsed;
                        const gPct = gTotal ? Math.round((gUsed / gTotal) * 100) : 0;
                        const gUtil = g.util_pct;
                        const gUtilText = (gUtil != null && gUtil > 0) ? ` · ${gUtil}%` : '';
                        const gPower = g.power_w ? ` · ${Math.round(g.power_w)}W` : '';
                        const memText = gTotal ? `${_fmtMb(gUsed)} / ${_fmtMb(gTotal)} (${_fmtMb(gFree)} frei)` : 'kein VRAM';
                        html += `
                        <div class="queue-provider-header" style="margin-top:2px;">
                            <span class="queue-provider-vram-text">${escapeHtml(g.name)} ${memText}${gUtilText}${gPower}</span>
                        </div>
                        <div class="queue-vram-bar">
                            <div class="queue-vram-fill${gPct > 85 ? ' vram-high' : ''}" style="width:${gPct}%"></div>
                        </div>`;
                    }
                } else {
                    // Fallback: single aggregated bar (Ollama, ComfyUI direct)
                    const usedMb = vram.vram_used_mb || 0;
                    const totalMb = vram.vram_total_mb;
                    const freeMb = totalMb - usedMb;
                    const pct = Math.round((usedMb / totalMb) * 100);
                    const gpuUtil = vram.gpu_util_pct;
                    const gpuUtilText = (gpuUtil != null && gpuUtil > 0) ? ` · GPU ${gpuUtil}%` : '';
                    html += `
                    <div class="queue-provider-header" style="margin-top:2px;">
                        <span class="queue-provider-vram-text">${_fmtMb(usedMb)} / ${_fmtMb(totalMb)} (${_fmtMb(freeMb)} frei)${gpuUtilText}</span>
                    </div>
                    <div class="queue-vram-bar">
                        <div class="queue-vram-fill${pct > 85 ? ' vram-high' : ''}" style="width:${pct}%"></div>
                    </div>`;
                }

                if (loadedNames) html += `<div class="queue-provider-models">${escapeHtml(loadedNames)}</div>`;
                html += `${taskInfo}
                </div>`;
            } else {
                const _displayName = _formatChannelName(pName, p.gpu_configs);
                html += `<div class="queue-provider-row">
                    <div class="queue-provider-header">
                        <span class="queue-provider-name"><span class="job-status-dot ${statusDot}"${statusTitle ? ` title="${escapeHtml(statusTitle)}"` : ''}></span>${escapeHtml(_displayName)}</span>
                        <span class="queue-provider-vram-text">${escapeHtml(p.type || '')}</span>
                    </div>
                    ${taskInfo}
                </div>`;
            }

            // Running LLM tasks — inline under provider
            for (const t of pRunning) {
                const meta = _renderTaskMeta(t);
                const estHtml = _renderTaskEstimate(t);
                html += `<div class="queue-task queue-task-running queue-provider-task">
                    <div class="queue-task-row">
                        <span class="queue-task-agent">${escapeHtml(t.agent_name || '')}</span>
                        <span class="queue-task-type">${escapeHtml(t.task_type || '')}</span>
                        <span class="queue-task-badge badge-running">laufend <span class="queue-elapsed" data-started="${escapeHtml(t.started_at || t.created_at || '')}"${t.estimated_p90_s ? ` data-p90="${t.estimated_p90_s}"` : ''}></span></span>
                        ${estHtml}
                        ${t.task_id ? `<button class="queue-cancel-btn" onclick="cancelQueueTask('${escapeHtml(t.task_id)}')" title="Abbrechen">✕</button>` : ''}
                    </div>
                    ${meta ? `<div class="queue-task-meta">${meta}</div>` : ''}
                </div>`;
            }
            // Pending LLM tasks — inline under provider
            for (const t of pPending) {
                html += `<div class="queue-task queue-task-pending queue-provider-task">
                    <div class="queue-task-row">
                        <span class="queue-task-agent">${escapeHtml(t.agent_name || '')}</span>
                        <span class="queue-task-type">${escapeHtml(t.task_type || '')}</span>
                        <span class="queue-task-badge badge-pending">p${t.priority || 20}</span>
                        <button class="queue-cancel-btn" onclick="cancelQueueTask('${escapeHtml(t.task_id)}')" title="Abbrechen">✕</button>
                    </div>
                </div>`;
            }
        }
        html += `</div>`;
    }

    // ── BACKGROUND QUEUES (SQLite TaskQueue — queued + tracked) ──────────
    const bgQueues = data.bg_queues || {};
    const bgQueueNames = Object.keys(bgQueues).sort();
    const allQueueNames = bgQueueNames;
    const trackedTasks = data.active_tasks || [];

    // Show section if there are bg queues OR tracked tasks
    if (bgQueueNames.length > 0 || trackedTasks.length > 0) {
        html += `<div class="queue-section">
            <div class="queue-section-title">Background-Queues</div>`;
        for (const qName of bgQueueNames) {
            const q = bgQueues[qName];
            const paused = q.paused;
            const pendingTasks = q.pending || [];
            const runningTasks = q.running || [];
            const pauseBtn = paused
                ? `<button class="queue-bg-btn queue-bg-resume" onclick="resumeBgQueue('${escapeHtml(qName)}')" title="Fortsetzen">▶ Fortsetzen</button>`
                : `<button class="queue-bg-btn queue-bg-pause" onclick="pauseBgQueue('${escapeHtml(qName)}')" title="Pausieren">⏸ Pause</button>`;
            const statusPill = paused
                ? `<span class="queue-bg-status bg-paused">⏸ pausiert</span>`
                : `<span class="queue-bg-status bg-active">● aktiv</span>`;

            html += `<div class="queue-bg-queue">
                <div class="queue-bg-header">
                    <span class="queue-bg-name">${escapeHtml(qName)}</span>
                    ${statusPill}
                    <span class="queue-bg-counts">${runningTasks.length ? `${runningTasks.length} laufend · ` : ''}${pendingTasks.length} wartend</span>
                    ${pauseBtn}
                </div>`;

            // Running bg tasks (queued + tracked)
            for (const t of runningTasks) {
                const typeLabel = t.label || t.task_type;
                const cancelBtn = (t.task_origin === 'tracked' && t.task_id)
                    ? `<button class="queue-cancel-btn" onclick="cancelQueueTask('${escapeHtml(t.task_id)}')" title="Abbrechen">✕</button>`
                    : '';
                html += `<div class="queue-task queue-task-running queue-bg-task">
                    <div class="queue-task-row">
                        <span class="queue-task-agent">${escapeHtml(t.agent_name || '')}</span>
                        <span class="queue-task-type">${escapeHtml(typeLabel)}</span>
                        <span class="queue-task-badge badge-running">laufend <span class="queue-elapsed" data-started="${escapeHtml(t.started_at || '')}"></span></span>
                        ${cancelBtn}
                    </div>
                </div>`;
            }

            // Pending bg tasks
            for (const t of pendingTasks) {
                const otherQueues = allQueueNames.filter(n => n !== qName);
                const moveOptions = otherQueues.map(n =>
                    `<option value="${escapeHtml(n)}">${escapeHtml(n)}</option>`
                ).join('');
                const moveCtrl = otherQueues.length > 0
                    ? `<select class="queue-move-select" onchange="if(this.value){moveBgTask('${escapeHtml(t.task_id)}',this.value);this.value='';}" title="Verschieben nach...">
                         <option value="">→</option>${moveOptions}
                       </select>`
                    : '';
                html += `<div class="queue-task queue-task-pending queue-bg-task">
                    <div class="queue-task-row">
                        <span class="queue-task-agent">${escapeHtml(t.agent_name || '')}</span>
                        <span class="queue-task-type">${escapeHtml(t.task_type)}</span>
                        <span class="queue-task-badge badge-pending">p${t.priority}</span>
                        ${moveCtrl}
                        <button class="queue-cancel-btn" onclick="cancelBgTask('${escapeHtml(t.task_id)}')" title="Abbrechen">✕</button>
                    </div>
                </div>`;
            }

            if (!runningTasks.length && !pendingTasks.length) {
                html += `<div class="queue-bg-empty">${escapeHtml(t('No waiting tasks'))}</div>`;
            }
            html += `</div>`;
        }

        // Tracked tasks (Image Gen, Outfit, TTS, etc.) — shown as inline tasks
        // Only show those NOT already in a bg_queue (to avoid duplicates)
        const bgQueueTaskIds = new Set();
        for (const qName of bgQueueNames) {
            for (const t of (bgQueues[qName].running || [])) bgQueueTaskIds.add(t.task_id);
        }
        const orphanedTracked = trackedTasks.filter(t => !bgQueueTaskIds.has(t.task_id));
        if (orphanedTracked.length > 0) {
            for (const t of orphanedTracked) {
                const typeLabel = t.label || t.task_type;
                const cancelBtn = t.task_id
                    ? `<button class="queue-cancel-btn" onclick="cancelQueueTask('${escapeHtml(t.task_id)}')" title="Abbrechen">✕</button>`
                    : '';
                const meta = _renderTaskMeta(t);
                html += `<div class="queue-task queue-task-running queue-bg-task">
                    <div class="queue-task-row">
                        <span class="queue-task-agent">${escapeHtml(t.agent_name || '')}</span>
                        <span class="queue-task-type">${escapeHtml(typeLabel)}</span>
                        <span class="queue-task-badge badge-running">laufend <span class="queue-elapsed" data-started="${escapeHtml(t.started_at || t.created_at || '')}"></span></span>
                        ${cancelBtn}
                    </div>
                    ${meta ? `<div class="queue-task-meta">${meta}</div>` : ''}
                </div>`;
            }
        }
        html += `</div>`;
    }

    // ── CHAT AKTIV ────────────────────────────────────────────────────
    // "Chat aktiv" enthaelt alle Tasks die die Provider-Queue pausieren —
    // also nicht nur User-Chat-Streams sondern auch Background-Thoughts,
    // Tool-Calls (talk_to), World/Story-Dev, etc. Das Badge muss den
    // tatsaechlichen Task-Typ widerspiegeln, damit man auf einen Blick
    // sieht ob der Provider durch eine User-Interaktion oder einen
    // Background-Job blockiert ist.
    const _CHAT_BADGE_BY_TYPE = {
        user_chat:   { text: 'streaming',  cls: 'badge-chat' },
        chat_stream: { text: 'streaming',  cls: 'badge-chat' },
        thought:     { text: 'denkt',      cls: 'badge-thought' },
        talk_to:     { text: 'spricht an', cls: 'badge-tool' },
        send_message:{ text: 'schreibt',   cls: 'badge-tool' },
        group_chat:  { text: 'gruppe',     cls: 'badge-chat' },
        story:       { text: 'story',      cls: 'badge-story' },
        world_dev:   { text: 'world dev',  cls: 'badge-dev' },
        story_dev:   { text: 'story dev',  cls: 'badge-dev' },
    };
    const chatActive = Array.isArray(data.chat_active)
        ? data.chat_active
        : (data.chat_active ? [data.chat_active] : []);
    if (chatActive.length > 0) {
        html += `<div class="queue-section">
            <div class="queue-section-title">Aktiv</div>`;
        for (const c of chatActive) {
            const meta = _renderTaskMeta(c);
            const badge = _CHAT_BADGE_BY_TYPE[c.task_type] || { text: c.task_type || 'aktiv', cls: 'badge-chat' };
            const estHtml = _renderTaskEstimate(c);
            html += `<div class="queue-task queue-task-chat">
                <div class="queue-task-row">
                    <span class="queue-task-agent">${escapeHtml(c.agent_name || '')}</span>
                    <span class="queue-task-type">${escapeHtml(c.label || c.task_type || '')}</span>
                    <span class="queue-task-badge ${badge.cls}">${escapeHtml(badge.text)} <span class="queue-elapsed" data-started="${escapeHtml(c.created_at || '')}"${c.estimated_p90_s ? ` data-p90="${c.estimated_p90_s}"` : ''}></span></span>
                    ${estHtml}
                </div>
                ${meta ? `<div class="queue-task-meta">${meta}</div>` : ''}
            </div>`;
        }
        html += `</div>`;
    }

    // ── ZULETZT (LLM recent + tracked recent + bg recent) ─────────
    const allRecent = [];
    for (const t of (data.recent || [])) allRecent.push({...t, _label: t.task_type});
    for (const t of (data.recent_tasks || [])) allRecent.push({...t, _label: t.label || t.task_type});
    // Also include recent bg tasks from all queues
    for (const [, q] of Object.entries(bgQueues)) {
        for (const t of (q.recent || [])) allRecent.push({...t, _label: t.label || t.task_type});
    }
    allRecent.sort((a, b) => (b.completed_at || b.created_at || '').localeCompare(a.completed_at || a.created_at || ''));
    const recentCapped = allRecent.slice(0, 25);

    if (recentCapped.length > 0) {
        html += `<div class="queue-section">
            <div class="queue-section-title">Zuletzt (${recentCapped.length})</div>`;
        for (const t of recentCapped) {
            const s = t.status;
            const badge = s === 'completed' ? 'badge-done' : s === 'failed' ? 'badge-failed' : 'badge-cancelled';
            const icon = s === 'completed' ? '✓' : s === 'failed' ? '✗' : '–';
            const dur = t.duration_s ? ` ${t.duration_s}s` : '';
            const meta = _renderTaskMeta(t);
            const errHint = (s === 'failed' && t.error) ? `<div class="queue-task-error">${escapeHtml(t.error.slice(0, 80))}</div>` : '';
            const doneAt = _formatEventTimestamp(t.completed_at || t.created_at || '');
            html += `<div class="queue-task queue-task-done">
                <div class="queue-task-row">
                    <span class="queue-task-agent">${escapeHtml(t.agent_name || '')}</span>
                    <span class="queue-task-type">${escapeHtml(t._label || '')}</span>
                    ${doneAt ? `<span class="queue-task-time">${escapeHtml(doneAt)}</span>` : ''}
                </div>
                <div class="queue-task-row-bottom">
                    <span class="queue-task-meta">${meta || ''}</span>
                    <span class="queue-task-badge ${badge}">${icon}${dur}</span>
                </div>
                ${errHint}
            </div>`;
        }
        html += '</div>';
    }

    // ── FORCE-RESUME (nur wenn Chat-Tasks registriert sind) ───────────
    if (chatActive.length > 0) {
        html += `<div class="queue-force-resume-hint">
            ${t('Queue stuck?')} <button class="queue-force-resume-btn" onclick="forceResumeQueues()" title="${escapeHtml(t('Clean up orphaned chat registrations'))}">${escapeHtml(t('Unstick queue'))}</button>
        </div>`;
    }

    container.innerHTML = html || `<p class="queue-empty">${escapeHtml(t('No active tasks'))}</p>`;
    _tickQueueTimers();
}

function _fmtMb(mb) {
    if (mb >= 1024) return (mb / 1024).toFixed(1) + ' GB';
    return mb + ' MB';
}

// === EVENTS PANEL ===

let _eventsPanelOpen = false;

async function toggleEventsPanel() {
    const panel = document.getElementById('events-panel');
    if (!panel) return;
    _eventsPanelOpen = !_eventsPanelOpen;
    panel.style.display = _eventsPanelOpen ? 'flex' : 'none';
    if (_eventsPanelOpen) {
        _restorePanelWidth('events-panel');
        await _populateEventsLocationDropdown();
        fetchEvents();
    }
}

async function _populateEventsLocationDropdown() {
    const select = document.getElementById('events-location');
    if (!select) return;
    // Locations vom Server laden falls Cache leer
    if (!_cachedWorldLocations || _cachedWorldLocations.length === 0) {
        try {
            const resp = await fetch(`/world/locations`);
            if (resp.ok) {
                const data = await resp.json();
                _cachedWorldLocations = data.locations || [];
                _buildLocationIdMap(_cachedWorldLocations);
            }
        } catch (e) {
            console.error('[Events] Location fetch error:', e);
        }
    }
    const locs = _cachedWorldLocations || [];
    select.innerHTML = '<option value="">Alle Orte (global)</option>';
    for (const loc of locs) {
        select.innerHTML += `<option value="${escapeHtml(loc.id)}">${escapeHtml(loc.name)}</option>`;
    }
}

async function fetchEvents() {
    try {
        // Avatar-Location parallel ziehen — bestimmt, welche Events unter "HIER" landen.
        const avatar = (typeof getPlayerCharacterName === 'function')
            ? getPlayerCharacterName() : '';
        const reqs = [fetch(`/events`)];
        if (avatar) reqs.push(fetch(`/characters/${encodeURIComponent(avatar)}/current-location`));
        const responses = await Promise.all(reqs);
        const evResp = responses[0];
        if (!evResp.ok) return;
        const data = await evResp.json();
        let avatarLocId = '';
        if (responses[1] && responses[1].ok) {
            const d = await responses[1].json();
            avatarLocId = d.current_location_id || d.current_location || '';
        }
        renderEvents(data.events || [], avatarLocId);
    } catch (e) {
        console.error('[Events] Fetch error:', e);
    }
}

function renderEvents(events, avatarLocId) {
    const container = document.getElementById('events-content');
    if (!container) return;
    if (!events || events.length === 0) {
        container.innerHTML = `<p class="events-empty">${escapeHtml(t('No events available.'))}</p>`;
        return;
    }
    // Location-ID -> Name + Name-Frequenz (fuer "unique location"-Filter)
    const locMap = {};
    const nameCount = {};
    for (const loc of (_cachedWorldLocations || [])) {
        locMap[loc.id] = loc.name;
        nameCount[loc.name] = (nameCount[loc.name] || 0) + 1;
    }
    const isUniqueLocation = (locId) => {
        const name = locMap[locId];
        return name ? (nameCount[name] === 1) : false;
    };

    // Buckets:
    //   here   — Avatar-Location (alle Events, hervorgehoben)
    //   global — location_id leer/null (alle Kategorien)
    //   other  — disruption/danger an Locations, deren Name nur einmal vorkommt
    const hereEvents = [];
    const globalEvents = [];
    const otherEvents = [];
    for (const evt of events) {
        const locId = evt.location_id || '';
        if (!locId) {
            globalEvents.push(evt);
            continue;
        }
        if (avatarLocId && locId === avatarLocId) {
            hereEvents.push(evt);
            continue;
        }
        const cat = evt.category || '';
        if ((cat === 'disruption' || cat === 'danger') && isUniqueLocation(locId)) {
            otherEvents.push(evt);
        }
        // sonst: ambient/social ausserhalb der Avatar-Location, oder Events an
        // Klonen — explizit ausgeblendet (Karte zeigt sie weiterhin).
    }

    const catOrder = { danger: 0, disruption: 1, social: 2, ambient: 3, '': 4 };
    const sortBucket = (list) => list.sort((a, b) => {
        const ca = catOrder[a.category || ''] ?? 4;
        const cb = catOrder[b.category || ''] ?? 4;
        if (ca !== cb) return ca - cb;
        return (b.created_at || '').localeCompare(a.created_at || '');
    });
    sortBucket(hereEvents); sortBucket(globalEvents); sortBucket(otherEvents);

    let html = '';
    const avatarLocName = avatarLocId ? (locMap[avatarLocId] || avatarLocId) : '';

    if (hereEvents.length) {
        html += `<div class="events-section events-section-here">
            <div class="events-section-header">📍 ${escapeHtml(t('Here'))}${avatarLocName ? ` · ${escapeHtml(avatarLocName)}` : ''}</div>`;
        for (const evt of hereEvents) html += _renderEventCard(evt, locMap, true);
        html += `</div>`;
    }

    if (globalEvents.length) {
        html += `<div class="events-section events-section-global">
            <div class="events-section-header">🌐 ${escapeHtml(t('Global'))}</div>`;
        for (const evt of globalEvents) html += _renderEventCard(evt, locMap, false);
        html += `</div>`;
    }

    if (otherEvents.length) {
        html += `<div class="events-section events-section-other">
            <div class="events-section-header">📌 ${escapeHtml(t('Other locations'))}</div>`;
        for (const evt of otherEvents) html += _renderEventCard(evt, locMap, false);
        html += `</div>`;
    }

    if (!html) {
        container.innerHTML = `<p class="events-empty">${escapeHtml(t('No events available.'))}</p>`;
        return;
    }
    container.innerHTML = html;
}

function _renderEventCard(evt, locMap, isHereBucket) {
    const catLabels = { ambient: 'Ambient', social: 'Social', disruption: 'Disruption', danger: 'Danger' };
    const locName = evt.location_id ? (locMap[evt.location_id] || evt.location_id) : 'Global';
    const ts = _formatEventTimestamp(evt.created_at || '');
    const expiry = evt.expires_at ? _formatEventExpiry(evt.expires_at) : 'permanent';
    const cat = evt.category || '';
    const isResolved = evt.resolved || false;
    const catBadge = cat ? `<span class="events-card-cat" data-cat="${escapeHtml(cat)}">${catLabels[cat] || cat}</span>` : '';
    const resolvedBadge = isResolved ? `<span class="events-card-cat" style="background:#43a047;">Resolved</span>` : '';
    const resolvedInfo = isResolved && evt.resolved_text
        ? `<div style="font-size:11px;color:#43a047;margin-top:2px;">${escapeHtml(evt.resolved_by || '?')}: ${escapeHtml(evt.resolved_text)}</div>` : '';
    const attempts = (evt.resolution && evt.resolution.attempts) || [];
    let attemptBadge = '';
    let attemptsBlock = '';
    if (attempts.length > 0) {
        const failCount = attempts.filter(a => a.outcome !== 'success').length;
        attemptBadge = `<span class="events-card-cat" style="background:#fb8c00;">Versuche: ${attempts.length}${failCount ? ` (${failCount} fehlgeschl.)` : ''}</span>`;
        const rows = [...attempts].sort((a, b) => (a.when || '').localeCompare(b.when || '')).map(a => {
            const when = _formatEventTimestamp(a.when || '');
            const icon = a.outcome === 'success' ? '✓' : '✗';
            const iconColor = a.outcome === 'success' ? '#43a047' : '#e53935';
            const joint = (a.joint_with && a.joint_with.length) ? ` <span style="color:var(--text-muted);">+${escapeHtml(a.joint_with.join(', '))}</span>` : '';
            const reason = a.reason ? `<div style="font-size:10px;color:#e53935;margin-top:1px;padding-left:14px;">Grund: ${escapeHtml(a.reason)}</div>` : '';
            return `<div style="font-size:11px;margin-top:4px;padding-left:2px;border-left:2px solid ${iconColor};padding-left:6px;">
                <span style="color:${iconColor};font-weight:bold;">${icon}</span>
                <span style="color:var(--text-muted);">${escapeHtml(when)} — ${escapeHtml(a.who || '')}${joint}</span><br>
                <span style="color:var(--text);">${escapeHtml(a.text || '')}</span>
                ${reason}
            </div>`;
        }).join('');
        attemptsBlock = `<div style="margin-top:6px;padding:6px 8px;background:var(--bg-alt);border-radius:4px;">${rows}</div>`;
    }
    const cardStyle = isResolved ? ' style="opacity:0.85;"' : '';
    const hereCls = isHereBucket ? ' events-card-here' : '';
    return `<div class="events-card${hereCls}" data-category="${escapeHtml(cat)}"${cardStyle}>
        <div class="events-card-body">
            <p class="events-card-text">${catBadge}${resolvedBadge}${attemptBadge}${escapeHtml(evt.text)}</p>
            ${resolvedInfo}
            ${attemptsBlock}
            <span class="events-card-meta">${escapeHtml(locName)} · ${escapeHtml(ts)} · ${escapeHtml(expiry)}</span>
        </div>
        <button class="events-card-delete" onclick="deleteEvent('${escapeHtml(evt.id)}')" title="${escapeHtml(t('Delete'))}">&times;</button>
    </div>`;
}

function _formatEventTimestamp(iso) {
    if (!iso) return '';
    try {
        const dt = new Date(iso);
        const now = new Date();
        const diffDays = Math.floor((now - dt) / 86400000);
        const time = dt.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });
        if (diffDays === 0) return `heute ${time}`;
        if (diffDays === 1) return `gestern ${time}`;
        if (diffDays < 7) return `vor ${diffDays} Tagen`;
        return dt.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' }) + ' ' + time;
    } catch (e) { return iso; }
}

function _formatEventExpiry(iso) {
    if (!iso) return '';
    try {
        const exp = new Date(iso);
        const now = new Date();
        const diffMs = exp - now;
        if (diffMs <= 0) return 'abgelaufen';
        const diffMin = Math.floor(diffMs / 60000);
        if (diffMin < 60) return `noch ${diffMin}m`;
        const diffH = Math.floor(diffMin / 60);
        if (diffH < 24) return `noch ${diffH}h`;
        const diffD = Math.floor(diffH / 24);
        return `noch ${diffD}d`;
    } catch (e) { return ''; }
}

async function addEvent() {
    const textEl = document.getElementById('events-text');
    const locEl = document.getElementById('events-location');
    const ttlEl = document.getElementById('events-ttl');
    const text = (textEl?.value || '').trim();
    if (!text) { showStatusToast(t('Text missing'), 'error'); return; }
    try {
        const resp = await fetch('/events', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                text: text,
                location_id: locEl?.value || null,
                ttl_hours: parseInt(ttlEl?.value || '24', 10),
            })
        });
        if (resp.ok) {
            textEl.value = '';
            fetchEvents();
        } else {
            showStatusToast(t('Create error'), 'error');
        }
    } catch (e) {
        console.error('[Events] Add error:', e);
    }
}

async function deleteEvent(eventId) {
    try {
        const resp = await fetch(`/events/${encodeURIComponent(eventId)}`, { method: 'DELETE' });
        if (resp.ok) {
            fetchEvents();
        }
    } catch (e) {
        console.error('[Events] Delete error:', e);
    }
}

// === EVENTS PANEL: TAB SWITCHING + ASSIGNMENTS ===

let _eventsCurrentTab = 'events';
let _assignmentSelectedChars = {};  // {charName: role}

function switchEventsTab(tab) {
    _eventsCurrentTab = tab;
    // Toggle tab buttons
    document.querySelectorAll('.events-tab').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.tab === tab);
    });
    // Toggle forms
    const evtForm = document.getElementById('events-form-events');
    const asgForm = document.getElementById('events-form-assignments');
    if (evtForm) evtForm.style.display = tab === 'events' ? 'flex' : 'none';
    if (asgForm) asgForm.style.display = tab === 'assignments' ? 'flex' : 'none';
    // Toggle title
    const title = document.getElementById('events-panel-title');
    if (title) title.textContent = tab === 'events' ? '\u{1F4CC} Ereignisse' : '\u{1F4CB} Aufgaben';
    // Load content
    if (tab === 'events') {
        fetchEvents();
    } else {
        _populateAssignmentCharacters();
        _populateAssignmentLocations();
        fetchAssignments();
    }
}

async function _populateAssignmentCharacters() {
    const container = document.getElementById('assignment-participants');
    if (!container) return;
    try {
        const resp = await fetch(`/characters/list`);
        if (!resp.ok) return;
        const data = await resp.json();
        const chars = data.characters || data || [];
        container.innerHTML = '';
        for (const name of chars) {
            const div = document.createElement('div');
            div.className = 'assignment-participant' + (_assignmentSelectedChars[name] !== undefined ? ' selected' : '');
            div.textContent = name;
            div.onclick = () => _toggleAssignmentChar(name, div);
            container.appendChild(div);
        }
    } catch (e) {
        console.error('[Assignments] Chars error:', e);
    }
}

async function _populateAssignmentLocations() {
    const select = document.getElementById('assignment-location');
    if (!select) return;
    if (!_cachedWorldLocations || _cachedWorldLocations.length === 0) {
        try {
            const resp = await fetch(`/world/locations`);
            if (resp.ok) {
                const data = await resp.json();
                _cachedWorldLocations = data.locations || [];
            }
        } catch (e) { return; }
    }
    select.innerHTML = '<option value="">Kein Ort</option>';
    for (const loc of (_cachedWorldLocations || [])) {
        select.innerHTML += `<option value="${escapeHtml(loc.id)}">${escapeHtml(loc.name)}</option>`;
    }
}

function _toggleAssignmentChar(name, el) {
    if (_assignmentSelectedChars[name] !== undefined) {
        delete _assignmentSelectedChars[name];
        el.classList.remove('selected');
        // Remove role input
        const roleEl = el.parentElement.querySelector(`.assignment-role-input[data-char="${name}"]`);
        if (roleEl) roleEl.remove();
    } else {
        _assignmentSelectedChars[name] = '';
        el.classList.add('selected');
        // Add role input after the participants row
        const roleInput = document.createElement('input');
        roleInput.className = 'assignment-role-input';
        roleInput.dataset.char = name;
        roleInput.placeholder = `Rolle von ${name}...`;
        roleInput.oninput = () => { _assignmentSelectedChars[name] = roleInput.value; };
        el.parentElement.appendChild(roleInput);
    }
}

async function fetchAssignments() {
    try {
        const resp = await fetch(`/assignments/default`);
        if (!resp.ok) return;
        const data = await resp.json();
        renderAssignments(data || []);
    } catch (e) {
        console.error('[Assignments] Fetch error:', e);
    }
}

const _priorityLabels = { 1: 'Dringend', 2: 'Hoch', 3: 'Normal', 4: 'Niedrig', 5: 'Hintergrund' };

function renderAssignments(assignments) {
    const container = document.getElementById('events-content');
    if (!container) return;
    if (!assignments.length) {
        container.innerHTML = `<p class="events-empty">${escapeHtml(t('No tasks available.'))}</p>`;
        return;
    }
    let html = '';
    for (const a of assignments) {
        const prio = a.priority || 3;
        const prioClass = prio <= 2 ? ` p${prio}` : '';
        const prioLabel = _priorityLabels[prio] || 'Normal';
        const target = a.target_count || 0;
        const participants = Object.entries(a.participants || {}).map(([name, d]) => {
            const role = d.role ? `: ${d.role}` : '';
            const count = (d.progress || []).length;
            const prog = target > 0 ? ` (${count}/${target})` : count ? ` (${count}x)` : '';
            return `${name}${role}${prog}`;
        }).join(', ');
        const isActive = a.status === 'active';
        const statusIcon = a.status === 'completed' ? '\u2705 ' : a.status === 'expired' ? '\u23F0 ' : '';
        const statusClass = !isActive ? ' assignment-card-inactive' : '';
        const expiry = a.expires_at ? _formatEventExpiry(a.expires_at) : '';
        const locId = a.location_id || '';
        const locName = locId && _cachedWorldLocations ? (_cachedWorldLocations.find(l => l.id === locId) || {}).name || '' : '';
        const eid = _escapeHtmlEvents(a.id);
        html += `<div class="assignment-card${statusClass}">
            <div class="assignment-card-header">
                <p class="assignment-card-title">${statusIcon}${_escapeHtmlEvents(a.title)}${locName ? ` <span class="assignment-card-loc">\u{1F4CD} ${_escapeHtmlEvents(locName)}</span>` : ''}</p>
                <span class="assignment-card-priority${prioClass}">${prioLabel}</span>
            </div>
            ${a.description ? `<p class="assignment-card-desc">${_escapeHtmlEvents(a.description)}</p>` : ''}
            ${a.outfit_hint ? `<p class="assignment-card-desc">\u{1F457} ${_escapeHtmlEvents(a.outfit_hint)}</p>` : ''}
            <div class="assignment-card-participants">${_escapeHtmlEvents(participants)}</div>
            ${target > 0 ? (() => {
                const totalProgress = Object.values(a.participants || {}).reduce((s, d) => s + (d.progress || []).length, 0);
                const pct = Math.min(100, Math.round(totalProgress / target * 100));
                return `<div class="assignment-progress-bar"><div class="assignment-progress-fill" style="width:${pct}%"></div><span class="assignment-progress-label">${totalProgress} / ${target}</span></div>`;
            })() : ''}
            <div class="assignment-card-meta">
                <span>${expiry}</span>
                <div class="assignment-card-actions">
                    ${isActive ? `<button onclick="editAssignment('${eid}')" title="Bearbeiten">\u270E</button>` : ''}
                    ${isActive ? `<button onclick="completeAssignment('${eid}')" title="Erledigt">\u2705</button>` : ''}
                    ${!isActive ? `<button onclick="reactivateAssignment('${eid}')" title="Reaktivieren">\u{1F504}</button>` : ''}
                    <button onclick="deleteAssignment('${eid}')" title="L\u00f6schen">&times;</button>
                </div>
            </div>
        </div>`;
    }
    container.innerHTML = html;
}

function _escapeHtmlEvents(text) {
    const d = document.createElement('div');
    d.textContent = text || '';
    return d.innerHTML;
}

async function addAssignment() {
    const title = document.getElementById('assignment-title')?.value?.trim();
    const desc = document.getElementById('assignment-desc')?.value?.trim();
    const priority = parseInt(document.getElementById('assignment-priority')?.value || '3', 10);
    const duration = parseInt(document.getElementById('assignment-duration')?.value || '120', 10);

    if (!title) { showStatusToast(t('Title missing'), 'error'); return; }
    const selectedChars = Object.keys(_assignmentSelectedChars);
    if (!selectedChars.length) { showStatusToast(t('Choose at least one character'), 'error'); return; }

    const participants = {};
    for (const name of selectedChars) {
        participants[name] = { role: _assignmentSelectedChars[name] || '' };
    }

    try {
        const resp = await fetch(`/assignments/default`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                title, description: desc || '', participants, priority,
                duration_minutes: duration || null,
                location_id: document.getElementById('assignment-location')?.value || null,
                outfit_hint: document.getElementById('assignment-outfit')?.value?.trim() || null,
            })
        });
        if (resp.ok) {
            // Clear form
            document.getElementById('assignment-title').value = '';
            document.getElementById('assignment-desc').value = '';
            _assignmentSelectedChars = {};
            _populateAssignmentCharacters();
            fetchAssignments();
            showStatusToast(t('Task created'), 'success');
        } else {
            showStatusToast(t('Create error'), 'error');
        }
    } catch (e) {
        console.error('[Assignments] Add error:', e);
    }
}

async function completeAssignment(id) {
    try {
        const resp = await fetch(`/assignments/default/${id}/complete`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({})
        });
        if (resp.ok) fetchAssignments();
    } catch (e) {
        console.error('[Assignments] Complete error:', e);
    }
}

async function reactivateAssignment(id) {
    const durations = { '60': '1 Stunde', '120': '2 Stunden', '480': '8 Stunden', '1440': '1 Tag', '4320': '3 Tage', '10080': '7 Tage' };
    const choice = prompt('Neue Dauer w\u00e4hlen (Minuten):\n60 = 1h, 120 = 2h, 480 = 8h, 1440 = 1 Tag, 4320 = 3 Tage', '120');
    if (!choice) return;
    const minutes = parseInt(choice, 10);
    if (isNaN(minutes) || minutes <= 0) { showStatusToast(t('Invalid duration'), 'error'); return; }
    const expires_at = new Date(Date.now() + minutes * 60000).toISOString();
    try {
        const resp = await fetch(`/assignments/default/${id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: 'active', expires_at: expires_at })
        });
        if (resp.ok) {
            fetchAssignments();
            showStatusToast(t('Task restarted (progress reset)'), 'success');
        }
    } catch (e) {
        console.error('[Assignments] Reactivate error:', e);
    }
}

let _editingAssignmentId = null;

async function editAssignment(id) {
    // Load assignment data and populate form
    try {
        const resp = await fetch(`/assignments/default/${id}`);
        if (!resp.ok) return;
        const a = await resp.json();
        _editingAssignmentId = id;

        // Fill form fields
        document.getElementById('assignment-title').value = a.title || '';
        document.getElementById('assignment-desc').value = a.description || '';
        document.getElementById('assignment-priority').value = a.priority || 3;
        // Calculate remaining minutes from expires_at
        const durationSel = document.getElementById('assignment-duration');
        if (a.expires_at) {
            const remainingMs = new Date(a.expires_at) - Date.now();
            const remainingMin = Math.max(0, Math.round(remainingMs / 60000));
            // Find closest dropdown option
            const options = Array.from(durationSel.options).map(o => parseInt(o.value, 10)).filter(v => v > 0);
            let best = options[0];
            for (const opt of options) {
                if (Math.abs(opt - remainingMin) < Math.abs(best - remainingMin)) best = opt;
            }
            durationSel.value = String(remainingMin <= 0 ? 60 : best);
        } else {
            durationSel.value = '0'; // Kein Ablauf
        }
        // Location
        await _populateAssignmentLocations();
        const locSel = document.getElementById('assignment-location');
        if (locSel) locSel.value = a.location_id || '';
        document.getElementById('assignment-outfit').value = a.outfit_hint || '';

        // Select participants
        _assignmentSelectedChars = {};
        for (const [name, data] of Object.entries(a.participants || {})) {
            _assignmentSelectedChars[name] = data.role || '';
        }
        await _populateAssignmentCharacters();
        // Fill role inputs
        for (const [name, role] of Object.entries(_assignmentSelectedChars)) {
            const roleInput = document.querySelector(`.assignment-role-input[data-char="${name}"]`);
            if (roleInput) roleInput.value = role;
        }

        // Change button to "save" mode
        const btn = document.querySelector('#events-form-assignments .events-add-btn');
        if (btn) {
            btn.textContent = '\u2714';
            btn.title = 'Speichern';
            btn.onclick = () => saveAssignmentEdit();
        }

        // Scroll form into view
        document.getElementById('assignment-title')?.focus();
    } catch (e) {
        console.error('[Assignments] Edit load error:', e);
    }
}

async function saveAssignmentEdit() {
    if (!_editingAssignmentId) return;
    const title = document.getElementById('assignment-title')?.value?.trim();
    const desc = document.getElementById('assignment-desc')?.value?.trim();
    const priority = parseInt(document.getElementById('assignment-priority')?.value || '3', 10);
    const durationMin = parseInt(document.getElementById('assignment-duration')?.value || '120', 10);

    if (!title) { showStatusToast(t('Title missing'), 'error'); return; }

    const participants = {};
    for (const [name, role] of Object.entries(_assignmentSelectedChars)) {
        participants[name] = { role: role || '' };
    }

    // Compute new expires_at from selected duration
    const patchBody = { title, description: desc || '', priority, participants,
        location_id: document.getElementById('assignment-location')?.value || '',
        outfit_hint: document.getElementById('assignment-outfit')?.value?.trim() || '' };
    if (durationMin > 0) {
        patchBody.expires_at = new Date(Date.now() + durationMin * 60000).toISOString();
    } else {
        patchBody.expires_at = null;
    }

    try {
        const resp = await fetch(`/assignments/default/${_editingAssignmentId}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(patchBody)
        });
        if (resp.ok) {
            _cancelAssignmentEdit();
            fetchAssignments();
            showStatusToast(t('Task saved'), 'success');
        }
    } catch (e) {
        console.error('[Assignments] Save error:', e);
    }
}

function _cancelAssignmentEdit() {
    _editingAssignmentId = null;
    document.getElementById('assignment-title').value = '';
    document.getElementById('assignment-desc').value = '';
    const locSel = document.getElementById('assignment-location');
    if (locSel) locSel.value = '';
    document.getElementById('assignment-outfit').value = '';
    document.getElementById('assignment-priority').value = '3';
    document.getElementById('assignment-duration').value = '120';
    _assignmentSelectedChars = {};
    _populateAssignmentCharacters();
    // Reset button
    const btn = document.querySelector('#events-form-assignments .events-add-btn');
    if (btn) {
        btn.textContent = '+';
        btn.title = 'Erstellen';
        btn.onclick = () => addAssignment();
    }
}

async function deleteAssignment(id) {
    try {
        const resp = await fetch(`/assignments/default/${id}`, { method: 'DELETE' });
        if (resp.ok) fetchAssignments();
    } catch (e) {
        console.error('[Assignments] Delete error:', e);
    }
}

// === STORY ARC PANEL ===

let _storyArcPanelOpen = false;
let _storyArcPollInterval = null;

function toggleStoryArcPanel() {
    const panel = document.getElementById('storyarc-panel');
    if (!panel) return;
    _storyArcPanelOpen = !_storyArcPanelOpen;
    panel.style.display = _storyArcPanelOpen ? 'flex' : 'none';
    if (_storyArcPanelOpen) {
        _restorePanelWidth('storyarc-panel');
        fetchStoryArcStatus();
        _storyArcPollInterval = setInterval(fetchStoryArcStatus, 5000);
    } else {
        if (_storyArcPollInterval) { clearInterval(_storyArcPollInterval); _storyArcPollInterval = null; }
    }
}

async function fetchStoryArcStatus() {
    try {
        const resp = await fetch(`/queue/story-arc/status`);
        if (!resp.ok) return;
        const data = await resp.json();
        renderStoryArcStatus(data);
    } catch (e) {
        console.error('[StoryArc] Fetch error:', e);
    }
}

async function generateStoryArc() {
    const btn = document.querySelector('.storyarc-generate-btn');
    if (btn) { btn.disabled = true; btn.textContent = '⏳'; }
    try {
        const resp = await fetch(`/queue/story-arc/generate`, { method: 'POST' });
        if (resp.ok) {
            const data = await resp.json();
            console.log('[StoryArc] Generate submitted:', data);
            // Status nach kurzer Wartezeit aktualisieren
            setTimeout(fetchStoryArcStatus, 3000);
            setTimeout(fetchStoryArcStatus, 8000);
        } else {
            console.error('[StoryArc] Generate failed:', resp.status, await resp.text());
        }
    } catch (e) {
        console.error('[StoryArc] Generate error:', e);
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = '+'; }
    }
}

function renderStoryArcStatus(data) {
    const container = document.getElementById('storyarc-content');
    if (!container) return;

    if (!data || !data.arcs || data.arcs.length === 0) {
        container.innerHTML = `<p class="storyarc-empty">${escapeHtml(t('No story arcs yet.'))}<br>${escapeHtml(t('Click + to generate one.'))}</p>`;
        return;
    }

    const active = data.arcs.filter(a => a.status === 'active');
    const resolved = data.arcs.filter(a => a.status === 'resolved');

    let html = '';

    if (active.length > 0) {
        html += '<div class="storyarc-section">';
        html += '<div class="storyarc-section-title">Aktiv</div>';
        for (const arc of active) {
            html += renderArcCard(arc);
        }
        html += '</div>';
    }

    if (resolved.length > 0) {
        html += '<div class="storyarc-section">';
        html += '<div class="storyarc-section-title">Abgeschlossen</div>';
        for (const arc of resolved.slice(0, 5)) {
            html += renderArcCard(arc);
        }
        html += '</div>';
    }

    container.innerHTML = html;
}

async function deleteStoryArc(arcId) {
    if (!confirm(t('Really delete this story arc?'))) return;
    try {
        const resp = await fetch(`/queue/story-arc/${encodeURIComponent(arcId)}`, { method: 'DELETE' });
        if (resp.ok) {
            fetchStoryArcStatus();
        } else {
            console.error('[StoryArc] Delete failed:', resp.status);
        }
    } catch (e) {
        console.error('[StoryArc] Delete error:', e);
    }
}

function renderArcCard(arc) {
    const isActive = arc.status === 'active';
    const dotClass = isActive ? 'dot-active' : 'dot-resolved';
    const beats = arc.beats || [];
    const maxBeats = arc.max_beats || 5;
    const tension = arc.tension || 1;
    const participants = (arc.participants || []).join(', ');

    // Tension-Bar: 1-5 Blocks
    let tensionBar = '';
    for (let i = 1; i <= 5; i++) {
        const filled = i <= tension ? 'filled' : '';
        tensionBar += `<span class="tension-block ${filled}"></span>`;
    }

    // Beat-Progress: filled dots
    let beatDots = '';
    for (let i = 0; i < maxBeats; i++) {
        const done = i < beats.length ? 'beat-done' : 'beat-pending';
        beatDots += `<span class="beat-dot ${done}"></span>`;
    }

    // Beats Timeline with images
    let beatsHtml = '';
    if (beats.length > 0) {
        beatsHtml = '<div class="arc-beats"><div class="arc-beats-title">Timeline</div>';
        for (const b of beats) {
            const time = b.timestamp ? new Date(b.timestamp).toLocaleString('de-DE', {day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit'}) : '';
            let imgHtml = '';
            const sceneImg = b.scene_image;
            if (sceneImg && sceneImg.filename && sceneImg.character) {
                const imgUrl = `/characters/${encodeURIComponent(sceneImg.character)}/images/${encodeURIComponent(sceneImg.filename)}`;
                imgHtml = `<img class="arc-beat-img" src="${imgUrl}" alt="Beat ${b.beat}" loading="lazy" onclick="window.open('${imgUrl}','_blank')">`;
            }
            beatsHtml += `<div class="arc-beat-item">${imgHtml}<div class="arc-beat-text"><span class="arc-beat-num">Beat ${b.beat}</span> <span class="arc-beat-time">${time}</span><div class="arc-beat-summary">${escapeHtml(b.summary || '')}</div></div></div>`;
        }
        beatsHtml += '</div>';
    }

    // Current state
    const state = arc.current_state || arc.seed || '';
    const hint = arc.next_beat_hint || '';
    const resolution = arc.resolution || '';

    let stateHtml = '';
    if (isActive && state) {
        stateHtml = `<div class="arc-state"><strong>Stand:</strong> ${escapeHtml(state)}</div>`;
        if (hint) {
            stateHtml += `<div class="arc-hint"><strong>${escapeHtml(t('Next step:'))}</strong> ${escapeHtml(hint)}</div>`;
        }
    } else if (!isActive && resolution) {
        stateHtml = `<div class="arc-resolution"><strong>Abschluss:</strong> ${escapeHtml(resolution)}</div>`;
    }

    // Character outcomes for resolved arcs
    let outcomesHtml = '';
    if (!isActive && arc.character_outcomes && Object.keys(arc.character_outcomes).length > 0) {
        outcomesHtml = '<div class="arc-outcomes"><div class="arc-outcomes-title">Auswirkungen</div>';
        for (const [charName, outcome] of Object.entries(arc.character_outcomes)) {
            outcomesHtml += `<div class="arc-outcome-item"><strong>${escapeHtml(charName)}:</strong> ${escapeHtml(outcome)}</div>`;
        }
        outcomesHtml += '</div>';
    }

    // Delete button
    const deleteBtn = `<button class="arc-delete-btn" onclick="deleteStoryArc('${arc.id}')" title="${escapeHtml(t('Delete arc'))}">🗑</button>`;

    // Created date
    const created = arc.created_at ? new Date(arc.created_at).toLocaleDateString('de-DE', {day: '2-digit', month: '2-digit', year: 'numeric'}) : '';
    const createdHtml = created ? `<span style="font-size:11px;color:var(--text-light);margin-left:auto;">${created}</span>` : '';

    return `<div class="arc-card ${isActive ? 'arc-active' : 'arc-resolved'}">
        <div class="arc-card-header">
            <span class="job-status-dot ${dotClass}"></span>
            <span class="arc-title">${escapeHtml(arc.title || 'Unbenannt')}</span>
            ${createdHtml}
            ${deleteBtn}
        </div>
        <div class="arc-participants">${escapeHtml(participants)}</div>
        <div class="arc-meta">
            <div class="arc-tension"><span class="arc-meta-label">Spannung</span> ${tensionBar}</div>
            <div class="arc-progress"><span class="arc-meta-label">Fortschritt</span> ${beatDots} <span class="arc-beat-count">${beats.length}/${maxBeats}</span></div>
        </div>
        ${stateHtml}
        ${outcomesHtml}
        ${beatsHtml}
    </div>`;
}

// === CHARACTER SIDEBAR ===

async function loadCharacterSidebar(prefetched) {
    // prefetched (optional): { sidebar: {location_id, characters, chatbots},
    //                          playerName: string } — wird vom Live-Tick
    // mitgegeben; spart 3 separate Fetches pro Tick.
    const container = document.getElementById('character-sidebar-content');
    if (!container) return;

    let userLocationId = '';
    let characters;
    let chatbots;
    let _playerChar = '';

    if (prefetched && prefetched.sidebar) {
        userLocationId = prefetched.sidebar.location_id || '';
        characters = prefetched.sidebar.characters || [];
        chatbots = prefetched.sidebar.chatbots || [];
        _playerChar = prefetched.playerName
            || document.getElementById('active-character-select')?.value
            || '';
    } else {
        // 1. Avatar-Position holen (kein Snapshot vorhanden — Standalone-Aufruf)
        let userRoomId = '';
        try {
            const _avatarName = (typeof getPlayerCharacterName === 'function')
                ? getPlayerCharacterName() : '';
            if (_avatarName) {
                const resp = await fetch(`/characters/${encodeURIComponent(_avatarName)}/current-location`);
                if (resp.ok) {
                    const d = await resp.json();
                    userLocationId = d.current_location_id || '';
                    userRoomId = d.current_room || '';
                }
            }
        } catch (e) {
            console.warn('[Sidebar] Avatar-Position laden fehlgeschlagen:', e);
        }

        if (!userLocationId) {
            container.innerHTML = `<div class="character-sidebar-empty">${escapeHtml(t('No location selected. Open the world map.'))}</div>`;
            return;
        }

        try {
            const _qs = `location=${encodeURIComponent(userLocationId)}` +
                        (userRoomId ? `&room=${encodeURIComponent(userRoomId)}` : '');
            const [locResp, botResp] = await Promise.all([
                fetch(`/characters/at-location?${_qs}`),
                fetch(`/characters/chatbots`),
            ]);
            const locData = locResp.ok ? await locResp.json() : {characters: []};
            const botData = botResp.ok ? await botResp.json() : {characters: []};
            characters = locData.characters || [];
            chatbots = botData.characters || [];
        } catch (e) {
            console.error('[Sidebar] Fehler:', e);
            container.innerHTML = `<div class="character-sidebar-empty">${escapeHtml(t('Error loading'))}</div>`;
            return;
        }

        _playerChar = document.getElementById('active-character-select')?.value || '';
        if (!_playerChar) {
            try {
                const _acResp = await fetch(`/account/characters`);
                if (_acResp.ok) {
                    const _acData = await _acResp.json();
                    _playerChar = _acData.active_character || '';
                }
            } catch(e) {}
        }
    }

    // Edge-Case: kein Ort gewaehlt (sowohl prefetched als auch Standalone)
    if (!userLocationId) {
        container.innerHTML = `<div class="character-sidebar-empty">${escapeHtml(t('No location selected. Open the world map.'))}</div>`;
        return;
    }

    try {
        if (characters.length === 0 && chatbots.length === 0) {
            container.innerHTML = `<div class="character-sidebar-empty">${escapeHtml(t('No characters available'))}</div>`;
            return;
        }

        // Sidebar zeigt nur wer im SELBEN Raum ist. Andere Raeume am gleichen
        // Ort sind raeumlich getrennt — die wurden frueher ausgegraut gerendert,
        // das hat aber den Group-Chat fehl-gefuettert + visuell verwirrt.
        const _sameRoom = characters.filter(c => c.same_room && c.name !== _playerChar);

        // Buttons rendern (Announce-Toggle, dann Group-Toggle bei >=2, dann Characters)
        let html = '';
        // Action mode toggle — always visible, lets the avatar perform a concrete action.
        html += `<button class="character-sidebar-btn act-toggle-btn${chatMode === 'act' ? ' active' : ''}" id="btn-act-mode" title="${escapeHtml(t('Perform an action'))}">`;
        html += `<span class="act-toggle-icon">🎭</span>`;
        html += `<span class="character-sidebar-name">${escapeHtml(t('Action'))}</span>`;
        html += `</button>`;
        if (_sameRoom.length >= 2) {
            html += `<button class="character-sidebar-btn group-chat-toggle-btn${chatMode === 'group' ? ' active' : ''}" id="btn-group-mode" title="Gruppenchat">`;
            html += `<span class="group-toggle-icon">${chatMode === 'group' ? '👥' : '👥'}</span>`;
            html += `<span class="character-sidebar-name">Gruppenchat</span>`;
            html += `</button>`;
        }
        let _locRendered = 0;
        for (const ch of _sameRoom) {
            const isGroupParticipant = chatMode === 'group';
            const isChatPartner = !isGroupParticipant && ch.name === currentCharacterName;
            const avatarSrc = ch.avatar_url || generateDefaultAvatar(ch.name);
            const _unread = !isChatPartner && _isChatUnread(ch.name);
            let btnClass = 'character-sidebar-btn';
            if (isChatPartner) btnClass += ' active';
            if (isGroupParticipant) btnClass += ' group-participant';
            if (_unread) btnClass += ' has-unread';
            html += `<button class="${btnClass}" data-character="${escapeHtml(ch.name)}" data-is-bot="0" title="${escapeHtml(ch.name)}${_unread ? ' — neue Nachricht' : ''}">`;
            html += `<img class="character-sidebar-avatar" src="${avatarSrc}" alt="${escapeHtml(ch.name)}" onerror="this.src='${generateDefaultAvatar(ch.name).replace(/'/g, "\\'")}'">`;
            html += `<span class="character-sidebar-name">${escapeHtml(ch.name)}</span>`;
            if (_unread) html += `<span class="character-sidebar-unread-badge" title="Neue Nachricht">💬</span>`;
            html += `</button>`;
            _locRendered++;
        }
        // (other_room-Block entfernt — siehe Kommentar oben)

        // Chatbots als eigene Gruppe mit Header
        const _bots = (chatbots || []).filter(b => b.name !== _playerChar);
        if (_bots.length) {
            html += `<div class="character-sidebar-group-header">🤖 Chat Bots</div>`;
            for (const ch of _bots) {
                const isChatPartner = chatMode !== 'group' && ch.name === currentCharacterName;
                const avatarSrc = ch.avatar_url || generateDefaultAvatar(ch.name);
                const _unread = !isChatPartner && _isChatUnread(ch.name);
                let btnClass = 'character-sidebar-btn';
                if (isChatPartner) btnClass += ' active';
                if (_unread) btnClass += ' has-unread';
                html += `<button class="${btnClass}" data-character="${escapeHtml(ch.name)}" data-is-bot="1" title="${escapeHtml(ch.name)}${_unread ? ' — neue Nachricht' : ''}">`;
                html += `<img class="character-sidebar-avatar" src="${avatarSrc}" alt="${escapeHtml(ch.name)}" onerror="this.src='${generateDefaultAvatar(ch.name).replace(/'/g, "\\'")}'">`;
                html += `<span class="character-sidebar-name">${escapeHtml(ch.name)}</span>`;
                if (_unread) html += `<span class="character-sidebar-unread-badge" title="Neue Nachricht">💬</span>`;
                html += `</button>`;
            }
        }

        if (!_locRendered && !_bots.length) {
            html += `<div class="character-sidebar-empty">${escapeHtml(t('No characters at this location'))}</div>`;
        }
        container.innerHTML = html;

        // 4. Click-Handler
        container.querySelectorAll('.character-sidebar-btn').forEach(btn => {
            btn.addEventListener('click', async (ev) => {
                const name = btn.dataset.character;
                // Toggle-Buttons (Announce, Gruppenchat) haben keine
                // data-character — die haben eigene Handler weiter unten.
                if (!name) return;
                if (isChatBusy) {
                    showStatusToast(t('Character switch not possible while chat is active'), 'error');
                    return;
                }

                // Im Gruppenmodus: Klick auf Character verlässt Gruppe und wechselt
                if (chatMode === 'group') {
                    chatMode = 'direct';
                    _groupSession = null;
                    _updateGroupHeader(false);
                    _showGroupChatBar(false);
                }
                // Action-Modus: Klick auf Character beendet den Action-Modus
                if (chatMode === 'act') {
                    chatMode = 'direct';
                    if (typeof userInput !== 'undefined' && userInput) userInput.placeholder = '';
                }

                if (name === currentCharacterName) {
                    // Bereits aktiver Chat-Partner — nur Sidebar neu rendern,
                    // Medium aus Locations re-deriven (Avatar oder Partner
                    // koennte zwischenzeitlich gewechselt haben).
                    await _recomputeChatMedium();
                    loadCharacterSidebar();
                    return;
                }

                await fetch(`/store/default/chat_partner`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ value: name })
                });
                currentCharacterName = name;
                // Medium ZUERST resolven, dann updateCharacterScene — sonst
                // zeigt das Scene-Bild kurz das Variant obwohl wir im
                // Phone-Chat sind.
                await _recomputeChatMedium();
                updateCharacterScene(name);
                _closeOverlayPanels();
                chatMessages.innerHTML = '';
                _currentCharacterRoom = '';
                _updateHeaderActivity('', '', '');
                setAgentButtonsVisible(true);
                updateStoryTabVisibility();
                await Promise.all([loadKnownInfo(), _loadCharacterHeaderState(name), loadHeaderMood(), loadStatusEffectsBars(), loadConditionBadges()]);
                await loadChatHistory();
                loadInitialPrompt();
                _markChatSeen(name);
                loadCharacterSidebar();
                if (typeof _triggerImmediateTick === 'function') _triggerImmediateTick();

                // KEIN Avatar-Auto-Move mehr beim Character-Klick (frueher: Avatar
                // wurde zur Position des Chat-Partners gezogen). Der Avatar bleibt
                // wo er ist — Raumwechsel macht der User explizit ueber den
                // Room-Picker oder die Weltkarte.

                showStatusToast(t('Character switched') + `: ${name}`, 'success');
            });
        });
        // Group-Toggle Handler
        const groupBtn = document.getElementById('btn-group-mode');
        if (groupBtn) {
            groupBtn.addEventListener('click', async () => {
                if (isChatBusy) return;
                if (chatMode === 'act') _exitActMode();
                chatMode = chatMode === 'direct' ? 'group' : 'direct';
                if (chatMode === 'group') {
                    await _initGroupSession();
                } else {
                    _groupSession = null;
                    _updateGroupHeader(false);
                    _showGroupChatBar(false);
                }
                loadCharacterSidebar();
            });
        }
        // Action-Toggle Handler
        const actBtn = document.getElementById('btn-act-mode');
        if (actBtn) {
            actBtn.addEventListener('click', async () => {
                if (isChatBusy) return;
                if (chatMode === 'act') {
                    _exitActMode();
                } else {
                    await _enterActMode();
                }
            });
        }

    } catch (e) {
        console.error('[Sidebar] Fehler:', e);
        container.innerHTML = `<div class="character-sidebar-empty">${escapeHtml(t('Error loading'))}</div>`;
    }
}


// === WORLD MAP PANEL ===

let _worldMapPanelOpen = false;

function toggleWorldPanel() {
    const panel = document.getElementById('worldmap-panel');
    if (!panel) return;
    _worldMapPanelOpen = !_worldMapPanelOpen;
    if (_worldMapPanelOpen) {
        panel.style.display = 'flex';
        loadWorldPanel();
    } else {
        panel.style.display = 'none';
    }
}

// Klick auf Overlay schliesst Weltkarte
document.addEventListener('DOMContentLoaded', function() {
    const wm = document.getElementById('worldmap-panel');
    if (wm) wm.addEventListener('click', function(e) {
        if (e.target === wm) toggleWorldPanel();
    });
});

async function loadWorldPanel() {
    const content = document.getElementById('worldmap-content');
    if (!content) return;

    content.innerHTML = `<p class="queue-empty">${escapeHtml(t('Loading world map…'))}</p>`;

    try {
        // Parallel: locations, characters list, user profile (fuer User-Location), events (Karten-Marker)
        const [locResp, charsResp, userProfileResp, evResp] = await Promise.all([
            fetch(`/world/locations`),
            fetch(`/characters/list`),
            fetch(`/store/default/user_profile`),
            fetch(`/events`)
        ]);

        const locations = locResp.ok ? (await locResp.json()).locations || [] : [];
        _buildLocationIdMap(locations);
        const characters = charsResp.ok ? (await charsResp.json()).characters || [] : [];
        let userLocation = '';
        if (userProfileResp && userProfileResp.ok) {
            const profileData = await userProfileResp.json();
            userLocation = (profileData.value && profileData.value.current_location) || '';
        }
        // Aktive disruption/danger-Events pro location_id sammeln —
        // wird im Grid als Pin pro Klon angezeigt.
        const eventsByLoc = {};
        if (evResp && evResp.ok) {
            const evData = await evResp.json();
            for (const ev of (evData.events || [])) {
                if (ev.resolved) continue;
                if (ev.category !== 'disruption' && ev.category !== 'danger') continue;
                const lid = ev.location_id || '';
                if (!lid) continue;
                (eventsByLoc[lid] = eventsByLoc[lid] || []).push(ev);
            }
        }

        // Load current location and avatar for all characters in parallel
        const charData = await Promise.all(characters.map(async (name) => {
            const [locResp2, imgResp] = await Promise.all([
                fetch(`/characters/${name}/current-location`),
                fetch(`/characters/${name}/images`)
            ]);
            let charLocation = '';
            let charActivity = '';
            let movementTargetId = '';
            let movementTargetName = '';
            if (locResp2.ok) {
                const d = await locResp2.json();
                charLocation = d.current_location_id || d.current_location || '';
                charActivity = (d.current_activity || '').toString();
                movementTargetId = d.movement_target_id || '';
                movementTargetName = d.movement_target_name || '';
            }
            let avatar = '';
            if (imgResp.ok) {
                const d = await imgResp.json();
                const profileImg = d.profile_image || '';
                if (profileImg) {
                    avatar = `/characters/${encodeURIComponent(name)}/images/${encodeURIComponent(profileImg)}`;
                }
            }
            return { name, location: charLocation, avatar, activity: charActivity,
                     movementTargetId, movementTargetName };
        }));

        renderWorldPanelGrid(locations, charData, userLocation, content, eventsByLoc);

        // Update header mit User-Location (ID → Name aufloesen)
        const headerEl = document.getElementById('worldmap-current-loc');
        if (headerEl) {
            const userLocName = locationIdToName(userLocation);
            headerEl.textContent = userLocName ? `📍 Dein Ort: ${userLocName}` : 'Kein Ort gewaehlt';
        }
    } catch (e) {
        console.error('[WorldMap] Error:', e);
        content.innerHTML = `<p class="queue-empty">${escapeHtml(t('Error loading'))}</p>`;
    }
}

function _getCharactersAtLocation(locationId, charData) {
    return charData.filter(c => c.location === locationId);
}

const WORLDMAP_GRID_COLS = 10;
const WORLDMAP_GRID_ROWS = 10;
const ISO_TILE_W = 180;
const ISO_TILE_H = 90;
let _worldmapZoom = 1.0;
let _worldmapAbort = null; // AbortController for event listeners

function _isoPos(gridX, gridY) {
    // Convert grid coords to isometric screen coords
    const screenX = (gridX - gridY) * (ISO_TILE_W / 2);
    const screenY = (gridX + gridY) * (ISO_TILE_H / 2);
    return { x: screenX, y: screenY };
}

function renderWorldPanelGrid(locations, charData, currentLocation, container, eventsByLoc) {
    eventsByLoc = eventsByLoc || {};
    if (!locations.length && !charData.length) {
        container.innerHTML = `<p class="queue-empty" style="padding:14px">${escapeHtml(t('No locations available. Create locations via the ⚙ gear icon.'))}</p>`;
        return;
    }

    // Placed locations only — placement (unplaced + passable templates)
    // moved to the Game Admin "Map" tab. Clones (template_location_id set)
    // and normal placed locations both render here; everything else is
    // hidden from the main UI map.
    const placedMap = {};
    for (const loc of locations) {
        if (loc.passable && !(loc.template_location_id || '').trim()) continue;
        if (loc.grid_x != null && loc.grid_y != null
            && loc.grid_x >= 0 && loc.grid_y >= 0) {
            placedMap[`${loc.grid_x},${loc.grid_y}`] = loc;
        }
    }

    // Calculate grid dimensions for the iso wrapper
    const offsetX = (WORLDMAP_GRID_ROWS - 1) * (ISO_TILE_W / 2); // shift right so y=max,x=0 is at left edge
    const totalW = (WORLDMAP_GRID_COLS + WORLDMAP_GRID_ROWS - 1) * (ISO_TILE_W / 2) + ISO_TILE_W;
    const totalH = (WORLDMAP_GRID_COLS + WORLDMAP_GRID_ROWS - 1) * (ISO_TILE_H / 2) + ISO_TILE_H + 60;

    // Isometric grid
    let html = `<div class="worldmap-grid-container"><div class="worldmap-iso-wrapper" style="width:${totalW}px;height:${totalH}px"><div class="worldmap-spatial-grid" style="width:${totalW}px;height:${totalH}px">`;
    for (let y = 0; y < WORLDMAP_GRID_ROWS; y++) {
        for (let x = 0; x < WORLDMAP_GRID_COLS; x++) {
            const loc = placedMap[`${x},${y}`];
            const locId = loc ? (loc.id || loc.name) : '';
            const isActive = loc && (locId === currentLocation || loc.name === currentLocation);
            const charsHere = loc ? _getCharactersAtLocation(locId, charData) : [];

            const pos = _isoPos(x, y);
            const left = pos.x + offsetX;
            const top = pos.y;
            // Iso-Basis-Z (weiter hinten = niedriger). Per-Location Override
            // map_z_offset (-10..+10) hebt/senkt das Icon ueber/unter Nachbarn.
            // Multiplikator 10000 stellt sicher, dass eine Stufe Offset komplett
            // dominiert (Iso-Range ist ca. 0..1000 bei 30x30 Grid).
            const baseZ = (x + y) * (WORLDMAP_GRID_COLS + 1) + y;
            const zOffset = (loc && parseInt(loc.map_z_offset)) || 0;
            const zIdx = baseZ + zOffset * 10000;

            const passableCls = (loc && loc.passable) ? ' worldmap-tile-passable' : '';
            html += `<div class="worldmap-grid-cell${loc ? ' occupied' : ''}${isActive ? ' worldmap-tile-active' : ''}${passableCls}" `;
            html += `style="left:${left}px;top:${top}px;z-index:${zIdx}" `;
            html += `data-grid-x="${x}" data-grid-y="${y}"`;
            if (loc) html += ` data-location="${escapeHtml(locId)}"`;
            html += `>`;

            if (loc) {
                const mapIconUrl = `/world/locations/${encodeURIComponent(locId)}/map-icon`;
                const fallbackEmoji = isActive ? '📍' : '🏠';
                html += `<div class="worldmap-cell-content" data-location-id="${escapeHtml(locId)}">`;
                html += `<img class="worldmap-map-bg" src="${mapIconUrl}" alt="" onload="this.closest('.worldmap-grid-cell').classList.add('has-map-bg')" onerror="this.style.display='none';this.nextElementSibling.style.display=''">`;
                html += `<div class="worldmap-cell-emoji" style="display:none">${fallbackEmoji}</div>`;
                html += `</div>`;
                // Name and avatars as direct children of grid-cell, outside cell-content
                html += `<div class="worldmap-cell-name">${escapeHtml(loc.name)}</div>`;
                // Event-Pin: disruption/danger an exakt dieser location_id
                const cellEvents = eventsByLoc[locId] || [];
                if (cellEvents.length) {
                    const hasDanger = cellEvents.some(e => e.category === 'danger');
                    const pinIcon = hasDanger ? '🔥' : '❗';
                    const pinCls = hasDanger ? 'worldmap-event-pin worldmap-event-pin-danger' : 'worldmap-event-pin worldmap-event-pin-disruption';
                    const tooltip = cellEvents.map(e => `${(e.category || '').toUpperCase()}: ${e.text || ''}`).join('\n');
                    html += `<div class="${pinCls}" title="${escapeHtml(tooltip)}">${pinIcon}${cellEvents.length > 1 ? `<span class="worldmap-event-count">${cellEvents.length}</span>` : ''}</div>`;
                }
                if (charsHere.length) {
                    html += `<div class="worldmap-cell-avatars">`;
                    for (const ch of charsHere) {
                        const src = ch.avatar ? ch.avatar : generateDefaultAvatar(ch.name);
                        const traveling = !!ch.movementTargetId && ch.movementTargetId !== locId;
                        const titleSuffix = traveling
                            ? ` — unterwegs nach ${ch.movementTargetName || ch.movementTargetId}`
                            : '';
                        const wrapClass = traveling ? 'worldmap-avatar-wrap traveling' : 'worldmap-avatar-wrap';
                        html += `<span class="${wrapClass}" title="${escapeHtml(ch.name)}${escapeHtml(titleSuffix)}">`;
                        html += `<img class="worldmap-avatar" src="${src}" alt="${escapeHtml(ch.name)}">`;
                        if (traveling) {
                            html += `<span class="worldmap-travel-badge">🚶</span>`;
                        }
                        html += `</span>`;
                    }
                    html += `</div>`;
                }
            }

            html += `</div>`;
        }
    }
    html += '</div></div></div>';

    // Tray: unplaced locations + homeless characters + sleeping off-map
    const locationIds = new Set(locations.map(l => l.id || l.name));
    const _isSleepingOffmap = (c) => !c.location && (c.activity || '').toLowerCase() === 'sleeping';
    const sleepingChars = charData.filter(_isSleepingOffmap);
    const homelessChars = charData.filter(c => !_isSleepingOffmap(c) && (!c.location || !locationIds.has(c.location)));

    // Tray: only homeless / sleeping characters now. Unplaced locations
    // and passable-template stamps moved to the Game Admin "Map" tab.
    if (homelessChars.length || sleepingChars.length) {
        html += '<div class="worldmap-tray">';
        if (homelessChars.length) {
            html += `<div class="worldmap-homeless">`;
            html += `<div class="worldmap-homeless-title">Ohne Ort</div>`;
            html += `<div class="worldmap-homeless-list">`;
            for (const ch of homelessChars) {
                const src = ch.avatar ? ch.avatar : generateDefaultAvatar(ch.name);
                html += `<button class="worldmap-homeless-btn" data-character="${escapeHtml(ch.name)}" title="${escapeHtml(ch.name)}">`;
                html += `<img class="worldmap-avatar" src="${src}" alt="${escapeHtml(ch.name)}">`;
                html += `<span>${escapeHtml(ch.name)}</span>`;
                html += `</button>`;
            }
            html += `</div></div>`;
        }
        if (sleepingChars.length) {
            html += `<div class="worldmap-homeless worldmap-sleeping">`;
            html += `<div class="worldmap-homeless-title">🌙 Schlafend (ausserhalb der Welt)</div>`;
            html += `<div class="worldmap-homeless-list">`;
            for (const ch of sleepingChars) {
                const src = ch.avatar ? ch.avatar : generateDefaultAvatar(ch.name);
                html += `<button class="worldmap-homeless-btn worldmap-sleeping-btn" data-character="${escapeHtml(ch.name)}" title="${escapeHtml(ch.name)} schlaeft">`;
                html += `<img class="worldmap-avatar" src="${src}" alt="${escapeHtml(ch.name)}">`;
                html += `<span>${escapeHtml(ch.name)}</span>`;
                html += `<span class="worldmap-sleep-badge">💤</span>`;
                html += `</button>`;
            }
            html += `</div></div>`;
        }
        html += '</div>';
    }

    // Abort old event listeners before attaching new ones
    if (_worldmapAbort) _worldmapAbort.abort();
    _worldmapAbort = new AbortController();

    container.innerHTML = html;
    // Placement (drag&drop, clone-stamping, unplace) lives in the Game
    // Admin "Map" tab now. The main UI map is display-only — pan & zoom
    // remain so the user can explore.
    _attachWorldmapPan(container, _worldmapAbort.signal);
    _attachWorldmapZoom(container);
    _centerWorldmapScroll(container);
}

function _attachWorldmapPan(container, signal) {
    const gridContainer = container.querySelector('.worldmap-grid-container');
    if (!gridContainer) return;
    let isPanning = false;
    let startX = 0, startY = 0, scrollX = 0, scrollY = 0;

    function stopPan() {
        if (!isPanning) return;
        isPanning = false;
        gridContainer.style.cursor = '';
    }

    gridContainer.addEventListener('mousedown', (e) => {
        if (e.button !== 0) return;
        const cell = e.target.closest('.worldmap-grid-cell');
        if (!cell || cell.classList.contains('occupied')) return;
        e.preventDefault();
        isPanning = true;
        startX = e.clientX;
        startY = e.clientY;
        scrollX = gridContainer.scrollLeft;
        scrollY = gridContainer.scrollTop;
        gridContainer.style.cursor = 'grabbing';
    });

    // Global listeners use signal so they are removed on re-render
    window.addEventListener('mousemove', (e) => {
        if (!isPanning) return;
        e.preventDefault();
        gridContainer.scrollLeft = scrollX - (e.clientX - startX);
        gridContainer.scrollTop = scrollY - (e.clientY - startY);
    }, { signal });

    window.addEventListener('mouseup', stopPan, { signal });
    document.addEventListener('mouseleave', stopPan, { signal });
    window.addEventListener('blur', stopPan, { signal });
}

function _centerWorldmapScroll(container) {
    const gridContainer = container.querySelector('.worldmap-grid-container');
    if (!gridContainer) return;
    // Apply current zoom
    const wrapper = gridContainer.querySelector('.worldmap-iso-wrapper');
    if (wrapper) wrapper.style.transform = `scale(${_worldmapZoom})`;
    // Center scroll on the isometric grid
    requestAnimationFrame(() => {
        const scrollW = gridContainer.scrollWidth - gridContainer.clientWidth;
        const scrollH = gridContainer.scrollHeight - gridContainer.clientHeight;
        gridContainer.scrollLeft = scrollW / 2;
        gridContainer.scrollTop = scrollH / 2;
    });
}

function _attachWorldmapZoom(container) {
    const gridContainer = container.querySelector('.worldmap-grid-container');
    const wrapper = gridContainer?.querySelector('.worldmap-iso-wrapper');
    if (!gridContainer || !wrapper) return;

    gridContainer.addEventListener('wheel', (e) => {
        e.preventDefault();
        const delta = e.deltaY > 0 ? -0.1 : 0.1;
        const oldZoom = _worldmapZoom;
        _worldmapZoom = Math.min(3, Math.max(0.3, _worldmapZoom + delta));
        if (oldZoom === _worldmapZoom) return;

        // Zoom toward mouse position
        const rect = gridContainer.getBoundingClientRect();
        const mouseX = e.clientX - rect.left + gridContainer.scrollLeft;
        const mouseY = e.clientY - rect.top + gridContainer.scrollTop;
        const ratio = _worldmapZoom / oldZoom;

        wrapper.style.transform = `scale(${_worldmapZoom})`;

        requestAnimationFrame(() => {
            gridContainer.scrollLeft = mouseX * ratio - (e.clientX - rect.left);
            gridContainer.scrollTop = mouseY * ratio - (e.clientY - rect.top);
        });
    }, { passive: false });
}

// Event delegation for world map tile clicks
document.getElementById('worldmap-content')?.addEventListener('click', function(e) {
    // Avatar-Bewegung via Karten-Klick wurde entfernt — Bewegung laeuft
    // jetzt ausschliesslich ueber das Direction-Pad neben dem Chat-Input.
    // Die Karte ist nur noch Anzeige (+ Homeless-Character auswaehlen).

    // Homeless-Character geklickt → Character auswaehlen ohne Ortswechsel
    const btn = e.target.closest('.worldmap-homeless-btn');
    if (btn && btn.dataset.character) {
        onHomelessCharacterClick(btn.dataset.character);
    }
});

async function onWorldPanelLocationClick(locationId) {
    // auth guard removed
    if (isChatBusy) {
        showStatusToast(t('Location switch not possible while chat is active'), 'error');
        return;
    }

    try {
        // Ersten Raum der Location bestimmen — Avatar landet immer dort.
        let firstRoomId = '';
        try {
            const _avatarN = (typeof getPlayerCharacterName === 'function')
                ? getPlayerCharacterName() : '';
            const _qs = _avatarN ? `?character_name=${encodeURIComponent(_avatarN)}` : '';
            const _wlResp = await fetch(`/world/locations${_qs}`);
            if (_wlResp.ok) {
                const _wl = await _wlResp.json();
                const _loc = (_wl.locations || []).find(l => l.id === locationId);
                const _rooms = (_loc && _loc.rooms) || [];
                if (_rooms.length) firstRoomId = _rooms[0].id || '';
            }
        } catch (_) {}

        // Set USER location (Legacy-Store) - speichert ID
        await fetch(`/store/default/user_profile`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ fields: { current_location: locationId } })
        });

        // Avatar-Character-Profil mit Location + ersten Raum aktualisieren
        // (Single-Source-of-Truth fuer Sidebar/Picker/Background-Refresh).
        const _avatarName = (typeof getPlayerCharacterName === 'function')
            ? getPlayerCharacterName() : '';
        if (_avatarName) {
            try {
                const _moveResp = await fetch(`/characters/${encodeURIComponent(_avatarName)}/current-location`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        current_location: locationId,
                        current_room: firstRoomId,
                    })
                });
                if (_moveResp.ok) {
                    const _moveData = await _moveResp.json().catch(() => null);
                    _announceRoomEntry(_moveData);
                } else if (_moveResp.status === 403) {
                    const err = await _moveResp.json().catch(() => ({}));
                    const msg = (err && err.detail && err.detail.message) || 'Access denied';
                    if (typeof showCharNoticeBlock === 'function') showCharNoticeBlock(msg);
                }
            } catch (_) {}
        }

        // Agent-Auswahl zuruecksetzen (neuer Ort = kein Agent aktiv)
        currentCharacterName = 'KI';
        updateCharacterScene('KI');
        _closeOverlayPanels();
        _currentCharacterRoom = '';
        _updateHeaderActivity('', '', '');
        await fetch(`/store/default/chat_partner`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: '' })
        });

        // Chat leeren
        chatMessages.innerHTML = '';

        // Header: Agent-Name und Profilbild zuruecksetzen
        document.getElementById('agent-name').textContent = '—';
        document.getElementById('agent-name').title = '';
        document.getElementById('agent-profile-image').style.display = 'none';
        const vidEl = document.getElementById('agent-profile-video');
        if (vidEl) { vidEl.style.display = 'none'; vidEl.src = ''; }

        // Mood/Activity ausblenden
        const moodEl = document.getElementById('header-mood-display');
        if (moodEl) moodEl.style.display = 'none';
        _updateHeaderActivity('', '', '', '', '');

        // Agent-Buttons ausblenden (kein Agent aktiv)
        setAgentButtonsVisible(false);
        // Status-Bars und Condition-Badges des vorigen Agents leeren
        loadStatusEffectsBars();
        loadConditionBadges();
        updateStoryTabVisibility();

        showStatusToast(`📍 ` + t('You are now:') + ` ${locationIdToName(locationId)}`, 'success');

        // Weltkarte schliessen
        const panel = document.getElementById('worldmap-panel');
        if (panel) { panel.style.display = 'none'; _worldMapPanelOpen = false; }

        // Zentraler UI-Refresh (Hintergrund + Player-Header + Sidebar + Items + ...).
        await refreshAfterAvatarMove();
    } catch (error) {
        console.error('[WorldMap] Fehler:', error);
        showStatusToast(t('Error setting location'), 'error');
    }
}

async function onHomelessCharacterClick(characterName) {
    if (characterName === currentCharacterName) return;
    if (isChatBusy) {
        showStatusToast(t('Character switch not possible while chat is active'), 'error');
        return;
    }

    try {
        // Character auswaehlen ohne Ort zu aendern
        await fetch(`/store/default/chat_partner`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ value: characterName })
        });
        currentCharacterName = characterName;
        updateCharacterScene(characterName);
        _closeOverlayPanels();
        chatMessages.innerHTML = '';
        _currentCharacterRoom = '';
        _updateHeaderActivity('', '', '');
        setAgentButtonsVisible(true);
        updateStoryTabVisibility();
        await Promise.all([loadKnownInfo(), _loadCharacterHeaderState(characterName)]);
        await loadChatHistory();
        loadInitialPrompt();
        loadCharacterSidebar();
        showStatusToast(t('Character switched') + `: ${characterName}`, 'success');
    } catch (error) {
        console.error('[WorldMap] Fehler:', error);
        showStatusToast(t('Character switch error'), 'error');
    }
}

// ============================================================
// === STORY DEV ===
// ============================================================

let _storyDevSessionId = null;
let _storyDevBusy = false;
let _storyDevRawResult = '';
let _storyDevSourceFilename = null;

async function storyDevLoadModels() {
    const select = document.getElementById('storydev-model-select');
    if (!select || select.options.length > 1) return;

    try {
        const res = await fetch('/characters/available-models');
        if (!res.ok) return;
        const data = await res.json();

        select.innerHTML = '<option value="">-- Modell waehlen --</option>';

        const groups = [];
        for (const [provName, provInfo] of Object.entries(data.providers || {})) {
            const models = (provInfo.models || []).filter(m => m.name);
            if (!models.length) continue;
            models.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
            groups.push({ provider: provName, models });
        }
        groups.sort((a, b) => a.provider.localeCompare(b.provider));

        for (const group of groups) {
            const optgroup = document.createElement('optgroup');
            optgroup.label = group.provider;
            for (const m of group.models) {
                const opt = document.createElement('option');
                opt.value = JSON.stringify({ model: m.name, provider: group.provider });
                let label = m.display_name || m.name;
                if (m.size_gb > 0) label += ` (${m.size_gb} GB)`;
                else if (m.parameter_size) label += ` (${m.parameter_size})`;
                if (m.pricing && (m.pricing.input > 0 || m.pricing.output > 0)) {
                    label += ` — $${m.pricing.input}/$${m.pricing.output}`;
                }
                opt.textContent = label;
                optgroup.appendChild(opt);
            }
            select.appendChild(optgroup);
        }
    } catch (e) {
        console.error('[StoryDev] Models load failed:', e);
    }
}

async function storyDevGenerate() {
    if (_storyDevBusy) return;

    const selectEl = document.getElementById('storydev-model-select');
    const modelJson = selectEl.value;
    if (!modelJson) {
        showStatusToast(t('Please choose a model'), 'error');
        return;
    }

    const thema = document.getElementById('storydev-thema').value.trim();
    if (!thema) {
        showStatusToast(t('Please enter a topic'), 'error');
        return;
    }

    const { model, provider } = JSON.parse(modelJson);

    const laengeMap = { small: '5-8', medium: '8-15', large: '15-25' };
    const laenge = laengeMap[document.getElementById('storydev-laenge').value] || '8-15';

    const params = {
        thema,
        laenge,
        verzweigungen: document.getElementById('storydev-verzweigungen').value,
        ton: document.getElementById('storydev-ton').value,
        max_antwort: document.getElementById('storydev-max-antwort').value,
    };

    _storyDevSessionId = 'sd-' + Date.now() + '-' + Math.random().toString(36).slice(2);
    _storyDevRawResult = '';
    _storyDevSourceFilename = null;
    _storyDevBusy = true;

    document.getElementById('storydev-result').style.display = '';
    document.getElementById('storydev-generate-btn').disabled = true;
    document.getElementById('storydev-config').style.display = 'none';
    document.getElementById('storydev-overwrite-btn').style.display = 'none';

    const contentEl = document.getElementById('storydev-result-content');
    contentEl.innerHTML = '<div class="storydev-loading"><span class="story-spinner"></span> Story wird generiert...</div>';

    try {
        const response = await fetch('/story-dev/generate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ model, provider, session_id: _storyDevSessionId, params }),
        });
        if (!response.ok) {
            const err = await response.json().catch(() => ({}));
            throw new Error(err.detail || 'Server-Fehler');
        }
        await _storyDevProcessStream(response, contentEl);
    } catch (e) {
        contentEl.innerHTML = `<div class="story-error">Fehler: ${e.message}</div>`;
    } finally {
        _storyDevBusy = false;
        document.getElementById('storydev-generate-btn').disabled = false;
    }
}

async function _storyDevProcessStream(response, contentEl) {
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let fullResponse = '';

    contentEl.innerHTML = '';

    while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n');

        for (const line of lines) {
            if (!line.startsWith('data: ')) continue;
            const jsonStr = line.slice(6).trim();
            if (!jsonStr) continue;

            try {
                const data = JSON.parse(jsonStr);

                if (data.error) {
                    contentEl.innerHTML = `<div class="story-error">Fehler: ${data.error}</div>`;
                    return;
                }

                if (data.content) {
                    fullResponse += data.content;
                    contentEl.innerHTML = marked.parse(stripExternalImages(fullResponse));
                    contentEl.scrollTop = contentEl.scrollHeight;
                }

                if (data.done) {
                    _storyDevRawResult = fullResponse;
                }
            } catch (e) {
                console.warn('[StoryDev] Parse error:', e);
            }
        }
    }

    _storyDevRawResult = fullResponse;
    contentEl.innerHTML = marked.parse(stripExternalImages(fullResponse));
}

async function storyDevRefine() {
    if (_storyDevBusy || !_storyDevSessionId) return;

    const input = document.getElementById('storydev-refine-text');
    const instruction = input.value.trim();
    if (!instruction) return;

    _storyDevBusy = true;
    input.value = '';
    document.getElementById('storydev-refine-btn').disabled = true;

    const contentEl = document.getElementById('storydev-result-content');
    contentEl.innerHTML = '<div class="storydev-loading"><span class="story-spinner"></span> Story wird verbessert...</div>';

    try {
        const response = await fetch('/story-dev/refine', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ session_id: _storyDevSessionId, instruction }),
        });
        if (!response.ok) {
            const err = await response.json().catch(() => ({}));
            throw new Error(err.detail || 'Server-Fehler');
        }
        await _storyDevProcessStream(response, contentEl);
        showStatusToast(t('Story updated'), 'success');
    } catch (e) {
        showStatusToast(t('Refine error') + ': ' + e.message, 'error');
    } finally {
        _storyDevBusy = false;
        document.getElementById('storydev-refine-btn').disabled = false;
    }
}

async function storyDevSave(overwrite) {
    if (!_storyDevSessionId || !_storyDevRawResult) {
        showStatusToast(t('No story to save'), 'error');
        return;
    }

    // Overwrite: save back to original file via PUT
    if (overwrite && _storyDevSourceFilename) {
        try {
            const res = await fetch(`/story/raw/${encodeURIComponent(_storyDevSourceFilename)}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ content: _storyDevRawResult }),
            });
            if (!res.ok) throw new Error('Speichern fehlgeschlagen');
            showStatusToast(t('Story overwritten') + ': ' + _storyDevSourceFilename, 'success');
        } catch (e) {
            showStatusToast(t('Overwrite error'), 'error');
        }
        return;
    }

    try {
        const res = await fetch('/story-dev/save', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ session_id: _storyDevSessionId }),
        });
        const data = await res.json();
        if (data.status === 'success') {
            showStatusToast(t('Story saved') + ': ' + data.filename, 'success');
        } else {
            showStatusToast(data.detail || 'Speichern fehlgeschlagen', 'error');
        }
    } catch (e) {
        showStatusToast(t('Save error'), 'error');
    }
}

function storyDevReset() {
    if (_storyDevSessionId) {
        fetch('/story-dev/cleanup', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ session_id: _storyDevSessionId }),
        }).catch(() => {});
    }

    _storyDevSessionId = null;
    _storyDevRawResult = '';
    _storyDevBusy = false;
    _storyDevSourceFilename = null;

    document.getElementById('storydev-result').style.display = 'none';
    document.getElementById('storydev-result-content').innerHTML = '';
    document.getElementById('storydev-config').style.display = '';
    document.getElementById('storydev-thema').value = '';
    document.getElementById('storydev-refine-text').value = '';
}

// === NOTIFICATIONS PANEL ===

let _notificationsPanelOpen = false;
let _notificationsPollInterval = null;
let _notificationsLastCount = 0;
const _expandedNotificationIds = new Set();  // Persistiert expand-State ueber Re-Renders

function toggleNotificationsPanel() {
    const panel = document.getElementById('notifications-panel');
    if (!panel) return;
    _notificationsPanelOpen = !_notificationsPanelOpen;
    panel.style.display = _notificationsPanelOpen ? 'flex' : 'none';
    if (_notificationsPanelOpen) {
        _restorePanelWidth('notifications-panel');
        loadNotifications();
        // Faster polling when panel is open
        if (_notificationsPollInterval) clearInterval(_notificationsPollInterval);
        _notificationsPollInterval = setInterval(loadNotifications, 5000);
    } else {
        // Back to slow polling
        if (_notificationsPollInterval) clearInterval(_notificationsPollInterval);
        _notificationsPollInterval = setInterval(pollUnreadCount, 30000);
    }
}

async function loadNotifications() {
    try {
        const resp = await fetch(`/notifications?limit=50`);
        if (!resp.ok) return;
        const data = await resp.json();
        renderNotifications(data.notifications || []);
        updateNotificationBadge(data.unread_count || 0);
    } catch (e) {
        console.error('[Notifications] Load error:', e);
    }
}

async function pollUnreadCount() {
    try {
        const resp = await fetch(`/notifications/unread-count`);
        if (!resp.ok) return;
        const data = await resp.json();
        const count = data.unread_count || 0;
        updateNotificationBadge(count);
        // Flash badge if count increased
        if (count > _notificationsLastCount && _notificationsLastCount >= 0) {
            const badge = document.getElementById('notifications-badge');
            if (badge) {
                badge.style.animation = 'none';
                badge.offsetHeight; // force reflow
                badge.style.animation = 'badgePulse 0.5s ease-in-out 3';
            }
        }
        _notificationsLastCount = count;
    } catch (e) {
        // Silently ignore polling errors
    }
}

function updateNotificationBadge(count) {
    const badge = document.getElementById('notifications-badge');
    if (!badge) return;
    if (count > 0) {
        badge.textContent = count > 99 ? '99+' : count;
        badge.style.display = 'flex';
    } else {
        badge.style.display = 'none';
    }
}

function renderNotifications(notifications) {
    const container = document.getElementById('notifications-content');
    if (!container) return;
    if (!notifications.length) {
        container.innerHTML = `<p class="notification-empty">${escapeHtml(t('No messages'))}</p>`;
        return;
    }
    // Expired IDs aus dem Expand-Set bereinigen
    const currentIds = new Set(notifications.map(n => n.id));
    for (const id of Array.from(_expandedNotificationIds)) {
        if (!currentIds.has(id)) _expandedNotificationIds.delete(id);
    }
    container.innerHTML = notifications.map(n => {
        const unreadClass = n.read ? '' : ' unread';
        const timeStr = _formatNotificationTime(n.timestamp);
        const avatarUrl = `/characters/${encodeURIComponent(n.character)}/images/profile`;
        const typeLabel = n.type && n.type !== 'message' ? `<span class="notification-type-badge">${n.type}</span>` : '';
        // Strip markdown for preview
        const preview = (n.content || '').replace(/\*{1,3}(.+?)\*{1,3}/g, '$1').replace(/#{1,6}\s+/g, '');
        const escapedId = n.id.replace(/'/g, "\\'");
        const escapedChar = n.character.replace(/'/g, "\\'");
        const expandedClass = _expandedNotificationIds.has(n.id) ? ' expanded' : '';
        return `<div class="notification-item${unreadClass}" data-id="${n.id}" data-character="${n.character}">
            <img class="notification-avatar" src="${avatarUrl}" alt="${n.character}" onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 40 40%22><rect fill=%22%23667eea%22 width=%2240%22 height=%2240%22/><text x=%2250%%22 y=%2255%%22 text-anchor=%22middle%22 fill=%22white%22 font-size=%2218%22>${n.character.charAt(0)}</text></svg>'">
            <div class="notification-body" onclick="toggleNotificationExpand(this)">
                <div class="notification-character">${n.character}${typeLabel}</div>
                <div class="notification-text${expandedClass}">${preview}</div>
                <div class="notification-time">${timeStr}</div>
            </div>
            <button class="notification-goto-btn" onclick="onNotificationClick('${escapedId}', '${escapedChar}')" title="Zum Chat">&#x2192;</button>
        </div>`;
    }).join('');
}

function _formatNotificationTime(isoStr) {
    if (!isoStr) return '';
    try {
        const d = new Date(isoStr);
        const now = new Date();
        const diffMs = now - d;
        const diffMin = Math.floor(diffMs / 60000);
        if (diffMin < 1) return 'gerade eben';
        if (diffMin < 60) return `vor ${diffMin} Min`;
        const diffHrs = Math.floor(diffMin / 60);
        if (diffHrs < 24) return `vor ${diffHrs} Std`;
        const diffDays = Math.floor(diffHrs / 24);
        if (diffDays < 7) return `vor ${diffDays} Tag${diffDays > 1 ? 'en' : ''}`;
        return d.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit' });
    } catch (e) {
        return '';
    }
}

function toggleNotificationExpand(bodyEl) {
    const textEl = bodyEl.querySelector('.notification-text');
    if (!textEl) return;
    const item = bodyEl.closest('.notification-item');
    const id = item && item.dataset.id;
    const isExpanded = textEl.classList.toggle('expanded');
    if (id) {
        if (isExpanded) _expandedNotificationIds.add(id);
        else _expandedNotificationIds.delete(id);
    }
}

async function onNotificationClick(notificationId, characterName) {
    // Mark as read
    try {
        await fetch(`/notifications/${notificationId}/read`, { method: 'POST' });
        const item = document.querySelector(`.notification-item[data-id="${notificationId}"]`);
        if (item) item.classList.remove('unread');
        // Update badge
        const badge = document.getElementById('notifications-badge');
        if (badge && badge.style.display !== 'none') {
            const current = parseInt(badge.textContent) || 0;
            updateNotificationBadge(Math.max(0, current - 1));
        }
    } catch (e) { /* ignore */ }

    // Count unread notifications from this character to load enough history
    const unreadFromChar = document.querySelectorAll(
        `.notification-item.unread[data-character="${characterName}"]`
    ).length;
    const historyLimit = Math.max(2, unreadFromChar + 1);

    // Switch to character or ensure chat is visible
    if (characterName && characterName !== currentCharacterName) {
        if (!isChatBusy) {
            try {
                await fetch(`/store/default/chat_partner`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ value: characterName })
                });
                // Avatar/User-Location an den Character-Ort ziehen, damit die
                // Sidebar die Mit-Anwesenden an diesem Ort zeigt.
                try {
                    const _locResp = await fetch(`/characters/${encodeURIComponent(characterName)}/current-location`);
                    if (_locResp.ok) {
                        const _locData = await _locResp.json();
                        const _newLocId = _locData.current_location_id || '';
                        if (_newLocId) {
                            const _upResp = await fetch(`/store/default/user_profile`);
                            const _prof = _upResp.ok ? (await _upResp.json()).value || {} : {};
                            _prof.current_location = _newLocId;
                            await fetch(`/store/default/user_profile`, {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({ value: _prof })
                            });
                        }
                    }
                } catch (_locErr) {
                    console.warn('[Notifications] Location-Follow failed:', _locErr);
                }
                currentCharacterName = characterName;
                updateCharacterScene(characterName);
                _closeOverlayPanels();
                document.getElementById('chat-messages').innerHTML = '';
                setAgentButtonsVisible(true);
                updateStoryTabVisibility();
                await loadKnownInfo();
                await loadChatHistory(historyLimit);
                loadCharacterSidebar();
                showStatusToast(t('Character') + `: ${characterName}`, 'success');
            } catch (e) {
                console.error('[Notifications] Character switch error:', e);
            }
        } else {
            showStatusToast(t('Chat is busy right now — please wait a moment'), 'warning');
        }
    } else if (characterName) {
        // Same character — just ensure chat is loaded and panels closed
        _closeOverlayPanels();
        const chatMsgs = document.getElementById('chat-messages');
        if (chatMsgs && chatMsgs.children.length === 0) {
            await loadChatHistory(historyLimit);
        }
    }
    // Close panel
    toggleNotificationsPanel();
}

async function markAllNotificationsRead() {
    try {
        await fetch(`/notifications/read-all`, { method: 'POST' });
        updateNotificationBadge(0);
        // Remove all unread styling
        document.querySelectorAll('.notification-item.unread').forEach(el => el.classList.remove('unread'));
        showStatusToast(t('All messages read'), 'success');
    } catch (e) {
        console.error('[Notifications] Mark all read error:', e);
    }
}

async function loadNotificationStyle() {
    try {
        const resp = await fetch(`/notifications/style`);
        if (!resp.ok) return;
        const data = await resp.json();
        setNotificationStyle(data.style || 'modern');
    } catch (e) { /* ignore */ }
}

function setNotificationStyle(style) {
    if (style === 'modern') {
        delete document.body.dataset.notificationStyle;
    } else {
        document.body.dataset.notificationStyle = style;
    }
}

function startNotificationPolling() {
    if (_notificationsPollInterval) clearInterval(_notificationsPollInterval);
    // Initial fetch
    pollUnreadCount();
    // Poll every 30 seconds
    _notificationsPollInterval = setInterval(pollUnreadCount, 30000);
}

// Enter-Key fuer Refine-Input
document.addEventListener('DOMContentLoaded', () => {
    const refineInput = document.getElementById('storydev-refine-text');
    if (refineInput) {
        refineInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') storyDevRefine();
        });
    }
    // Enter-Key fuer WorldDev-Input
    const wdInput = document.getElementById('worlddev-user-input');
    if (wdInput) {
        wdInput.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                worldDevSend();
            }
        });
    }
});

