let _worldDevBusy = false;
let _worldDevLastLocationData = null;
let _worldDevLastCharacterData = null;
let _worldDevLastOutfitData = null;        // {character_name, outfit: {name, pieces, ...}}
let _worldDevLastSoulData = null;          // {character_name, section, content}
let _worldDevLastProfilePatchData = null;  // {character_name, fields: {...}}
let _worldDevEditLocationId = null;

async function worldDevLoadModels() {
    const select = document.getElementById('worlddev-model-select');
    if (!select || select.options.length > 1) return;

    try {
        const res = await fetch('/characters/available-models');
        if (!res.ok) return;
        const data = await res.json();

        select.innerHTML = '<option value="">-- Modell waehlen --</option>';

        const groups = [];
        for (const [provName, provInfo] of Object.entries(data.providers || {})) {
            const models = (provInfo.models || []).filter(m => m.name);
            if (!models.length) continue;
            models.sort((a, b) => (a.name || '').localeCompare(b.name || ''));
            groups.push({ provider: provName, models });
        }
        groups.sort((a, b) => a.provider.localeCompare(b.provider));

        for (const group of groups) {
            const optgroup = document.createElement('optgroup');
            optgroup.label = group.provider;
            for (const m of group.models) {
                const opt = document.createElement('option');
                opt.value = JSON.stringify({ model: m.name, provider: group.provider });
                let label = m.display_name || m.name;
                if (m.size_gb > 0) label += ` (${m.size_gb} GB)`;
                else if (m.parameter_size) label += ` (${m.parameter_size})`;
                if (m.pricing && (m.pricing.input > 0 || m.pricing.output > 0)) {
                    label += ` — $${m.pricing.input}/$${m.pricing.output}`;
                }
                opt.textContent = label;
                optgroup.appendChild(opt);
            }
            select.appendChild(optgroup);
        }
    } catch (e) {
        console.error('[WorldDev] Models load failed:', e);
    }
}

async function worldDevLoadSchemas() {
    const select = document.getElementById('worlddev-schema-select');
    if (!select) return;

    try {
        const res = await fetch('/world-dev/schemas');
        if (!res.ok) return;
        const data = await res.json();

        select.innerHTML = '';
        for (const s of (data.schemas || [])) {
            const opt = document.createElement('option');
            opt.value = s.name;
            opt.textContent = s.label;
            select.appendChild(opt);
        }
    } catch (e) {
        console.error('[WorldDev] Schema load failed:', e);
    }
}

async function worldDevLoadLocations() {
    const select = document.getElementById('worlddev-location-select');
    if (!select) return;

    select.innerHTML = '<option value="">-- Neuer Ort --</option>';

    try {
        const res = await fetch(`/world/locations`);
        if (!res.ok) return;
        const data = await res.json();

        for (const loc of (data.locations || [])) {
            const opt = document.createElement('option');
            opt.value = loc.id || '';
            opt.textContent = loc.name;
            select.appendChild(opt);
        }
    } catch (e) {
        console.error('[WorldDev] Locations load failed:', e);
    }
}

async function worldDevLoadContextOptions() {

    // Load locations for context (checkboxes). Nur Unique-Orte (passable=false)
    // anbieten — Templates und ihre Klone haben hier keinen Sinn als Kontext-
    // Anker.
    const locContainer = document.getElementById('worlddev-context-locations');
    if (locContainer) {
        locContainer.innerHTML = '';
        try {
            const res = await fetch(`/world/locations`);
            if (res.ok) {
                const data = await res.json();
                const onlyUnique = (data.locations || []).filter(l => !l.passable);
                for (const loc of onlyUnique) {
                    const lbl = document.createElement('label');
                    const cb = document.createElement('input');
                    cb.type = 'checkbox';
                    cb.value = loc.id || '';
                    cb.name = 'worlddev-ctx-loc';
                    lbl.appendChild(cb);
                    lbl.appendChild(document.createTextNode(loc.name));
                    locContainer.appendChild(lbl);
                }
            }
        } catch (e) { /* ignore */ }
    }

    // Load characters for context (checkboxes)
    const charContainer = document.getElementById('worlddev-context-characters');
    if (charContainer) {
        charContainer.innerHTML = '';
        try {
            const res = await fetch(`/characters/list`);
            if (res.ok) {
                const data = await res.json();
                for (const name of (data.characters || [])) {
                    const lbl = document.createElement('label');
                    const cb = document.createElement('input');
                    cb.type = 'checkbox';
                    cb.value = name;
                    cb.name = 'worlddev-ctx-char';
                    lbl.appendChild(cb);
                    lbl.appendChild(document.createTextNode(name));
                    charContainer.appendChild(lbl);
                }
            }
        } catch (e) { /* ignore */ }
    }
}

async function worldDevLoadCharacters() {
    const select = document.getElementById('worlddev-character-select');
    if (!select) return;

    select.innerHTML = '<option value="">-- Neuer Character --</option>';

    try {
        const res = await fetch(`/characters/list`);
        if (!res.ok) return;
        const data = await res.json();

        for (const name of (data.characters || [])) {
            const opt = document.createElement('option');
            opt.value = name;
            opt.textContent = name;
            select.appendChild(opt);
        }
    } catch (e) {
        console.error('[WorldDev] Characters load failed:', e);
    }
}

function worldDevEditLocation() {
    const select = document.getElementById('worlddev-location-select');
    if (!select || !select.value) return;

    // Reset character select
    const charSelect = document.getElementById('worlddev-character-select');
    if (charSelect) charSelect.value = '';

    // Set schema internally
    const schemaEl = document.getElementById('worlddev-schema-select');
    if (schemaEl) schemaEl.value = 'location';

    // Reset session and start edit flow
    _worldDevSessionId = null;
    _worldDevLastLocationData = null;
    _worldDevLastCharacterData = null;
    _worldDevEditLocationId = select.value;
    const locName = select.options[select.selectedIndex].textContent.split(' — ')[0];

    const chatEl = document.getElementById('worlddev-chat-messages');
    if (chatEl) {
        chatEl.innerHTML = '';
    }

    const inputEl = document.getElementById('worlddev-user-input');
    if (inputEl) {
        inputEl.value = `Ich moechte den Ort "${locName}" bearbeiten.`;
        worldDevSend();
    }
}

function worldDevEditCharacter() {
    const select = document.getElementById('worlddev-character-select');
    if (!select || !select.value) return;

    // Reset location select
    const locSelect = document.getElementById('worlddev-location-select');
    if (locSelect) locSelect.value = '';

    // Set schema internally
    const schemaEl = document.getElementById('worlddev-schema-select');
    if (schemaEl) schemaEl.value = 'character';

    // Reset session and start edit flow
    _worldDevSessionId = null;
    _worldDevLastLocationData = null;
    _worldDevLastCharacterData = null;
    _worldDevEditLocationId = select.value;  // reused for character name
    const charName = select.options[select.selectedIndex].textContent;

    const chatEl = document.getElementById('worlddev-chat-messages');
    if (chatEl) {
        chatEl.innerHTML = '';
    }

    const inputEl = document.getElementById('worlddev-user-input');
    if (inputEl) {
        inputEl.value = `Ich moechte den Character "${charName}" bearbeiten.`;
        worldDevSend();
    }
}

function worldDevNewSession() {
    _worldDevSessionId = null;
    _worldDevLastLocationData = null;
    _worldDevLastCharacterData = null;
    _worldDevEditLocationId = null;
    const costEl = document.getElementById('worlddev-cost');
    if (costEl) { costEl.style.display = 'none'; costEl.textContent = ''; }
    const locSelect = document.getElementById('worlddev-location-select');
    if (locSelect) locSelect.value = '';
    const charSelect = document.getElementById('worlddev-character-select');
    if (charSelect) charSelect.value = '';
    const modeSelect = document.getElementById('worlddev-mode-select');
    if (modeSelect) modeSelect.value = 'new';
    worldDevModeChanged();
    const chatEl = document.getElementById('worlddev-chat-messages');
    if (chatEl) {
        chatEl.innerHTML = '<div class="worlddev-welcome"><p>Waehle ein Modell und beschreibe, was du erstellen moechtest.</p></div>';
    }
}

function worldDevModeChanged() {
    const mode = document.getElementById('worlddev-mode-select')?.value || 'new';
    const schemaGroup = document.getElementById('worlddev-schema-group');
    const templateGroup = document.getElementById('worlddev-template-group');
    const editLocGroup = document.getElementById('worlddev-edit-location-group');
    const editCharGroup = document.getElementById('worlddev-edit-character-group');

    if (mode === 'new') {
        if (schemaGroup) schemaGroup.style.display = '';
        if (editLocGroup) editLocGroup.style.display = 'none';
        if (editCharGroup) editCharGroup.style.display = 'none';
        worldDevSchemaChanged();
    } else {
        // Edit mode
        if (schemaGroup) schemaGroup.style.display = 'none';
        if (templateGroup) templateGroup.style.display = 'none';
        if (editLocGroup) editLocGroup.style.display = '';
        if (editCharGroup) editCharGroup.style.display = '';
    }
}

function worldDevSchemaChanged() {
    const schemaEl = document.getElementById('worlddev-schema-select');
    const templateGroup = document.getElementById('worlddev-template-group');
    if (!schemaEl || !templateGroup) return;
    templateGroup.style.display = schemaEl.value === 'character' ? '' : 'none';
}

function _worldDevAppendMessage(role, content) {
    const chatEl = document.getElementById('worlddev-chat-messages');
    if (!chatEl) return null;

    // Remove welcome message
    const welcome = chatEl.querySelector('.worlddev-welcome');
    if (welcome) welcome.remove();

    const msgDiv = document.createElement('div');
    msgDiv.className = `worlddev-msg worlddev-msg-${role}`;

    if (role === 'assistant') {
        msgDiv.innerHTML = typeof marked !== 'undefined' ? marked.parse(content) : content;
    } else {
        msgDiv.textContent = content;
    }

    chatEl.appendChild(msgDiv);
    chatEl.scrollTop = chatEl.scrollHeight;
    return msgDiv;
}

async function worldDevSend() {
    if (_worldDevBusy) return;

    const selectEl = document.getElementById('worlddev-model-select');
    const inputEl = document.getElementById('worlddev-user-input');
    const schemaEl = document.getElementById('worlddev-schema-select');
    const sendBtn = document.getElementById('worlddev-send-btn');

    if (!selectEl || !selectEl.value) {
        alert('Bitte waehle ein Modell aus.');
        return;
    }

    const message = inputEl.value.trim();
    if (!message) return;

    let modelInfo;
    try {
        modelInfo = JSON.parse(selectEl.value);
    } catch (e) {
        alert('Ungueltiges Modell.');
        return;
    }

    _worldDevBusy = true;
    sendBtn.disabled = true;
    inputEl.value = '';

    // Show user message
    _worldDevAppendMessage('user', message);

    // Create assistant message placeholder
    const assistantDiv = _worldDevAppendMessage('assistant', '');
    let fullResponse = '';

    try {
        const body = {
            model: modelInfo.model,
            provider: modelInfo.provider,
            session_id: _worldDevSessionId || '',
            message: message,
            schema: schemaEl ? schemaEl.value : 'location',
            character_template: document.getElementById('worlddev-template-select')?.value || '' || '',
            edit_location_id: _worldDevEditLocationId || '',
            context_location_ids: [],
            context_character_names: [],
        };
        // Only send context + edit_location_id on first message (session creation)
        if (_worldDevSessionId) {
            delete body.edit_location_id;
            delete body.context_location_ids;
            delete body.context_character_names;
        } else {
            // Gather selected context from checkboxes
            body.context_location_ids = Array.from(document.querySelectorAll('input[name="worlddev-ctx-loc"]:checked')).map(cb => cb.value);
            body.context_character_names = Array.from(document.querySelectorAll('input[name="worlddev-ctx-char"]:checked')).map(cb => cb.value);
        }

        const res = await fetch('/world-dev/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
        });

        if (!res.ok) {
            const err = await res.json().catch(() => ({ detail: 'Fehler' }));
            throw new Error(err.detail || 'Request failed');
        }

        const reader = res.body.getReader();
        const decoder = new TextDecoder();
        let buffer = '';

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;

            buffer += decoder.decode(value, { stream: true });
            const lines = buffer.split('\n');
            buffer = lines.pop() || '';

            for (const line of lines) {
                if (!line.startsWith('data: ')) continue;
                try {
                    const data = JSON.parse(line.slice(6));

                    if (data.session_id) {
                        _worldDevSessionId = data.session_id;
                    }
                    if (data.content) {
                        fullResponse += data.content;
                        if (assistantDiv) {
                            assistantDiv.innerHTML = typeof marked !== 'undefined' ? marked.parse(fullResponse) : fullResponse;
                            const chatEl = document.getElementById('worlddev-chat-messages');
                            if (chatEl) chatEl.scrollTop = chatEl.scrollHeight;
                        }
                    }
                    if (data.location_data) {
                        _worldDevLastLocationData = data.location_data;
                        _worldDevShowApplyButton(assistantDiv);
                    }
                    if (data.character_data) {
                        _worldDevLastCharacterData = data.character_data;
                        console.log('[WorldDev] character_data received:', JSON.stringify(data.character_data).substring(0, 200));
                        _worldDevShowApplyButton(assistantDiv);
                    }
                    if (data.outfit_data) {
                        _worldDevLastOutfitData = data.outfit_data;
                        _worldDevShowApplyButton(assistantDiv);
                    }
                    if (data.soul_data) {
                        _worldDevLastSoulData = data.soul_data;
                        _worldDevShowApplyButton(assistantDiv);
                    }
                    if (data.profile_patch_data) {
                        _worldDevLastProfilePatchData = data.profile_patch_data;
                        _worldDevShowApplyButton(assistantDiv);
                    }
                    if (data.usage) {
                        const costEl = document.getElementById('worlddev-cost');
                        if (costEl) {
                            const u = data.usage;
                            const costStr = u.cost_total < 0.01
                                ? `$${u.cost_total.toFixed(4)}`
                                : `$${u.cost_total.toFixed(2)}`;
                            costEl.textContent = `${costStr} (${u.tokens_in + u.tokens_out} tok)`;
                            costEl.style.display = '';
                        }
                    }
                    if (data.error) {
                        fullResponse += `\n\n**Fehler:** ${data.error}`;
                        if (assistantDiv) {
                            assistantDiv.innerHTML = typeof marked !== 'undefined' ? marked.parse(fullResponse) : fullResponse;
                        }
                    }
                } catch (e) { /* ignore parse errors */ }
            }
        }
    } catch (e) {
        console.error('[WorldDev] Chat error:', e);
        if (assistantDiv) {
            assistantDiv.innerHTML += `<div class="worlddev-error">Fehler: ${e.message}</div>`;
        }
    } finally {
        _worldDevBusy = false;
        sendBtn.disabled = false;
        inputEl.focus();
    }
}

function _worldDevShowApplyButton(parentDiv) {
    if (!parentDiv) return;

    // Remove existing apply buttons
    parentDiv.querySelectorAll('.worlddev-apply-btn').forEach(b => b.remove());

    if (_worldDevLastLocationData) {
        const btn = document.createElement('button');
        btn.className = 'save-btn worlddev-apply-btn';
        btn.textContent = `Ort "${_worldDevLastLocationData.name}" uebernehmen`;
        btn.onclick = () => worldDevApply();
        parentDiv.appendChild(btn);
    }
    if (_worldDevLastCharacterData) {
        const btn = document.createElement('button');
        btn.className = 'save-btn worlddev-apply-btn';
        const charName = _worldDevLastCharacterData.character_name || _worldDevLastCharacterData.name || '?';
        btn.textContent = `Character "${charName}" uebernehmen`;
        btn.onclick = () => worldDevApplyCharacter();
        parentDiv.appendChild(btn);
    }
    if (_worldDevLastOutfitData) {
        const btn = document.createElement('button');
        btn.className = 'save-btn worlddev-apply-btn';
        const charN = _worldDevLastOutfitData.character_name || '?';
        const outN = (_worldDevLastOutfitData.outfit || {}).name || '?';
        btn.textContent = `Outfit "${outN}" → ${charN} uebernehmen`;
        btn.onclick = () => worldDevApplyOutfit();
        parentDiv.appendChild(btn);
    }
    if (_worldDevLastSoulData) {
        const btn = document.createElement('button');
        btn.className = 'save-btn worlddev-apply-btn';
        const charN = _worldDevLastSoulData.character_name || '?';
        const sec = _worldDevLastSoulData.section || '?';
        btn.textContent = `Soul "${sec}" → ${charN} uebernehmen`;
        btn.onclick = () => worldDevApplySoul();
        parentDiv.appendChild(btn);
    }
    if (_worldDevLastProfilePatchData) {
        const btn = document.createElement('button');
        btn.className = 'save-btn worlddev-apply-btn';
        const charN = _worldDevLastProfilePatchData.character_name || '?';
        const fieldKeys = Object.keys(_worldDevLastProfilePatchData.fields || {});
        btn.textContent = `Profil-Patch (${fieldKeys.length} Felder) → ${charN}`;
        btn.onclick = () => worldDevApplyProfilePatch();
        parentDiv.appendChild(btn);
    }
}

async function worldDevApply() {
    if (!_worldDevLastLocationData) {
        alert('Keine Daten zum Uebernehmen vorhanden.');
        return;
    }

    try {
        const res = await fetch('/world-dev/apply', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                
                location_data: _worldDevLastLocationData,
            }),
        });

        if (!res.ok) {
            const err = await res.json().catch(() => ({ detail: 'Fehler' }));
            throw new Error(err.detail || 'Apply failed');
        }

        const result = await res.json();
        _worldDevAppendMessage('assistant', `Ort **"${_worldDevLastLocationData.name}"** wurde erfolgreich in die Welt uebernommen!`);
        _worldDevLastLocationData = null;
        _worldDevEditLocationId = null;

        // Remove apply buttons
        document.querySelectorAll('.worlddev-apply-btn').forEach(b => b.remove());

        // Refresh location list
        worldDevLoadLocations();

    } catch (e) {
        console.error('[WorldDev] Apply error:', e);
        alert('Fehler beim Uebernehmen: ' + e.message);
    }
}

async function worldDevApplyCharacter() {
    if (!_worldDevLastCharacterData) {
        alert('Keine Character-Daten zum Uebernehmen vorhanden.');
        return;
    }

    // Normalize: some LLMs use "name" instead of "character_name"
    const charData = { ..._worldDevLastCharacterData };
    if (!charData.character_name && charData.name) {
        charData.character_name = charData.name;
    }

    try {
        const res = await fetch('/world-dev/apply-character', {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                character_data: charData,
                selected_template: document.getElementById('worlddev-template-select')?.value || '',
            }),
        });

        if (!res.ok) {
            const err = await res.json().catch(() => ({ detail: 'Fehler' }));
            throw new Error(err.detail || 'Apply failed');
        }

        const result = await res.json();
        _worldDevAppendMessage('assistant', `Character **"${charData.character_name}"** wurde erfolgreich uebernommen!`);
        _worldDevLastCharacterData = null;
        _worldDevEditLocationId = null;

        // Remove apply buttons
        document.querySelectorAll('.worlddev-apply-btn').forEach(b => b.remove());

    } catch (e) {
        console.error('[WorldDev] Apply character error:', e);
        alert('Fehler beim Uebernehmen: ' + e.message);
    }
}

// ── Granulare Apply-Funktionen (Sub-Block Marker) ──────────────────────────

async function _worldDevPostJson(url, body, label) {
    const res = await fetch(url, {
        method: 'POST',
        credentials: 'same-origin',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
    });
    if (!res.ok) {
        const err = await res.json().catch(() => ({ detail: 'Fehler' }));
        throw new Error(err.detail || `${label} failed`);
    }
    return await res.json();
}

async function worldDevApplyOutfit() {
    const data = _worldDevLastOutfitData;
    if (!data || !data.character_name || !data.outfit) {
        alert('Keine Outfit-Daten zum Uebernehmen.');
        return;
    }
    try {
        const r = await _worldDevPostJson('/world-dev/apply-outfit', data, 'Apply outfit');
        _worldDevAppendMessage('assistant',
            `${t('Outfit')} **"${r.name}"** ${t('for')} ${r.character} ${t('applied')} — ${r.pieces_created} ${t('new pieces,')} ${r.pieces_reused} ${t('reused.')}`);
        _worldDevLastOutfitData = null;
        document.querySelectorAll('.worlddev-apply-btn').forEach(b => b.remove());
    } catch (e) {
        console.error('[WorldDev] Apply outfit error:', e);
        alert('Fehler beim Outfit-Uebernehmen: ' + e.message);
    }
}

async function worldDevApplySoul() {
    const data = _worldDevLastSoulData;
    if (!data || !data.character_name || !data.section) {
        alert('Keine Soul-Daten zum Uebernehmen.');
        return;
    }
    try {
        const r = await _worldDevPostJson('/world-dev/apply-soul', data, 'Apply soul');
        _worldDevAppendMessage('assistant',
            `Soul **"${r.section}"** ${t('for')} ${r.character} ${t('applied')} (${r.size} ${t('characters')}).`);
        _worldDevLastSoulData = null;
        document.querySelectorAll('.worlddev-apply-btn').forEach(b => b.remove());
    } catch (e) {
        console.error('[WorldDev] Apply soul error:', e);
        alert('Fehler beim Soul-Uebernehmen: ' + e.message);
    }
}

async function worldDevApplyProfilePatch() {
    const data = _worldDevLastProfilePatchData;
    if (!data || !data.character_name || !data.fields) {
        alert('Keine Profil-Patch-Daten zum Uebernehmen.');
        return;
    }
    try {
        const r = await _worldDevPostJson('/world-dev/apply-profile-patch', data, 'Apply profile patch');
        _worldDevAppendMessage('assistant',
            `${t('Profile patch')} ${t('for')} ${r.character} ${t('applied')} (${t('Fields:')} ${(r.applied_fields || []).join(', ')}).`);
        _worldDevLastProfilePatchData = null;
        document.querySelectorAll('.worlddev-apply-btn').forEach(b => b.remove());
    } catch (e) {
        console.error('[WorldDev] Apply profile-patch error:', e);
        alert('Fehler beim Profil-Patch: ' + e.message);
    }
}

// ── Manual JSON Import Dialog ──────────────────────────────────────────────
//
// Catch-all for cases the chat-flow doesn't cover: paste any character /
// location / outfit / soul / profile-patch JSON and apply it. Backend does
// type-detect + soul-flatten + template-alias mapping; we just drive the UI.

let _worldDevJsonPreviewTimer = null;
let _worldDevJsonLastPreview = null;  // last server-validated preview blob

function worldDevOpenJsonImport() {
    const modal = document.getElementById('worlddev-json-modal');
    if (!modal) return;
    // Pre-fill with whatever we last picked up from the chat stream — saves
    // the user from manually copying out of the markdown render.
    const ta = document.getElementById('worlddev-json-input');
    const seed = _worldDevLastCharacterData || _worldDevLastLocationData
        || _worldDevLastOutfitData || _worldDevLastSoulData
        || _worldDevLastProfilePatchData;
    if (ta && seed) ta.value = JSON.stringify(seed, null, 2);
    document.getElementById('worlddev-json-type').value = '';
    modal.style.display = 'flex';
    worldDevJsonPreview();
    if (ta) ta.focus();
}

function worldDevCloseJsonImport() {
    const modal = document.getElementById('worlddev-json-modal');
    if (modal) modal.style.display = 'none';
    _worldDevJsonLastPreview = null;
}

function worldDevJsonInputChanged() {
    // Debounce — preview hits the server, no need to fire on every keystroke
    clearTimeout(_worldDevJsonPreviewTimer);
    _worldDevJsonPreviewTimer = setTimeout(worldDevJsonPreview, 300);
}

async function worldDevJsonPreview() {
    const ta = document.getElementById('worlddev-json-input');
    const status = document.getElementById('worlddev-json-status');
    const warnEl = document.getElementById('worlddev-json-warnings');
    const infoEl = document.getElementById('worlddev-json-info');
    const applyBtn = document.getElementById('worlddev-json-apply-btn');
    if (!ta || !status) return;
    const raw = ta.value.trim();
    warnEl.style.display = 'none';
    infoEl.style.display = 'none';
    _worldDevJsonLastPreview = null;
    applyBtn.disabled = true;
    if (!raw) {
        status.textContent = 'Paste JSON below.';
        status.style.color = '';
        return;
    }
    const typeHint = document.getElementById('worlddev-json-type').value;
    try {
        const res = await fetch('/world-dev/preview-json', {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ json: raw, type_hint: typeHint }),
        });
        const data = await res.json();
        if (!data.valid) {
            status.textContent = data.error || 'Invalid JSON.';
            status.style.color = '#ff8080';
            return;
        }
        _worldDevJsonLastPreview = data;
        applyBtn.disabled = false;
        const t = data.detected_type;
        const info = data.info || {};
        const name = info.name || '?';
        let label;
        if (t === 'character') {
            const tmpl = info.template || '?';
            const ofc = info.outfits || 0;
            const extra = (info.soul_md_files || []).length;
            label = `Character "${name}" — template ${tmpl}, ${ofc} outfit(s)`
                + (extra ? `, +${extra} extra soul file(s)` : '');
        } else if (t === 'location') {
            label = `Location "${name}" — ${info.rooms || 0} room(s)`;
        } else if (t === 'outfit') {
            label = `Outfit "${name}" → ${info.character_name || '?'}`;
        } else if (t === 'soul') {
            label = `Soul section "${info.section || '?'}" → ${name}`;
        } else if (t === 'profile-patch') {
            const fk = (info.fields || []).join(', ');
            label = `Profile patch → ${name} (${fk || 'no fields'})`;
        } else {
            label = `Detected: ${t}`;
        }
        status.textContent = '✓ ' + label + (data.type_hint_used ? ' [override]' : '');
        status.style.color = '#88dd88';
        if ((data.warnings || []).length) {
            warnEl.innerHTML = data.warnings.map(w => '⚠ ' + w).join('<br>');
            warnEl.style.display = '';
        }
    } catch (e) {
        status.textContent = 'Preview failed: ' + e.message;
        status.style.color = '#ff8080';
    }
}

async function worldDevJsonApply() {
    const ta = document.getElementById('worlddev-json-input');
    if (!ta || !_worldDevJsonLastPreview) {
        alert('No valid JSON to apply.');
        return;
    }
    const raw = ta.value.trim();
    const typeHint = document.getElementById('worlddev-json-type').value;
    const applyBtn = document.getElementById('worlddev-json-apply-btn');
    applyBtn.disabled = true;
    try {
        const res = await fetch('/world-dev/apply-json', {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ json: raw, type_hint: typeHint }),
        });
        const data = await res.json();
        if (!res.ok) {
            throw new Error(data.detail || 'Apply failed');
        }
        const t = data.type;
        const name = data.name || '?';
        let summary;
        if (t === 'character') {
            const ofc = (data.outfits || []).length;
            summary = `Character **"${name}"** applied (${ofc} outfit(s)).`;
        } else if (t === 'location') {
            summary = `Location **"${name}"** applied.`;
        } else if (t === 'outfit') {
            summary = `Outfit **"${name}"** → ${data.character} (${data.pieces_created} new, ${data.pieces_reused} reused).`;
        } else if (t === 'soul') {
            summary = `Soul section **"${data.section}"** → ${name} (${data.size} chars).`;
        } else if (t === 'profile-patch') {
            summary = `Profile patch → ${name}: ${(data.applied_fields || []).join(', ')}.`;
        } else {
            summary = `${t} applied.`;
        }
        if ((data.warnings || []).length) {
            summary += '\n\nWarnings:\n' + data.warnings.map(w => '- ' + w).join('\n');
        }
        worldDevCloseJsonImport();
        _worldDevAppendMessage('assistant', summary);
        // Refresh dropdowns so the new entry shows up
        if (t === 'location' && typeof worldDevLoadLocations === 'function') {
            worldDevLoadLocations();
        }
        if (t === 'character' && typeof worldDevLoadCharacters === 'function') {
            worldDevLoadCharacters();
        }
    } catch (e) {
        console.error('[WorldDev] JSON apply error:', e);
        alert('Apply failed: ' + e.message);
        applyBtn.disabled = false;
    }
}

// ============================================================
// GROUP CHAT
// ============================================================

// Dynamic turn-taking settings (sent with each group message)
let _groupTurnTaking = {
    threshold: 2.0,
    min_responders: 1,
    max_responders: 3,
};

function _showGroupChatBar(show) {
    const bar = document.getElementById('group-chat-bar');
    if (!bar) return;
    bar.style.display = show ? 'flex' : 'none';
    if (show) {
        // Sync sliders with current settings
        const minSlider = document.getElementById('gcb-min');
        const maxSlider = document.getElementById('gcb-max');
        if (minSlider) { minSlider.value = _groupTurnTaking.min_responders; document.getElementById('gcb-min-val').textContent = _groupTurnTaking.min_responders; }
        if (maxSlider) { maxSlider.value = _groupTurnTaking.max_responders; document.getElementById('gcb-max-val').textContent = _groupTurnTaking.max_responders; }
        // Whisper-Dropdown mit Teilnehmern fuellen
        const whisperSel = document.getElementById('gcb-whisper-to');
        if (whisperSel && _groupSession) {
            const participants = (_groupSession.participants || []).map(p => typeof p === 'string' ? p : p.name).filter(Boolean);
            whisperSel.innerHTML = '<option value="">-- an alle --</option>' +
                participants.map(p => `<option value="${escapeHtml(p)}">${escapeHtml(p)}</option>`).join('');
        }
    }
}

// Wire up group chat bar sliders (once on page load)
document.addEventListener('DOMContentLoaded', () => {
    const minSlider = document.getElementById('gcb-min');
    const maxSlider = document.getElementById('gcb-max');
    if (minSlider) {
        minSlider.addEventListener('input', () => {
            _groupTurnTaking.min_responders = parseInt(minSlider.value);
            document.getElementById('gcb-min-val').textContent = minSlider.value;
        });
    }
    if (maxSlider) {
        maxSlider.addEventListener('input', () => {
            _groupTurnTaking.max_responders = parseInt(maxSlider.value);
            document.getElementById('gcb-max-val').textContent = maxSlider.value;
        });
    }
    const resetBtn = document.getElementById('gcb-reset');
    if (resetBtn) {
        resetBtn.addEventListener('click', _resetGroupSession);
    }
});

function _characterColor(name) {
    let hash = 0;
    for (let i = 0; i < (name || '').length; i++) {
        hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    const hue = Math.abs(hash) % 360;
    return `hsl(${hue}, 45%, 45%)`;
}

async function _initGroupSession() {
    // Get user's current location
    let userLocation = '';
    try {
        const resp = await fetch(`/store/default/user_profile`);
        if (resp.ok) {
            const data = await resp.json();
            userLocation = (data.value && data.value.current_location) || '';
        }
    } catch (e) {
        console.warn('[GroupChat] User-Location laden fehlgeschlagen:', e);
    }
    if (!userLocation) {
        showStatusToast(t('No location chosen — open the world map'), 'error');
        chatMode = 'direct';
        return;
    }

    try {
        const resp = await fetch(`/chat/default/group/session?location_id=${encodeURIComponent(userLocation)}`);
        if (!resp.ok) {
            const errData = await resp.json().catch(() => ({}));
            showStatusToast(errData.detail || 'Gruppenchat nicht moeglich', 'error');
            chatMode = 'direct';
            return;
        }
        _groupSession = await resp.json();
        // Participants normalisieren: Server liefert manchmal Strings,
        // manchmal {name, avatar_url}-Objekte. Auf einheitliches Format
        // zwingen, sonst tauchen "undefined"-Eintraege in Portraits/Badges
        // und Selectors auf.
        if (_groupSession && Array.isArray(_groupSession.participants)) {
            _groupSession.participants = _groupSession.participants
                .map(p => {
                    if (typeof p === 'string') return { name: p.trim(), avatar_url: '' };
                    if (p && typeof p === 'object') {
                        return { name: (p.name || '').toString().trim(),
                                 avatar_url: p.avatar_url || '' };
                    }
                    return { name: '', avatar_url: '' };
                })
                .filter(p => p.name);
        }
        console.log('[GroupChat] Session geladen:', _groupSession.session_id, _groupSession.participants.length, 'Teilnehmer');

        // Load group chat history
        chatMessages.innerHTML = '';
        for (const msg of (_groupSession.chat_history || [])) {
            if (msg.role === 'user') {
                addMessage('Du', msg.content, true);
            } else if (msg.character) {
                _addGroupCharacterMessage(msg.character, msg.content, null, true);
            }
        }

        _updateGroupHeader(true);
        _showGroupChatBar(true);
        const _pnames = (_groupSession.participants || [])
            .map(p => typeof p === 'string' ? p : (p && p.name) || '')
            .filter(Boolean);
        showStatusToast(t('Group chat') + `: ${_pnames.join(', ')}`, 'success');
    } catch (e) {
        console.error('[GroupChat] Session-Fehler:', e);
        chatMode = 'direct';
        _groupSession = null;
    }
}

async function _resetGroupSession() {
    if (!_groupSession) return;
    try {
        const resp = await fetch(`/chat/default/group/reset`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                session_id: _groupSession.session_id,
                location_id: _groupSession.location_id,
            }),
        });
        if (!resp.ok) {
            const errData = await resp.json().catch(() => ({}));
            showStatusToast(errData.detail || 'Reset fehlgeschlagen', 'error');
            return;
        }
        _groupSession = await resp.json();
        // Clear chat and reload with empty history
        chatMessages.innerHTML = '';
        _updateGroupHeader(true);
        showStatusToast(t('New group chat started'), 'success');
    } catch (e) {
        console.error('[GroupChat] Reset-Fehler:', e);
        showStatusToast(t('Reset failed'), 'error');
    }
}

function _updateGroupHeader(isGroup) {
    const nameEl = document.getElementById('agent-name');
    const singleWrapper = document.getElementById('profile-image-wrapper-single');
    const groupPortraits = document.getElementById('group-portraits');
    const singleScene = document.getElementById('character-scene-img');
    const groupScene = document.getElementById('group-scene');

    if (!nameEl) return;

    if (isGroup && _groupSession) {
        // Participants koennen Strings ODER {name, avatar_url}-Objekte sein.
        // Normalisieren auf {name, avatar_url} und leere Namen filtern,
        // damit kein "undefined" als Portrait/Badge erscheint.
        const participants = (_groupSession.participants || [])
            .map(p => {
                if (typeof p === 'string') return { name: p.trim(), avatar_url: '' };
                if (p && typeof p === 'object') {
                    return { name: (p.name || '').toString().trim(),
                             avatar_url: p.avatar_url || '' };
                }
                return { name: '', avatar_url: '' };
            })
            .filter(p => p.name);
        const names = participants.map(p => p.name).join(', ');
        nameEl.textContent = `${_groupSession.location_name} (${participants.length})`;
        nameEl.title = names;

        // --- Header Portraits: Kachel-Grid ---
        if (singleWrapper) singleWrapper.style.display = 'none';
        if (groupPortraits) {
            groupPortraits.style.display = 'grid';
            // CSS class for column count
            groupPortraits.className = `group-portraits gp-${Math.min(participants.length, 6)}`;
            groupPortraits.innerHTML = '';
            for (const p of participants) {
                const item = document.createElement('div');
                item.className = 'gp-item';
                const img = document.createElement('img');
                img.src = p.avatar_url || generateDefaultAvatar(p.name);
                img.alt = p.name;
                img.onerror = function() { this.src = generateDefaultAvatar(p.name); };
                const label = document.createElement('div');
                label.className = 'gp-name';
                label.textContent = p.name;
                item.appendChild(img);
                item.appendChild(label);
                groupPortraits.appendChild(item);
            }
        }

        // --- Character Scene: Alle Expression-Bilder (gleiche Höhe, passt auf Bildschirm) ---
        if (singleScene) singleScene.style.display = 'none';
        if (groupScene) {
            groupScene.style.display = 'flex';
            groupScene.innerHTML = '';
            // Höhe skalieren: je mehr Teilnehmer, desto kleiner
            const count = participants.length;
            const heightPct = count <= 2 ? 90 : count <= 3 ? 75 : count <= 4 ? 60 : 50;
            for (const p of participants) {
                const charDiv = document.createElement('div');
                charDiv.className = 'gs-char';
                charDiv.style.height = heightPct + '%';
                const img = document.createElement('img');
                img.alt = p.name;
                img.style.height = '100%';
                // Load expression/outfit image for each character
                _loadGroupCharacterScene(p.name, img);
                const nameLabel = document.createElement('div');
                nameLabel.className = 'gs-name';
                nameLabel.textContent = p.name;
                charDiv.appendChild(img);
                charDiv.appendChild(nameLabel);
                groupScene.appendChild(charDiv);
            }
        }
    } else {
        nameEl.textContent = currentCharacterName || '—';
        nameEl.title = '';

        // Restore single-character view
        if (singleWrapper) singleWrapper.style.display = '';
        if (groupPortraits) { groupPortraits.style.display = 'none'; groupPortraits.innerHTML = ''; }
        if (singleScene) { /* visibility managed by updateCharacterScene */ }
        if (groupScene) { groupScene.style.display = 'none'; groupScene.innerHTML = ''; }

        // Refresh single character scene
        if (currentCharacterName && currentCharacterName !== 'KI') {
            updateCharacterScene(currentCharacterName);
        }
    }
}

async function _loadGroupCharacterScene(charName, imgEl) {
    /**Load DEFAULT-pose/expression variant for a group chat tile.

    Strategie:
      1. /outfit-expression mit mood='', activity='', override=1 + den
         tatsaechlich equipped Pieces — liefert die Default-Pose-Variant
         (kein Profilbild-Fallback ueber X-Variant-Status=fallback-default).
      2. Wenn das nicht klappt: aktuelles outfit-Bild ohne Pose/Expression.
      3. Letzter Fallback (NICHT Profilbild): generierter Default-Avatar.
    */
    try {
        // Equipped-State holen, sonst rendert das Backend im override-Mode nackt.
        let pieces = '', items = '', piece_colors = '';
        try {
            const eqRes = await fetch(`/inventory/characters/${encodeURIComponent(charName)}/equipped`);
            if (eqRes.ok) {
                const eq = await eqRes.json();
                const ep = eq.equipped_pieces || {};
                pieces = Object.entries(ep)
                    .filter(([, iid]) => !!iid)
                    .map(([slot, iid]) => `${slot}:${iid}`)
                    .join(',');
                const ei = (eq.equipped_items || []).filter(Boolean);
                items = ei.join(',');
                const meta = eq.equipped_pieces_meta || {};
                piece_colors = Object.entries(meta)
                    .filter(([slot, m]) => m && m.color && !!ep[slot])
                    .map(([slot, m]) => `${slot}:${m.color}`)
                    .join(',');
            }
        } catch (_) { /* fallthrough — equipped optional */ }

        // 1. Versuch: Default-Pose-Variant (override=1 + equipped, kein Mood)
        //    Wenn der Server liefert UND es keine Profilbild-Fallback-Antwort
        //    ist, nehmen wir das.
        const params = `mood=&activity=&override=1`
            + `&pieces=${encodeURIComponent(pieces)}`
            + `&items=${encodeURIComponent(items)}`
            + `&piece_colors=${encodeURIComponent(piece_colors)}`
            + `&t=${Date.now()}`;
        const exprUrl = `/characters/${encodeURIComponent(charName)}/outfit-expression?${params}`;
        try {
            const exprResp = await fetch(exprUrl);
            if (exprResp.status === 200) {
                const _vs = (exprResp.headers.get('X-Variant-Status') || '').toLowerCase();
                if (!_vs.startsWith('fallback-')) {
                    const blob = await exprResp.blob();
                    imgEl.src = URL.createObjectURL(blob);
                    return;
                }
            }
        } catch (_) { /* fallthrough */ }

        // 2. Versuch: aktuelle Mood/Activity-Variant — die ist haeufiger
        //    gecacht. fallback=default lassen wir hier ZU, damit der Server
        //    notfalls das Profilbild als Platzhalter schickt — besser als
        //    bunter Initialen-Avatar.
        try {
            const fbUrl = `/characters/${encodeURIComponent(charName)}/outfit-expression?fallback=default&t=${Date.now()}`;
            const fbResp = await fetch(fbUrl);
            if (fbResp.status === 200) {
                const blob = await fbResp.blob();
                imgEl.src = URL.createObjectURL(blob);
                return;
            }
        } catch (_) { /* fallthrough */ }

        // 3. Fallback: Outfit-Basisbild
        const outfitsRes = await fetch(`/characters/${encodeURIComponent(charName)}/outfits`);
        const outfits = outfitsRes.ok ? (await outfitsRes.json()).outfits || [] : [];
        const target = outfits.find(o => o.image);
        if (target) {
            imgEl.src = `/characters/${encodeURIComponent(charName)}/outfits/${target.image}?t=${Date.now()}`;
            return;
        }
    } catch (e) {
        console.warn(`[GroupScene] Fehler bei ${charName}:`, e);
    }
    // Letzter Fallback: generierter Default-Avatar (NICHT Profilbild).
    imgEl.src = generateDefaultAvatar(charName);
}

function _addGroupCharacterMessage(characterName, content, avatarUrl, addButtons) {
    const color = _characterColor(characterName);
    const avatar = avatarUrl || generateDefaultAvatar(characterName);

    const msgDiv = document.createElement('div');
    msgDiv.classList.add('message', 'bot-message', 'group-character-message');
    msgDiv.style.setProperty('--group-char-color', color);
    // Always store character name for TTS/visualize
    msgDiv._groupCharName = characterName;

    const avatarImg = document.createElement('img');
    avatarImg.className = 'group-msg-avatar';
    avatarImg.src = avatar;
    avatarImg.alt = characterName;
    avatarImg.onerror = function() { this.src = generateDefaultAvatar(characterName); };

    const headerDiv = document.createElement('div');
    headerDiv.className = 'group-msg-header';
    const nameSpan = document.createElement('span');
    nameSpan.className = 'group-msg-name';
    nameSpan.style.color = color;
    nameSpan.textContent = characterName;
    headerDiv.appendChild(nameSpan);

    const contentSpan = document.createElement('span');
    contentSpan.className = 'group-msg-content';
    if (content) {
        contentSpan.innerHTML = marked.parse(stripExternalImages(content));
    }

    msgDiv.appendChild(avatarImg);
    msgDiv.appendChild(headerDiv);
    msgDiv.appendChild(contentSpan);

    // Add speak/visualize buttons (for history messages or when explicitly requested)
    if (addButtons && content) {
        appendSpeakButton(msgDiv);
        appendVisualizeButton(msgDiv);
    }

    chatMessages.appendChild(msgDiv);
    chatMessages.scrollTop = chatMessages.scrollHeight;

    return { element: msgDiv, contentSpan: contentSpan };
}

function _addGroupPassiveNotice(characterName) {
    const div = document.createElement('div');
    div.className = 'group-passive-notice';
    div.innerHTML = `<em>${escapeHtml(characterName)} hoert zu</em>`;
    chatMessages.appendChild(div);
    chatMessages.scrollTop = chatMessages.scrollHeight;
}

function _showGroupTypingIndicator(characterName, color) {
    removeTypingIndicator();
    const div = document.createElement('div');
    div.id = 'typing-indicator';
    div.className = 'group-typing-indicator';
    div.innerHTML = `<span class="typing-char-name" style="color: ${color || 'var(--text)'}">${escapeHtml(characterName)}</span> denkt nach<span class="typing-dots"><span class="typing-dot"></span><span class="typing-dot"></span><span class="typing-dot"></span></span>`;
    chatMessages.appendChild(div);
    chatMessages.scrollTop = chatMessages.scrollHeight;
}

async function _readGroupChatStream(streamUrl) {
    const response = await fetch(streamUrl);
    if (!response.ok) throw new Error(`Stream-Fehler: ${response.status}`);

    const reader = response.body.getReader();
    const decoder = new TextDecoder();

    let currentChar = null;
    let currentMsgEl = null;
    let currentContentSpan = null;
    let currentFullResponse = '';
    let currentTtsChunkPlayer = null;

    while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        const lines = chunk.split('\n').filter(l => l.trim() !== '');

        for (const line of lines) {
            if (!line.startsWith('data: ')) continue;
            try {
                const data = JSON.parse(line.substring(6));

                if (data.error) {
                    addMessage('System', `Fehler: ${data.error}`, false);
                    return;
                }

                if (data.group_start) {
                    removeTypingIndicator();
                    console.log('[GroupChat] Start:', data.group_start.responders.length, 'Antwortende');
                }

                if (data.char_passive) {
                    _addGroupPassiveNotice(data.char_passive.character);
                }

                if (data.char_start) {
                    removeTypingIndicator();
                    currentChar = data.char_start.character;
                    currentFullResponse = '';
                    currentTtsChunkPlayer = null;
                    const { element, contentSpan } = _addGroupCharacterMessage(
                        currentChar, '', data.char_start.avatar_url
                    );
                    currentMsgEl = element;
                    currentContentSpan = contentSpan;
                }

                if (data.content && currentChar && currentContentSpan) {
                    currentFullResponse += data.content;
                    const displayText = stripExternalImages(currentFullResponse);
                    currentContentSpan.innerHTML = marked.parse(displayText);
                    chatMessages.scrollTop = chatMessages.scrollHeight;
                }

                // Chunked TTS audio for current character
                if (data.audio_chunk && currentMsgEl) {
                    if (!currentTtsChunkPlayer) currentTtsChunkPlayer = createTtsChunkPlayer(currentMsgEl);
                    currentTtsChunkPlayer.addChunk(data.audio_chunk);
                }

                // TTS auto-mode fallback for current character
                if (data.tts_auto && currentMsgEl && currentChar) {
                    const _ttsChar = data.tts_character || currentChar;
                    const _ttsMsgEl = currentMsgEl;
                    const _ttsText = currentFullResponse;
                    (async () => {
                        try {
                            const resp = await fetch('/tts/speak', {
                                method: 'POST',
                                headers: {'Content-Type': 'application/json'},
                                body: JSON.stringify({ text: _ttsText, character_name: _ttsChar }),
                            });
                            const result = await resp.json();
                            if (result.audio_url) appendAudioPlayer(_ttsMsgEl, result.audio_url);
                        } catch (e) {
                            console.error('[GroupChat TTS] Auto-TTS error:', e);
                        }
                    })();
                }

                if (data.char_end) {
                    // Finalize: add speak + visualize buttons to this character's message
                    if (currentMsgEl) {
                        appendSpeakButton(currentMsgEl);
                        appendVisualizeButton(currentMsgEl);
                    }
                    currentChar = null;
                    currentMsgEl = null;
                    currentContentSpan = null;
                    currentFullResponse = '';
                    currentTtsChunkPlayer = null;
                }

                if (data.group_end) {
                    removeTypingIndicator();
                    console.log('[GroupChat] Ende');
                }
            } catch (e) {
                console.error('[GroupChat] SSE parse error:', e, 'line:', line);
            }
        }
    }
}

// @Mention Autocomplete for Group Chat
(function() {
    const input = document.getElementById('user-input');
    if (!input) return;

    let _mentionDropdown = null;

    function _createMentionDropdown() {
        if (_mentionDropdown) return _mentionDropdown;
        const dd = document.createElement('div');
        dd.className = 'mention-dropdown';
        dd.style.cssText = 'display:none; position:absolute; bottom:100%; left:10px; background:var(--bg-message,#2a2a4a); border:1px solid var(--border,#444); border-radius:8px; padding:4px; z-index:100; max-height:200px; overflow-y:auto; min-width:150px;';
        input.parentElement.style.position = 'relative';
        input.parentElement.appendChild(dd);
        _mentionDropdown = dd;
        return dd;
    }

    function _hideMentionDropdown() {
        if (_mentionDropdown) _mentionDropdown.style.display = 'none';
    }

    input.addEventListener('input', () => {
        if (chatMode !== 'group' || !_groupSession) { _hideMentionDropdown(); return; }
        const text = input.value;
        const cursorPos = input.selectionStart;
        const before = text.substring(0, cursorPos);
        const atMatch = before.match(/@(\w*)$/);
        if (!atMatch) { _hideMentionDropdown(); return; }

        const query = atMatch[1].toLowerCase();
        const matches = (_groupSession.participants || []).filter(p =>
            p.name.toLowerCase().startsWith(query)
        );
        if (matches.length === 0) { _hideMentionDropdown(); return; }

        const dd = _createMentionDropdown();
        dd.innerHTML = '';
        for (const p of matches) {
            const item = document.createElement('div');
            item.style.cssText = 'display:flex; align-items:center; gap:6px; padding:4px 8px; cursor:pointer; border-radius:4px; font-size:13px;';
            item.onmouseenter = () => item.style.background = 'var(--bg-hover, rgba(255,255,255,0.1))';
            item.onmouseleave = () => item.style.background = '';
            const color = _characterColor(p.name);
            item.innerHTML = `<span style="color:${color}; font-weight:600;">${escapeHtml(p.name)}</span>`;
            item.addEventListener('mousedown', (e) => {
                e.preventDefault();
                const replaceStart = atMatch.index;
                const replaceEnd = cursorPos;
                input.value = text.substring(0, replaceStart) + '@' + p.name + ' ' + text.substring(replaceEnd);
                input.selectionStart = input.selectionEnd = replaceStart + p.name.length + 2;
                _hideMentionDropdown();
                input.focus();
            });
            dd.appendChild(item);
        }
        dd.style.display = 'block';
    });

    input.addEventListener('blur', () => setTimeout(_hideMentionDropdown, 200));
    input.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') _hideMentionDropdown();
    });
})();


// ===========================================================================
// Diary / Timeline Panel
// ===========================================================================

let _diaryPanelOpen = false;
let _diaryDatesLoaded = false;

const _diaryIcons = {
    mood: '\u{1F3AD}',
    location: '\u{1F4CD}',
    activity: '\u26A1',
    condition: '\u{1F525}',
    forced_action: '\u26A0\uFE0F',
    thought: '\u{1F9E0}',
    assignment_update: '\u{1F4CB}',
    assignment_done: '\u2705',
    daily_summary: '\u{1F4D6}',
    instagram_post: '\u{1F4F8}',
    instagram_comment: '\u{1F4AC}',
};

const _diaryTypeLabels = {
    mood: 'Stimmung',
    location: 'Ortswechsel',
    activity: 'Aktivit\u00e4t',
    condition: 'Zustand',
    forced_action: 'Erzwungen',
    thought: 'Gedanke',
    assignment_update: 'Aufgabe',
    assignment_done: 'Erledigt',
    daily_summary: 'R\u00fcckblick',
    instagram_post: 'Instagram',
    instagram_comment: 'Kommentar',
};

// Diary haelt eine eigene Character-Auswahl (unabhaengig vom Chat-Partner),
// damit man im Tagebuch bloettern kann ohne den globalen Chat zu wechseln.
let _diarySelectedCharacter = null;

function _buildDiaryCharacterSelector() {
    const container = document.getElementById('diary-character');
    if (!container) return;
    const options = _buildCharacterSelectorOptions();
    if (!_diarySelectedCharacter || !options.find(o => o.name === _diarySelectedCharacter)) {
        // Default: aktueller Chat-Partner, sonst erster Eintrag
        const fallback = (currentCharacterName && currentCharacterName !== 'KI')
            ? currentCharacterName
            : (options[0] && options[0].name) || null;
        _diarySelectedCharacter = fallback;
    }
    _renderCharacterSelector(container, options, _diarySelectedCharacter, (name) => {
        _diarySelectedCharacter = name;
        _loadDiaryDates().then(() => loadDiary());
    });
}

function toggleDiaryPanel() {
    const panel = document.getElementById('diary-panel');
    if (!panel) return;
    _diaryPanelOpen = !_diaryPanelOpen;
    panel.style.display = _diaryPanelOpen ? 'flex' : 'none';
    if (_diaryPanelOpen) {
        _restorePanelWidth('diary-panel');
        _buildDiaryCharacterSelector();
        _loadDiaryDates().then(() => loadDiary());
    }
}

async function _loadDiaryDates() {
    const agent = _getCurrentAgent();
    if (!agent) return;
    try {
        const resp = await fetch(`/diary/default/${encodeURIComponent(agent)}/dates`);
        if (!resp.ok) return;
        const dates = await resp.json();
        const sel = document.getElementById('diary-date');
        if (!sel) return;
        // Preserve current selection if possible
        const prev = sel.value;
        sel.innerHTML = '';
        // Add "Alle" option
        const allOpt = document.createElement('option');
        allOpt.value = '';
        allOpt.textContent = 'Alle Tage';
        sel.appendChild(allOpt);
        // Add today if not in list
        const today = new Date().toISOString().slice(0, 10);
        const allDates = dates.includes(today) ? dates : [today, ...dates];
        for (const d of allDates) {
            const opt = document.createElement('option');
            opt.value = d;
            const dt = new Date(d + 'T00:00:00');
            opt.textContent = dt.toLocaleDateString('de-DE', { weekday: 'short', day: '2-digit', month: '2-digit', year: 'numeric' });
            sel.appendChild(opt);
        }
        // Default: today, fallback auf neuestes verfuegbares Datum wenn today
        // nicht in der Liste ist. Vorheriges Datum nur uebernehmen wenn es als
        // Option existiert — sonst kleben wir an einem Datum das es nicht gibt.
        const optionValues = Array.from(sel.options).map(o => o.value);
        if (prev && optionValues.includes(prev)) {
            sel.value = prev;
        } else if (optionValues.includes(today)) {
            sel.value = today;
        } else if (allDates.length) {
            sel.value = allDates[0];
        } else {
            sel.value = '';
        }
        _diaryDatesLoaded = true;
    } catch (e) {
        console.error('[Diary] Dates load error:', e);
    }
}

function _getCurrentAgent() {
    // Diary nutzt seine eigene Character-Auswahl, damit man im Tagebuch
    // bloettern kann ohne den globalen Chat-Partner zu wechseln.
    if (_diarySelectedCharacter) return _diarySelectedCharacter;
    if (typeof currentCharacterName !== 'undefined' && currentCharacterName
        && currentCharacterName !== 'KI' && currentCharacterName !== '—') {
        return currentCharacterName;
    }
    const el = document.getElementById('agent-name');
    const txt = el ? el.textContent.trim() : '';
    if (txt && txt !== '—') return txt;
    return null;
}

let _diaryEntriesCache = [];

async function loadDiary() {
    const agent = _getCurrentAgent();
    if (!agent) return;
    const dateVal = document.getElementById('diary-date')?.value ?? '';
    const filterVal = document.getElementById('diary-filter')?.value || '';
    try {
        // Wenn dateVal '' (Alle Tage) → backend-side all
        let url = `/diary/default/${encodeURIComponent(agent)}?limit=500`;
        url += `&date=${encodeURIComponent(dateVal || 'all')}`;
        if (filterVal) url += `&type=${encodeURIComponent(filterVal)}`;
        const resp = await fetch(url, {cache: 'no-store'});
        if (!resp.ok) return;
        const data = await resp.json();
        _diaryEntriesCache = data.entries || [];
        // Dropdown-Typen dynamisch aus Response befuellen (falls noch leer)
        _populateDiaryFilterOptions(data.types || {}, data.icons || {}, filterVal);
        _renderDiaryFiltered();
    } catch (e) {
        console.error('[Diary] Load error:', e);
    }
}

function _populateDiaryFilterOptions(types, icons, selected) {
    const sel = document.getElementById('diary-filter');
    if (!sel) return;
    if (sel.options.length > 1) return;   // schon befuellt
    const order = ['mood','location','activity','condition','effects','thought',
                   'assignment_update','assignment_done','daily_summary',
                   'instagram_post','instagram_comment','forced_action','access_denied'];
    const keys = order.filter(k => types[k]).concat(
        Object.keys(types).filter(k => !order.includes(k)));
    for (const k of keys) {
        const opt = document.createElement('option');
        opt.value = k;
        opt.textContent = (icons[k] || '•') + ' ' + types[k];
        if (k === selected) opt.selected = true;
        sel.appendChild(opt);
    }
}

let _diarySearchTimer = null;
function _onDiarySearchInput() {
    if (_diarySearchTimer) clearTimeout(_diarySearchTimer);
    _diarySearchTimer = setTimeout(() => _renderDiaryFiltered(), 150);
}

function _renderDiaryFiltered() {
    const q = (document.getElementById('diary-search')?.value || '').trim().toLowerCase();
    if (!q) return _renderDiary(_diaryEntriesCache);
    const filtered = _diaryEntriesCache.filter(e => {
        const hay = ((e.content || '') + ' ' + JSON.stringify(e.metadata || {})).toLowerCase();
        return hay.includes(q);
    });
    _renderDiary(filtered);
}

function _renderDiary(entries) {
    const container = document.getElementById('diary-content');
    if (!container) return;
    if (!entries.length) {
        container.innerHTML = `<p class="diary-empty">${escapeHtml(t('No entries for this day'))}</p>`;
        return;
    }

    let html = '';
    let lastDate = '';

    for (const e of entries) {
        const ts = e.timestamp || '';
        const dateStr = ts.slice(0, 10);
        const timeStr = ts.length >= 16 ? ts.slice(11, 16) : '';

        // Day header if date changed
        if (dateStr !== lastDate) {
            const dt = new Date(dateStr + 'T00:00:00');
            const dayLabel = dt.toLocaleDateString('de-DE', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric' });
            html += `<div class="diary-day-header">${dayLabel}</div>`;
            lastDate = dateStr;
        }

        let icon = _diaryIcons[e.type] || '\u{1F4DD}';
        // Social dialog: different icon for active vs passive
        if (e.type === 'social_dialog' && e.metadata) {
            icon = e.metadata.direction === 'outgoing' ? '\u{1F5E3}\uFE0F' : '\u{1F44B}';
        }
        const typeLabel = _diaryTypeLabels[e.type] || e.type;
        const isSummary = e.type === 'daily_summary' ? ' summary' : '';

        // If entry has relationship impact, show colored tag (skip 0 = neutral)
        let relTag = '';
        if (e.metadata && e.metadata.relationship_sentiment !== undefined) {
            const sent = parseFloat(e.metadata.relationship_sentiment);
            if (Math.abs(sent) >= 0.005) {
                const color = sent >= 0 ? '#43a047' : '#e53935';
                const sign = sent > 0 ? '+' : '';
                const target = e.metadata.relationship_target || '';
                const targetLabel = target ? ` zu ${target}` : '';
                relTag = `<span class="diary-entry-type diary-rel-tag" style="background:${color};color:#fff;">Beziehung${targetLabel} ${sign}${sent.toFixed(2)}</span>`;
            }
        }

        // Effects-Tags: show duration + old → new values
        let effectsTags = '';
        if (e.type === 'effects' && e.metadata && e.metadata.changes) {
            if (e.metadata.elapsed_minutes) {
                const mins = e.metadata.elapsed_minutes;
                const durLabel = mins >= 60 ? `${Math.floor(mins / 60)}h ${mins % 60}m` : `${mins}m`;
                effectsTags += `<span class="diary-entry-type" style="background:#757575;color:#fff;">⏱ ${durLabel}</span>`;
            }
            effectsTags += Object.entries(e.metadata.changes)
                .map(([stat, vals]) => {
                    const oldV = vals.old ?? '?';
                    const newV = vals.new ?? '?';
                    const color = newV > oldV ? '#43a047' : (newV < oldV ? '#e53935' : '#757575');
                    return `<span class="diary-entry-type" style="background:${color};color:#fff;">${stat} ${oldV}→${newV}</span>`;
                }).join('');
        }

        html += `<div class="diary-entry${isSummary}">
            <div class="diary-entry-icon">${icon}</div>
            <div class="diary-entry-body">
                <div class="diary-entry-content" onclick="this.classList.toggle('expanded')">${escapeDiaryHtml(e.content)}</div>
                <div class="diary-entry-time">${timeStr}<span class="diary-entry-type">${typeLabel}</span>${relTag}${effectsTags}</div>
            </div>
        </div>`;
    }

    container.innerHTML = html;
}

function escapeDiaryHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    let escaped = div.innerHTML;
    escaped = escaped.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    return escaped;
}

async function generateDiarySummary() {
    const agent = _getCurrentAgent();
    if (!agent) return;
    const dateVal = document.getElementById('diary-date')?.value || new Date().toISOString().slice(0, 10);

    // Check if there are any entries first
    const container = document.getElementById('diary-content');
    const hasEntries = container && !container.querySelector('.diary-empty');
    if (!hasEntries) {
        _showDiaryToast('Keine Eintr\u00e4ge vorhanden \u2014 chatte zuerst mit ' + agent + ', damit Ereignisse im Tagebuch landen.');
        return;
    }

    const btn = document.querySelector('.diary-summary-btn');
    if (btn) { btn.disabled = true; btn.textContent = '...'; }
    try {
        const resp = await fetch(`/diary/default/${encodeURIComponent(agent)}/summary`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ date: dateVal }),
        });
        if (resp.ok) {
            _showDiaryToast('Tagesr\u00fcckblick wird generiert \u2014 erscheint in wenigen Sekunden...');
        } else {
            const err = await resp.json().catch(() => ({}));
            if (resp.status === 409) {
                _showDiaryToast('Tagesr\u00fcckblick existiert bereits f\u00fcr diesen Tag.');
            } else if (resp.status === 404) {
                _showDiaryToast('Keine Eintr\u00e4ge f\u00fcr diesen Tag \u2014 es muss zuerst etwas passieren.');
            } else {
                _showDiaryToast(err.detail || 'Fehler beim Generieren');
            }
        }
    } catch (e) {
        console.error('[Diary] Summary error:', e);
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = '\u2726'; }
    }
}

function _showDiaryToast(msg) {
    const container = document.getElementById('diary-content');
    if (!container) return;
    // Remove existing toast
    const old = container.querySelector('.diary-toast');
    if (old) old.remove();
    const toast = document.createElement('div');
    toast.className = 'diary-toast';
    toast.textContent = msg;
    container.prepend(toast);
    setTimeout(() => toast.remove(), 4000);
}
